String _formatToolbarBorderStyleWidth(double width) {
  return width == width.roundToDouble()
      ? width.toInt().toString()
      : width.toStringAsFixed(1);
}

const Color _fortuneEditorLightSelectionBackgroundColor = Color(0xffb8dcff);
const int _fortuneEditorSelectionBackgroundAlpha = 0xcc;

bool _stringListsEqual(List<String> left, List<String> right) {
  if (identical(left, right)) {
    return true;
  }
  if (left.length != right.length) {
    return false;
  }
  for (var index = 0; index < left.length; index += 1) {
    if (left[index] != right[index]) {
      return false;
    }
  }
  return true;
}

typedef FortuneImagePicker = Future<FortuneImagePickResult?> Function();
typedef FortuneBarcodeRenderer =
    Future<FortuneBarcodeRenderResult?> Function(FortuneBarcodeRequest request);

class FortuneBarcodeFormatOption {
  const FortuneBarcodeFormatOption({
    required this.id,
    required this.label,
    this.ratio = 1.0,
  });

  final String id;
  final String label;
  final double ratio;
}

class FortuneBarcodeRequest {
  const FortuneBarcodeRequest({
    required this.text,
    required this.formatId,
    required this.width,
    required this.height,
    required this.rotation,
    this.moduleScale = 3,
    this.barHeight = 10,
    this.leadingText = '',
    this.trailingText = '',
    this.showHumanReadableText = false,
    this.humanReadableFontFamily,
    this.humanReadableFontSize = 14,
  });

  final String text;
  final String formatId;
  final double width;
  final double height;
  final double rotation;
  final double moduleScale;
  final double barHeight;
  final String leadingText;
  final String trailingText;
  final bool showHumanReadableText;
  final String? humanReadableFontFamily;
  final double humanReadableFontSize;
}

class FortuneBarcodeRenderResult {
  const FortuneBarcodeRenderResult({
    required this.bytes,
    this.mimeType = 'image/png',
    this.pixelWidth,
    this.pixelHeight,
    this.bodyTop,
    this.bodyHeight,
  });

  final Uint8List bytes;
  final String mimeType;
  final int? pixelWidth;
  final int? pixelHeight;
  final int? bodyTop;
  final int? bodyHeight;
}

Map<String, Object?> fortuneImageResizeExtraFieldsForMetadata(
  FortuneImage initial, {
  required double width,
  required double height,
  required bool usesMillimeters,
}) {
  final extraFields = <String, Object?>{...initial.extraFields};
  if (usesMillimeters || extraFields.containsKey('widthMm')) {
    extraFields['widthMm'] = fortuneLogicalPixelsToMillimeters(width);
  }
  if (usesMillimeters || extraFields.containsKey('heightMm')) {
    extraFields['heightMm'] = fortuneLogicalPixelsToMillimeters(height);
  }
  if (initial.extraFields['fortuneBarcode'] == true && initial.height > 0) {
    final heightScale = height / initial.height;
    if (heightScale.isFinite && heightScale > 0) {
      final barHeight = _fortuneExtraDouble(extraFields['barcodeBarHeight']);
      if (barHeight != null) {
        extraFields['barcodeBarHeight'] = barHeight * heightScale;
      }
      final fontSize = _fortuneExtraDouble(
        extraFields['barcodeHumanReadableFontSize'],
      );
      if (fontSize != null) {
        extraFields['barcodeHumanReadableFontSize'] = fontSize * heightScale;
      }
      final bodyTop = _fortuneExtraDouble(
        extraFields[fortuneBarcodeBodyTopExtraKey],
      );
      if (bodyTop != null) {
        extraFields[fortuneBarcodeBodyTopExtraKey] = bodyTop * heightScale;
      }
      final bodyHeight = _fortuneExtraDouble(
        extraFields[fortuneBarcodeBodyHeightExtraKey],
      );
      if (bodyHeight != null) {
        extraFields[fortuneBarcodeBodyHeightExtraKey] = bodyHeight * heightScale;
      }
    }
  }
  return extraFields;
}

double? _fortuneExtraDouble(Object? value) {
  if (value is num) {
    return value.toDouble();
  }
  if (value is String) {
    return double.tryParse(value.trim());
  }
  return null;
}

class _FortuneRichTextEditingController extends TextEditingController {
  _FortuneRichTextEditingController();

  List<FortuneInlineTextRun> _runs = const <FortuneInlineTextRun>[];
  bool _hasInlineRuns = false;
  bool _replacingValue = false;
  String Function(String? raw, TextStyle baseStyle)? fontFamilyResolver;

  bool get hasInlineRuns => _hasInlineRuns && _runs.isNotEmpty;

  List<FortuneInlineTextRun> get inlineRuns => [
    for (final run in _runs)
      if (run.text.isNotEmpty) run.copyWith(),
  ];

  void setCellValue(FortuneCell? cell, TextEditingValue nextValue) {
    final text = nextValue.text;
    final runs = cell?.inlineRuns;
    _runs = runs != null && runs.isNotEmpty
        ? _runsForText(text, [for (final run in runs) run.copyWith()])
        : text.isEmpty
        ? const <FortuneInlineTextRun>[]
        : [
            FortuneInlineTextRun(
              text: text,
              rawText: text,
              hasRawText: true,
              foreground: cell?.foreground,
              rawForeground: cloneFortuneMetadata(cell?.rawForeground),
              hasRawForeground: cell?.hasRawForeground ?? false,
              bold: cell?.bold,
              rawBold: cloneFortuneMetadata(cell?.rawBold),
              hasRawBold: cell?.hasRawBold ?? false,
              italic: cell?.italic,
              rawItalic: cloneFortuneMetadata(cell?.rawItalic),
              hasRawItalic: cell?.hasRawItalic ?? false,
              strikeThrough: cell?.strikeThrough,
              rawStrikeThrough: cloneFortuneMetadata(cell?.rawStrikeThrough),
              hasRawStrikeThrough: cell?.hasRawStrikeThrough ?? false,
              underline: cell?.underline,
              rawUnderline: cloneFortuneMetadata(cell?.rawUnderline),
              hasRawUnderline: cell?.hasRawUnderline ?? false,
              fontSize: cell?.fontSize,
              rawFontSize: cloneFortuneMetadata(cell?.rawFontSize),
              hasRawFontSize: cell?.hasRawFontSize ?? false,
              fontFamily: cell?.fontFamily,
              rawFontFamily: cloneFortuneMetadata(cell?.rawFontFamily),
              hasRawFontFamily: cell?.hasRawFontFamily ?? false,
            ),
          ];
    _hasInlineRuns = runs != null && runs.isNotEmpty;
    _replacingValue = true;
    value = nextValue;
    _replacingValue = false;
  }

  void applyInlineFormat(String key, Object? formatValue, {TextRange? range}) {
    final selected = range ?? selection;
    if (!selected.isValid || selected.isCollapsed || text.isEmpty) {
      return;
    }
    final start = math.max(0, math.min(selected.start, selected.end));
    final end = math.min(text.length, math.max(selected.start, selected.end));
    if (start >= end) {
      return;
    }
    _ensureRunsForText();
    if (key == 'fs' && _applyInlineFontSizeFormat(formatValue, start, end)) {
      return;
    }
    final current = FortuneCell(
      value: text,
      rawValue: text,
      hasRawValue: true,
      inlineRuns: _runs,
    );
    final next = updateInlineStringFormat(
      current,
      key,
      formatValue,
      startOffset: start,
      endOffset: end,
    );
    _runs = _mergeAdjacentRuns(
      next.inlineRuns ?? const <FortuneInlineTextRun>[],
    );
    _hasInlineRuns = true;
    notifyListeners();
  }

  bool _applyInlineFontSizeFormat(Object? formatValue, int start, int end) {
    final baseFontSize = formatValue is num
        ? formatValue.toDouble()
        : double.tryParse('$formatValue');
    if (baseFontSize == null) {
      return false;
    }
    final nextRuns = <FortuneInlineTextRun>[];
    var cursor = 0;
    for (final run in _runs) {
      final runStart = cursor;
      final runEnd = cursor + run.text.length;
      cursor = runEnd;
      if (run.text.isEmpty || end <= runStart || start >= runEnd) {
        nextRuns.add(run);
        continue;
      }
      final localStart = math.max(0, start - runStart);
      final localEnd = math.min(run.text.length, end - runStart);
      if (localStart > 0) {
        nextRuns.add(_runWithText(run, run.text.substring(0, localStart)));
      }
      if (localEnd > localStart) {
        final fontSize = run.extraFields['script'] == null
            ? baseFontSize
            : baseFontSize * fortuneInlineScriptFontSizeScale;
        nextRuns.add(
          _runWithText(run, run.text.substring(localStart, localEnd)).copyWith(
            fontSize: fontSize,
            rawFontSize: fontSize,
            hasRawFontSize: true,
          ),
        );
      }
      if (localEnd < run.text.length) {
        nextRuns.add(_runWithText(run, run.text.substring(localEnd)));
      }
    }
    _runs = _mergeAdjacentRuns(nextRuns);
    _hasInlineRuns = true;
    notifyListeners();
    return true;
  }

  void clearScriptAndSetFontSize(TextRange range, double fontSize) {
    if (!range.isValid || range.isCollapsed || text.isEmpty) {
      return;
    }
    final start = math.max(0, math.min(range.start, range.end));
    final end = math.min(text.length, math.max(range.start, range.end));
    if (start >= end) {
      return;
    }
    _ensureRunsForText();
    final nextRuns = <FortuneInlineTextRun>[];
    var cursor = 0;
    for (final run in _runs) {
      final runStart = cursor;
      final runEnd = cursor + run.text.length;
      cursor = runEnd;
      if (run.text.isEmpty || end <= runStart || start >= runEnd) {
        nextRuns.add(run);
        continue;
      }
      final localStart = math.max(0, start - runStart);
      final localEnd = math.min(run.text.length, end - runStart);
      if (localStart > 0) {
        nextRuns.add(_runWithText(run, run.text.substring(0, localStart)));
      }
      if (localEnd > localStart) {
        final extraFields = Map<String, Object?>.from(run.extraFields)
          ..remove('script');
        nextRuns.add(
          _runWithText(run, run.text.substring(localStart, localEnd)).copyWith(
            fontSize: fontSize,
            rawFontSize: fontSize,
            hasRawFontSize: true,
            extraFields: extraFields,
          ),
        );
      }
      if (localEnd < run.text.length) {
        nextRuns.add(_runWithText(run, run.text.substring(localEnd)));
      }
    }
    _runs = _mergeAdjacentRuns(nextRuns);
    _hasInlineRuns = true;
    notifyListeners();
  }

  FortuneInlineTextRun? runAtOffset(int offset) {
    _ensureRunsForText();
    if (_runs.isEmpty) {
      return null;
    }
    final target = offset <= 0 ? 0 : math.min(offset - 1, text.length - 1);
    var cursor = 0;
    for (final run in _runs) {
      final nextCursor = cursor + run.text.length;
      if (target < nextCursor) {
        return run;
      }
      cursor = nextCursor;
    }
    return _runs.last;
  }

  bool rangeContainsScript(TextRange range) {
    return runsForRange(range).any((run) => run.extraFields['script'] != null);
  }

  List<FortuneInlineTextRun> runsForRange(TextRange range) {
    if (!range.isValid || range.isCollapsed || text.isEmpty) {
      return const <FortuneInlineTextRun>[];
    }
    _ensureRunsForText();
    final start = math.max(0, math.min(range.start, range.end));
    final end = math.min(text.length, math.max(range.start, range.end));
    return _sliceRuns(start, end);
  }

  void replaceRangeWithRuns(
    TextRange range,
    String replacement,
    List<FortuneInlineTextRun> replacementRuns,
  ) {
    if (!range.isValid) {
      return;
    }
    final currentText = text;
    final start = math.max(0, math.min(range.start, range.end));
    final end = math.min(currentText.length, math.max(range.start, range.end));
    if (start > end) {
      return;
    }
    _ensureRunsForText();
    final nextText = currentText.replaceRange(start, end, replacement);
    final normalizedRuns = _runsForText(replacement, [
      for (final run in replacementRuns) run.copyWith(),
    ]);
    _runs = _mergeAdjacentRuns([
      ..._sliceRuns(0, start),
      ...normalizedRuns,
      ..._sliceRuns(end, currentText.length),
    ]);
    _hasInlineRuns = _runs.isNotEmpty;
    _replacingValue = true;
    value = TextEditingValue(
      text: nextText,
      selection: TextSelection.collapsed(offset: start + replacement.length),
    );
    _replacingValue = false;
  }

  @override
  set value(TextEditingValue nextValue) {
    final previousValue = value;
    if (!_replacingValue && previousValue.text != nextValue.text) {
      _syncRunsForTextChange(previousValue, nextValue);
    }
    super.value = nextValue;
  }

  @override
  TextSpan buildTextSpan({
    required BuildContext context,
    TextStyle? style,
    required bool withComposing,
  }) {
    if (!_hasInlineRuns || _runs.isEmpty) {
      return super.buildTextSpan(
        context: context,
        style: style,
        withComposing: withComposing,
      );
    }
    final baseStyle = style ?? const TextStyle();
    final selectedRange = _selectedTextRangeForEditorPaint();
    return TextSpan(
      style: baseStyle,
      children: _spansForRuns(context, baseStyle, selectedRange),
    );
  }

  List<InlineSpan> _spansForRuns(
    BuildContext context,
    TextStyle baseStyle,
    TextRange? selectedRange,
  ) {
    final spans = <InlineSpan>[];
    var cursor = 0;
    for (final run in _runs) {
      spans.addAll(
        _spansForRun(
          context,
          baseStyle,
          run,
          runStart: cursor,
          selectedRange: selectedRange,
        ),
      );
      cursor += run.text.length;
    }
    return spans;
  }

  TextRange? _selectedTextRangeForEditorPaint() {
    final selected = selection;
    if (!selected.isValid || selected.isCollapsed || text.isEmpty) {
      return null;
    }
    final start = math.max(0, math.min(selected.start, selected.end));
    final end = math.min(text.length, math.max(selected.start, selected.end));
    if (start >= end) {
      return null;
    }
    return TextRange(start: start, end: end);
  }

  List<InlineSpan> _spansForRun(
    BuildContext context,
    TextStyle baseStyle,
    FortuneInlineTextRun run, {
    required int runStart,
    required TextRange? selectedRange,
  }) {
    if (run.text.isEmpty || selectedRange == null) {
      return _spansForRunSegment(context, baseStyle, run);
    }
    final runEnd = runStart + run.text.length;
    if (selectedRange.end <= runStart || selectedRange.start >= runEnd) {
      return _spansForRunSegment(context, baseStyle, run);
    }
    final localStart = math.max(0, selectedRange.start - runStart);
    final localEnd = math.min(run.text.length, selectedRange.end - runStart);
    final spans = <InlineSpan>[];
    if (localStart > 0) {
      spans.addAll(
        _spansForRunSegment(
          context,
          baseStyle,
          _runWithText(run, run.text.substring(0, localStart)),
        ),
      );
    }
    if (localEnd > localStart) {
      spans.addAll(
        _spansForRunSegment(
          context,
          baseStyle,
          _runWithText(run, run.text.substring(localStart, localEnd)),
          selectedBackgroundColor: _selectedInlineRunBackgroundColor(run),
        ),
      );
    }
    if (localEnd < run.text.length) {
      spans.addAll(
        _spansForRunSegment(
          context,
          baseStyle,
          _runWithText(run, run.text.substring(localEnd)),
        ),
      );
    }
    return spans;
  }

  List<InlineSpan> _spansForRunSegment(
    BuildContext context,
    TextStyle baseStyle,
    FortuneInlineTextRun run, {
    Color? selectedBackgroundColor,
  }) {
    if (run.extraFields['rtfHidden'] == true) {
      return const <InlineSpan>[];
    }
    final displayText = _rtfDisplayText(run.text, run);
    if (displayText.isEmpty) {
      return const <InlineSpan>[];
    }
    run = _runWithText(run, displayText);
    final style = _styleForRun(
      baseStyle,
      run,
      selectedBackgroundColor: selectedBackgroundColor,
    );
    final script = run.extraFields['script'];
    final fontScale = _inlineRunFontScale(run);
    final baselineShift = _inlineRunBaselineShift(baseStyle, run, script);
    if (script != 'superscript' &&
        script != 'subscript' &&
        fontScale == 1 &&
        baselineShift == 0) {
      return [TextSpan(text: run.text, style: style)];
    }
    return [
      for (final rune in run.text.runes)
        _scaledRunWidgetSpan(
          context,
          String.fromCharCode(rune),
          style,
          fontScale: fontScale,
          baselineShift: baselineShift,
        ),
    ];
  }

  WidgetSpan _scaledRunWidgetSpan(
    BuildContext context,
    String text,
    TextStyle style, {
    required double fontScale,
    required double baselineShift,
  }) {
    final textPainter = TextPainter(
      text: TextSpan(text: text, style: style),
      textDirection: Directionality.of(context),
      maxLines: 1,
    )..layout();
    return WidgetSpan(
      alignment: PlaceholderAlignment.baseline,
      baseline: TextBaseline.alphabetic,
      child: SizedBox(
        width: textPainter.width * fontScale,
        child: Transform.translate(
          offset: Offset(0, baselineShift),
          child: Transform.scale(
            alignment: Alignment.centerLeft,
            scaleX: fontScale,
            child: Text(text, style: style),
          ),
        ),
      ),
    );
  }

  double _inlineRunFontScale(FortuneInlineTextRun run) {
    final value = _inlineRunDoubleExtra(run, 'fontScale');
    if (value == null || !value.isFinite || value <= 0) {
      return 1;
    }
    return value / 100;
  }

  double _inlineRunBaselineShift(
    TextStyle baseStyle,
    FortuneInlineTextRun run,
    Object? script,
  ) {
    final explicitShift = _inlineRunDoubleExtra(run, 'rtfBaselineShiftPt');
    if (explicitShift != null && explicitShift.isFinite && explicitShift != 0) {
      return -explicitShift;
    }
    return _scriptBaselineShift(baseStyle, run, script);
  }

  double? _inlineRunDoubleExtra(FortuneInlineTextRun run, String key) {
    final value = run.extraFields[key];
    if (value is num) {
      return value.toDouble();
    }
    return double.tryParse('$value');
  }

  double _scriptBaselineShift(
    TextStyle baseStyle,
    FortuneInlineTextRun run,
    Object? script,
  ) {
    final scaledFontSize = run.fontSize;
    final baseFontSize = scaledFontSize == null
        ? baseStyle.fontSize ?? 10
        : scaledFontSize / fortuneInlineScriptFontSizeScale;
    return switch (script) {
      'superscript' =>
        baseFontSize * fortuneInlineSuperscriptBaselineShiftScale,
      'subscript' => baseFontSize * fortuneInlineSubscriptBaselineShiftScale,
      _ => 0,
    };
  }

  TextStyle _styleForRun(
    TextStyle baseStyle,
    FortuneInlineTextRun run, {
    Color? selectedBackgroundColor,
  }) {
    final lineHeight = _inlineRunDoubleExtra(run, 'lineHeight');
    final smallCaps = run.extraFields['rtfSmallCaps'] == true;
    final fontSize = run.fontSize ?? baseStyle.fontSize;
    return baseStyle.copyWith(
      color: run.foreground ?? baseStyle.color,
      backgroundColor:
          selectedBackgroundColor ?? _inlineRunBackgroundColor(run),
      fontSize: smallCaps && fontSize != null ? fontSize * 0.82 : fontSize,
      height: lineHeight != null && lineHeight.isFinite && lineHeight > 0
          ? lineHeight
          : run.fontSize == null
          ? baseStyle.height
          : 1.2,
      letterSpacing: _inlineRunDoubleExtra(run, 'letterSpacing'),
      fontFamily: _normalizedRunFontFamily(run.fontFamily, baseStyle),
      fontWeight: run.bold == null
          ? baseStyle.fontWeight
          : run.bold!
          ? FontWeight.w700
          : FontWeight.w400,
      fontStyle: run.italic == null
          ? baseStyle.fontStyle
          : run.italic!
          ? FontStyle.italic
          : FontStyle.normal,
      decoration: _runTextDecoration(run, baseStyle.decoration),
      decorationStyle: _runTextDecorationStyle(run, baseStyle.decorationStyle),
      shadows: _runTextShadows(run, baseStyle.shadows),
    );
  }

  String _rtfDisplayText(String text, FortuneInlineTextRun run) {
    if (run.extraFields['rtfAllCaps'] == true ||
        run.extraFields['rtfSmallCaps'] == true) {
      return text.toUpperCase();
    }
    return text;
  }

  Color? _inlineRunBackgroundColor(FortuneInlineTextRun run) {
    final raw = run.extraFields['bg'];
    if (raw == null) {
      return null;
    }
    if (raw is Color) {
      return raw;
    }
    return FortuneSheetCodec.parseColor('$raw');
  }

  Color? _selectedInlineRunBackgroundColor(FortuneInlineTextRun run) {
    final background = _inlineRunBackgroundColor(run);
    if (background == null) {
      return null;
    }
    final opaqueBackground = Color.alphaBlend(
      background,
      const Color(0xffffffff),
    );
    final selectionColor = opaqueBackground.computeLuminance() < 0.35
        ? _fortuneEditorLightSelectionBackgroundColor
        : fortuneSheetSelectionColor;
    return Color.alphaBlend(
      selectionColor.withAlpha(_fortuneEditorSelectionBackgroundAlpha),
      opaqueBackground,
    );
  }

  String? _normalizedRunFontFamily(String? raw, TextStyle baseStyle) {
    final resolver = fontFamilyResolver;
    if (resolver != null) {
      return resolver(raw, baseStyle);
    }
    if (raw == null || raw.trim().isEmpty) {
      return baseStyle.fontFamily;
    }
    final index = int.tryParse(raw);
    if (index != null && index >= 0 && index < fortuneFontArray.length) {
      return fortuneFontArray[index];
    }
    return raw.replaceAll('"', '').replaceAll("'", '').trim();
  }

  TextDecoration? _runTextDecoration(
    FortuneInlineTextRun run,
    TextDecoration? fallback,
  ) {
    final decorations = [
      if (run.underline == true) TextDecoration.underline,
      if (run.strikeThrough == true) TextDecoration.lineThrough,
    ];
    if (decorations.isEmpty) {
      return fallback;
    }
    return TextDecoration.combine(decorations);
  }

  TextDecorationStyle? _runTextDecorationStyle(
    FortuneInlineTextRun run,
    TextDecorationStyle? fallback,
  ) {
    return switch (run.extraFields['rtfUnderlineStyle']) {
      'uldb' => TextDecorationStyle.double,
      'uld' ||
      'uldash' ||
      'uldashd' ||
      'uldashdd' ||
      'ulthdash' ||
      'ulthdashd' ||
      'ulthdashdd' ||
      'ulthldash' => TextDecorationStyle.dashed,
      'ulwave' || 'ulhwave' || 'ululdbwave' => TextDecorationStyle.wavy,
      _ => fallback,
    };
  }

  List<Shadow>? _runTextShadows(
    FortuneInlineTextRun run,
    List<Shadow>? fallback,
  ) {
    if (run.extraFields['rtfShadow'] != true) {
      return fallback;
    }
    return [
      ...?fallback,
      const Shadow(
        offset: Offset(1, 1),
        blurRadius: 0,
        color: Color(0x66000000),
      ),
    ];
  }

  void _ensureRunsForText() {
    _runs = _runsForText(text, _runs);
  }

  void _syncRunsForTextChange(
    TextEditingValue previousValue,
    TextEditingValue nextValue,
  ) {
    if (!_hasInlineRuns) {
      _runs = nextValue.text.isEmpty
          ? const <FortuneInlineTextRun>[]
          : [
              FortuneInlineTextRun(
                text: nextValue.text,
                rawText: nextValue.text,
                hasRawText: true,
              ),
            ];
      return;
    }
    final oldText = previousValue.text;
    final newText = nextValue.text;
    var prefix = 0;
    while (prefix < oldText.length &&
        prefix < newText.length &&
        oldText.codeUnitAt(prefix) == newText.codeUnitAt(prefix)) {
      prefix += 1;
    }
    var oldSuffix = oldText.length;
    var newSuffix = newText.length;
    while (oldSuffix > prefix &&
        newSuffix > prefix &&
        oldText.codeUnitAt(oldSuffix - 1) ==
            newText.codeUnitAt(newSuffix - 1)) {
      oldSuffix -= 1;
      newSuffix -= 1;
    }
    final inserted = newText.substring(prefix, newSuffix);
    final before = _sliceRuns(0, prefix);
    final after = _sliceRuns(oldSuffix, oldText.length);
    final styleRun =
        _runAtOffsetInRuns(
          _runs,
          previousValue.selection.start,
          oldText.length,
        ) ??
        (before.isNotEmpty
            ? before.last
            : after.isNotEmpty
            ? after.first
            : const FortuneInlineTextRun(text: ''));
    final insertedRuns = inserted.isEmpty
        ? const <FortuneInlineTextRun>[]
        : [
            styleRun.copyWith(
              text: inserted,
              rawText: inserted,
              hasRawText: true,
            ),
          ];
    _runs = _mergeAdjacentRuns([...before, ...insertedRuns, ...after]);
  }

  List<FortuneInlineTextRun> _sliceRuns(int startOffset, int endOffset) {
    if (startOffset >= endOffset || _runs.isEmpty) {
      return const <FortuneInlineTextRun>[];
    }
    final sliced = <FortuneInlineTextRun>[];
    var cursor = 0;
    for (final run in _runs) {
      final runStart = cursor;
      final runEnd = cursor + run.text.length;
      cursor = runEnd;
      if (endOffset <= runStart || startOffset >= runEnd) {
        continue;
      }
      final localStart = math.max(0, startOffset - runStart);
      final localEnd = math.min(run.text.length, endOffset - runStart);
      if (localStart < localEnd) {
        final text = run.text.substring(localStart, localEnd);
        sliced.add(run.copyWith(text: text, rawText: text, hasRawText: true));
      }
    }
    return sliced;
  }

  FortuneInlineTextRun? _runAtOffsetInRuns(
    List<FortuneInlineTextRun> runs,
    int offset,
    int textLength,
  ) {
    if (runs.isEmpty || textLength <= 0) {
      return null;
    }
    final target = offset <= 0 ? 0 : math.min(offset - 1, textLength - 1);
    var cursor = 0;
    for (final run in runs) {
      final nextCursor = cursor + run.text.length;
      if (target < nextCursor) {
        return run;
      }
      cursor = nextCursor;
    }
    return runs.last;
  }

  FortuneInlineTextRun _runWithText(FortuneInlineTextRun run, String text) {
    return run.copyWith(text: text, rawText: text, hasRawText: true);
  }

  List<FortuneInlineTextRun> _runsForText(
    String text,
    List<FortuneInlineTextRun> runs,
  ) {
    if (text.isEmpty) {
      return const <FortuneInlineTextRun>[];
    }
    if (runs.isEmpty) {
      return [
        FortuneInlineTextRun(text: text, rawText: text, hasRawText: true),
      ];
    }
    final joined = runs.map((run) => run.text).join();
    if (joined == text) {
      return _mergeAdjacentRuns(runs);
    }
    return [runs.first.copyWith(text: text, rawText: text, hasRawText: true)];
  }

  List<FortuneInlineTextRun> _mergeAdjacentRuns(
    List<FortuneInlineTextRun> runs,
  ) {
    final merged = <FortuneInlineTextRun>[];
    for (final run in runs) {
      if (run.text.isEmpty) {
        continue;
      }
      if (merged.isNotEmpty && _sameRunStyle(merged.last, run)) {
        final text = '${merged.last.text}${run.text}';
        merged[merged.length - 1] = merged.last.copyWith(
          text: text,
          rawText: text,
          hasRawText: true,
        );
      } else {
        merged.add(run.copyWith());
      }
    }
    return merged;
  }

  bool _sameRunStyle(FortuneInlineTextRun left, FortuneInlineTextRun right) {
    return left.foreground == right.foreground &&
        left.bold == right.bold &&
        left.italic == right.italic &&
        left.strikeThrough == right.strikeThrough &&
        left.underline == right.underline &&
        left.fontSize == right.fontSize &&
        left.fontFamily == right.fontFamily &&
        left.wrap == right.wrap &&
        left.extraFields.length == right.extraFields.length &&
        left.extraFields.entries.every(
          (entry) => right.extraFields[entry.key] == entry.value,
        );
  }
}

