      case 'setCellFormat':
        if (args.length >= 4 && args[2] is String) {
          final row = _apiCallInt(args[0]);
          final column = _apiCallInt(args[1]);
          if (row != null && column != null) {
            final options = _apiCallOptions(args.length > 4 ? args[4] : null);
            if (options == null) {
