  @override
  void initState() {
    super.initState();
    widget.controller?._attach(this);
    _workbook = _effectiveWorkbook(widget.workbook);
    selection = _selectionFromSheet(_workbook.activeSheet);
    _editorController.addListener(_handleEditorValueChanged);
    _focusNode.addListener(_handleSheetFocusChanged);
    _imageInsertWidthController.addListener(_handleImageInsertWidthChanged);
    _imageInsertHeightController.addListener(_handleImageInsertHeightChanged);
    _barcodeTextController.addListener(_handleBarcodeTextChanged);
    _barcodeWidthController.addListener(_handleBarcodeWidthChanged);
    _barcodeHeightController.addListener(_handleBarcodeHeightChanged);
    for (final input in _imageInsertDialogInputs) {
      input.focusNode.addListener(_handleImageInsertInputFocusChanged);
    }
    for (final input in _barcodeDialogInputs) {
      input.focusNode.addListener(_handleBarcodeInputFocusChanged);
    }
    for (final node in _contextMenuInlineInputFocusNodes.values) {
      node.addListener(_handleContextMenuInlineInputFocusChanged);
    }
    _recalculateWorkbookFormulas();
    _loadAvailableFontFamilies();
    _scheduleImageDecodes();
    _notifyWorkbookChangedAfterFrame();
    _notifySelectionChangedAfterFrame();
  }

  void _handleEditorValueChanged() {
    if (_editingCoord == null || !mounted) {
      return;
    }
    final previousValue = _editorTraceLastValue;
    final currentValue = _editorController.value;
    // [재사용 금지] 한글 IME 잔여 조합(예: 차→챀, 다→달)을 조합 도중
    // userUpdateTextEditingValue 로 즉시 복원하는 방식(구 _restoreImeResidualAfterCaret
    // / _trackImeResidualRestoreCandidate)은 Windows 한글 IME 를 desync 시켜
    // 잔여형을 재주입하고 다음 글자를 삼키는 오동작(글자 씹힘)을 유발한다.
    // 근거: .tmp/app_2026-07-01_16-32-12.log (#1840~#1853: 가→간 복원 후 '나' 씹힘 등,
    // 총 8회 복원 모두 위험). 활성 조합 중 controller 값 강제 변경 금지.
    if (previousValue != null &&
        currentValue.composing.isValid &&
        currentValue.composing.isCollapsed &&
        (!previousValue.composing.isValid ||
            previousValue.composing.start != currentValue.composing.start)) {
      _editorImeCompositionBaseValue = currentValue;
    }
    if (previousValue != null &&
        previousValue.composing.isValid &&
        previousValue.text != currentValue.text &&
        currentValue.text.length <= previousValue.text.length) {
      _editorSkipDeletionKeyUntil = DateTime.now().add(
        const Duration(milliseconds: 200),
      );
      _editorImeResidualDeletionValue =
          _valueHasImeResidualAfterCaret(
            previousValue,
            currentValue,
            _editorImeCompositionBaseValue,
          )
          ? currentValue
          : null;
    } else if (previousValue != null &&
        _editorImeResidualDeletionValue == previousValue &&
        previousValue.text == currentValue.text &&
        previousValue.selection == currentValue.selection &&
        previousValue.composing.isValid &&
        previousValue.composing.isCollapsed &&
        !currentValue.composing.isValid) {
      _editorImeResidualDeletionValue = currentValue;
    }
    _traceCellEditor(
      'valueChanged',
      previousValue: previousValue,
      value: currentValue,
    );
    _editorTraceLastValue = currentValue;
    if (_editorInlineHistoryText != _editorController.text) {
      _clearEditorInlineHistory(keepCurrentText: true);
    }
    _logEditorDebug('valueChanged');
    _rememberInlineToolbarSelectionRange();
    // 활성 조합(composing) 도중에는 캔버스 전체 rebuild(_setState 오버라이드의
    // 워크북 clone+JSON diff)와 캐럿 reveal 스크롤(bringIntoView)을 건너뛴다.
    // 조합 중 매 키 입력마다 부모를 rebuild/스크롤하면 Windows 한글 IME 가
    // desync 되어 잔여 확장형(예: 나→낟)이 조합 붕괴 시 교정되지 못하고 커서
    // 오른쪽에 고착되는 오동작이 발생한다.
    // 근거: .tmp/app_2026-07-01_17-43-14.log #22→#23 (가낟 composing 1-2 →
    // composing 1-1 붕괴 시 텍스트 미교정 → 이후 입력이 낟 앞에 삽입되어 '가라낟').
    // 에디터 텍스트는 EditableText 가 자체 컨트롤러로 렌더링하므로 부모 rebuild
    // 를 건너뛰어도 조합 텍스트 표시에는 영향이 없다. 조합이 확정/붕괴(-1 또는
    // collapsed)되어 실제 커밋될 때만 갱신한다.
    final composingActive =
        currentValue.composing.isValid && !currentValue.composing.isCollapsed;
    if (composingActive) {
      return;
    }
    _scheduleEditorCaretReveal();
    setState(() {});
  }

  void _handleEditorSelectionChanged(
    TextSelection selection,
    SelectionChangedCause? cause,
  ) {
    _traceCellEditor(
      'selectionChanged',
      selection: selection,
      selectionCause: cause,
    );
    _rememberEditorSelection(selection);
  }

  void _handleContextMenuInlineInputFocusChanged() {
    for (final entry in _contextMenuInlineInputFocusNodes.entries) {
      if (entry.value.hasFocus) {
        continue;
      }
      final controller = _contextMenuInlineInputControllers[entry.key];
      if (controller == null || controller.selection.isCollapsed) {
        continue;
      }
      final offset = controller.selection.extentOffset.clamp(
        0,
        controller.text.length,
      );
      controller.selection = TextSelection.collapsed(offset: offset);
    }
  }

  void _handleSheetFocusChanged() {
    if (!_focusNode.hasFocus) {
      _clearSheetRulerSelection();
    }
  }

  void _handleBarcodeTextChanged() {
    if (!_barcodeDialogOpen || !mounted) {
      return;
    }
    setState(() {
      if (_barcodeErrorText == '내용을 입력하세요.' && _barcodeCanConfirm) {
        _barcodeErrorText = null;
      }
    });
  }

  void _resetEditorInlineHistory() {
    _editorInlineUndoStack.clear();
    _editorInlineRedoStack.clear();
    _editorInlineHistoryText = _editorController.text;
  }

  void _clearEditorInlineHistory({bool keepCurrentText = false}) {
    _editorInlineUndoStack.clear();
    _editorInlineRedoStack.clear();
    if (keepCurrentText) {
      _editorInlineHistoryText = _editorController.text;
    } else {
      _editorInlineHistoryText = '';
    }
  }

  _EditorInlineHistorySnapshot _currentEditorInlineSnapshot() {
    return _EditorInlineHistorySnapshot(
      value: _editorController.value,
      runs: [for (final run in _editorController._runs) run.copyWith()],
      hasInlineRuns: _editorController._hasInlineRuns,
      inlineToolbarSelectionRange: _inlineToolbarSelectionRange,
    );
  }

  void _recordEditorInlineUndoSnapshot() {
    if (_editingCoord == null) {
      return;
    }
    _editorInlineUndoStack.add(_currentEditorInlineSnapshot());
    if (_editorInlineUndoStack.length > _maxUndoSnapshots) {
      _editorInlineUndoStack.removeAt(0);
    }
    _editorInlineRedoStack.clear();
    _editorInlineHistoryText = _editorController.text;
  }

  bool _undoEditorInlineFormat() {
    while (_editorInlineUndoStack.isNotEmpty) {
      final snapshot = _editorInlineUndoStack.removeLast();
      if (snapshot.value.text != _editorController.text) {
        continue;
      }
      _editorInlineRedoStack.add(_currentEditorInlineSnapshot());
      _restoreEditorInlineSnapshot(snapshot);
      return true;
    }
    return false;
  }

  bool _redoEditorInlineFormat() {
    while (_editorInlineRedoStack.isNotEmpty) {
      final snapshot = _editorInlineRedoStack.removeLast();
      if (snapshot.value.text != _editorController.text) {
        continue;
      }
      _editorInlineUndoStack.add(_currentEditorInlineSnapshot());
      _restoreEditorInlineSnapshot(snapshot);
      return true;
    }
    return false;
  }

  void _restoreEditorInlineSnapshot(_EditorInlineHistorySnapshot snapshot) {
    _editorController._runs = [for (final run in snapshot.runs) run.copyWith()];
    _editorController._hasInlineRuns = snapshot.hasInlineRuns;
    _editorController._replacingValue = true;
    _editorController.value = snapshot.value;
    _editorController._replacingValue = false;
    _inlineToolbarSelectionRange = snapshot.inlineToolbarSelectionRange;
    _editorInlineHistoryText = snapshot.value.text;
    _editorFocusNode.requestFocus();
    _syncEditorPlatformEditingState(snapshot.value);
    setState(() {});
  }

  void _scheduleEditorCaretReveal() {
    if (_editorCaretRevealScheduled) {
      return;
    }
    _editorCaretRevealScheduled = true;
    final session = _editorTextMutationSession;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _editorCaretRevealScheduled = false;
      if (!mounted ||
          _editingCoord == null ||
          session != _editorTextMutationSession) {
        return;
      }
      _revealEditorCaret();
    });
  }

  void _revealEditorCaret() {
    final editableState = _editorEditableKey.currentState;
    if (editableState == null || !_editorScrollController.hasClients) {
      return;
    }
    final selection = _editorController.selection;
    if (!selection.isValid) {
      return;
    }
    final offset = math.min(
      math.max(selection.extentOffset, 0),
      _editorController.text.length,
    );
    editableState.bringIntoView(TextPosition(offset: offset));
  }

  @override
  void setState(VoidCallback fn) {
    final previousWorkbook = _cloneWorkbook(_workbook);
    final previousSheetId = _workbook.activeSheet.id;
    final previousSelection = selection;
    super.setState(fn);
    if (_workbookJsonChanged(previousWorkbook, _workbook)) {
      _queueOrNotifyWorkbookChanged(
        _workbook,
        previousWorkbook: previousWorkbook,
      );
    }
    if (previousSheetId != _workbook.activeSheet.id ||
        !_sameSelection(previousSelection, selection)) {
      _queueOrNotifySelectionChanged(previousSheetId, previousSelection);
    }
  }

  void _runControllerApiBatch(VoidCallback fn) {
    if (_controllerApiBatchDepth == 0) {
      _batchedUndoSnapshotRecorded = false;
      _batchedInitialUndoStackLength = _undoStack.length;
      _batchedInitialRedoStack = [..._redoStack];
    }
    _controllerApiBatchDepth += 1;
    try {
      fn();
    } finally {
      _controllerApiBatchDepth -= 1;
      if (_controllerApiBatchDepth == 0) {
        _flushControllerApiBatchNotifications();
        _batchedUndoSnapshotRecorded = false;
        _batchedInitialUndoStackLength = null;
        _batchedInitialRedoStack = null;
      }
    }
  }

  void _queueOrNotifyWorkbookChanged(
    FortuneWorkbook workbook, {
    FortuneWorkbook? previousWorkbook,
    bool force = false,
  }) {
    if (_controllerApiBatchDepth > 0) {
      _batchedPreviousWorkbook ??= previousWorkbook;
      _batchedForceWorkbookChange = _batchedForceWorkbookChange || force;
      if (_suppressNextOnOp) {
        _batchedSuppressOnOp = true;
        _suppressNextOnOp = false;
      }
      return;
    }
    _notifyWorkbookChanged(workbook, previousWorkbook: previousWorkbook);
  }

  void _queueOrNotifySelectionChanged(
    String previousSheetId,
    FortuneSelection previousSelection,
  ) {
    if (_controllerApiBatchDepth > 0) {
      _batchedPreviousSheetId ??= previousSheetId;
      _batchedPreviousSelection ??= previousSelection;
      return;
    }
    _notifySelectionChanged();
  }

  void _flushControllerApiBatchNotifications() {
    final previousWorkbook = _batchedPreviousWorkbook;
    final forceWorkbookChange = _batchedForceWorkbookChange;
    final suppressOnOp = _batchedSuppressOnOp;
    final previousSheetId = _batchedPreviousSheetId;
    final previousSelection = _batchedPreviousSelection;
    final hasWorkbookChange =
        previousWorkbook != null &&
        _workbookJsonChanged(previousWorkbook, _workbook);
    _batchedPreviousWorkbook = null;
    _batchedForceWorkbookChange = false;
    _batchedSuppressOnOp = false;
    _batchedPreviousSheetId = null;
    _batchedPreviousSelection = null;

    if (previousWorkbook != null &&
        (forceWorkbookChange || hasWorkbookChange)) {
      if (suppressOnOp) {
        _suppressNextOnOp = true;
      }
      _notifyWorkbookChanged(_workbook, previousWorkbook: previousWorkbook);
    } else if (!forceWorkbookChange) {
      _restoreControllerApiBatchHistory();
    }
    if (previousSheetId != null &&
        previousSelection != null &&
        (previousSheetId != _workbook.activeSheet.id ||
            !_sameSelection(previousSelection, selection))) {
      _notifySelectionChanged();
    }
  }

  void _restoreControllerApiBatchHistory() {
    final undoLength = _batchedInitialUndoStackLength;
    final redoStack = _batchedInitialRedoStack;
    if (undoLength != null && _undoStack.length > undoLength) {
      _undoStack.removeRange(undoLength, _undoStack.length);
    }
    if (redoStack != null) {
      _redoStack
        ..clear()
        ..addAll(redoStack);
    }
  }

  bool _workbookJsonChanged(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    return jsonEncode(FortuneSheetCodec.workbookToJson(previousWorkbook)) !=
        jsonEncode(FortuneSheetCodec.workbookToJson(workbook));
  }

  @override
  void didUpdateWidget(covariant FortuneSheetCanvas oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.controller != widget.controller) {
      oldWidget.controller?._detach(this);
      widget.controller?._attach(this);
    }
    final workbookChanged = oldWidget.workbook != widget.workbook;
    final settingsChanged =
        oldWidget.settings != widget.settings ||
        oldWidget.showFormulaBar != widget.showFormulaBar ||
        oldWidget.showSheetTabs != widget.showSheetTabs;
    final onChangeAttached =
        oldWidget.onChange == null && widget.onChange != null;
    final previousSelectionHook =
        (oldWidget.settings ?? oldWidget.workbook.settings)
            .afterSelectionChange;
    if (!workbookChanged && !settingsChanged) {
      if (onChangeAttached) {
        _notifyWorkbookChangedAfterFrame();
      }
      return;
    }

    _workbook = workbookChanged
        ? _effectiveWorkbook(widget.workbook)
        : _workbook.copyWith(settings: _effectiveSettings(widget.workbook));
    _recalculateWorkbookFormulas();
    _loadAvailableFontFamilies();
    _scheduleImageDecodes();
    if (workbookChanged) {
      _resetTransientStateForWorkbookChange();
    }
    _notifyWorkbookChangedAfterFrame();
    if (workbookChanged ||
        previousSelectionHook != _workbook.settings.afterSelectionChange) {
      _notifySelectionChangedAfterFrame();
    }
  }

  FortuneSettings _effectiveSettings(FortuneWorkbook workbook) {
    final settings = widget.settings ?? workbook.settings;
    final showFormulaBar = widget.showFormulaBar;
    final showSheetTabs = widget.showSheetTabs;
    return showFormulaBar == null && showSheetTabs == null
        ? settings
        : settings.copyWith(
            showFormulaBar: showFormulaBar,
            showSheetTabs: showSheetTabs,
          );
  }

