  Future<FortuneImagePickResult?> _pickImageFromFileSystem() async {
    const imageGroup = XTypeGroup(
      label: 'Images',
      extensions: <String>[
        'png',
        'jpg',
        'jpeg',
        'gif',
        'bmp',
        'webp',
        'tif',
        'tiff',
      ],
      mimeTypes: <String>['image/*'],
    );
    final file = await openFile(
      acceptedTypeGroups: const <XTypeGroup>[imageGroup],
    );
    if (file == null) {
      return null;
    }
    final bytes = await file.readAsBytes();
    if (bytes.isEmpty) {
      return null;
    }
    return FortuneImagePickResult(
      bytes: bytes,
      fileName: file.name,
      mimeType: _imageMimeTypeForName(file.name),
    );
  }

  static String _imageMimeTypeForName(String fileName) {
    final extension = fileName.split('.').last.toLowerCase();
    return switch (extension) {
      'jpg' || 'jpeg' => 'image/jpeg',
      'gif' => 'image/gif',
      'bmp' => 'image/bmp',
      'webp' => 'image/webp',
      'tif' || 'tiff' => 'image/tiff',
      _ => 'image/png',
    };
  }

  static String _imageDataUri(FortuneImagePickResult result) {
    return _bytesDataUri(result.bytes, result.mimeType);
  }

  static String _bytesDataUri(Uint8List bytes, String mimeType) {
    return 'data:$mimeType;base64,${base64Encode(bytes)}';
  }

  void _scheduleImageDecodes() {
    for (final image in _workbook.activeSheet.images) {
      _decodeImageIfNeeded(image.src);
    }
  }

  void _decodeImageIfNeeded(String src) {
    if (src.isEmpty ||
        _decodedImages.containsKey(src) ||
        _imageDecodeInProgress.contains(src)) {
      return;
    }
    final bytes = _bytesFromImageDataUri(src);
    if (bytes == null) {
      return;
    }
    _imageDecodeInProgress.add(src);
    unawaited(
      _decodeImageBytes(bytes).then((image) {
        _imageDecodeInProgress.remove(src);
        if (image == null) {
          return;
        }
        if (!mounted) {
          image.dispose();
          return;
        }
        setState(() {
          _decodedImages[src] = image;
        });
      }),
    );
  }

  static Uint8List? _bytesFromImageDataUri(String src) {
    final comma = src.indexOf(',');
    if (comma <= 0 ||
        !src.substring(0, comma).toLowerCase().contains('base64')) {
      return null;
    }
    try {
      return base64Decode(src.substring(comma + 1));
    } on FormatException {
      return null;
    }
  }

  FortuneWorkbook _cloneWorkbook(FortuneWorkbook workbook) {
    return FortuneSheetCodec.workbookFromJson(
      FortuneSheetCodec.workbookToJson(workbook),
      settings: workbook.settings,
    );
  }

  FortuneWorkbook _effectiveWorkbook(FortuneWorkbook workbook) {
    final settings = _effectiveSettings(workbook);
    return settings == workbook.settings
        ? workbook
        : workbook.copyWith(settings: settings);
  }

  void _loadAvailableFontFamilies() {
    final generation = ++_fontLoadGeneration;
    final settings = _workbook.settings;
    final provider =
        settings.fontProvider ?? FortuneSystemFonts.loadFontFamilies;
    provider()
        .then((families) {
          if (!mounted || generation != _fontLoadGeneration) {
            return;
          }
          final collapsedFamilies = <String>[];
          final duplicateFamilies = <String>[];
          final filteredFamilies = <String>[];
          final nextFamilies = fortuneSortFontFamilies(
            fortuneMergeFontFamilies(
              families,
              onCollapsedFamily: (source, family) {
                collapsedFamilies.add('$source -> $family');
              },
              onDuplicateFamily: (source, family) {
                duplicateFamilies.add('$source -> $family');
              },
              onFilteredFamily: filteredFamilies.add,
            ),
            preferred: widget.locale.preferredFontFamilies,
          );
          fortuneSheetDebugLog(
            'font canvas merge provider=${families.length} '
            'previous=${settings.fontFamilies.length} next=${nextFamilies.length} '
            'collapsed=${collapsedFamilies.length} duplicates=${duplicateFamilies.length} '
            'filtered=${filteredFamilies.length}',
          );
          for (final collapse in collapsedFamilies.take(80)) {
            fortuneSheetDebugLog('font canvas collapse $collapse');
          }
          for (final duplicate in duplicateFamilies.take(80)) {
            fortuneSheetDebugLog('font canvas duplicate $duplicate');
          }
          for (final filtered in filteredFamilies.take(80)) {
            fortuneSheetDebugLog('font canvas filtered $filtered');
          }
          for (final line in fortuneFontFamilyDebugListLines(
            'canvas',
            nextFamilies,
          )) {
            fortuneSheetDebugLog(line);
          }
          if (_stringListsEqual(settings.fontFamilies, nextFamilies)) {
            return;
          }
          _workbook = _workbook.copyWith(
            settings: _workbook.settings.copyWith(fontFamilies: nextFamilies),
          );
          super.setState(() {});
        })
        .catchError((Object _) {});
  }

  FortuneSelection _selectionFromSheet(FortuneSheet sheet) {
    final raw = sheet.selectionSave;
    if (raw is! List || raw.isEmpty) {
      return _defaultSelectionFromSheet(sheet);
    }
    final first = raw.first;
    if (first is! Map) {
      return _defaultSelectionFromSheet(sheet);
    }
    final row = first['row'];
    final column = first['column'];
    if (row is! List ||
        row.length < 2 ||
        column is! List ||
        column.length < 2) {
      return _defaultSelectionFromSheet(sheet);
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return _defaultSelectionFromSheet(sheet);
    }
    final normalizedRowStart = math.min(rowStart, rowEnd);
    final normalizedRowEnd = math.max(rowStart, rowEnd);
    final normalizedColumnStart = math.min(columnStart, columnEnd);
    final normalizedColumnEnd = math.max(columnStart, columnEnd);
    final rowFocus = _intValue(first['row_focus']) ?? normalizedRowStart;
    final columnFocus =
        _intValue(first['column_focus']) ?? normalizedColumnStart;
    return FortuneSelection(
      row: rowFocus,
      column: columnFocus,
      rowEnd: rowFocus == normalizedRowEnd
          ? normalizedRowStart
          : normalizedRowEnd,
      columnEnd: columnFocus == normalizedColumnEnd
          ? normalizedColumnStart
          : normalizedColumnEnd,
    );
  }

  Offset _scrollOffsetFromSheet(FortuneSheet sheet) {
    return _sheetScrollOffsets[sheet.id] ?? Offset.zero;
  }

  void _rememberActiveSheetScrollOffset() {
    _sheetScrollOffsets[_workbook.activeSheet.id] = scrollOffset;
  }

  void _activateSheetAtIndex(int sheetIndex) {
    final sheets = [..._workbook.sheets];
    final targetSheet = sheets[sheetIndex].copyWith(
      selectionRange: const [],
      hasRawSelectionRange: true,
    );
    sheets[sheetIndex] = targetSheet;
    _workbook = _workbook.copyWith(
      sheets: sheets,
      activeSheetIndex: sheetIndex,
    );
    _activeImageId = null;
    selection = _selectionFromSheet(targetSheet);
    scrollOffset = _scrollOffsetFromSheet(targetSheet);
  }

  FortuneSelection _defaultSelectionFromSheet(FortuneSheet sheet) {
    final merge = sheet.cells[const FortuneCellCoord(0, 0)]?.merge;
    if (merge == null || (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
      return const FortuneSelection(row: 0, column: 0);
    }
    final rowSpan = merge.rowSpan < 1 ? 1 : merge.rowSpan;
    final columnSpan = merge.columnSpan < 1 ? 1 : merge.columnSpan;
    return FortuneSelection(
      row: merge.row,
      column: merge.column,
      rowEnd: merge.row + rowSpan - 1,
      columnEnd: merge.column + columnSpan - 1,
    );
  }

  void _notifyWorkbookChanged(
    FortuneWorkbook workbook, {
    FortuneWorkbook? previousWorkbook,
  }) {
    final suppressOnOp = _suppressNextOnOp;
    _suppressNextOnOp = false;
    widget.onChange?.call(_cloneWorkbook(workbook));
    if (!suppressOnOp && previousWorkbook != null && widget.onOp != null) {
      final ops = _workbookChangeOps(previousWorkbook, workbook);
      if (ops.isNotEmpty) {
        widget.onOp!(ops);
      }
    }
  }

  List<FortuneOp> _workbookChangeOps(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    final pendingOps = _takePendingOnOpOps();
    final sheetOps = _sheetListChangeOps(previousWorkbook, workbook);
    if (sheetOps.isNotEmpty) {
      return [...pendingOps, ...sheetOps];
    }
    final sheetMetadataOps = _sheetMetadataChangeOps(
      previousWorkbook,
      workbook,
    );
    final sheetConfigOps = _sheetConfigChangeOps(previousWorkbook, workbook);
    final sheetTopLevelOps = _sheetTopLevelChangeOps(
      previousWorkbook,
      workbook,
    );
    final cellOps = _cellChangeOps(previousWorkbook, workbook);
    if (sheetMetadataOps.isNotEmpty ||
        sheetConfigOps.isNotEmpty ||
        sheetTopLevelOps.isNotEmpty ||
        cellOps.isNotEmpty) {
      return [
        ...pendingOps,
        ...sheetMetadataOps,
        ...sheetConfigOps,
        ...sheetTopLevelOps,
        ...cellOps,
      ];
    }
    final previousData = FortuneSheetCodec.workbookToJson(
      previousWorkbook,
    )['data'];
    final data = FortuneSheetCodec.workbookToJson(workbook)['data'];
    if (jsonEncode(previousData) == jsonEncode(data)) {
      return pendingOps;
    }
    return [
      ...pendingOps,
      {
        'op': 'replace',
        'path': const ['data'],
        'value': cloneFortuneMetadata(data),
      },
    ];
  }

  List<FortuneOp> _takePendingOnOpOps() {
    final ops = _pendingOnOpOps;
    _pendingOnOpOps = null;
    return ops == null ? const [] : [...ops];
  }

  void _queueRowColOnOp(String op, Map<String, Object?> value) {
    _pendingOnOpOps = [
      {
        'op': op,
        'id': value['id'],
        'path': const <Object?>[],
        'value': cloneFortuneMetadata(value),
      },
    ];
  }

  List<FortuneOp> _sheetListChangeOps(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    final previousSheets = previousWorkbook.sheets;
    final sheets = workbook.sheets;
    if (sheets.length == previousSheets.length + 1) {
      final addedIndex = _singleInsertedSheetIndex(previousSheets, sheets);
      if (addedIndex != null) {
        final addedSheet = sheets[addedIndex];
        return [
          {
            'op': 'addSheet',
            'id': addedSheet.id,
            'path': const <Object?>[],
            'value': cloneFortuneMetadata(
              FortuneSheetCodec.sheetToJson(addedSheet),
            ),
          },
          ..._restoredDeletedSheetOps(addedSheet, sheets, addedIndex),
        ];
      }
    }
    if (sheets.length + 1 == previousSheets.length) {
      final deletedIndex = _singleInsertedSheetIndex(sheets, previousSheets);
      if (deletedIndex != null) {
        final deletedSheet = previousSheets[deletedIndex];
        return [
          {
            'op': 'deleteSheet',
            'id': deletedSheet.id,
            'path': const <Object?>[],
            'value': cloneFortuneMetadata(
              FortuneSheetCodec.sheetToJson(deletedSheet),
            ),
          },
          ..._deletedSheetOrderOps(deletedSheet, sheets, deletedIndex),
        ];
      }
    }
    return const [];
  }

  List<FortuneOp> _restoredDeletedSheetOps(
    FortuneSheet addedSheet,
    List<FortuneSheet> sheets,
    int addedIndex,
  ) {
    if (addedIndex == sheets.length - 1) {
      return const [];
    }
    final addedOrder = addedSheet.order ?? addedIndex;
    final ops = <FortuneOp>[
      {
        'op': 'replace',
        'id': addedSheet.id,
        'path': const ['name'],
        'value': addedSheet.name,
      },
    ];
    for (var index = 0; index < sheets.length; index += 1) {
      final sheet = sheets[index];
      if (sheet.id == addedSheet.id) {
        continue;
      }
      final order = sheet.order ?? index;
      if (order < addedOrder) {
        continue;
      }
      ops.add({
        'op': 'replace',
        'id': sheet.id,
        'path': const ['order'],
        'value': order,
      });
    }
    return ops;
  }

  List<FortuneOp> _deletedSheetOrderOps(
    FortuneSheet deletedSheet,
    List<FortuneSheet> sheets,
    int deletedIndex,
  ) {
    final deletedOrder = deletedSheet.order ?? deletedIndex;
    final ops = <FortuneOp>[];
    for (var index = 0; index < sheets.length; index += 1) {
      final sheet = sheets[index];
      final order = sheet.order ?? index;
      if (order < deletedOrder) {
        continue;
      }
      ops.add({
        'op': 'replace',
        'id': sheet.id,
        'path': const ['order'],
        'value': order,
      });
    }
    return ops;
  }

  List<FortuneOp> _sheetMetadataChangeOps(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    final previousIds = [for (final sheet in previousWorkbook.sheets) sheet.id];
    final ids = [for (final sheet in workbook.sheets) sheet.id];
    if (previousIds.length != ids.length ||
        previousIds.toSet().length != previousIds.length ||
        ids.toSet().length != ids.length ||
        !previousIds.toSet().containsAll(ids)) {
      return const [];
    }

    final previousData = _workbookSheetDataById(previousWorkbook);
    final data = _workbookSheetDataById(workbook);
    final ops = <FortuneOp>[];
    const metadataKeys = [
      'name',
      'status',
      'hide',
      'color',
      'luckysheet_select_save',
    ];
    for (final id in ids) {
      final previousSheet = previousData[id];
      final sheet = data[id];
      if (previousSheet == null || sheet == null) {
        return const [];
      }
      for (final key in metadataKeys) {
        if (!_metadataValueChanged(previousSheet, sheet, key)) {
          continue;
        }
        ops.add({
          'op': sheet.containsKey(key) ? 'replace' : 'remove',
          'id': id,
          'path': [key],
          if (sheet.containsKey(key)) 'value': cloneFortuneMetadata(sheet[key]),
        });
      }
    }

    for (var index = 0; index < ids.length; index += 1) {
      if (previousIds[index] == ids[index]) {
        continue;
      }
      ops.add({
        'op': 'replace',
        'id': ids[index],
        'path': const ['order'],
        'value': index,
      });
    }
    return ops;
  }

  List<FortuneOp> _sheetConfigChangeOps(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    if (!_sameSheetOrder(previousWorkbook, workbook)) {
      return const [];
    }
    final previousData = _workbookSheetDataById(previousWorkbook);
    final data = _workbookSheetDataById(workbook);
    final ops = <FortuneOp>[];
    for (final sheet in workbook.sheets) {
      final previousSheetData = previousData[sheet.id];
      final sheetData = data[sheet.id];
      if (previousSheetData == null || sheetData == null) {
        return const [];
      }
      final previousConfig = _sheetConfigMap(previousSheetData);
      final config = _sheetConfigMap(sheetData);
      final keys = {...previousConfig.keys, ...config.keys}.toList()..sort();
      for (final key in keys) {
        if (!_metadataValueChanged(previousConfig, config, key)) {
          continue;
        }
        ops.add({
          'op': config.containsKey(key) ? 'replace' : 'remove',
          'id': sheet.id,
          'path': ['config', key],
          if (config.containsKey(key))
            'value': cloneFortuneMetadata(config[key]),
        });
      }
    }
    return ops;
  }

  List<FortuneOp> _sheetTopLevelChangeOps(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    if (!_sameSheetOrder(previousWorkbook, workbook)) {
      return const [];
    }
    final previousData = _workbookSheetDataById(previousWorkbook);
    final data = _workbookSheetDataById(workbook);
    final ops = <FortuneOp>[];
    const keys = [
      'images',
      'dataVerification',
      'filter',
      'filter_select',
      'calcChain',
      'luckysheet_conditionformat_save',
      'luckysheet_alternateformat_save',
      'pivotTable',
      'isPivotTable',
      'dynamicArray_compute',
      'dynamicArray',
      'frozen',
    ];
    for (final sheet in workbook.sheets) {
      final previousSheetData = previousData[sheet.id];
      final sheetData = data[sheet.id];
      if (previousSheetData == null || sheetData == null) {
        return const [];
      }
      for (final key in keys) {
        if (!_metadataValueChanged(previousSheetData, sheetData, key)) {
          continue;
        }
        ops.add({
          'op': sheetData.containsKey(key) ? 'replace' : 'remove',
          'id': sheet.id,
          'path': [key],
          if (sheetData.containsKey(key))
            'value': cloneFortuneMetadata(sheetData[key]),
        });
      }
    }
    return ops;
  }

  List<FortuneOp> _cellChangeOps(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    if (!_sameSheetOrder(previousWorkbook, workbook)) {
      return const [];
    }
    final ops = <FortuneOp>[];
    for (
      var sheetIndex = 0;
      sheetIndex < workbook.sheets.length;
      sheetIndex++
    ) {
      final previousSheet = previousWorkbook.sheets[sheetIndex];
      final sheet = workbook.sheets[sheetIndex];
      final coords =
          <FortuneCellCoord>{
            ...previousSheet.cells.keys,
            ...previousSheet.nullCells,
            ...sheet.cells.keys,
            ...sheet.nullCells,
          }.toList()..sort((left, right) {
            final rowCompare = left.row.compareTo(right.row);
            return rowCompare != 0
                ? rowCompare
                : left.column.compareTo(right.column);
          });
      for (final coord in coords) {
        final previousValue = _cellOpValue(previousSheet, coord);
        final value = _cellOpValue(sheet, coord);
        if (jsonEncode(previousValue) == jsonEncode(value)) {
          continue;
        }
        ops.add({
          'op': 'replace',
          'id': sheet.id,
          'path': ['data', coord.row, coord.column],
          'value': cloneFortuneMetadata(value),
        });
        final hyperlinkOp = _cellHyperlinkOp(sheet, coord, value);
        if (hyperlinkOp != null) {
          ops.add(hyperlinkOp);
        }
      }
    }
    return ops;
  }

  FortuneOp? _cellHyperlinkOp(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    Object? value,
  ) {
    if (value is! Map || value['hl'] == null) {
      return null;
    }
    final hyperlink = value['hl'];
    if (hyperlink is! Map) {
      return null;
    }
    final row = _intLike(hyperlink['r']);
    final column = _intLike(hyperlink['c']);
    if (row == null || column == null) {
      return null;
    }
    return {
      'op': 'replace',
      'id': sheet.id,
      'path': ['hyperlink', '${coord.row}_${coord.column}'],
      'value': cloneFortuneMetadata(sheet.hyperlinks['${row}_$column']),
    };
  }

  int? _intLike(Object? value) {
    if (value is int) {
      return value;
    }
    if (value is num) {
      return value.toInt();
    }
    return int.tryParse(value?.toString() ?? '');
  }

  bool _sameSheetOrder(
    FortuneWorkbook previousWorkbook,
    FortuneWorkbook workbook,
  ) {
    if (previousWorkbook.sheets.length != workbook.sheets.length) {
      return false;
    }
    for (var index = 0; index < workbook.sheets.length; index += 1) {
      if (previousWorkbook.sheets[index].id != workbook.sheets[index].id) {
        return false;
      }
    }
    return true;
  }

  Object? _cellOpValue(FortuneSheet sheet, FortuneCellCoord coord) {
    final cell = sheet.cells[coord];
    if (cell != null) {
      return FortuneSheetCodec.cellToJson(cell);
    }
    if (sheet.nullCells.contains(coord)) {
      return null;
    }
    return null;
  }

  Map<String, Map<String, Object?>> _workbookSheetDataById(
    FortuneWorkbook workbook,
  ) {
    final data = FortuneSheetCodec.workbookToJson(workbook)['data'];
    if (data is! List) {
      return const {};
    }
    final sheets = <String, Map<String, Object?>>{};
    for (final item in data) {
      if (item is! Map) {
        continue;
      }
      final id = item['id']?.toString();
      if (id == null || id.isEmpty) {
        continue;
      }
      sheets[id] = Map<String, Object?>.from(item);
    }
    return sheets;
  }

  Map<String, Object?> _sheetConfigMap(Map<String, Object?> sheet) {
    final config = sheet['config'];
    if (config is! Map) {
      return const {};
    }
    return Map<String, Object?>.from(config);
  }

  bool _metadataValueChanged(
    Map<String, Object?> previousSheet,
    Map<String, Object?> sheet,
    String key,
  ) {
    if (!previousSheet.containsKey(key) && !sheet.containsKey(key)) {
      return false;
    }
    return jsonEncode(previousSheet[key]) != jsonEncode(sheet[key]);
  }

  int? _singleInsertedSheetIndex(
    List<FortuneSheet> shorter,
    List<FortuneSheet> longer,
  ) {
    var shortIndex = 0;
    int? insertedIndex;
    for (var longIndex = 0; longIndex < longer.length; longIndex += 1) {
      if (shortIndex < shorter.length &&
          shorter[shortIndex].id == longer[longIndex].id) {
        shortIndex += 1;
        continue;
      }
      if (insertedIndex != null) {
        return null;
      }
      insertedIndex = longIndex;
    }
    if (shortIndex != shorter.length) {
      return null;
    }
    return insertedIndex;
  }

