  void _recordUndoSnapshot() {
    if (_controllerApiBatchDepth > 0) {
      if (_batchedUndoSnapshotRecorded) {
        return;
      }
      _batchedUndoSnapshotRecorded = true;
    }
    final redoOps = _cloneFortuneOps(_pendingOnOpOps);
    _pushUndoSnapshot(
      _WorkbookHistorySnapshot(
        workbook: _cloneWorkbook(_workbook),
        selection: selection,
        scrollOffset: scrollOffset,
        sheetTabScrollOffset: _sheetTabScrollOffset,
        undoOps: _inverseRowColOnOpOps(redoOps),
        redoOps: redoOps,
      ),
    );
  }

  List<FortuneOp> _cloneFortuneOps(List<FortuneOp>? ops) {
    if (ops == null || ops.isEmpty) {
      return const [];
    }
    return [
      for (final op in ops)
        Map<String, Object?>.from(cloneFortuneMetadata(op) as Map),
    ];
  }

  List<FortuneOp> _inverseRowColOnOpOps(List<FortuneOp> ops) {
    final inverseOps = <FortuneOp>[];
    for (final op in ops) {
      final opType = op['op']?.toString();
      final value = op['value'];
      if (value is! Map) {
        continue;
      }
      final rowColValue = Map<String, Object?>.from(value);
      if (opType == 'insertRowCol') {
        var index = _historyNullableIntArg(rowColValue['index']) ?? 0;
        if (rowColValue['direction'] == 'rightbottom') {
          index += 1;
        }
        final count = _historyNullableIntArg(rowColValue['count']) ?? 1;
        inverseOps.add({
          'op': 'deleteRowCol',
          'id': rowColValue['id'],
          'path': const <Object?>[],
          'value': {
            'type': rowColValue['type'],
            'id': rowColValue['id'],
            'start': index,
            'end': index + count - 1,
          },
        });
      } else if (opType == 'deleteRowCol') {
        final start = _historyNullableIntArg(rowColValue['start']) ?? 0;
        final end = _historyNullableIntArg(rowColValue['end']) ?? start;
        inverseOps.add({
          'op': 'insertRowCol',
          'id': rowColValue['id'],
          'path': const <Object?>[],
          'value': {
            'type': rowColValue['type'],
            'id': rowColValue['id'],
            'index': start,
            'count': end - start + 1,
            'direction': 'lefttop',
          },
        });
      }
    }
    return inverseOps;
  }

  int? _historyNullableIntArg(Object? value) {
    if (value is int) {
      return value;
    }
    if (value is num) {
      return value.toInt();
    }
    return int.tryParse(value?.toString() ?? '');
  }

  void _pushUndoSnapshot(_WorkbookHistorySnapshot snapshot) {
    _undoStack.add(snapshot);
    if (_undoStack.length > _maxUndoSnapshots) {
      _undoStack.removeAt(0);
    }
    _redoStack.clear();
  }

