      snapshot.selection,
      sheet,
      settings: _workbook.settings,
    );
    scrollOffset = _clampScrollOffsetToVisibleSheet(
      snapshot.scrollOffset,
      sheet,
      settings: _workbook.settings,
    );
    _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
      snapshot.sheetTabScrollOffset,
    );
    _closeTransientMenus();
    _cancelImageResize();
    _cancelImageMove();
    _editingCoord = null;
    _editingCommentCoord = null;
    _commentEditorDraftUndoSnapshot = null;
    _hyperlinkDialogCoord = null;
    _hyperlinkDialogSelectingCellRange = false;
    _hyperlinkDialogRangeSelectionOriginAddress = null;
    _hyperlinkDialogRangeSelectionAnchor = null;
    _editingFormulaBar = false;
    _renamingSheetIndex = null;
    _customSortDialogOpen = false;
    _axisSizeDialogAxis = null;
    _axisSizeDialogIndex = null;
    _dataVerificationDialogCoord = null;
    _dataVerificationDialogRange = null;
    _dataVerificationDialogSelectingRange = false;
    _dataVerificationDialogRangeEdited = false;
    _dataVerificationDialogRangeSelectionAnchor = null;
    _dataVerificationDialogRangeSelectionTarget = null;
    _dataVerificationDialogOriginalRule = null;
    _dataVerificationDialogOriginalOptionsText = '';
    _dataVerificationDialogType = 'dropdown';
    _dataVerificationDialogType2 = '';
    _dataVerificationDialogAllowMulti = false;
    _dataVerificationDialogProhibitInput = false;
    _dataVerificationDialogHintShow = false;
    _dataVerificationRangeEditorController.clear();
    _dataVerificationEditorController.clear();
    _dataVerificationSecondEditorController.clear();
    _dataVerificationHintEditorController.clear();
    _formulaSearchDialogOpen = false;
    _formulaSearchCategoryMenuOpen = false;
    _formulaSearchScrollOffset = 0;
    _formatMoreSubmenuOpen = false;
    _formatMoreHoveredIndex = null;
    _formatSearchDialogOpen = false;
    _formatSearchType = fortuneToolbarFormatMoreCurrencyCommand;
