  void _undoWorkbookChange() {
    if (_undoStack.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    final snapshot = _undoStack.removeLast();
    setState(() {
      _redoStack.add(
        _WorkbookHistorySnapshot(
          workbook: _cloneWorkbook(_workbook),
          selection: selection,
          scrollOffset: scrollOffset,
          sheetTabScrollOffset: _sheetTabScrollOffset,
          redoOps: snapshot.redoOps,
        ),
      );
      _pendingOnOpOps = _cloneFortuneOps(snapshot.undoOps);
      _restoreHistorySnapshot(snapshot);
    });
  }

  void _redoWorkbookChange() {
    if (_redoStack.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    final snapshot = _redoStack.removeLast();
    setState(() {
      _undoStack.add(
        _WorkbookHistorySnapshot(
          workbook: _cloneWorkbook(_workbook),
          selection: selection,
          scrollOffset: scrollOffset,
          sheetTabScrollOffset: _sheetTabScrollOffset,
          undoOps: _inverseRowColOnOpOps(snapshot.redoOps),
          redoOps: _cloneFortuneOps(snapshot.redoOps),
        ),
      );
      _pendingOnOpOps = _cloneFortuneOps(snapshot.redoOps);
      _restoreHistorySnapshot(snapshot);
    });
  }

  Map<String, Object?> _scrollWorkbook({
    Object? scrollLeft,
    Object? scrollTop,
    Object? targetRow,
    Object? targetColumn,
  }) {
    final sheet = _workbook.activeSheet;
    final metrics = sheet.metrics(_workbook.settings);
    final result = scroll(
      visibleDataRows: metrics.visibleDataRows,
      visibleDataColumns: metrics.visibleDataColumns,
      scrollLeft: scrollLeft,
      scrollTop: scrollTop,
      targetRow: targetRow,
      targetColumn: targetColumn,
    );
    if (result.isEmpty) {
      return result;
    }
    setState(() {
      final nextScrollLeft =
          (result['scrollLeft'] as num?)?.toDouble() ?? scrollOffset.dx;
      final nextScrollTop =
          (result['scrollTop'] as num?)?.toDouble() ?? scrollOffset.dy;
      scrollOffset = _clampScrollOffsetToVisibleSheet(
        Offset(nextScrollLeft, nextScrollTop),
        sheet,
        settings: _workbook.settings,
      );
    });
    return result;
  }

