  List<Presence> _controllerPresences() {
    final raw = _workbook.extraFields['presences'];
    if (raw is Iterable) {
      return [
        for (final item in raw)
          if (item is Map) Map<String, Object?>.from(item),
      ];
    }
    return const <Presence>[];
  }

  void _setControllerPresences(List<Presence> presences) {
    final previousWorkbook = _workbook;
    final previousPresences = _controllerPresences();
    final extraFields = Map<String, Object?>.from(_workbook.extraFields);
    extraFields['presences'] = [
      for (final presence in presences) Map<String, Object?>.from(presence),
    ];
    final nextWorkbook = _workbook.copyWith(extraFields: extraFields);
    if (_jsonLikeEquals(previousPresences, presences)) {
      return;
    }
    setState(() {
      _workbook = nextWorkbook;
    });
    _queueOrNotifyWorkbookChanged(
      _workbook,
      previousWorkbook: previousWorkbook,
      force: true,
    );
  }

  void _addControllerPresences(Iterable<Presence> newPresences) {
    _setControllerPresences(addPresences(_controllerPresences(), newPresences));
  }

  void _removeControllerPresences(Iterable<Presence> removedPresences) {
    _setControllerPresences(
      removePresences(_controllerPresences(), removedPresences),
    );
  }

  Map<String, Object?>? _autoFillControllerCell(
    FortuneRange copyRange,
    FortuneRange applyRange,
    String direction,
  ) {
    final sheet = _workbook.activeSheet;
    if (!_canEditRange(sheet, applyRange)) {
      return null;
    }
    final cache = autoFillCell(sheet, copyRange, applyRange, direction);
    final payload = updateDropCell(_workbook, <String, Object?>{
      'currentSheetId': sheet.id,
    }, cache: cache);
    final nextSheet = payload?['sheet'];
    if (nextSheet is! FortuneSheet) {
      return null;
    }
    if (_jsonLikeEquals(
      FortuneSheetCodec.sheetToJson(sheet),
      FortuneSheetCodec.sheetToJson(nextSheet),
    )) {
      return payload;
    }
    _replaceActiveSheetForController(nextSheet, recalculate: true);
    return payload;
  }

