      return;
    }
    final targetSheetIndex = _sheetIndexByIdOrIndex(id: id, index: sheetIndex);
    final sheet = _workbook.sheets[targetSheetIndex];
    if (!_canControllerInsertRowOrColumn(sheet, type, index, count)) {
      return;
    }
    final nextSheet = sheet.insertRowOrColumn(
      type,
      index,
      count,
      direction: direction,
    );
