  void _deleteControllerRowOrColumn(
    String type,
    int start,
    int end, {
    String? id,
    int? sheetIndex,
  }) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final targetSheetIndex = _sheetIndexByIdOrIndex(id: id, index: sheetIndex);
    final sheet = _workbook.sheets[targetSheetIndex];
    final deleteBounds = _controllerDeleteBounds(sheet, type, start, end);
    if (deleteBounds == null ||
        !_canControllerDeleteRowOrColumn(sheet, type, start, end)) {
      return;
    }
    final nextSheet = sheet.deleteRowOrColumn(
      type,
      deleteBounds.start,
      deleteBounds.end,
    );
    _replaceControllerSheet(targetSheetIndex, nextSheet);
  }

  bool _canControllerInsertRowOrColumn(
    FortuneSheet sheet,
    String type,
    int index,
    int count,
  ) {
    return switch (type) {
      'row' =>
        !_isIndexReadOnly(sheet.rowReadOnly, index) &&
            _effectiveRowCount(sheet) + count < 10000 &&
            _canEditRowStructureFrom(sheet, index),
      'column' =>
        !_isIndexReadOnly(sheet.colReadOnly, index) &&
            _effectiveColumnCount(sheet) + count < 1000 &&
            _canEditColumnStructureFrom(sheet, index),
      _ => true,
    };
  }

  bool _canControllerDeleteRowOrColumn(
    FortuneSheet sheet,
    String type,
    int start,
    int end,
  ) {
    final deleteBounds = _controllerDeleteBounds(sheet, type, start, end);
    if (deleteBounds == null) {
      return false;
    }
    final deleteStart = deleteBounds.start;
    final readOnlyStart = math.min(start, end);
    final readOnlyEnd = math.max(start, end);
    return switch (type) {
      'row' =>
        _canEditRowStructureFrom(sheet, deleteStart) &&
            Iterable<int>.generate(
              readOnlyEnd - readOnlyStart + 1,
              (offset) => readOnlyStart + offset,
            ).every((row) => !_isIndexReadOnly(sheet.rowReadOnly, row)),
      'column' =>
        _canEditColumnStructureFrom(sheet, deleteStart) &&
            Iterable<int>.generate(
              readOnlyEnd - readOnlyStart + 1,
              (offset) => readOnlyStart + offset,
            ).every((column) => !_isIndexReadOnly(sheet.colReadOnly, column)),
      _ => true,
    };
  }

  ({int start, int end})? _controllerDeleteBounds(
    FortuneSheet sheet,
    String type,
    int start,
    int end,
  ) {
    final maxIndex = switch (type) {
      'row' => math.max(0, _effectiveRowCount(sheet) - 1),
      'column' => math.max(0, _effectiveColumnCount(sheet) - 1),
      _ => null,
    };
    var deleteStart = math.max(0, math.min(start, end));
    var deleteEnd = math.max(0, math.max(start, end));
    if (maxIndex != null) {
      deleteStart = math.min(deleteStart, maxIndex);
      deleteEnd = math.min(deleteEnd, maxIndex);
    }
    if (deleteStart > deleteEnd) {
      return null;
    }
    return (start: deleteStart, end: deleteEnd);
  }

  bool _sameHiddenAxis(
    FortuneSheet previousSheet,
    FortuneSheet nextSheet,
    String type,
  ) {
    return switch (type) {
      'row' =>
        _sameIntSet(previousSheet.hiddenRows, nextSheet.hiddenRows) &&
            _sameObjectMap(
              previousSheet.hiddenRowValues,
              nextSheet.hiddenRowValues,
            ),
      'column' =>
        _sameIntSet(previousSheet.hiddenColumns, nextSheet.hiddenColumns) &&
            _sameObjectMap(
              previousSheet.hiddenColumnValues,
              nextSheet.hiddenColumnValues,
            ),
      _ => false,
    };
  }

  bool _sameAxisSizes(
    Map<int, double> previousSizes,
    Map<int, double> nextSizes,
    Map<int, double> previousCustomSizes,
    Map<int, double> nextCustomSizes,
  ) {
    return _sameDoubleMap(previousSizes, nextSizes) &&
        _sameDoubleMap(previousCustomSizes, nextCustomSizes);
  }

  bool _sameDoubleMap(Map<int, double> left, Map<int, double> right) {
    if (left.length != right.length) {
      return false;
    }
    for (final entry in left.entries) {
      if (right[entry.key] != entry.value) {
        return false;
      }
    }
    return true;
  }

  bool _sameIntSet(Set<int> left, Set<int> right) {
    if (left.length != right.length) {
      return false;
    }
    for (final value in left) {
      if (!right.contains(value)) {
        return false;
      }
    }
    return true;
  }

  bool _sameObjectMap(Map<int, Object?> left, Map<int, Object?> right) {
    if (left.length != right.length) {
      return false;
    }
    for (final entry in left.entries) {
      if (!right.containsKey(entry.key) || right[entry.key] != entry.value) {
        return false;
      }
    }
    return true;
  }

  bool _sameCellMerges(
    Map<FortuneCellCoord, FortuneCell> left,
    Map<FortuneCellCoord, FortuneCell> right,
  ) {
    final coords = <FortuneCellCoord>{...left.keys, ...right.keys};
    for (final coord in coords) {
      if (!_sameMerge(left[coord]?.merge, right[coord]?.merge)) {
        return false;
      }
    }
    return true;
  }

  bool _sameMerge(FortuneCellMerge? left, FortuneCellMerge? right) {
    if (left == null || right == null) {
      return left == null && right == null;
    }
    return left.row == right.row &&
        left.column == right.column &&
        left.rowSpan == right.rowSpan &&
        left.columnSpan == right.columnSpan;
  }

  void _replaceActiveSheetForController(
    FortuneSheet nextSheet, {
    bool recalculate = false,
  }) {
    _replaceControllerSheet(
      _workbook.activeSheetIndex,
      nextSheet,
      recalculate: recalculate,
    );
  }

  void _replaceControllerSheet(
    int sheetIndex,
    FortuneSheet nextSheet, {
    bool recalculate = false,
  }) {
    setState(() {
      _recordUndoSnapshot();
      final sheets = [..._workbook.sheets];
      sheets[sheetIndex] = nextSheet;
      _workbook = _workbook.copyWith(sheets: sheets);
      if (recalculate) {
        _recalculateWorkbookFormulas();
      }
    });
  }

  void _activateControllerSheet({String? id, int? index}) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    final targetSheet = _workbook.sheets[sheetIndex];
    if (targetSheet.id == _workbook.activeSheet.id) {
      return;
    }
    if (_workbook.settings.beforeActivateSheet?.call(targetSheet.id) == false) {
      return;
    }
    setState(() {
      _rememberActiveSheetScrollOffset();
      _activateSheetAtIndex(sheetIndex);
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(sheetIndex);
    });
    _workbook.settings.afterActivateSheet?.call(targetSheet.id);
  }

  void _setControllerSheetName(String name, {String? id, int? index}) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    final rename = _prepareSheetRename(sheetIndex, name);
    if (rename == null) {
      return;
    }
    setState(() {
      _applyPreparedSheetRename(sheetIndex, rename);
    });
    _notifyPreparedSheetRename(rename);
  }

  void _setControllerSheetOrder(Map<String, int> orderList) {
    if (!_workbook.settings.allowEdit || orderList.isEmpty) {
      return;
    }
    final nextWorkbook = _workbook.setSheetOrder(orderList);
    if (_sameSheetOrder(_workbook, nextWorkbook)) {
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(
        _workbook.activeSheetIndex,
      );
    });
  }

  void _addControllerSheet({
    String? id,
    String? name,
    int? rowCount,
    int? columnCount,
    FortuneSheet? sheet,
  }) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final previousWorkbook = _workbook;
    final nextWorkbook = addSheet(
      previousWorkbook,
      id: id,
      name: name,
      rowCount: rowCount,
      columnCount: columnCount,
      sheet: sheet,
      beforeAddSheet: _workbook.settings.beforeAddSheet,
    );
    if (nextWorkbook.sheets.length == previousWorkbook.sheets.length) {
      return;
    }
    final addedSheet = nextWorkbook.sheets.firstWhere(
      (candidate) => !previousWorkbook.sheets.any(
        (existing) => existing.id == candidate.id,
      ),
    );
    setState(() {
      _recordUndoSnapshot();
      if (nextWorkbook.activeSheet.id != previousWorkbook.activeSheet.id) {
        _rememberActiveSheetScrollOffset();
        selection = _selectionFromSheet(nextWorkbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(nextWorkbook.activeSheet);
      }
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(
        _workbook.activeSheetIndex,
      );
    });
    _workbook.settings.afterAddSheet?.call(addedSheet);
  }

  void _deleteControllerSheet({String? id, int? index}) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (!_workbook.settings.allowEdit || _visibleSheetIndexes().length <= 1) {
      return;
    }
    final deletedSheet = _workbook.sheets[sheetIndex];
    if (_workbook.settings.beforeDeleteSheet?.call(deletedSheet.id) == false) {
      return;
    }
    final previousWorkbook = _workbook;
    final nextWorkbook = deleteSheet(previousWorkbook, id: deletedSheet.id);
    if (nextWorkbook.sheets.length == previousWorkbook.sheets.length) {
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      if (deletedSheet.id == previousWorkbook.activeSheet.id) {
        _rememberActiveSheetScrollOffset();
        selection = _selectionFromSheet(nextWorkbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(nextWorkbook.activeSheet);
      }
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
        _sheetTabScrollOffset,
        sheets: _workbook.sheets,
      );
    });
    _workbook.settings.afterDeleteSheet?.call(deletedSheet.id);
  }

  void _clearControllerSheet({
    String? id,
    int? index,
    int? rowCount,
    int? columnCount,
  }) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final targetSheet = _workbook.sheets[sheetIndex];
    final nextWorkbook = clearSheet(
      _workbook,
      id: targetSheet.id,
      rowCount: rowCount,
      columnCount: columnCount,
    );
    if (!_workbookJsonChanged(_workbook, nextWorkbook)) {
      setState(_closeTransientMenus);
      return;
    }
    _pendingOnOpOps = [
      {
        'op': 'clearSheet',
        'id': targetSheet.id,
        'path': const <Object?>[],
        'value': {'id': targetSheet.id},
      },
    ];
    setState(() {
      _recordUndoSnapshot();
      _workbook = nextWorkbook;
      if (targetSheet.id == _workbook.activeSheet.id) {
        selection = _selectionFromSheet(_workbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(_workbook.activeSheet);
      }
      _closeTransientMenus();
    });
  }

  void _resizeControllerSheetGridClientArea(
    int widthMm,
    int heightMm, {
    String? id,
    int? index,
  }) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final targetSheet = _workbook.sheets[sheetIndex];
    final nextWorkbook = resizeSheetGridClientArea(
      _workbook,
      widthMm,
      heightMm,
      id: targetSheet.id,
    );
    if (!_workbookJsonChanged(_workbook, nextWorkbook)) {
      setState(_closeTransientMenus);
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      _workbook = nextWorkbook;
      if (targetSheet.id == _workbook.activeSheet.id) {
        selection = _selectionFromSheet(_workbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(_workbook.activeSheet);
      }
      _closeTransientMenus();
    });
  }

  void _copyControllerSheet({String? id, int? index, String? newSheetId}) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final previousWorkbook = _workbook;
    final nextWorkbook = copySheet(
      previousWorkbook,
      id: previousWorkbook.sheets[sheetIndex].id,
      newSheetId: newSheetId,
    );
    if (nextWorkbook.sheets.length == previousWorkbook.sheets.length) {
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(
        _workbook.activeSheetIndex,
      );
    });
  }

  void _hideControllerSheet({String? id, int? index}) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (!_workbook.settings.allowEdit || _visibleSheetIndexes().length <= 1) {
      return;
    }
    final targetSheet = _workbook.sheets[sheetIndex];
    if (targetSheet.hide == 1) {
      return;
    }
    final previousWorkbook = _workbook;
    final nextWorkbook = hideSheet(previousWorkbook, targetSheet.id);
    if (nextWorkbook.sheets[sheetIndex].hide != 1) {
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      if (nextWorkbook.activeSheet.id != previousWorkbook.activeSheet.id) {
        _rememberActiveSheetScrollOffset();
        selection = _selectionFromSheet(nextWorkbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(nextWorkbook.activeSheet);
      }
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
        _sheetTabScrollOffset,
        sheets: _workbook.sheets,
      );
    });
  }

  void _showControllerSheet({String? id, int? index}) {
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final targetSheet = _workbook.sheets[sheetIndex];
    if (targetSheet.hide != 1) {
      return;
    }
    final nextWorkbook = showSheet(_workbook, targetSheet.id);
    if (nextWorkbook.sheets[sheetIndex].hide == 1) {
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
        _sheetTabScrollOffset,
        sheets: _workbook.sheets,
      );
    });
  }

  void _updateControllerSheet(List<FortuneSheet> data) {
    if (!_workbook.settings.allowEdit || data.isEmpty) {
      return;
    }
    final previousWorkbook = _workbook;
    final activeSheetId = previousWorkbook.activeSheet.id;
    final updatesActiveSheet = data.any((sheet) => sheet.id == activeSheetId);
    final nextWorkbook = updateSheet(previousWorkbook, data);
    setState(() {
      _recordUndoSnapshot();
      if (updatesActiveSheet) {
        _rememberActiveSheetScrollOffset();
        selection = _selectionFromSheet(nextWorkbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(nextWorkbook.activeSheet);
      }
      _workbook = nextWorkbook;
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(
        _workbook.activeSheetIndex,
      );
    });
  }

  void _setControllerZoomRatio(double zoomRatio, {String? id, int? index}) {
    final targetSheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    if (targetSheetIndex < 0) {
      return;
    }
    final roundedZoom =
        (zoomRatio.clamp(minZoomRatio, maxZoomRatio) * 100).roundToDouble() /
        100;
    final sheet = _workbook.sheets[targetSheetIndex];
    if (roundedZoom == sheet.zoomRatio) {
      return;
    }
    setState(() {
      _suppressNextOnOp = true;
      _rememberActiveSheetScrollOffset();
      final sheets = [..._workbook.sheets];
      sheets[targetSheetIndex] = sheet.copyWith(zoomRatio: roundedZoom);
      _workbook = _workbook.copyWith(sheets: sheets);
    });
  }

  void _initControllerSheetData(int index, FortuneSheet newData) {
    if (!_workbook.settings.allowEdit || index < 0) {
      return;
    }
    final initialized = newData.copyWith(
      rawCelldata: null,
      hasRawCelldata: false,
    );
    setState(() {
      _recordUndoSnapshot();
      final sheets = [..._workbook.sheets];
      if (index < sheets.length) {
        final target = sheets[index];
        var nextTarget = target.copyWith(
          cells: initialized.cells,
          nullCells: initialized.nullCells,
          rawData: initialized.rawData,
          hasRawData: initialized.hasRawData,
          rawCelldata: null,
          hasRawCelldata: false,
        );
        if (initialized.rowCount != null) {
          nextTarget = nextTarget.copyWith(
            rowCount: initialized.rowCount,
            rawRowCount: initialized.rawRowCount,
            hasRawRowCount: initialized.hasRawRowCount,
          );
        }
        if (initialized.columnCount != null) {
          nextTarget = nextTarget.copyWith(
            columnCount: initialized.columnCount,
            rawColumnCount: initialized.rawColumnCount,
            hasRawColumnCount: initialized.hasRawColumnCount,
          );
        }
        sheets[index] = nextTarget;
      } else {
        sheets.add(initialized);
      }
      _workbook = _workbook.copyWith(sheets: sheets);
      _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
        _sheetTabScrollOffset,
        sheets: _workbook.sheets,
      );
    });
  }

  void _applyControllerOps(Iterable<FortuneOp> ops) {
    final pendingOps = _cloneFortuneOps(ops.toList(growable: false));
    if (pendingOps.isEmpty) {
      return;
    }
    final previousWorkbook = _workbook;
    final nextWorkbook = applyOp(previousWorkbook, pendingOps);
    if (!_workbookJsonChanged(previousWorkbook, nextWorkbook)) {
      return;
    }
    final previousActiveSheetId = previousWorkbook.activeSheet.id;
    final deletesSheets = previousWorkbook.sheets.any(
      (sheet) => nextWorkbook.getSheet(id: sheet.id) == null,
    );
    final canRebaseHistory = pendingOps.every(_canRebaseHistoryWithOp);
    _suppressNextOnOp = true;
    setState(() {
      if (deletesSheets) {
        _undoStack.clear();
        _redoStack.clear();
      } else if (canRebaseHistory) {
        _rebaseHistoryStacksWithOps(pendingOps);
      } else {
        _undoStack.clear();
        _redoStack.clear();
      }
      _workbook = nextWorkbook;
      _recalculateWorkbookFormulas();
      if (previousActiveSheetId != _workbook.activeSheet.id) {
        selection = _selectionFromSheet(_workbook.activeSheet);
        scrollOffset = _scrollOffsetFromSheet(_workbook.activeSheet);
        _sheetTabScrollOffset = _sheetTabOffsetToReveal(
          _workbook.activeSheetIndex,
        );
      } else {
        selection = clampSelectionToSheet(
          selection,
          _workbook.activeSheet,
          settings: _workbook.settings,
        );
        scrollOffset = _clampScrollOffsetToVisibleSheet(
          scrollOffset,
          _workbook.activeSheet,
          settings: _workbook.settings,
        );
        _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
          _sheetTabScrollOffset,
        );
      }
    });
    _scheduleImageDecodes();
  }

  void _calculateControllerFormula({String? id, FortuneRange? range}) {
    final rawData = _workbook.rawData;
    final hasRawData = _workbook.hasRawData;
    final nextWorkbook = FortuneFormulaEngine.calculateFormula(
      _workbook,
      id: id,
      range: range,
    ).copyWith(rawData: rawData, hasRawData: hasRawData);
    if (!_workbookJsonChanged(_workbook, nextWorkbook)) {
      return;
    }
    setState(() {
      _workbook = nextWorkbook;
    });
  }

  bool _canRebaseHistoryWithOp(FortuneOp op) {
    final opType = op['op']?.toString();

    final id = op['id'];
    final path = op['path'];
    return (opType == 'add' || opType == 'replace' || opType == 'remove') &&
        id is String &&
        id.isNotEmpty &&
        path is List &&
        path.isNotEmpty;
  }

  void _rebaseHistoryStacksWithOps(List<FortuneOp> ops) {
    if (ops.isEmpty || (_undoStack.isEmpty && _redoStack.isEmpty)) {
      return;
    }
    final rebasedUndo = [
      for (final snapshot in _undoStack)
        _rebaseHistorySnapshotWithOps(snapshot, ops),
    ];
    final rebasedRedo = [
      for (final snapshot in _redoStack)
        _rebaseHistorySnapshotWithOps(snapshot, ops),
    ];
    _undoStack
      ..clear()
      ..addAll(rebasedUndo);
    _redoStack
      ..clear()
      ..addAll(rebasedRedo);
  }

  _WorkbookHistorySnapshot _rebaseHistorySnapshotWithOps(
    _WorkbookHistorySnapshot snapshot,
    List<FortuneOp> ops,
  ) {
    final rebasedWorkbook = applyOp(snapshot.workbook, ops);
    if (!_workbookJsonChanged(snapshot.workbook, rebasedWorkbook)) {
      return snapshot;
    }
    return _WorkbookHistorySnapshot(
      workbook: rebasedWorkbook,
      selection: snapshot.selection,
      scrollOffset: snapshot.scrollOffset,
      sheetTabScrollOffset: snapshot.sheetTabScrollOffset,
      undoOps: snapshot.undoOps,
      redoOps: snapshot.redoOps,
    );
  }

  int _sheetIndexByIdOrIndex({String? id, int? index}) {
    if (index != null) {
      if (index < 0 || index >= _workbook.sheets.length) {
        throw SHEET_NOT_FOUND;
      }
      return index;
    }
    if (id != null) {
      final sheetIndex = _workbook.sheets.indexWhere((sheet) => sheet.id == id);
      if (sheetIndex < 0) {
        throw SHEET_NOT_FOUND;
      }
      return sheetIndex;
    }
    return _workbook.activeSheetIndex;
  }

  void _setControllerSelection(
    Iterable<FortuneRange> ranges, {
    String? id,
    int? index,
  }) {
    final nextRanges = [for (final range in ranges) range.copyWith()];
    if (nextRanges.isEmpty) {
      return;
    }
    final sheetIndex = _sheetIndexByIdOrIndex(id: id, index: index);
    final range = nextRanges.last;
    final focus = FortuneCellCoord(
      range.rowFocus ?? range.rowStart,
      range.columnFocus ?? range.columnStart,
    );
    setState(() {
      if (sheetIndex == _workbook.activeSheetIndex) {
        _setSelectionToRange(range);
      }
      _writeSelectionRanges(nextRanges, focus, sheetIndex: sheetIndex);
    });
  }

  void _clearControllerHoverState() {
    if (_toolbarHoveredKey == null &&
        _toolbarHoveredComboArrowKey == null &&
        _mouseCursor == SystemMouseCursors.basic) {
      return;
    }
    setState(() {
      _toolbarHoveredKey = null;
      _toolbarHoveredComboArrowKey = null;
      _mouseCursor = SystemMouseCursors.basic;
    });
  }

