  void _handlePointerDown(PointerDownEvent event) {
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final local = event.localPosition;
    final editorRect = _editingRect();
    final editorMenuAt = contextMenuAt;
    final editorMenuContains =
        _contextMenuIsEditor &&
        editorMenuAt != null &&
        fortuneContextMenuRect(
          editorMenuAt,
          _editorContextMenuItems,
        ).contains(local);
    final editorMenuCommand = _contextMenuIsEditor
        ? _contextMenuCommandAt(local)
        : null;
    fortuneSheetDebugLog(
      'editor pointerDown pointer=${event.pointer} buttons=${event.buttons} '
      'kind=${event.kind.name} local=${local.dx.toStringAsFixed(1)},${local.dy.toStringAsFixed(1)} '
      'editing=$_editingCoord editorRect=${_debugRect(editorRect)} '
      'editorRectContains=${editorRect?.contains(local) == true} '
      'contextMenuIsEditor=$_contextMenuIsEditor menuAt=$editorMenuAt '
      'menuContains=$editorMenuContains menuCommand=$editorMenuCommand '
      'openingPointer=$_editorContextMenuOpeningPointer '
      'selection=${_debugSelection(_editorController.selection)}',
    );
    _cancelSheetTabLongPress();
    _cancelSheetTabDrag();

    final closeKey = _dialogCloseButtonKeyAt(local);
    if (closeKey != null) {
      _commitEditing();
      _commitSheetRename();
      setState(() {
        _dialogClosePressedKey = closeKey;
        _dialogCloseHoveredKey = closeKey;
        _imageInsertHoveredControl = null;
        _barcodeHoveredControl = null;
      });
      return;
    }

    if (_handleToolbarPopupPointerDown(event)) {
      return;
    }

    if (_contextMenuIsEditor) {
      if (_editorContextMenuOpeningPointer == event.pointer) {
        fortuneSheetDebugLog(
          'editor pointerDown ignored openingPointer pointer=${event.pointer}',
        );
        return;
      }
      if (editorMenuCommand != null) {
        _activateContextMenuCommand(editorMenuCommand);
        return;
      }
      if (editorMenuContains) {
        fortuneSheetDebugLog(
          'editor pointerDown insideMenuNoCommand local=${local.dx.toStringAsFixed(1)},${local.dy.toStringAsFixed(1)}',
        );
        return;
      }
      setState(_closeTransientMenus);
    }

    if (_editingCoord != null &&
        event.kind == PointerDeviceKind.mouse &&
        (event.buttons & kSecondaryMouseButton) != 0 &&
        editorRect?.contains(local) == true) {
      final selection = _editorController.selection;
      final fallbackOffset = selection.isValid
          ? math.min(
              _editorController.text.length,
              math.max(0, selection.extentOffset),
            )
          : _editorController.text.length;
      final offset =
          _editorTextOffsetForGlobalPosition(event.position) ?? fallbackOffset;
      _editorFocusNode.requestFocus();
      _showEditorContextMenu(event, offset, openingPointer: event.pointer);
      return;
    }

    if (_editorDragSelectionPointer != null ||
        (_editingCoord != null && editorRect?.contains(local) == true)) {
      return;
    }

    if (_searchDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final searchInput = _searchDialogInputRect();
      if (searchInput != null && searchInput.contains(local)) {
        _searchEditorFocusNode.requestFocus();
        return;
      }
      final replaceInput = _searchDialogReplaceInputRect();
      if (_searchReplaceMode &&
          replaceInput != null &&
          replaceInput.contains(local)) {
        _replaceEditorFocusNode.requestFocus();
        return;
      }
      final command = _searchDialogCommandAt(local);
      if (command == null && _searchDialogRect()?.contains(local) == true) {
        _startSearchDialogDrag(local);
        return;
      }
      _activateSearchDialogCommand(command);
      return;
    }

    if (_locationMessageDialogText != null) {
      _commitEditing();
      _commitSheetRename();
      _activateLocationMessageDialogCommand(
        _locationMessageDialogCommandAt(local),
      );
      return;
    }

    if (_screenshotDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      _activateScreenshotDialogCommand(_screenshotDialogCommandAt(local));
      return;
    }

    if (_customSortDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      _activateCustomSortDialogCommand(_customSortDialogCommandAt(local));
      return;
    }

    if (_axisSizeDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final inputRect = _axisSizeInputRect();
      if (inputRect != null && inputRect.contains(local)) {
        _axisSizeEditorFocusNode.requestFocus();
        return;
      }
      _activateAxisSizeDialogCommand(_axisSizeDialogCommandAt(local));
      return;
    }

    if (_imageInsertDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final command = _imageInsertDialogCommandAt(local);
      if (command == null ||
          (command != 'width' &&
              command != 'height' &&
              command != 'rotation')) {
        _clearImageInsertInputSelections();
      }
      if (command == 'width') {
        _imageInsertWidthFocusNode.requestFocus();
        return;
      }
      if (command == 'height') {
        _imageInsertHeightFocusNode.requestFocus();
        return;
      }
      if (command == 'rotation') {
        _imageInsertRotationFocusNode.requestFocus();
        return;
      }
      if (command != null && command != 'modal') {
        setState(() {
          _imageInsertPressedControl = command;
        });
      }
      _activateImageInsertDialogCommand(command);
      return;
    }

    if (_barcodeDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final command = _barcodeDialogCommandAt(local);
      if (_barcodeObjectIdMenuOpen &&
          (command == null ||
              (command != 'object-id' && !command.startsWith('object-id-')))) {
        setState(() {
          _barcodeObjectIdMenuOpen = false;
          _barcodeObjectIdMenuHoveredIndex = null;
          _barcodeObjectIdMenuScrollOffset = 0;
        });
      }
      if (_barcodeFormatMenuOpen &&
          (command == null ||
              (command != 'format' && !command.startsWith('format-')))) {
        setState(() {
          _barcodeFormatMenuOpen = false;
          _barcodeFormatMenuHoveredIndex = null;
          _barcodeFormatMenuScrollOffset = 0;
        });
      }
      if (_barcodeTextFontMenuOpen &&
          (command == null ||
              (command != 'text-font' && !command.startsWith('text-font-')))) {
        setState(() {
          _barcodeTextFontMenuOpen = false;
          _barcodeTextFontMenuHoveredIndex = null;
          _barcodeTextFontMenuScrollOffset = 0;
        });
      }
      if (_barcodeTextFontSizeMenuOpen &&
          (command == null ||
              (command != 'text-font-size' &&
                  !command.startsWith('text-font-size-')))) {
        setState(() {
          _barcodeTextFontSizeMenuOpen = false;
          _barcodeTextFontSizeMenuHoveredIndex = null;
          _barcodeTextFontSizeMenuScrollOffset = 0;
        });
      }
      if (command == null ||
          (command != 'text' &&
              command != 'width' &&
              command != 'module-scale' &&
              command != 'bar-height' &&
              command != 'height' &&
              command != 'leading-quiet-zone' &&
              command != 'trailing-quiet-zone' &&
              command != 'rotation')) {
        _clearBarcodeInputSelections();
      }
      if (command == 'text') {
        _barcodeTextFocusNode.requestFocus();
        return;
      }
      if (command == 'width') {
        _barcodeWidthFocusNode.requestFocus();
        return;
      }
      if (command == 'module-scale') {
        _barcodeModuleScaleFocusNode.requestFocus();
        return;
      }
      if (command == 'bar-height') {
        _barcodeBarHeightFocusNode.requestFocus();
        return;
      }
      if (command == 'height') {
        _barcodeHeightFocusNode.requestFocus();
        return;
      }
      if (command == 'leading-quiet-zone') {
        _barcodeLeadingQuietZoneFocusNode.requestFocus();
        return;
      }
      if (command == 'trailing-quiet-zone') {
        _barcodeTrailingQuietZoneFocusNode.requestFocus();
        return;
      }
      if (command == 'rotation') {
        _barcodeRotationFocusNode.requestFocus();
        return;
      }
      if (command != null && command != 'modal') {
        setState(() {
          _barcodePressedControl = command;
        });
      }
      _activateBarcodeDialogCommand(command);
      return;
    }

    if (_hyperlinkDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final hyperlinkDialogRect = _hyperlinkDialogRect();
      if (_hyperlinkDialogSelectingCellRange &&
          hyperlinkDialogRect?.contains(local) != true) {
        _startHyperlinkDialogRangeSelection(local, settings, metrics);
        return;
      }
      final displayInput = _hyperlinkDialogDisplayInputRect();
      if (displayInput != null && displayInput.contains(local)) {
        _hyperlinkDisplayEditorFocusNode.requestFocus();
        return;
      }
      final addressInput = _hyperlinkDialogAddressEditorRect();
      if (addressInput != null && addressInput.contains(local)) {
        _hyperlinkAddressEditorFocusNode.requestFocus();
        return;
      }
      _activateHyperlinkDialogCommand(_hyperlinkDialogCommandAt(local));
      return;
    }

    final hyperlinkCardCommand = _hyperlinkCardCommandAt(local);
    if (hyperlinkCardCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _activateHyperlinkCardCommand(hyperlinkCardCommand);
      return;
    }

    if (_dataVerificationDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final dataVerificationDialogRect = _dataVerificationDialogRect();
      if (_dataVerificationDialogSelectingRange &&
          dataVerificationDialogRect?.contains(local) != true) {
        _startDataVerificationDialogRangeSelection(local, settings, metrics);
        return;
      }
      final sourceRangeIconRect = _dataVerificationDialogSourceRangeIconRect();
      if (sourceRangeIconRect != null && sourceRangeIconRect.contains(local)) {
        _activateDataVerificationDialogCommand('select-dropdown-source');
        return;
      }
      final inputRect = _dataVerificationDialogInputRect();
      if (inputRect != null && inputRect.contains(local)) {
        _dataVerificationEditorFocusNode.requestFocus();
        return;
      }
      _activateDataVerificationDialogCommand(
        _dataVerificationDialogCommandAt(local),
      );
      return;
    }

    if (_splitTextDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final inputRect = _splitTextOtherInputRect();
      if (inputRect != null && inputRect.contains(local)) {
        setState(() {
          _splitTextOther = true;
        });
        _splitTextOtherFocusNode.requestFocus();
        return;
      }
      _activateSplitTextDialogCommand(_splitTextDialogCommandAt(local));
      return;
    }

    if (_locationDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      _activateLocationDialogCommand(_locationDialogCommandAt(local));
      return;
    }

    if (_formatSearchDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final decimalRect = _formatSearchDecimalInputRect();
      if (decimalRect != null && decimalRect.contains(local)) {
        _formatSearchDecimalFocusNode.requestFocus();
        return;
      }
      _activateFormatSearchDialogCommand(_formatSearchDialogCommandAt(local));
      return;
    }

    if (_formulaSearchDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final inputRect = _formulaSearchInputRect();
      if (inputRect != null && inputRect.contains(local)) {
        _formulaSearchEditorFocusNode.requestFocus();
        return;
      }
      _activateFormulaSearchDialogCommand(_formulaSearchDialogCommandAt(local));
      return;
    }

    if (_conditionRuleDialogOpen) {
      _commitEditing();
      _commitSheetRename();
      final inputRect = _conditionRuleInputRect();
      if (inputRect != null && inputRect.contains(local)) {
        _conditionRuleEditorFocusNode.requestFocus();
        return;
      }
      final secondInputRect = _conditionRuleSecondInputRect();
      if (secondInputRect != null && secondInputRect.contains(local)) {
        _conditionRuleSecondEditorFocusNode.requestFocus();
        return;
      }
      _activateConditionRuleDialogCommand(_conditionRuleDialogCommandAt(local));
      return;
    }

    _focusNode.requestFocus();

    _updateRawChartClick(local);

    if (_startSheetScrollbarDrag(local)) {
      _commitEditing();
      _commitSheetRename();
      return;
    }

    final freezeAxis = _freezeHandleAxisAt(local, settings, metrics);
    if (freezeAxis != null) {
      _commitEditing();
      _commitSheetRename();
      _startFreezeDrag(freezeAxis, local);
      return;
    }

    final resizeTarget = _headerResizeTargetAt(local, settings, metrics);
    if (resizeTarget != null) {
      _commitEditing();
      if (_isResizeTargetReadOnly(_workbook.activeSheet, resizeTarget)) {
        setState(_closeTransientMenus);
        return;
      }
      final isDoubleClick =
          _lastResizeDownAxis == resizeTarget.axis &&
          _lastResizeDownIndex == resizeTarget.index &&
          _lastResizeDownTime != null &&
          event.timeStamp - _lastResizeDownTime! <
              const Duration(milliseconds: 450);
      _lastResizeDownTime = event.timeStamp;
      _lastResizeDownAxis = resizeTarget.axis;
      _lastResizeDownIndex = resizeTarget.index;
      if (isDoubleClick) {
        _autoFitHeader(resizeTarget);
        return;
      }
      _startResizeDrag(resizeTarget, local, settings, metrics);
      return;
    }

    final dataVerificationOption = _dataVerificationOptionAt(local);
    if (dataVerificationOption != null) {
      _commitEditing();
      _commitSheetRename();
      _activateDataVerificationOption(dataVerificationOption);
      return;
    }

    final filterSearchRect = _filterDropdownSearchRect();
    if (filterSearchRect != null && filterSearchRect.contains(local)) {
      _commitEditing();
      _commitSheetRename();
      _filterDropdownSearchFocusNode.requestFocus();
      return;
    }

    if (_startFilterDropdownScrollbarDrag(local)) {
      _commitEditing();
      _commitSheetRename();
      return;
    }

    final filterCheckboxOption = _filterDropdownCheckboxOptionAt(local);
    if (filterCheckboxOption != null) {
      _commitEditing();
      _commitSheetRename();
      _toggleFilterDropdownChoiceOption(filterCheckboxOption);
      return;
    }

    final filterBulkCommand = _filterDropdownBulkCommandAt(local);
    if (filterBulkCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _activateFilterDropdownBulkCommand(filterBulkCommand);
      return;
    }

    final filterOption = _filterDropdownOptionAt(local);
    if (filterOption != null) {
      _commitEditing();
      _commitSheetRename();
      _activateFilterDropdownOption(filterOption);
      return;
    }

    if (filterDropdownColumn != null &&
        _filterDropdownRect()?.contains(local) == true) {
      _commitEditing();
      _commitSheetRename();
      return;
    }

    if (filterDropdownColumn != null &&
        _filterDropdownRect()?.contains(local) != true &&
        _filterDropdownSearchRect()?.contains(local) != true &&
        _filterMarkerColumnAt(local, settings, metrics) == null) {
      setState(() {
        filterDropdownColumn = null;
      });
    }

    final zoomCommand = _zoomCommandAt(local);
    if (zoomCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _activateZoomCommand(zoomCommand);
      return;
    }
    if (_zoomMenuOpen) {
      setState(_closeTransientMenus);
    }

    final sheetTabsAction = _sheetTabsActionAt(local);

    final sheetListHiddenButtonIndex = _sheetListHiddenButtonIndexAt(local);
    if (sheetListHiddenButtonIndex != null) {
      _commitEditing();
      _commitSheetRename();
      _showSheetFromSheetListHiddenButton(sheetListHiddenButtonIndex);
      return;
    }

    final sheetListIndex = _sheetListIndexAt(local);
    if (sheetListIndex != null) {
      _commitEditing();
      _commitSheetRename();
      _activateSheetListItem(sheetListIndex);
      return;
    }

    final hiddenSheetIndex = _hiddenSheetListIndexAt(local);
    if (hiddenSheetIndex != null) {
      _commitEditing();
      _commitSheetRename();
      _showHiddenSheet(hiddenSheetIndex);
      return;
    }

    final openSheetListAt = sheetListAt;
    if (openSheetListAt != null && sheetTabsAction?.openSheetList != true) {
      final sheetListRect = fortuneSheetListRect(
        openSheetListAt,
        _workbook.sheets.length,
        viewportHeight: context.size?.height ?? double.infinity,
      );
      if (!sheetListRect.contains(local)) {
        setState(() {
          sheetListAt = null;
          hiddenSheetListAt = null;
          _sheetListScrollOffset = 0;
        });
      }
    }

    final sheetTabColorCommand = _sheetTabColorMenuCommandAt(local);
    if (sheetTabColorCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _activateSheetTabMenuCommand(sheetTabColorCommand);
      return;
    }
    if (_sheetTabColorMenuOpen && !_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }

    final sheetTabCommand = _sheetTabMenuCommandAt(local);
    if (sheetTabCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _activateSheetTabMenuCommand(sheetTabCommand);
      return;
    }

    final contextMenuCommand = _contextMenuCommandAt(local);
    final contextMenuInputCommand = _contextMenuInlineInputCommandAt(local);
    if (contextMenuInputCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _focusContextMenuInlineInput(contextMenuInputCommand);
      return;
    }
    if (contextMenuCommand != null) {
      _commitEditing();
      _commitSheetRename();
      _activateContextMenuCommand(contextMenuCommand);
      return;
    }

    if (_handleToolbarPointerDown(event, local, settings)) {
      return;
    }

    if (_isOutsideActiveSheetEventArea(local, settings)) {
      if (_hasOpenTransientMenu()) {
        setState(_closeTransientMenus);
      }
      _clearSheetRulerSelection();
      _clearActiveSheetPointerFocus();
      return;
    }

    _sheetFocused = true;

    if (event.kind == PointerDeviceKind.mouse &&
        (event.buttons & kSecondaryMouseButton) != 0) {
      _commitEditing();
      _commitSheetRename();
      final contextSelection = _cellCoordAtLocal(local, settings, metrics);
      final headerSelection = _headerSelectionAt(local, settings, metrics);
      if (contextSelection != null) {
        final anchor = _workbook.activeSheet.mergeAnchorFor(contextSelection);
        if (_isDataVerificationMarkerHit(anchor, local)) {
          _showDataVerificationDialog(anchor);
          return;
        }
      }
      if (sheetTabsAction?.sheetIndex != null) {
        final sheetTabItems = _sheetTabMenuItems;
        setState(() {
          final sheetIndex = sheetTabsAction!.sheetIndex!;
          if (sheetIndex != _workbook.activeSheetIndex) {
            _rememberActiveSheetScrollOffset();
            _activateSheetAtIndex(sheetIndex);
          }
          contextMenuAt = null;
          sheetTabMenuAt = sheetTabItems.isEmpty
              ? null
              : _sheetTabMenuOrigin(local);
          hiddenSheetListAt = null;
          _sheetTabColorMenuOpen = false;
          dataVerificationDropdownCoord = null;
          filterDropdownColumn = null;
          _sheetTabMenuSheetIndex = sheetIndex;
          toolbarPopupKey = null;
        });
        return;
      }
      if (!_workbook.settings.allowEdit) {
        setState(_closeTransientMenus);
        return;
      }
      final imageId = _imageIdAt(local, settings);
      final previousSelectionSave = cloneFortuneMetadata(
        _workbook.activeSheet.selectionSave,
      );
      final previousSelectionRange = cloneFortuneMetadata(
        _workbook.activeSheet.selectionRange,
      );
      if (imageId != null) {
        final image = _imageById(imageId);
        if (image != null) {
          setState(() => _activeImageId = imageId);
          if (_isBarcodeImage(image)) {
            _showBarcodeEditDialog(image);
          } else {
            _showImageEditDialog(image);
          }
        }
        return;
      }
      final headerContextRange = headerSelection == null
          ? null
          : _headerContextRangeForRightClick(headerSelection);
      setState(() {
        _contextMenuPreviousSelectionSave = previousSelectionSave;
        _contextMenuPreviousSelectionRange = previousSelectionRange;
        if (contextSelection != null) {
          final anchor = _workbook.activeSheet.mergeAnchorFor(contextSelection);
          if (!_selectionContainsCoord(_workbook.activeSheet, anchor)) {
            final range = _cellSelectionRange(anchor);
            selection = FortuneSelection(
              row: range.rowStart,
              column: range.columnStart,
              rowEnd: range.rowEnd,
              columnEnd: range.columnEnd,
            );
            _writeSelectionRange(range, anchor);
          }
        } else if (headerContextRange != null) {
          final range = headerContextRange;
          selection = FortuneSelection(
            row: range.rowStart,
            column: range.columnStart,
            rowEnd: range.rowEnd,
            columnEnd: range.columnEnd,
          );
          _writeSelectionRange(
            range,
            FortuneCellCoord(range.rowStart, range.columnStart),
          );
        }
        final contextItems = _contextMenuItemsForSelection(
          headerSelection != null
              ? _workbook.settings.headerContextMenu
              : _workbook.settings.cellContextMenu,
          range: headerContextRange,
        );
        _syncContextMenuInlineInputControllers(contextItems);
        contextMenuAt = contextItems.isEmpty
            ? null
            : _contextMenuOrigin(local, contextItems);
        _contextMenuHoveredIndex = null;
        _contextMenuIsHeader = headerSelection != null;
        _contextMenuIsEditor = false;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        dataVerificationDropdownCoord = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        _activeImageId = null;
      });
      return;
    }

    if (_handleToolbarPointerDown(event, local, settings)) {
      return;
    }

    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final formulaInputRect = _formulaBarInputRect();
    if (formulaInputRect != null && formulaInputRect.contains(local)) {
      _commitEditing();
      _commitSheetRename();
      _startFormulaBarEditing();
      return;
    }

    if (sheetTabsAction != null) {
      _commitEditing();
      _commitSheetRename();
      if (event.kind != PointerDeviceKind.mouse &&
          sheetTabsAction.sheetIndex != null &&
          !sheetTabsAction.openMenu) {
        _scheduleSheetTabLongPress(local, sheetTabsAction.sheetIndex!);
      }
      if (sheetTabsAction.sheetIndex != null && !sheetTabsAction.openMenu) {
        _sheetTabDragStart = local;
        _sheetTabDragSheetIndex = sheetTabsAction.sheetIndex;
      }
      _activateSheetTabsAction(sheetTabsAction, event.timeStamp, local);
      return;
    }

    if (local.dy < sheetTop) {
      _commitEditing();
      _commitSheetRename();
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        dataVerificationDropdownCoord = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        _activeImageId = null;
      });
      return;
    }

    final commentResizeSide = _commentBoxResizeSideAt(local);
    if (commentResizeSide != null &&
        _startCommentBoxResize(commentResizeSide, local)) {
      return;
    }

    final commentBoxCoord = _visibleCommentBoxCoordAt(local);
    if (commentBoxCoord != null &&
        _startCommentBoxMove(commentBoxCoord, local)) {
      return;
    }

    final imageHandle = _imageResizeSideAt(local, settings);
    if (imageHandle != null) {
      _commitEditing();
      _commitSheetRename();
      _startImageResize(imageHandle, local);
      return;
    }

    final imageId = _imageIdAt(local, settings);
    if (imageId != null) {
      _commitEditing();
      _commitSheetRename();
      final image = _imageById(imageId);
      if ((event.buttons & kSecondaryMouseButton) != 0 && image != null) {
        setState(() => _activeImageId = imageId);
        if (_isBarcodeImage(image)) {
          _showBarcodeEditDialog(image);
        } else {
          _showImageEditDialog(image);
        }
        return;
      }
      _startImageMove(imageId, local);
      setState(() {
        _activeImageId = imageId;
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
      });
      return;
    }

    final sheetY = local.dy - sheetTop;
    if ((event.buttons & kPrimaryMouseButton) != 0 &&
        _startSheetRulerGuideDrag(local)) {
      _commitEditing();
      _commitSheetRename();
      return;
    }
    if ((event.buttons & kPrimaryMouseButton) != 0) {
      _clearSheetRulerSelection();
    }
    final filterMarkerColumn = _filterMarkerColumnAt(local, settings, metrics);
    if (filterMarkerColumn != null) {
      _commitEditing();
      _commitSheetRename();
      _openFilterDropdown(filterMarkerColumn);
      return;
    }

    final columnHeaderMenuColumn = _columnHeaderMenuButtonColumnAt(
      local,
      settings,
      metrics,
    );
    if (columnHeaderMenuColumn != null) {
      _commitEditing();
      _commitSheetRename();
      _openColumnHeaderContextMenu(columnHeaderMenuColumn, local);
      return;
    }

    final headerSelection = _headerSelectionAt(local, settings, metrics);
    if (headerSelection != null) {
      _commitSheetRename();
      if (!_canSelectHeaderRange(_workbook.activeSheet)) {
        return;
      }
      if (_editingCommentCoord != null) {
        _commitCommentEditing();
      }
      _startHeaderSelectionDrag(
        headerSelection.axis,
        headerSelection.index,
        headerSelection.range,
      );
      return;
    }

    if (_selectionFillHandleRect(settings, metrics)?.contains(local) == true) {
      _commitEditing();
      _commitSheetRename();
      _startFillDrag();
      return;
    }

    final row = metrics.rowAt(_dataYAt(sheetY, settings, metrics)).index;
    final column = metrics
        .columnAt(_dataXAt(local.dx, settings, metrics))
        .index;
    if (_editingCommentCoord != null) {
      _commitCommentEditing();
    }
    final anchor = _workbook.activeSheet.mergeAnchorFor(
      FortuneCellCoord(math.max(0, row), math.max(0, column)),
    );
    final primaryRange = _cellSelectionRange(anchor);
    final hookCell = _workbook.activeSheet.cells[anchor];
    final hookInfo = _cellMouseHookInfo(anchor, primaryRange, metrics);
    if (_workbook.settings.beforeCellMouseDown?.call(hookCell, hookInfo) ==
        false) {
      return;
    }
    if (!_canSelectCell(_workbook.activeSheet, anchor)) {
      return;
    }
    final isDoubleTap =
        _lastPrimaryDownCoord == anchor &&
        _lastPrimaryDownTime != null &&
        event.timeStamp - _lastPrimaryDownTime! <
            const Duration(milliseconds: 450);
    _lastPrimaryDownTime = event.timeStamp;
    _lastPrimaryDownCoord = anchor;

    _commitEditing();
    _commitSheetRename();

    if (_formatPainterCell != null) {
      _startFormatPainterDrag(anchor);
      _notifyAfterCellMouseDown(hookCell, hookInfo);
      return;
    }

    if (HardwareKeyboard.instance.isShiftPressed) {
      final focus = FortuneCellCoord(selection.row, selection.column);
      final range = _expandRangeForMergedCells(
        FortuneRange(
          rowStart: math.min(focus.row, anchor.row),
          rowEnd: math.max(focus.row, anchor.row),
          columnStart: math.min(focus.column, anchor.column),
          columnEnd: math.max(focus.column, anchor.column),
        ),
      );
      setState(() {
        selection = FortuneSelection(
          row: focus.row,
          column: focus.column,
          rowEnd: range.rowEnd,
          columnEnd: range.columnEnd,
        );
        _writeSelectionRange(range, focus);
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        dataVerificationDropdownCoord = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        _activeImageId = null;
      });
      _selectionDragAnchor = null;
      _selectionDragging = false;
      _notifyAfterCellMouseDown(hookCell, hookInfo);
      return;
    }

    if (HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed) {
      setState(() {
        _addSelectionRange(primaryRange, anchor);
        selection = FortuneSelection(
          row: primaryRange.rowStart,
          column: primaryRange.columnStart,
          rowEnd: primaryRange.rowEnd,
          columnEnd: primaryRange.columnEnd,
        );
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        _activeImageId = null;
      });
      _selectionDragAnchor = null;
      _selectionDragging = false;
      _notifyAfterCellMouseDown(hookCell, hookInfo);
      return;
    }

    setState(() {
      selection = FortuneSelection(
        row: primaryRange.rowStart,
        column: primaryRange.columnStart,
        rowEnd: primaryRange.rowEnd,
        columnEnd: primaryRange.columnEnd,
      );
      _writeSelectionRange(primaryRange, anchor);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _activeImageId = null;
    });
    _selectionDragAnchor = anchor;
    _selectionDragging = false;
    _notifyAfterCellMouseDown(hookCell, hookInfo);
    if (_isDataVerificationCheckbox(anchor)) {
      _toggleDataVerificationCheckbox(anchor);
      return;
    }
    if (!isDoubleTap && _isDataVerificationMarkerHit(anchor, local)) {
      _openDataVerificationDropdown(anchor);
      return;
    }
    if (isDoubleTap) {
      _startEditing(anchor);
    }
  }

  FortuneCellCoord? _cellCoordAtLocal(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics, {
    Offset? scrollOverride,
  }) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    if (local.dy < sheetTop + dataTop || local.dx < dataLeft) {
      return null;
    }
    final size = _lastCanvasSize ?? context.size;
    if (size != null) {
      final footerHeight =
          settings.effectiveSheetBarHeight + settings.statisticBarHeight;
      if (local.dy > size.height - footerHeight) {
        return null;
      }
      final viewport = _sheetDataViewportSize(
        size,
        settings,
        _workbook.activeSheet,
      );
      if (viewport != null &&
          (local.dx >= dataLeft + viewport.width ||
              local.dy >= sheetTop + dataTop + viewport.height)) {
        return null;
      }
    }
    final sheetY = local.dy - sheetTop;
    final row = metrics
        .rowAt(
          _dataYAt(sheetY, settings, metrics, scrollOverride: scrollOverride),
        )
        .index;
    final column = metrics
        .columnAt(
          _dataXAt(local.dx, settings, metrics, scrollOverride: scrollOverride),
        )
        .index;
    final anchor = _workbook.activeSheet.mergeAnchorFor(
      FortuneCellCoord(math.max(0, row), math.max(0, column)),
    );
    return FortuneCellCoord(anchor.row, anchor.column);
  }

  ({String axis, int index, FortuneRange range})? _headerSelectionAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetY = local.dy - sheetTop;
    final headerLeft = _sheetHeaderLeft(settings);
    final headerTop = _sheetHeaderTop(settings);
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    final rowEnd = math.max(0, _effectiveRowCount(_workbook.activeSheet) - 1);
    final columnEnd = math.max(
      0,
      _effectiveColumnCount(_workbook.activeSheet) - 1,
    );
    if (_sheetRulerInserted(settings) &&
        sheetY >= 0 &&
        sheetY < dataTop &&
        local.dx >= 0 &&
        local.dx < dataLeft) {
      return (
        axis: 'all',
        index: 0,
        range: FortuneRange(
          rowStart: 0,
          rowEnd: rowEnd,
          columnStart: 0,
          columnEnd: columnEnd,
          extraFields: const {'row_select': true, 'column_select': true},
        ),
      );
    }
    if (sheetY >= headerTop &&
        sheetY < dataTop &&
        local.dx >= headerLeft &&
        local.dx < dataLeft) {
      return (
        axis: 'all',
        index: 0,
        range: FortuneRange(
          rowStart: 0,
          rowEnd: rowEnd,
          columnStart: 0,
          columnEnd: columnEnd,
          extraFields: const {'row_select': true, 'column_select': true},
        ),
      );
    }
    if (sheetY >= headerTop && sheetY < dataTop && local.dx >= dataLeft) {
      final size = _lastCanvasSize ?? context.size;
      final viewport = size == null
          ? null
          : _sheetDataViewportSize(size, settings, _workbook.activeSheet);
      if (viewport != null && local.dx >= dataLeft + viewport.width) {
        return null;
      }
      final column = metrics
          .columnAt(_dataXAt(local.dx, settings, metrics))
          .index
          .clamp(0, columnEnd)
          .toInt();
      return (
        axis: 'column',
        index: column,
        range: FortuneRange(
          rowStart: 0,
          rowEnd: rowEnd,
          columnStart: column,
          columnEnd: column,
          extraFields: const {'column_select': true},
        ),
      );
    }
    if (local.dx >= headerLeft && local.dx < dataLeft && sheetY >= dataTop) {
      final size = _lastCanvasSize ?? context.size;
      final viewport = size == null
          ? null
          : _sheetDataViewportSize(size, settings, _workbook.activeSheet);
      if (viewport != null &&
          local.dy >= sheetTop + dataTop + viewport.height) {
        return null;
      }
      final row = metrics
          .rowAt(_dataYAt(sheetY, settings, metrics))
          .index
          .clamp(0, rowEnd)
          .toInt();
      return (
        axis: 'row',
        index: row,
        range: FortuneRange(
          rowStart: row,
          rowEnd: row,
          columnStart: 0,
          columnEnd: columnEnd,
          extraFields: const {'row_select': true},
        ),
      );
    }
    return null;
  }

  Rect? _columnHeaderRect(
    int column,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    if (column < 0 || column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final width = metrics.columnEnd(column) - metrics.columnStart(column);
    if (width <= 0) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    return Rect.fromLTWH(
      _visualCellLeft(column, settings, metrics),
      sheetTop + _sheetHeaderTop(settings),
      width,
      settings.columnHeaderHeight,
    );
  }

  int? _columnHeaderAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetY = local.dy - sheetTop;
    final headerTop = _sheetHeaderTop(settings);
    final dataLeft = _sheetDataLeft(settings);
    if (sheetY < headerTop ||
        sheetY >= headerTop + settings.columnHeaderHeight ||
        local.dx < dataLeft) {
      return null;
    }
    final size = _lastCanvasSize ?? context.size;
    final viewport = size == null
        ? null
        : _sheetDataViewportSize(size, settings, _workbook.activeSheet);
    if (viewport != null && local.dx >= dataLeft + viewport.width) {
      return null;
    }
    final columnEnd = math.max(
      0,
      _effectiveColumnCount(_workbook.activeSheet) - 1,
    );
    return metrics
        .columnAt(_dataXAt(local.dx, settings, metrics))
        .index
        .clamp(0, columnEnd)
        .toInt();
  }

  int? _rowHeaderAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetY = local.dy - sheetTop;
    final headerLeft = _sheetHeaderLeft(settings);
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    if (local.dx < headerLeft || local.dx >= dataLeft || sheetY < dataTop) {
      return null;
    }
    final size = _lastCanvasSize ?? context.size;
    final viewport = size == null
        ? null
        : _sheetDataViewportSize(size, settings, _workbook.activeSheet);
    if (viewport != null && local.dy >= sheetTop + dataTop + viewport.height) {
      return null;
    }
    final rowEnd = math.max(0, _effectiveRowCount(_workbook.activeSheet) - 1);
    return metrics
        .rowAt(_dataYAt(sheetY, settings, metrics))
        .index
        .clamp(0, rowEnd)
        .toInt();
  }

  int? _columnHeaderMenuButtonColumnAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final column = _columnHeaderAt(local, settings, metrics);
    if (column == null || !_workbook.settings.allowEdit) {
      return null;
    }
    if (_hoveredColumnHeaderIndex != column) {
      return null;
    }
    final headerRect = _columnHeaderRect(column, settings, metrics);
    if (headerRect == null ||
        headerRect.width < fortuneColumnHeaderMenuMinWidth ||
        headerRect.height < fortuneColumnHeaderMenuMinHeight) {
      return null;
    }
    return fortuneColumnHeaderMenuButtonRect(headerRect).contains(local)
        ? column
        : null;
  }

  void _updateHeaderHover(Offset local) {
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final resizeTarget = _headerResizeTargetAt(local, settings, metrics);
    final nextColumn = _columnHeaderAt(local, settings, metrics);
    final nextRow = _rowHeaderAt(local, settings, metrics);
    final overHeader = nextColumn != null || nextRow != null;
    final nextCursor = resizeTarget != null
        ? resizeTarget.axis == 'column'
              ? SystemMouseCursors.resizeLeftRight
              : SystemMouseCursors.resizeUpDown
        : overHeader &&
              (_mouseCursor == SystemMouseCursors.resizeLeftRight ||
                  _mouseCursor == SystemMouseCursors.resizeUpDown)
        ? SystemMouseCursors.basic
        : _mouseCursor;
    if (nextColumn == _hoveredColumnHeaderIndex &&
        nextRow == _hoveredRowHeaderIndex &&
        nextCursor == _mouseCursor) {
      return;
    }
    setState(() {
      _hoveredColumnHeaderIndex = nextColumn;
      _hoveredRowHeaderIndex = nextRow;
      _mouseCursor = nextCursor;
    });
  }

  void _openColumnHeaderContextMenu(int column, Offset local) {
    if (!_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    final range = FortuneRange(
      rowStart: 0,
      rowEnd: math.max(0, _effectiveRowCount(_workbook.activeSheet) - 1),
      columnStart: column,
      columnEnd: column,
      extraFields: const {'column_select': true},
    );
    final previousSelectionSave = cloneFortuneMetadata(
      _workbook.activeSheet.selectionSave,
    );
    final previousSelectionRange = cloneFortuneMetadata(
      _workbook.activeSheet.selectionRange,
    );
    setState(() {
      _contextMenuPreviousSelectionSave = previousSelectionSave;
      _contextMenuPreviousSelectionRange = previousSelectionRange;
      selection = FortuneSelection(
        row: range.rowStart,
        column: range.columnStart,
        rowEnd: range.rowEnd,
        columnEnd: range.columnEnd,
      );
      _writeSelectionRange(
        range,
        FortuneCellCoord(range.rowStart, range.columnStart),
      );
      final contextItems = _contextMenuItemsForSelection(
        _workbook.settings.headerContextMenu,
        range: range,
      );
      _syncContextMenuInlineInputControllers(contextItems);
      contextMenuAt = contextItems.isEmpty
          ? null
          : _contextMenuOrigin(local, contextItems);
      _contextMenuIsHeader = true;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _activeImageId = null;
    });
  }

  void _handlePointerSignal(PointerSignalEvent event) {
    if (event is! PointerScrollEvent) {
      return;
    }
    _handlePointerScrollDelta(event, event.localPosition, event.scrollDelta);
  }

  void _handlePointerPanZoomUpdate(PointerPanZoomUpdateEvent event) {
    _handlePointerScrollDelta(event, event.localPosition, event.panDelta);
  }

  void _handlePointerScrollDelta(
    PointerEvent event,
    Offset localPosition,
    Offset scrollDelta,
  ) {
    final deltaY = scrollDelta.dy;
    if (_imageInsertDialogOpen) {
      return;
    }
    if (_barcodeDialogOpen) {
      _scrollBarcodeMenu(localPosition, deltaY);
      return;
    }
    if (_scrollFormulaSearchDialog(localPosition, deltaY)) {
      return;
    }
    if (_scrollFormatSearchDialog(localPosition, deltaY)) {
      return;
    }
    if (_shouldBlockDialogWheel(localPosition)) {
      return;
    }
    if (_toolbarPopupEventContains(localPosition)) {
      _scrollToolbarPopup(localPosition, deltaY);
      return;
    }
    if (_scrollToolbarPopup(localPosition, deltaY)) {
      return;
    }
    if (_scrollSheetList(localPosition, deltaY)) {
      return;
    }
    if (_scrollFilterDropdown(localPosition, deltaY)) {
      return;
    }
    final settings = _workbook.settings;
    final size = _lastCanvasSize ?? context.size;
    if (size != null &&
        !_sheetScrollAreaRect(size, settings).contains(localPosition)) {
      return;
    }
    setState(() {
      final metrics = _workbook.activeSheet.metrics(_workbook.settings);
      final sheet = _workbook.activeSheet;
      final viewport = _sheetDataViewportSize(size, settings, sheet);
      if (viewport == null || viewport.width <= 0 || viewport.height <= 0) {
        return;
      }
      final maxX = math.max(0.0, metrics.columnTotalWidth - viewport.width);
      final maxY = math.max(0.0, metrics.rowTotalHeight - viewport.height);
      final zoomRatio = _workbook.activeSheet.zoomRatio <= 0
          ? 1.0
          : _workbook.activeSheet.zoomRatio;
      final wheelAction = handleGlobalWheel(
        deltaX: scrollDelta.dx,
        deltaY: scrollDelta.dy,
        scrollLeft: scrollOffset.dx,
        scrollTop: scrollOffset.dy,
        visibleDataRows: metrics.visibleDataRows,
        visibleDataColumns: metrics.visibleDataColumns,
        zoomRatio: zoomRatio,
        verticalScrollLock: _wheelVerticalScrollLock,
        horizontalScrollLock: _wheelHorizontalScrollLock,
        visibleRowsUnique: _wheelVisibleRowsUnique,
        visibleColumnsUnique: _wheelVisibleColumnsUnique,
      );
      final nextScrollLeft = switch (wheelAction?['type']) {
        'horizontalScroll' => (wheelAction?['scrollLeft'] as num).toDouble(),
        _ => scrollOffset.dx,
      };
      final nextScrollTop = switch (wheelAction?['type']) {
        'verticalScroll' => (wheelAction?['scrollTop'] as num).toDouble(),
        _ => scrollOffset.dy,
      };
      scrollOffset = Offset(
        nextScrollLeft.clamp(0, maxX),
        nextScrollTop.clamp(0, maxY),
      );
      _applyWheelScrollState(wheelAction);
    });
    _updateRawChartHover(event);
  }

  Rect _sheetScrollAreaRect(Size size, FortuneSettings settings) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final footerHeight =
        settings.effectiveSheetBarHeight + settings.statisticBarHeight;
    return Rect.fromLTRB(
      0,
      sheetTop,
      size.width,
      math.max(sheetTop, size.height - footerHeight),
    );
  }

  Rect? _activeSheetEventAreaRect(FortuneSettings settings) {
    return null;
  }

  bool _isOutsideActiveSheetEventArea(Offset local, FortuneSettings settings) {
    final rect = _activeSheetEventAreaRect(settings);
    return rect != null && !rect.contains(local);
  }

  void _clearActiveSheetPointerFocus() {
    setState(() {
      _sheetFocused = false;
      _clearSheetAreaHoverStateValues();
    });
  }

  void _clearSheetAreaHoverState() {
    if (_hoveredColumnHeaderIndex == null &&
        _hoveredRowHeaderIndex == null &&
        _sheetRulerHoveredGuideIndex == null &&
        _sheetRulerTooltipText == null &&
        !_sheetRulerHoveringRuler &&
        !_sheetPrintAreaTooltipActive &&
        _sheetPrintAreaTooltipShowTimer == null &&
        !_sheetCornerTooltipActive &&
        _sheetCornerTooltipShowTimer == null &&
        _mouseCursor == SystemMouseCursors.basic) {
      return;
    }
    setState(_clearSheetAreaHoverStateValues);
  }

  void _clearSheetAreaHoverStateValues() {
    _cancelSheetPrintAreaTooltipTimers();
    _cancelSheetCornerTooltipTimers();
    _hoveredColumnHeaderIndex = null;
    _hoveredRowHeaderIndex = null;
    _sheetRulerHoveredGuideIndex = null;
    _sheetRulerTooltipText = null;
    _sheetRulerTooltipPosition = null;
    _sheetRulerHoveringRuler = false;
    _sheetPrintAreaTooltipHoverPosition = null;
    _sheetPrintAreaTooltipActive = false;
    _sheetCornerTooltipHoverPosition = null;
    _sheetCornerTooltipActive = false;
    _sheetCornerTooltipDismissedUntilExit = false;
    _mouseCursor = SystemMouseCursors.basic;
  }

  Size? _sheetDataViewportSize(
    Size? size,
    FortuneSettings settings,
    FortuneSheet sheet,
  ) {
    if (size == null) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final footerHeight =
        settings.effectiveSheetBarHeight + settings.statisticBarHeight;
    final metrics = sheet.metrics(settings);
    var dataWidth = math.max(0.0, size.width - _sheetDataLeft(settings));
    var dataHeight = math.max(
      0.0,
      size.height - sheetTop - footerHeight - _sheetDataTop(settings),
    );
    var vertical = metrics.rowTotalHeight > dataHeight;
    var horizontal = metrics.columnTotalWidth > dataWidth;
    if (vertical) {
      dataWidth = math.max(0.0, dataWidth - fortuneSheetScrollbarThickness);
    }
    if (horizontal) {
      dataHeight = math.max(0.0, dataHeight - fortuneSheetScrollbarThickness);
    }
    if (!vertical && metrics.rowTotalHeight > dataHeight) {
      dataWidth = math.max(0.0, dataWidth - fortuneSheetScrollbarThickness);
    }
    if (!horizontal && metrics.columnTotalWidth > dataWidth) {
      dataHeight = math.max(0.0, dataHeight - fortuneSheetScrollbarThickness);
    }
    return Size(dataWidth, dataHeight);
  }

  bool _sheetRulerInserted(FortuneSettings settings) {
    return _activeSheetRulerVisible() &&
        fortuneSheetGridClientPhysicalSize(_workbook.activeSheet) != null;
  }

  double _sheetRulerTopInset(FortuneSettings settings) {
    return _sheetRulerInserted(settings) ? settings.columnHeaderHeight : 0.0;
  }

  double _sheetRulerLeftInset(FortuneSettings settings) {
    return _sheetRulerInserted(settings) ? settings.rowHeaderWidth : 0.0;
  }

  double _sheetHeaderTop(FortuneSettings settings) {
    return _sheetRulerTopInset(settings);
  }

  double _sheetHeaderLeft(FortuneSettings settings) {
    return _sheetRulerLeftInset(settings);
  }

  double _sheetDataTop(FortuneSettings settings) {
    return _sheetHeaderTop(settings) + settings.columnHeaderHeight;
  }

  double _sheetDataLeft(FortuneSettings settings) {
    return _sheetHeaderLeft(settings) + settings.rowHeaderWidth;
  }

  Size _sheetPaintSize(
    Size size,
    FortuneSettings settings,
    FortuneSheet sheet,
  ) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final footerHeight =
        settings.effectiveSheetBarHeight + settings.statisticBarHeight;
    final availableSheetHeight = math.max(
      0.0,
      size.height - sheetTop - footerHeight,
    );
    return Size(size.width, availableSheetHeight);
  }

  bool _activeSheetRulerVisible() {
    final sheet = _workbook.activeSheet;
    final visible = sheet.extraFields[fortuneSheetRulerVisibleKey];
    if (visible is bool) {
      return visible;
    }
    return fortuneSheetGridClientPhysicalSize(sheet) != null;
  }

  List<FortuneSheetGuide> _activeSheetRulerGuides() {
    return _sheetRulerGuides(_workbook.activeSheet);
  }

  List<FortuneSheetGuide> _sheetRulerGuides(FortuneSheet sheet) {
    final raw = sheet.extraFields[fortuneSheetRulerGuidesKey];
    if (raw is! List) {
      return const <FortuneSheetGuide>[];
    }
    final guides = <FortuneSheetGuide>[];
    for (var index = 0; index < raw.length; index += 1) {
      final item = raw[index];
      if (item is! Map) {
        continue;
      }
      final axis = item['axis'];
      final position = _doubleFromObject(item['positionMm']);
      if ((axis != 'vertical' && axis != 'horizontal') || position == null) {
        continue;
      }
      guides.add(
        FortuneSheetGuide(
          index: _intValue(item['id']) ?? index,
          axis: '$axis',
          positionMm: position,
        ),
      );
    }
    return guides;
  }

  void _writeSheetRulerState({bool? visible, List<FortuneSheetGuide>? guides}) {
    final sheet = _workbook.activeSheet;
    final extraFields = <String, Object?>{
      for (final entry in sheet.extraFields.entries)
        entry.key: cloneFortuneMetadata(entry.value),
    };
    if (visible != null) {
      extraFields[fortuneSheetRulerVisibleKey] = visible;
    }
    if (guides != null) {
      extraFields[fortuneSheetRulerGuidesKey] = [
        for (final guide in guides)
          {
            'id': guide.index,
            'axis': guide.axis,
            'positionMm': guide.positionMm,
          },
      ];
    }
    _replaceActiveSheet(sheet.copyWith(extraFields: extraFields));
  }

  Rect? _sheetRulerDataRect(FortuneSettings settings) {
    final size = _lastCanvasSize ?? context.size;
    final sheet = _workbook.activeSheet;
    final physicalSize = fortuneSheetGridClientPhysicalSize(sheet);
    if (size == null || physicalSize == null || !_activeSheetRulerVisible()) {
      return null;
    }
    final dataViewport = _sheetDataViewportSize(size, settings, sheet);
    if (dataViewport == null) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final metrics = sheet.metrics(settings);
    final width = math.min(
      math.max(0.0, metrics.columnTotalWidth - scrollOffset.dx),
      dataViewport.width,
    );
    final height = math.min(
      math.max(0.0, metrics.rowTotalHeight - scrollOffset.dy),
      dataViewport.height,
    );
    if (width <= 0 || height <= 0) {
      return null;
    }
    return Rect.fromLTWH(
      _sheetDataLeft(settings),
      sheetTop + _sheetDataTop(settings),
      width,
      height,
    );
  }

  Rect? _sheetRulerTopRect(FortuneSettings settings) {
    final dataRect = _sheetRulerDataRect(settings);
    if (dataRect == null) {
      return null;
    }
    return Rect.fromLTWH(
      dataRect.left,
      dataRect.top - _sheetDataTop(settings),
      dataRect.width,
      _sheetRulerTopInset(settings),
    );
  }

  Rect? _sheetRulerLeftRect(FortuneSettings settings) {
    final dataRect = _sheetRulerDataRect(settings);
    if (dataRect == null) {
      return null;
    }
    return Rect.fromLTWH(
      0,
      dataRect.top,
      _sheetRulerLeftInset(settings),
      dataRect.height,
    );
  }

  String? _sheetRulerAxisAt(Offset local, FortuneSettings settings) {
    if (!_activeSheetRulerVisible() ||
        fortuneSheetGridClientPhysicalSize(_workbook.activeSheet) == null) {
      return null;
    }
    if (_headerResizeTargetAt(
          local,
          settings,
          _workbook.activeSheet.metrics(settings),
        ) !=
        null) {
      return null;
    }
    if (_sheetRulerTopRect(settings)?.contains(local) == true) {
      return 'vertical';
    }
    if (_sheetRulerLeftRect(settings)?.contains(local) == true) {
      return 'horizontal';
    }
    return null;
  }

  FortuneSheetGuide? _sheetGuideAt(Offset local, FortuneSettings settings) {
    final dataRect = _sheetRulerDataRect(settings);
    final physicalSize = fortuneSheetGridClientPhysicalSize(
      _workbook.activeSheet,
    );
    if (dataRect == null || physicalSize == null || !dataRect.contains(local)) {
      return null;
    }
    final metrics = _workbook.activeSheet.metrics(settings);
    final maxWidthMm = fortuneLogicalPixelsToMillimeters(
      metrics.columnTotalWidth,
    );
    final maxHeightMm = fortuneLogicalPixelsToMillimeters(
      metrics.rowTotalHeight,
    );
    FortuneSheetGuide? best;
    var bestDistance = double.infinity;
    for (final guide in _activeSheetRulerGuides()) {
      final distance = guide.axis == 'vertical'
          ? (local.dx -
                    (dataRect.left +
                        fortuneMillimetersToLogicalPixels(
                          guide.positionMm.clamp(0.0, maxWidthMm),
                        ) -
                        scrollOffset.dx))
                .abs()
          : (local.dy -
                    (dataRect.top +
                        fortuneMillimetersToLogicalPixels(
                          guide.positionMm.clamp(0.0, maxHeightMm),
                        ) -
                        scrollOffset.dy))
                .abs();
      if (distance < bestDistance && distance <= fortuneSheetGuideHitSlop) {
        best = guide;
        bestDistance = distance;
      }
    }
    return best;
  }

  double _sheetGuidePositionMmFromLocal(
    String axis,
    Offset local,
    Rect dataRect,
    FortuneSheetMetrics metrics,
  ) {
    final clampedLocal = Offset(
      local.dx.clamp(dataRect.left, dataRect.right).toDouble(),
      local.dy.clamp(dataRect.top, dataRect.bottom).toDouble(),
    );
    final logical = axis == 'vertical'
        ? (clampedLocal.dx - dataRect.left + scrollOffset.dx).clamp(
            0.0,
            metrics.columnTotalWidth,
          )
        : (clampedLocal.dy - dataRect.top + scrollOffset.dy).clamp(
            0.0,
            metrics.rowTotalHeight,
          );
    final mm = fortuneLogicalPixelsToMillimeters(logical);
    final maxMm = fortuneLogicalPixelsToMillimeters(
      axis == 'vertical' ? metrics.columnTotalWidth : metrics.rowTotalHeight,
    );
    final snapped = mm.clamp(0.0, maxMm).roundToDouble();
    return snapped > maxMm ? maxMm.floorToDouble() : snapped;
  }

  String _formatSheetGuidePosition(double positionMm) {
    return '${positionMm.toStringAsFixed(0)} mm';
  }

  int _nextSheetGuideIndex(List<FortuneSheetGuide> guides) {
    var next = 0;
    for (final guide in guides) {
      next = math.max(next, guide.index + 1);
    }
    return next;
  }

  Offset _clampScrollOffsetToVisibleSheet(
    Offset source,
    FortuneSheet sheet, {
    required FortuneSettings settings,
    Size? size,
  }) {
    final viewport = _sheetDataViewportSize(
      size ?? _lastCanvasSize ?? context.size,
      settings,
      sheet,
    );
    if (viewport == null || viewport.width <= 0 || viewport.height <= 0) {
      return Offset.zero;
    }
    final metrics = sheet.metrics(settings);
    final maxX = math.max(0.0, metrics.columnTotalWidth - viewport.width);
    final maxY = math.max(0.0, metrics.rowTotalHeight - viewport.height);
    return Offset(
      source.dx.clamp(0.0, maxX).toDouble(),
      source.dy.clamp(0.0, maxY).toDouble(),
    );
  }

  ({
    Rect? verticalTrack,
    Rect? verticalThumb,
    Rect? horizontalTrack,
    Rect? horizontalThumb,
    double maxScrollX,
    double maxScrollY,
  })?
  _sheetScrollbarGeometry() {
    final size = _lastCanvasSize ?? context.size;
    if (size == null) {
      return null;
    }
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final viewport = _sheetDataViewportSize(size, settings, sheet);
    if (viewport == null || viewport.width <= 0 || viewport.height <= 0) {
      return null;
    }
    final metrics = sheet.metrics(settings);
    final maxScrollX = math.max(0.0, metrics.columnTotalWidth - viewport.width);
    final maxScrollY = math.max(0.0, metrics.rowTotalHeight - viewport.height);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    Rect? verticalTrack;
    Rect? verticalThumb;
    if (maxScrollY > 0 && metrics.rowTotalHeight > 0) {
      verticalTrack = Rect.fromLTWH(
        dataLeft + viewport.width,
        sheetTop + dataTop,
        fortuneSheetScrollbarThickness,
        viewport.height,
      );
      final thumbHeight = math.min(
        verticalTrack.height,
        math.max(
          fortuneSheetScrollbarMinThumbLength,
          verticalTrack.height * viewport.height / metrics.rowTotalHeight,
        ),
      );
      final travel = math.max(0.0, verticalTrack.height - thumbHeight);
      final progress = (scrollOffset.dy / maxScrollY).clamp(0.0, 1.0);
      verticalThumb = Rect.fromLTWH(
        verticalTrack.left + 1,
        verticalTrack.top + travel * progress,
        verticalTrack.width - 2,
        thumbHeight,
      );
    }
    Rect? horizontalTrack;
    Rect? horizontalThumb;
    if (maxScrollX > 0 && metrics.columnTotalWidth > 0) {
      horizontalTrack = Rect.fromLTWH(
        dataLeft,
        sheetTop + dataTop + viewport.height,
        viewport.width,
        fortuneSheetScrollbarThickness,
      );
      final thumbWidth = math.min(
        horizontalTrack.width,
        math.max(
          fortuneSheetScrollbarMinThumbLength,
          horizontalTrack.width * viewport.width / metrics.columnTotalWidth,
        ),
      );
      final travel = math.max(0.0, horizontalTrack.width - thumbWidth);
      final progress = (scrollOffset.dx / maxScrollX).clamp(0.0, 1.0);
      horizontalThumb = Rect.fromLTWH(
        horizontalTrack.left + travel * progress,
        horizontalTrack.top + 1,
        thumbWidth,
        horizontalTrack.height - 2,
      );
    }
    if (verticalTrack == null && horizontalTrack == null) {
      return null;
    }
    return (
      verticalTrack: verticalTrack,
      verticalThumb: verticalThumb,
      horizontalTrack: horizontalTrack,
      horizontalThumb: horizontalThumb,
      maxScrollX: maxScrollX,
      maxScrollY: maxScrollY,
    );
  }

  bool _startSheetScrollbarDrag(Offset local) {
    final geometry = _sheetScrollbarGeometry();
    if (geometry == null) {
      return false;
    }
    final verticalTrack = geometry.verticalTrack;
    final verticalThumb = geometry.verticalThumb;
    if (verticalTrack != null && verticalThumb != null) {
      if (verticalTrack.contains(local)) {
        if (!verticalThumb.inflate(3).contains(local)) {
          final direction = local.dy < verticalThumb.top ? -1.0 : 1.0;
          final nextOffset = _clampScrollOffsetToVisibleSheet(
            Offset(
              scrollOffset.dx,
              scrollOffset.dy + direction * verticalTrack.height,
            ),
            _workbook.activeSheet,
            settings: _workbook.settings,
            size: _lastCanvasSize ?? context.size,
          );
          if (nextOffset != scrollOffset) {
            setState(() {
              scrollOffset = nextOffset;
              _rememberActiveSheetScrollOffset();
            });
          }
          return true;
        }
        setState(() {
          _sheetScrollbarDragAxis = 'vertical';
          _sheetScrollbarDragStartPosition = local.dy;
          _sheetScrollbarDragStartOffset = scrollOffset.dy;
        });
        return true;
      }
    }
    final horizontalTrack = geometry.horizontalTrack;
    final horizontalThumb = geometry.horizontalThumb;
    if (horizontalTrack != null && horizontalThumb != null) {
      if (horizontalTrack.contains(local)) {
        if (!horizontalThumb.inflate(3).contains(local)) {
          final direction = local.dx < horizontalThumb.left ? -1.0 : 1.0;
          final nextOffset = _clampScrollOffsetToVisibleSheet(
            Offset(
              scrollOffset.dx + direction * horizontalTrack.width,
              scrollOffset.dy,
            ),
            _workbook.activeSheet,
            settings: _workbook.settings,
            size: _lastCanvasSize ?? context.size,
          );
          if (nextOffset != scrollOffset) {
            setState(() {
              scrollOffset = nextOffset;
              _rememberActiveSheetScrollOffset();
            });
          }
          return true;
        }
        setState(() {
          _sheetScrollbarDragAxis = 'horizontal';
          _sheetScrollbarDragStartPosition = local.dx;
          _sheetScrollbarDragStartOffset = scrollOffset.dx;
        });
        return true;
      }
    }
    return false;
  }

  bool _updateSheetScrollbarDrag(Offset local) {
    final axis = _sheetScrollbarDragAxis;
    if (axis == null) {
      return false;
    }
    final geometry = _sheetScrollbarGeometry();
    if (geometry == null) {
      _cancelSheetScrollbarDrag();
      return false;
    }
    final isVertical = axis == 'vertical';
    final track = isVertical
        ? geometry.verticalTrack
        : geometry.horizontalTrack;
    final thumb = isVertical
        ? geometry.verticalThumb
        : geometry.horizontalThumb;
    final maxScroll = isVertical ? geometry.maxScrollY : geometry.maxScrollX;
    if (track == null || thumb == null || maxScroll <= 0) {
      return true;
    }
    final trackTravel = isVertical
        ? track.height - thumb.height
        : track.width - thumb.width;
    if (trackTravel <= 0) {
      return true;
    }
    final pointerPosition = isVertical ? local.dy : local.dx;
    final delta = pointerPosition - _sheetScrollbarDragStartPosition;
    final nextAxisOffset =
        (_sheetScrollbarDragStartOffset + delta / trackTravel * maxScroll)
            .clamp(0.0, maxScroll)
            .toDouble();
    final nextOffset = isVertical
        ? Offset(scrollOffset.dx, nextAxisOffset)
        : Offset(nextAxisOffset, scrollOffset.dy);
    if (nextOffset == scrollOffset) {
      return true;
    }
    setState(() {
      scrollOffset = nextOffset;
      _rememberActiveSheetScrollOffset();
    });
    return true;
  }

  bool _commitSheetScrollbarDrag() {
    if (_sheetScrollbarDragAxis == null) {
      return false;
    }
    _cancelSheetScrollbarDrag();
    return true;
  }

  void _cancelSheetScrollbarDrag() {
    _sheetScrollbarDragAxis = null;
    _sheetScrollbarDragStartPosition = 0;
    _sheetScrollbarDragStartOffset = 0;
  }

  bool _shouldBlockDialogWheel(Offset local) {
    final dialogRects = <Rect?>[
      _searchDialogRect(),
      _locationMessageDialogRect(),
      _screenshotDialogRect(),
      _customSortDialogRect(),
      _axisSizeDialogRect(),
      _imageInsertDialogRect(),
      _hyperlinkDialogRect(),
      _dataVerificationDialogRect(),
      _splitTextDialogRect(),
      _locationDialogRect(),
      _formatSearchDialogRect(),
      _formulaSearchDialogRect(),
      _conditionRuleDialogRect(),
    ];
    return dialogRects.any((rect) => rect?.contains(local) == true);
  }

  void _applyWheelScrollState(Map<String, Object?>? wheelAction) {
    if (wheelAction == null) {
      return;
    }
    final rows = wheelAction['visibleRowsUnique'];
    if (rows is List) {
      _wheelVisibleRowsUnique = List<num>.from(rows);
    }
    final columns = wheelAction['visibleColumnsUnique'];
    if (columns is List) {
      _wheelVisibleColumnsUnique = List<num>.from(columns);
    }
    final verticalScrollLock = wheelAction['verticalScrollLock'];
    if (verticalScrollLock is bool) {
      _wheelVerticalScrollLock = verticalScrollLock;
    }
    final horizontalScrollLock = wheelAction['horizontalScrollLock'];
    if (horizontalScrollLock is bool) {
      _wheelHorizontalScrollLock = horizontalScrollLock;
    }
    _wheelCacheClearTimer?.cancel();
    _wheelCacheClearTimer = Timer(const Duration(milliseconds: 500), () {
      _wheelVisibleRowsUnique = null;
      _wheelVisibleColumnsUnique = null;
    });
    _wheelScrollLockTimer?.cancel();
    _wheelScrollLockTimer = Timer(const Duration(milliseconds: 50), () {
      _wheelVerticalScrollLock = false;
      _wheelHorizontalScrollLock = false;
    });
  }

  void _clearWheelScrollState() {
    _wheelCacheClearTimer?.cancel();
    _wheelCacheClearTimer = null;
    _wheelScrollLockTimer?.cancel();
    _wheelScrollLockTimer = null;
    _wheelVerticalScrollLock = false;
    _wheelHorizontalScrollLock = false;
    _wheelVisibleRowsUnique = null;
    _wheelVisibleColumnsUnique = null;
  }

  bool _scrollToolbarPopup(Offset local, double deltaY) {
