    final nextOffset = (_toolbarPopupScrollOffset + deltaY).clamp(
      0.0,
      maxScrollOffset,
    );
    if (nextOffset == _toolbarPopupScrollOffset) {
      return true;
    }
    final key = toolbarPopupKey;
    setState(() {
      _toolbarPopupScrollOffset = nextOffset;
      _toolbarPopupHoveredScrollButtonDirection = null;
      _toolbarPopupPressedScrollButtonDirection = null;
      _toolbarPopupHoveredIndex = key == null
          ? null
          : _toolbarPopupHoverIndexAt(rect, key, local);
    });
    return true;
  }

