  bool _scrollFilterDropdown(Offset local, double deltaY) {
    final column = filterDropdownColumn;
    final rect = _filterDropdownRect();
    if (column == null || rect == null) {
      return false;
    }
    final searchRect = _filterDropdownSearchRect();
    if (!rect.contains(local)) {
      return searchRect?.contains(local) == true;
    }
    final labels = _filterDropdownLabels(column);
    final fixedRows = _filterDropdownFixedRowCount();
    final choiceCount = math.max(0, labels.length - fixedRows);
    final visibleChoiceRows = math.max(
      0.0,
      fortuneFilterDropdownMaxVisibleRows - fixedRows,
    );
    final maxScrollOffset = math.max(
      0.0,
      (choiceCount - visibleChoiceRows) * fortuneFilterDropdownRowHeight,
    );
    if (maxScrollOffset <= 0) {
      return true;
    }
    final nextOffset = (_filterDropdownScrollOffset + deltaY).clamp(
      0.0,
      maxScrollOffset,
    );
    if (nextOffset == _filterDropdownScrollOffset) {
      return true;
    }
    setState(() {
      _filterDropdownScrollOffset = nextOffset;
    });
    return true;
  }

  ({Rect track, Rect thumb, double maxScrollOffset})?
  _filterDropdownScrollbarGeometry() {
    final column = filterDropdownColumn;
    final rect = _filterDropdownRect();
    if (column == null || rect == null) {
      return null;
    }
    final labels = _filterDropdownLabels(column);
    final fixedRows = _filterDropdownFixedRowCount();
    final choiceCount = math.max(0, labels.length - fixedRows);
    final visibleChoiceRows = math.max(
      0.0,
      fortuneFilterDropdownMaxVisibleRows - fixedRows,
    );
    if (choiceCount <= visibleChoiceRows) {
      return null;
    }
    final trackTop = rect.top + fixedRows * fortuneFilterDropdownRowHeight + 3;
    final trackHeight =
        (visibleChoiceRows * fortuneFilterDropdownRowHeight) - 6;
    final maxScrollOffset = math.max(
      0.0,
      (choiceCount - visibleChoiceRows) * fortuneFilterDropdownRowHeight,
    );
    if (maxScrollOffset <= 0) {
      return null;
    }
    final trackRect = Rect.fromLTWH(rect.right - 5, trackTop, 3, trackHeight);
    final thumbHeight = math.max(
      16.0,
      trackHeight * visibleChoiceRows / choiceCount,
    );
    final thumbTop =
        trackTop +
        (trackHeight - thumbHeight) *
            (_filterDropdownScrollOffset / maxScrollOffset).clamp(0.0, 1.0);
    final thumbRect = Rect.fromLTWH(
      trackRect.left,
      thumbTop,
      trackRect.width,
      thumbHeight,
    );
    return (
      track: trackRect,
      thumb: thumbRect,
      maxScrollOffset: maxScrollOffset,
    );
  }

  bool _startFilterDropdownScrollbarDrag(Offset local) {
    final geometry = _filterDropdownScrollbarGeometry();
    if (geometry == null) {
      return false;
    }
    final hitRect = Rect.fromLTRB(
      geometry.track.left - 5,
      geometry.track.top,
      geometry.track.right + 5,
      geometry.track.bottom,
    );
    if (!hitRect.contains(local)) {
      return false;
    }
    if (!geometry.thumb.inflate(3).contains(local)) {
      final visibleChoiceRows = math.max(
        0.0,
        fortuneFilterDropdownMaxVisibleRows - _filterDropdownFixedRowCount(),
      );
      final pageDelta = visibleChoiceRows * fortuneFilterDropdownRowHeight;
      final direction = local.dy < geometry.thumb.top ? -1.0 : 1.0;
      final nextOffset = (_filterDropdownScrollOffset + direction * pageDelta)
          .clamp(0.0, geometry.maxScrollOffset);
      if (nextOffset != _filterDropdownScrollOffset) {
        setState(() {
          _filterDropdownScrollOffset = nextOffset;
        });
      }
      return true;
    }
    setState(() {
      _filterDropdownScrollbarDragging = true;
      _filterDropdownScrollbarDragStartY = local.dy;
      _filterDropdownScrollbarDragStartOffset = _filterDropdownScrollOffset;
    });
    return true;
  }

  bool _updateFilterDropdownScrollbarDrag(Offset local) {
    if (!_filterDropdownScrollbarDragging) {
      return false;
    }
    final geometry = _filterDropdownScrollbarGeometry();
    if (geometry == null) {
      _cancelFilterDropdownScrollbarDrag();
      return false;
    }
    final trackTravel = geometry.track.height - geometry.thumb.height;
    if (trackTravel <= 0) {
      return true;
    }
    final delta = local.dy - _filterDropdownScrollbarDragStartY;
    final nextOffset =
        (_filterDropdownScrollbarDragStartOffset +
                delta / trackTravel * geometry.maxScrollOffset)
            .clamp(0.0, geometry.maxScrollOffset);
    if (nextOffset == _filterDropdownScrollOffset) {
      return true;
    }
    setState(() {
      _filterDropdownScrollOffset = nextOffset;
    });
    return true;
  }

  bool _commitFilterDropdownScrollbarDrag() {
    if (!_filterDropdownScrollbarDragging) {
      return false;
    }
    _cancelFilterDropdownScrollbarDrag();
    return true;
  }

  void _cancelFilterDropdownScrollbarDrag() {
    _filterDropdownScrollbarDragging = false;
    _filterDropdownScrollbarDragStartY = 0;
    _filterDropdownScrollbarDragStartOffset = 0;
  }

