  bool _scrollBarcodeTextMenu(
    Offset local,
    double deltaY, {
    required bool open,
    required int itemCount,
    required double scrollOffset,
    required Rect Function(Rect dialogRect, int itemCount) menuRect,
    required ValueChanged<double> setScrollOffset,
    required ValueChanged<int?> setHoveredIndex,
    required int? Function(Offset local) indexAt,
  }) {
    if (!_barcodeDialogOpen || !open) {
      return false;
    }
    final rect = _barcodeDialogRect();
    if (rect == null) {
      return false;
    }
    final menu = menuRect(rect, itemCount);
    if (!menu.contains(local)) {
      return false;
    }
    final maxScrollOffset = fortuneBarcodeTextMenuMaxScrollOffset(itemCount);
    if (maxScrollOffset <= 0) {
      return true;
    }
    final nextOffset = (scrollOffset + deltaY).clamp(0.0, maxScrollOffset);
    if (nextOffset == scrollOffset) {
      return true;
    }
    setState(() {
      setScrollOffset(nextOffset);
      setHoveredIndex(indexAt(local));
    });
    return true;
  }

