  bool _handleToolbarPointerDown(
    PointerDownEvent event,
    Offset local,
    FortuneSettings settings,
  ) {
    if (!settings.showToolbar || local.dy > settings.effectiveToolbarHeight) {
      return false;
    }
    final toolbarKey = _toolbarKeyAt(local);
    final toolbarComboArrowKey = _toolbarComboArrowKeyAt(local);
    if (toolbarKey == null && toolbarComboArrowKey == null) {
      return false;
    }
    if (toolbarComboArrowKey != null) {
      if (_editingCoord != null) {
        _rememberInlineToolbarSelectionRange();
      } else if (!_shouldKeepEditingForToolbarCombo(toolbarComboArrowKey)) {
        _commitEditing();
      }
      _commitSheetRename();
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        dataVerificationDropdownCoord = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = toolbarComboArrowKey;
        _toolbarPopupHoveredIndex = null;
        _toolbarPopupScrollOffset = _initialToolbarPopupScrollOffsetFor(
          toolbarComboArrowKey,
        );
        _toolbarPopupHoveredScrollButtonDirection = null;
        _toolbarPopupPressedScrollButtonDirection = null;
        _conditionFormatSubmenuKey = null;
        _conditionFormatHoveredTopLevelIndex = null;
        _conditionFormatHoveredSubmenuIndex = null;
      });
      return true;
    }
    if (_isToolbarEditCommand(toolbarKey)) {
      _commitEditing();
      _commitSheetRename();
      final isDoubleClick =
          _lastToolbarDownKey == toolbarKey &&
          _lastToolbarDownTime != null &&
          event.timeStamp - _lastToolbarDownTime! <
              const Duration(milliseconds: 450);
      _lastToolbarDownTime = event.timeStamp;
      _lastToolbarDownKey = toolbarKey;
      _activateToolbarEditCommand(toolbarKey!, isDoubleClick: isDoubleClick);
      return true;
    }
    if (_isToolbarStyleCommand(toolbarKey)) {
      if (_editingCoord != null) {
        final inlineRange = _inlineToolbarFormatRange();
        if (inlineRange != null) {
          _inlineToolbarSelectionRange = inlineRange;
          _commitSheetRename();
          _activateToolbarPopupCommand(toolbarKey!);
          return true;
        }
      }
      _commitEditing();
      _commitSheetRename();
      _toggleSelectedCellStyle(toolbarKey!);
      return true;
    }
    if (_isToolbarComboCommand(toolbarKey)) {
      final comboKey = toolbarKey!;
      if (!_shouldKeepEditingForToolbarCombo(comboKey)) {
        _commitEditing();
      } else {
        _rememberInlineToolbarSelectionRange();
      }
      _commitSheetRename();
      _activateToolbarComboPrimaryCommand(comboKey);
      return true;
    }
    if (_isToolbarImmediateCommand(toolbarKey)) {
      _commitEditing();
      _commitSheetRename();
      _activateToolbarImmediateCommand(toolbarKey!);
      return true;
    }
    _commitEditing();
    _commitSheetRename();
    if (_activateCustomToolbarItem(toolbarKey)) {
      return true;
    }
    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = toolbarKey;
      _toolbarPopupHoveredIndex = null;
      _toolbarPopupScrollOffset = _initialToolbarPopupScrollOffsetFor(
        toolbarKey!,
      );
      _toolbarPopupHoveredScrollButtonDirection = null;
      _toolbarPopupPressedScrollButtonDirection = null;
      _conditionFormatSubmenuKey = null;
      _conditionFormatHoveredTopLevelIndex = null;
      _conditionFormatHoveredSubmenuIndex = null;
    });
    return true;
  }

  double _dataXAt(
    double localX,
    FortuneSettings settings,
    FortuneSheetMetrics metrics, {
    Offset? scrollOverride,
  }) {
    final effectiveScrollOffset = scrollOverride ?? scrollOffset;
    final dataX = localX - _sheetDataLeft(settings);
    final frozen = _workbook.activeSheet.frozen;
    final columnFocus = frozen?.columnFocusIndex(
      metrics.visibleDataColumns.length,
    );
    if (columnFocus == null) {
      return dataX + effectiveScrollOffset.dx;
    }
    final frozenWidth = metrics.columnEnd(columnFocus);
    return dataX < frozenWidth ? dataX : dataX + effectiveScrollOffset.dx;
  }

  double _dataYAt(
    double sheetY,
    FortuneSettings settings,
    FortuneSheetMetrics metrics, {
    Offset? scrollOverride,
  }) {
    final effectiveScrollOffset = scrollOverride ?? scrollOffset;
    final dataY = sheetY - _sheetDataTop(settings);
    final frozen = _workbook.activeSheet.frozen;
    final rowFocus = frozen?.rowFocusIndex(metrics.visibleDataRows.length);
    if (rowFocus == null) {
      return dataY + effectiveScrollOffset.dy;
    }
    final frozenHeight = metrics.rowEnd(rowFocus);
    return dataY < frozenHeight ? dataY : dataY + effectiveScrollOffset.dy;
  }

  double _visualCellLeft(
    int column,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final start = metrics.columnStart(column);
    final frozen = _workbook.activeSheet.frozen;
    final columnFocus = frozen?.columnFocusIndex(
      metrics.visibleDataColumns.length,
    );
    if (columnFocus != null && column <= columnFocus) {
      return _sheetDataLeft(settings) + start;
    }
    return _sheetDataLeft(settings) + start - scrollOffset.dx;
  }

  double _visualCellTop(
    int row,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final start = metrics.rowStart(row);
    final frozen = _workbook.activeSheet.frozen;
    final rowFocus = frozen?.rowFocusIndex(metrics.visibleDataRows.length);
    if (rowFocus != null && row <= rowFocus) {
      return _sheetDataTop(settings) + start;
    }
    return _sheetDataTop(settings) + start - scrollOffset.dy;
  }

  bool _startSheetRulerGuideDrag(Offset local) {
    final settings = _workbook.settings;
    final dataRect = _sheetRulerDataRect(settings);
    final physicalSize = fortuneSheetGridClientPhysicalSize(
      _workbook.activeSheet,
    );
    final metrics = _workbook.activeSheet.metrics(settings);
    if (dataRect == null || physicalSize == null) {
      return false;
    }
    final existing = _sheetGuideAt(local, settings);
    if (existing != null) {
      setState(() {
        _sheetRulerDragAxis = existing.axis;
        _sheetRulerDragStart = local;
        _sheetRulerGuideMoved = false;
        _sheetRulerDraggingGuide = existing;
        _sheetRulerSelectedGuideIndex = null;
        _sheetRulerHoveredGuideIndex = existing.index;
        _sheetRulerTooltipText = _formatSheetGuidePosition(existing.positionMm);
        _sheetRulerTooltipPosition = local;
        _closeTransientMenus();
      });
      return true;
    }
    final axis = _sheetRulerAxisAt(local, settings);
    if (axis == null) {
      return false;
    }
    final guides = _activeSheetRulerGuides();
    final positionMm = _sheetGuidePositionMmFromLocal(
      axis,
      local,
      dataRect,
      metrics,
    );
    final guide = FortuneSheetGuide(
      index: _nextSheetGuideIndex(guides),
      axis: axis,
      positionMm: positionMm,
    );
    setState(() {
      _sheetRulerDragAxis = axis;
      _sheetRulerDragStart = local;
      _sheetRulerGuideMoved = true;
      _sheetRulerDraggingGuide = guide;
      _sheetRulerSelectedGuideIndex = null;
      _sheetRulerHoveredGuideIndex = guide.index;
      _sheetRulerTooltipText = _formatSheetGuidePosition(positionMm);
      _sheetRulerTooltipPosition = local;
      _closeTransientMenus();
    });
    return true;
  }

  bool _updateSheetRulerGuideDrag(Offset local) {
    final axis = _sheetRulerDragAxis;
    final guide = _sheetRulerDraggingGuide;
    if (axis == null || guide == null) {
      return false;
    }
    final dataRect = _sheetRulerDataRect(_workbook.settings);
    final physicalSize = fortuneSheetGridClientPhysicalSize(
      _workbook.activeSheet,
    );
    final metrics = _workbook.activeSheet.metrics(_workbook.settings);
    if (dataRect == null || physicalSize == null) {
      _cancelSheetRulerGuideDrag();
      return true;
    }
    final positionMm = _sheetGuidePositionMmFromLocal(
      axis,
      local,
      dataRect,
      metrics,
    );
    final tooltipPosition = _clampSheetGuideTooltipPosition(local, dataRect);
    setState(() {
      final start = _sheetRulerDragStart;
      if (start == null || (local - start).distance > 3) {
        _sheetRulerGuideMoved = true;
      }
      _sheetRulerDraggingGuide = guide.copyWith(positionMm: positionMm);
      _sheetRulerTooltipText = _formatSheetGuidePosition(positionMm);
      _sheetRulerTooltipPosition = tooltipPosition;
    });
    return true;
  }

  Offset _clampSheetGuideTooltipPosition(Offset local, Rect dataRect) {
    return Offset(
      local.dx.clamp(dataRect.left, dataRect.right).toDouble(),
      local.dy.clamp(dataRect.top, dataRect.bottom).toDouble(),
    );
  }

  Offset? _sheetPrintAreaBoundaryTooltipPosition(Offset local) {
    final size = _lastCanvasSize ?? context.size;
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final physicalSize = fortuneSheetGridClientPhysicalSize(sheet);
    if (size == null || physicalSize == null) {
      return null;
    }
    final viewport = _sheetDataViewportSize(size, settings, sheet);
    if (viewport == null || viewport.width <= 0 || viewport.height <= 0) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final dataRect = Rect.fromLTWH(
      _sheetDataLeft(settings),
      sheetTop + _sheetDataTop(settings),
      viewport.width,
      viewport.height,
    );
    if (dataRect.isEmpty || !dataRect.inflate(4).contains(local)) {
      return null;
    }
    final boundaryX =
        dataRect.left +
        fortuneMillimetersToLogicalPixels(physicalSize.widthMm) -
        scrollOffset.dx;
    final boundaryY =
        dataRect.top +
        fortuneMillimetersToLogicalPixels(physicalSize.heightMm) -
        scrollOffset.dy;
    final endX = boundaryX.clamp(dataRect.left, dataRect.right).toDouble();
    final endY = boundaryY.clamp(dataRect.top, dataRect.bottom).toDouble();
    const tolerance = 4.0;
    final onVertical =
        boundaryX >= dataRect.left - 0.5 &&
        boundaryX <= dataRect.right + 0.5 &&
        (local.dx - boundaryX).abs() <= tolerance &&
        local.dy >= dataRect.top - tolerance &&
        local.dy <= endY + tolerance;
    final onHorizontal =
        boundaryY >= dataRect.top - 0.5 &&
        boundaryY <= dataRect.bottom + 0.5 &&
        (local.dy - boundaryY).abs() <= tolerance &&
        local.dx >= dataRect.left - tolerance &&
        local.dx <= endX + tolerance;
    return onVertical || onHorizontal ? local : null;
  }

  bool _updateSheetPrintAreaBoundaryHover(Offset local) {
    final tooltipPosition = _sheetPrintAreaBoundaryTooltipPosition(local);
    if (tooltipPosition == null) {
      if (_sheetPrintAreaTooltipShowTimer != null ||
          _sheetPrintAreaTooltipActive) {
        setState(() {
          _cancelSheetPrintAreaTooltipTimers();
          if (_sheetPrintAreaTooltipActive) {
            _sheetRulerTooltipText = null;
            _sheetRulerTooltipPosition = null;
            _sheetPrintAreaTooltipActive = false;
          }
          _sheetPrintAreaTooltipHoverPosition = null;
        });
      }
      return false;
    }
    _sheetPrintAreaTooltipHoverPosition = tooltipPosition;
    if (_sheetPrintAreaTooltipShowTimer == null &&
        !_sheetPrintAreaTooltipActive) {
      _sheetPrintAreaTooltipShowTimer = Timer(
        const Duration(milliseconds: 500),
        () {
          if (!mounted) {
            return;
          }
          _sheetPrintAreaTooltipShowTimer = null;
          setState(() {
            _sheetRulerHoveredGuideIndex = null;
            _sheetRulerTooltipText = '라벨 영역';
            _sheetRulerTooltipPosition = _sheetPrintAreaTooltipHoverPosition;
            _sheetRulerHoveringRuler = false;
            _sheetPrintAreaTooltipActive = true;
          });
          _sheetPrintAreaTooltipHideTimer?.cancel();
          _sheetPrintAreaTooltipHideTimer = Timer(
            const Duration(seconds: 1),
            () {
              if (!mounted) {
                return;
              }
              setState(() {
                if (_sheetPrintAreaTooltipActive) {
                  _sheetRulerTooltipText = null;
                  _sheetRulerTooltipPosition = null;
                  _sheetPrintAreaTooltipActive = false;
                }
                _sheetPrintAreaTooltipHoverPosition = null;
              });
            },
          );
        },
      );
    }
    return true;
  }

  Rect? _sheetCornerTooltipRect(FortuneSettings settings) {
    if (!_sheetRulerInserted(settings)) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final width = _sheetDataLeft(settings);
    final height = _sheetDataTop(settings);
    if (width <= 0 || height <= 0) {
      return null;
    }
    return Rect.fromLTWH(0, sheetTop, width, height);
  }

  bool _updateSheetCornerTooltipHover(Offset local) {
    final rect = _sheetCornerTooltipRect(_workbook.settings);
    if (rect == null || !rect.contains(local)) {
      if (_sheetCornerTooltipShowTimer != null ||
          _sheetCornerTooltipHideTimer != null ||
          _sheetCornerTooltipActive ||
          _sheetCornerTooltipHoverPosition != null ||
          _sheetCornerTooltipDismissedUntilExit) {
        setState(() {
          _cancelSheetCornerTooltipTimers();
          if (_sheetCornerTooltipActive &&
              _sheetRulerTooltipText == _sheetCornerTooltipText) {
            _sheetRulerTooltipText = null;
            _sheetRulerTooltipPosition = null;
          }
          _sheetCornerTooltipHoverPosition = null;
          _sheetCornerTooltipActive = false;
          _sheetCornerTooltipDismissedUntilExit = false;
        });
      }
      return false;
    }

    if (_sheetCornerTooltipDismissedUntilExit) {
      _sheetCornerTooltipHoverPosition = local;
      return true;
    }

    _sheetCornerTooltipHoverPosition = local;
    if (_sheetCornerTooltipActive) {
      if (_sheetRulerTooltipPosition != local) {
        setState(() {
          _sheetRulerTooltipPosition = local;
        });
      }
      return true;
    }

    _sheetCornerTooltipShowTimer ??= Timer(
      const Duration(milliseconds: 200),
      () {
        if (!mounted) {
          return;
        }
        _sheetCornerTooltipShowTimer = null;
        final position = _sheetCornerTooltipHoverPosition;
        if (position == null || _sheetCornerTooltipDismissedUntilExit) {
          return;
        }
        setState(() {
          _sheetRulerHoveredGuideIndex = null;
          _sheetRulerTooltipText = _sheetCornerTooltipText;
          _sheetRulerTooltipPosition = position;
          _sheetRulerHoveringRuler = false;
          _sheetCornerTooltipActive = true;
        });
        _sheetCornerTooltipHideTimer?.cancel();
        _sheetCornerTooltipHideTimer = Timer(
          const Duration(seconds: 3),
          () {
            if (!mounted) {
              return;
            }
            setState(() {
              if (_sheetCornerTooltipActive &&
                  _sheetRulerTooltipText == _sheetCornerTooltipText) {
                _sheetRulerTooltipText = null;
                _sheetRulerTooltipPosition = null;
              }
              _sheetCornerTooltipActive = false;
              _sheetCornerTooltipDismissedUntilExit = true;
            });
          },
        );
      },
    );
    return true;
  }

  void _cancelSheetPrintAreaTooltipTimers() {
    _sheetPrintAreaTooltipShowTimer?.cancel();
    _sheetPrintAreaTooltipShowTimer = null;
    _sheetPrintAreaTooltipHideTimer?.cancel();
    _sheetPrintAreaTooltipHideTimer = null;
  }

  void _cancelSheetCornerTooltipTimers() {
    _sheetCornerTooltipShowTimer?.cancel();
    _sheetCornerTooltipShowTimer = null;
    _sheetCornerTooltipHideTimer?.cancel();
    _sheetCornerTooltipHideTimer = null;
  }

  bool _commitSheetRulerGuideDrag() {
    final guide = _sheetRulerDraggingGuide;
    if (guide == null) {
      return false;
    }
    final guideMoved = _sheetRulerGuideMoved;
    final guides = _activeSheetRulerGuides();
    final nextGuides = <FortuneSheetGuide>[];
    var replaced = false;
    for (final item in guides) {
      if (item.index == guide.index) {
        nextGuides.add(guide);
        replaced = true;
      } else {
        nextGuides.add(item);
      }
    }
    if (!replaced) {
      nextGuides.add(guide);
    }
    if (guideMoved) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (guideMoved) {
        _writeSheetRulerState(guides: nextGuides);
      }
      _sheetRulerDragAxis = null;
      _sheetRulerDragStart = null;
      _sheetRulerGuideMoved = false;
      _sheetRulerDraggingGuide = null;
      _sheetRulerHoveredGuideIndex = guide.index;
      _sheetRulerSelectedGuideIndex = guideMoved ? null : guide.index;
      _sheetRulerTooltipText = _formatSheetGuidePosition(guide.positionMm);
    });
    return true;
  }

  void _cancelSheetRulerGuideDrag() {
    _sheetRulerDragAxis = null;
    _sheetRulerDragStart = null;
    _sheetRulerGuideMoved = false;
    _sheetRulerDraggingGuide = null;
  }

  void _clearSheetRulerSelection() {
    if (_sheetRulerSelectedGuideIndex == null) {
      return;
    }
    setState(_clearSheetRulerSelectionValues);
  }

  void _clearSheetRulerSelectionValues() {
    _sheetRulerSelectedGuideIndex = null;
  }

  bool _deleteSelectedSheetRulerGuide() {
    final selected = _sheetRulerSelectedGuideIndex;
    if (selected == null || !_activeSheetRulerVisible()) {
      return false;
    }
    final guides = _activeSheetRulerGuides();
    final nextGuides = [
      for (final guide in guides)
        if (guide.index != selected) guide,
    ];
    if (nextGuides.length == guides.length) {
      return false;
    }
    _recordUndoSnapshot();
    setState(() {
      _writeSheetRulerState(guides: nextGuides);
      _sheetRulerSelectedGuideIndex = null;
      _sheetRulerHoveredGuideIndex = null;
      _sheetRulerTooltipText = null;
      _sheetRulerTooltipPosition = null;
    });
    return true;
  }

  bool _updateSheetRulerHover(Offset local) {
    if (!_activeSheetRulerVisible()) {
      if (_sheetRulerHoveredGuideIndex != null ||
          _sheetRulerTooltipText != null ||
          _sheetRulerHoveringRuler) {
        setState(() {
          _sheetRulerHoveredGuideIndex = null;
          _sheetRulerTooltipText = null;
          _sheetRulerTooltipPosition = null;
          _sheetRulerHoveringRuler = false;
        });
      }
      return false;
    }
    final settings = _workbook.settings;
    final guide = _sheetGuideAt(local, settings);
    if (guide != null) {
      final positionText = _formatSheetGuidePosition(guide.positionMm);
      if (_sheetRulerHoveredGuideIndex != guide.index ||
          _sheetRulerTooltipText != positionText ||
          _sheetRulerTooltipPosition != local ||
          _sheetRulerHoveringRuler) {
        setState(() {
          _sheetRulerHoveredGuideIndex = guide.index;
          _sheetRulerTooltipText = positionText;
          _sheetRulerTooltipPosition = local;
          _sheetRulerHoveringRuler = false;
        });
      }
      _setMouseCursor(SystemMouseCursors.move);
      return true;
    }
    final axis = _sheetRulerAxisAt(local, settings);
    if (axis != null) {
      if (_sheetRulerHoveredGuideIndex != null ||
          _sheetRulerTooltipText != '눈금 자 드래그시 안내선 표시' ||
          _sheetRulerTooltipPosition != local ||
          !_sheetRulerHoveringRuler) {
        setState(() {
          _sheetRulerHoveredGuideIndex = null;
          _sheetRulerTooltipText = '눈금 자 드래그시 안내선 표시';
          _sheetRulerTooltipPosition = local;
          _sheetRulerHoveringRuler = true;
        });
      }
      _setMouseCursor(SystemMouseCursors.grab);
      return true;
    }
    if (_sheetRulerHoveredGuideIndex != null ||
        _sheetRulerTooltipText != null ||
        _sheetRulerHoveringRuler) {
      setState(() {
        _sheetRulerHoveredGuideIndex = null;
        _sheetRulerTooltipText = null;
        _sheetRulerTooltipPosition = null;
        _sheetRulerHoveringRuler = false;
      });
    }
    return false;
  }

  void _handlePointerMove(PointerMoveEvent event) {
    if (_updateDialogCloseHover(event.localPosition)) {
      return;
    }
    if (_imageInsertDialogOpen) {
      if (!_isImageInsertDialogInputPosition(event.localPosition)) {
        _updateImageInsertDialogHover(event.localPosition);
      }
      return;
    }
    if (_barcodeDialogOpen) {
      if (!_isBarcodeDialogInputPosition(event.localPosition)) {
        _updateBarcodeDialogHover(event.localPosition);
      }
      return;
    }
    if (_toolbarPopupEventContains(event.localPosition)) {
      _updateToolbarPopupEventHover(event.localPosition);
      return;
    }
    if (_editorDragSelectionPointer != null ||
        (_editingCoord != null &&
            _editingRect()?.contains(event.localPosition) == true)) {
      return;
    }
    if (_updateSheetRulerGuideDrag(event.localPosition)) {
      return;
    }
    if (_updateImageResize(event.localPosition)) {
      return;
    }
    if (_updateImageMove(event.localPosition)) {
      return;
    }
    if (_updateCommentBoxResize(event.localPosition)) {
      return;
    }
    if (_updateCommentBoxMove(event.localPosition)) {
      return;
    }
    _updateImageResizeCursor(event.localPosition);
    _updateRawChartHover(event);
    if (_updateResizeDrag(event.localPosition)) {
      return;
    }
    if (_updateFreezeDrag(event.localPosition)) {
      return;
    }
    if (_updateFilterDropdownScrollbarDrag(event.localPosition)) {
      return;
    }
    if (_updateSheetScrollbarDrag(event.localPosition)) {
      return;
    }
    if (_updateHeaderSelectionDrag(event)) {
      return;
    }
    if (_updateFormatPainterDrag(event)) {
      return;
    }
    if (_updateSelectionDrag(event)) {
      return;
    }
    if (_updateFillDrag(event)) {
      return;
    }
    if (_updateSearchDialogDrag(event.localPosition)) {
      return;
    }
    if (_updateHyperlinkDialogRangeSelection(event)) {
      return;
    }
    if (_updateDataVerificationDialogRangeSelection(event)) {
      return;
    }
    _updateSheetTabDrag(event.localPosition);
    if (_updateToolbarPopupScrollButtonHover(event.localPosition)) {
      return;
    }
    if (_updateToolbarFormatSubmenuHover(event.localPosition)) {
      return;
    }
    if (_updateConditionFormatSubmenuHover(event.localPosition)) {
      return;
    }
    _updateToolbarHover(event.localPosition);
    _updateHoveredComment(event);
    final start = _sheetTabLongPressStart;
    if (start == null) {
      return;
    }
    if ((event.localPosition - start).distance > 8) {
      _cancelSheetTabLongPress();
    }
  }

  void _handlePointerHover(PointerHoverEvent event) {
    if (_updateDialogCloseHover(event.localPosition)) {
      return;
    }
    if (_updateImageInsertDialogHover(event.localPosition)) {
      return;
    }
    if (_updateBarcodeDialogHover(event.localPosition)) {
      return;
    }
    if (_toolbarPopupEventContains(event.localPosition)) {
      _updateToolbarPopupEventHover(event.localPosition);
      return;
    }
    if (_updateContextMenuHover(event.localPosition)) {
      return;
    }
    _updateImageResizeCursor(event.localPosition);
    _updateRawChartHover(event);
    _updateSheetTabOptionsHover(event.localPosition);
    _updateSheetListHover(event.localPosition);
    if (_updateSheetTabColorMenuHover(event.localPosition)) {
      return;
    }
    if (_updateToolbarPopupScrollButtonHover(event.localPosition)) {
      return;
    }
    if (_updateToolbarFormatSubmenuHover(event.localPosition)) {
      return;
    }
    if (_updateConditionFormatSubmenuHover(event.localPosition)) {
      return;
    }
    if (_updateToolbarBorderSubmenuHover(event.localPosition)) {
      return;
    }
    if (_updateToolbarPopupHover(event.localPosition)) {
      return;
    }
    _updateToolbarHover(event.localPosition);
    if (_isOutsideActiveSheetEventArea(
      event.localPosition,
      _workbook.settings,
    )) {
      _clearSheetAreaHoverState();
      return;
    }
    if (_updateSheetCornerTooltipHover(event.localPosition)) {
      return;
    }
    if (_updateSheetPrintAreaBoundaryHover(event.localPosition)) {
      return;
    }
    if (_updateSheetRulerHover(event.localPosition)) {
      return;
    }
    _updateHeaderHover(event.localPosition);
    _updateHoveredComment(event);
  }

  bool _updateImageInsertDialogHover(Offset local) {
    if (!_imageInsertDialogOpen) {
      if (_imageInsertHoveredControl != null) {
        setState(() {
          _imageInsertHoveredControl = null;
        });
      }
      return false;
    }
    final command = _imageInsertDialogCommandAt(local);
    final hoverControl = command == null || command == 'modal' ? null : command;
    final cursor =
        hoverControl == 'width' ||
            hoverControl == 'height' ||
            hoverControl == 'rotation'
        ? SystemMouseCursors.text
        : hoverControl == null
        ? SystemMouseCursors.basic
        : SystemMouseCursors.click;
    if (_imageInsertHoveredControl != hoverControl || _mouseCursor != cursor) {
      setState(() {
        _imageInsertHoveredControl = hoverControl;
        _mouseCursor = cursor;
      });
    }
    return true;
  }

  bool _isImageInsertDialogInputPosition(Offset local) {
    final rect = _imageInsertDialogRect();
    if (rect == null) {
      return false;
    }
    return fortuneImageInsertWidthInputRect(rect).contains(local) ||
        fortuneImageInsertHeightInputRect(rect).contains(local) ||
        fortuneImageInsertRotationInputRect(rect).contains(local);
  }

  bool _updateBarcodeDialogHover(Offset local) {
    if (!_barcodeDialogOpen) {
      if (_barcodeHoveredControl != null) {
        setState(() {
          _barcodeHoveredControl = null;
        });
      }
      return false;
    }
    final command = _barcodeDialogCommandAt(local);
    final hoverControl = command == null || command == 'modal' ? null : command;
    final objectIdMenuIndex =
        hoverControl != null && hoverControl.startsWith('object-id-')
        ? int.tryParse(hoverControl.substring('object-id-'.length))
        : null;
    final menuIndex = hoverControl != null && hoverControl.startsWith('format-')
        ? int.tryParse(hoverControl.substring('format-'.length))
        : null;
    final textFontSizeMenuIndex =
        hoverControl != null && hoverControl.startsWith('text-font-size-')
        ? int.tryParse(hoverControl.substring('text-font-size-'.length))
        : null;
    final textFontMenuIndex =
        hoverControl != null &&
            hoverControl.startsWith('text-font-') &&
            !hoverControl.startsWith('text-font-size-')
        ? int.tryParse(hoverControl.substring('text-font-'.length))
        : null;
    final cursor =
        hoverControl == 'text' ||
            hoverControl == 'width' ||
            hoverControl == 'module-scale' ||
            hoverControl == 'bar-height' ||
            hoverControl == 'height' ||
            hoverControl == 'leading-quiet-zone' ||
            hoverControl == 'trailing-quiet-zone' ||
            hoverControl == 'rotation'
        ? SystemMouseCursors.text
        : hoverControl == null
        ? SystemMouseCursors.basic
        : SystemMouseCursors.click;
    if (_barcodeHoveredControl != hoverControl ||
        _barcodeObjectIdMenuHoveredIndex != objectIdMenuIndex ||
        _barcodeFormatMenuHoveredIndex != menuIndex ||
        _barcodeTextFontMenuHoveredIndex != textFontMenuIndex ||
        _barcodeTextFontSizeMenuHoveredIndex != textFontSizeMenuIndex ||
        _mouseCursor != cursor) {
      setState(() {
        _barcodeHoveredControl = hoverControl;
        _barcodeObjectIdMenuHoveredIndex = objectIdMenuIndex;
        _barcodeFormatMenuHoveredIndex = menuIndex;
        _barcodeTextFontMenuHoveredIndex = textFontMenuIndex;
        _barcodeTextFontSizeMenuHoveredIndex = textFontSizeMenuIndex;
        _mouseCursor = cursor;
      });
    }
    return true;
  }

  bool _isBarcodeDialogInputPosition(Offset local) {
    final rect = _barcodeDialogRect();
    if (rect == null) {
      return false;
    }
    if (_barcodeFormatMenuOpen &&
        fortuneBarcodeFormatMenuRect(
          rect,
          _effectiveBarcodeFormats.length,
        ).contains(local)) {
      return false;
    }
    if (_barcodeObjectIdMenuOpen &&
        fortuneBarcodeObjectIdMenuRect(
          rect,
          _effectiveBarcodeObjectIds.length,
        ).contains(local)) {
      return false;
    }
    return fortuneBarcodeTextInputRect(rect).contains(local) ||
        fortuneBarcodeModuleScaleInputRect(rect).contains(local) ||
        fortuneBarcodeBarHeightInputRect(rect).contains(local) ||
        fortuneBarcodeWidthInputRect(rect).contains(local) ||
        fortuneBarcodeHeightInputRect(rect).contains(local) ||
        fortuneBarcodeLeadingQuietZoneInputRect(rect).contains(local) ||
        fortuneBarcodeTrailingQuietZoneInputRect(rect).contains(local) ||
        fortuneBarcodeRotationInputRect(rect).contains(local);
  }

  bool _updateContextMenuHover(Offset local) {
    final at = contextMenuAt;
    if (at == null) {
      return false;
    }
    final rect = fortuneContextMenuRect(at, _activeContextMenuItems);
    if (!rect.contains(local)) {
      if (_contextMenuHoveredIndex != null) {
        setState(() {
          _contextMenuHoveredIndex = null;
        });
      }
      return false;
    }
    final hoveredIndex = _contextMenuItemIndexAt(local);
    if (hoveredIndex != _contextMenuHoveredIndex) {
      setState(() {
        _contextMenuHoveredIndex = hoveredIndex;
      });
    }
    _setMouseCursor(
      hoveredIndex == null
          ? SystemMouseCursors.basic
          : SystemMouseCursors.click,
    );
    return true;
  }

  void _updateSheetTabOptionsHover(Offset local) {
    final action = _sheetTabsActionAt(local);
    final nextIndex = action?.openMenu == true ? action?.sheetIndex : null;
    if (nextIndex == _hoveredSheetTabOptionsIndex) {
      return;
    }
    setState(() {
      _hoveredSheetTabOptionsIndex = nextIndex;
    });
  }

  void _updateSheetListHover(Offset local) {
    final nextHiddenButtonIndex = _sheetListHiddenButtonIndexAt(local);
    final nextIndex = nextHiddenButtonIndex ?? _sheetListIndexAt(local);
    if (nextIndex == _hoveredSheetListIndex &&
        nextHiddenButtonIndex == _hoveredSheetListHiddenButtonIndex) {
      return;
    }
    setState(() {
      _hoveredSheetListIndex = nextIndex;
      _hoveredSheetListHiddenButtonIndex = nextHiddenButtonIndex;
    });
  }

  bool _updateSheetTabColorMenuHover(Offset local) {
    final at = sheetTabMenuAt;
    final sheetIndex = _sheetTabMenuSheetIndex;
    final items = _sheetTabMenuItems;
    final colorIndex = items.indexOf(fortuneSheetTabColorCommand);
    if (at == null ||
        sheetIndex == null ||
        colorIndex < 0 ||
        !_workbook.settings.allowEdit) {
      if (_sheetTabColorMenuOpen) {
        setState(() {
          _sheetTabColorMenuOpen = false;
        });
      }
      return false;
    }

    final colorItem = fortuneSheetTabMenuItemTextRect(at, colorIndex, items);
    final colorMenu = fortuneSheetTabColorMenuRect(at, items);
    final shouldOpen =
        colorItem.contains(local) ||
        (_sheetTabColorMenuOpen && colorMenu.contains(local));
    if (shouldOpen != _sheetTabColorMenuOpen) {
      setState(() {
        _sheetTabColorMenuOpen = shouldOpen;
        if (shouldOpen) {
          contextMenuAt = null;
          hiddenSheetListAt = null;
          toolbarPopupKey = null;
        }
      });
    }
    return shouldOpen;
  }

  bool _updateToolbarPopupHover(Offset local) {
    final rect = _toolbarPopupRect();
    final key = toolbarPopupKey;
    if (rect == null || key == null || !rect.contains(local)) {
      if (_toolbarPopupHoveredIndex != null ||
          _toolbarPopupHoveredScrollButtonDirection != null) {
        setState(() {
          _toolbarPopupHoveredIndex = null;
          _toolbarPopupHoveredScrollButtonDirection = null;
        });
      }
      return false;
    }
    final nextHoveredIndex = _toolbarPopupHoverIndexAt(rect, key, local);
    if (_toolbarPopupHoveredIndex != nextHoveredIndex) {
      setState(() {
        _toolbarPopupHoveredIndex = nextHoveredIndex;
      });
    }
    return true;
  }

  bool _updateToolbarPopupScrollButtonHover(Offset local) {
    final rect = _toolbarPopupRect();
    if (rect == null || !rect.contains(local)) {
      if (_toolbarPopupHoveredScrollButtonDirection != null) {
        setState(() {
          _toolbarPopupHoveredScrollButtonDirection = null;
        });
      }
      return false;
    }
    final nextDirection = _toolbarPopupScrollButtonDirectionAt(local);
    if (_toolbarPopupHoveredScrollButtonDirection != nextDirection ||
        (nextDirection != null && _toolbarPopupHoveredIndex != null)) {
      setState(() {
        _toolbarPopupHoveredScrollButtonDirection = nextDirection;
        if (nextDirection != null) {
          _toolbarPopupHoveredIndex = null;
          _toolbarBorderHoveredTopLevelIndex = null;
          _toolbarBorderHoveredSubmenuIndex = null;
          _conditionFormatHoveredTopLevelIndex = null;
          _conditionFormatHoveredSubmenuIndex = null;
        }
      });
    }
    if (nextDirection != null) {
      _setMouseCursor(SystemMouseCursors.click);
    }
    return nextDirection != null;
  }

  void _updateToolbarPopupEventHover(Offset local) {
    if (_updateToolbarPopupScrollButtonHover(local)) {
      return;
    }
    if (_updateToolbarFormatSubmenuHover(local)) {
      return;
    }
    if (_updateConditionFormatSubmenuHover(local)) {
      return;
    }
    if (_updateToolbarBorderSubmenuHover(local)) {
      return;
    }
    _updateToolbarPopupHover(local);
  }

  bool _updateToolbarFormatSubmenuHover(Offset local) {
    if (toolbarPopupKey != fortuneToolbarFormatCommand) {
      return false;
    }
    final popupRect = _toolbarPopupRect();
    final size = context.size;
    if (popupRect == null || size == null) {
      return false;
    }
    final submenuRect = fortuneToolbarFormatMoreSubmenuRect(
      popupRect,
      viewportWidth: size.width,
    );
    if (submenuRect.contains(local)) {
      final index =
          ((local.dy - submenuRect.top) /
                  fortuneToolbarFormatMoreSubmenuRowHeight)
              .floor();
      final nextIndex =
          index >= 0 && index < fortuneToolbarFormatMoreSubmenuCommands.length
          ? index
          : null;
      if (!_formatMoreSubmenuOpen || _formatMoreHoveredIndex != nextIndex) {
        setState(() {
          _formatMoreSubmenuOpen = true;
          _formatMoreHoveredIndex = nextIndex;
          _toolbarPopupHoveredIndex = fortuneToolbarFormatCommands.indexOf(
            fortuneToolbarFormatMoreCommand,
          );
        });
      }
      return true;
    }
    if (popupRect.contains(local)) {
      final inContentViewport = _toolbarPopupContentViewportRect(
        popupRect,
      ).contains(local);
      final index = inContentViewport
          ? _toolbarPopupOptionIndexAt(
              popupRect,
              fortuneToolbarFormatCommand,
              fortuneToolbarFormatCommands,
              local.dy + _toolbarPopupScrollOffset,
            )
          : null;
      final open =
          index ==
          fortuneToolbarFormatCommands.indexOf(fortuneToolbarFormatMoreCommand);
      if (_formatMoreSubmenuOpen != open ||
          _formatMoreHoveredIndex != null ||
          _toolbarPopupHoveredIndex != index) {
        setState(() {
          _formatMoreSubmenuOpen = open;
          _formatMoreHoveredIndex = null;
          _toolbarPopupHoveredIndex = index;
        });
      }
      return true;
    }
    if (_formatMoreSubmenuOpen || _formatMoreHoveredIndex != null) {
      setState(() {
        _formatMoreSubmenuOpen = false;
        _formatMoreHoveredIndex = null;
      });
    }
    return false;
  }

  int? _toolbarPopupHoverIndexAt(Rect rect, String key, Offset local) {
    if (!_toolbarPopupContentViewportRect(rect).contains(local)) {
      return null;
    }
    final contentLocal = Offset(local.dx, local.dy + _toolbarPopupScrollOffset);
    if (key == fortuneToolbarFontColorPopupKey ||
        key == fortuneToolbarBackgroundPopupKey) {
      final resetRect = Rect.fromLTWH(
        rect.left,
        rect.top,
        rect.width,
        fortuneToolbarFontColorResetHeight,
      );
      if (resetRect.contains(contentLocal)) {
        return 0;
      }
      final customRect = Rect.fromLTWH(
        rect.left,
        rect.top + fortuneToolbarFontColorCustomTop,
        rect.width,
        fortuneToolbarFontColorCustomHeight,
      );
      return customRect.contains(contentLocal) ? 1 : null;
    }
    final options = _toolbarPopupOptionsFor(key, context.size?.width ?? 0);
    return _toolbarPopupOptionIndexAt(
      rect,
      key,
      options,
      local.dy + _toolbarPopupScrollOffset,
    );
  }

  void _updateToolbarHover(Offset local) {
    final toolbarHeight = _workbook.settings.effectiveToolbarHeight;
    final inToolbar = local.dy >= 0 && local.dy <= toolbarHeight;
    final nextKey = inToolbar ? _toolbarKeyAt(local) : null;
    final nextArrowKey = inToolbar ? _toolbarComboArrowKeyAt(local) : null;
    if (_toolbarHoveredKey == nextKey &&
        _toolbarHoveredComboArrowKey == nextArrowKey) {
      return;
    }
    setState(() {
      _toolbarHoveredKey = nextKey;
      _toolbarHoveredComboArrowKey = nextArrowKey;
    });
  }

  bool _updateConditionFormatSubmenuHover(Offset local) {
    if (toolbarPopupKey != fortuneToolbarConditionFormatPopupKey) {
      return false;
    }
    final topLevelRect = _conditionFormatTopLevelPopupRect();
    if (topLevelRect == null) {
      return false;
    }
    final submenuKey = _conditionFormatSubmenuKey;
    if (submenuKey != null) {
      final submenuRect = _conditionFormatSubmenuRect(submenuKey);
      if (submenuRect != null && submenuRect.contains(local)) {
        final items = _conditionFormatSubmenuItems(submenuKey);
        final index =
            ((local.dy - submenuRect.top) /
                    fortuneConditionFormatSubmenuRowHeight)
                .floor();
        final nextHoveredIndex = index >= 0 && index < items.length
            ? index
            : null;
        final nextTopLevelIndex = _conditionFormatTopLevelIndexForSubmenuKey(
          submenuKey,
        );
        if (_conditionFormatHoveredSubmenuIndex != nextHoveredIndex ||
            _conditionFormatHoveredTopLevelIndex != nextTopLevelIndex) {
          setState(() {
            _conditionFormatHoveredSubmenuIndex = nextHoveredIndex;
            _conditionFormatHoveredTopLevelIndex = nextTopLevelIndex;
            _toolbarPopupHoveredIndex = null;
          });
        }
        return true;
      }
    }
    String? nextSubmenuKey;
    int? nextTopLevelIndex;
    if (topLevelRect.contains(local) &&
        _toolbarPopupContentViewportRect(topLevelRect).contains(local)) {
      final topLevelIndex = _toolbarPopupOptionIndexAt(
        topLevelRect,
        fortuneToolbarConditionFormatPopupKey,
        fortuneConditionFormatTopLevelItems,
        local.dy + _toolbarPopupScrollOffset,
      );
      nextTopLevelIndex = topLevelIndex;
      nextSubmenuKey = switch (topLevelIndex) {
        fortuneConditionFormatHighlightTopLevelIndex =>
          fortuneConditionFormatHighlightSubmenuKey,
        fortuneConditionFormatSelectionTopLevelIndex =>
          fortuneConditionFormatSelectionSubmenuKey,
        fortuneConditionFormatDeleteTopLevelIndex =>
          fortuneConditionFormatDeleteSubmenuKey,
        _ => null,
      };
    }
    if (_conditionFormatSubmenuKey != nextSubmenuKey) {
      setState(() {
        _conditionFormatSubmenuKey = nextSubmenuKey;
        _conditionFormatHoveredTopLevelIndex = nextTopLevelIndex;
        _conditionFormatHoveredSubmenuIndex = null;
        _toolbarPopupHoveredIndex = null;
      });
    } else if (_conditionFormatHoveredSubmenuIndex != null ||
        _conditionFormatHoveredTopLevelIndex != nextTopLevelIndex) {
      setState(() {
        _conditionFormatHoveredTopLevelIndex = nextTopLevelIndex;
        _conditionFormatHoveredSubmenuIndex = null;
        _toolbarPopupHoveredIndex = null;
      });
    }
    return topLevelRect.contains(local) || submenuKey != null;
  }

  bool _updateToolbarBorderSubmenuHover(Offset local) {
    if (toolbarPopupKey != fortuneToolbarBorderPopupKey) {
      return false;
    }
    final topLevelRect = _toolbarPopupRect();
    if (topLevelRect == null) {
      return false;
    }
    final submenuKey = _toolbarBorderSubmenuKey;
    if (submenuKey != null) {
      final submenuRect = _toolbarBorderSubmenuRect(submenuKey);
      if (submenuRect != null && submenuRect.contains(local)) {
        final nextHoveredIndex = _toolbarBorderSubmenuIndexAt(
          submenuRect,
          submenuKey,
          local,
        );
        final nextTopLevelIndex = fortuneToolbarBorderPopupCommands.indexOf(
          submenuKey,
        );
        if (_toolbarBorderHoveredSubmenuIndex != nextHoveredIndex ||
            _toolbarBorderHoveredTopLevelIndex != nextTopLevelIndex) {
          setState(() {
            _toolbarBorderHoveredSubmenuIndex = nextHoveredIndex;
            _toolbarBorderHoveredTopLevelIndex = nextTopLevelIndex;
            _toolbarPopupHoveredIndex = null;
          });
        }
        return true;
      }
    }
    String? nextSubmenuKey;
    int? nextTopLevelIndex;
    if (topLevelRect.contains(local) &&
        _toolbarPopupContentViewportRect(topLevelRect).contains(local)) {
      final topLevelIndex = _toolbarPopupOptionIndexAt(
        topLevelRect,
        fortuneToolbarBorderPopupKey,
        fortuneToolbarBorderPopupCommands,
        local.dy + _toolbarPopupScrollOffset,
      );
      if (topLevelIndex != null) {
        nextTopLevelIndex = topLevelIndex;
        final option = fortuneToolbarBorderPopupCommands[topLevelIndex];
        if (option == fortuneToolbarBorderColorSubmenuKey ||
            option == fortuneToolbarBorderStyleSubmenuKey) {
          nextSubmenuKey = option;
        }
      }
    }
    if (_toolbarBorderSubmenuKey != nextSubmenuKey) {
      setState(() {
        _toolbarBorderSubmenuKey = nextSubmenuKey;
        _toolbarBorderHoveredTopLevelIndex = nextTopLevelIndex;
        _toolbarBorderHoveredSubmenuIndex = null;
        _toolbarPopupHoveredIndex = null;
      });
    } else if (_toolbarBorderHoveredSubmenuIndex != null ||
        _toolbarBorderHoveredTopLevelIndex != nextTopLevelIndex) {
      setState(() {
        _toolbarBorderHoveredTopLevelIndex = nextTopLevelIndex;
        _toolbarBorderHoveredSubmenuIndex = null;
        _toolbarPopupHoveredIndex = null;
      });
    }
    return topLevelRect.contains(local) || submenuKey != null;
  }

  int? _toolbarBorderSubmenuIndexAt(
    Rect submenuRect,
    String submenuKey,
    Offset local,
  ) {
    if (submenuKey == fortuneToolbarBorderColorSubmenuKey) {
      return null;
    }
    final resetTop = submenuRect.top + fortuneToolbarPopupContentTopPadding;
    final resetBottom = resetTop + fortuneToolbarBorderStyleSubmenuResetHeight;
    if (local.dy >= resetTop && local.dy < resetBottom) {
      return 0;
    }
    final index =
        ((local.dy - resetBottom) / fortuneToolbarBorderStyleSubmenuRowHeight)
            .floor();
    return index >= 0 && index < fortuneToolbarBorderStyleValues.length
        ? index + 1
        : null;
  }

  int? _conditionFormatTopLevelIndexForSubmenuKey(String submenuKey) {
    return switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightTopLevelIndex,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionTopLevelIndex,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteTopLevelIndex,
      _ => null,
    };
  }

  void _startHeaderSelectionDrag(String axis, int index, FortuneRange range) {
    _selectionDragAnchor = null;
    _selectionDragging = false;
    _formatPainterDragAnchor = null;
    _formatPainterDragging = false;
    _headerSelectionDragAxis = axis;
    _headerSelectionDragAnchor = index;
    _headerSelectionFormatPainter = _formatPainterCell != null;
    _applyHeaderSelectionRange(range);
  }

  bool _updateHeaderSelectionDrag(PointerMoveEvent event) {
    final axis = _headerSelectionDragAxis;
    final anchor = _headerSelectionDragAnchor;
    if (axis == null || anchor == null) {
      return false;
    }
    if (axis == 'all') {
      return true;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final nextScrollOffset = _autoScrollOffsetForDrag(
      event.localPosition,
      settings,
      metrics,
    );
    final nextSelection = _headerSelectionAt(
      event.localPosition,
      settings,
      metrics,
    );
    if (nextSelection == null || nextSelection.axis != axis) {
      return true;
    }
    if (!_canSelectHeaderRange(_workbook.activeSheet)) {
      _cancelHeaderSelectionDrag();
      return true;
    }
    final nextIndex = nextSelection.index;
    final range = _headerSelectionRangeFor(axis, anchor, nextIndex);
    setState(() {
      scrollOffset = nextScrollOffset;
      _setSelectionToRange(range);
      _writeSelectionRange(
        range,
        FortuneCellCoord(range.rowStart, range.columnStart),
      );
      _closeTransientMenus();
    });
    return true;
  }

  bool _commitHeaderSelectionDrag() {
    final axis = _headerSelectionDragAxis;
    if (axis == null) {
      return false;
    }
    final source = _formatPainterCell;
    final shouldApplyPainter = _headerSelectionFormatPainter && source != null;
    final range = _currentSelectionRange(_workbook.activeSheet);
    _cancelHeaderSelectionDrag();
    if (shouldApplyPainter) {
      _applyFormatPainterToRange(range, source);
    }
    return true;
  }

  void _cancelHeaderSelectionDrag() {
    _headerSelectionDragAxis = null;
    _headerSelectionDragAnchor = null;
    _headerSelectionFormatPainter = false;
  }

  void _applyHeaderSelectionRange(FortuneRange range) {
    final focus = FortuneCellCoord(range.rowStart, range.columnStart);
    setState(() {
      _setSelectionToRange(range);
      _writeSelectionRange(range, focus);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _closeTransientMenus();
    });
  }

  void _setSelectionToRange(FortuneRange range) {
    selection = FortuneSelection(
      row: range.rowStart,
      column: range.columnStart,
      rowEnd: range.rowEnd,
      columnEnd: range.columnEnd,
    );
  }

  bool _canSelectCell(FortuneSheet sheet, FortuneCellCoord coord) {
    return checkProtectionSelectLockedOrUnLockedCells(
      sheet,
      coord.row,
      coord.column,
    );
  }

  bool _canSelectHeaderRange(FortuneSheet sheet) {
    return checkProtectionAllSelected(sheet);
  }

  FortuneRange _headerSelectionRangeFor(String axis, int start, int end) {
    final sheet = _workbook.activeSheet;
    final rowEnd = math.max(0, _effectiveRowCount(sheet) - 1);
    final columnEnd = math.max(0, _effectiveColumnCount(sheet) - 1);
    return switch (axis) {
      'column' => FortuneRange(
        rowStart: 0,
        rowEnd: rowEnd,
        columnStart: math.min(start, end),
        columnEnd: math.max(start, end),
        extraFields: const {'column_select': true},
      ),
      'row' => FortuneRange(
        rowStart: math.min(start, end),
        rowEnd: math.max(start, end),
        columnStart: 0,
        columnEnd: columnEnd,
        extraFields: const {'row_select': true},
      ),
      _ => FortuneRange(
        rowStart: 0,
        rowEnd: rowEnd,
        columnStart: 0,
        columnEnd: columnEnd,
        extraFields: const {'row_select': true, 'column_select': true},
      ),
    };
  }

  void _handlePointerUp(PointerUpEvent event) {
    fortuneSheetDebugLog(
      'editor pointerUp pointer=${event.pointer} buttons=${event.buttons} '
      'local=${event.localPosition.dx.toStringAsFixed(1)},${event.localPosition.dy.toStringAsFixed(1)} '
      'openingPointer=$_editorContextMenuOpeningPointer '
      'contextMenuIsEditor=$_contextMenuIsEditor selection=${_debugSelection(_editorController.selection)}',
    );
    if (_editorContextMenuOpeningPointer == event.pointer) {
      _editorContextMenuOpeningPointer = null;
    }
    final pressedCloseKey = _dialogClosePressedKey;
    if (pressedCloseKey != null) {
      final closeKey = _dialogCloseButtonKeyAt(event.localPosition);
      final shouldActivate = closeKey == pressedCloseKey;
      setState(() {
        _dialogClosePressedKey = null;
        _dialogCloseHoveredKey = shouldActivate ? null : closeKey;
      });
      if (shouldActivate) {
        _activateDialogCloseButton(pressedCloseKey);
      }
      return;
    }
    _clearImageInsertPressedControl();
    _clearBarcodePressedControl();
    if (_imageInsertDialogOpen) {
      return;
    }
    if (_barcodeDialogOpen) {
      return;
    }
    if (_toolbarPopupEventContains(event.localPosition)) {
      if (_toolbarPopupPressedScrollButtonDirection != null) {
        setState(() {
          _toolbarPopupPressedScrollButtonDirection = null;
        });
      }
      return;
    }
    if (_editorDragSelectionPointer != null ||
        (_editingCoord != null &&
            _editingRect()?.contains(event.localPosition) == true)) {
      return;
    }
    if (_toolbarPopupPressedScrollButtonDirection != null) {
      setState(() {
        _toolbarPopupPressedScrollButtonDirection = null;
      });
    }
    if (_commitSheetRulerGuideDrag()) {
      return;
    }
    if (_commitImageResize()) {
      return;
    }
    if (_commitImageMove()) {
      return;
    }
    if (_commitCommentBoxResize()) {
      return;
    }
    if (_commitCommentBoxMove()) {
      return;
    }
    if (_commitResizeDrag()) {
      return;
    }
    if (_commitFreezeDrag(event.localPosition)) {
      return;
    }
    if (_commitFilterDropdownScrollbarDrag()) {
      return;
    }
    if (_commitSheetScrollbarDrag()) {
      return;
    }
    if (_commitHeaderSelectionDrag()) {
      return;
    }
    if (_commitFormatPainterDrag()) {
      return;
    }
    if (_commitFillDrag()) {
      return;
    }
    if (_commitSearchDialogDrag()) {
      return;
    }
    if (_commitHyperlinkDialogRangeSelection()) {
      return;
    }
    if (_commitDataVerificationDialogRangeSelection()) {
      return;
    }
    _commitSheetTabDrag(event.localPosition);
    _cancelSelectionDrag();
    _cancelSheetTabLongPress();
  }

  void _handlePointerCancel(PointerCancelEvent event) {
    if (_editorContextMenuOpeningPointer == event.pointer) {
      _editorContextMenuOpeningPointer = null;
    }
    _clearDialogClosePressedKey();
    _clearImageInsertPressedControl();
    _clearBarcodePressedControl();
    if (_imageInsertDialogOpen) {
      return;
    }
    if (_barcodeDialogOpen) {
      return;
    }
    _endEditorSelectionDrag(event.pointer);
    if (_toolbarPopupPressedScrollButtonDirection != null) {
      setState(() {
        _toolbarPopupPressedScrollButtonDirection = null;
      });
    }
    _cancelSheetTabLongPress();
    _cancelSheetTabDrag();
    _cancelFreezeDrag();
    _cancelResizeDrag();
    _cancelSheetRulerGuideDrag();
    _cancelFilterDropdownScrollbarDrag();
    _cancelSheetScrollbarDrag();
    _cancelSelectionDrag();
    _cancelFormatPainterDrag(clearPainter: true);
    _cancelFillDrag();
    _cancelSearchDialogDrag();
    _cancelHyperlinkDialogRangeSelection();
    _cancelDataVerificationDialogRangeSelection();
    _cancelImageResize();
    _cancelImageMove();
    _cancelCommentBoxResize();
    _cancelCommentBoxMove();
    _setHoveredComment(null);
    _setRawChartHoverPosition(null, null);
  }

  bool _updateSelectionDrag(PointerMoveEvent event) {
    final anchor = _selectionDragAnchor;
    if (anchor == null) {
      return false;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final nextScrollOffset = _autoScrollOffsetForDrag(
      event.localPosition,
      settings,
      metrics,
    );
    final coord = _cellCoordAtLocal(
      event.localPosition,
      settings,
      metrics,
      scrollOverride: nextScrollOffset,
    );
    if (coord == null) {
      return false;
    }
    if (!_canSelectCell(_workbook.activeSheet, coord)) {
      _cancelSelectionDrag();
      return true;
    }
    if (!_selectionDragging &&
        coord == anchor &&
        nextScrollOffset == scrollOffset) {
      return true;
    }
    final range = _expandRangeForMergedCells(
      FortuneRange(
        rowStart: math.min(anchor.row, coord.row),
        rowEnd: math.max(anchor.row, coord.row),
        columnStart: math.min(anchor.column, coord.column),
        columnEnd: math.max(anchor.column, coord.column),
      ),
    );
    setState(() {
      scrollOffset = nextScrollOffset;
      _selectionDragging = true;
      selection = FortuneSelection(
        row: anchor.row,
        column: anchor.column,
        rowEnd: coord.row,
        columnEnd: coord.column,
      );
      _writeSelectionRange(range, anchor);
      _closeTransientMenus();
    });
    return true;
  }

  void _cancelSelectionDrag() {
    _selectionDragAnchor = null;
    _selectionDragging = false;
  }

  void _startFillDrag() {
    if (!_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    _selectionDragAnchor = null;
    _selectionDragging = false;
    _fillDragSourceRange = _currentSelectionRange(_workbook.activeSheet);
    _fillDragExtent = null;
    _fillDragUndoSnapshot = _currentHistorySnapshot();
    _fillDragging = false;
    setState(_closeTransientMenus);
  }

  bool _updateFillDrag(PointerMoveEvent event) {
    final source = _fillDragSourceRange;
    if (source == null) {
      return false;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final nextScrollOffset = _autoScrollOffsetForDrag(
      event.localPosition,
      settings,
      metrics,
    );
    final coord = _cellCoordAtLocal(
      event.localPosition,
      settings,
      metrics,
      scrollOverride: nextScrollOffset,
    );
    if (coord == null) {
      return true;
    }
    final fillRange = _fillDragRangeFor(source, coord);
    if (fillRange == null) {
      return true;
    }
    final end = _fillSelectionEnd(source, fillRange);
    setState(() {
      scrollOffset = nextScrollOffset;
      _fillDragExtent = coord;
      _fillDragging = true;
      selection = FortuneSelection(
        row: source.rowStart,
        column: source.columnStart,
        rowEnd: end.row,
        columnEnd: end.column,
      );
      _writeSelectionRange(
        fillRange,
        FortuneCellCoord(source.rowStart, source.columnStart),
      );
    });
    return true;
  }

  bool _commitFillDrag() {
    final source = _fillDragSourceRange;
    if (source == null) {
      return false;
    }
    final extent = _fillDragExtent;
    final fillRange = extent == null ? null : _fillDragRangeFor(source, extent);
    if (!_fillDragging || fillRange == null) {
      _cancelFillDrag();
      return true;
    }
    final sheet = _workbook.activeSheet;
    for (var row = fillRange.rowStart; row <= fillRange.rowEnd; row += 1) {
      for (
        var column = fillRange.columnStart;
        column <= fillRange.columnEnd;
        column += 1
      ) {
        final coord = FortuneCellCoord(row, column);
        if (_rangeContainsCoord(source, coord)) {
          continue;
        }
        if (!_canEditCell(sheet, sheet.mergeAnchorFor(coord))) {
          _cancelFillDrag();
          setState(_closeTransientMenus);
          return true;
        }
      }
    }
    _pushUndoSnapshot(_fillDragUndoSnapshot ?? _currentHistorySnapshot());
    setState(() {
      for (var row = fillRange.rowStart; row <= fillRange.rowEnd; row += 1) {
        for (
          var column = fillRange.columnStart;
          column <= fillRange.columnEnd;
          column += 1
        ) {
          final target = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
          if (_rangeContainsCoord(source, target)) {
            continue;
          }
          final sourceCoord = _fillSourceCoordFor(source, fillRange, target);
          final sourceCell = sheet.cells[sourceCoord];
          if (sourceCell == null) {
            sheet.cells.remove(target);
            continue;
          }
          _setSheetCell(
            sheet,
            target,
            _cellForFill(
              sheet,
              source,
              fillRange,
              sourceCell,
              sourceCoord,
              target,
            ),
          );
        }
      }
      final end = _fillSelectionEnd(source, fillRange);
      selection = FortuneSelection(
        row: source.rowStart,
        column: source.columnStart,
        rowEnd: end.row,
        columnEnd: end.column,
      );
      _writeSelectionRange(
        fillRange,
        FortuneCellCoord(source.rowStart, source.columnStart),
      );
      _recalculateWorkbookFormulas();
      _cancelFillDrag();
      _closeTransientMenus();
    });
    return true;
  }

  void _cancelFillDrag() {
    _fillDragSourceRange = null;
    _fillDragExtent = null;
    _fillDragUndoSnapshot = null;
    _fillDragging = false;
  }

  Offset _autoScrollOffsetForDrag(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final size = context.size;
    if (size == null) {
      return scrollOffset;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = sheetTop + _sheetDataTop(settings);
    final footerTop =
        size.height -
        settings.effectiveSheetBarHeight -
        settings.statisticBarHeight;
    const threshold = 24.0;
    const step = 32.0;
    var dx = 0.0;
    var dy = 0.0;
    if (local.dx >= dataLeft && local.dx <= size.width) {
      if (local.dx > size.width - threshold) {
        dx = step;
      } else if (local.dx < dataLeft + threshold) {
        dx = -step;
      }
    }
    if (local.dy >= dataTop && local.dy <= footerTop) {
      if (local.dy > footerTop - threshold) {
        dy = step;
      } else if (local.dy < dataTop + threshold) {
        dy = -step;
      }
    }
    if (dx == 0 && dy == 0) {
      return scrollOffset;
    }
    return Offset(
      (scrollOffset.dx + dx).clamp(0, metrics.columnTotalWidth).toDouble(),
      (scrollOffset.dy + dy).clamp(0, metrics.rowTotalHeight).toDouble(),
    );
  }

  Rect? _selectionFillHandleRect(
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final rect = _selectionVisualRect(settings, metrics);
    if (rect == null) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    if (selection.isSingleCell) {
      return Rect.fromLTWH(rect.right - 5, sheetTop + rect.bottom - 5, 10, 10);
    }
    return Rect.fromLTWH(
      rect.right - 6,
      sheetTop + rect.bottom - 6,
      12,
      12,
    ).inflate(6);
  }

  Rect? _selectionVisualRect(
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final range = _currentSelectionRange(_workbook.activeSheet);
    if (range.rowStart >= metrics.visibleDataRows.length ||
        range.columnStart >= metrics.visibleDataColumns.length) {
      return null;
    }
    final rowEnd = math.min(range.rowEnd, metrics.visibleDataRows.length - 1);
    final columnEnd = math.min(
      range.columnEnd,
      metrics.visibleDataColumns.length - 1,
    );
    final startX = _visualCellLeft(range.columnStart, settings, metrics);
    final startY = _visualCellTop(range.rowStart, settings, metrics);
    final endX =
        _visualCellLeft(columnEnd, settings, metrics) +
        metrics.columnEnd(columnEnd) -
        metrics.columnStart(columnEnd);
    final endY =
        _visualCellTop(rowEnd, settings, metrics) +
        metrics.rowEnd(rowEnd) -
        metrics.rowStart(rowEnd);
    if (endX <= startX || endY <= startY) {
      return null;
    }
    return Rect.fromLTRB(startX, startY, endX, endY);
  }

  FortuneRange? _fillDragRangeFor(
    FortuneRange source,
    FortuneCellCoord extent,
  ) {
    final maxRow = _effectiveRowCount(_workbook.activeSheet) - 1;
    final maxColumn = _effectiveColumnCount(_workbook.activeSheet) - 1;
    final row = extent.row.clamp(0, maxRow);
    final column = extent.column.clamp(0, maxColumn);
    final rowDelta = row < source.rowStart
        ? row - source.rowStart
        : row > source.rowEnd
        ? row - source.rowEnd
        : 0;
    final columnDelta = column < source.columnStart
        ? column - source.columnStart
        : column > source.columnEnd
        ? column - source.columnEnd
        : 0;
    if (rowDelta == 0 && columnDelta == 0) {
      return null;
    }
    final preferRow = rowDelta.abs() >= columnDelta.abs();
    if (preferRow && row > source.rowEnd) {
      return source.copyWith(rowEnd: row);
    }
    if (preferRow && row < source.rowStart) {
      return source.copyWith(rowStart: row);
    }
    if (column > source.columnEnd) {
      return source.copyWith(columnEnd: column);
    }
    if (column < source.columnStart) {
      return source.copyWith(columnStart: column);
    }
    return row > source.rowEnd
        ? source.copyWith(rowEnd: row)
        : source.copyWith(rowStart: row);
  }

  FortuneCellCoord _fillSelectionEnd(
    FortuneRange source,
    FortuneRange fillRange,
  ) {
    return FortuneCellCoord(
      fillRange.rowStart < source.rowStart
          ? fillRange.rowStart
          : fillRange.rowEnd,
      fillRange.columnStart < source.columnStart
          ? fillRange.columnStart
          : fillRange.columnEnd,
    );
  }

  bool _rangeContainsCoord(FortuneRange range, FortuneCellCoord coord) {
    return coord.row >= range.rowStart &&
        coord.row <= range.rowEnd &&
        coord.column >= range.columnStart &&
        coord.column <= range.columnEnd;
  }

  bool _rangeContainsRange(FortuneRange range, FortuneRange other) {
    return other.rowStart >= range.rowStart &&
        other.rowEnd <= range.rowEnd &&
        other.columnStart >= range.columnStart &&
        other.columnEnd <= range.columnEnd;
  }

  FortuneCellCoord _fillSourceCoordFor(
    FortuneRange source,
    FortuneRange fillRange,
    FortuneCellCoord target,
  ) {
    if (source.rowStart == source.rowEnd &&
        source.columnStart == source.columnEnd) {
      return FortuneCellCoord(source.rowStart, source.columnStart);
    }
    final rowCount = source.rowEnd - source.rowStart + 1;
    final columnCount = source.columnEnd - source.columnStart + 1;
    final rowOffset = (target.row - fillRange.rowStart) % rowCount;
    final columnOffset = (target.column - fillRange.columnStart) % columnCount;
    return FortuneCellCoord(
      source.rowStart + rowOffset,
      source.columnStart + columnOffset,
    );
  }

  FortuneCell _cellForFill(
    FortuneSheet sheet,
    FortuneRange sourceRange,
    FortuneRange fillRange,
    FortuneCell source,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord target,
  ) {
    final formula = _cellFormulaText(source);
    if (formula != null) {
      final translated = FortuneFormulaEngine.translateReferences(
        formula,
        rowDelta: target.row - sourceCoord.row,
        columnDelta: target.column - sourceCoord.column,
      );
      return source.copyWith(
        value: translated,
        rawValue: translated,
        hasRawValue: true,
        formula: translated,
        rawFormula: translated,
        hasRawFormula: true,
        displayValue: null,
        rawDisplayValue: null,
        hasRawDisplayValue: false,
      );
    }
    final seriesCell = _numericSeriesCellForFill(
      sheet,
      sourceRange,
      fillRange,
      source,
      sourceCoord,
      target,
    );
    if (seriesCell != null) {
      return seriesCell;
    }
    final dateTimeCell = _singleDateTimeCellForFill(
      sourceRange,
      fillRange,
      source,
      sourceCoord,
      target,
    );
    if (dateTimeCell != null) {
      return dateTimeCell;
    }
    final dateCell = _singleDateCellForFill(
      sourceRange,
      fillRange,
      source,
      sourceCoord,
      target,
    );
    if (dateCell != null) {
      return dateCell;
    }
    final timeCell = _singleTimeCellForFill(
      sourceRange,
      fillRange,
      source,
      sourceCoord,
      target,
    );
    if (timeCell != null) {
      return timeCell;
    }
    final sequenceCell = _singleSequenceCellForFill(
      sourceRange,
      fillRange,
      source,
      sourceCoord,
      target,
    );
    if (sequenceCell != null) {
      return sequenceCell;
    }
    return source;
  }

  String? _cellFormulaText(FortuneCell? cell) {
    if (cell == null) {
      return null;
    }
    if (cell.formula != null) {
      return cell.formula;
    }
    final rawFormula = cell.hasRawFormula ? cell.rawFormula : null;
    return rawFormula is String ? rawFormula : null;
  }

  FortuneCell? _numericSeriesCellForFill(
    FortuneSheet sheet,
    FortuneRange sourceRange,
    FortuneRange fillRange,
    FortuneCell source,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord target,
  ) {
    if (source.formula != null) {
      return null;
    }
    final fillsVertically =
        fillRange.rowStart < sourceRange.rowStart ||
        fillRange.rowEnd > sourceRange.rowEnd;
    final fillsHorizontally =
        fillRange.columnStart < sourceRange.columnStart ||
        fillRange.columnEnd > sourceRange.columnEnd;
    if (fillsVertically && sourceRange.rowEnd > sourceRange.rowStart) {
      final dateTimeSeries = _dateTimeSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowStart, sourceCoord.column)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowEnd, sourceCoord.column)],
        sourceIndex: sourceRange.rowStart,
        targetIndex: target.row,
        stepDivisor: sourceRange.rowEnd - sourceRange.rowStart,
      );
      if (dateTimeSeries != null) {
        return dateTimeSeries;
      }
      final dateSeries = _dateSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowStart, sourceCoord.column)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowEnd, sourceCoord.column)],
        sourceIndex: sourceRange.rowStart,
        targetIndex: target.row,
        stepDivisor: sourceRange.rowEnd - sourceRange.rowStart,
      );
      if (dateSeries != null) {
        return dateSeries;
      }
      final timeSeries = _timeSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowStart, sourceCoord.column)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowEnd, sourceCoord.column)],
        sourceIndex: sourceRange.rowStart,
        targetIndex: target.row,
        stepDivisor: sourceRange.rowEnd - sourceRange.rowStart,
      );
      if (timeSeries != null) {
        return timeSeries;
      }
      final first = _numericFillValue(
        sheet.cells[FortuneCellCoord(sourceRange.rowStart, sourceCoord.column)],
      );
      final last = _numericFillValue(
        sheet.cells[FortuneCellCoord(sourceRange.rowEnd, sourceCoord.column)],
      );
      if (first != null && last != null) {
        final geometricSeries = _geometricNumericSeriesCellForFill(
          sheet,
          sourceRange,
          source,
          targetIndex: target.row,
          axisIndex: sourceCoord.column,
          vertical: true,
        );
        if (geometricSeries != null) {
          return geometricSeries;
        }
        final step =
            (last - first) / (sourceRange.rowEnd - sourceRange.rowStart);
        final value = first + step * (target.row - sourceRange.rowStart);
        return _cellWithFillNumber(source, value);
      }
      final textSeries = _textSuffixSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowStart, sourceCoord.column)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowEnd, sourceCoord.column)],
        sourceIndex: sourceRange.rowStart,
        targetIndex: target.row,
        stepDivisor: sourceRange.rowEnd - sourceRange.rowStart,
      );
      if (textSeries != null) {
        return textSeries;
      }
      final chineseNumberSeries = _chineseNumberSeriesCellForFill(
        sheet,
        sourceRange,
        source,
        targetIndex: target.row,
        axisIndex: sourceCoord.column,
        vertical: true,
      );
      if (chineseNumberSeries != null) {
        return chineseNumberSeries;
      }
      final sequenceSeries = _sequenceSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowStart, sourceCoord.column)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceRange.rowEnd, sourceCoord.column)],
        sourceIndex: sourceRange.rowStart,
        targetIndex: target.row,
        stepDivisor: sourceRange.rowEnd - sourceRange.rowStart,
      );
      if (sequenceSeries != null) {
        return sequenceSeries;
      }
    }
    if (fillsHorizontally && sourceRange.columnEnd > sourceRange.columnStart) {
      final dateTimeSeries = _dateTimeSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnStart)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnEnd)],
        sourceIndex: sourceRange.columnStart,
        targetIndex: target.column,
        stepDivisor: sourceRange.columnEnd - sourceRange.columnStart,
      );
      if (dateTimeSeries != null) {
        return dateTimeSeries;
      }
      final dateSeries = _dateSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnStart)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnEnd)],
        sourceIndex: sourceRange.columnStart,
        targetIndex: target.column,
        stepDivisor: sourceRange.columnEnd - sourceRange.columnStart,
      );
      if (dateSeries != null) {
        return dateSeries;
      }
      final timeSeries = _timeSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnStart)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnEnd)],
        sourceIndex: sourceRange.columnStart,
        targetIndex: target.column,
        stepDivisor: sourceRange.columnEnd - sourceRange.columnStart,
      );
      if (timeSeries != null) {
        return timeSeries;
      }
      final first = _numericFillValue(
        sheet.cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnStart)],
      );
      final last = _numericFillValue(
        sheet.cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnEnd)],
      );
      if (first != null && last != null) {
        final geometricSeries = _geometricNumericSeriesCellForFill(
          sheet,
          sourceRange,
          source,
          targetIndex: target.column,
          axisIndex: sourceCoord.row,
          vertical: false,
        );
        if (geometricSeries != null) {
          return geometricSeries;
        }
        final step =
            (last - first) / (sourceRange.columnEnd - sourceRange.columnStart);
        final value = first + step * (target.column - sourceRange.columnStart);
        return _cellWithFillNumber(source, value);
      }
      final textSeries = _textSuffixSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnStart)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnEnd)],
        sourceIndex: sourceRange.columnStart,
        targetIndex: target.column,
        stepDivisor: sourceRange.columnEnd - sourceRange.columnStart,
      );
      if (textSeries != null) {
        return textSeries;
      }
      final chineseNumberSeries = _chineseNumberSeriesCellForFill(
        sheet,
        sourceRange,
        source,
        targetIndex: target.column,
        axisIndex: sourceCoord.row,
        vertical: false,
      );
      if (chineseNumberSeries != null) {
        return chineseNumberSeries;
      }
      final sequenceSeries = _sequenceSeriesCellForFill(
        source,
        firstCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnStart)],
        lastCell: sheet
            .cells[FortuneCellCoord(sourceCoord.row, sourceRange.columnEnd)],
        sourceIndex: sourceRange.columnStart,
        targetIndex: target.column,
        stepDivisor: sourceRange.columnEnd - sourceRange.columnStart,
      );
      if (sequenceSeries != null) {
        return sequenceSeries;
      }
    }
    return null;
  }

  FortuneCell? _geometricNumericSeriesCellForFill(
    FortuneSheet sheet,
    FortuneRange sourceRange,
    FortuneCell source, {
    required int targetIndex,
    required int axisIndex,
    required bool vertical,
  }) {
    final start = vertical ? sourceRange.rowStart : sourceRange.columnStart;
    final end = vertical ? sourceRange.rowEnd : sourceRange.columnEnd;
    if (end - start < 2) {
      return null;
    }
    final values = <double>[];
    for (var index = start; index <= end; index += 1) {
      final coord = vertical
          ? FortuneCellCoord(index, axisIndex)
          : FortuneCellCoord(axisIndex, index);
      final value = _numericFillValue(sheet.cells[coord]);
      if (value == null || value == 0 || !value.isFinite) {
        return null;
      }
      values.add(value);
    }
    final ratio = values[1] / values[0];
    if (!ratio.isFinite) {
      return null;
    }
    for (var index = 2; index < values.length; index += 1) {
      final previous = values[index - 1];
      final currentRatio = values[index] / previous;
      if ((currentRatio - ratio).abs() > 1e-10) {
        return null;
      }
    }
    final value = values.first * math.pow(ratio, targetIndex - start);
    return _cellWithFillNumber(source, value.toDouble());
  }

  FortuneCell? _chineseNumberSeriesCellForFill(
    FortuneSheet sheet,
    FortuneRange sourceRange,
    FortuneCell source, {
    required int targetIndex,
    required int axisIndex,
    required bool vertical,
  }) {
    final start = vertical ? sourceRange.rowStart : sourceRange.columnStart;
    final end = vertical ? sourceRange.rowEnd : sourceRange.columnEnd;
    if (end == start) {
      return null;
    }
    final values = <int>[];
    for (var index = start; index <= end; index += 1) {
      final coord = vertical
          ? FortuneCellCoord(index, axisIndex)
          : FortuneCellCoord(axisIndex, index);
      final value = _parseFillChineseNumber(sheet.cells[coord]);
      if (value == null) {
        return null;
      }
      values.add(value);
    }
    final step = values[1] - values[0];
    for (var index = 2; index < values.length; index += 1) {
      if (values[index] - values[index - 1] != step) {
        return null;
      }
    }
    final value = values.first + step * (targetIndex - start);
    return _cellWithFillText(source, _formatFillChineseNumber(value));
  }

  int? _parseFillChineseNumber(FortuneCell? cell) {
    if (cell == null || cell.formula != null) {
      return null;
    }
    final text = cell.renderedText.trim();
    if (text.isEmpty || text == '日') {
      return null;
    }
    var result = 0;
    var section = 0;
    var number = 0;
    for (final rune in text.runes) {
      final character = String.fromCharCode(rune);
      final digit = _fillChineseDigits[character];
      if (digit != null) {
        number = digit;
        continue;
      }
      final unit = _fillChineseUnits[character];
      if (unit == null) {
        return null;
      }
      if (unit == 10000 || unit == 100000000) {
        section = (section + number) * unit;
        result += section;
        section = 0;
      } else {
        section += number * unit;
      }
      number = 0;
    }
    return result + section + number;
  }

  String _formatFillChineseNumber(int value) {
    if (value <= 0) {
      return _fillChineseDigitLabels[0];
    }
    var remaining = value;
    var unitPosition = 0;
    var needsZero = false;
    var text = '';
    while (remaining > 0) {
      final section = remaining % 10000;
      if (needsZero) {
        text = '${_fillChineseDigitLabels[0]}$text';
      }
      final sectionText = _formatFillChineseSection(section);
      text =
          '$sectionText${section != 0 ? _fillChineseSectionLabels[unitPosition] : ''}$text';
      needsZero = section < 1000 && section > 0;
      remaining ~/= 10000;
      unitPosition += 1;
    }
    return text;
  }

  String _formatFillChineseSection(int section) {
    var remaining = section;
    var unitPosition = 0;
    var zero = true;
    var text = '';
    while (remaining > 0) {
      final digit = remaining % 10;
      if (digit == 0) {
        if (!zero) {
          zero = true;
          text = '${_fillChineseDigitLabels[digit]}$text';
        }
      } else {
        zero = false;
        text =
            '${_fillChineseDigitLabels[digit]}${_fillChineseUnitLabels[unitPosition]}$text';
      }
      unitPosition += 1;
      remaining ~/= 10;
    }
    return text;
  }

  FortuneCell? _singleDateCellForFill(
    FortuneRange sourceRange,
    FortuneRange fillRange,
    FortuneCell source,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord target,
  ) {
    if (source.formula != null) {
      return null;
    }
    if (sourceRange.rowStart != sourceRange.rowEnd ||
        sourceRange.columnStart != sourceRange.columnEnd) {
      return null;
    }
    final date = _parseFillDateValue(source);
    if (date == null) {
      return null;
    }
    final fillsVertically =
        fillRange.rowStart < sourceRange.rowStart ||
        fillRange.rowEnd > sourceRange.rowEnd;
    final fillsHorizontally =
        fillRange.columnStart < sourceRange.columnStart ||
        fillRange.columnEnd > sourceRange.columnEnd;
    final offset = fillsVertically
        ? target.row - sourceCoord.row
        : fillsHorizontally
        ? target.column - sourceCoord.column
        : 0;
    if (offset == 0) {
      return null;
    }
    final nextDate = date.date.add(Duration(days: offset));
    return source.cellType?.type == 'd'
        ? _cellWithFillDate(source, nextDate)
        : _cellWithFillText(source, _formatFillDate(nextDate, date));
  }

  FortuneCell? _dateSeriesCellForFill(
    FortuneCell source, {
    required FortuneCell? firstCell,
    required FortuneCell? lastCell,
    required int sourceIndex,
    required int targetIndex,
    required int stepDivisor,
  }) {
    if (firstCell == null || lastCell == null || stepDivisor == 0) {
      return null;
    }
    final first = _parseFillDateValue(firstCell);
    final last = _parseFillDateValue(lastCell);
    if (first == null || last == null) {
      return null;
    }
    final monthStep = _dateMonthStep(first.date, last.date, stepDivisor);
    if (monthStep != null) {
      final monthOffset = monthStep * (targetIndex - sourceIndex);
      final nextDate = _addMonthsClamped(
        first.date,
        monthOffset,
        preserveEndOfMonth: _isLastDayOfMonth(first.date),
      );
      return source.cellType?.type == 'd'
          ? _cellWithFillDate(source, nextDate)
          : _cellWithFillText(source, _formatFillDate(nextDate, first));
    }
    final days = last.date.difference(first.date).inDays;
    final step = days / stepDivisor;
    final offset = step * (targetIndex - sourceIndex);
    if ((offset - offset.round()).abs() > 1e-10) {
      return null;
    }
    final nextDate = first.date.add(Duration(days: offset.round()));
    return source.cellType?.type == 'd'
        ? _cellWithFillDate(source, nextDate)
        : _cellWithFillText(source, _formatFillDate(nextDate, first));
  }

  int? _dateMonthStep(DateTime first, DateTime last, int stepDivisor) {
    final totalMonths =
        (last.year - first.year) * 12 + last.month - first.month;
    if (totalMonths == 0 || totalMonths % stepDivisor != 0) {
      return null;
    }
    final preserveEndOfMonth = _isLastDayOfMonth(first);
    final expectedLast = _addMonthsClamped(
      first,
      totalMonths,
      preserveEndOfMonth: preserveEndOfMonth,
    );
    if (expectedLast.year != last.year ||
        expectedLast.month != last.month ||
        expectedLast.day != last.day) {
      return null;
    }
    return totalMonths ~/ stepDivisor;
  }

  DateTime _addMonthsClamped(
    DateTime date,
    int months, {
    required bool preserveEndOfMonth,
  }) {
    final monthIndex = date.month - 1 + months;
    final year = date.year + monthIndex ~/ 12;
    final month = monthIndex % 12 + 1;
    final day = preserveEndOfMonth
        ? _lastDayOfMonth(year, month)
        : math.min(date.day, _lastDayOfMonth(year, month));
    return DateTime(year, month, day);
  }

  bool _isLastDayOfMonth(DateTime date) {
    return date.day == _lastDayOfMonth(date.year, date.month);
  }

  int _lastDayOfMonth(int year, int month) {
    return DateTime(year, month + 1, 0).day;
  }

  FortuneCell? _singleDateTimeCellForFill(
    FortuneRange sourceRange,
    FortuneRange fillRange,
    FortuneCell source,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord target,
  ) {
    if (source.formula != null) {
      return null;
    }
    if (sourceRange.rowStart != sourceRange.rowEnd ||
        sourceRange.columnStart != sourceRange.columnEnd) {
      return null;
    }
    final dateTime = _parseFillDateTimeValue(source);
    if (dateTime == null) {
      return null;
    }
    final fillsVertically =
        fillRange.rowStart < sourceRange.rowStart ||
        fillRange.rowEnd > sourceRange.rowEnd;
    final fillsHorizontally =
        fillRange.columnStart < sourceRange.columnStart ||
        fillRange.columnEnd > sourceRange.columnEnd;
    final offset = fillsVertically
        ? target.row - sourceCoord.row
        : fillsHorizontally
        ? target.column - sourceCoord.column
        : 0;
    if (offset == 0) {
      return null;
    }
    final nextDateTime = dateTime.value.add(Duration(days: offset));
    return source.cellType?.type == 'd'
        ? _cellWithFillDate(source, nextDateTime)
        : _cellWithFillText(
            source,
            _formatFillDateTime(nextDateTime, dateTime),
          );
  }

  FortuneCell? _dateTimeSeriesCellForFill(
    FortuneCell source, {
    required FortuneCell? firstCell,
    required FortuneCell? lastCell,
    required int sourceIndex,
    required int targetIndex,
    required int stepDivisor,
  }) {
    if (firstCell == null || lastCell == null || stepDivisor == 0) {
      return null;
    }
    final first = _parseFillDateTimeValue(firstCell);
    final last = _parseFillDateTimeValue(lastCell);
    if (first == null || last == null) {
      return null;
    }
    final monthStep = first.time.seconds == last.time.seconds
        ? _dateMonthStep(first.date.date, last.date.date, stepDivisor)
        : null;
    if (monthStep != null) {
      final monthOffset = monthStep * (targetIndex - sourceIndex);
      final nextDateTime = _addMonthsClamped(
        first.date.date,
        monthOffset,
        preserveEndOfMonth: _isLastDayOfMonth(first.date.date),
      ).add(Duration(seconds: first.time.seconds));
      return source.cellType?.type == 'd'
          ? _cellWithFillDate(source, nextDateTime)
          : _cellWithFillText(source, _formatFillDateTime(nextDateTime, first));
    }
    final seconds = last.value.difference(first.value).inSeconds;
    final step = seconds / stepDivisor;
    final offset = step * (targetIndex - sourceIndex);
    if ((offset - offset.round()).abs() > 1e-10) {
      return null;
    }
    final nextDateTime = first.value.add(Duration(seconds: offset.round()));
    return source.cellType?.type == 'd'
        ? _cellWithFillDate(source, nextDateTime)
        : _cellWithFillText(source, _formatFillDateTime(nextDateTime, first));
  }

  ({
    DateTime value,
    String separator,
    ({
      DateTime date,
      String format,
      String delimiter,
      bool twoDigitMonth,
      bool twoDigitDay,
      String yearMonthGap,
      String monthDayGap,
    })
    date,
    ({
      int seconds,
      String format,
      bool twoDigitHour,
      bool twoDigitMinute,
      bool showSeconds,
      bool twoDigitSecond,
      String gap,
      String meridiemText,
    })
    time,
  })?
  _parseFillDateTimeValue(FortuneCell cell) {
    if (cell.formula != null) {
      return null;
    }
    final text = cell.renderedText.trim();
    for (final match in RegExp(r'\s+|[Tt]').allMatches(text)) {
      final date = _parseFillDateText(text.substring(0, match.start));
      if (date == null) {
        continue;
      }
      final time = _parseFillTimeText(text.substring(match.end));
      if (time == null) {
        continue;
      }
      return (
        value: DateTime(
          date.date.year,
          date.date.month,
          date.date.day,
        ).add(Duration(seconds: time.seconds)),
        separator: text.substring(match.start, match.end),
        date: date,
        time: time,
      );
    }
    return null;
  }

  String _formatFillDateTime(
    DateTime value,
    ({
      DateTime value,
      String separator,
      ({
        DateTime date,
        String format,
        String delimiter,
        bool twoDigitMonth,
        bool twoDigitDay,
        String yearMonthGap,
        String monthDayGap,
      })
      date,
      ({
        int seconds,
        String format,
        bool twoDigitHour,
        bool twoDigitMinute,
        bool showSeconds,
        bool twoDigitSecond,
        String gap,
        String meridiemText,
      })
      time,
    })
    sourceFormat,
  ) {
    return '${_formatFillDate(value, sourceFormat.date)}'
        '${sourceFormat.separator}'
        '${_formatFillTime(value.hour * 3600 + value.minute * 60 + value.second, sourceFormat.time)}';
  }

  FortuneCell? _singleTimeCellForFill(
    FortuneRange sourceRange,
    FortuneRange fillRange,
    FortuneCell source,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord target,
  ) {
    if (source.formula != null) {
      return null;
    }
    if (sourceRange.rowStart != sourceRange.rowEnd ||
        sourceRange.columnStart != sourceRange.columnEnd) {
      return null;
    }
    final time = _parseFillTimeValue(source);
    if (time == null) {
      return null;
    }
    final fillsVertically =
        fillRange.rowStart < sourceRange.rowStart ||
        fillRange.rowEnd > sourceRange.rowEnd;
    final fillsHorizontally =
        fillRange.columnStart < sourceRange.columnStart ||
        fillRange.columnEnd > sourceRange.columnEnd;
    final offset = fillsVertically
        ? target.row - sourceCoord.row
        : fillsHorizontally
        ? target.column - sourceCoord.column
        : 0;
    if (offset == 0) {
      return null;
    }
    final nextSeconds = time.seconds + offset * 60 * 60;
    return source.cellType?.type == 'd'
        ? _cellWithFillTime(source, nextSeconds)
        : _cellWithFillText(source, _formatFillTime(nextSeconds, time));
  }

  FortuneCell? _timeSeriesCellForFill(
    FortuneCell source, {
    required FortuneCell? firstCell,
    required FortuneCell? lastCell,
    required int sourceIndex,
    required int targetIndex,
    required int stepDivisor,
  }) {
    if (firstCell == null || lastCell == null || stepDivisor == 0) {
      return null;
    }
    final first = _parseFillTimeValue(firstCell);
    final last = _parseFillTimeValue(lastCell);
    if (first == null || last == null) {
      return null;
    }
    final step =
        _timeSeriesStepSeconds(first.seconds, last.seconds) / stepDivisor;
    final offset = step * (targetIndex - sourceIndex);
    if ((offset - offset.round()).abs() > 1e-10) {
      return null;
    }
    final nextSeconds = first.seconds + offset.round();
    return source.cellType?.type == 'd'
        ? _cellWithFillTime(source, nextSeconds)
        : _cellWithFillText(source, _formatFillTime(nextSeconds, first));
  }

  int _timeSeriesStepSeconds(int firstSeconds, int lastSeconds) {
    const secondsPerDay = 24 * 60 * 60;
    final rawDelta = lastSeconds - firstSeconds;
    final forwardDelta = rawDelta < 0 ? rawDelta + secondsPerDay : rawDelta;
    final backwardDelta = forwardDelta - secondsPerDay;
    return forwardDelta.abs() < backwardDelta.abs()
        ? forwardDelta
        : backwardDelta;
  }

  ({
    int seconds,
    String format,
    bool twoDigitHour,
    bool twoDigitMinute,
    bool showSeconds,
    bool twoDigitSecond,
    String gap,
    String meridiemText,
  })?
  _parseFillTimeValue(FortuneCell cell) {
    if (cell.formula != null) {
      return null;
    }
    return _parseFillTimeText(cell.renderedText.trim());
  }

  ({
    int seconds,
    String format,
    bool twoDigitHour,
    bool twoDigitMinute,
    bool showSeconds,
    bool twoDigitSecond,
    String gap,
    String meridiemText,
  })?
  _parseFillTimeText(String text) {
    if (text.isEmpty) {
      return null;
    }
    final korean = RegExp(
      r'^(오전|오후)(\s*)(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?$',
    ).firstMatch(text);
    if (korean != null) {
      return _parsedFillTime(
        hourText: korean.group(3)!,
        minuteText: korean.group(4)!,
        secondText: korean.group(5),
        format: 'koreanPrefix',
        gap: korean.group(2)!,
        meridiemText: korean.group(1)!,
      );
    }
    final meridiem = RegExp(
      r'^(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?(\s*)([AaPp]\.?[Mm]\.?)$',
    ).firstMatch(text);
    if (meridiem != null) {
      return _parsedFillTime(
        hourText: meridiem.group(1)!,
        minuteText: meridiem.group(2)!,
        secondText: meridiem.group(3),
        format: 'meridiemSuffix',
        gap: meridiem.group(4)!,
        meridiemText: meridiem.group(5)!,
      );
    }
    final twentyFour = RegExp(
      r'^(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?$',
    ).firstMatch(text);
    if (twentyFour != null) {
      return _parsedFillTime(
        hourText: twentyFour.group(1)!,
        minuteText: twentyFour.group(2)!,
        secondText: twentyFour.group(3),
        format: 'twentyFour',
        gap: '',
        meridiemText: '',
      );
    }
    return null;
  }

  ({
    int seconds,
    String format,
    bool twoDigitHour,
    bool twoDigitMinute,
    bool showSeconds,
    bool twoDigitSecond,
    String gap,
    String meridiemText,
  })?
  _parsedFillTime({
    required String hourText,
    required String minuteText,
    required String? secondText,
    required String format,
    required String gap,
    required String meridiemText,
  }) {
    var hour = int.tryParse(hourText);
    final minute = int.tryParse(minuteText);
    final second = int.tryParse(secondText ?? '0');
    if (hour == null || minute == null || second == null) {
      return null;
    }
    if (format == 'koreanPrefix' || format == 'meridiemSuffix') {
      if (hour < 1 || hour > 12) {
        return null;
      }
      final normalized = meridiemText.toUpperCase().replaceAll('.', '');
      final isPm = meridiemText == '오후' || normalized == 'PM';
      hour = isPm ? (hour == 12 ? 12 : hour + 12) : (hour == 12 ? 0 : hour);
    }
    if (hour >= 24 || minute >= 60 || second >= 60) {
      return null;
    }
    return (
      seconds: hour * 60 * 60 + minute * 60 + second,
      format: format,
      twoDigitHour: hourText.length > 1,
      twoDigitMinute: minuteText.length > 1,
      showSeconds: secondText != null,
      twoDigitSecond: (secondText ?? '').length > 1,
      gap: gap,
      meridiemText: meridiemText,
    );
  }

  String _formatFillTime(
    int seconds,
    ({
      int seconds,
      String format,
      bool twoDigitHour,
      bool twoDigitMinute,
      bool showSeconds,
      bool twoDigitSecond,
      String gap,
      String meridiemText,
    })
    sourceFormat,
  ) {
    const secondsPerDay = 24 * 60 * 60;
    final wrapped = seconds % secondsPerDay;
    final normalized = wrapped < 0 ? wrapped + secondsPerDay : wrapped;
    final hour24 = normalized ~/ 3600;
    final minute = (normalized % 3600) ~/ 60;
    final second = normalized % 60;
    var hour = hour24;
    var meridiem = sourceFormat.meridiemText;
    if (sourceFormat.format == 'koreanPrefix' ||
        sourceFormat.format == 'meridiemSuffix') {
      final isPm = hour24 >= 12;
      hour = hour24 % 12 == 0 ? 12 : hour24 % 12;
      if (sourceFormat.format == 'koreanPrefix') {
        meridiem = isPm ? '오후' : '오전';
      } else {
        meridiem = _matchingMeridiemText(sourceFormat.meridiemText, isPm);
      }
    }
    final hourText = sourceFormat.twoDigitHour
        ? hour.toString().padLeft(2, '0')
        : hour.toString();
    final minuteText = sourceFormat.twoDigitMinute
        ? minute.toString().padLeft(2, '0')
        : minute.toString();
    final secondText = sourceFormat.showSeconds
        ? ':${sourceFormat.twoDigitSecond ? second.toString().padLeft(2, '0') : second}'
        : '';
    final timeText = '$hourText:$minuteText$secondText';
    return switch (sourceFormat.format) {
      'koreanPrefix' => '$meridiem${sourceFormat.gap}$timeText',
      'meridiemSuffix' => '$timeText${sourceFormat.gap}$meridiem',
      _ => timeText,
    };
  }

  String _matchingMeridiemText(String source, bool isPm) {
    final hasDots = source.contains('.');
    final isLower = source == source.toLowerCase();
    final base = isPm ? 'PM' : 'AM';
    final cased = isLower ? base.toLowerCase() : base;
    return hasDots ? '${cased[0]}.${cased[1]}.' : cased;
  }

  FortuneCell? _singleSequenceCellForFill(
    FortuneRange sourceRange,
    FortuneRange fillRange,
    FortuneCell source,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord target,
  ) {
    if (source.formula != null) {
      return null;
    }
    if (sourceRange.rowStart != sourceRange.rowEnd ||
        sourceRange.columnStart != sourceRange.columnEnd) {
      return null;
    }
    final sequence = _parseFillSequenceValue(source);
    if (sequence == null) {
      return null;
    }
    final fillsVertically =
        fillRange.rowStart < sourceRange.rowStart ||
        fillRange.rowEnd > sourceRange.rowEnd;
    final fillsHorizontally =
        fillRange.columnStart < sourceRange.columnStart ||
        fillRange.columnEnd > sourceRange.columnEnd;
    final offset = fillsVertically
        ? target.row - sourceCoord.row
        : fillsHorizontally
        ? target.column - sourceCoord.column
        : 0;
    if (offset == 0) {
      return null;
    }
    return _cellWithFillText(
      source,
      _sequenceFillText(sequence.labels, sequence.index + offset),
    );
  }

  FortuneCell? _sequenceSeriesCellForFill(
    FortuneCell source, {
    required FortuneCell? firstCell,
    required FortuneCell? lastCell,
    required int sourceIndex,
    required int targetIndex,
    required int stepDivisor,
  }) {
    if (firstCell == null || lastCell == null || stepDivisor == 0) {
      return null;
    }
    final first = _parseFillSequenceValue(firstCell);
    final last = _parseFillSequenceValue(lastCell);
    if (first == null ||
        last == null ||
        !identical(first.labels, last.labels)) {
      return null;
    }
    final length = first.labels.length;
    final forwardDelta = (last.index - first.index) % length;
    final backwardDelta = forwardDelta - length;
    final delta = forwardDelta.abs() <= backwardDelta.abs()
        ? forwardDelta
        : backwardDelta;
    final step = delta / stepDivisor;
    final valueIndex = first.index + step * (targetIndex - sourceIndex);
    if ((valueIndex - valueIndex.round()).abs() > 1e-10) {
      return null;
    }
    return _cellWithFillText(
      source,
      _sequenceFillText(first.labels, valueIndex.round()),
    );
  }

  ({List<String> labels, int index})? _parseFillSequenceValue(
    FortuneCell cell,
  ) {
    if (cell.formula != null) {
      return null;
    }
    final normalized = cell.renderedText.trim().toLowerCase();
    if (normalized.isEmpty) {
      return null;
    }
    for (final labels in _fillTextSequences) {
      final index = labels.indexWhere(
        (label) => label.toLowerCase() == normalized,
      );
      if (index >= 0) {
        return (labels: labels, index: index);
      }
    }
    return null;
  }

  String _sequenceFillText(List<String> labels, int index) {
    final wrapped = index % labels.length;
    return labels[wrapped < 0 ? wrapped + labels.length : wrapped];
  }

  ({
    DateTime date,
    String format,
    String delimiter,
    bool twoDigitMonth,
    bool twoDigitDay,
    String yearMonthGap,
    String monthDayGap,
  })?
  _parseFillDateValue(FortuneCell cell) {
    if (cell.formula != null) {
      return null;
    }
    final text = cell.renderedText.trim();
    final textDate = _parseFillDateText(text);
    if (textDate != null) {
      return textDate;
    }
    if (cell.cellType?.type == 'd') {
      final serial = double.tryParse(cell.value.trim());
      if (serial != null && serial.isFinite && _fillFormatHasDatePart(cell)) {
        return (
          date: DateTime(1899, 12, 30).add(Duration(days: serial.floor())),
          format: 'separated',
          delimiter: '-',
          twoDigitMonth: true,
          twoDigitDay: true,
          yearMonthGap: '',
          monthDayGap: '',
        );
      }
    }
    return null;
  }

  bool _fillFormatHasDatePart(FortuneCell cell) {
    final format = cell.cellType?.format?.toLowerCase() ?? '';
    return format.contains('y') ||
        format.contains('d') ||
        format.contains('月') ||
        format.contains('年') ||
        format.contains('日');
  }

  ({
    DateTime date,
    String format,
    String delimiter,
    bool twoDigitMonth,
    bool twoDigitDay,
    String yearMonthGap,
    String monthDayGap,
  })?
  _parseFillDateText(String text) {
    final separated = RegExp(
      r'^(\d{4})([-/.])(\d{1,2})\2(\d{1,2})$',
    ).firstMatch(text);
    if (separated != null) {
      return _parsedFillDate(
        yearText: separated.group(1)!,
        monthText: separated.group(3)!,
        dayText: separated.group(4)!,
        format: 'separated',
        delimiter: separated.group(2)!,
      );
    }
    final korean = RegExp(
      r'^(\d{4})년(\s*)(\d{1,2})월(\s*)(\d{1,2})일$',
    ).firstMatch(text);
    if (korean != null) {
      return _parsedFillDate(
        yearText: korean.group(1)!,
        monthText: korean.group(3)!,
        dayText: korean.group(5)!,
        format: 'korean',
        delimiter: '',
        yearMonthGap: korean.group(2)!,
        monthDayGap: korean.group(4)!,
      );
    }
    final dottedTrailing = RegExp(
      r'^(\d{4})\.(\s*)(\d{1,2})\.(\s*)(\d{1,2})\.$',
    ).firstMatch(text);
    if (dottedTrailing != null) {
      return _parsedFillDate(
        yearText: dottedTrailing.group(1)!,
        monthText: dottedTrailing.group(3)!,
        dayText: dottedTrailing.group(5)!,
        format: 'dottedTrailing',
        delimiter: '.',
        yearMonthGap: dottedTrailing.group(2)!,
        monthDayGap: dottedTrailing.group(4)!,
      );
    }
    return null;
  }

  ({
    DateTime date,
    String format,
    String delimiter,
    bool twoDigitMonth,
    bool twoDigitDay,
    String yearMonthGap,
    String monthDayGap,
  })?
  _parsedFillDate({
    required String yearText,
    required String monthText,
    required String dayText,
    required String format,
    required String delimiter,
    String yearMonthGap = '',
    String monthDayGap = '',
  }) {
    final year = int.tryParse(yearText);
    final month = int.tryParse(monthText);
    final day = int.tryParse(dayText);
    if (year == null || month == null || day == null) {
      return null;
    }
    final date = DateTime(year, month, day);
    if (date.year != year || date.month != month || date.day != day) {
      return null;
    }
    return (
      date: date,
      format: format,
      delimiter: delimiter,
      twoDigitMonth: monthText.length > 1,
      twoDigitDay: dayText.length > 1,
      yearMonthGap: yearMonthGap,
      monthDayGap: monthDayGap,
    );
  }

  String _formatFillDate(
    DateTime date,
    ({
      DateTime date,
      String format,
      String delimiter,
      bool twoDigitMonth,
      bool twoDigitDay,
      String yearMonthGap,
      String monthDayGap,
    })
    sourceFormat,
  ) {
    final month = sourceFormat.twoDigitMonth
        ? date.month.toString().padLeft(2, '0')
        : date.month.toString();
    final day = sourceFormat.twoDigitDay
        ? date.day.toString().padLeft(2, '0')
        : date.day.toString();
    return switch (sourceFormat.format) {
      'korean' =>
        '${date.year}년${sourceFormat.yearMonthGap}$month월${sourceFormat.monthDayGap}$day일',
      'dottedTrailing' =>
        '${date.year}.${sourceFormat.yearMonthGap}$month.${sourceFormat.monthDayGap}$day.',
      _ =>
        '${date.year}${sourceFormat.delimiter}$month${sourceFormat.delimiter}$day',
    };
  }

  FortuneCell? _textSuffixSeriesCellForFill(
    FortuneCell source, {
    required FortuneCell? firstCell,
    required FortuneCell? lastCell,
    required int sourceIndex,
    required int targetIndex,
    required int stepDivisor,
  }) {
    if (firstCell == null || lastCell == null || stepDivisor == 0) {
      return null;
    }
    final first = _parseTextSuffixFillValue(firstCell);
    final last = _parseTextSuffixFillValue(lastCell);
    if (first == null || last == null || first.prefix != last.prefix) {
      return null;
    }
    final step = (last.number - first.number) / stepDivisor;
    final value = first.number + step * (targetIndex - sourceIndex);
    return _cellWithFillText(
      source,
      '${first.prefix}${_formatFillSuffixNumber(value, first.width)}',
    );
  }

  ({String prefix, double number, int width})? _parseTextSuffixFillValue(
    FortuneCell cell,
  ) {
    if (cell.formula != null) {
      return null;
    }
    final match = RegExp(
      r'^(.*?)(-?\d+(?:\.\d+)?)$',
    ).firstMatch(cell.renderedText.trim());
    if (match == null) {
      return null;
    }
    final prefix = match.group(1) ?? '';
    if (prefix.isEmpty) {
      return null;
    }
    final suffix = match.group(2) ?? '';
    final number = double.tryParse(suffix);
    if (number == null) {
      return null;
    }
    final width = suffix.contains('.') || suffix.startsWith('-')
        ? 0
        : suffix.length;
    return (prefix: prefix, number: number, width: width);
  }

  FortuneCell _cellWithFillText(FortuneCell source, String text) {
    return source.copyWith(
      value: text,
      rawValue: text,
      hasRawValue: true,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      displayValue: null,
      rawDisplayValue: null,
      hasRawDisplayValue: false,
    );
  }

  FortuneCell _cellWithFillDate(FortuneCell source, DateTime date) {
    final serial = datenumLocal(date);
    final value = _formatFillNumber(serial);
    final display = update(source.cellType?.format ?? 'yyyy-MM-dd', serial);
    return source.copyWith(
      value: value,
      rawValue: source.hasRawValue ? serial : null,
      hasRawValue: source.hasRawValue,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      displayValue: display,
      rawDisplayValue: display,
      hasRawDisplayValue: true,
    );
  }

  FortuneCell _cellWithFillTime(FortuneCell source, int seconds) {
    const secondsPerDay = 24 * 60 * 60;
    final wrapped = seconds % secondsPerDay;
    final normalized = wrapped < 0 ? wrapped + secondsPerDay : wrapped;
    final serial = normalized / secondsPerDay;
    final value = _formatFillNumber(serial);
    final display = update(source.cellType?.format ?? 'hh:mm', serial);
    return source.copyWith(
      value: value,
      rawValue: source.hasRawValue ? serial : null,
      hasRawValue: source.hasRawValue,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      displayValue: display,
      rawDisplayValue: display,
      hasRawDisplayValue: true,
    );
  }

  String _formatFillSuffixNumber(double value, int width) {
    final text = _formatFillNumber(value);
    if (width <= 0 || text.contains('.') || text.startsWith('-')) {
      return text;
    }
    return text.padLeft(width, '0');
  }

  double? _numericFillValue(FortuneCell? cell) {
    if (cell == null || cell.formula != null) {
      return null;
    }
    return double.tryParse(cell.renderedText.trim());
  }

  FortuneCell _cellWithFillNumber(FortuneCell source, double value) {
    final text = _formatFillNumber(value);
    return source.copyWith(
      value: text,
      rawValue: text,
      hasRawValue: true,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      displayValue: null,
      rawDisplayValue: null,
      hasRawDisplayValue: false,
    );
  }

  String _formatFillNumber(double value) {
    if (value.isFinite && (value - value.round()).abs() < 1e-10) {
      return value.round().toString();
    }
    return value.toString();
  }

  void _writeSelectionRange(FortuneRange range, FortuneCellCoord focus) {
    _writeSelectionRanges([range], focus);
  }

  void _writeSelectionSaveRange(FortuneRange range, FortuneCellCoord focus) {
    final rawRange = <String, Object?>{
      for (final entry in range.extraFields.entries)
        entry.key: cloneFortuneMetadata(entry.value),
      'row': [range.rowStart, range.rowEnd],
      'column': [range.columnStart, range.columnEnd],
      'row_focus': focus.row,
      'column_focus': focus.column,
    };
    final sheets = [..._workbook.sheets];
    sheets[_workbook.activeSheetIndex] = _workbook.activeSheet.copyWith(
      selectionSave: [rawRange],
      hasRawSelectionSave: true,
    );
    _workbook = _workbook.copyWith(sheets: sheets);
  }

  void _addSelectionRange(FortuneRange range, FortuneCellCoord focus) {
    final ranges = _rawSelectionRanges(_workbook.activeSheet);
    if (ranges.isEmpty) {
      ranges.add(_currentSelectionRange(_workbook.activeSheet));
    }
    ranges.removeWhere((existing) => _sameRange(existing, range));
    ranges.add(range);
    _writeSelectionRanges(ranges, focus);
  }

  void _writeSelectionRanges(
    List<FortuneRange> ranges,
    FortuneCellCoord focus, {
    int? sheetIndex,
  }) {
    if (ranges.isEmpty) {
      return;
    }
    final targetSheetIndex = sheetIndex ?? _workbook.activeSheetIndex;
    final rawRanges = ranges
        .map(
          (range) => <String, Object?>{
            for (final entry in range.extraFields.entries)
              entry.key: cloneFortuneMetadata(entry.value),
            'row': [range.rowStart, range.rowEnd],
            'column': [range.columnStart, range.columnEnd],
            'row_focus': focus.row,
            'column_focus': focus.column,
          },
        )
        .toList();

    final sheets = [..._workbook.sheets];
    final targetSheet = sheets[targetSheetIndex];
    sheets[targetSheetIndex] = targetSheet.copyWith(
      selectionSave: rawRanges.map(Map<String, Object?>.from).toList(),
      hasRawSelectionSave: true,
      selectionRange: rawRanges.map(Map<String, Object?>.from).toList(),
      hasRawSelectionRange: true,
    );
    _workbook = _workbook.copyWith(sheets: sheets);
  }

  void _clearSelectionRangeMetadata() {
    final sheets = [..._workbook.sheets];
    sheets[_workbook.activeSheetIndex] = _workbook.activeSheet.copyWith(
      selectionRange: const [],
      hasRawSelectionRange: true,
    );
    _workbook = _workbook.copyWith(sheets: sheets);
  }

  void _writeCopySelectionRangeMetadata(List<FortuneRange> ranges) {
    if (ranges.isEmpty) {
      return;
    }
    final rawRanges = ranges
        .map(
          (range) => <String, Object?>{
            'row': [range.rowStart, range.rowEnd],
            'column': [range.columnStart, range.columnEnd],
          },
        )
        .toList();
    final sheets = [..._workbook.sheets];
    sheets[_workbook.activeSheetIndex] = _workbook.activeSheet.copyWith(
      selectionRange: rawRanges.map(Map<String, Object?>.from).toList(),
      hasRawSelectionRange: true,
    );
    _workbook = _workbook.copyWith(sheets: sheets);
  }

  List<FortuneRange> _rawSelectionRanges(FortuneSheet sheet) {
    final raw = sheet.selectionSave;
    if (raw is! List) {
      return <FortuneRange>[];
    }
    final ranges = <FortuneRange>[];
    for (final item in raw) {
      if (item is! Map) {
        continue;
      }
      final row = item['row'];
      final column = item['column'];
      if (row is! List ||
          row.length < 2 ||
          column is! List ||
          column.length < 2) {
        continue;
      }
      final rowStart = _intValue(row[0]);
      final rowEnd = _intValue(row[1]);
      final columnStart = _intValue(column[0]);
      final columnEnd = _intValue(column[1]);
      if (rowStart == null ||
          rowEnd == null ||
          columnStart == null ||
          columnEnd == null) {
        continue;
      }
      ranges.add(
        FortuneRange(
          rowStart: math.min(rowStart, rowEnd),
          rowEnd: math.max(rowStart, rowEnd),
          columnStart: math.min(columnStart, columnEnd),
          columnEnd: math.max(columnStart, columnEnd),
          extraFields: {
            if (item['row_select'] == true) 'row_select': true,
            if (item['column_select'] == true) 'column_select': true,
          },
        ),
      );
    }
    return ranges;
  }

  FortuneRange _singleCellRange(FortuneCellCoord coord) {
    return FortuneRange(
      rowStart: coord.row,
      rowEnd: coord.row,
      columnStart: coord.column,
      columnEnd: coord.column,
    );
  }

  FortuneRange _cellSelectionRange(FortuneCellCoord coord) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    final merge = sheet.cells[anchor]?.merge;
    if (merge == null || (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
      return _singleCellRange(anchor);
    }
    return FortuneRange(
      rowStart: merge.row,
      rowEnd: merge.row + (merge.rowSpan < 1 ? 1 : merge.rowSpan) - 1,
      columnStart: merge.column,
      columnEnd:
          merge.column + (merge.columnSpan < 1 ? 1 : merge.columnSpan) - 1,
    );
  }

  FortuneRange _expandRangeForMergedCells(FortuneRange range) {
    var expanded = FortuneRange(
      rowStart: math.min(range.rowStart, range.rowEnd),
      rowEnd: math.max(range.rowStart, range.rowEnd),
      columnStart: math.min(range.columnStart, range.columnEnd),
      columnEnd: math.max(range.columnStart, range.columnEnd),
    );
    var changed = true;
    while (changed) {
      changed = false;
      for (final cell in _workbook.activeSheet.cells.values) {
        final merge = cell.merge;
        if (merge == null || (merge.rowSpan <= 1 && merge.columnSpan <= 1)) {
          continue;
        }
        final mergeRange = FortuneRange(
          rowStart: merge.row,
          rowEnd: merge.row + (merge.rowSpan < 1 ? 1 : merge.rowSpan) - 1,
          columnStart: merge.column,
          columnEnd:
              merge.column + (merge.columnSpan < 1 ? 1 : merge.columnSpan) - 1,
        );
        if (!_rangesIntersect(expanded, mergeRange)) {
          continue;
        }
        final next = FortuneRange(
          rowStart: math.min(expanded.rowStart, mergeRange.rowStart),
          rowEnd: math.max(expanded.rowEnd, mergeRange.rowEnd),
          columnStart: math.min(expanded.columnStart, mergeRange.columnStart),
          columnEnd: math.max(expanded.columnEnd, mergeRange.columnEnd),
        );
        if (!_sameRange(expanded, next)) {
          expanded = next;
          changed = true;
        }
      }
    }
    return expanded;
  }

  bool _rangesIntersect(FortuneRange a, FortuneRange b) {
    return a.rowStart <= b.rowEnd &&
        a.rowEnd >= b.rowStart &&
        a.columnStart <= b.columnEnd &&
        a.columnEnd >= b.columnStart;
  }

  FortuneRange? _rangeIntersection(FortuneRange a, FortuneRange b) {
    if (!_rangesIntersect(a, b)) {
      return null;
    }
    return FortuneRange(
      rowStart: math.max(a.rowStart, b.rowStart),
      rowEnd: math.min(a.rowEnd, b.rowEnd),
      columnStart: math.max(a.columnStart, b.columnStart),
      columnEnd: math.min(a.columnEnd, b.columnEnd),
    );
  }

  bool _sameRange(FortuneRange a, FortuneRange b) {
    return a.rowStart == b.rowStart &&
        a.rowEnd == b.rowEnd &&
        a.columnStart == b.columnStart &&
        a.columnEnd == b.columnEnd;
  }

  void _updateHoveredComment(PointerEvent event) {
    if (event.kind != PointerDeviceKind.mouse ||
        _editingCoord != null ||
        _editingFormulaBar ||
        _renamingSheetIndex != null ||
        contextMenuAt != null ||
        sheetTabMenuAt != null ||
        sheetListAt != null ||
        hiddenSheetListAt != null ||
        toolbarPopupKey != null) {
      _setHoveredComment(null);
      return;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final coord = _cellCoordAtLocal(event.localPosition, settings, metrics);
    if (coord == null) {
      _setHoveredComment(null);
      return;
    }
    final cell = _workbook.activeSheet.cells[coord];
    if (cell?.comment == null || (cell!.comment?.isShow ?? false)) {
      _setHoveredComment(null);
      return;
    }
    _setHoveredComment(coord);
  }

  void _setHoveredComment(FortuneCellCoord? coord) {
    if (_hoveredCommentCoord == coord) {
      return;
    }
    setState(() {
      _hoveredCommentCoord = coord;
    });
  }

  FortuneCellCoord? _visibleCommentBoxCoordAt(Offset local) {
    final sheet = _workbook.activeSheet;
    for (final entry in sheet.cells.entries.toList().reversed) {
      final coord = entry.key;
      final comment = entry.value.comment;
      if (comment == null) {
        continue;
      }
      if (!comment.isShow && coord != _hoveredCommentCoord) {
        continue;
      }
      if (_commentBoxRectForCoord(coord)?.contains(local) == true) {
        return coord;
      }
    }
    return null;
  }

  String? _commentBoxResizeSideAt(Offset local) {
    final coord = _editingCommentCoord;
    if (coord == null || !_workbook.settings.allowEdit) {
      return null;
    }
    final rect = _commentBoxRectForCoord(coord);
    if (rect == null) {
      return null;
    }
    const hitSize = 12.0;
    final handles = <String, Offset>{
      'lt': rect.topLeft,
      'mt': rect.topCenter,
      'rt': rect.topRight,
      'lm': rect.centerLeft,
      'rm': rect.centerRight,
      'lb': rect.bottomLeft,
      'mb': rect.bottomCenter,
      'rb': rect.bottomRight,
    };
    for (final entry in handles.entries) {
      final handleRect = Rect.fromCenter(
        center: entry.value,
        width: hitSize,
        height: hitSize,
      );
      if (handleRect.contains(local)) {
        return entry.key;
      }
    }
    return null;
  }

  bool _startCommentBoxResize(String side, Offset local) {
    final coord = _editingCommentCoord;
    if (coord == null || !_workbook.settings.allowEdit) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      return false;
    }
    final rect = _commentBoxRectForCoord(anchor);
    if (rect == null) {
      return false;
    }
    _commitSheetRename();
    setState(() {
      _commentBoxResizeCoord = anchor;
      _commentBoxResizeSide = side;
      _commentBoxResizeStart = local;
      _commentBoxResizeInitialRect = rect;
      _commentBoxResizeSnapshotRecorded = false;
    });
    return true;
  }

  bool _updateCommentBoxResize(Offset local) {
    final coord = _commentBoxResizeCoord;
    final side = _commentBoxResizeSide;
    final start = _commentBoxResizeStart;
    final initialRect = _commentBoxResizeInitialRect;
    if (coord == null || side == null || start == null || initialRect == null) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final previous = sheet.cells[coord];
    final comment = previous?.comment;
    if (previous == null || comment == null || !_canEditCell(sheet, coord)) {
      setState(_cancelCommentBoxResize);
      return true;
    }
    final settings = _workbook.settings;
    final zoom = sheet.zoomRatio == 0 ? 1.0 : sheet.zoomRatio;
    final origin = Offset(
      settings.rowHeaderWidth,
      settings.effectiveToolbarHeight +
          settings.effectiveFormulaBarHeight +
          settings.columnHeaderHeight,
    );
    final initial = initialRect.shift(-origin);
    final delta = local - start;
    var left = initial.left;
    var top = initial.top;
    var width = initial.width;
    var height = initial.height;
    final minHeight = 60 * zoom;
    final minWidth = 90 * zoom;
    if (side == 'lm' || side == 'lt' || side == 'lb') {
      if (width - delta.dx < minWidth) {
        left += width - minWidth;
        width = minWidth;
      } else {
        left += delta.dx;
        width -= delta.dx;
      }
      if (left < 0) {
        left = 0;
      }
    }
    if (side == 'rm' || side == 'rt' || side == 'rb') {
      width = width + delta.dx < minWidth ? minWidth : width + delta.dx;
    }
    if (side == 'mt' || side == 'lt' || side == 'rt') {
      if (height - delta.dy < minHeight) {
        top += height - minHeight;
        height = minHeight;
      } else {
        top += delta.dy;
        height -= delta.dy;
      }
      if (top < 0) {
        top = 0;
      }
    }
    if (side == 'mb' || side == 'lb' || side == 'rb') {
      height = height + delta.dy < minHeight ? minHeight : height + delta.dy;
    }
    final nextCell = _cellWithComment(
      previous,
      comment.copyWith(
        left: left / zoom,
        top: top / zoom,
        width: width / zoom,
        height: height / zoom,
      ),
    );
    if (_cellWouldChange(sheet, coord, nextCell) &&
        !_commentBoxResizeSnapshotRecorded) {
      _recordUndoSnapshot();
      _commentBoxResizeSnapshotRecorded = true;
    }
    setState(() {
      _setSheetCell(sheet, coord, nextCell);
    });
    return true;
  }

  bool _commitCommentBoxResize() {
    if (_commentBoxResizeCoord == null) {
      return false;
    }
    setState(_cancelCommentBoxResize);
    return true;
  }

  void _cancelCommentBoxResize() {
    _commentBoxResizeCoord = null;
    _commentBoxResizeSide = null;
    _commentBoxResizeStart = null;
    _commentBoxResizeInitialRect = null;
    _commentBoxResizeSnapshotRecorded = false;
  }

  bool _startCommentBoxMove(FortuneCellCoord coord, Offset local) {
    if (!_workbook.settings.allowEdit) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      return false;
    }
    final rect = _commentBoxRectForCoord(anchor);
    final comment = sheet.cells[anchor]?.comment;
    if (rect == null || comment == null) {
      return false;
    }
    _commitEditing();
    _commitSheetRename();
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      _writeSelectionRange(_cellSelectionRange(anchor), anchor);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _hoveredCommentCoord = null;
      _editingCoord = null;
      _editingFormulaBar = false;
      _editingCommentCoord = anchor;
      _commentEditorDraftUndoSnapshot = null;
      _commentEditorController.value = TextEditingValue(
        text: comment.value,
        selection: TextSelection.collapsed(offset: comment.value.length),
      );
      _commentBoxMoveCoord = anchor;
      _commentBoxMoveStart = local;
      _commentBoxMoveInitialTopLeft = rect.topLeft;
      _commentBoxMoveSnapshotRecorded = false;
    });
    return true;
  }

  bool _updateCommentBoxMove(Offset local) {
    final coord = _commentBoxMoveCoord;
    final start = _commentBoxMoveStart;
    final initialTopLeft = _commentBoxMoveInitialTopLeft;
    if (coord == null || start == null || initialTopLeft == null) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final previous = sheet.cells[coord];
    final comment = previous?.comment;
    if (previous == null || comment == null || !_canEditCell(sheet, coord)) {
      setState(_cancelCommentBoxMove);
      return true;
    }
    final settings = _workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final nextTopLeft = initialTopLeft + (local - start);
    final zoom = sheet.zoomRatio == 0 ? 1.0 : sheet.zoomRatio;
    final nextLeft =
        (nextTopLeft.dx - _sheetDataLeft(settings) + scrollOffset.dx) / zoom;
    final nextTop = math.max(
      0.0,
      (nextTopLeft.dy - sheetTop - _sheetDataTop(settings) + scrollOffset.dy) /
          zoom,
    );
    final nextCell = _cellWithComment(
      previous,
      comment.copyWith(left: nextLeft, top: nextTop),
    );
    if (_cellWouldChange(sheet, coord, nextCell) &&
        !_commentBoxMoveSnapshotRecorded) {
      _recordUndoSnapshot();
      _commentBoxMoveSnapshotRecorded = true;
    }
    setState(() {
      _setSheetCell(sheet, coord, nextCell);
    });
    return true;
  }

  bool _commitCommentBoxMove() {
    if (_commentBoxMoveCoord == null) {
      return false;
    }
    setState(_cancelCommentBoxMove);
    return true;
  }

  void _cancelCommentBoxMove() {
    _commentBoxMoveCoord = null;
    _commentBoxMoveStart = null;
    _commentBoxMoveInitialTopLeft = null;
    _commentBoxMoveSnapshotRecorded = false;
  }

  void _updateRawChartHover(PointerEvent event) {
    if (event.kind != PointerDeviceKind.mouse ||
        event.buttons != 0 ||
        sheetListAt != null ||
        hiddenSheetListAt != null) {
      _clearRawChartHoverPosition();
      return;
    }
    final settings = _workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetLocal = event.localPosition - Offset(0, sheetTop);
    if (sheetLocal.dy < _sheetDataTop(settings) ||
        sheetLocal.dx < _sheetDataLeft(settings)) {
      _clearRawChartHoverPosition();
      return;
    }
    final overlays = fortuneRawShapeOverlays(_workbook.activeSheet);
    for (final overlay in overlays.reversed) {
      if (overlay.placeholderLabel != 'Chart' ||
          !overlay.chartTooltipVisible ||
          overlay.chartTooltipAlwaysShowContent == true) {
        continue;
      }
      final rect = fortuneRawShapeOverlayScreenRect(
        overlay,
        settings,
        scrollOffset,
        _workbook.activeSheet.zoomRatio,
      );
      if (rect.contains(sheetLocal)) {
        _scheduleRawChartHoverPosition(
          sheetLocal,
          overlay.hitKey,
          overlay.chartTooltipShowDelay,
          overlay.chartTooltipHideDelay,
        );
        return;
      }
    }
    _clearRawChartHoverPosition();
  }

  void _updateRawChartClick(Offset local) {
    final settings = _workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetLocal = local - Offset(0, sheetTop);
    if (sheetLocal.dy < _sheetDataTop(settings) ||
        sheetLocal.dx < _sheetDataLeft(settings)) {
      _setRawChartClickPosition(null, null);
      return;
    }
    final overlays = fortuneRawShapeOverlays(_workbook.activeSheet);
    for (final overlay in overlays.reversed) {
      if (overlay.placeholderLabel != 'Chart' ||
          !overlay.chartTooltipVisible ||
          overlay.chartTooltipAlwaysShowContent == true ||
          !_fortuneCanvasRawChartTooltipAllowsClick(
            overlay.chartTooltipTriggerOn,
          )) {
        continue;
      }
      final rect = fortuneRawShapeOverlayScreenRect(
        overlay,
        settings,
        scrollOffset,
        _workbook.activeSheet.zoomRatio,
      );
      if (rect.contains(sheetLocal)) {
        _setRawChartClickPosition(sheetLocal, overlay.hitKey);
        return;
      }
    }
    _setRawChartClickPosition(null, null);
  }

  void _setRawChartHoverPosition(Offset? position, String? overlayKey) {
    if (_rawChartHoverPosition == position &&
        _rawChartHoverOverlayKey == overlayKey) {
      return;
    }
    setState(() {
      _rawChartHoverPosition = position;
      _rawChartHoverOverlayKey = overlayKey;
    });
  }

  void _scheduleRawChartHoverPosition(
    Offset position,
    String overlayKey,
    double? showDelay,
    double? hideDelay,
  ) {
    _cancelRawChartTooltipHideTimer();
    final delay = showDelay == null || !showDelay.isFinite
        ? 0
        : showDelay.round();
    if (delay <= 0 || _rawChartHoverPosition != null) {
      _cancelRawChartTooltipShowTimer();
      _rawChartTooltipHideDelay = hideDelay;
      _setRawChartHoverPosition(position, overlayKey);
      return;
    }
    if (_pendingRawChartHoverPosition == position &&
        _pendingRawChartHoverOverlayKey == overlayKey &&
        _rawChartTooltipShowTimer != null) {
      return;
    }
    _cancelRawChartTooltipShowTimer();
    _pendingRawChartHoverPosition = position;
    _pendingRawChartHoverOverlayKey = overlayKey;
    _rawChartTooltipShowTimer = Timer(Duration(milliseconds: delay), () {
      final pending = _pendingRawChartHoverPosition;
      final pendingOverlayKey = _pendingRawChartHoverOverlayKey;
      _pendingRawChartHoverPosition = null;
      _pendingRawChartHoverOverlayKey = null;
      _rawChartTooltipShowTimer = null;
      if (!mounted || pending == null || pendingOverlayKey == null) {
        return;
      }
      _rawChartTooltipHideDelay = hideDelay;
      _setRawChartHoverPosition(pending, pendingOverlayKey);
    });
  }

  void _clearRawChartHoverPosition() {
    _cancelRawChartTooltipShowTimer();
    final delay = _rawChartTooltipHideDelay;
    if (_rawChartHoverPosition != null &&
        delay != null &&
        delay.isFinite &&
        delay > 0) {
      _cancelRawChartTooltipHideTimer();
      _rawChartTooltipHideTimer = Timer(
        Duration(milliseconds: delay.round()),
        () {
          _rawChartTooltipHideTimer = null;
          _rawChartTooltipHideDelay = null;
          if (!mounted) {
            return;
          }
          _setRawChartHoverPosition(null, null);
        },
      );
      return;
    }
    _rawChartTooltipHideDelay = null;
    _setRawChartHoverPosition(null, null);
  }

  void _cancelRawChartTooltipShowTimer() {
    _rawChartTooltipShowTimer?.cancel();
    _rawChartTooltipShowTimer = null;
    _pendingRawChartHoverPosition = null;
    _pendingRawChartHoverOverlayKey = null;
  }

  void _cancelRawChartTooltipHideTimer() {
    _rawChartTooltipHideTimer?.cancel();
    _rawChartTooltipHideTimer = null;
  }

  void _setRawChartClickPosition(Offset? position, String? overlayKey) {
    if (_rawChartClickPosition == position &&
        _rawChartClickOverlayKey == overlayKey) {
      return;
    }
    setState(() {
      _rawChartClickPosition = position;
      _rawChartClickOverlayKey = overlayKey;
    });
  }

  bool _fortuneCanvasRawChartTooltipAllowsClick(String? triggerOn) {
    if (triggerOn == null) {
      return true;
    }
    return triggerOn
        .split('|')
        .map((part) => part.trim().toLowerCase())
        .contains('click');
  }

  _HeaderResizeTarget? _headerResizeTargetAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    const resizeHitSlop = 6.0;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final sheetY = local.dy - sheetTop;
    final headerLeft = _sheetHeaderLeft(settings);
    final headerTop = _sheetHeaderTop(settings);
    final dataLeft = _sheetDataLeft(settings);
    final dataTop = _sheetDataTop(settings);
    if (sheetY >= headerTop && sheetY <= dataTop && local.dx >= dataLeft) {
      final range = metrics.visibleColumns(
        scrollOffset.dx,
        (context.size?.width ?? 0) - dataLeft,
      );
      for (var c = range.start; c <= range.end; c += 1) {
        final width = metrics.columnEnd(c) - metrics.columnStart(c);
        if (width <= 0 && _workbook.activeSheet.hiddenColumns.contains(c)) {
          final edge = _visualCellLeft(c, settings, metrics);
          if ((local.dx - edge).abs() <= resizeHitSlop) {
            return _HeaderResizeTarget.column(c, hidden: true);
          }
        }
      }
      for (var c = range.start; c <= range.end; c += 1) {
        final width = metrics.columnEnd(c) - metrics.columnStart(c);
        if (width <= 0) continue;
        final edge = _visualCellLeft(c, settings, metrics) + width;
        if ((local.dx - edge).abs() <= resizeHitSlop) {
          return _HeaderResizeTarget.column(c);
        }
      }
    }
    if (local.dx >= headerLeft && local.dx <= dataLeft && sheetY >= dataTop) {
      final range = metrics.visibleRows(
        scrollOffset.dy,
        (context.size?.height ?? 0) -
            sheetTop -
            settings.effectiveSheetBarHeight -
            settings.statisticBarHeight -
            dataTop,
      );
      for (var r = range.start; r <= range.end; r += 1) {
        final height = metrics.rowEnd(r) - metrics.rowStart(r);
        if (height <= 0 && _workbook.activeSheet.hiddenRows.contains(r)) {
          final edge = _visualCellTop(r, settings, metrics);
          if ((sheetY - edge).abs() <= resizeHitSlop) {
            return _HeaderResizeTarget.row(r, hidden: true);
          }
        }
      }
      for (var r = range.start; r <= range.end; r += 1) {
        final height = metrics.rowEnd(r) - metrics.rowStart(r);
        if (height <= 0) continue;
        final edge = _visualCellTop(r, settings, metrics) + height;
        if ((sheetY - edge).abs() <= resizeHitSlop) {
          return _HeaderResizeTarget.row(r);
        }
      }
    }
    return null;
  }

  void _startResizeDrag(
    _HeaderResizeTarget target,
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheet = _workbook.activeSheet;
    final initialExtent = target.axis == 'column'
        ? target.hidden
              ? 0.0
              : sheet.columnWidths[target.index] ??
                    sheet.defaultColWidth ??
                    settings.defaultColWidth
        : target.hidden
        ? 0.0
        : sheet.rowHeights[target.index] ??
              sheet.defaultRowHeight ??
              settings.defaultRowHeight;
    setState(() {
      _clearSheetRulerSelectionValues();
      _resizeDragAxis = target.axis;
      _resizeDragIndex = target.index;
      _resizeDragStart = local;
      _resizeDragInitialExtent = initialExtent;
      _resizeDragSnapshotRecorded = false;
      _resizeDragLineX = target.axis == 'column'
          ? _visualCellLeft(target.index, settings, metrics) +
                metrics.columnEnd(target.index) -
                metrics.columnStart(target.index)
          : null;
      _resizeDragLineY = target.axis == 'row'
          ? _visualCellTop(target.index, settings, metrics) +
                metrics.rowEnd(target.index) -
                metrics.rowStart(target.index)
          : null;
      _closeTransientMenus();
    });
  }

  bool _updateResizeDrag(Offset local) {
    final axis = _resizeDragAxis;
    final index = _resizeDragIndex;
    final start = _resizeDragStart;
    final initialExtent = _resizeDragInitialExtent;
    if (axis == null ||
        index == null ||
        start == null ||
        initialExtent == null) {
      return false;
    }
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final zoomRatio = sheet.zoomRatio <= 0 ? 1.0 : sheet.zoomRatio;
    final nextExtent = axis == 'column'
        ? math.max(8.0, initialExtent + (local.dx - start.dx) / zoomRatio)
        : math.max(4.0, initialExtent + (local.dy - start.dy) / zoomRatio);
    final resizeIndexes = _resizeDragIndexes(sheet, axis, index);
    final changed = axis == 'column'
        ? resizeIndexes.any(
            (column) =>
                sheet.hiddenColumns.contains(column) ||
                sheet.hiddenColumnValues.containsKey(column) ||
                sheet.columnWidths[column] != nextExtent ||
                sheet.customWidth[column] != 1,
          )
        : resizeIndexes.any(
            (row) =>
                sheet.hiddenRows.contains(row) ||
                sheet.hiddenRowValues.containsKey(row) ||
                sheet.rowHeights[row] != nextExtent ||
                sheet.customHeight[row] != 1,
          );
    if (changed && !_resizeDragSnapshotRecorded) {
      _recordUndoSnapshot();
      _resizeDragSnapshotRecorded = true;
    }
    setState(() {
      if (axis == 'column') {
        if (changed) {
          for (final column in resizeIndexes) {
            sheet.hiddenColumns.remove(column);
            sheet.hiddenColumnValues.remove(column);
            sheet.columnWidths[column] = nextExtent;
            sheet.customWidth[column] = 1;
          }
          _replaceActiveSheet(
            sheet.copyWith(
              columnWidths: sheet.columnWidths,
              customWidth: sheet.customWidth,
              hiddenColumns: sheet.hiddenColumns,
              hiddenColumnValues: sheet.hiddenColumnValues,
            ),
          );
        }
        final metrics = sheet.metrics(settings);
        _resizeDragLineX =
            _visualCellLeft(index, settings, metrics) +
            metrics.columnEnd(index) -
            metrics.columnStart(index);
      } else {
        if (changed) {
          for (final row in resizeIndexes) {
            sheet.hiddenRows.remove(row);
            sheet.hiddenRowValues.remove(row);
            sheet.rowHeights[row] = nextExtent;
            sheet.customHeight[row] = 1;
          }
          _replaceActiveSheet(
            sheet.copyWith(
              rowHeights: sheet.rowHeights,
              customHeight: sheet.customHeight,
              hiddenRows: sheet.hiddenRows,
              hiddenRowValues: sheet.hiddenRowValues,
            ),
          );
        }
        final metrics = sheet.metrics(settings);
        _resizeDragLineY =
            _visualCellTop(index, settings, metrics) +
            metrics.rowEnd(index) -
            metrics.rowStart(index);
      }
    });
    return true;
  }

  List<int> _resizeDragIndexes(FortuneSheet sheet, String axis, int index) {
    final ranges = _rawSelectionRanges(sheet);
    final selectedRanges = ranges.where((range) {
      return axis == 'column'
          ? range.extraFields['column_select'] == true &&
                index >= range.columnStart &&
                index <= range.columnEnd
          : range.extraFields['row_select'] == true &&
                index >= range.rowStart &&
                index <= range.rowEnd;
    });
    final indexes = <int>{};
    for (final range in selectedRanges) {
      if (axis == 'column') {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          indexes.add(column);
        }
      } else {
        for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
          indexes.add(row);
        }
      }
    }
    if (indexes.isEmpty) {
      indexes.add(index);
    }
    return indexes.toList()..sort();
  }

  bool _commitResizeDrag() {
    if (_resizeDragAxis == null) {
      return false;
    }
    setState(_cancelResizeDrag);
    return true;
  }

  void _cancelResizeDrag() {
    _resizeDragAxis = null;
    _resizeDragIndex = null;
    _resizeDragStart = null;
    _resizeDragInitialExtent = null;
    _resizeDragLineX = null;
    _resizeDragLineY = null;
    _resizeDragSnapshotRecorded = false;
  }

  void _autoFitHeader(_HeaderResizeTarget target) {
    final sheet = _workbook.activeSheet;
    if (_isResizeTargetReadOnly(sheet, target)) {
      setState(_closeTransientMenus);
      return;
    }
    final changed = target.axis == 'column'
        ? sheet.hiddenColumns.contains(target.index) ||
              sheet.hiddenColumnValues.containsKey(target.index) ||
              sheet.columnWidths[target.index] !=
                  _autoFitColumnWidth(sheet, target.index) ||
              sheet.customWidth[target.index] != 1
        : sheet.hiddenRows.contains(target.index) ||
              sheet.hiddenRowValues.containsKey(target.index) ||
              sheet.rowHeights[target.index] !=
                  _autoFitRowHeight(sheet, target.index) ||
              sheet.customHeight[target.index] != 1;
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        if (target.axis == 'column') {
          sheet.hiddenColumns.remove(target.index);
          sheet.hiddenColumnValues.remove(target.index);
          sheet.columnWidths[target.index] = _autoFitColumnWidth(
            sheet,
            target.index,
          );
          sheet.customWidth[target.index] = 1;
          _replaceActiveSheet(
            sheet.copyWith(
              columnWidths: sheet.columnWidths,
              customWidth: sheet.customWidth,
              hiddenColumns: sheet.hiddenColumns,
              hiddenColumnValues: sheet.hiddenColumnValues,
            ),
          );
        } else {
          sheet.hiddenRows.remove(target.index);
          sheet.hiddenRowValues.remove(target.index);
          sheet.rowHeights[target.index] = _autoFitRowHeight(
            sheet,
            target.index,
          );
          sheet.customHeight[target.index] = 1;
          _replaceActiveSheet(
            sheet.copyWith(
              rowHeights: sheet.rowHeights,
              customHeight: sheet.customHeight,
              hiddenRows: sheet.hiddenRows,
              hiddenRowValues: sheet.hiddenRowValues,
            ),
          );
        }
      }
      _cancelResizeDrag();
      _closeTransientMenus();
    });
  }

  double _autoFitColumnWidth(FortuneSheet sheet, int column) {
    var width = _columnHeaderTextWidth(column) + 12;
    for (final entry in sheet.cells.entries) {
      if (entry.key.column != column || entry.value.renderedText.isEmpty) {
        continue;
      }
      width = math.max(width, _measureAutoFitTextWidth(entry.value) + 10);
    }
    return math.max(8, width);
  }

  double _autoFitRowHeight(FortuneSheet sheet, int row) {
    final settings = _workbook.settings;
    var height = sheet.defaultRowHeight ?? settings.defaultRowHeight;
    for (final entry in sheet.cells.entries) {
      if (entry.key.row != row || entry.value.renderedText.isEmpty) {
        continue;
      }
      final cell = entry.value;
      final fontSize = cell.fontSize ?? settings.defaultFontSize;
      final textHeight = cell.normalizedTextWrap == '2'
          ? _measureAutoFitTextHeight(
              cell,
              sheet.columnWidths[entry.key.column] ??
                  sheet.defaultColWidth ??
                  settings.defaultColWidth,
            )
          : math.max(1, cell.renderedText.split('\n').length) *
                    fontSize *
                    1.35 +
                6;
      height = math.max(height, textHeight);
    }
    return math.max(4, height);
  }

  void _syncWrappedEditRowHeight(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell cell,
  ) {
    if (cell.normalizedTextWrap != '2' || cell.renderedText.isEmpty) {
      return;
    }
    final merge = cell.merge;
    if (merge != null && (merge.rowSpan > 1 || merge.columnSpan > 1)) {
      return;
    }
    if (sheet.customHeight[coord.row] == 1) {
      return;
    }
    final defaultHeight =
        sheet.defaultRowHeight ?? _workbook.settings.defaultRowHeight;
    final nextHeight = _autoFitRowHeight(sheet, coord.row);
    if (nextHeight > defaultHeight &&
        sheet.rowHeights[coord.row] != nextHeight) {
      sheet.rowHeights[coord.row] = nextHeight;
    }
  }

  double _measureAutoFitTextHeight(FortuneCell cell, double columnWidth) {
    final settings = _workbook.settings;
    final fontSize = cell.fontSize ?? settings.defaultFontSize;
    final painter = TextPainter(
      text: TextSpan(
        text: cell.renderedText,
        style: TextStyle(
          fontSize: fontSize,
          fontFamily: _resolvedCellFontFamily(cell),
          fontWeight: cell.bold ? FontWeight.bold : FontWeight.normal,
          fontStyle: cell.italic ? FontStyle.italic : FontStyle.normal,
        ),
      ),
      textDirection: TextDirection.ltr,
    )..layout(maxWidth: math.max(1, columnWidth));
    return painter.height + 6;
  }

  double _measureAutoFitTextWidth(FortuneCell cell) {
    final settings = _workbook.settings;
    final fontSize = cell.fontSize ?? settings.defaultFontSize;
    final style = TextStyle(
      fontSize: fontSize,
      fontFamily: _resolvedCellFontFamily(cell),
      fontWeight: cell.bold ? FontWeight.bold : FontWeight.normal,
      fontStyle: cell.italic ? FontStyle.italic : FontStyle.normal,
    );
    var width = 0.0;
    for (final line in cell.renderedText.split('\n')) {
      final painter = TextPainter(
        text: TextSpan(text: line, style: style),
        textDirection: TextDirection.ltr,
        maxLines: 1,
      )..layout();
      width = math.max(width, painter.width);
    }
    return width;
  }

  double _columnHeaderTextWidth(int column) {
    var index = column;
    var label = '';
    do {
      label = String.fromCharCode(65 + (index % 26)) + label;
      index = index ~/ 26 - 1;
    } while (index >= 0);
    final painter = TextPainter(
      text: TextSpan(
        text: label,
        style: const TextStyle(fontSize: 12, fontWeight: FontWeight.w600),
      ),
      textDirection: TextDirection.ltr,
      maxLines: 1,
    )..layout();
    return painter.width;
  }

  bool _isResizeTargetReadOnly(FortuneSheet sheet, _HeaderResizeTarget target) {
    if (!_canEditSheetDefaultCell(sheet)) {
      return true;
    }
    return target.axis == 'column'
        ? _isIndexReadOnly(sheet.colReadOnly, target.index)
        : _isIndexReadOnly(sheet.rowReadOnly, target.index);
  }

  String? _freezeHandleAxisAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final size = context.size;
    if (size == null) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final footerHeight =
        settings.effectiveSheetBarHeight + settings.statisticBarHeight;
    final sheetBottom = size.height - footerHeight;
    if (local.dy < sheetTop || local.dy > sheetBottom) {
      return null;
    }
    final sheetY = local.dy - sheetTop;
    final frozen = _workbook.activeSheet.frozen;
    final columnFocus = frozen?.columnFocusIndex(
      metrics.visibleDataColumns.length,
    );
    final rowFocus = frozen?.rowFocusIndex(metrics.visibleDataRows.length);
    final frozenWidth = columnFocus == null
        ? 0
        : metrics.columnEnd(columnFocus);
    final frozenHeight = rowFocus == null ? 0 : metrics.rowEnd(rowFocus);
    final headerTop = _sheetHeaderTop(settings);
    final dataTop = _sheetDataTop(settings);
    final headerLeft = _sheetHeaderLeft(settings);
    final dataLeft = _sheetDataLeft(settings);
    final columnHandleX = dataLeft + frozenWidth;
    if (sheetY >= headerTop &&
        sheetY <= dataTop &&
        (local.dx - columnHandleX).abs() <= 5) {
      return 'column';
    }
    final rowHandleY = dataTop + frozenHeight;
    if (local.dx >= headerLeft &&
        local.dx <= dataLeft &&
        (sheetY - rowHandleY).abs() <= 5) {
      return 'row';
    }
    return null;
  }

  void _startFreezeDrag(String axis, Offset local) {
    if (!_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    setState(() {
      _freezeDragAxis = axis;
      _freezeDragLineX = axis == 'column' ? local.dx : null;
      _freezeDragLineY = axis == 'row'
          ? local.dy -
                _workbook.settings.effectiveToolbarHeight -
                _workbook.settings.effectiveFormulaBarHeight
          : null;
      contextMenuAt = null;
      sheetTabMenuAt = null;
      sheetListAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  bool _updateFreezeDrag(Offset local) {
    final axis = _freezeDragAxis;
    if (axis == null) {
      return false;
    }
    final settings = _workbook.settings;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    setState(() {
      if (axis == 'column') {
        _freezeDragLineX = math.max(settings.rowHeaderWidth, local.dx);
      } else {
        _freezeDragLineY = math.max(
          settings.columnHeaderHeight,
          local.dy - sheetTop,
        );
      }
    });
    return true;
  }

  bool _commitFreezeDrag(Offset local) {
    final axis = _freezeDragAxis;
    if (axis == null) {
      return false;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final sheet = _workbook.activeSheet;
    final nextFrozen = axis == 'column'
        ? _columnFreezeForIndex(
            sheet.frozen,
            _freezeColumnIndexAt(local, settings, metrics),
          )
        : _rowFreezeForIndex(
            sheet.frozen,
            _freezeRowIndexAt(local, settings, metrics),
          );
    final frozenChanged = !_frozenPaneEquals(sheet.frozen, nextFrozen);
    if (frozenChanged) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (frozenChanged) {
        _setActiveSheetFrozen(nextFrozen);
      }
      _freezeDragAxis = null;
      _freezeDragLineX = null;
      _freezeDragLineY = null;
    });
    return true;
  }

  void _cancelFreezeDrag() {
    _freezeDragAxis = null;
    _freezeDragLineX = null;
    _freezeDragLineY = null;
  }

  void _scheduleSheetTabLongPress(Offset local, int sheetIndex) {
    _sheetTabLongPressStart = local;
    _sheetTabLongPressSheetIndex = sheetIndex;
    _sheetTabLongPressTimer = Timer(const Duration(milliseconds: 550), () {
      if (!mounted || _sheetTabLongPressSheetIndex != sheetIndex) {
        return;
      }
      setState(() {
        final targetSheet = _workbook.sheets[sheetIndex];
        if (targetSheet.id != _workbook.activeSheet.id) {
          _rememberActiveSheetScrollOffset();
          _activateSheetAtIndex(sheetIndex);
        }
        contextMenuAt = null;
        final sheetTabItems = _sheetTabMenuItems;
        sheetTabMenuAt = sheetTabItems.isEmpty
            ? null
            : _sheetTabMenuOrigin(local);
        hiddenSheetListAt = null;
        _sheetTabMenuSheetIndex = sheetIndex;
        toolbarPopupKey = null;
      });
    });
  }

  void _cancelSheetTabLongPress() {
    _sheetTabLongPressTimer?.cancel();
    _sheetTabLongPressTimer = null;
    _sheetTabLongPressStart = null;
    _sheetTabLongPressSheetIndex = null;
  }

  void _updateSheetTabDrag(Offset local) {
    final start = _sheetTabDragStart;
    final index = _sheetTabDragSheetIndex;
    if (start == null || index == null) {
      return;
    }
    if (!_sheetTabDragging && (local - start).distance <= 8) {
      return;
    }
    final insertX = _sheetTabInsertionXAt(local);
    if (insertX == null) {
      return;
    }
    _cancelSheetTabLongPress();
    setState(() {
      _sheetTabDragging = true;
      _sheetTabDragInsertX = insertX;
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  void _commitSheetTabDrag(Offset local) {
    final from = _sheetTabDragSheetIndex;
    if (!_sheetTabDragging || from == null) {
      _cancelSheetTabDrag();
      return;
    }
    final insertBefore = _sheetTabInsertBeforeIndexAt(local);
    setState(() {
      _reorderSheetByDrag(from, insertBefore);
      _sheetTabDragStart = null;
      _sheetTabDragSheetIndex = null;
      _sheetTabDragging = false;
      _sheetTabDragInsertX = null;
    });
  }

  void _cancelSheetTabDrag() {
    _sheetTabDragStart = null;
    _sheetTabDragSheetIndex = null;
    _sheetTabDragging = false;
    _sheetTabDragInsertX = null;
  }

  String? _toolbarKeyAt(Offset local) {
    for (final entry in _visibleToolbarItemRects()) {
      if (entry.value.inflate(4).contains(local)) {
        return entry.key;
      }
    }
    return null;
  }

  String? _toolbarComboArrowKeyAt(Offset local) {
    final width = context.size?.width ?? 0;
    for (final entry in _visibleToolbarItemRects()) {
      if (!fortuneToolbarItemUsesCombo(entry.key, width)) {
        continue;
      }
      if (fortuneToolbarComboArrowRect(entry.value).contains(local)) {
        return entry.key;
      }
    }
    return null;
  }

  bool _isToolbarComboCommand(String? key) {
    final width = context.size?.width ?? 0;
    return key != null && fortuneToolbarItemUsesCombo(key, width);
  }

  void _activateToolbarComboPrimaryCommand(String key) {
    final command = _toolbarComboPrimaryCommand(key);
    if (command == null) {
      if (_isToolbarColorPrimaryNoop(key)) {
        return;
      }
      setState(() {
        toolbarPopupKey = key;
        _toolbarPopupHoveredIndex = null;
        _toolbarPopupScrollOffset = 0;
        _conditionFormatSubmenuKey = null;
        _conditionFormatHoveredTopLevelIndex = null;
        _conditionFormatHoveredSubmenuIndex = null;
      });
      return;
    }
    if (_isToolbarImmediateCommand(command)) {
      _activateToolbarImmediateCommand(command);
      return;
    }
    _activateToolbarPopupCommand(command);
  }

  bool _isToolbarColorPrimaryNoop(String key) {
    return (key == fortuneToolbarFontColorPopupKey &&
            _toolbarRecentTextColor == null) ||
        (key == fortuneToolbarBackgroundPopupKey &&
            _toolbarRecentBackgroundColor == null);
  }

  String? _toolbarComboPrimaryCommand(String key) {
    return switch (key) {
      fortuneToolbarFormatCommand => fortuneToolbarFormatAutomaticCommand,
      fortuneToolbarFontPopupKey => fortuneToolbarFontTimesCommand,
      fortuneToolbarFontSizePopupKey => fortuneToolbarFontSize10Command,
      fortuneToolbarFontColorPopupKey =>
        _toolbarRecentTextColor == null
            ? null
            : fortuneToolbarFontColorPaletteCommand(
                _toolbarHexString(_toolbarRecentTextColor!),
              ),
      fortuneToolbarBackgroundPopupKey =>
        _toolbarRecentBackgroundColor == null
            ? null
            : fortuneToolbarBackgroundPaletteCommand(
                _toolbarHexString(_toolbarRecentBackgroundColor!),
              ),
      fortuneToolbarBorderPopupKey => fortuneToolbarBorderAllCommand,
      fortuneToolbarMergePopupKey => fortuneToolbarMergeAllCommand,
      fortuneToolbarHorizontalAlignPopupKey => fortuneToolbarAlignLeftCommand,
      fortuneToolbarVerticalAlignPopupKey =>
        fortuneToolbarVerticalAlignMiddleCommand,
      fortuneToolbarTextWrapPopupKey => fortuneToolbarWrapOverflowCommand,
      fortuneToolbarTextRotationPopupKey => fortuneToolbarRotateNoneCommand,
      fortuneToolbarFreezePopupKey => fortuneFreezeRowColumnCommand,
      fortuneToolbarFilterCommand => fortuneToolbarFilterCommand,
      fortuneToolbarCommentCommand => fortuneToolbarCommentCommand,
      fortuneToolbarQuickFormulaPopupKey => fortuneToolbarFormulaSumCommand,
      _ => null,
    };
  }

  String _toolbarHexString(Color color) {
    final value = color.toARGB32();
    final red = ((value >> 16) & 0xff).toRadixString(16).padLeft(2, '0');
    final green = ((value >> 8) & 0xff).toRadixString(16).padLeft(2, '0');
    final blue = (value & 0xff).toRadixString(16).padLeft(2, '0');
    return '#$red$green$blue';
  }

  void _rememberToolbarColorCommand(String command) {
    if (command == fortuneToolbarFontColorResetCommand) {
      _toolbarRecentTextColor = const Color(0xff000000);
      return;
    }
    if (command == fortuneToolbarFontColorCustomBlackCommand) {
      _toolbarRecentTextColor = const Color(0xff000000);
      return;
    }
    if (command.startsWith(fortuneToolbarFontColorPaletteCommandPrefix)) {
      _toolbarRecentTextColor = fortuneToolbarHexColor(
        command.substring(fortuneToolbarFontColorPaletteCommandPrefix.length),
      );
      return;
    }
    if (fortuneToolbarFontColorCommands.contains(command)) {
      _toolbarRecentTextColor =
          fortuneToolbarColorCommands[command] ?? const Color(0xff000000);
      return;
    }

    if (command == fortuneToolbarBackgroundNoneCommand ||
        command == fortuneToolbarBackgroundResetCommand) {
      _toolbarRecentBackgroundColor = null;
      return;
    }
    if (command == fortuneToolbarBackgroundCustomBlackCommand) {
      _toolbarRecentBackgroundColor = const Color(0xff000000);
      return;
    }
    if (command.startsWith(fortuneToolbarBackgroundPaletteCommandPrefix)) {
      _toolbarRecentBackgroundColor = fortuneToolbarHexColor(
        command.substring(fortuneToolbarBackgroundPaletteCommandPrefix.length),
      );
      return;
    }
    if (fortuneToolbarBackgroundCommands.contains(command)) {
      _toolbarRecentBackgroundColor = fortuneToolbarColorCommands[command];
    }
  }

  bool _isToolbarStyleCommand(String? key) {
    return fortuneToolbarStyleCommands.contains(key);
  }

  bool _isToolbarEditCommand(String? key) {
    return fortuneToolbarEditCommands.contains(key);
  }

  void _activateToolbarEditCommand(String key, {bool isDoubleClick = false}) {
    switch (key) {
      case fortuneToolbarUndoCommand:
        _undoWorkbookChange();
        break;
      case fortuneToolbarRedoCommand:
        _redoWorkbookChange();
        break;
      case fortuneToolbarFormatPainterCommand:
        _activateFormatPainterCommand();
        break;
    }
  }

  void _activateFormatPainterCommand({bool persistent = false}) {
    final sheet = _workbook.activeSheet;
    if (!_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    final selectedRanges = _rawSelectionRanges(sheet);
    if (selectedRanges.length > 1) {
      setState(_closeTransientMenus);
      return;
    }
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final range = selectedRanges.isEmpty
        ? _currentSelectionRange(sheet)
        : selectedRanges.single;
    if (hasPartMC(
      sheet,
      range.rowStart,
      range.rowEnd,
      range.columnStart,
      range.columnEnd,
    )) {
      setState(_closeTransientMenus);
      return;
    }
    final hasRange =
        range.rowStart != range.rowEnd || range.columnStart != range.columnEnd;
    setState(() {
      _formatPainterCell = sheet.cells[coord] ?? const FortuneCell();
      _formatPainterCoord = coord;
      _formatPainterSourceRange = hasRange ? range : null;
      _formatPainterSourceCells = hasRange
          ? _formatPainterCellsForSourceRange(sheet, range)
          : null;
      _formatPainterPersistent = persistent;
      _writeCopySelectionRangeMetadata([range]);
      _closeTransientMenus();
    });
  }

  Map<FortuneCellCoord, FortuneCell> _formatPainterCellsForSourceRange(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    return {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1)
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        )
          FortuneCellCoord(
            row,
            column,
          ): sheet.cells[sheet.mergeAnchorFor(FortuneCellCoord(row, column))] ??
              const FortuneCell(),
    };
  }

  void _applyFormatPainterToRange(FortuneRange range, FortuneCell source) {
    final sheet = _workbook.activeSheet;
    if (!_canEditRange(sheet, range)) {
      setState(() {
        if (!_formatPainterPersistent) {
          _formatPainterCell = null;
          _formatPainterCoord = null;
          _formatPainterSourceRange = null;
          _formatPainterSourceCells = null;
        }
        _closeTransientMenus();
      });
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final updates = <MapEntry<FortuneCellCoord, FortuneCell>>[];
    for (final coord in targets) {
      final previous = sheet.cells[coord] ?? const FortuneCell();
      final next = _cellWithPaintedFormat(
        previous,
        _formatPainterSourceCellForTarget(coord, range, source),
      );
      if (_cellWouldChange(sheet, coord, next)) {
        updates.add(MapEntry(coord, next));
      }
    }
    final borderUpdates = _formatPainterBorderInfoForTargets(
      sheet,
      targets,
      range,
    );
    final dataVerificationUpdates = _formatPainterDataVerificationForTargets(
      sheet,
      targets,
      range,
    );
    final rawDataVerificationUpdates =
        _formatPainterRawDataVerificationForTargets(sheet, targets, range);
    final conditionFormatUpdates = _formatPainterConditionFormatsForRange(
      sheet,
      range,
    );
    if (updates.isNotEmpty ||
        borderUpdates.isNotEmpty ||
        conditionFormatUpdates != null ||
        dataVerificationUpdates.entries.any(
          (entry) =>
              _dataVerificationWouldChange(sheet, entry.key, entry.value),
        ) ||
        rawDataVerificationUpdates.entries.any(
          (entry) =>
              _rawDataVerificationWouldChange(sheet, entry.key, entry.value),
        )) {
      _recordUndoSnapshot();
    }
    setState(() {
      for (final update in updates) {
        _setSheetCell(sheet, update.key, update.value);
      }
      if (borderUpdates.isNotEmpty) {
        _replaceActiveSheet(
          sheet.copyWith(borderInfo: [...sheet.borderInfo, ...borderUpdates]),
        );
      }
      for (final entry in dataVerificationUpdates.entries) {
        sheet.dataVerification[_cellKey(entry.key)] = entry.value;
      }
      if (rawDataVerificationUpdates.isNotEmpty) {
        final rawDataVerification = sheet.rawDataVerification;
        final nextRawDataVerification = rawDataVerification is Map
            ? Map<Object?, Object?>.from(
                cloneFortuneMetadata(rawDataVerification) as Map,
              )
            : <Object?, Object?>{};
        for (final entry in rawDataVerificationUpdates.entries) {
          nextRawDataVerification[_cellKey(entry.key)] = cloneFortuneMetadata(
            entry.value,
          );
        }
        _replaceActiveSheet(
          _workbook.activeSheet.copyWith(
            rawDataVerification: nextRawDataVerification,
            hasRawDataVerification: true,
          ),
        );
      }
      if (conditionFormatUpdates != null) {
        _replaceActiveSheet(
          _workbook.activeSheet.copyWith(
            conditionFormats: conditionFormatUpdates,
            hasRawConditionFormats: true,
          ),
        );
      }
      if (!_formatPainterPersistent) {
        _formatPainterCell = null;
        _formatPainterCoord = null;
        _formatPainterSourceRange = null;
        _formatPainterSourceCells = null;
      }
      _cancelFormatPainterDrag();
      _closeTransientMenus();
    });
  }

  void _startFormatPainterDrag(FortuneCellCoord anchor) {
    _selectionDragAnchor = null;
    _selectionDragging = false;
    _formatPainterDragAnchor = anchor;
    _formatPainterDragging = false;
    setState(() {
      final range = _cellSelectionRange(anchor);
      selection = FortuneSelection(
        row: range.rowStart,
        column: range.columnStart,
        rowEnd: range.rowEnd,
        columnEnd: range.columnEnd,
      );
      _writeSelectionRange(range, anchor);
      _closeTransientMenus();
    });
  }

  bool _updateFormatPainterDrag(PointerMoveEvent event) {
    final anchor = _formatPainterDragAnchor;
    if (anchor == null) {
      return false;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final nextScrollOffset = _autoScrollOffsetForDrag(
      event.localPosition,
      settings,
      metrics,
    );
    final coord = _cellCoordAtLocal(
      event.localPosition,
      settings,
      metrics,
      scrollOverride: nextScrollOffset,
    );
    if (coord == null) {
      return true;
    }
    if (!_formatPainterDragging &&
        coord == anchor &&
        nextScrollOffset == scrollOffset) {
      return true;
    }
    final range = FortuneRange(
      rowStart: math.min(anchor.row, coord.row),
      rowEnd: math.max(anchor.row, coord.row),
      columnStart: math.min(anchor.column, coord.column),
      columnEnd: math.max(anchor.column, coord.column),
    );
    setState(() {
      scrollOffset = nextScrollOffset;
      _formatPainterDragging = true;
      selection = FortuneSelection(
        row: anchor.row,
        column: anchor.column,
        rowEnd: coord.row,
        columnEnd: coord.column,
      );
      _writeSelectionRange(range, anchor);
      _closeTransientMenus();
    });
    return true;
  }

  bool _commitFormatPainterDrag() {
    final source = _formatPainterCell;
    final anchor = _formatPainterDragAnchor;
    if (source == null || anchor == null) {
      return false;
    }
    final range = _currentSelectionRange(_workbook.activeSheet);
    _applyFormatPainterToRange(range, source);
    return true;
  }

  void _cancelFormatPainterDrag({bool clearPainter = false}) {
    _formatPainterDragAnchor = null;
    _formatPainterDragging = false;
    if (clearPainter) {
      _formatPainterCell = null;
      _formatPainterCoord = null;
      _formatPainterSourceRange = null;
      _formatPainterSourceCells = null;
      _formatPainterPersistent = false;
    }
  }

  FortuneCell _formatPainterSourceCellForTarget(
    FortuneCellCoord target,
    FortuneRange targetRange,
    FortuneCell fallback,
  ) {
    final sourceCoord = _formatPainterSourceCoordForTarget(target, targetRange);
    if (sourceCoord == null) {
      return fallback;
    }
    return _formatPainterSourceCells?[sourceCoord] ?? fallback;
  }

  FortuneCellCoord? _formatPainterSourceCoordForTarget(
    FortuneCellCoord target,
    FortuneRange targetRange,
  ) {
    final sourceRange = _formatPainterSourceRange;
    final sourceCells = _formatPainterSourceCells;
    if (sourceRange == null || sourceCells == null) {
      return null;
    }
    final sourceRowCount = sourceRange.rowEnd - sourceRange.rowStart + 1;
    final sourceColumnCount =
        sourceRange.columnEnd - sourceRange.columnStart + 1;
    if (sourceRowCount <= 0 || sourceColumnCount <= 0) {
      return null;
    }
    final sourceRow =
        sourceRange.rowStart +
        (target.row - targetRange.rowStart) % sourceRowCount;
    final sourceColumn =
        sourceRange.columnStart +
        (target.column - targetRange.columnStart) % sourceColumnCount;
    return FortuneCellCoord(sourceRow, sourceColumn);
  }

  List<FortuneBorderInfo> _formatPainterBorderInfoForTargets(
    FortuneSheet sheet,
    Iterable<FortuneCellCoord> targets,
    FortuneRange targetRange,
  ) {
    if (_formatPainterSourceRange != null) {
      final bordersByCell = FortuneBorderCompute.compute(sheet);
      final candidates = <FortuneBorderInfo>[];
      for (final target in targets) {
        final sourceCoord = _formatPainterSourceCoordForTarget(
          target,
          targetRange,
        );
        final sourceBorders = sourceCoord == null
            ? null
            : bordersByCell[sourceCoord];
        if (sourceBorders == null || sourceBorders.isEmpty) {
          continue;
        }
        candidates.addAll(
          _formatPainterBorderInfosForTarget(target, sourceBorders),
        );
      }
      return candidates.where((candidate) {
        return !sheet.borderInfo.any(
          (existing) => _borderInfoSemanticallyEquals(existing, candidate),
        );
      }).toList();
    }
    final sourceCoord = _formatPainterCoord;
    if (sourceCoord == null) {
      return const [];
    }
    final sourceBorders = FortuneBorderCompute.compute(sheet)[sourceCoord];
    if (sourceBorders == null || sourceBorders.isEmpty) {
      return const [];
    }
    final candidates = <FortuneBorderInfo>[];
    for (final target in targets) {
      candidates.addAll(
        _formatPainterBorderInfosForTarget(target, sourceBorders),
      );
    }
    return candidates.where((candidate) {
      return !sheet.borderInfo.any(
        (existing) => _borderInfoSemanticallyEquals(existing, candidate),
      );
    }).toList();
  }

  Map<FortuneCellCoord, Object?> _formatPainterDataVerificationForTargets(
    FortuneSheet sheet,
    Iterable<FortuneCellCoord> targets,
    FortuneRange targetRange,
  ) {
    if (_formatPainterSourceRange != null) {
      return {
        for (final target in targets)
          if (_formatPainterSourceCoordForTarget(target, targetRange)
              case final sourceCoord?)
            if (sheet.dataVerification[_cellKey(sourceCoord)]
                case final sourceDataVerification?)
              target: cloneFortuneMetadata(sourceDataVerification),
      };
    }
    final sourceCoord = _formatPainterCoord;
    if (sourceCoord == null) {
      return const {};
    }
    final sourceDataVerification =
        sheet.dataVerification[_cellKey(sourceCoord)];
    if (sourceDataVerification == null) {
      return const {};
    }
    return {
      for (final target in targets)
        target: cloneFortuneMetadata(sourceDataVerification),
    };
  }

  Map<FortuneCellCoord, Object?> _formatPainterRawDataVerificationForTargets(
    FortuneSheet sheet,
    Iterable<FortuneCellCoord> targets,
    FortuneRange targetRange,
  ) {
    final rawDataVerification = sheet.rawDataVerification;
    if (rawDataVerification is! Map) {
      return const {};
    }
    if (_formatPainterSourceRange != null) {
      return {
        for (final target in targets)
          if (_formatPainterSourceCoordForTarget(target, targetRange)
              case final sourceCoord?)
            if (rawDataVerification[_cellKey(sourceCoord)]
                case final sourceDataVerification?)
              target: cloneFortuneMetadata(sourceDataVerification),
      };
    }
    final sourceCoord = _formatPainterCoord;
    if (sourceCoord == null) {
      return const {};
    }
    final sourceDataVerification = rawDataVerification[_cellKey(sourceCoord)];
    if (sourceDataVerification == null) {
      return const {};
    }
    return {
      for (final target in targets)
        target: cloneFortuneMetadata(sourceDataVerification),
    };
  }

  Object? _formatPainterConditionFormatsForRange(
    FortuneSheet sheet,
    FortuneRange targetRange,
  ) {
    final rawRules = sheet.conditionFormats;
    if (rawRules is! List || rawRules.isEmpty) {
      return null;
    }
    if (_formatPainterSourceRange != null) {
      return _formatPainterConditionFormatsForRangeSource(
        rawRules,
        targetRange,
      );
    }
    final sourceCoord = _formatPainterCoord;
    if (sourceCoord == null) {
      return null;
    }
    final additions = <Object?>[];
    for (final rawRule in rawRules) {
      if (rawRule is! Map) {
        continue;
      }
      final includesSource = _conditionFormatRuleRanges(
        rawRule,
      ).any((range) => _rangeContainsCoord(range, sourceCoord));
      if (!includesSource) {
        continue;
      }
      final clonedRule = <String, Object?>{};
      for (final entry in rawRule.entries) {
        clonedRule['${entry.key}'] = cloneFortuneMetadata(entry.value);
      }
      clonedRule['cellrange'] = [_conditionRangeMap(targetRange)];
      additions.add(clonedRule);
    }
    if (additions.isEmpty) {
      return null;
    }
    return [...rawRules, ...additions];
  }

  Object? _formatPainterConditionFormatsForRangeSource(
    List rawRules,
    FortuneRange targetRange,
  ) {
    final additions = <Object?>[];
    for (final rawRule in rawRules) {
      if (rawRule is! Map) {
        continue;
      }
      final ruleRanges = _conditionFormatRuleRanges(rawRule);
      if (ruleRanges.isEmpty) {
        continue;
      }
      final mappedRanges = <Map<String, Object?>>[];
      for (
        var row = targetRange.rowStart;
        row <= targetRange.rowEnd;
        row += 1
      ) {
        for (
          var column = targetRange.columnStart;
          column <= targetRange.columnEnd;
          column += 1
        ) {
          final targetCoord = FortuneCellCoord(row, column);
          final sourceCoord = _formatPainterSourceCoordForTarget(
            targetCoord,
            targetRange,
          );
          if (sourceCoord == null ||
              !ruleRanges.any(
                (range) => _rangeContainsCoord(range, sourceCoord),
              )) {
            continue;
          }
          mappedRanges.add(
            _conditionRangeMap(
              FortuneRange(
                rowStart: row,
                rowEnd: row,
                columnStart: column,
                columnEnd: column,
                rowFocus: row,
                columnFocus: column,
              ),
            ),
          );
        }
      }
      if (mappedRanges.isEmpty) {
        continue;
      }
      final clonedRule = <String, Object?>{};
      for (final entry in rawRule.entries) {
        clonedRule['${entry.key}'] = cloneFortuneMetadata(entry.value);
      }
      clonedRule['cellrange'] = mappedRanges;
      additions.add(clonedRule);
    }
    if (additions.isEmpty) {
      return null;
    }
    return [...rawRules, ...additions];
  }

  List<FortuneBorderInfo> _formatPainterBorderInfosForTarget(
    FortuneCellCoord target,
    FortuneCellBorders borders,
  ) {
    final items = <FortuneBorderInfo>[];
    void add(String borderType, FortuneBorderSide? side) {
      if (side == null) {
        return;
      }
      items.add(
        FortuneBorderInfo(
          rangeType: 'range',
          borderType: borderType,
          color: side.color,
          style: side.style,
          ranges: [
            FortuneRange(
              rowStart: target.row,
              rowEnd: target.row,
              columnStart: target.column,
              columnEnd: target.column,
              rowFocus: target.row,
              columnFocus: target.column,
            ),
          ],
        ),
      );
    }

    add(fortuneToolbarBorderTopCommand, borders.top);
    add(fortuneToolbarBorderRightCommand, borders.right);
    add(fortuneToolbarBorderBottomCommand, borders.bottom);
    add(fortuneToolbarBorderLeftCommand, borders.left);
    add(fortuneToolbarBorderSlashCommand, borders.slash);
    return items;
  }

  List<Object?> _rawBorderInfoForTarget(
    FortuneCellCoord target,
    FortuneCellBorders borders,
  ) {
    if (borders.slash != null) {
      return [_rawSlashBorderInfoForTarget(target, borders.slash!)];
    }
    return [_rawCellBorderInfoForTarget(target, borders)];
  }

  Map<String, Object?> _rawCellBorderInfoForTarget(
    FortuneCellCoord target,
    FortuneCellBorders borders,
  ) {
    return {
      'rangeType': 'cell',
      'value': {
        'row_index': target.row,
        'col_index': target.column,
        'l': _rawCellBorderSide(borders.left),
        'r': _rawCellBorderSide(borders.right),
        't': _rawCellBorderSide(borders.top),
        'b': _rawCellBorderSide(borders.bottom),
      },
    };
  }

  Map<String, Object?> _rawSlashBorderInfoForTarget(
    FortuneCellCoord target,
    FortuneBorderSide side,
  ) {
    return {
      'rangeType': 'range',
      'borderType': fortuneToolbarBorderSlashCommand,
      'color': _toolbarHexString(side.color),
      'style': side.style,
      'range': [
        _rawBorderRange(
          FortuneRange(
            rowStart: target.row,
            rowEnd: target.row,
            columnStart: target.column,
            columnEnd: target.column,
            rowFocus: target.row,
            columnFocus: target.column,
          ),
        ),
      ],
    };
  }

  Map<String, Object?>? _rawCellBorderSide(FortuneBorderSide? side) {
    if (side == null) {
      return null;
    }
    return {'color': _toolbarHexString(side.color), 'style': side.style};
  }

  bool _cellBordersHaveAnySide(FortuneCellBorders borders) {
    return borders.top != null ||
        borders.right != null ||
        borders.bottom != null ||
        borders.left != null ||
        borders.slash != null;
  }

  FortuneCell _cellWithPaintedFormat(FortuneCell target, FortuneCell source) {
    return target.copyWith(
      cellType: source.cellType,
      quotePrefix: source.quotePrefix,
      rawQuotePrefix: source.rawQuotePrefix,
      hasRawQuotePrefix: source.hasRawQuotePrefix,
      background: source.background,
      rawBackground: source.rawBackground,
      hasRawBackground: source.hasRawBackground,
      foreground: source.foreground,
      rawForeground: source.rawForeground,
      hasRawForeground: source.hasRawForeground,
      bold: source.bold,
      rawBold: source.rawBold,
      hasRawBold: source.hasRawBold,
      italic: source.italic,
      rawItalic: source.rawItalic,
      hasRawItalic: source.hasRawItalic,
      strikeThrough: source.strikeThrough,
      rawStrikeThrough: source.rawStrikeThrough,
      hasRawStrikeThrough: source.hasRawStrikeThrough,
      underline: source.underline,
      rawUnderline: source.rawUnderline,
      hasRawUnderline: source.hasRawUnderline,
      fontSize: source.fontSize,
      rawFontSize: source.rawFontSize,
      hasRawFontSize: source.hasRawFontSize,
      fontFamily: source.fontFamily,
      rawFontFamily: source.rawFontFamily,
      hasRawFontFamily: source.hasRawFontFamily,
      horizontalAlign: source.horizontalAlign,
      rawHorizontalAlign: source.rawHorizontalAlign,
      hasRawHorizontalAlign: source.hasRawHorizontalAlign,
      verticalAlign: source.verticalAlign,
      rawVerticalAlign: source.rawVerticalAlign,
      hasRawVerticalAlign: source.hasRawVerticalAlign,
      textWrap: source.textWrap,
      rawTextWrap: source.rawTextWrap,
      hasRawTextWrap: source.hasRawTextWrap,
      textRotation: source.textRotation,
      rawTextRotation: source.rawTextRotation,
      hasRawTextRotation: source.hasRawTextRotation,
      textRotationMode: source.textRotationMode,
      rawTextRotationMode: source.rawTextRotationMode,
      hasRawTextRotationMode: source.hasRawTextRotationMode,
    );
  }

  bool _isToolbarImmediateCommand(String? key) {
    return fortuneToolbarImmediateCommands.contains(key);
  }

  void _activateToolbarImmediateCommand(String key) {
    switch (key) {
      case fortuneToolbarCurrencyFormatCommand:
      case fortuneToolbarPercentageFormatCommand:
      case fortuneToolbarNumberDecreaseCommand:
      case fortuneToolbarNumberIncreaseCommand:
        _applyToolbarNumberFormatCommand(key);
        break;
      case fortuneToolbarClearFormatCommand:
        _clearSelectedCellFormat();
        break;
      case fortuneToolbarLinkCommand:
        _toggleSelectedCellHyperlink();
        break;
      case fortuneToolbarCommentCommand:
        _toggleSelectedCellComment();
        break;
      case fortuneToolbarFilterCommand:
        _toggleSelectedColumnFilter();
        break;
      case fortuneToolbarDataVerificationCommand:
        _showDataVerificationDialogForSelection();
        break;
      case fortuneToolbarImageCommand:
        _showImageInsertDialog();
        break;
      case fortuneToolbarBarcodeCommand:
        _showBarcodeInsertDialog();
        break;
      case fortuneToolbarSplitColumnCommand:
        _showSplitTextDialog();
        break;
      case fortuneToolbarScreenshotCommand:
        _showScreenshotDialog();
        break;
      case fortuneToolbarSearchCommand:
        _showSearchDialog();
        break;
    }
  }

  void _applyToolbarNumberFormatCommand(String command) {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final focusCoord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final focusCell = sheet.cells[focusCoord] ?? const FortuneCell();
    final format = _toolbarNumberFormatForCommand(command, focusCell);
    if (format == null) {
      setState(_closeTransientMenus);
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final updates = <FortuneCellCoord, FortuneCell>{};
    for (final coord in targets) {
      final previous = sheet.cells[coord] ?? const FortuneCell();
      final previousType = previous.cellType ?? const FortuneCellType();
      final rawValue = previous.hasRawValue
          ? previous.rawValue
          : previous.value;
      final displayValue = update(format, rawValue);
      updates[coord] = previous.copyWith(
        cellType: previousType.copyWith(type: 'n', format: format),
        displayValue: displayValue,
        rawDisplayValue: cloneFortuneMetadata(displayValue),
        hasRawDisplayValue: true,
      );
    }
    final hasChanges = updates.entries.any(
      (entry) => _cellWouldChange(sheet, entry.key, entry.value),
    );
    if (hasChanges) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChanges) {
        for (final entry in updates.entries) {
          if (_cellWouldChange(sheet, entry.key, entry.value)) {
            _setSheetCell(sheet, entry.key, entry.value);
          }
        }
      }
      _closeTransientMenus();
    });
  }

  String? _toolbarNumberFormatForCommand(
    String command,
    FortuneCell focusCell,
  ) {
    return switch (command) {
      fortuneToolbarCurrencyFormatCommand =>
        '${_workbook.settings.currency} #.00',
      fortuneToolbarPercentageFormatCommand => '0.00%',
      fortuneToolbarNumberDecreaseCommand => _decreasedNumberFormat(focusCell),
      fortuneToolbarNumberIncreaseCommand => _increasedNumberFormat(focusCell),
      _ => null,
    };
  }

  String? _decreasedNumberFormat(FortuneCell focusCell) {
    final cellType = focusCell.cellType;
    if (cellType?.type != 'n') {
      return null;
    }
    final format = cellType?.format ?? 'General';
    if (format == 'General' || !format.contains('.')) {
      return null;
    }
    final dotIndex = format.indexOf('.');
    final prefix = format.substring(0, dotIndex);
    final main = format.substring(dotIndex + 1);
    final tail = _toolbarFormatTail(main);
    final suffix = tail.isEmpty
        ? main
        : main.substring(0, main.length - tail.length);
    final decimalPlaces = suffix.replaceAll('#', '0');
    final reduced = decimalPlaces.substring(0, decimalPlaces.length - 1);
    return reduced.isEmpty ? '$prefix$tail' : '$prefix.$reduced$tail';
  }

  String? _increasedNumberFormat(FortuneCell focusCell) {
    final cellType = focusCell.cellType;
    if (cellType?.type != 'n') {
      return null;
    }
    final format = cellType?.format ?? 'General';
    if (format == 'General') {
      return focusCell.value.isEmpty ? null : '#.0';
    }
    if (format.contains('.')) {
      final dotIndex = format.indexOf('.');
      final prefix = format.substring(0, dotIndex);
      final main = format.substring(dotIndex + 1);
      final tail = _toolbarFormatTail(main);
      final suffix = tail.isEmpty
          ? main
          : main.substring(0, main.length - tail.length);
      return '$prefix.${suffix.replaceAll('#', '0')}0$tail';
    }
    final tail = _toolbarFormatTail(format);
    final main = tail.isEmpty
        ? format
        : format.substring(0, format.length - tail.length);
    return '$main.0$tail';
  }

  String _toolbarFormatTail(String formatPart) {
    var tail = '';
    for (var index = formatPart.length - 1; index >= 0; index -= 1) {
      final char = formatPart[index];
      final isFormatChar =
          char == '#' ||
          char == '0' ||
          char == ',' ||
          int.tryParse(char) != null;
      if (isFormatChar) {
        break;
      }
      tail = '$char$tail';
    }
    return tail;
  }

  void _showScreenshotDialog() {
    final sheet = _workbook.activeSheet;
    final ranges = _rawSelectionRanges(sheet);
    if (ranges.length > 1) {
      _showLocationMessageDialog(widget.locale.screenshotTipHasMulti);
      return;
    }
    final range = ranges.isEmpty
        ? _currentSelectionRange(sheet)
        : ranges.single;
    if (_rangeHasPartialMerge(sheet, range)) {
      _showLocationMessageDialog(widget.locale.screenshotTipHasMerge);
      return;
    }
    setState(() {
      _closeTransientMenus();
      _screenshotDialogOpen = true;
      _screenshotRange = range;
      _clearScreenshotCapture();
    });
    unawaited(_updateScreenshotImageDataUrl(range));
  }

  Future<void> _updateScreenshotImageDataUrl(FortuneRange range) async {
    final capture = await _generateScreenshotCapture(range);
    if (!mounted || !_screenshotDialogOpen || _screenshotRange != range) {
      capture?.image.dispose();
      return;
    }
    setState(() {
      _clearScreenshotCapture();
      _screenshotImageDataUrl = capture?.dataUrl;
      _screenshotImage = capture?.image;
    });
  }

  Future<_FortuneScreenshotCapture?> _generateScreenshotCapture(
    FortuneRange range,
    {
    double? pixelRatio,
    bool includeGridLines = true,
    bool includeCellBorders = true,
    bool includeRulerGuides = false,
    bool includeLabelAreaBoundary = true,
  }
  ) async {
    final sheet = _workbook.activeSheet;
    final settings = _workbook.settings;
    final metrics = sheet.metrics(settings);
    final borderCompute = FortuneBorderCompute.compute(sheet);
    final conditionStyles = _screenshotConditionStyles(sheet);
    double rowTop(int row) => row <= 0 ? 0 : metrics.visibleDataRows[row - 1];
    double rowBottom(int row) => metrics.visibleDataRows[row];
    double columnLeft(int column) =>
        column <= 0 ? 0 : metrics.visibleDataColumns[column - 1];
    double columnRight(int column) => metrics.visibleDataColumns[column];

    final originX = columnLeft(range.columnStart);
    final originY = rowTop(range.rowStart);
    final captureWidth = math.max(1.0, columnRight(range.columnEnd) - originX);
    final captureHeight = math.max(1.0, rowBottom(range.rowEnd) - originY);
    final devicePixelRatio =
      pixelRatio ??
      (settings.devicePixelRatio > 0
      ? settings.devicePixelRatio
      : View.of(context).devicePixelRatio);
    final bounds = Rect.fromLTWH(0, 0, captureWidth, captureHeight);
    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);
    canvas.scale(devicePixelRatio);
    canvas.drawRect(bounds, Paint()..color = const Color(0xffffffff));

    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      if (sheet.hiddenRows.contains(row)) {
        continue;
      }
      final top = rowTop(row) - originY;
      final bottom = rowBottom(row) - originY;
      if (bottom <= top) {
        continue;
      }
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (sheet.hiddenColumns.contains(column)) {
          continue;
        }
        final coord = FortuneCellCoord(row, column);
        final anchor = sheet.mergeAnchorFor(coord);
        if (anchor != coord) {
          continue;
        }
        final cell = sheet.cells[anchor];
        final merge = cell?.merge;
        final rectRowEnd = merge == null
            ? row
            : math.min(range.rowEnd, merge.row + merge.rowSpan - 1);
        final rectColumnEnd = merge == null
            ? column
            : math.min(range.columnEnd, merge.column + merge.columnSpan - 1);
        final left = columnLeft(column) - originX;
        final right = columnRight(rectColumnEnd) - originX;
        if (right <= left) {
          continue;
        }
        final rect = Rect.fromLTRB(
          left,
          top,
          right,
          rowBottom(rectRowEnd) - originY,
        );
        final conditionStyle = conditionStyles[anchor];
        final background = conditionStyle?.cellColor ?? cell?.background;
        if (background != null) {
          canvas.drawRect(rect, Paint()..color = background);
        }
        if (conditionStyle?.dataBar case final dataBar?) {
          _drawScreenshotConditionDataBar(canvas, rect, dataBar);
        }
        if (cell?.sparkline != null) {
          _drawScreenshotCellSparkline(canvas, rect, cell!);
        }
        final dataVerification = _screenshotDataVerificationForCoord(
          sheet,
          anchor,
        );
        if (_screenshotDataVerificationFails(
          sheet,
          anchor,
          cell,
          dataVerification,
        )) {
          _drawScreenshotDataVerificationFailureIndicator(canvas, rect);
        }
        if (cell?.comment != null) {
          _drawScreenshotCommentIndicator(canvas, rect);
        }
        if (_showsScreenshotQuotePrefixIndicator(cell)) {
          _drawScreenshotQuotePrefixIndicator(canvas, rect);
        }
        if (dataVerification != null &&
            dataVerification['type'] != 'checkbox') {
          _drawScreenshotDataVerificationMarker(canvas, rect);
        }
        if (includeGridLines && sheet.showGridLines) {
          canvas.drawRect(
            rect,
            Paint()
              ..style = PaintingStyle.stroke
              ..strokeWidth = 1
              ..color = const Color(0xffdfdfdf),
          );
        }
        final borders = borderCompute[anchor];
        if (includeCellBorders && borders != null) {
          _drawScreenshotCellBorders(canvas, rect, borders);
        }
      }
    }

    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      if (sheet.hiddenRows.contains(row)) {
        continue;
      }
      final top = rowTop(row) - originY;
      final bottom = rowBottom(row) - originY;
      if (bottom <= top) {
        continue;
      }
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (sheet.hiddenColumns.contains(column)) {
          continue;
        }
        final coord = FortuneCellCoord(row, column);
        final anchor = sheet.mergeAnchorFor(coord);
        if (anchor != coord) {
          continue;
        }
        final cell = sheet.cells[anchor];
        final merge = cell?.merge;
        final rectRowEnd = merge == null
            ? row
            : math.min(range.rowEnd, merge.row + merge.rowSpan - 1);
        final rectColumnEnd = merge == null
            ? column
            : math.min(range.columnEnd, merge.column + merge.columnSpan - 1);
        final left = columnLeft(column) - originX;
        final right = columnRight(rectColumnEnd) - originX;
        if (right <= left) {
          continue;
        }
        final rect = Rect.fromLTRB(
          left,
          top,
          right,
          rowBottom(rectRowEnd) - originY,
        );
        final dataVerification = _screenshotDataVerificationForCoord(
          sheet,
          anchor,
        );
        if (dataVerification != null &&
            dataVerification['type'] == 'checkbox') {
          _drawScreenshotDataVerificationCheckbox(
            canvas,
            rect,
            cell,
            dataVerification,
          );
          continue;
        }
        final renderCell = _screenshotCellWithDynamicArrayComputeText(
          sheet,
          anchor,
          cell,
        );
        final text = renderCell?.renderedText ?? '';
        if (text.isEmpty) {
          continue;
        }
        final conditionStyle = conditionStyles[anchor];
        if (conditionStyle?.icon case final icon?) {
          _drawScreenshotConditionIcon(canvas, rect, icon);
        }
        final baseTextRect = _screenshotCellTextRect(
          sheet: sheet,
          metrics: metrics,
          settings: settings,
          row: anchor.row,
          column: anchor.column,
          cell: renderCell!,
          cellRect: rect,
          originX: originX,
        );
        final textRect = conditionStyle?.icon == null
            ? baseTextRect
            : Rect.fromLTRB(
                math.min(baseTextRect.left + 14, baseTextRect.right),
                baseTextRect.top,
                baseTextRect.right,
                baseTextRect.bottom,
              );
        _drawScreenshotCellText(
          canvas,
          textRect.deflate(2),
          renderCell,
          fontSize: renderCell.fontSize ?? settings.defaultFontSize,
          textColor: conditionStyle?.textColor,
        );
      }
    }

    _drawScreenshotImages(canvas, bounds, originX: originX, originY: originY);
    _drawScreenshotRawShapeOverlays(
      canvas,
      bounds,
      originX: originX,
      originY: originY,
    );

    if (includeRulerGuides) {
      _drawScreenshotRulerGuides(canvas, bounds, metrics, originX, originY);
    }

    if (includeLabelAreaBoundary) {
      final borderPaint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 2
        ..color = const Color(0xffdfdfdf);
      canvas.drawLine(bounds.topLeft, bounds.bottomLeft, borderPaint);
      canvas.drawLine(bounds.topLeft, bounds.topRight, borderPaint);
    }

    final picture = recorder.endRecording();
    final image = await picture.toImage(
      (captureWidth * devicePixelRatio).ceil(),
      (captureHeight * devicePixelRatio).ceil(),
    );
    picture.dispose();
    final bytes = await image.toByteData(format: ui.ImageByteFormat.png);
    if (bytes == null) {
      image.dispose();
      return null;
    }
    final pngBytes = bytes.buffer.asUint8List();
    return _FortuneScreenshotCapture(
      dataUrl: 'data:image/png;base64,${base64Encode(pngBytes)}',
      image: image,
      pngBytes: Uint8List.fromList(pngBytes),
      logicalSize: Size(captureWidth, captureHeight),
      pixelSize: Size(
        (captureWidth * devicePixelRatio).ceilToDouble(),
        (captureHeight * devicePixelRatio).ceilToDouble(),
      ),
    );
  }

  Future<FortuneSheetCapture?> _captureRangeAsPng(
    FortuneRange range, {
    required double pixelRatio,
    required bool includeGridLines,
    required bool includeCellBorders,
    required bool includeRulerGuides,
    required bool includeLabelAreaBoundary,
  }) async {
    final capture = await _generateScreenshotCapture(
      range,
      pixelRatio: math.max(0.01, pixelRatio),
      includeGridLines: includeGridLines,
      includeCellBorders: includeCellBorders,
      includeRulerGuides: includeRulerGuides,
      includeLabelAreaBoundary: includeLabelAreaBoundary,
    );
    if (capture == null) {
      return null;
    }
    capture.image.dispose();
    return FortuneSheetCapture(
      pngBytes: capture.pngBytes,
      logicalSize: capture.logicalSize,
      pixelSize: capture.pixelSize,
    );
  }

  TextStyle _screenshotTextStyle(
    FortuneCell cell, {
    required double fontSize,
    Color? textColor,
  }) {
    final color = _screenshotCellTextColor(cell, textColor: textColor);
    return TextStyle(
      color: color,
      fontSize: fontSize,
      fontFamily: _resolvedCellFontFamily(cell),
      fontWeight: cell.bold ? FontWeight.w700 : FontWeight.w400,
      fontStyle: cell.italic ? FontStyle.italic : FontStyle.normal,
      decoration: _screenshotTextDecoration(cell),
      decorationColor: color,
    );
  }

  Color _screenshotCellTextColor(FortuneCell cell, {Color? textColor}) {
    if (_screenshotIsRedNegativeNumberFormat(cell)) {
      return const Color(0xffff0000);
    }
    if (textColor != null) {
      return textColor;
    }
    if (cell.hyperlink != null) {
      return const Color(0xff1155cc);
    }
    return cell.foreground;
  }

  bool _screenshotIsRedNegativeNumberFormat(FortuneCell cell) {
    final cellType = cell.cellType;
    if (cellType?.type != 'n' || !(cellType?.format ?? '').contains('[Red]')) {
      return false;
    }
    final numberValue =
        _screenshotNumberValue(cell.value) ??
        _screenshotNumberValue(cell.renderedText);
    return numberValue != null && numberValue < 0;
  }

  void _drawScreenshotCellSparkline(
    Canvas canvas,
    Rect rect,
    FortuneCell cell,
  ) {
    final type = fortuneSparklineType(cell.sparkline);
    if (type == 'compose' ||
        type == 'composespline' ||
        type == 'composesplines') {
      for (final child in fortuneSparklineChildren(cell.sparkline)) {
        _drawScreenshotCellSparkline(
          canvas,
          rect,
          FortuneCell(sparkline: child),
        );
      }
      return;
    }
    final values = fortuneSparklineValues(cell.sparkline);
    if (values.isEmpty) {
      return;
    }
    final sparklineColor = fortuneSparklineColor(cell.sparkline);
    final negativeColor = fortuneSparklineNegativeColor(cell.sparkline);
    final zeroColor = fortuneSparklineZeroColor(cell.sparkline);
    final sparklineLineWidth = fortuneSparklineLineWidth(cell.sparkline);
    final normalRangeValue = fortuneSparklineNormalRangeValue(
      cell.sparkline,
      values,
    );
    final normalRangeColor = fortuneSparklineNormalRangeColor(cell.sparkline);
    final maxSpotColor = fortuneSparklineMaxSpotColor(cell.sparkline);
    final minSpotColor = fortuneSparklineMinSpotColor(cell.sparkline);
    final thresholdValue = fortuneSparklineThresholdValue(cell.sparkline);
    final pieOffset = fortuneSparklinePieOffset(cell.sparkline);
    final pieBorderWidth = fortuneSparklinePieBorderWidth(cell.sparkline);
    final pieBorderColor = fortuneSparklinePieBorderColor(cell.sparkline);
    final sliceColors = fortuneSparklineSliceColors(cell.sparkline);
    final targetValue = fortuneSparklineTargetValue(cell.sparkline);
    final outlierIqr = fortuneSparklineOutlierIqr(cell.sparkline);
    final spotRadius = fortuneSparklineSpotRadius(cell.sparkline);
    final barSpacing = fortuneSparklineBarSpacing(cell.sparkline);
    final chartRangeMax = fortuneSparklineChartRangeMax(cell.sparkline);
    final colorMap = fortuneSparklineColorMap(cell.sparkline);
    final stackedBarColors = fortuneSparklineStackedBarColors(cell.sparkline);
    final stackGroups = fortuneSparklineStackGroups(cell.sparkline, values);
    final chartRect = rect.deflate(4);
    if (chartRect.width <= 0 || chartRect.height <= 0) {
      return;
    }
    if (type == 'pie' || type == 'piespline' || type == 'piesplines') {
      _drawScreenshotSparklinePie(
        canvas,
        rect,
        chartRect,
        values,
        offsetDegrees: pieOffset,
        borderWidth: pieBorderWidth,
        borderColor: pieBorderColor,
        sliceColors: sliceColors,
      );
      return;
    }
    if (type == 'box' ||
        type == 'boxspline' ||
        type == 'boxsplines' ||
        type == 'boxplot') {
      _drawScreenshotSparklineBox(
        canvas,
        rect,
        chartRect,
        values,
        sparklineColor,
        targetValue: targetValue,
        outlierIqr: outlierIqr,
        spotRadius: spotRadius,
      );
      return;
    }
    if (type == 'bullet' || type == 'bulletspline' || type == 'bulletsplines') {
      _drawScreenshotSparklineBullet(
        canvas,
        rect,
        chartRect,
        values,
        sparklineColor,
      );
      return;
    }
    if (type == 'discrete' ||
        type == 'discretespline' ||
        type == 'discretesplines' ||
        type == 'tristate' ||
        type == 'tristatespline' ||
        type == 'tristatesplines') {
      final useThreshold =
          type == 'discrete' ||
          type == 'discretespline' ||
          type == 'discretesplines';
      _drawScreenshotSparklineDiscrete(
        canvas,
        rect,
        chartRect,
        values,
        sparklineColor,
        negativeColor,
        zeroColor: zeroColor,
        thresholdValue: useThreshold ? thresholdValue : 0,
        useThreshold: useThreshold,
      );
      return;
    }
    canvas.save();
    canvas.clipRect(rect, doAntiAlias: false);
    if (type == 'stackcolumn' ||
        type == 'stackcolumnspline' ||
        type == 'stackcolumnsplines') {
      _drawScreenshotSparklineStackColumns(
        canvas,
        chartRect,
        values,
        sparklineColor,
        stackGroups: stackGroups,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        stackedBarColors: stackedBarColors,
      );
      canvas.restore();
      return;
    }
    if (type == 'stackbar' ||
        type == 'stackbarspline' ||
        type == 'stackbarsplines') {
      _drawScreenshotSparklineStackBars(
        canvas,
        chartRect,
        values,
        sparklineColor,
        stackGroups: stackGroups,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        stackedBarColors: stackedBarColors,
      );
      canvas.restore();
      return;
    }
    if (type == 'column' || type == 'columnspline' || type == 'columnsplines') {
      _drawScreenshotSparklineColumns(
        canvas,
        chartRect,
        values,
        sparklineColor,
        negativeColor,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        colorMap: colorMap,
      );
      canvas.restore();
      return;
    }
    if (type == 'bar' || type == 'barspline' || type == 'barsplines') {
      _drawScreenshotSparklineBars(
        canvas,
        chartRect,
        values,
        sparklineColor,
        negativeColor,
        barSpacing: barSpacing,
        chartRangeMax: chartRangeMax,
        colorMap: colorMap,
      );
      canvas.restore();
      return;
    }
    if (values.length < 2) {
      canvas.restore();
      return;
    }
    final points = fortuneSparklinePoints(values, chartRect);
    if (points.isEmpty) {
      canvas.restore();
      return;
    }
    final path = Path();
    for (var index = 0; index < points.length; index += 1) {
      final point = points[index];
      if (index == 0) {
        path.moveTo(point.dx, point.dy);
      } else {
        path.lineTo(point.dx, point.dy);
      }
    }
    if (type == 'area' || type == 'areaspline' || type == 'areasplines') {
      final areaOpacity = fortuneSparklineAreaOpacity(cell.sparkline);
      final areaColor = fortuneSparklineAreaColor(
        cell.sparkline,
        sparklineColor,
      );
      final areaPath = Path.from(path)
        ..lineTo(points.last.dx, chartRect.bottom)
        ..lineTo(points.first.dx, chartRect.bottom)
        ..close();
      canvas.drawPath(
        areaPath,
        Paint()..color = areaColor.withValues(alpha: areaColor.a * areaOpacity),
      );
    } else if (type != 'line' &&
        type != 'linespline' &&
        type != 'linesplines') {
      canvas.restore();
      return;
    }
    canvas.drawPath(
      path,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = sparklineLineWidth
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round
        ..color = sparklineColor,
    );
    if (normalRangeValue != null) {
      _drawScreenshotSparklineNormalRange(
        canvas,
        chartRect,
        values,
        normalRangeValue,
        normalRangeColor,
      );
    }
    if (maxSpotColor != null || minSpotColor != null) {
      _drawScreenshotSparklineValueSpots(
        canvas,
        values,
        points,
        maxSpotColor: maxSpotColor,
        minSpotColor: minSpotColor,
        spotRadius: spotRadius,
      );
    }
    canvas.restore();
  }

  void _drawScreenshotSparklineColumns(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color color,
    Color negativeColor, {
    double? barSpacing,
    double? chartRangeMax,
    List<Object?> colorMap = const [],
  }) {
    final maximum =
        chartRangeMax ?? values.map((value) => value.abs()).reduce(math.max);
    if (maximum == 0) {
      return;
    }
    final baseline = rect.center.dy;
    final slotWidth = rect.width / values.length;
    final gap = math.min(
      barSpacing ?? math.min(2.0, rect.width / (values.length * 4)),
      math.max(0.0, slotWidth - 1),
    );
    final barWidth = math.max(1.0, slotWidth - gap);
    for (var index = 0; index < values.length; index += 1) {
      final value = values[index];
      final ratio = (value.abs() / maximum).clamp(0.0, 1.0).toDouble();
      final height = ratio * rect.height / 2;
      final left = rect.left + index * slotWidth + gap / 2;
      final top = value >= 0 ? baseline - height : baseline;
      final barColor = fortuneSparklineMappedBarColor(
        colorMap,
        value,
        index,
        value >= 0 ? color : negativeColor,
      );
      canvas.drawRect(
        Rect.fromLTWH(left, top, barWidth, math.max(1.0, height)),
        Paint()..color = barColor,
      );
    }
  }

  void _drawScreenshotSparklineBars(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color color,
    Color negativeColor, {
    double? barSpacing,
    double? chartRangeMax,
    List<Object?> colorMap = const [],
  }) {
    final maximum =
        chartRangeMax ?? values.map((value) => value.abs()).reduce(math.max);
    if (maximum == 0) {
      return;
    }
    final baseline = rect.center.dx;
    final slotHeight = rect.height / values.length;
    final gap = math.min(
      barSpacing ?? math.min(2.0, rect.height / (values.length * 4)),
      math.max(0.0, slotHeight - 1),
    );
    final barHeight = math.max(1.0, slotHeight - gap);
    for (var index = 0; index < values.length; index += 1) {
      final value = values[index];
      final ratio = (value.abs() / maximum).clamp(0.0, 1.0).toDouble();
      final width = ratio * rect.width / 2;
      final top = rect.top + index * slotHeight + gap / 2;
      final left = value >= 0 ? baseline : baseline - width;
      final barColor = fortuneSparklineMappedBarColor(
        colorMap,
        value,
        index,
        value >= 0 ? color : negativeColor,
      );
      canvas.drawRect(
        Rect.fromLTWH(left, top, math.max(1.0, width), barHeight),
        Paint()..color = barColor,
      );
    }
  }

  void _drawScreenshotSparklineNormalRange(
    Canvas canvas,
    Rect rect,
    List<double> values,
    double value,
    Color color,
  ) {
    final minimum = values.reduce(math.min);
    final maximum = values.reduce(math.max);
    if (maximum == minimum || value < minimum || value > maximum) {
      return;
    }
    final y =
        rect.bottom - ((value - minimum) / (maximum - minimum)) * rect.height;
    canvas.drawLine(
      Offset(rect.left, y),
      Offset(rect.right, y),
      Paint()
        ..strokeWidth = 1
        ..color = color,
    );
  }

  void _drawScreenshotSparklineValueSpots(
    Canvas canvas,
    List<double> values,
    List<Offset> points, {
    Color? maxSpotColor,
    Color? minSpotColor,
    double spotRadius = 1.5,
  }) {
    if (values.isEmpty || values.length != points.length) {
      return;
    }
    final maximum = values.reduce(math.max);
    final minimum = values.reduce(math.min);
    if (maxSpotColor != null) {
      final paint = Paint()..color = maxSpotColor;
      for (var index = 0; index < values.length; index += 1) {
        if (values[index] == maximum) {
          canvas.drawCircle(points[index], spotRadius, paint);
        }
      }
    }
    if (minSpotColor != null && minimum != maximum) {
      final paint = Paint()..color = minSpotColor;
      for (var index = 0; index < values.length; index += 1) {
        if (values[index] == minimum) {
          canvas.drawCircle(points[index], spotRadius, paint);
        }
      }
    }
  }

  void _drawScreenshotSparklineStackColumns(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color firstColor, {
    List<List<double>>? stackGroups,
    double? barSpacing,
    double? chartRangeMax,
    List<Color> stackedBarColors = const [],
  }) {
    final groups = (stackGroups ?? [values])
        .map(
          (group) => [
            for (final value in group)
              if (value != 0) value.abs(),
          ],
        )
        .where((group) => group.isNotEmpty)
        .toList();
    if (groups.isEmpty) {
      return;
    }
    final totals = [
      for (final group in groups)
        group.fold<double>(0, (sum, value) => sum + value),
    ];
    final maximum = chartRangeMax ?? totals.reduce(math.max);
    if (maximum <= 0) {
      return;
    }
    final gap = groups.length <= 1
        ? 0.0
        : math.min(
            barSpacing ?? math.min(2.0, rect.width / (groups.length * 4)),
            math.max(0.0, rect.width / groups.length - 1),
          );
    final stackWidth = groups.length <= 1
        ? rect.width
        : math.max(
            1.0,
            (rect.width - gap * (groups.length - 1)) / groups.length,
          );
    const colors = [
      Color(0xffffb300),
      Color(0xff34a853),
      Color(0xffea4335),
      Color(0xff7e57c2),
    ];
    for (var groupIndex = 0; groupIndex < groups.length; groupIndex += 1) {
      final group = groups[groupIndex];
      final left = rect.left + groupIndex * (stackWidth + gap);
      final right = math.min(rect.right, left + stackWidth);
      var bottom = rect.bottom;
      var remainingHeight = rect.height;
      for (var index = 0; index < group.length; index += 1) {
        final height = math.min(
          group[index] / maximum * rect.height,
          remainingHeight,
        );
        final segmentColor = index < stackedBarColors.length
            ? stackedBarColors[index]
            : index == 0
            ? firstColor
            : colors[(index - 1) % colors.length];
        canvas.drawRect(
          Rect.fromLTRB(left, bottom - height, right, bottom),
          Paint()..color = segmentColor,
        );
        bottom -= height;
        remainingHeight -= height;
        if (remainingHeight <= 0) {
          break;
        }
      }
    }
  }

  void _drawScreenshotSparklineStackBars(
    Canvas canvas,
    Rect rect,
    List<double> values,
    Color firstColor, {
    List<List<double>>? stackGroups,
    double? barSpacing,
    double? chartRangeMax,
    List<Color> stackedBarColors = const [],
  }) {
    final groups = (stackGroups ?? [values])
        .map(
          (group) => [
            for (final value in group)
              if (value != 0) value.abs(),
          ],
        )
        .where((group) => group.isNotEmpty)
        .toList();
    if (groups.isEmpty) {
      return;
    }
    final totals = [
      for (final group in groups)
        group.fold<double>(0, (sum, value) => sum + value),
    ];
    final maximum = chartRangeMax ?? totals.reduce(math.max);
    if (maximum <= 0) {
      return;
    }
    final gap = groups.length <= 1
        ? 0.0
        : math.min(
            barSpacing ?? math.min(2.0, rect.height / (groups.length * 4)),
            math.max(0.0, rect.height / groups.length - 1),
          );
    final stackHeight = groups.length <= 1
        ? rect.height
        : math.max(
            1.0,
            (rect.height - gap * (groups.length - 1)) / groups.length,
          );
    const colors = [
      Color(0xffffb300),
      Color(0xff34a853),
      Color(0xffea4335),
      Color(0xff7e57c2),
    ];
    for (var groupIndex = 0; groupIndex < groups.length; groupIndex += 1) {
      final group = groups[groupIndex];
      final top = rect.top + groupIndex * (stackHeight + gap);
      final bottom = math.min(rect.bottom, top + stackHeight);
      var left = rect.left;
      var remainingWidth = rect.width;
      for (var index = 0; index < group.length; index += 1) {
        final width = math.min(
          group[index] / maximum * rect.width,
          remainingWidth,
        );
        final segmentColor = index < stackedBarColors.length
            ? stackedBarColors[index]
            : index == 0
            ? firstColor
            : colors[(index - 1) % colors.length];
        canvas.drawRect(
          Rect.fromLTRB(left, top, left + width, bottom),
          Paint()..color = segmentColor,
        );
        left += width;
        remainingWidth -= width;
        if (remainingWidth <= 0) {
          break;
        }
      }
    }
  }

  void _drawScreenshotSparklinePie(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values, {
    double offsetDegrees = 0,
    double borderWidth = 1,
    Color borderColor = const Color(0xff5f6368),
    List<Color> sliceColors = const [],
  }) {
    final positiveValues = [
      for (final value in values)
        if (value > 0) value,
    ];
    if (positiveValues.isEmpty) {
      return;
    }
    final total = positiveValues.fold<double>(0, (sum, value) => sum + value);
    if (total <= 0) {
      return;
    }
    final side = math.min(rect.width, rect.height);
    final pieRect = Rect.fromCenter(
      center: rect.center,
      width: side,
      height: side,
    );
    const colors = [
      Color(0xff0188fb),
      Color(0xffffb300),
      Color(0xff34a853),
      Color(0xffea4335),
      Color(0xff7e57c2),
    ];
    final palette = sliceColors.isEmpty ? colors : sliceColors;
    var start = -math.pi / 2 + offsetDegrees * math.pi / 180;
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    for (var index = 0; index < positiveValues.length; index += 1) {
      final sweep = positiveValues[index] / total * math.pi * 2;
      canvas.drawArc(
        pieRect,
        start,
        sweep,
        true,
        Paint()..color = palette[index % palette.length],
      );
      start += sweep;
    }
    if (borderWidth > 0) {
      canvas.drawOval(
        pieRect,
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = borderWidth
          ..color = borderColor,
      );
    }
    canvas.restore();
  }

  void _drawScreenshotSparklineBox(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values,
    Color color, {
    double? targetValue,
    double? outlierIqr,
    double spotRadius = 1.5,
  }) {
    if (values.length < 2) {
      return;
    }
    final sorted = [...values]..sort();
    final minimum = sorted.first;
    final maximum = sorted.last;
    if (minimum == maximum) {
      return;
    }
    double percentile(double position) {
      final lower = position.floor();
      final upper = position.ceil();
      if (lower == upper) {
        return sorted[lower];
      }
      final weight = position - lower;
      return sorted[lower] + (sorted[upper] - sorted[lower]) * weight;
    }

    final q1 = percentile((sorted.length - 1) * 0.25);
    final median = percentile((sorted.length - 1) * 0.5);
    final q3 = percentile((sorted.length - 1) * 0.75);
    final iqr = q3 - q1;
    final lowerFence = outlierIqr == null ? null : q1 - iqr * outlierIqr;
    final upperFence = outlierIqr == null ? null : q3 + iqr * outlierIqr;
    final inlierValues = lowerFence == null || upperFence == null
        ? sorted
        : sorted
              .where((value) => value >= lowerFence && value <= upperFence)
              .toList();
    final whiskerMinimum = inlierValues.isEmpty ? minimum : inlierValues.first;
    final whiskerMaximum = inlierValues.isEmpty ? maximum : inlierValues.last;
    double xFor(double value) {
      return rect.left + (value - minimum) / (maximum - minimum) * rect.width;
    }

    final centerY = rect.center.dy;
    final boxTop = rect.top + rect.height * 0.22;
    final boxBottom = rect.bottom - rect.height * 0.22;
    final whiskerTop = rect.top + rect.height * 0.32;
    final whiskerBottom = rect.bottom - rect.height * 0.32;
    final outline = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.2
      ..color = const Color(0xff5f6368);
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    canvas.drawLine(
      Offset(xFor(whiskerMinimum), centerY),
      Offset(xFor(q1), centerY),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(q3), centerY),
      Offset(xFor(whiskerMaximum), centerY),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(whiskerMinimum), whiskerTop),
      Offset(xFor(whiskerMinimum), whiskerBottom),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(whiskerMaximum), whiskerTop),
      Offset(xFor(whiskerMaximum), whiskerBottom),
      outline,
    );
    canvas.drawRect(
      Rect.fromLTRB(xFor(q1), boxTop, xFor(q3), boxBottom),
      Paint()..color = color.withValues(alpha: color.a * 0.13),
    );
    canvas.drawRect(
      Rect.fromLTRB(xFor(q1), boxTop, xFor(q3), boxBottom),
      outline,
    );
    canvas.drawLine(
      Offset(xFor(median), boxTop),
      Offset(xFor(median), boxBottom),
      Paint()
        ..strokeWidth = 1.5
        ..color = color,
    );
    if (targetValue != null &&
        targetValue >= minimum &&
        targetValue <= maximum) {
      canvas.drawCircle(
        Offset(xFor(targetValue), centerY),
        spotRadius,
        Paint()..color = color,
      );
    }
    if (lowerFence != null && upperFence != null) {
      final outlierPaint = Paint()..color = color;
      for (final value in sorted) {
        if (value < lowerFence || value > upperFence) {
          canvas.drawCircle(
            Offset(xFor(value), centerY),
            spotRadius,
            outlierPaint,
          );
        }
      }
    }
    canvas.restore();
  }

  void _drawScreenshotSparklineBullet(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values,
    Color color,
  ) {
    if (values.length < 2) {
      return;
    }
    final target = values[0].abs();
    final achieved = values[1].abs();
    final comparisons = [
      for (var index = 2; index < values.length; index += 1)
        values[index].abs(),
    ]..sort();
    final maximum = [
      ...comparisons,
      target,
      achieved,
    ].fold<double>(0, math.max);
    if (maximum <= 0) {
      return;
    }
    final track = Rect.fromLTWH(
      rect.left,
      rect.top + rect.height * 0.25,
      rect.width,
      rect.height * 0.5,
    );
    double widthFor(double value) =>
        (value / maximum).clamp(0.0, 1.0) * track.width;

    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    canvas.drawRect(track, Paint()..color = const Color(0xffe8eaed));
    const comparisonColors = [
      Color(0xffdadce0),
      Color(0xffcfd4da),
      Color(0xffbdc1c6),
    ];
    for (var index = comparisons.length - 1; index >= 0; index -= 1) {
      canvas.drawRect(
        Rect.fromLTWH(
          track.left,
          track.top,
          widthFor(comparisons[index]),
          track.height,
        ),
        Paint()..color = comparisonColors[index % comparisonColors.length],
      );
    }
    canvas.drawRect(
      Rect.fromLTWH(
        track.left,
        track.top + track.height * 0.32,
        widthFor(achieved),
        track.height * 0.36,
      ),
      Paint()..color = color,
    );
    final targetX = track.left + widthFor(target);
    canvas.drawLine(
      Offset(targetX, track.top - 2),
      Offset(targetX, track.bottom + 2),
      Paint()
        ..strokeWidth = 1.5
        ..color = const Color(0xffea4335),
    );
    canvas.restore();
  }

  void _drawScreenshotSparklineDiscrete(
    Canvas canvas,
    Rect clip,
    Rect rect,
    List<double> values,
    Color positiveColor,
    Color negativeColor, {
    Color zeroColor = const Color(0xff9aa0a6),
    double thresholdValue = 0,
    bool useThreshold = false,
  }) {
    if (values.isEmpty) {
      return;
    }
    final baseline = rect.center.dy;
    final gap = math.min(2.0, rect.width / (values.length * 4));
    final barWidth = math.max(1.0, rect.width / values.length - gap);
    final positiveHeight = math.max(1.0, baseline - rect.top);
    final negativeHeight = math.max(1.0, rect.bottom - baseline);
    canvas.save();
    canvas.clipRect(clip, doAntiAlias: false);
    for (var index = 0; index < values.length; index += 1) {
      final value = values[index];
      final state = useThreshold
          ? value.compareTo(thresholdValue)
          : value.compareTo(0);
      final left = rect.left + index * rect.width / values.length + gap / 2;
      final top = state > 0
          ? baseline - positiveHeight
          : state < 0
          ? baseline
          : baseline - 0.75;
      final height = state == 0
          ? 1.5
          : state > 0
          ? positiveHeight
          : negativeHeight;
      final color = state > 0
          ? positiveColor
          : state < 0
          ? negativeColor
          : zeroColor;
      canvas.drawRect(
        Rect.fromLTWH(left, top, barWidth, height),
        Paint()..color = color,
      );
    }
    canvas.restore();
  }

  void _drawScreenshotCellText(
    Canvas canvas,
    Rect rect,
    FortuneCell cell, {
    required double fontSize,
    Color? textColor,
  }) {
    if (cell.isVerticalText) {
      _drawScreenshotVerticalCellText(
        canvas,
        rect,
        cell,
        fontSize: fontSize,
        textColor: textColor,
      );
      return;
    }
    final maxLines = cell.normalizedTextWrap == '2' ? null : 1;
    TextAlign textAlign = TextAlign.left;
    if (maxLines == null) {
      switch (cell.normalizedHorizontalAlign) {
        case '0':
          textAlign = TextAlign.center;
        case '2':
          textAlign = TextAlign.right;
        case '3':
          textAlign = TextAlign.justify;
      }
    }
    final textPainter =
        TextPainter(
          text: _screenshotCellTextSpan(
            cell,
            fontSize: fontSize,
            textColor: textColor,
          ),
          maxLines: maxLines,
          textAlign: textAlign,
          textDirection: TextDirection.ltr,
          ellipsis: cell.normalizedTextWrap == '2' ? null : '',
        )..layout(
          maxWidth: maxLines == null
              ? math.max(0.0, rect.width)
              : double.infinity,
        );
    final dx = maxLines == null
        ? rect.left
        : _screenshotTextLeft(
            cell,
            rect,
            math.min(textPainter.width, rect.width),
          );
    final dy = _screenshotTextTop(cell, rect, textPainter.height);
    final rotation = cell.normalizedTextRotation;
    canvas.save();
    canvas.clipRect(rect, doAntiAlias: false);
    if (rotation != 0) {
      final pivot = rect.center;
      canvas.translate(pivot.dx, pivot.dy);
      canvas.rotate(-rotation * math.pi / 180);
      canvas.translate(-pivot.dx, -pivot.dy);
    }
    textPainter.paint(canvas, Offset(dx, dy));
    canvas.restore();
  }

  TextSpan _screenshotCellTextSpan(
    FortuneCell cell, {
    required double fontSize,
    Color? textColor,
  }) {
    final baseStyle = _screenshotTextStyle(
      cell,
      fontSize: fontSize,
      textColor: textColor,
    );
    final runs = cell.inlineRuns;
    if (runs == null || runs.isEmpty) {
      return TextSpan(text: cell.renderedText, style: baseStyle);
    }
    final overrideRunColor =
        textColor != null || _screenshotIsRedNegativeNumberFormat(cell);
    return TextSpan(
      style: baseStyle,
      children: runs.map((run) {
        final color = overrideRunColor
            ? baseStyle.color ?? cell.foreground
            : run.foreground ?? cell.foreground;
        return TextSpan(
          text: run.text,
          style: baseStyle.copyWith(
            color: color,
            backgroundColor: _screenshotInlineRunBackgroundColor(run),
            fontSize: run.fontSize ?? fontSize,
            fontFamily: _resolvedRunFontFamily(run.fontFamily, cell),
            fontWeight: (run.bold ?? cell.bold)
                ? FontWeight.w700
                : FontWeight.w400,
            fontStyle: (run.italic ?? cell.italic)
                ? FontStyle.italic
                : FontStyle.normal,
            decoration: _screenshotInlineTextDecoration(run, cell),
            decorationColor: color,
          ),
        );
      }).toList(),
    );
  }

  void _drawScreenshotVerticalCellText(
    Canvas canvas,
    Rect rect,
    FortuneCell cell, {
    required double fontSize,
    Color? textColor,
  }) {
    final color = _screenshotCellTextColor(cell, textColor: textColor);
    final style = TextStyle(
      color: color,
      fontSize: fontSize,
      fontFamily: _resolvedCellFontFamily(cell),
      fontWeight: cell.bold ? FontWeight.w700 : FontWeight.w400,
      fontStyle: cell.italic ? FontStyle.italic : FontStyle.normal,
      decoration: _screenshotTextDecoration(cell),
      decorationColor: color,
    );
    final spans = _screenshotVerticalTextSpans(
      cell,
      fallbackStyle: style,
      forceBaseColor:
          textColor != null || _screenshotIsRedNegativeNumberFormat(cell),
    );
    final painters = spans.map((span) {
      return TextPainter(
        text: span,
        textDirection: TextDirection.ltr,
        textAlign: TextAlign.center,
        maxLines: 1,
      )..layout(maxWidth: math.max(0.0, rect.width));
    }).toList();
    if (painters.isEmpty) {
      return;
    }
    final totalHeight = painters.fold<double>(
      0,
      (sum, painter) => sum + painter.height,
    );
    var y = _screenshotTextTop(cell, rect, totalHeight);
    canvas.save();
    canvas.clipRect(rect, doAntiAlias: false);
    for (final painter in painters) {
      final x = _screenshotTextLeft(
        cell,
        rect,
        math.min(painter.width, rect.width),
      );
      painter.paint(canvas, Offset(x, y));
      y += painter.height;
    }
    canvas.restore();
  }

  List<TextSpan> _screenshotVerticalTextSpans(
    FortuneCell cell, {
    required TextStyle fallbackStyle,
    bool forceBaseColor = false,
  }) {
    final runs = cell.inlineRuns;
    if (runs == null || runs.isEmpty) {
      return cell.renderedText.runes
          .map(
            (rune) =>
                TextSpan(text: String.fromCharCode(rune), style: fallbackStyle),
          )
          .toList();
    }
    final spans = <TextSpan>[];
    for (final run in runs) {
      final color = forceBaseColor
          ? fallbackStyle.color ?? cell.foreground
          : run.foreground ?? cell.foreground;
      final style = fallbackStyle.copyWith(
        color: color,
        backgroundColor: _screenshotInlineRunBackgroundColor(run),
        fontSize: run.fontSize ?? fallbackStyle.fontSize,
        fontFamily: _resolvedRunFontFamily(run.fontFamily, cell),
        fontWeight: (run.bold ?? cell.bold) ? FontWeight.w700 : FontWeight.w400,
        fontStyle: (run.italic ?? cell.italic)
            ? FontStyle.italic
            : FontStyle.normal,
        decoration: _screenshotInlineTextDecoration(run, cell),
        decorationColor: color,
      );
      spans.addAll(
        run.text.runes.map(
          (rune) => TextSpan(text: String.fromCharCode(rune), style: style),
        ),
      );
    }
    return spans;
  }

  Color? _screenshotInlineRunBackgroundColor(FortuneInlineTextRun run) {
    final raw = run.extraFields['bg'];
    if (raw == null) {
      return null;
    }
    if (raw is Color) {
      return raw;
    }
    return FortuneSheetCodec.parseColor('$raw');
  }

  String _resolvedCellFontFamily(FortuneCell cell) {
    return fortuneResolveFontFamily(
      cell.fontFamily,
      _workbook.settings.fontFamilies,
    );
  }

  String _resolvedRunFontFamily(String? raw, FortuneCell fallback) {
    return fortuneResolveFontFamily(
      raw,
      _workbook.settings.fontFamilies,
      fallback: _resolvedCellFontFamily(fallback),
    );
  }

  TextDecoration _screenshotInlineTextDecoration(
    FortuneInlineTextRun run,
    FortuneCell fallback,
  ) {
    final decorations = [
      if (run.underline ?? fallback.underline) TextDecoration.underline,
      if (run.strikeThrough ?? fallback.strikeThrough)
        TextDecoration.lineThrough,
    ];
    return decorations.isEmpty
        ? TextDecoration.none
        : TextDecoration.combine(decorations);
  }

  Rect _screenshotCellTextRect({
    required FortuneSheet sheet,
    required FortuneSheetMetrics metrics,
    required FortuneSettings settings,
    required int row,
    required int column,
    required FortuneCell cell,
    required Rect cellRect,
    required double originX,
  }) {
    if (cell.normalizedTextWrap != '1' ||
        cell.normalizedTextRotation != 0 ||
        cell.isVerticalText) {
      return cellRect;
    }
    final textWidth = _screenshotMeasureTextWidth(
      cell,
      fontSize: cell.fontSize ?? settings.defaultFontSize,
    );
    if (textWidth <= cellRect.width - 4) {
      return cellRect;
    }

    var startColumn = column;
    var endColumn = column;
    var startX = column <= 0 ? 0.0 : metrics.visibleDataColumns[column - 1];
    var endX = metrics.visibleDataColumns[column];

    bool canUseColumn(int candidate) {
      if (candidate < 0 ||
          candidate >= settings.column ||
          sheet.hiddenColumns.contains(candidate)) {
        return false;
      }
      final other = sheet.cells[FortuneCellCoord(row, candidate)];
      return other == null || other.isVisuallyEmpty;
    }

    double width() => endX - startX;
    final align = cell.normalizedHorizontalAlign;
    if (align == '2') {
      while (width() < textWidth + 4 && canUseColumn(startColumn - 1)) {
        startColumn -= 1;
        startX = startColumn <= 0
            ? 0.0
            : metrics.visibleDataColumns[startColumn - 1];
      }
    } else if (align == '0') {
      var growLeft = true;
      while (width() < textWidth + 4) {
        if (growLeft && canUseColumn(startColumn - 1)) {
          startColumn -= 1;
          startX = startColumn <= 0
              ? 0.0
              : metrics.visibleDataColumns[startColumn - 1];
        } else if (canUseColumn(endColumn + 1)) {
          endColumn += 1;
          endX = metrics.visibleDataColumns[endColumn];
        } else if (!growLeft && canUseColumn(startColumn - 1)) {
          startColumn -= 1;
          startX = startColumn <= 0
              ? 0.0
              : metrics.visibleDataColumns[startColumn - 1];
        } else {
          break;
        }
        growLeft = !growLeft;
      }
    } else {
      while (width() < textWidth + 4 && canUseColumn(endColumn + 1)) {
        endColumn += 1;
        endX = metrics.visibleDataColumns[endColumn];
      }
    }

    return Rect.fromLTWH(
      startX - originX,
      cellRect.top,
      endX - startX,
      cellRect.height,
    );
  }

  double _screenshotMeasureTextWidth(
    FortuneCell cell, {
    required double fontSize,
  }) {
    final painter = TextPainter(
      text: _screenshotCellTextSpan(cell, fontSize: fontSize),
      textDirection: TextDirection.ltr,
      maxLines: 1,
    )..layout();
    return painter.width;
  }

  double _screenshotTextLeft(FortuneCell cell, Rect rect, double textWidth) {
    return switch (cell.normalizedHorizontalAlign) {
      '0' => rect.left + math.max(0, (rect.width - textWidth) / 2),
      '2' => rect.right - textWidth,
      _ => rect.left,
    };
  }

  double _screenshotTextTop(FortuneCell cell, Rect rect, double textHeight) {
    return switch (cell.normalizedVerticalAlign) {
      '1' => rect.top,
      '2' => rect.bottom - textHeight,
      _ => rect.top + math.max(0, (rect.height - textHeight) / 2),
    };
  }

  TextDecoration _screenshotTextDecoration(FortuneCell cell) {
    final decorations = [
      if (cell.underline || cell.hyperlink != null) TextDecoration.underline,
      if (cell.strikeThrough) TextDecoration.lineThrough,
    ];
    return decorations.isEmpty
        ? TextDecoration.none
        : TextDecoration.combine(decorations);
  }

  Map<FortuneCellCoord, _FortuneScreenshotConditionStyle>
  _screenshotConditionStyles(FortuneSheet sheet) {
    final rawRules = sheet.conditionFormats;
    if (rawRules is! List || rawRules.isEmpty) {
      return const {};
    }
    final styles = <FortuneCellCoord, _FortuneScreenshotConditionStyle>{};
    for (final rawRule in rawRules) {
      if (rawRule is! Map) {
        continue;
      }
      final conditionName = '${rawRule['conditionName'] ?? rawRule['type']}';
      if (conditionName == 'dataBar') {
        _applyScreenshotDataBarCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == 'colorGradation') {
        _applyScreenshotColorGradationCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == 'icons') {
        _applyScreenshotIconCondition(sheet, rawRule, styles);
        continue;
      }
      if (_isScreenshotAggregateCondition(conditionName)) {
        _applyScreenshotAggregateCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == 'formula') {
        _applyScreenshotFormulaCondition(sheet, rawRule, styles);
        continue;
      }
      if (conditionName == fortuneConditionRuleOccurrenceDateType) {
        _applyScreenshotOccurrenceDateCondition(sheet, rawRule, styles);
        continue;
      }
      final ranges = _screenshotConditionRanges(rawRule['cellrange']);
      if (ranges.isEmpty) {
        continue;
      }
      final format = rawRule['format'];
      final textColor = format is Map
          ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
          : null;
      final cellColor = format is Map
          ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
          : null;
      if (textColor == null && cellColor == null) {
        continue;
      }
      final values = rawRule['conditionValue'] is List
          ? rawRule['conditionValue'] as List
          : const [];
      for (final range in ranges) {
        for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          ) {
            final coord = FortuneCellCoord(row, column);
            final cell = sheet.cells[coord];
            if (cell == null || _screenshotConditionCellText(cell).isEmpty) {
              continue;
            }
            if (_matchesScreenshotCondition(cell, conditionName, values)) {
              final current = styles[coord];
              styles[coord] = _FortuneScreenshotConditionStyle(
                textColor: textColor,
                cellColor: cellColor,
                dataBar: current?.dataBar,
                icon: current?.icon,
              );
            }
          }
        }
      }
    }
    return styles;
  }

  void _applyScreenshotFormulaCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
  ) {
    final ranges = _screenshotConditionRanges(rawRule['cellrange']);
    if (ranges.isEmpty) {
      return;
    }
    final values = rawRule['conditionValue'] is List
        ? rawRule['conditionValue'] as List
        : const [];
    if (values.isEmpty || '${values[0]}'.trim().isEmpty) {
      return;
    }
    final format = rawRule['format'];
    final textColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
        : null;
    final cellColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
        : null;
    if (textColor == null && cellColor == null) {
      return;
    }
    final baseFormula = '${values[0]}'.startsWith('=')
        ? '${values[0]}'
        : '=${values[0]}';
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final formula = FortuneFormulaEngine.translateReferences(
            baseFormula,
            rowDelta: row - range.rowStart,
            columnDelta: column - range.columnStart,
          );
          final value = FortuneFormulaEngine.evaluateFormula(sheet, formula);
          if (!_screenshotConditionFormulaTruthy(value)) {
            continue;
          }
          _applyScreenshotConditionFormatStyle(
            styles,
            FortuneCellCoord(row, column),
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  bool _screenshotConditionFormulaTruthy(Object? value) {
    if (value == null) {
      return false;
    }
    if (value is bool) {
      return value;
    }
    if (value is num) {
      return value != 0 && value.isFinite;
    }
    final text = '$value'.trim();
    if (text.isEmpty) {
      return false;
    }
    if (text.toUpperCase() == 'FALSE') {
      return false;
    }
    final number = _screenshotNumberValue(text);
    return number == null ? true : number != 0 && number.isFinite;
  }

  void _applyScreenshotOccurrenceDateCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
  ) {
    final ranges = _screenshotConditionRanges(rawRule['cellrange']);
    if (ranges.isEmpty) {
      return;
    }
    final values = rawRule['conditionValue'] is List
        ? rawRule['conditionValue'] as List
        : const [];
    if (values.isEmpty || '${values[0]}'.trim().isEmpty) {
      return;
    }
    final dateRange = _screenshotConditionDateRange(values[0]);
    if (dateRange == null) {
      return;
    }
    final format = rawRule['format'];
    final textColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
        : null;
    final cellColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
        : null;
    if (textColor == null && cellColor == null) {
      return;
    }
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final coord = FortuneCellCoord(row, column);
          final cell = sheet.cells[coord];
          if (cell?.cellType?.type != 'd') {
            continue;
          }
          final serial =
              (cell == null
                  ? null
                  : _screenshotConditionDateSerial(
                      _screenshotConditionCellValue(cell),
                    )) ??
              _screenshotConditionDateSerial(cell?.value) ??
              _screenshotConditionDateSerial(cell?.displayValue);
          if (serial == null ||
              serial < dateRange.start ||
              serial > dateRange.end) {
            continue;
          }
          _applyScreenshotConditionFormatStyle(
            styles,
            coord,
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  _FortuneScreenshotConditionDateRange? _screenshotConditionDateRange(
    Object raw,
  ) {
    final text = '$raw'.trim();
    final parts = text.split(RegExp(r'\s+-\s+'));
    if (parts.length == 2) {
      final start = _screenshotConditionDateSerial(parts[0]);
      final end = _screenshotConditionDateSerial(parts[1]);
      if (start == null || end == null) {
        return null;
      }
      return _FortuneScreenshotConditionDateRange(
        math.min(start, end),
        math.max(start, end),
      );
    }
    final exact = _screenshotConditionDateSerial(text);
    if (exact == null) {
      return null;
    }
    return _FortuneScreenshotConditionDateRange(exact, exact);
  }

  int? _screenshotConditionDateSerial(Object? raw) {
    if (raw == null) {
      return null;
    }
    if (raw is num) {
      return raw.floor();
    }
    final text = '$raw'.trim();
    if (text.isEmpty) {
      return null;
    }
    final number = double.tryParse(text);
    if (number != null) {
      return number.floor();
    }
    final match = RegExp(
      r'^(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})',
    ).firstMatch(text);
    if (match == null) {
      return null;
    }
    final year = int.parse(match.group(1)!);
    final month = int.parse(match.group(2)!);
    final day = int.parse(match.group(3)!);
    final date = DateTime.utc(year, month, day);
    if (date.year != year || date.month != month || date.day != day) {
      return null;
    }
    return date.difference(DateTime.utc(1899, 12, 30)).inDays;
  }

  bool _isScreenshotAggregateCondition(String conditionName) {
    return conditionName == fortuneConditionRuleDuplicateType ||
        fortuneConditionRuleProjectTypes.contains(conditionName) ||
        fortuneConditionRuleAverageTypes.contains(conditionName);
  }

  void _applyScreenshotAggregateCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
  ) {
    final conditionName = '${rawRule['conditionName'] ?? rawRule['type']}';
    final ranges = _screenshotConditionRanges(rawRule['cellrange']);
    if (ranges.isEmpty) {
      return;
    }
    final format = rawRule['format'];
    final textColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['textColor'] ?? ''}')
        : null;
    final cellColor = format is Map
        ? FortuneSheetCodec.parseColor('${format['cellColor'] ?? ''}')
        : null;
    if (textColor == null && cellColor == null) {
      return;
    }
    final values = rawRule['conditionValue'] is List
        ? rawRule['conditionValue'] as List
        : const [];
    if (conditionName == fortuneConditionRuleDuplicateType) {
      _applyScreenshotDuplicateCondition(
        sheet,
        ranges,
        styles,
        unique: values.isNotEmpty && '${values[0]}' == '1',
        textColor: textColor,
        cellColor: cellColor,
      );
      return;
    }
    _applyScreenshotNumericAggregateCondition(
      sheet,
      ranges,
      styles,
      conditionName,
      values,
      textColor: textColor,
      cellColor: cellColor,
    );
  }

  void _applyScreenshotDuplicateCondition(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles, {
    required bool unique,
    required Color? textColor,
    required Color? cellColor,
  }) {
    for (final range in ranges) {
      final groups = <String, List<FortuneCellCoord>>{};
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final coord = FortuneCellCoord(row, column);
          final cell = sheet.cells[coord];
          if (cell == null || _screenshotConditionCellText(cell).isEmpty) {
            continue;
          }
          groups
              .putIfAbsent(_screenshotConditionCellText(cell), () => [])
              .add(coord);
        }
      }
      for (final coords in groups.values) {
        final matches = unique ? coords.length == 1 : coords.length > 1;
        if (!matches) {
          continue;
        }
        for (final coord in coords) {
          _applyScreenshotConditionFormatStyle(
            styles,
            coord,
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  void _applyScreenshotNumericAggregateCondition(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
    String conditionName,
    List conditionValues, {
    required Color? textColor,
    required Color? cellColor,
  }) {
    for (final range in ranges) {
      final numbers = _screenshotConditionNumericValues(sheet, [range]);
      if (numbers.isEmpty) {
        continue;
      }
      if (fortuneConditionRuleAverageTypes.contains(conditionName)) {
        final average =
            numbers.values.reduce((sum, value) => sum + value) / numbers.length;
        for (final entry in numbers.entries) {
          final matches = conditionName == fortuneConditionRuleAboveAverageType
              ? entry.value > average
              : entry.value < average;
          if (matches) {
            _applyScreenshotConditionFormatStyle(
              styles,
              entry.key,
              textColor: textColor,
              cellColor: cellColor,
            );
          }
        }
        continue;
      }
      final sorted = numbers.values.toList()..sort((a, b) => b.compareTo(a));
      final rawCount = _intValue(
        conditionValues.isEmpty ? 10 : conditionValues[0],
      );
      final count = rawCount == null ? 10 : math.max(0, rawCount);
      final takeCount =
          fortuneConditionRuleProjectPercentTypes.contains(conditionName)
          ? ((count * sorted.length) / 100).floor()
          : count;
      if (takeCount <= 0) {
        continue;
      }
      final clampedTake = math.min(takeCount, sorted.length);
      final selectedValues = <double>{};
      if (fortuneConditionRuleProjectTopTypes.contains(conditionName)) {
        selectedValues.addAll(sorted.take(clampedTake));
      } else if (fortuneConditionRuleProjectBottomTypes.contains(
        conditionName,
      )) {
        selectedValues.addAll(sorted.skip(sorted.length - clampedTake));
      }
      if (selectedValues.isEmpty) {
        continue;
      }
      for (final entry in numbers.entries) {
        if (selectedValues.contains(entry.value)) {
          _applyScreenshotConditionFormatStyle(
            styles,
            entry.key,
            textColor: textColor,
            cellColor: cellColor,
          );
        }
      }
    }
  }

  void _applyScreenshotConditionFormatStyle(
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
    FortuneCellCoord coord, {
    required Color? textColor,
    required Color? cellColor,
  }) {
    final current = styles[coord];
    styles[coord] = _FortuneScreenshotConditionStyle(
      textColor: textColor,
      cellColor: cellColor,
      dataBar: current?.dataBar,
      icon: current?.icon,
    );
  }

  void _applyScreenshotDataBarCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
  ) {
    final ranges = _screenshotConditionRanges(rawRule['cellrange']);
    final values = _screenshotConditionNumericValues(
      sheet,
      ranges,
    ).map((coord, value) => MapEntry(coord, value.truncateToDouble()));
    if (values.isEmpty) {
      return;
    }
    final maxValue = values.values.reduce(math.max);
    final minValue = values.values.reduce(math.min);
    final colors = _screenshotConditionFormatColors(rawRule['format']);
    final plusLen = minValue < 0 && maxValue > 0
        ? (((maxValue / (maxValue - minValue)) * 10).round() / 10).clamp(
            0.0,
            1.0,
          )
        : 1.0;
    final minusLen = minValue < 0 && maxValue > 0
        ? (((minValue.abs() / (maxValue - minValue)) * 10).round() / 10).clamp(
            0.0,
            1.0,
          )
        : 0.0;
    for (final entry in values.entries) {
      final value = entry.value;
      if (value == 0 && minValue < 0 && maxValue > 0) {
        continue;
      }
      final valueLen = value < 0
          ? (minValue == 0
                ? 0.0
                : ((value.abs() / minValue.abs()) * 100).round() / 100)
          : (maxValue == 0 ? 1.0 : ((value / maxValue) * 100).round() / 100);
      final current = styles[entry.key];
      styles[entry.key] = _FortuneScreenshotConditionStyle(
        textColor: current?.textColor,
        cellColor: current?.cellColor,
        icon: current?.icon,
        dataBar: _FortuneScreenshotDataBar(
          valueType: value < 0
              ? _FortuneScreenshotDataBarType.minus
              : _FortuneScreenshotDataBarType.plus,
          valueLen: valueLen.clamp(0.0, 1.0),
          plusLen: plusLen,
          minusLen: minusLen,
          colors: colors.isEmpty ? const [Color(0xff638ec6)] : colors,
        ),
      );
    }
  }

  void _applyScreenshotColorGradationCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
  ) {
    final ranges = _screenshotConditionRanges(rawRule['cellrange']);
    final values = _screenshotConditionNumericValues(
      sheet,
      ranges,
    ).map((coord, value) => MapEntry(coord, value.truncateToDouble()));
    final colors = _screenshotConditionFormatColors(rawRule['format']);
    if (values.isEmpty || colors.length < 2) {
      return;
    }
    final maxValue = values.values.reduce(math.max);
    final minValue = values.values.reduce(math.min);
    final middleValue =
        (values.values.reduce((sum, value) => sum + value) / values.length)
            .floorToDouble();
    for (final entry in values.entries) {
      final color = colors.length >= 3
          ? _screenshotThreeColorScale(
              entry.value,
              minValue,
              middleValue,
              maxValue,
              low: colors[2],
              middle: colors[1],
              high: colors[0],
            )
          : _screenshotTwoColorScale(
              entry.value,
              minValue,
              maxValue,
              low: colors[1],
              high: colors[0],
            );
      final current = styles[entry.key];
      styles[entry.key] = _FortuneScreenshotConditionStyle(
        textColor: current?.textColor,
        cellColor: color,
        dataBar: current?.dataBar,
        icon: current?.icon,
      );
    }
  }

  void _applyScreenshotIconCondition(
    FortuneSheet sheet,
    Map rawRule,
    Map<FortuneCellCoord, _FortuneScreenshotConditionStyle> styles,
  ) {
    final ranges = _screenshotConditionRanges(rawRule['cellrange']);
    final values = _screenshotConditionNumericValues(sheet, ranges);
    if (values.isEmpty) {
      return;
    }
    final maxValue = values.values.reduce(math.max);
    final minValue = values.values.reduce(math.min);
    final span = maxValue - minValue;
    for (final entry in values.entries) {
      final normalized = span == 0 ? 1.0 : (entry.value - minValue) / span;
      final kind = normalized >= 2 / 3
          ? _FortuneScreenshotIconKind.up
          : normalized >= 1 / 3
          ? _FortuneScreenshotIconKind.side
          : _FortuneScreenshotIconKind.down;
      final current = styles[entry.key];
      styles[entry.key] = _FortuneScreenshotConditionStyle(
        textColor: current?.textColor,
        cellColor: current?.cellColor,
        dataBar: current?.dataBar,
        icon: _FortuneScreenshotIcon(kind),
      );
    }
  }

  List<FortuneRange> _screenshotConditionRanges(Object? raw) {
    if (raw is! List) {
      return const [];
    }
    final ranges = <FortuneRange>[];
    for (final item in raw) {
      if (item is! Map) {
        continue;
      }
      final row = item['row'];
      final column = item['column'];
      if (row is! List ||
          row.length < 2 ||
          column is! List ||
          column.length < 2) {
        continue;
      }
      final rowStart = _intValue(row[0]);
      final rowEnd = _intValue(row[1]);
      final columnStart = _intValue(column[0]);
      final columnEnd = _intValue(column[1]);
      if (rowStart == null ||
          rowEnd == null ||
          columnStart == null ||
          columnEnd == null) {
        continue;
      }
      ranges.add(
        FortuneRange(
          rowStart: math.min(rowStart, rowEnd),
          rowEnd: math.max(rowStart, rowEnd),
          columnStart: math.min(columnStart, columnEnd),
          columnEnd: math.max(columnStart, columnEnd),
        ),
      );
    }
    return ranges;
  }

  bool _matchesScreenshotCondition(
    FortuneCell cell,
    String conditionName,
    List values,
  ) {
    final text = _screenshotConditionCellText(cell);
    final number = _screenshotNumberValue(_screenshotConditionCellValue(cell));
    final first = values.isEmpty ? null : values[0];
    final second = values.length < 2 ? null : values[1];
    final firstNumber = _screenshotNumberValue(first);
    final secondNumber = _screenshotNumberValue(second);
    return switch (conditionName) {
      'greaterThan' =>
        number != null && firstNumber != null && number > firstNumber,
      'lessThan' =>
        number != null && firstNumber != null && number < firstNumber,
      'equal' => text == '$first',
      'textContains' => first != null && text.contains('$first'),
      'between' =>
        number != null &&
            firstNumber != null &&
            secondNumber != null &&
            number >= math.min(firstNumber, secondNumber) &&
            number <= math.max(firstNumber, secondNumber),
      _ => false,
    };
  }

  Object? _screenshotConditionCellValue(FortuneCell cell) {
    return cell.hasRawValue ? cell.rawValue : cell.value;
  }

  String _screenshotConditionCellText(FortuneCell cell) {
    final raw = _screenshotConditionCellValue(cell);
    return raw == null ? '' : '$raw';
  }

  double? _screenshotNumberValue(Object? raw) {
    if (raw is num) {
      return raw.toDouble();
    }
    return double.tryParse('$raw'.replaceAll(',', '').trim());
  }

  Map? _screenshotDataVerificationForCoord(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    final raw = sheet.dataVerification['${coord.row}_${coord.column}'];
    return raw is Map ? raw : null;
  }

  bool _screenshotDataVerificationFails(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell? cell,
    Map? dataVerification,
  ) {
    if (dataVerification == null) {
      return false;
    }
    final item = Map<String, Object?>.from(dataVerification);
    final value =
        _screenshotDynamicArrayComputeText(sheet.dynamicArrayCompute, coord) ??
        cell?.renderedText;
    return !validateCellData(item, value, sheet: sheet);
  }

  String? _screenshotDynamicArrayComputeText(
    Object? raw,
    FortuneCellCoord coord,
  ) {
    Object? entry;
    if (raw is Map) {
      entry = raw['${coord.row}_${coord.column}'];
    } else if (raw is List) {
      for (final item in raw) {
        if (item is Map &&
            _intValue(item['r']) == coord.row &&
            _intValue(item['c']) == coord.column) {
          entry = item;
          break;
        }
      }
    }
    if (entry is Map && entry.containsKey('v')) {
      final value = entry['v'];
      return value == null ? '' : '$value';
    }
    return null;
  }

  FortuneCell? _screenshotCellWithDynamicArrayComputeText(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell? cell,
  ) {
    final text = _screenshotDynamicArrayComputeText(
      sheet.dynamicArrayCompute,
      coord,
    );
    if (text == null) {
      return cell;
    }
    final source = cell ?? const FortuneCell();
    return source.copyWith(
      value: text,
      displayValue: text,
      rawDisplayValue: text,
      hasRawDisplayValue: true,
      inlineRuns: null,
    );
  }

  Map<FortuneCellCoord, double> _screenshotConditionNumericValues(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
  ) {
    final values = <FortuneCellCoord, double>{};
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final coord = FortuneCellCoord(row, column);
          final cell = sheet.cells[coord];
          final value = cell == null
              ? null
              : _screenshotNumberValue(_screenshotConditionCellValue(cell));
          if (value != null) {
            values[coord] = value;
          }
        }
      }
    }
    return values;
  }

  List<Color> _screenshotConditionFormatColors(Object? raw) {
    if (raw is List) {
      return [for (final item in raw) ?FortuneSheetCodec.parseColor('$item')];
    }
    if (raw is Map) {
      return [
        ?FortuneSheetCodec.parseColor('${raw['cellColor'] ?? ''}'),
        ?FortuneSheetCodec.parseColor('${raw['textColor'] ?? ''}'),
      ];
    }
    return const [];
  }

  Color _screenshotTwoColorScale(
    double value,
    double minValue,
    double maxValue, {
    required Color low,
    required Color high,
  }) {
    if (maxValue == minValue) {
      return high;
    }
    final t = ((value - minValue) / (maxValue - minValue)).clamp(0.0, 1.0);
    return Color.lerp(low, high, t)!;
  }

  Color _screenshotThreeColorScale(
    double value,
    double minValue,
    double middleValue,
    double maxValue, {
    required Color low,
    required Color middle,
    required Color high,
  }) {
    if (value <= middleValue) {
      return _screenshotTwoColorScale(
        value,
        minValue,
        middleValue,
        low: low,
        high: middle,
      );
    }
    return _screenshotTwoColorScale(
      value,
      middleValue,
      maxValue,
      low: middle,
      high: high,
    );
  }

  void _drawScreenshotConditionDataBar(
    Canvas canvas,
    Rect rect,
    _FortuneScreenshotDataBar dataBar,
  ) {
    if (rect.width <= 4 || rect.height <= 4 || dataBar.valueLen <= 0) {
      return;
    }
    final content = rect.deflate(2);
    final width = content.width;
    final paint = Paint();
    final color = dataBar.colors.first;
    late Rect barRect;
    if (dataBar.valueType == _FortuneScreenshotDataBarType.minus) {
      final axis = content.left + width * dataBar.minusLen;
      final barWidth = width * dataBar.minusLen * dataBar.valueLen;
      barRect = Rect.fromLTWH(
        axis - barWidth,
        content.top,
        barWidth,
        content.height,
      );
      paint.color = const Color(0xffff0000);
    } else if (dataBar.minusLen > 0 && dataBar.plusLen < 1) {
      final axis = content.left + width * dataBar.minusLen;
      barRect = Rect.fromLTWH(
        axis,
        content.top,
        width * dataBar.plusLen * dataBar.valueLen,
        content.height,
      );
      paint.color = color;
    } else {
      barRect = Rect.fromLTWH(
        content.left,
        content.top,
        width * dataBar.valueLen,
        content.height,
      );
      paint.color = color;
    }
    if (barRect.width <= 0) {
      return;
    }
    if (dataBar.colors.length > 1 &&
        dataBar.valueType == _FortuneScreenshotDataBarType.plus) {
      paint.shader = ui.Gradient.linear(
        barRect.topLeft,
        barRect.topRight,
        dataBar.colors.take(2).toList(),
      );
    }
    if (dataBar.valueType == _FortuneScreenshotDataBarType.minus &&
        dataBar.colors.length > 1) {
      final columns = math.max(1, barRect.width.ceil());
      for (var i = 0; i < columns; i += 1) {
        final t = columns <= 1 ? 1.0 : i / (columns - 1);
        final stripLeft = barRect.left + i;
        final stripRight = math.min(stripLeft + 1, barRect.right);
        canvas.drawRect(
          Rect.fromLTRB(stripLeft, barRect.top, stripRight, barRect.bottom),
          Paint()
            ..color = Color.lerp(
              const Color(0xffffffff),
              const Color(0xffff0000),
              t,
            )!,
        );
      }
    } else {
      canvas.drawRect(barRect, paint);
    }
    canvas.drawRect(
      barRect,
      Paint()
        ..color = dataBar.valueType == _FortuneScreenshotDataBarType.minus
            ? const Color(0xffff0000)
            : color
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1,
    );
  }

  void _drawScreenshotConditionIcon(
    Canvas canvas,
    Rect rect,
    _FortuneScreenshotIcon icon,
  ) {
    if (rect.width < 16 || rect.height < 12) {
      return;
    }
    final size = math.min(11.0, rect.height - 6);
    final center = Offset(rect.left + 8, rect.center.dy);
    final paint = Paint()..style = PaintingStyle.fill;
    final path = Path();
    switch (icon.kind) {
      case _FortuneScreenshotIconKind.up:
        paint.color = const Color(0xff188038);
        path
          ..moveTo(center.dx, center.dy - size / 2)
          ..lineTo(center.dx + size / 2, center.dy + size / 2)
          ..lineTo(center.dx - size / 2, center.dy + size / 2)
          ..close();
      case _FortuneScreenshotIconKind.side:
        paint.color = const Color(0xfffbbc04);
        path
          ..moveTo(center.dx + size / 2, center.dy)
          ..lineTo(center.dx - size / 2, center.dy - size / 2)
          ..lineTo(center.dx - size / 2, center.dy + size / 2)
          ..close();
      case _FortuneScreenshotIconKind.down:
        paint.color = const Color(0xffd93025);
        path
          ..moveTo(center.dx, center.dy + size / 2)
          ..lineTo(center.dx + size / 2, center.dy - size / 2)
          ..lineTo(center.dx - size / 2, center.dy - size / 2)
          ..close();
    }
    canvas.drawPath(path, paint);
  }

  void _drawScreenshotCommentIndicator(Canvas canvas, Rect rect) {
    final path = Path()
      ..moveTo(rect.right - 7, rect.top + 1)
      ..lineTo(rect.right - 1, rect.top + 1)
      ..lineTo(rect.right - 1, rect.top + 7)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xffd93025));
  }

  bool _showsScreenshotQuotePrefixIndicator(FortuneCell? cell) {
    if (cell == null || !cell.quotePrefix) {
      return false;
    }
    final value = cell.hasRawValue ? cell.rawValue : cell.value;
    return _screenshotNumberValue(value) != null;
  }

  void _drawScreenshotQuotePrefixIndicator(Canvas canvas, Rect rect) {
    final path = Path()
      ..moveTo(rect.left + 5, rect.top)
      ..lineTo(rect.left - 1, rect.top)
      ..lineTo(rect.left - 1, rect.top + 6)
      ..close();
    canvas.drawPath(path, Paint()..color = const Color(0xff487f1e));
  }

