  void _drawScreenshotDataVerificationCheckbox(
    Canvas canvas,
    Rect rect,
    FortuneCell? cell,
    Map dataVerification,
  ) {
    if (rect.width < 14 || rect.height < 12) {
      return;
    }
    final text = cell?.renderedText ?? '';
    final foreground = cell?.foreground ?? const Color(0xff000000);
    final fontSize = cell?.fontSize ?? _workbook.settings.defaultFontSize;
    final checkboxTop = rect.center.dy - 5;
    final checkboxLeft = switch (cell?.normalizedHorizontalAlign) {
      '0' => rect.center.dx - (text.isEmpty ? 5 : 28),
      '2' => rect.right - 14 - (text.isEmpty ? 0 : 42),
      _ => rect.left + 2,
    };
    final box = Rect.fromLTWH(
      checkboxLeft.clamp(rect.left + 1, rect.right - 11).toDouble(),
      checkboxTop.clamp(rect.top + 1, rect.bottom - 11).toDouble(),
      10,
      10,
    );
    final paint = Paint()
      ..color = const Color(0xff000000)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1;
    canvas.drawRect(box, paint);
    if (fortuneRawBool(dataVerification['checked']) == true) {
      final check = Path()
        ..moveTo(box.left + 1, box.top + 6)
        ..lineTo(box.left + 4, box.top + 9)
        ..lineTo(box.left + 9, box.top + 2);
      canvas.drawPath(check, paint);
    }
    if (text.isEmpty) {
      return;
    }
    final textSpan = TextSpan(
      text: text,
      style: _screenshotTextStyle(
        cell!,
        fontSize: fontSize,
        textColor: foreground,
      ),
    );
    final textPainter = TextPainter(
      text: textSpan,
      maxLines: 1,
      textDirection: TextDirection.ltr,
      ellipsis: '...',
    )..layout(maxWidth: math.max(0.0, rect.right - box.right - 6));
    textPainter.paint(
      canvas,
      Offset(box.right + 4, _screenshotTextTop(cell, rect, textPainter.height)),
    );
  }

  void _drawScreenshotImages(
    Canvas canvas,
    Rect bounds, {
    required double originX,
    required double originY,
  }) {
    final images = _workbook.activeSheet.images;
    if (images.isEmpty) {
      return;
    }
    canvas.save();
    canvas.clipRect(bounds, doAntiAlias: false);
    for (final image in images) {
      final rect = Rect.fromLTWH(
        image.left - originX,
        image.top - originY,
        image.width,
        image.height,
      );
      if (!rect.overlaps(bounds)) {
        continue;
      }
      final decoded = _decodedImages[image.src];
      if (decoded == null) {
        _drawScreenshotImagePlaceholder(canvas, rect, image);
      } else {
        _drawScreenshotImageBitmap(canvas, rect, decoded);
      }
    }
    canvas.restore();
  }

  void _drawScreenshotRawShapeOverlays(
    Canvas canvas,
    Rect bounds, {
    required double originX,
    required double originY,
  }) {
    final overlays = fortuneRawShapeOverlays(_workbook.activeSheet);
    if (overlays.isEmpty) {
      return;
    }
    canvas.save();
    canvas.clipRect(bounds, doAntiAlias: false);
    for (final overlay in overlays) {
      final rect = overlay.rect.translate(-originX, -originY);
      fortuneDrawRawShapeOverlay(canvas, rect, overlay, bounds);
    }
    canvas.restore();
  }

  void _drawScreenshotRulerGuides(
    Canvas canvas,
    Rect bounds,
    FortuneSheetMetrics metrics,
    double originX,
    double originY,
  ) {
    final guides = _sheetRulerGuides(_workbook.activeSheet);
    if (guides.isEmpty) {
      return;
    }
    final maxWidthMm = fortuneLogicalPixelsToMillimeters(
      metrics.columnTotalWidth,
    );
    final maxHeightMm = fortuneLogicalPixelsToMillimeters(
      metrics.rowTotalHeight,
    );
    final paint = Paint()
      ..color = fortuneSheetGuideColor
      ..strokeWidth = 1.0;
    canvas.save();
    canvas.clipRect(bounds, doAntiAlias: false);
    for (final guide in guides) {
      if (guide.axis == 'vertical') {
        final x = fortuneMillimetersToLogicalPixels(
              guide.positionMm.clamp(0.0, maxWidthMm),
            ) -
            originX;
        canvas.drawLine(Offset(x, bounds.top), Offset(x, bounds.bottom), paint);
      } else if (guide.axis == 'horizontal') {
        final y = fortuneMillimetersToLogicalPixels(
              guide.positionMm.clamp(0.0, maxHeightMm),
            ) -
            originY;
        canvas.drawLine(Offset(bounds.left, y), Offset(bounds.right, y), paint);
      }
    }
    canvas.restore();
  }

  void _drawScreenshotImageBitmap(Canvas canvas, Rect rect, ui.Image image) {
    canvas.drawImageRect(
      image,
      Rect.fromLTWH(0, 0, image.width.toDouble(), image.height.toDouble()),
      rect,
      Paint()..filterQuality = FilterQuality.medium,
    );
  }

  void _drawScreenshotImagePlaceholder(
    Canvas canvas,
    Rect rect,
    FortuneImage image,
  ) {
    canvas.drawRect(rect, Paint()..color = const Color(0xffffffff));
    canvas.drawRect(rect, Paint()..color = const Color(0xffe8f0fe));
    canvas.drawRect(
      rect,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1
        ..color = const Color(0xff0188fb),
    );
    final iconRect = Rect.fromCenter(
      center: rect.center,
      width: math.max(0, math.min(32, rect.width - 8)),
      height: math.max(0, math.min(24, rect.height - 8)),
    );
    if (iconRect.width > 8 && iconRect.height > 8) {
      final paint = Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1.4
        ..color = const Color(0xff5f6368);
      canvas.drawRect(iconRect, paint);
      final mountain = Path()
        ..moveTo(iconRect.left + 4, iconRect.bottom - 4)
        ..lineTo(iconRect.left + iconRect.width * 0.42, iconRect.center.dy)
        ..lineTo(iconRect.left + iconRect.width * 0.58, iconRect.bottom - 7)
        ..lineTo(iconRect.right - 4, iconRect.bottom - 4);
      canvas.drawPath(mountain, paint);
      canvas.drawCircle(
        Offset(iconRect.right - 7, iconRect.top + 6),
        2,
        Paint()..color = const Color(0xff5f6368),
      );
    }
    if (image.src.isNotEmpty && rect.width > 42 && rect.height > 28) {
      final textSpan = TextSpan(
        text: 'image',
        style: const TextStyle(fontSize: 10, color: Color(0xff5f6368)),
      );
      final textPainter = TextPainter(
        text: textSpan,
        textAlign: TextAlign.center,
        maxLines: 1,
        textDirection: TextDirection.ltr,
      )..layout(maxWidth: rect.width - 8);
      textPainter.paint(
        canvas,
        Offset(
          rect.left + 4 + math.max(0, rect.width - 8 - textPainter.width) / 2,
          rect.bottom - 20 + math.max(0, 16 - textPainter.height) / 2,
        ),
      );
    }
  }

  void _drawScreenshotCellBorders(
    Canvas canvas,
    Rect rect,
    FortuneCellBorders borders,
  ) {
    if (borders.top case final side?) {
      _drawScreenshotBorderLine(
        canvas,
        side,
        rect.topLeft,
        rect.topRight,
        horizontal: true,
      );
    }
    if (borders.right case final side?) {
      _drawScreenshotBorderLine(
        canvas,
        side,
        rect.topRight,
        rect.bottomRight,
        horizontal: false,
      );
    }
    if (borders.bottom case final side?) {
      _drawScreenshotBorderLine(
        canvas,
        side,
        rect.bottomLeft,
        rect.bottomRight,
        horizontal: true,
      );
    }
    if (borders.left case final side?) {
      _drawScreenshotBorderLine(
        canvas,
        side,
        rect.topLeft,
        rect.bottomLeft,
        horizontal: false,
      );
    }
    if (borders.slash case final side?) {
      _drawScreenshotBorderLine(
        canvas,
        side,
        rect.bottomLeft,
        rect.topRight,
        horizontal: false,
      );
    }
  }

  void _drawScreenshotBorderLine(
    Canvas canvas,
    FortuneBorderSide side,
    Offset start,
    Offset end, {
    required bool horizontal,
  }) {
    final paint = Paint()
      ..color = side.color
      ..strokeWidth = fortuneToolbarBorderStrokeWidth(
        side.style,
        _toolbarBorderStyleStrokeWidths,
      )
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.square;
    final adjustedStart = horizontal
        ? Offset(start.dx, start.dy - 0.5)
        : Offset(start.dx - 0.5, start.dy);
    final adjustedEnd = horizontal
        ? Offset(end.dx, end.dy - 0.5)
        : Offset(end.dx - 0.5, end.dy);
    final dash = fortuneToolbarBorderStyleDashPatterns[side.style];
    if (dash == null || dash.length < 2 || dash[1] == 0) {
      canvas.drawLine(adjustedStart, adjustedEnd, paint);
      return;
    }
    _drawScreenshotDashedLine(canvas, adjustedStart, adjustedEnd, paint, dash);
  }

  void _drawScreenshotDashedLine(
    Canvas canvas,
    Offset start,
    Offset end,
    Paint paint,
    List<double> dash,
  ) {
    final delta = end - start;
    final distance = delta.distance;
    if (distance == 0) {
      return;
    }
    final direction = delta / distance;
    var drawn = 0.0;
    var dashIndex = 0;
    while (drawn < distance) {
      final length = dash[dashIndex % dash.length];
      final next = math.min(distance, drawn + length);
      if (dashIndex.isEven) {
        canvas.drawLine(
          start + direction * drawn,
          start + direction * next,
          paint,
        );
      }
      drawn = next;
      dashIndex += 1;
    }
  }

  void _clearScreenshotCapture() {
    _screenshotImage?.dispose();
    _screenshotImage = null;
    _screenshotImageDataUrl = null;
  }

  bool _rangeHasPartialMerge(FortuneSheet sheet, FortuneRange range) {
    for (final entry in sheet.cells.entries) {
      final merge = entry.value.merge;
      if (merge == null || merge.rowSpan <= 1 && merge.columnSpan <= 1) {
        continue;
      }
      final mergeRange = FortuneRange(
        rowStart: merge.row,
        rowEnd: merge.row + merge.rowSpan - 1,
        columnStart: merge.column,
        columnEnd: merge.column + merge.columnSpan - 1,
      );
      final intersects =
          range.rowStart <= mergeRange.rowEnd &&
          range.rowEnd >= mergeRange.rowStart &&
          range.columnStart <= mergeRange.columnEnd &&
          range.columnEnd >= mergeRange.columnStart;
      final contains =
          range.rowStart <= mergeRange.rowStart &&
          range.rowEnd >= mergeRange.rowEnd &&
          range.columnStart <= mergeRange.columnStart &&
          range.columnEnd >= mergeRange.columnEnd;
      if (intersects && !contains) {
        return true;
      }
    }
    return false;
  }

  Rect? _screenshotDialogRect([Size? overrideSize]) {
    if (!_screenshotDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    return size == null ? null : fortuneScreenshotDialogRect(size);
  }

  String? _screenshotDialogCommandAt(Offset local) {
    final rect = _screenshotDialogRect();
    if (rect == null) {
      return null;
    }
    if (fortuneScreenshotCloseButtonRect(rect).contains(local) ||
        fortuneScreenshotOkButtonRect(rect).contains(local)) {
      return 'close';
    }
    return null;
  }

  void _activateScreenshotDialogCommand(String? command) {
    if (command == 'close') {
      setState(() {
        _screenshotDialogOpen = false;
        _screenshotRange = null;
        _clearScreenshotCapture();
      });
      _focusNode.requestFocus();
    }
  }

  void _showSearchDialog({bool replace = false}) {
    setState(() {
      _closeTransientMenus();
      _searchDialogOpen = true;
      _searchReplaceMode = replace;
      _searchResults = const <FortuneSearchResultView>[];
      _searchSelectedResultIndex = null;
      _searchDialogOffset = Offset.zero;
      _cancelSearchDialogDrag();
    });
    if (replace) {
      _replaceEditorFocusNode.requestFocus();
    } else {
      _searchEditorFocusNode.requestFocus();
    }
  }

  Rect? _searchDialogRect([Size? overrideSize]) {
    if (!_searchDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    if (size == null) {
      return null;
    }
    return fortuneSearchDialogRect(
      size,
      hasResults: _searchResults.isNotEmpty,
      offset: _searchDialogOffset,
    );
  }

  Offset _clampedSearchDialogOffset(Offset offset, Size size) {
    final baseRect = fortuneSearchDialogRect(
      size,
      hasResults: _searchResults.isNotEmpty,
    );
    final shiftedRect = fortuneSearchDialogRect(
      size,
      hasResults: _searchResults.isNotEmpty,
      offset: offset,
    );
    return shiftedRect.topLeft - baseRect.topLeft;
  }

  void _startSearchDialogDrag(Offset local) {
    _searchDialogDragStart = local;
    _searchDialogDragInitialOffset = _searchDialogOffset;
  }

  bool _updateSearchDialogDrag(Offset local) {
    final start = _searchDialogDragStart;
    final initialOffset = _searchDialogDragInitialOffset;
    final size = context.size;
    if (start == null || initialOffset == null || size == null) {
      return false;
    }
    setState(() {
      _searchDialogOffset = _clampedSearchDialogOffset(
        initialOffset + local - start,
        size,
      );
    });
    return true;
  }

  bool _commitSearchDialogDrag() {
    if (_searchDialogDragStart == null) {
      return false;
    }
    _cancelSearchDialogDrag();
    return true;
  }

  void _cancelSearchDialogDrag() {
    _searchDialogDragStart = null;
    _searchDialogDragInitialOffset = null;
  }

  Rect? _searchDialogInputRect([Size? overrideSize]) {
    final rect = _searchDialogRect(overrideSize);
    return rect == null ? null : fortuneSearchInputRect(rect);
  }

  Rect? _searchDialogReplaceInputRect([Size? overrideSize]) {
    final rect = _searchDialogRect(overrideSize);
    return rect == null ? null : fortuneSearchReplaceInputRect(rect);
  }

  String? _searchDialogCommandAt(Offset local) {
    final rect = _searchDialogRect();
    if (rect == null) {
      return null;
    }
    if (fortuneSearchCloseButtonRect(rect).contains(local) ||
        fortuneSearchBottomCloseButtonRect(rect).contains(local)) {
      return 'close';
    }
    if (fortuneSearchFindTabRect(rect).contains(local)) {
      return 'findTab';
    }
    if (fortuneSearchReplaceTabRect(rect).contains(local)) {
      return 'replaceTab';
    }
    for (var i = 0; i < 3; i += 1) {
      if (fortuneSearchCheckboxRect(rect, i).inflate(8).contains(local)) {
        return 'check-$i';
      }
    }
    for (final command in ['replaceAll', 'replace', 'findAll', 'findNext']) {
      final button = fortuneSearchButtonRect(
        rect,
        command,
        replace: _searchReplaceMode,
      );
      if (!button.isEmpty && button.contains(local)) {
        return command;
      }
    }
    if (_searchResults.isNotEmpty) {
      final resultsRect = fortuneSearchResultsRect(rect);
      if (resultsRect.contains(local) && local.dy >= resultsRect.top + 30) {
        final index = ((local.dy - resultsRect.top - 30) / 30).floor();
        if (index >= 0 && index < math.min(_searchResults.length, 6)) {
          return 'result-$index';
        }
      }
    }
    return null;
  }

  void _activateSearchDialogCommand(String? command) {
    if (command == null) {
      return;
    }
    if (command == 'close') {
      setState(() => _searchDialogOpen = false);
      _focusNode.requestFocus();
      return;
    }
    if (command == 'findTab' || command == 'replaceTab') {
      setState(() => _searchReplaceMode = command == 'replaceTab');
      if (_searchReplaceMode) {
        _replaceEditorFocusNode.requestFocus();
      } else {
        _searchEditorFocusNode.requestFocus();
      }
      return;
    }
    if (command.startsWith('check-')) {
      final index = int.parse(command.substring('check-'.length));
      setState(() {
        if (index == 0) _searchRegex = !_searchRegex;
        if (index == 1) _searchWholeWord = !_searchWholeWord;
        if (index == 2) _searchCaseSensitive = !_searchCaseSensitive;
      });
      return;
    }
    if (command == 'findAll') {
      _searchAllFromDialog();
      return;
    }
    if (command == 'findNext') {
      _searchNextFromDialog();
      return;
    }
    if (command == 'replace') {
      _replaceCurrentFromDialog();
      return;
    }
    if (command == 'replaceAll') {
      _replaceAllFromDialog();
      return;
    }
    if (command.startsWith('result-')) {
      final index = int.parse(command.substring('result-'.length));
      _selectSearchResult(index);
    }
  }

  List<FortuneSearchResultView> _searchMatches() {
    final query = _searchEditorController.text;
    if (query.isEmpty) {
      return const <FortuneSearchResultView>[];
    }
    RegExp? regex;
    if (_searchRegex) {
      try {
        regex = _fortuneSearchRegExp(query);
      } catch (_) {
        return const <FortuneSearchResultView>[];
      }
    }
    final matches = <FortuneSearchResultView>[];
    final sheetIndex = _workbook.activeSheetIndex;
    final sheet = _workbook.activeSheet;
    final ranges = _searchScopeRanges(sheet);
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final coord = FortuneCellCoord(row, column);
          final anchor = sheet.mergeAnchorFor(coord);
          if (anchor != coord) {
            continue;
          }
          final value = valueShowEs(sheet.cells[coord])?.toString() ?? '';
          if (value.isEmpty) {
            continue;
          }
          if (_searchTextMatches(value, query, regex)) {
            matches.add(
              FortuneSearchResultView(
                sheetIndex: sheetIndex,
                sheetName: sheet.name,
                row: row,
                column: column,
                value: value,
              ),
            );
          }
        }
      }
    }
    return matches;
  }

  List<FortuneRange> _searchScopeRanges(FortuneSheet sheet) {
    final ranges = _rawSelectionRanges(sheet);
    final singleCellSelection =
        ranges.length == 1 &&
        ranges.single.rowStart == ranges.single.rowEnd &&
        ranges.single.columnStart == ranges.single.columnEnd;
    if (ranges.isEmpty || singleCellSelection) {
      return [
        FortuneRange(
          rowStart: 0,
          rowEnd: _effectiveRowCount(sheet) - 1,
          columnStart: 0,
          columnEnd: _effectiveColumnCount(sheet) - 1,
        ),
      ];
    }
    return ranges;
  }

  bool _searchTextMatches(String value, String query, RegExp? regex) {
    if (regex != null) {
      final match = regex.firstMatch(value);
      if (match == null) {
        return false;
      }
      return !_searchWholeWord || match.group(0) == value;
    }
    final source = _searchCaseSensitive ? value : value.toLowerCase();
    final needle = _searchCaseSensitive ? query : query.toLowerCase();
    return _searchWholeWord ? source == needle : source.contains(needle);
  }

  RegExp _fortuneSearchRegExp(String query) {
    return RegExp(getRegExpStr(query), caseSensitive: _searchCaseSensitive);
  }

  void _searchAllFromDialog() {
    final matches = _searchMatches();
    setState(() {
      _searchResults = matches;
      _searchSelectedResultIndex = matches.isEmpty ? null : 0;
    });
    if (matches.isEmpty && _searchEditorController.text.isNotEmpty) {
      _showLocationMessageDialog(widget.locale.noFindTip);
    } else if (matches.isNotEmpty) {
      _selectSearchResult(0, matches: matches);
    }
  }

  void _searchNextFromDialog() {
    final matches = _searchMatches();
    if (matches.isEmpty) {
      if (_searchEditorController.text.isEmpty) {
        _showLocationMessageDialog(widget.locale.searchInputTip);
      } else {
        _showLocationMessageDialog(widget.locale.noFindTip);
      }
      return;
    }
    final currentIndex = _searchSelectedResultIndex;
    final nextIndex = currentIndex == null
        ? 0
        : (currentIndex + 1) % matches.length;
    setState(() {
      _searchResults = const <FortuneSearchResultView>[];
      _searchSelectedResultIndex = nextIndex;
    });
    _selectSearchResult(nextIndex, matches: matches);
  }

  void _selectSearchResult(
    int index, {
    List<FortuneSearchResultView>? matches,
  }) {
    final source = matches ?? _searchResults;
    if (index < 0 || index >= source.length) {
      return;
    }
    final result = source[index];
    setState(() {
      _workbook = _workbook.copyWith(activeSheetIndex: result.sheetIndex);
      selection = FortuneSelection(row: result.row, column: result.column);
      _searchSelectedResultIndex = index;
      if (matches != null) {
        _searchResults = matches;
      }
      scrollOffset = Offset.zero;
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(result.sheetIndex);
    });
  }

  void _replaceCurrentFromDialog() {
    if (!_canReplaceFromDialog()) {
      setState(() {
        _searchResults = const <FortuneSearchResultView>[];
        _searchSelectedResultIndex = null;
      });
      _showLocationMessageDialog(widget.locale.modeTip);
      return;
    }
    if (_searchEditorController.text.isEmpty) {
      _showLocationMessageDialog(widget.locale.searchInputTip);
      return;
    }
    final matches = _searchMatches();
    if (matches.isEmpty) {
      _showLocationMessageDialog(widget.locale.noReplaceTip);
      return;
    }
    final index =
        _searchSelectedResultIndex == null ||
            _searchSelectedResultIndex! >= matches.length
        ? 0
        : _searchSelectedResultIndex!;
    _replaceSearchResult(matches[index]);
    setState(() {
      _searchResults = const <FortuneSearchResultView>[];
      _searchSelectedResultIndex = null;
    });
  }

  void _replaceAllFromDialog() {
    if (!_canReplaceFromDialog()) {
      setState(() {
        _searchResults = const <FortuneSearchResultView>[];
        _searchSelectedResultIndex = null;
      });
      _showLocationMessageDialog(widget.locale.modeTip);
      return;
    }
    if (_searchEditorController.text.isEmpty) {
      _showLocationMessageDialog(widget.locale.searchInputTip);
      return;
    }
    final matches = _searchMatches();
    if (matches.isEmpty) {
      _showLocationMessageDialog(widget.locale.noReplaceTip);
      return;
    }
    final sheets = _workbook.sheets.toList();
    var changed = false;
    final replacedSelection = [
      for (final range in _searchScopeRanges(_workbook.activeSheet))
        range.copyWith(),
    ];
    FortuneCellCoord? focus;
    for (final result in matches) {
      final sheet = sheets[result.sheetIndex];
      final coord = FortuneCellCoord(result.row, result.column);
      final cell = sheet.cells[coord];
      if (cell == null || !_canEditCell(sheet, coord)) {
        continue;
      }
      final nextValue = _searchReplacementValue(cell);
      final nextSheet = setCellValue(
        sheet,
        result.row,
        result.column,
        nextValue,
      );
      final next = nextSheet.cells[coord];
      if (next == null) {
        continue;
      }
      if (_jsonLikeEquals(
        FortuneSheetCodec.cellToJson(cell),
        FortuneSheetCodec.cellToJson(next),
      )) {
        continue;
      }
      if (!changed) {
        _recordUndoSnapshot();
        changed = true;
      }
      sheets[result.sheetIndex] = nextSheet;
      replacedSelection.add(_singleCellRange(coord));
      focus = coord;
    }
    if (!changed) {
      setState(() {
        _searchResults = const <FortuneSearchResultView>[];
        _searchSelectedResultIndex = null;
      });
      _showLocationMessageDialog(
        widget.locale.replaceSuccessMessage(matches.length),
      );
      return;
    }
    setState(() {
      _workbook = _workbook.copyWith(sheets: sheets);
      _recalculateWorkbookFormulas();
      if (focus != null) {
        final replacementFocus = focus;
        selection = FortuneSelection(
          row: replacementFocus.row,
          column: replacementFocus.column,
        );
        _writeSelectionRanges(replacedSelection, replacementFocus);
      }
      _searchResults = const <FortuneSearchResultView>[];
      _searchSelectedResultIndex = null;
    });
    _showLocationMessageDialog(
      widget.locale.replaceSuccessMessage(matches.length),
    );
  }

  bool _canReplaceFromDialog() {
    final sheet = _workbook.activeSheet;
    final ranges = _rawSelectionRanges(sheet);
    return isAllowEdit(
      sheet,
      ranges: ranges.isEmpty
          ? [
              FortuneRange(
                rowStart: selection.row,
                rowEnd: selection.rowEnd,
                columnStart: selection.column,
                columnEnd: selection.columnEnd,
              ),
            ]
          : ranges,
      settings: _workbook.settings,
    );
  }

  void _replaceSearchResult(FortuneSearchResultView result) {
    final sheet = _workbook.sheets[result.sheetIndex];
    final coord = FortuneCellCoord(result.row, result.column);
    final cell = sheet.cells[coord];
    if (cell == null || !_canEditCell(sheet, coord)) {
      return;
    }
    final nextValue = _searchReplacementValue(cell);
    final nextSheet = setCellValue(sheet, result.row, result.column, nextValue);
    final next = nextSheet.cells[coord];
    if (next == null) {
      return;
    }
    if (_jsonLikeEquals(
      FortuneSheetCodec.cellToJson(cell),
      FortuneSheetCodec.cellToJson(next),
    )) {
      setState(() {
        _workbook = _workbook.copyWith(activeSheetIndex: result.sheetIndex);
        selection = FortuneSelection(row: result.row, column: result.column);
      });
      return;
    }
    _recordUndoSnapshot();
    final sheets = _workbook.sheets.toList();
    sheets[result.sheetIndex] = nextSheet;
    setState(() {
      _workbook = _workbook.copyWith(
        sheets: sheets,
        activeSheetIndex: result.sheetIndex,
      );
      selection = FortuneSelection(row: result.row, column: result.column);
      _recalculateWorkbookFormulas();
    });
  }

  String _searchReplacementValue(FortuneCell cell) {
    final source = valueShowEs(cell)?.toString() ?? '';
    final replacement = _replaceEditorController.text;
    final query = _searchEditorController.text;
    return _searchWholeWord
        ? replacement
        : source.replaceAll(_fortuneSearchRegExp(query), replacement);
  }

  void _clearSelectedCellFormat() {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      if (sheet.hiddenRows.contains(row)) {
        continue;
      }
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final updates = <FortuneCellCoord, FortuneCell>{};
    for (final coord in targets) {
      final previous = sheet.cells[coord];
      if (previous != null) {
        updates[coord] = _cellWithClearedFormat(previous);
      }
    }
    final hasChanges = updates.entries.any(
      (entry) => _cellWouldChange(sheet, entry.key, entry.value),
    );
    final nextBorderInfo = _clearFormatBorderInfoForRange(sheet, range);
    final nextRawBorderInfo = _clearFormatRawBorderInfoForRange(sheet, range);
    final hasBorderChanges =
        !_borderInfoListSemanticallyEquals(sheet.borderInfo, nextBorderInfo) ||
        !_jsonLikeEquals(sheet.rawBorderInfo, nextRawBorderInfo);
    if (hasChanges || hasBorderChanges) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChanges) {
        for (final entry in updates.entries) {
          if (_cellWouldChange(sheet, entry.key, entry.value)) {
            _setSheetCell(sheet, entry.key, entry.value);
          }
        }
      }
      if (hasBorderChanges) {
        _replaceActiveSheet(
          sheet.copyWith(
            borderInfo: nextBorderInfo,
            rawBorderInfo: nextRawBorderInfo,
            hasRawBorderInfo: nextRawBorderInfo != null,
          ),
        );
      }
      _closeTransientMenus();
    });
  }

  List<FortuneBorderInfo> _clearFormatBorderInfoForRange(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    final nextBorderInfo = <FortuneBorderInfo>[];
    for (final border in sheet.borderInfo) {
      if (border.rangeType == 'cell') {
        final firstRange = border.ranges.firstOrNull;
        if (firstRange == null || !_rangeStartInRange(firstRange, range)) {
          nextBorderInfo.add(border.copyWith());
        }
        continue;
      }
      if (border.rangeType != 'range') {
        nextBorderInfo.add(border.copyWith());
        continue;
      }
      if (border.borderType == 'border-slash') {
        final firstRange = border.ranges.firstOrNull;
        if (firstRange == null || !_rangeStartInRange(firstRange, range)) {
          nextBorderInfo.add(border.copyWith());
        }
        continue;
      }
      final ranges = <FortuneRange>[];
      for (final borderRange in border.ranges) {
        ranges.addAll(cfSplitRange(borderRange, range, range, 'restPart'));
      }
      if (ranges.isNotEmpty) {
        nextBorderInfo.add(border.copyWith(ranges: ranges));
      }
    }
    return nextBorderInfo;
  }

  Object? _clearFormatRawBorderInfoForRange(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    if (!sheet.hasRawBorderInfo || sheet.rawBorderInfo is! List) {
      return sheet.rawBorderInfo == null
          ? null
          : cloneFortuneMetadata(sheet.rawBorderInfo);
    }
    final next = <Object?>[];
    for (final item in sheet.rawBorderInfo! as List) {
      if (item is! Map) {
        next.add(cloneFortuneMetadata(item));
        continue;
      }
      final map = Map<Object?, Object?>.from(cloneFortuneMetadata(item) as Map);
      final rangeType = map['rangeType']?.toString();
      if (rangeType == 'cell') {
        final value = map['value'];
        final row = value is Map ? _intValue(value['row_index']) : null;
        final column = value is Map ? _intValue(value['col_index']) : null;
        if (row == null ||
            column == null ||
            row < range.rowStart ||
            row > range.rowEnd ||
            column < range.columnStart ||
            column > range.columnEnd) {
          next.add(map);
        }
        continue;
      }
      if (rangeType == 'range' && map['borderType'] == 'border-slash') {
        final firstRange = _rawBorderRanges(map['range']).firstOrNull;
        if (firstRange == null || !_rangeStartInRange(firstRange, range)) {
          next.add(map);
        }
        continue;
      }
      if (rangeType == 'range') {
        final ranges = <FortuneRange>[];
        for (final borderRange in _rawBorderRanges(map['range'])) {
          ranges.addAll(cfSplitRange(borderRange, range, range, 'restPart'));
        }
        if (ranges.isNotEmpty) {
          map['range'] = [for (final split in ranges) _rawBorderRange(split)];
          next.add(map);
        }
        continue;
      }
      next.add(map);
    }
    return next.isEmpty ? null : next;
  }

  Object? _rawBorderInfoWithoutRanges(
    Object? rawBorderInfo,
    Iterable<FortuneRange> ranges,
  ) {
    var current = rawBorderInfo;
    for (final range in ranges) {
      current = _rawBorderInfoWithoutRange(current, range);
    }
    return current;
  }

  Object? _rawBorderInfoWithoutRange(
    Object? rawBorderInfo,
    FortuneRange range,
  ) {
    if (rawBorderInfo is! List) {
      return rawBorderInfo == null ? null : cloneFortuneMetadata(rawBorderInfo);
    }
    final next = <Object?>[];
    for (final item in rawBorderInfo) {
      if (item is! Map) {
        next.add(cloneFortuneMetadata(item));
        continue;
      }
      final map = Map<Object?, Object?>.from(cloneFortuneMetadata(item) as Map);
      final rangeType = map['rangeType']?.toString();
      if (rangeType == 'cell') {
        final value = map['value'];
        final row = value is Map ? _intValue(value['row_index']) : null;
        final column = value is Map ? _intValue(value['col_index']) : null;
        if (row == null ||
            column == null ||
            row < range.rowStart ||
            row > range.rowEnd ||
            column < range.columnStart ||
            column > range.columnEnd) {
          next.add(map);
        }
        continue;
      }
      if (rangeType == 'range') {
        final ranges = <FortuneRange>[];
        for (final borderRange in _rawBorderRanges(map['range'])) {
          ranges.addAll(cfSplitRange(borderRange, range, range, 'restPart'));
        }
        if (ranges.isNotEmpty) {
          map['range'] = [for (final split in ranges) _rawBorderRange(split)];
          next.add(map);
        }
        continue;
      }
      next.add(map);
    }
    return next;
  }

  List<FortuneRange> _rawBorderRanges(Object? raw) {
    if (raw is! List) {
      return const [];
    }
    final ranges = <FortuneRange>[];
    for (final item in raw) {
      if (item is! Map) {
        continue;
      }
      final row = _rawBorderAxis(item['row']);
      final column = _rawBorderAxis(item['column']);
      if (row == null || column == null) {
        continue;
      }
      ranges.add(
        FortuneRange(
          rowStart: row.$1,
          rowEnd: row.$2,
          columnStart: column.$1,
          columnEnd: column.$2,
        ),
      );
    }
    return ranges;
  }

  (int, int)? _rawBorderAxis(Object? raw) {
    if (raw is! List || raw.length < 2) {
      return null;
    }
    final start = _intValue(raw[0]);
    final end = _intValue(raw[1]);
    if (start == null || end == null) {
      return null;
    }
    return (math.min(start, end), math.max(start, end));
  }

  Map<String, Object?> _rawBorderRange(FortuneRange range) {
    return {
      'row': [range.rowStart, range.rowEnd],
      'column': [range.columnStart, range.columnEnd],
    };
  }

  bool _rangeStartInRange(FortuneRange range, FortuneRange container) {
    return range.rowStart >= container.rowStart &&
        range.rowStart <= container.rowEnd &&
        range.columnStart >= container.columnStart &&
        range.columnStart <= container.columnEnd;
  }

  FortuneCell _cellWithClearedFormat(FortuneCell cell) {
    return FortuneCell(
      value: cell.inlineRuns == null ? cell.value : cell.renderedText,
      rawValue: cell.inlineRuns == null ? cell.rawValue : cell.renderedText,
      hasRawValue: cell.inlineRuns == null ? cell.hasRawValue : true,
      displayValue: cell.inlineRuns == null ? cell.displayValue : null,
      rawDisplayValue: cell.inlineRuns == null ? cell.rawDisplayValue : null,
      hasRawDisplayValue: cell.inlineRuns == null
          ? cell.hasRawDisplayValue
          : false,
      formula: cell.formula,
      merge: cell.merge,
      cellType: cell.cellType,
      quotePrefix: cell.quotePrefix,
      sparkline: cell.sparkline,
      locked: cell.locked,
      comment: cell.comment,
      hyperlink: cell.hyperlink,
      extraFields: cell.extraFields,
    );
  }

  void _toggleSelectedCellHyperlink() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    _showHyperlinkDialog(coord);
  }

  void _toggleSelectedCellHyperlinkMetadata() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    final previous = sheet.cells[coord] ?? const FortuneCell();
    final nextHyperlink = previous.hyperlink == null
        ? FortuneHyperlink(
            row: coord.row,
            column: coord.column,
            linkType: 'webpage',
            linkAddress: _linkAddressForCell(previous),
          )
        : null;
    _recordUndoSnapshot();
    setState(() {
      _setCellHyperlink(sheet, coord, previous, nextHyperlink);
      _closeTransientMenus();
    });
  }

  bool get _hyperlinkDialogOpen => _hyperlinkDialogCoord != null;

  void _showHyperlinkDialog(FortuneCellCoord coord) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    final cell = sheet.cells[anchor] ?? const FortuneCell();
    final address = cell.hyperlink?.linkAddress ?? _linkAddressForCell(cell);
    final display = cell.renderedText.trim();
    final linkType = _normalizedHyperlinkDialogType(cell.hyperlink?.linkType);
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _editingCoord = null;
      _editingCommentCoord = null;
      _editingFormulaBar = false;
      _customSortDialogOpen = false;
      _axisSizeDialogAxis = null;
      _axisSizeDialogIndex = null;
      _dataVerificationDialogCoord = null;
      _dataVerificationDialogRange = null;
      _dataVerificationDialogSelectingRange = false;
      _dataVerificationDialogRangeEdited = false;
      _dataVerificationDialogRangeSelectionAnchor = null;
      _dataVerificationDialogRangeSelectionTarget = null;
      _dataVerificationRangeEditorController.clear();
      _conditionRuleDialogOpen = false;
      _formulaSearchDialogOpen = false;
      _formulaSearchCategoryMenuOpen = false;
      _hyperlinkDialogCoord = anchor;
      _hyperlinkDialogLinkType = linkType;
      _hyperlinkDialogSelectingCellRange = false;
      _hyperlinkDialogRangeSelectionOriginAddress = null;
      _hyperlinkDialogRangeSelectionAnchor = null;
      _hyperlinkDisplayEditorController.value = TextEditingValue(
        text: display,
        selection: TextSelection.collapsed(offset: display.length),
      );
      _hyperlinkAddressEditorController.value = TextEditingValue(
        text: address,
        selection: TextSelection.collapsed(offset: address.length),
      );
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _hyperlinkDialogOpen) {
        _hyperlinkDisplayEditorFocusNode.requestFocus();
      }
    });
  }

  String _linkAddressForCell(FortuneCell cell) {
    final text = cell.renderedText.trim();
    if (text.startsWith('http://') || text.startsWith('https://')) {
      return text;
    }
    return 'https://';
  }

  String _normalizedHyperlinkDialogType(String? type) {
    return switch (type?.trim()) {
      'cellrange' => 'cellrange',
      'sheet' => 'sheet',
      _ => 'webpage',
    };
  }

  Rect? _hyperlinkDialogRect([Size? overrideSize]) {
    final coord = _hyperlinkDialogCoord;
    if (coord == null) {
      return null;
    }
    final cellRect = _cellRectForCoord(coord);
    final size = overrideSize ?? context.size;
    if (cellRect == null || size == null) {
      return null;
    }
    return _hyperlinkDialogSelectingCellRange
        ? fortuneHyperlinkRangeSelectionDialogRect(size, cellRect)
        : fortuneHyperlinkDialogRect(size, cellRect);
  }

  Rect? _hyperlinkDialogDisplayInputRect([Size? overrideSize]) {
    final rect = _hyperlinkDialogRect(overrideSize);
    if (rect == null || _hyperlinkDialogSelectingCellRange) {
      return null;
    }
    return fortuneHyperlinkDialogDisplayInputRect(rect);
  }

  Rect? _hyperlinkDialogAddressEditorRect([Size? overrideSize]) {
    final rect = _hyperlinkDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    if (_hyperlinkDialogSelectingCellRange) {
      return fortuneHyperlinkRangeSelectionInputRect(rect);
    }
    return _hyperlinkDialogLinkType == 'cellrange'
        ? fortuneHyperlinkDialogCellRangeInputTextRect(rect)
        : fortuneHyperlinkDialogAddressInputRect(rect);
  }

  Rect? _hyperlinkDialogCellSelectorRect([Size? overrideSize]) {
    final rect = _hyperlinkDialogRect(overrideSize);
    if (rect == null ||
        _hyperlinkDialogSelectingCellRange ||
        _hyperlinkDialogLinkType != 'cellrange') {
      return null;
    }
    return fortuneHyperlinkDialogCellSelectorRect(rect);
  }

  void _startHyperlinkDialogRangeSelection(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final coord = _cellCoordAtLocal(local, settings, metrics);
    if (coord == null || !_canSelectCell(_workbook.activeSheet, coord)) {
      return;
    }
    _hyperlinkDialogRangeSelectionAnchor = coord;
    _applyHyperlinkDialogRangeSelection(coord, coord);
  }

  bool _updateHyperlinkDialogRangeSelection(PointerMoveEvent event) {
    final anchor = _hyperlinkDialogRangeSelectionAnchor;
    if (anchor == null || !_hyperlinkDialogOpen) {
      return false;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final nextScrollOffset = _autoScrollOffsetForDrag(
      event.localPosition,
      settings,
      metrics,
    );
    final coord = _cellCoordAtLocal(
      event.localPosition,
      settings,
      metrics,
      scrollOverride: nextScrollOffset,
    );
    if (coord == null) {
      return true;
    }
    if (!_canSelectCell(_workbook.activeSheet, coord)) {
      _cancelHyperlinkDialogRangeSelection();
      return true;
    }
    _applyHyperlinkDialogRangeSelection(
      anchor,
      coord,
      nextScrollOffset: nextScrollOffset,
    );
    return true;
  }

  bool _commitHyperlinkDialogRangeSelection() {
    if (_hyperlinkDialogRangeSelectionAnchor == null) {
      return false;
    }
    _hyperlinkDialogRangeSelectionAnchor = null;
    return true;
  }

  void _cancelHyperlinkDialogRangeSelection() {
    _hyperlinkDialogRangeSelectionAnchor = null;
  }

  void _applyHyperlinkDialogRangeSelection(
    FortuneCellCoord anchor,
    FortuneCellCoord extent, {
    Offset? nextScrollOffset,
  }) {
    final range = _expandRangeForMergedCells(
      FortuneRange(
        rowStart: math.min(anchor.row, extent.row),
        rowEnd: math.max(anchor.row, extent.row),
        columnStart: math.min(anchor.column, extent.column),
        columnEnd: math.max(anchor.column, extent.column),
      ),
    );
    final address = getRangetxt(
      _workbook,
      _workbook.activeSheet.id,
      range,
      currentSheetId: _workbook.activeSheet.id,
    );
    setState(() {
      if (nextScrollOffset != null) {
        scrollOffset = nextScrollOffset;
      }
      selection = FortuneSelection(
        row: anchor.row,
        column: anchor.column,
        rowEnd: extent.row,
        columnEnd: extent.column,
      );
      _writeSelectionRange(range, anchor);
      _hyperlinkAddressEditorController.value = TextEditingValue(
        text: address,
        selection: TextSelection.collapsed(offset: address.length),
      );
    });
  }

  ({FortuneCellCoord coord, String type, String address})?
  _selectedHyperlinkFields() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final cellLink = sheet.cells[coord]?.hyperlink;
    if (cellLink != null) {
      return (
        coord: coord,
        type: cellLink.linkType ?? 'webpage',
        address: cellLink.linkAddress ?? '',
      );
    }
    final rawLink = sheet.hyperlinks['${coord.row}_${coord.column}'];
    if (rawLink is Map) {
      return (
        coord: coord,
        type: '${rawLink['linkType'] ?? 'webpage'}',
        address: '${rawLink['linkAddress'] ?? ''}',
      );
    }
    return null;
  }

  Rect? _hyperlinkCardRect([Size? overrideSize]) {
    final link = _selectedHyperlinkFields();
    if (link == null || _hyperlinkDialogOpen) {
      return null;
    }
    final cellRect = _cellRectForCoord(link.coord);
    final size = overrideSize ?? context.size;
    if (cellRect == null || size == null) {
      return null;
    }
    return fortuneHyperlinkCardRect(
      size,
      cellRect,
      allowEdit: _workbook.settings.allowEdit,
      showCopy: link.type == 'webpage',
    );
  }

  String? _hyperlinkCardCommandAt(Offset local) {
    final rect = _hyperlinkCardRect();
    final link = _selectedHyperlinkFields();
    if (rect == null || link == null || !rect.contains(local)) {
      return null;
    }
    final showCopy = link.type == 'webpage';
    if (fortuneHyperlinkCardContentRect(rect).contains(local)) {
      return 'open';
    }
    if (!_workbook.settings.allowEdit) {
      return null;
    }
    if (showCopy && fortuneHyperlinkCardCopyButtonRect(rect).contains(local)) {
      return 'copy';
    }
    if (fortuneHyperlinkCardEditButtonRect(
      rect,
      showCopy: showCopy,
    ).contains(local)) {
      return 'edit';
    }
    if (fortuneHyperlinkCardUnlinkButtonRect(
      rect,
      showCopy: showCopy,
    ).contains(local)) {
      return 'unlink';
    }
    return null;
  }

  void _activateHyperlinkCardCommand(String command) {
    final link = _selectedHyperlinkFields();
    if (link == null) {
      return;
    }
    if (command == 'copy') {
      Clipboard.setData(ClipboardData(text: link.address));
      return;
    }
    if (command == 'edit') {
      _showHyperlinkDialog(link.coord);
      return;
    }
    if (command == 'unlink') {
      _removeSelectedHyperlink(link.coord);
      return;
    }
    if (command == 'open') {
      _goToSelectedHyperlink(link);
    }
  }

  void _removeSelectedHyperlink(FortuneCellCoord coord) {
    final sheet = _workbook.activeSheet;
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    final nextSheet = removeHyperlink(
      sheet,
      coord.row,
      coord.column,
      allowEdit: _workbook.settings.allowEdit,
    );
    if (identical(nextSheet, sheet)) {
      return;
    }
    _recordUndoSnapshot();
    setState(() {
      _replaceActiveSheet(nextSheet);
      _closeTransientMenus();
    });
  }

  void _goToSelectedHyperlink(
    ({FortuneCellCoord coord, String type, String address}) link,
  ) {
    final action = goToLink(
      _workbook,
      _workbook.activeSheet.id,
      link.coord.row,
      link.coord.column,
      link.type,
      link.address,
    );
    if (action == null || action['type'] == 'webpage') {
      return;
    }
    final sheetId = action['sheetId'];
    final sheetIndex = _workbook.sheets.indexWhere(
      (sheet) => sheet.id == sheetId,
    );
    final selectionValue = action['selection'];
    setState(() {
      if (sheetIndex != -1) {
        _workbook = _workbook.copyWith(activeSheetIndex: sheetIndex);
      }
      if (action['scrollLeft'] is num || action['scrollTop'] is num) {
        scrollOffset = Offset(
          (action['scrollLeft'] as num?)?.toDouble() ?? scrollOffset.dx,
          (action['scrollTop'] as num?)?.toDouble() ?? scrollOffset.dy,
        );
      }
      if (selectionValue is List<FortuneRange> && selectionValue.isNotEmpty) {
        final focus = FortuneCellCoord(
          selectionValue.first.rowStart,
          selectionValue.first.columnStart,
        );
        _writeSelectionRanges(selectionValue, focus);
        selection = FortuneSelection(row: focus.row, column: focus.column);
      }
      _closeTransientMenus();
    });
  }

  String? _hyperlinkDialogCommandAt(Offset local) {
    final rect = _hyperlinkDialogRect();
    if (rect == null || !rect.contains(local)) {
      return 'cancel';
    }
    if (_hyperlinkDialogSelectingCellRange) {
      if (fortuneHyperlinkRangeSelectionCloseButtonRect(rect).contains(local)) {
        return 'close-range-selection';
      }
      if (fortuneHyperlinkRangeSelectionInputRect(rect).contains(local)) {
        return 'address-input';
      }
      if (fortuneHyperlinkRangeSelectionCancelButtonRect(
        rect,
      ).contains(local)) {
        return 'cancel-range-selection';
      }
      if (fortuneHyperlinkRangeSelectionOkButtonRect(rect).contains(local)) {
        return 'confirm-range-selection';
      }
      return 'modal';
    }
    if (fortuneHyperlinkDialogDisplayInputRect(rect).contains(local)) {
      return 'display-input';
    }
    if (_hyperlinkDialogCellSelectorRect()?.contains(local) == true) {
      return 'cell-selector';
    }
    if ((_hyperlinkDialogAddressEditorRect() ??
            fortuneHyperlinkDialogAddressInputRect(rect))
        .contains(local)) {
      return 'address-input';
    }
    if (fortuneHyperlinkDialogTypeSelectRect(rect).contains(local)) {
      return 'type-select';
    }
    if (fortuneHyperlinkDialogCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (fortuneHyperlinkDialogOkButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    return 'modal';
  }

  void _activateHyperlinkDialogCommand(String? command) {
    if (command == null || command == 'modal') {
      return;
    }
    if (command == 'display-input') {
      _hyperlinkDisplayEditorFocusNode.requestFocus();
      return;
    }
    if (command == 'address-input') {
      _hyperlinkAddressEditorFocusNode.requestFocus();
      return;
    }
    if (command == 'type-select') {
      _cycleHyperlinkDialogLinkType();
      return;
    }
    if (command == 'cell-selector') {
      setState(() {
        _hyperlinkDialogSelectingCellRange = true;
        _hyperlinkDialogRangeSelectionOriginAddress =
            _hyperlinkAddressEditorController.text;
        _hyperlinkDialogRangeSelectionAnchor = null;
      });
      _focusNode.requestFocus();
      return;
    }
    if (command == 'confirm-range-selection') {
      _confirmHyperlinkDialogRangeSelection();
      return;
    }
    if (command == 'cancel-range-selection') {
      _cancelHyperlinkDialogRangeSelectionModal();
      return;
    }
    if (command == 'close-range-selection') {
      _closeHyperlinkDialogRangeSelection();
      return;
    }
    if (command == 'confirm') {
      _commitHyperlinkDialog();
      return;
    }
    setState(() {
      _hyperlinkDialogCoord = null;
      _hyperlinkDialogLinkType = 'webpage';
      _hyperlinkDialogSelectingCellRange = false;
      _hyperlinkDialogRangeSelectionOriginAddress = null;
      _hyperlinkDialogRangeSelectionAnchor = null;
    });
    _focusNode.requestFocus();
  }

  void _cycleHyperlinkDialogLinkType() {
    final nextType = switch (_hyperlinkDialogLinkType) {
      'webpage' => 'cellrange',
      'cellrange' => 'sheet',
      _ => 'webpage',
    };
    final nextAddress = nextType == 'sheet' && _workbook.sheets.isNotEmpty
        ? _workbook.sheets.first.name
        : '';
    setState(() {
      _hyperlinkDialogLinkType = nextType;
      _hyperlinkDialogSelectingCellRange = nextType == 'cellrange';
      _hyperlinkDialogRangeSelectionOriginAddress = nextType == 'cellrange'
          ? _hyperlinkAddressEditorController.text
          : null;
      _hyperlinkDialogRangeSelectionAnchor = null;
      _hyperlinkAddressEditorController.value = TextEditingValue(
        text: nextAddress,
        selection: TextSelection.collapsed(offset: nextAddress.length),
      );
    });
    _hyperlinkAddressEditorFocusNode.requestFocus();
  }

  bool _confirmHyperlinkDialogRangeSelection() {
    if (!_isValidHyperlinkCellRange(_hyperlinkAddressEditorController.text)) {
      _hyperlinkAddressEditorFocusNode.requestFocus();
      return false;
    }
    setState(() {
      _hyperlinkDialogSelectingCellRange = false;
      _hyperlinkDialogRangeSelectionOriginAddress = null;
      _hyperlinkDialogRangeSelectionAnchor = null;
    });
    _hyperlinkAddressEditorFocusNode.requestFocus();
    return true;
  }

  void _cancelHyperlinkDialogRangeSelectionModal() {
    final origin = _hyperlinkDialogRangeSelectionOriginAddress;
    setState(() {
      if (origin != null) {
        _hyperlinkAddressEditorController.value = TextEditingValue(
          text: origin,
          selection: TextSelection.collapsed(offset: origin.length),
        );
      }
      _hyperlinkDialogSelectingCellRange = false;
      _hyperlinkDialogRangeSelectionOriginAddress = null;
      _hyperlinkDialogRangeSelectionAnchor = null;
    });
    _hyperlinkAddressEditorFocusNode.requestFocus();
  }

  void _closeHyperlinkDialogRangeSelection() {
    setState(() {
      _hyperlinkDialogSelectingCellRange = false;
      _hyperlinkDialogRangeSelectionOriginAddress = null;
      _hyperlinkDialogRangeSelectionAnchor = null;
    });
    _hyperlinkAddressEditorFocusNode.requestFocus();
  }

  void _commitHyperlinkDialog() {
    final coord = _hyperlinkDialogCoord;
    if (coord == null) {
      return;
    }
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    final address = _hyperlinkAddressEditorController.text.trim();
    if (address.isEmpty) {
      _hyperlinkAddressEditorFocusNode.requestFocus();
      return;
    }
    final displayText = _hyperlinkDisplayEditorController.text.trim();
    final text = displayText.isEmpty ? address : displayText;
    final previous = sheet.cells[anchor] ?? const FortuneCell();
    final currentLink = previous.hyperlink;
    final linkType = _normalizedHyperlinkDialogType(_hyperlinkDialogLinkType);
    if (linkType == 'webpage' && !_isValidHyperlinkWebpage(address)) {
      _hyperlinkAddressEditorFocusNode.requestFocus();
      return;
    }
    if (linkType == 'cellrange' && !_isValidHyperlinkCellRange(address)) {
      _hyperlinkAddressEditorFocusNode.requestFocus();
      return;
    }
    final nextLink = (currentLink ?? const FortuneHyperlink()).copyWith(
      row: anchor.row,
      column: anchor.column,
      id: sheet.id,
      linkType: linkType,
      linkAddress: address,
    );
    final nextCell = previous
        .withEditedValue(text)
        .copyWith(
          foreground: const Color(0xff0000ff),
          underline: true,
          hyperlink: nextLink,
        );
    if (_cellWouldChange(sheet, anchor, nextCell) ||
        _sheetHyperlinkWouldChange(sheet, anchor, nextLink)) {
      _recordUndoSnapshot();
    }
    setState(() {
      _setSheetCell(sheet, anchor, nextCell);
      final key = _cellKey(anchor);
      sheet.hyperlinks[key] = {'linkType': linkType, 'linkAddress': address};
      _replaceActiveSheet(
        sheet.copyWith(cells: sheet.cells, hyperlinks: sheet.hyperlinks),
      );
      _hyperlinkDialogCoord = null;
      _hyperlinkDialogLinkType = 'webpage';
      _hyperlinkDialogSelectingCellRange = false;
      _hyperlinkDialogRangeSelectionOriginAddress = null;
      _hyperlinkDialogRangeSelectionAnchor = null;
    });
    _focusNode.requestFocus();
  }

  bool _isValidHyperlinkWebpage(String address) {
    final normalized = address.trim().startsWith(RegExp(r'https?://'))
        ? address.trim()
        : 'https://${address.trim()}';
    return RegExp(
      r'^https?:\/\/([\w\-\.]+)+[\w-]*([\w\-\.\/\?%&=]+)?$',
      caseSensitive: false,
    ).hasMatch(normalized);
  }

  bool _isValidHyperlinkCellRange(String address) {
    return iscelldata(address.trim());
  }

  void _toggleSelectedCellComment() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    final previous = sheet.cells[coord] ?? const FortuneCell();
    final creatingComment = previous.comment == null;
    final nextComment = creatingComment
        ? const FortuneCellComment(value: '')
        : null;
    if (creatingComment) {
      if (_workbook.settings.beforeInsertComment?.call(
            coord.row,
            coord.column,
          ) ==
          false) {
        setState(_closeTransientMenus);
        return;
      }
    } else if (_workbook.settings.beforeDeleteComment?.call(
          coord.row,
          coord.column,
        ) ==
        false) {
      setState(_closeTransientMenus);
      return;
    }
    final draftUndoSnapshot = creatingComment
        ? _currentHistorySnapshot()
        : null;
    if (!creatingComment) {
      _recordUndoSnapshot();
    }
    setState(() {
      _setSheetCell(sheet, coord, _cellWithComment(previous, nextComment));
      _closeTransientMenus();
    });
    if (creatingComment) {
      _workbook.settings.afterInsertComment?.call(coord.row, coord.column);
      _startCommentEditing(coord, draftUndoSnapshot: draftUndoSnapshot);
    } else {
      _workbook.settings.afterDeleteComment?.call(coord.row, coord.column);
    }
  }

  void _insertSelectedCellComment() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    final previous = sheet.cells[coord] ?? const FortuneCell();
    if (previous.comment != null) {
      setState(_closeTransientMenus);
      _startCommentEditing(coord);
      return;
    }
    if (_workbook.settings.beforeInsertComment?.call(coord.row, coord.column) ==
        false) {
      setState(_closeTransientMenus);
      return;
    }
    final next = _cellWithComment(
      previous,
      const FortuneCellComment(value: ''),
    );
    final draftUndoSnapshot = _cellWouldChange(sheet, coord, next)
        ? _currentHistorySnapshot()
        : null;
    setState(() {
      _setSheetCell(sheet, coord, next);
      _closeTransientMenus();
    });
    _workbook.settings.afterInsertComment?.call(coord.row, coord.column);
    _startCommentEditing(coord, draftUndoSnapshot: draftUndoSnapshot);
  }

  void _editSelectedCellComment() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (sheet.cells[coord]?.comment == null || !_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    setState(_closeTransientMenus);
    _startCommentEditing(coord);
  }

  void _deleteSelectedCellComment() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    final previous = sheet.cells[coord] ?? const FortuneCell();
    if (previous.comment == null) {
      setState(_closeTransientMenus);
      return;
    }
    if (_workbook.settings.beforeDeleteComment?.call(coord.row, coord.column) ==
        false) {
      setState(_closeTransientMenus);
      return;
    }
    final next = _cellWithComment(previous, null);
    _recordUndoSnapshot();
    setState(() {
      _setSheetCell(sheet, coord, next);
      _closeTransientMenus();
    });
    _workbook.settings.afterDeleteComment?.call(coord.row, coord.column);
  }

  void _toggleSelectedCellCommentVisibility() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    final previous = sheet.cells[coord] ?? const FortuneCell();
    final comment = previous.comment;
    if (comment == null) {
      setState(_closeTransientMenus);
      return;
    }
    final next = _cellWithComment(
      previous,
      comment.copyWith(isShow: !comment.isShow),
    );
    _recordUndoSnapshot();
    setState(() {
      _setSheetCell(sheet, coord, next);
      _closeTransientMenus();
    });
  }

  void _toggleAllCommentVisibility() {
    final sheet = _workbook.activeSheet;
    final commentEntries = sheet.cells.entries.where(
      (entry) => entry.value.comment != null && _canEditCell(sheet, entry.key),
    );
    final entries = commentEntries.toList();
    if (entries.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    final shouldShow = entries.any((entry) => !entry.value.comment!.isShow);
    final updates = <MapEntry<FortuneCellCoord, FortuneCell>>[];
    for (final entry in entries) {
      final comment = entry.value.comment!;
      if (comment.isShow == shouldShow) {
        continue;
      }
      updates.add(
        MapEntry(
          entry.key,
          _cellWithComment(entry.value, comment.copyWith(isShow: shouldShow)),
        ),
      );
    }
    if (updates.isNotEmpty) {
      _recordUndoSnapshot();
    }
    setState(() {
      for (final update in updates) {
        _setSheetCell(sheet, update.key, update.value);
      }
      _closeTransientMenus();
    });
  }

  FortuneCell _cellWithHyperlink(FortuneCell cell, FortuneHyperlink? link) {
    if (link != null) {
      return cell.copyWith(
        foreground: const Color(0xff0000ff),
        underline: true,
        hyperlink: link,
      );
    }
    var nextCell = cell.copyWith(hyperlink: null);
    if (cell.hyperlink != null &&
        cell.foreground == const Color(0xff0000ff) &&
        cell.underline) {
      nextCell = nextCell.copyWith(
        foreground: const Color(0xff000000),
        rawForeground: null,
        hasRawForeground: false,
        underline: false,
        rawUnderline: null,
        hasRawUnderline: false,
      );
    }
    return nextCell;
  }

  void _setCellHyperlink(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell previous,
    FortuneHyperlink? link,
  ) {
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      return;
    }
    final base = anchor == coord
        ? previous
        : sheet.cells[anchor] ?? const FortuneCell();
    final nextLink = link?.copyWith(
      row: anchor.row,
      column: anchor.column,
      id: sheet.id,
    );
    _setSheetCell(sheet, anchor, _cellWithHyperlink(base, nextLink));
    final key = '${anchor.row}_${anchor.column}';
    if (link == null) {
      sheet.hyperlinks.remove(key);
    } else {
      sheet.hyperlinks[key] = {
        'linkType': nextLink?.linkType ?? 'webpage',
        'linkAddress': nextLink?.linkAddress ?? '',
      };
    }
    _replaceActiveSheet(
      sheet.copyWith(cells: sheet.cells, hyperlinks: sheet.hyperlinks),
    );
  }

  FortuneCell _cellWithComment(FortuneCell cell, FortuneCellComment? comment) {
    return cell.copyWith(comment: comment);
  }

  void _toggleSelectedColumnFilter() {
    final sheet = _workbook.activeSheet;
    final column = selection.column;
    final key = _filterKeyForColumn(sheet, column);
    _setSelectedColumnFilterEnabled(!sheet.filter.containsKey(key));
  }

  void _setSelectedColumnFilterEnabled(bool enabled) {
    final sheet = _workbook.activeSheet;
    if (!_canEditFilterCommand(sheet)) {
      setState(_closeTransientMenus);
      return;
    }
    final column = selection.column;
    final key = _filterKeyForColumn(sheet, column);
    final filter = Map<String, Object?>.from(sheet.filter);
    final hiddenRows = Set<int>.from(sheet.hiddenRows);
    final hiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues);
    if (enabled) {
      filter[key] = {
        'rangeType': 'column',
        'row': [0, _workbook.settings.row - 1],
        'column': [column, column],
        'column_focus': column,
      };
    } else {
      for (final row in _filterHiddenRowsForEntry(sheet, key, filter[key])) {
        hiddenRows.remove(row);
        hiddenRowValues.remove(row);
      }
      filter.remove(key);
    }
    final changed =
        !_jsonLikeEquals(sheet.filter, filter) ||
        !_intSetEquals(sheet.hiddenRows, hiddenRows) ||
        !_jsonLikeEquals(sheet.hiddenRowValues, hiddenRowValues);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          filter: filter,
          hiddenRows: hiddenRows,
          hiddenRowValues: hiddenRowValues,
          filterSelect: filter.isEmpty ? null : sheet.filterSelect,
          hasRawFilterSelect: filter.isEmpty ? false : sheet.hasRawFilterSelect,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _closeTransientMenus();
    });
  }

  void _clearAllFilters() {
    final sheet = _workbook.activeSheet;
    if (!_canEditFilterCommand(sheet)) {
      setState(_closeTransientMenus);
      return;
    }
    final hiddenRows = Set<int>.from(sheet.hiddenRows);
    final hiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues);
    for (final row in _filterHiddenRows(sheet)) {
      hiddenRows.remove(row);
      hiddenRowValues.remove(row);
    }
    final changed =
        sheet.filter.isNotEmpty ||
        sheet.filterSelect != null ||
        sheet.hasRawFilterSelect ||
        !_intSetEquals(sheet.hiddenRows, hiddenRows) ||
        !_jsonLikeEquals(sheet.hiddenRowValues, hiddenRowValues);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          filter: const {},
          hiddenRows: hiddenRows,
          hiddenRowValues: hiddenRowValues,
          filterSelect: null,
          hasRawFilterSelect: false,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _closeTransientMenus();
    });
  }

  void _createFilterForSelection() {
    final sheet = _workbook.activeSheet;
    if (!_canEditFilterCommand(sheet)) {
      setState(_closeTransientMenus);
      return;
    }
    if (_rawSelectionRanges(sheet).length > 1) {
      setState(_closeTransientMenus);
      return;
    }
    if (sheet.filter.isNotEmpty || sheet.filterSelect != null) {
      _clearAllFilters();
      return;
    }
    if (sheet.isPivotTable == true) {
      setState(_closeTransientMenus);
      return;
    }
    final range = _filterCreationRange(sheet);
    if (range == null) {
      setState(_closeTransientMenus);
      return;
    }
    final focus = FortuneCellCoord(range.rowStart, range.columnStart);
    final rawRange = _selectionRangeMetadata(range, focus);
    _recordUndoSnapshot();
    setState(() {
      final sheets = [..._workbook.sheets];
      sheets[_workbook.activeSheetIndex] = sheet.copyWith(
        filterSelect: Map<String, Object?>.from(rawRange),
        hasRawFilterSelect: true,
        selectionSave: [Map<String, Object?>.from(rawRange)],
        hasRawSelectionSave: true,
        selectionRange: [Map<String, Object?>.from(rawRange)],
        hasRawSelectionRange: true,
      );
      _workbook = _workbook.copyWith(sheets: sheets);
      selection = FortuneSelection(
        row: range.rowStart,
        column: range.columnStart,
        rowEnd: range.rowEnd,
        columnEnd: range.columnEnd,
      );
      _closeTransientMenus();
    });
  }

  FortuneRange? _filterCreationRange(FortuneSheet sheet) {
    var range = _currentSelectionRange(sheet);
    if (range.rowStart != range.rowEnd ||
        range.columnStart != range.columnEnd) {
      return _extendFilterCreationRangeDown(sheet, range);
    }
    final row = range.rowStart;
    int? columnStart;
    int? columnEnd;
    final columnCount = _effectiveColumnCount(sheet);
    for (var column = 0; column < columnCount; column += 1) {
      final hasValue = _filterCellHasValue(sheet, row, column);
      if (hasValue) {
        columnStart ??= column;
      } else if (columnStart != null) {
        columnEnd = column - 1;
        break;
      }
    }
    if (columnStart == null) {
      return range;
    }
    columnEnd ??= columnCount - 1;
    range = FortuneRange(
      rowStart: row,
      rowEnd: row,
      columnStart: columnStart,
      columnEnd: columnEnd,
    );
    return _extendFilterCreationRangeDown(sheet, range);
  }

  FortuneRange _extendFilterCreationRangeDown(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    if (range.rowEnd - range.rowStart >= 2) {
      return range;
    }
    var rowEnd = range.rowEnd;
    final rowCount = _effectiveRowCount(sheet);
    for (var row = range.rowEnd + 1; row < rowCount; row += 1) {
      var rowHasValue = false;
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (_filterCellHasValue(sheet, row, column)) {
          rowHasValue = true;
          break;
        }
      }
      if (!rowHasValue) {
        break;
      }
      rowEnd = row;
    }
    if (rowEnd == range.rowEnd) {
      return range;
    }
    return FortuneRange(
      rowStart: range.rowStart,
      rowEnd: rowEnd,
      columnStart: range.columnStart,
      columnEnd: range.columnEnd,
    );
  }

  bool _filterCellHasValue(FortuneSheet sheet, int row, int column) {
    final cell = sheet.cells[FortuneCellCoord(row, column)];
    if (cell == null) {
      return false;
    }
    return cell.renderedText.trim().isNotEmpty;
  }

  Map<String, Object?> _selectionRangeMetadata(
    FortuneRange range,
    FortuneCellCoord focus,
  ) {
    return <String, Object?>{
      'row': [range.rowStart, range.rowEnd],
      'column': [range.columnStart, range.columnEnd],
      'row_focus': focus.row,
      'column_focus': focus.column,
    };
  }

  Set<int> _filterHiddenRows(FortuneSheet sheet, {String? exceptKey}) {
    final rows = <int>{};
    for (final entry in sheet.filter.entries) {
      if (entry.key == exceptKey) {
        continue;
      }
      rows.addAll(_filterHiddenRowsForEntry(sheet, entry.key, entry.value));
    }
    return rows;
  }

  Set<int> _filterHiddenRowsForEntry(
    FortuneSheet sheet,
    String key,
    Object? raw,
  ) {
    if (raw is! Map) {
      return const {};
    }
    final rowhidden = raw['rowhidden'];
    final parsed = <int>{};
    if (rowhidden is Map) {
      for (final entry in rowhidden.entries) {
        final row = entry.key is int
            ? entry.key as int
            : int.tryParse('${entry.key}');
        if (row != null) {
          parsed.add(row);
        }
      }
    }
    if (parsed.isNotEmpty) {
      return parsed;
    }
    final column = _filterColumnFromConfig(key, raw);
    if (column == null) {
      return const {};
    }
    final colorFilter = _filterColorFilterFromCaljs(raw['caljs']);
    if (colorFilter != null) {
      final rows = <int>{};
      final rowRange = _filterRowRangeFromConfig(sheet, raw);
      final conditionStyles = _screenshotConditionStyles(sheet);
      for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
        final coord = FortuneCellCoord(row, column);
        final cell = sheet.cells[coord];
        final cellColor = colorFilter.$1 == 'cell'
            ? _filterCellColorHex(
                cell,
                colorFilter.$1,
                conditionStyle: conditionStyles[coord],
              )
            : _filterCellForegroundHex(
                cell,
                conditionStyle: conditionStyles[coord],
              );
        if (cellColor != colorFilter.$2) {
          rows.add(row);
        }
      }
      return rows;
    }
    final filterValue = raw['filterValue'];
    if (filterValue == null) {
      return const {};
    }
    final value = '$filterValue';
    final rows = <int>{};
    final rowRange = _filterRowRangeFromConfig(sheet, raw);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      final text =
          _filterCellOptionText(
            sheet.cells[FortuneCellCoord(row, column)],
          )?.trim() ??
          '';
      final matches = value == fortuneFilterBlankLabel
          ? text.isEmpty
          : text == value;
      if (!matches) {
        rows.add(row);
      }
    }
    return rows;
  }

  int? _filterColumnFromConfig(String key, Map raw) {
    if (key.startsWith('column_')) {
      final parsed = int.tryParse(key.substring('column_'.length));
      if (parsed != null) {
        return parsed;
      }
    }
    final focus = raw['column_focus'];
    if (focus is int) {
      return focus;
    }
    final cindex = raw['cindex'];
    if (cindex is int) {
      return cindex;
    }
    final column = raw['column'];
    if (column is int) {
      return column;
    }
    if (column is List && column.isNotEmpty) {
      final first = column.first;
      if (first is int) {
        return first;
      }
      return int.tryParse('$first');
    }
    return null;
  }

  (int, int) _filterRowRangeFromConfig(FortuneSheet sheet, Map raw) {
    final rowCount = _effectiveRowCount(sheet);
    final row = raw['row'];
    if (row is List && row.length >= 2) {
      final start = _intValue(row[0]);
      final end = _intValue(row[1]);
      if (start != null && end != null) {
        return (
          math.min(start, end).clamp(0, rowCount - 1).toInt() + 1,
          math.max(start, end).clamp(0, rowCount - 1).toInt(),
        );
      }
    }
    final str = _intValue(raw['str']);
    final edr = _intValue(raw['edr']);
    if (str != null && edr != null) {
      return (
        math.min(str, edr).clamp(0, rowCount - 1).toInt() + 1,
        math.max(str, edr).clamp(0, rowCount - 1).toInt(),
      );
    }
    return (1, math.max(0, rowCount - 1));
  }

  (int, int) _filterDataRowRangeFromSelect(FortuneSheet sheet) {
    final range = _filterSelectRange(sheet);
    if (range == null) {
      return (1, math.max(0, _effectiveRowCount(sheet) - 1));
    }
    return (range.rowStart + 1, range.rowEnd);
  }

  bool _isToolbarSortFilterCommand(String command) {
    return command == fortuneToolbarSortAscendingCommand ||
        command == fortuneToolbarSortDescendingCommand ||
        command == fortuneToolbarCreateFilterCommand ||
        command == fortuneToolbarClearFilterCommand;
  }

  void _applyToolbarSortFilterCommand(String command) {
    switch (command) {
      case fortuneToolbarSortAscendingCommand:
        _sortSelectedRange(isAscending: true);
      case fortuneToolbarSortDescendingCommand:
        _sortSelectedRange(isAscending: false);
      case fortuneToolbarCreateFilterCommand:
        _createFilterForSelection();
      case fortuneToolbarClearFilterCommand:
        _clearAllFilters();
    }
  }

  Set<int> _filterColumns(FortuneSheet sheet) {
    final columns = <int>{};
    final filterSelectRange = _filterSelectRange(sheet);
    if (filterSelectRange != null) {
      for (
        var column = filterSelectRange.columnStart;
        column <= filterSelectRange.columnEnd;
        column += 1
      ) {
        columns.add(column);
      }
    }
    for (final entry in sheet.filter.entries) {
      final value = entry.value;
      if (entry.key.startsWith('column_')) {
        final parsed = int.tryParse(entry.key.substring('column_'.length));
        if (parsed != null) {
          columns.add(parsed);
        }
      }
      if (value is Map) {
        final focus = value['column_focus'];
        if (focus is int) {
          columns.add(focus);
        }
        final cindex = value['cindex'];
        if (cindex is int) {
          columns.add(cindex);
        }
        final column = value['column'];
        if (column is List && column.isNotEmpty) {
          final first = column.first;
          if (first is int) {
            columns.add(first);
          }
        } else if (column is int) {
          columns.add(column);
        }
      }
    }
    return columns;
  }

  int? _filterMarkerColumnAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final headerTop = sheetTop + _sheetHeaderTop(settings);
    if (local.dy < headerTop ||
        local.dy >= headerTop + settings.columnHeaderHeight) {
      return null;
    }
    final columns = _filterColumns(_workbook.activeSheet);
    if (columns.isEmpty) {
      return null;
    }
    for (final column in columns) {
      if (column < 0 || column >= metrics.visibleDataColumns.length) {
        continue;
      }
      final width = metrics.columnEnd(column) - metrics.columnStart(column);
      if (width <= 0) {
        continue;
      }
      final left = _visualCellLeft(column, settings, metrics);
      final markerRect = Rect.fromLTWH(
        left + width - 18,
        headerTop,
        18,
        settings.columnHeaderHeight,
      );
      if (markerRect.contains(local)) {
        return column;
      }
    }
    return null;
  }

  void _openFilterDropdown(int column) {
    final options = _filterDropdownValues(column);
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    final labels = _filterDropdownUnfilteredLabels(column);
    if (labels.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    if (options.isEmpty && raw is! Map) {
      setState(_closeTransientMenus);
      return;
    }
    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = column;
      _filterDropdownScrollOffset = 0;
      _filterDropdownSearchController.clear();
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  List<String> _filterDropdownValues(int column) {
    final values = <String>{};
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    final rowRange = raw is Map
        ? _filterRowRangeFromConfig(sheet, raw)
        : _filterDataRowRangeFromSelect(sheet);
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final text = _filterCellOptionText(
        sheet.cells[FortuneCellCoord(row, column)],
      );
      final trimmed = text?.trim();
      if (trimmed == null || trimmed.isEmpty) {
        values.add(fortuneFilterBlankLabel);
      } else {
        values.add(trimmed);
      }
    }
    return values.toList();
  }

  List<String> _filterDropdownColorLabels(int column) {
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    final rowRange = raw is Map
        ? _filterRowRangeFromConfig(sheet, raw)
        : _filterDataRowRangeFromSelect(sheet);
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    final backgroundColors = <String>{};
    final foregroundColors = <String>{};
    final conditionStyles = _screenshotConditionStyles(sheet);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final coord = FortuneCellCoord(row, column);
      final cell = sheet.cells[coord];
      final conditionStyle = conditionStyles[coord];
      backgroundColors.add(
        _filterCellColorHex(cell, 'cell', conditionStyle: conditionStyle),
      );
      final foreground = _filterCellForegroundHex(
        cell,
        conditionStyle: conditionStyle,
      );
      if (foreground != null) {
        foregroundColors.add(foreground);
      }
    }
    final labels = <String>[];
    if (backgroundColors.length > 1) {
      labels.addAll(
        (backgroundColors.toList()..sort()).map(
          (color) => '$fortuneFilterDropdownCellColorLabel $color',
        ),
      );
    }
    if (foregroundColors.length > 1) {
      labels.addAll(
        (foregroundColors.toList()..sort()).map(
          (color) => '$fortuneFilterDropdownTextColorLabel $color',
        ),
      );
    }
    return labels;
  }

  Rect? _filterDropdownRect({Size? sizeOverride}) {
    final column = filterDropdownColumn;
    if (column == null) {
      return null;
    }
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    if (column < 0 || column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final width = metrics.columnEnd(column) - metrics.columnStart(column);
    if (width <= 0) {
      return null;
    }
    final labels = _filterDropdownUnfilteredLabels(column);
    final popupWidth = math.max(
      fortuneFilterDropdownMinWidth,
      _longestOptionWidth(labels),
    );
    final popupHeight =
        math.min(
          fortuneFilterDropdownMaxVisibleRows,
          labels.length.toDouble(),
        ) *
        fortuneFilterDropdownRowHeight;
    final size = sizeOverride ?? context.size;
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    var left = _visualCellLeft(column, settings, metrics) + width - popupWidth;
    var top = sheetTop + _sheetDataTop(settings) + 1;
    if (size != null) {
      left = left.clamp(0.0, math.max(0.0, size.width - popupWidth)).toDouble();
      if (top + popupHeight > size.height) {
        top = math.max(0.0, sheetTop - popupHeight - 1);
      }
    }
    return Rect.fromLTWH(left, top, popupWidth, popupHeight);
  }

  Rect? _filterDropdownSearchRect({Size? sizeOverride}) {
    final rect = _filterDropdownRect(sizeOverride: sizeOverride);
    return rect == null ? null : fortuneFilterDropdownSearchRect(rect);
  }

  String? _filterDropdownOptionAt(Offset local) {
    final column = filterDropdownColumn;
    if (column == null) {
      return null;
    }
    final rect = _filterDropdownRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    final labels = _filterDropdownLabels(column);
    final fixedRows = _filterDropdownFixedRowCount();
    final visibleIndex =
        ((local.dy - rect.top) / fortuneFilterDropdownRowHeight).floor();
    final index = visibleIndex < fixedRows
        ? visibleIndex
        : fixedRows +
              _filterDropdownFirstVisibleChoiceIndex() +
              visibleIndex -
              fixedRows;
    if (visibleIndex < 0 || visibleIndex >= 8 || index >= labels.length) {
      return null;
    }
    return _filterDropdownCommandForFixedIndex(index) ?? labels[index];
  }

  String? _filterDropdownCheckboxOptionAt(Offset local) {
    final column = filterDropdownColumn;
    if (column == null) {
      return null;
    }
    final rect = _filterDropdownRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    final labels = _filterDropdownLabels(column);
    final fixedRows = _filterDropdownFixedRowCount();
    final visibleIndex =
        ((local.dy - rect.top) / fortuneFilterDropdownRowHeight).floor();
    final index = visibleIndex < fixedRows
        ? visibleIndex
        : fixedRows +
              _filterDropdownFirstVisibleChoiceIndex() +
              visibleIndex -
              fixedRows;
    if (visibleIndex < 0 ||
        visibleIndex >= 8 ||
        index < fixedRows ||
        index >= labels.length) {
      return null;
    }
    if (local.dx > rect.left + 28) {
      return null;
    }
    return labels[index];
  }

  String? _filterDropdownBulkCommandAt(Offset local) {
    if (filterDropdownColumn == null) {
      return null;
    }
    final rect = _filterDropdownRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    final index = ((local.dy - rect.top) / fortuneFilterDropdownRowHeight)
        .floor();
    if (index != _filterDropdownClearRowIndex()) {
      return null;
    }
    final controlsLeft =
        rect.right - fortuneFilterDropdownBulkControlsWidth - 6;
    if (local.dx < controlsLeft || local.dx > rect.right - 6) {
      return null;
    }
    final relativeX = local.dx - controlsLeft;
    final checkAllEnd = fortuneFilterDropdownBulkCheckAllWidth;
    final clearStart = checkAllEnd + fortuneFilterDropdownBulkSeparatorWidth;
    final clearEnd = clearStart + fortuneFilterDropdownBulkClearWidth;
    final inverseStart = clearEnd + fortuneFilterDropdownBulkSeparatorWidth;
    final inverseEnd = inverseStart + fortuneFilterDropdownBulkInverseWidth;
    if (relativeX < checkAllEnd) {
      return '__check_all__';
    }
    if (relativeX >= clearStart && relativeX < clearEnd) {
      return '__clear_all__';
    }
    if (relativeX >= inverseStart && relativeX < inverseEnd) {
      return '__inverse__';
    }
    return null;
  }

  int _filterDropdownFirstVisibleChoiceIndex() {
    return (_filterDropdownScrollOffset / fortuneFilterDropdownRowHeight)
        .floor();
  }

  List<String> _filterDropdownLabels(int column) {
    final values = _filterDropdownValues(column);
    final searchText = _filterDropdownSearchController.text
        .trim()
        .toLowerCase();
    final filteredValues = searchText.isEmpty
        ? values
        : values
              .where((value) => value.toLowerCase().contains(searchText))
              .toList(growable: false);
    return _filterDropdownLabelsForSettings(
      colorLabels: _filterDropdownColorLabels(column),
      valueLabels: filteredValues,
    );
  }

  List<String> _filterDropdownUnfilteredLabels(int column) {
    return _filterDropdownLabelsForSettings(
      colorLabels: _filterDropdownColorLabels(column),
      valueLabels: _filterDropdownValues(column),
    );
  }

  List<String> _filterDropdownLabelsForSettings({
    required List<String> colorLabels,
    required List<String> valueLabels,
  }) {
    final items = _workbook.settings.filterContextMenu;
    final labels = <String>[];
    if (items.contains(fortuneFilterSortAscCommand)) {
      labels.add(widget.locale.filterSortByAsc);
    }
    if (items.contains(fortuneFilterSortDescCommand)) {
      labels.add(widget.locale.filterSortByDesc);
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      labels.add(widget.locale.filterClear);
    }
    if (items.contains(fortuneFilterByConditionCommand)) {
      labels.add(widget.locale.filterByCondition);
    }
    if (items.contains(fortuneFilterByColorCommand)) {
      labels.addAll(colorLabels);
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      labels.addAll(valueLabels);
    }
    return labels;
  }

  int _filterDropdownFixedRowCount() {
    final items = _workbook.settings.filterContextMenu;
    var count = 0;
    if (items.contains(fortuneFilterSortAscCommand)) {
      count += 1;
    }
    if (items.contains(fortuneFilterSortDescCommand)) {
      count += 1;
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      count += 1;
    }
    if (items.contains(fortuneFilterByConditionCommand)) {
      count += 1;
    }
    return count;
  }

  int _filterDropdownClearRowIndex() {
    final items = _workbook.settings.filterContextMenu;
    if (!items.contains(fortuneFilterByValueCommand)) {
      return -1;
    }
    var index = 0;
    if (items.contains(fortuneFilterSortAscCommand)) {
      index += 1;
    }
    if (items.contains(fortuneFilterSortDescCommand)) {
      index += 1;
    }
    return index;
  }

  String? _filterDropdownCommandForFixedIndex(int index) {
    final items = _workbook.settings.filterContextMenu;
    var cursor = 0;
    if (items.contains(fortuneFilterSortAscCommand)) {
      if (index == cursor) {
        return fortuneFilterSortAscCommand;
      }
      cursor += 1;
    }
    if (items.contains(fortuneFilterSortDescCommand)) {
      if (index == cursor) {
        return fortuneFilterSortDescCommand;
      }
      cursor += 1;
    }
    if (items.contains(fortuneFilterByValueCommand) && index == cursor) {
      return '__clear__';
    }
    if (items.contains(fortuneFilterByValueCommand)) {
      cursor += 1;
    }
    if (items.contains(fortuneFilterByConditionCommand) && index == cursor) {
      return fortuneFilterByConditionCommand;
    }
    return null;
  }

  String _filterKeyForColumn(FortuneSheet sheet, int column) {
    for (final entry in sheet.filter.entries) {
      final value = entry.value;
      if (entry.key == 'column_$column') {
        return entry.key;
      }
      if (value is Map) {
        final focus = value['column_focus'];
        if (focus is int && focus == column) {
          return entry.key;
        }
        final cindex = value['cindex'];
        if (cindex is int && cindex == column) {
          return entry.key;
        }
        final rawColumn = value['column'];
        if (rawColumn is List &&
            rawColumn.isNotEmpty &&
            rawColumn.first == column) {
          return entry.key;
        }
        if (rawColumn is int && rawColumn == column) {
          return entry.key;
        }
      }
    }
    final filterSelectRange = _filterSelectRange(sheet);
    if (filterSelectRange != null &&
        column >= filterSelectRange.columnStart &&
        column <= filterSelectRange.columnEnd) {
      return '${column - filterSelectRange.columnStart}';
    }
    return 'column_$column';
  }

  FortuneRange? _filterSelectRange(FortuneSheet sheet) {
    final raw = sheet.filterSelect;
    if (raw is! Map) {
      return null;
    }
    final row = raw['row'];
    final column = raw['column'];
    if (row is! List ||
        row.length < 2 ||
        column is! List ||
        column.length < 2) {
      return null;
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return null;
    }
    return FortuneRange(
      rowStart: math.min(rowStart, rowEnd),
      rowEnd: math.max(rowStart, rowEnd),
      columnStart: math.min(columnStart, columnEnd),
      columnEnd: math.max(columnStart, columnEnd),
    );
  }

  void _activateFilterDropdownOption(String option) {
    final column = filterDropdownColumn;
    if (column == null) {
      return;
    }
    if (option == fortuneFilterSortAscCommand ||
        option == fortuneFilterSortDescCommand) {
      _sortFilterRange(
        column,
        isAscending: option == fortuneFilterSortAscCommand,
      );
      return;
    }
    if (option == fortuneFilterByConditionCommand) {
      return;
    }
    final colorOption = _filterDropdownColorOption(option);
    if (colorOption != null) {
      _activateFilterDropdownColorOption(
        column,
        type: colorOption.$1,
        color: colorOption.$2,
      );
      return;
    }
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final filter = Map<String, Object?>.from(sheet.filter);
    final raw = filter[key];
    final filterSelectRange = _filterSelectRange(sheet);
    final nextFilterConfig = raw is Map
        ? Map<String, Object?>.from(raw)
        : <String, Object?>{
            'rangeType': 'column',
            'row': [
              filterSelectRange?.rowStart ?? 0,
              filterSelectRange?.rowEnd ?? _effectiveRowCount(sheet) - 1,
            ],
            'column': [column, column],
            'column_focus': column,
          };
    final hiddenRows = Set<int>.from(sheet.hiddenRows);
    final hiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues);
    for (final row in _filterHiddenRowsForEntry(sheet, key, raw)) {
      hiddenRows.remove(row);
      hiddenRowValues.remove(row);
    }
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    for (final row in otherHiddenRows) {
      hiddenRows.add(row);
      hiddenRowValues[row] = 0;
    }
    if (option == '__clear__') {
      filter.remove(key);
    } else {
      nextFilterConfig['filterValue'] = option;
      final headerRange = _filterConfigHeaderRange(
        sheet,
        nextFilterConfig,
        filterSelectRange,
      );
      final columnRange = _filterConfigColumnRange(
        nextFilterConfig,
        filterSelectRange,
        column,
      );
      nextFilterConfig['optionstate'] = true;
      nextFilterConfig['caljs'] = null;
      nextFilterConfig['str'] = headerRange.$1;
      nextFilterConfig['edr'] = headerRange.$2;
      nextFilterConfig['cindex'] = column;
      nextFilterConfig['stc'] = columnRange.$1;
      nextFilterConfig['edc'] = columnRange.$2;
      final rowhidden = <String, Object?>{};
      final rowRange = _filterRowRangeFromConfig(sheet, nextFilterConfig);
      for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
        if (otherHiddenRows.contains(row)) {
          continue;
        }
        final text =
            _filterCellOptionText(
              sheet.cells[FortuneCellCoord(row, column)],
            )?.trim() ??
            '';
        final matches = option == fortuneFilterBlankLabel
            ? text.isEmpty
            : text == option;
        if (!matches) {
          hiddenRows.add(row);
          hiddenRowValues[row] = 0;
          rowhidden['$row'] = 0;
        }
      }
      nextFilterConfig['rowhidden'] = rowhidden;
      filter[key] = nextFilterConfig;
    }
    final changed =
        !_jsonLikeEquals(sheet.filter, filter) ||
        !_intSetEquals(sheet.hiddenRows, hiddenRows) ||
        !_jsonLikeEquals(sheet.hiddenRowValues, hiddenRowValues);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          filter: filter,
          hiddenRows: hiddenRows,
          hiddenRowValues: hiddenRowValues,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      filterDropdownColumn = null;
    });
  }

  void _toggleFilterDropdownChoiceOption(String option) {
    final column = filterDropdownColumn;
    if (column == null) {
      return;
    }
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final filter = Map<String, Object?>.from(sheet.filter);
    final raw = filter[key];
    final filterSelectRange = _filterSelectRange(sheet);
    final nextFilterConfig = raw is Map
        ? Map<String, Object?>.from(raw)
        : <String, Object?>{
            'rangeType': 'column',
            'row': [
              filterSelectRange?.rowStart ?? 0,
              filterSelectRange?.rowEnd ?? _effectiveRowCount(sheet) - 1,
            ],
            'column': [column, column],
            'column_focus': column,
          };
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    final currentHiddenRows = _filterHiddenRowsForEntry(sheet, key, raw);
    final rowRange = _filterRowRangeFromConfig(sheet, nextFilterConfig);
    final targetRows = <int>{};
    final colorOption = _filterDropdownColorOption(option);
    final conditionStyles = colorOption == null
        ? const <FortuneCellCoord, _FortuneScreenshotConditionStyle>{}
        : _screenshotConditionStyles(sheet);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final coord = FortuneCellCoord(row, column);
      final cell = sheet.cells[coord];
      final matches = colorOption == null
          ? _filterCellMatchesDropdownValue(cell, option)
          : _filterCellMatchesDropdownColor(
              cell,
              type: colorOption.$1,
              color: colorOption.$2,
              conditionStyle: conditionStyles[coord],
            );
      if (matches) {
        targetRows.add(row);
      }
    }
    if (targetRows.isEmpty) {
      return;
    }
    final targetChecked = targetRows.every(
      (row) => !currentHiddenRows.contains(row),
    );
    final nextCurrentHiddenRows = Set<int>.from(currentHiddenRows);
    if (targetChecked) {
      nextCurrentHiddenRows.addAll(targetRows);
    } else {
      nextCurrentHiddenRows.removeAll(targetRows);
    }

    final hiddenRows = Set<int>.from(sheet.hiddenRows);
    final hiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues);
    for (final row in currentHiddenRows) {
      hiddenRows.remove(row);
      hiddenRowValues.remove(row);
    }
    for (final row in otherHiddenRows) {
      hiddenRows.add(row);
      hiddenRowValues[row] = 0;
    }
    for (final row in nextCurrentHiddenRows) {
      hiddenRows.add(row);
      hiddenRowValues[row] = 0;
    }

    if (nextCurrentHiddenRows.isEmpty) {
      filter.remove(key);
    } else {
      final headerRange = _filterConfigHeaderRange(
        sheet,
        nextFilterConfig,
        filterSelectRange,
      );
      final columnRange = _filterConfigColumnRange(
        nextFilterConfig,
        filterSelectRange,
        column,
      );
      nextFilterConfig
        ..remove('filterValue')
        ..['optionstate'] = true
        ..['caljs'] = null
        ..['str'] = headerRange.$1
        ..['edr'] = headerRange.$2
        ..['cindex'] = column
        ..['stc'] = columnRange.$1
        ..['edc'] = columnRange.$2
        ..['rowhidden'] = {
          for (final row in (nextCurrentHiddenRows.toList()..sort())) '$row': 0,
        };
      filter[key] = nextFilterConfig;
    }
    final changed =
        !_jsonLikeEquals(sheet.filter, filter) ||
        !_intSetEquals(sheet.hiddenRows, hiddenRows) ||
        !_jsonLikeEquals(sheet.hiddenRowValues, hiddenRowValues);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          filter: filter,
          hiddenRows: hiddenRows,
          hiddenRowValues: hiddenRowValues,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
    });
  }

  void _activateFilterDropdownBulkCommand(String command) {
    final column = filterDropdownColumn;
    if (column == null) {
      return;
    }
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final filter = Map<String, Object?>.from(sheet.filter);
    final raw = filter[key];
    final filterSelectRange = _filterSelectRange(sheet);
    final nextFilterConfig = raw is Map
        ? Map<String, Object?>.from(raw)
        : <String, Object?>{
            'rangeType': 'column',
            'row': [
              filterSelectRange?.rowStart ?? 0,
              filterSelectRange?.rowEnd ?? _effectiveRowCount(sheet) - 1,
            ],
            'column': [column, column],
            'column_focus': column,
          };
    final rowRange = _filterRowRangeFromConfig(sheet, nextFilterConfig);
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    final currentHiddenRows = _filterHiddenRowsForEntry(sheet, key, raw);
    final visibleRows = <int>{};
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (!otherHiddenRows.contains(row)) {
        visibleRows.add(row);
      }
    }

    final nextCurrentHiddenRows = switch (command) {
      '__check_all__' => <int>{},
      '__clear_all__' => visibleRows,
      '__inverse__' => visibleRows.difference(currentHiddenRows),
      _ => currentHiddenRows,
    };

    if (_intSetEquals(currentHiddenRows, nextCurrentHiddenRows)) {
      return;
    }

    final hiddenRows = Set<int>.from(sheet.hiddenRows);
    final hiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues);
    for (final row in currentHiddenRows) {
      hiddenRows.remove(row);
      hiddenRowValues.remove(row);
    }
    for (final row in otherHiddenRows) {
      hiddenRows.add(row);
      hiddenRowValues[row] = 0;
    }
    for (final row in nextCurrentHiddenRows) {
      hiddenRows.add(row);
      hiddenRowValues[row] = 0;
    }

    if (nextCurrentHiddenRows.isEmpty) {
      filter.remove(key);
    } else {
      final headerRange = _filterConfigHeaderRange(
        sheet,
        nextFilterConfig,
        filterSelectRange,
      );
      final columnRange = _filterConfigColumnRange(
        nextFilterConfig,
        filterSelectRange,
        column,
      );
      nextFilterConfig
        ..remove('filterValue')
        ..['optionstate'] = true
        ..['caljs'] = null
        ..['str'] = headerRange.$1
        ..['edr'] = headerRange.$2
        ..['cindex'] = column
        ..['stc'] = columnRange.$1
        ..['edc'] = columnRange.$2
        ..['rowhidden'] = {
          for (final row in (nextCurrentHiddenRows.toList()..sort())) '$row': 0,
        };
      filter[key] = nextFilterConfig;
    }
    final changed =
        !_jsonLikeEquals(sheet.filter, filter) ||
        !_intSetEquals(sheet.hiddenRows, hiddenRows) ||
        !_jsonLikeEquals(sheet.hiddenRowValues, hiddenRowValues);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          filter: filter,
          hiddenRows: hiddenRows,
          hiddenRowValues: hiddenRowValues,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
    });
  }

  bool _filterCellMatchesDropdownValue(FortuneCell? cell, String option) {
    final text = _filterCellOptionText(cell)?.trim() ?? '';
    return option == fortuneFilterBlankLabel ? text.isEmpty : text == option;
  }

  bool _filterCellMatchesDropdownColor(
    FortuneCell? cell, {
    required String type,
    required String color,
    _FortuneScreenshotConditionStyle? conditionStyle,
  }) {
    final cellColor = type == 'cell'
        ? _filterCellColorHex(cell, type, conditionStyle: conditionStyle)
        : _filterCellForegroundHex(cell, conditionStyle: conditionStyle);
    return cellColor == color;
  }

  (String, String)? _filterDropdownColorOption(String option) {
    final cellPrefix = '$fortuneFilterDropdownCellColorLabel ';
    if (option.startsWith(cellPrefix)) {
      final color = option.substring(cellPrefix.length).trim().toLowerCase();
      return color.startsWith('#') ? ('cell', color) : null;
    }
    final textPrefix = '$fortuneFilterDropdownTextColorLabel ';
    if (option.startsWith(textPrefix)) {
      final color = option.substring(textPrefix.length).trim().toLowerCase();
      return color.startsWith('#') ? ('text', color) : null;
    }
    return null;
  }

  (String, String)? _filterColorFilterFromCaljs(Object? raw) {
    if (raw is! Map) {
      return null;
    }
    final type = '${raw['type'] ?? ''}'.trim();
    if (type != 'cell' && type != 'text') {
      return null;
    }
    final color = '${raw['color'] ?? ''}'.trim().toLowerCase();
    if (!color.startsWith('#')) {
      return null;
    }
    return (type, color);
  }

  void _activateFilterDropdownColorOption(
    int column, {
    required String type,
    required String color,
  }) {
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final filter = Map<String, Object?>.from(sheet.filter);
    final raw = filter[key];
    final filterSelectRange = _filterSelectRange(sheet);
    final nextFilterConfig = raw is Map
        ? Map<String, Object?>.from(raw)
        : <String, Object?>{
            'rangeType': 'column',
            'row': [
              filterSelectRange?.rowStart ?? 0,
              filterSelectRange?.rowEnd ?? _effectiveRowCount(sheet) - 1,
            ],
            'column': [column, column],
            'column_focus': column,
          };
    final hiddenRows = Set<int>.from(sheet.hiddenRows);
    final hiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues);
    for (final row in _filterHiddenRowsForEntry(sheet, key, raw)) {
      hiddenRows.remove(row);
      hiddenRowValues.remove(row);
    }
    final otherHiddenRows = _filterHiddenRows(sheet, exceptKey: key);
    for (final row in otherHiddenRows) {
      hiddenRows.add(row);
      hiddenRowValues[row] = 0;
    }
    final headerRange = _filterConfigHeaderRange(
      sheet,
      nextFilterConfig,
      filterSelectRange,
    );
    final columnRange = _filterConfigColumnRange(
      nextFilterConfig,
      filterSelectRange,
      column,
    );
    nextFilterConfig.remove('filterValue');
    nextFilterConfig['optionstate'] = true;
    nextFilterConfig['caljs'] = {'type': type, 'color': color};
    nextFilterConfig['str'] = headerRange.$1;
    nextFilterConfig['edr'] = headerRange.$2;
    nextFilterConfig['cindex'] = column;
    nextFilterConfig['stc'] = columnRange.$1;
    nextFilterConfig['edc'] = columnRange.$2;
    final rowhidden = <String, Object?>{};
    final rowRange = _filterRowRangeFromConfig(sheet, nextFilterConfig);
    final conditionStyles = _screenshotConditionStyles(sheet);
    for (var row = rowRange.$1; row <= rowRange.$2; row += 1) {
      if (otherHiddenRows.contains(row)) {
        continue;
      }
      final coord = FortuneCellCoord(row, column);
      final cell = sheet.cells[coord];
      final cellColor = type == 'cell'
          ? _filterCellColorHex(
              cell,
              type,
              conditionStyle: conditionStyles[coord],
            )
          : _filterCellForegroundHex(
              cell,
              conditionStyle: conditionStyles[coord],
            );
      if (cellColor != color) {
        hiddenRows.add(row);
        hiddenRowValues[row] = 0;
        rowhidden['$row'] = 0;
      }
    }
    nextFilterConfig['rowhidden'] = rowhidden;
    filter[key] = nextFilterConfig;
    final changed =
        !_jsonLikeEquals(sheet.filter, filter) ||
        !_intSetEquals(sheet.hiddenRows, hiddenRows) ||
        !_jsonLikeEquals(sheet.hiddenRowValues, hiddenRowValues);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          filter: filter,
          hiddenRows: hiddenRows,
          hiddenRowValues: hiddenRowValues,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      filterDropdownColumn = null;
    });
  }

  String? _filterCellOptionText(FortuneCell? cell) {
    if (cell == null) {
      return null;
    }
    if (cell.cellType?.type == 'd') {
      final value = cell.hasRawValue ? cell.rawValue : cell.value;
      if (value != null && !isRealNull(value)) {
        return update('YYYY-MM-DD', value);
      }
    }
    return cell.renderedText;
  }

  String _filterCellColorHex(
    FortuneCell? cell,
    String type, {
    _FortuneScreenshotConditionStyle? conditionStyle,
  }) {
    if (type == 'cell') {
      if (conditionStyle?.cellColor case final cellColor?) {
        return _filterColorHex(cellColor);
      }
      return _filterColorHex(cell?.background ?? const Color(0xffffffff));
    }
    if (conditionStyle?.textColor case final textColor?) {
      return _filterColorHex(textColor);
    }
    return _filterColorHex(cell?.foreground ?? const Color(0xff000000));
  }

  String? _filterCellForegroundHex(
    FortuneCell? cell, {
    _FortuneScreenshotConditionStyle? conditionStyle,
  }) {
    if (cell == null) {
      return null;
    }
    if (cell.renderedText.trim().isEmpty) {
      return null;
    }
    if (conditionStyle?.textColor case final textColor?) {
      return _filterColorHex(textColor);
    }
    if (!cell.hasRawForeground && cell.foreground == const Color(0xff000000)) {
      return null;
    }
    return _filterColorHex(cell.foreground);
  }

  String _filterColorHex(Color color) {
    final rgb = color.toARGB32() & 0x00ffffff;
    return '#${rgb.toRadixString(16).padLeft(6, '0')}';
  }

  void _toggleSelectedCellDataVerification() {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final dataVerification = Map<String, Object?>.from(sheet.dataVerification);
    final removing = targets.every((coord) {
      return dataVerification.containsKey(_cellKey(coord));
    });
    if (removing) {
      for (final coord in targets) {
        dataVerification.remove(_cellKey(coord));
      }
    } else {
      for (final coord in targets) {
        dataVerification.putIfAbsent(
          _cellKey(coord),
          () => _defaultDataVerificationRule(
            rangeText: _rangeTextForDataVerification(range),
          ),
        );
      }
    }
    final changed = !_jsonLikeEquals(sheet.dataVerification, dataVerification);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          dataVerification: dataVerification,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _closeTransientMenus();
    });
  }

  (int, int) _filterConfigHeaderRange(
    FortuneSheet sheet,
    Map<String, Object?> raw,
    FortuneRange? filterSelectRange,
  ) {
    final row = raw['row'];
    if (row is List && row.length >= 2) {
      final start = _intValue(row[0]);
      final end = _intValue(row[1]);
      if (start != null && end != null) {
        return (math.min(start, end), math.max(start, end));
      }
    }
    final str = _intValue(raw['str']);
    final edr = _intValue(raw['edr']);
    if (str != null && edr != null) {
      return (math.min(str, edr), math.max(str, edr));
    }
    return (
      filterSelectRange?.rowStart ?? 0,
      filterSelectRange?.rowEnd ?? _effectiveRowCount(sheet) - 1,
    );
  }

  (int, int) _filterConfigColumnRange(
    Map<String, Object?> raw,
    FortuneRange? filterSelectRange,
    int column,
  ) {
    final stc = _intValue(raw['stc']);
    final edc = _intValue(raw['edc']);
    if (stc != null && edc != null) {
      return (math.min(stc, edc), math.max(stc, edc));
    }
    return (
      filterSelectRange?.columnStart ?? column,
      filterSelectRange?.columnEnd ?? column,
    );
  }

  Map<String, Object?> _defaultDataVerificationRule({String rangeText = ''}) {
    return {
      'type': 'dropdown',
      'type2': 'false',
      'rangeTxt': rangeText,
      'value1': 'Option 1,Option 2',
      'value2': '',
      'checked': false,
      'validity': '',
      'remote': false,
      'prohibitInput': false,
      'hintShow': false,
      'hintValue': '',
    };
  }

  String _rangeTextForDataVerification(FortuneRange range) {
    return getRangetxt(
      _workbook,
      _workbook.activeSheet.id,
      range,
      currentSheetId: _workbook.activeSheet.id,
    );
  }

  bool _isDataVerificationMarkerHit(FortuneCellCoord coord, Offset local) {
    final rect = _cellRectForCoord(coord);
    if (rect == null || rect.width < 14 || rect.height < 12) {
      return false;
    }
    final raw = _workbook.activeSheet.dataVerification[_cellKey(coord)];
    if (raw is! Map || raw['type'] == 'checkbox') {
      return false;
    }
    return Rect.fromLTWH(
      rect.right - 18,
      rect.top,
      18,
      rect.height,
    ).contains(local);
  }

  bool _isDataVerificationCheckbox(FortuneCellCoord coord) {
    final raw = _workbook.activeSheet.dataVerification[_cellKey(coord)];
    return raw is Map && raw['type'] == 'checkbox';
  }

  void _toggleDataVerificationCheckbox(FortuneCellCoord coord) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    final key = _cellKey(anchor);
    final raw = sheet.dataVerification[key];
    if (raw is! Map) {
      return;
    }
    _recordUndoSnapshot();
    final dataVerification = Map<String, Object?>.from(sheet.dataVerification);
    final next = Map<String, Object?>.from(raw);
    final nextChecked = fortuneRawBool(next['checked']) != true;
    next['checked'] = nextChecked;
    dataVerification[key] = next;
    final checkboxValue = nextChecked ? next['value1'] : next['value2'];
    final sheets = [..._workbook.sheets];
    var nextSheet = sheet.copyWith(dataVerification: dataVerification);
    nextSheet = setCellValue(
      nextSheet,
      anchor.row,
      anchor.column,
      checkboxValue == null ? null : '$checkboxValue',
    );
    sheets[_workbook.activeSheetIndex] = nextSheet;
    setState(() {
      _workbook = _workbook.copyWith(sheets: sheets);
      _recalculateWorkbookFormulas();
      _closeTransientMenus();
    });
  }

  void _openDataVerificationDropdown(FortuneCellCoord coord) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    final options = _dataVerificationOptions(
      sheet.dataVerification[_cellKey(anchor)],
      sheet: sheet,
    );
    if (options.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      dataVerificationDropdownCoord = anchor;
    });
  }

  String? _dataVerificationOptionAt(Offset local) {
    final coord = dataVerificationDropdownCoord;
    if (coord == null) {
      return null;
    }
    final rect = _dataVerificationDropdownRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    final sheet = _workbook.activeSheet;
    final options = _dataVerificationOptions(
      sheet.dataVerification[_cellKey(coord)],
      sheet: sheet,
    );
    if (options.isEmpty) {
      return null;
    }
    final index = ((local.dy - rect.top) / 24).floor();
    if (index < 0 || index >= options.length) {
      return null;
    }
    return options[index];
  }

  void _activateDataVerificationOption(String value) {
    final coord = dataVerificationDropdownCoord;
    if (coord == null) {
      return;
    }
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    final raw = sheet.dataVerification[_cellKey(anchor)];
    final previous = sheet.cells[anchor] ?? const FortuneCell();
    var nextValue = value;
    final isMultiSelect = raw is Map && fortuneRawBool(raw['type2']) == true;
    if (isMultiSelect) {
      final sourceOptions = _dataVerificationOptions(raw, sheet: sheet);
      final currentValues = _dataVerificationOptions({
        'value1': previous.value,
      }, resolveReferences: false);
      final selectedValues = currentValues.contains(value)
          ? currentValues.where((item) => item != value).toSet()
          : {...currentValues, value};
      nextValue = sourceOptions
          .where((option) => selectedValues.contains(option))
          .join(',');
    }
    final nextSheet = setCellValue(sheet, anchor.row, anchor.column, nextValue);
    final next = nextSheet.cells[anchor];
    final changed = _cellWouldChange(sheet, anchor, next);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = nextSheet;
        _workbook = _workbook.copyWith(sheets: sheets);
        _recalculateWorkbookFormulas();
      }
      if (!isMultiSelect) {
        _closeTransientMenus();
      }
    });
  }

  Rect? _dataVerificationDropdownRect() {
    final coord = dataVerificationDropdownCoord;
    if (coord == null) {
      return null;
    }
    final cellRect = _cellRectForCoord(coord);
    if (cellRect == null) {
      return null;
    }
    final sheet = _workbook.activeSheet;
    final options = _dataVerificationOptions(
      sheet.dataVerification[_cellKey(coord)],
      sheet: sheet,
    );
    if (options.isEmpty) {
      return null;
    }
    final size = context.size;
    final width = math.max(
      120.0,
      math.max(cellRect.width, _longestOptionWidth(options)),
    );
    final height = math.min(8, options.length) * 24.0;
    var left = cellRect.left;
    var top = cellRect.bottom + 1;
    if (size != null) {
      left = left.clamp(0.0, math.max(0.0, size.width - width)).toDouble();
      if (top + height > size.height) {
        top = math.max(0.0, cellRect.top - height - 1);
      }
    }
    return Rect.fromLTWH(left, top, width, height);
  }

  double _longestOptionWidth(List<String> options) {
    var longest = 0;
    for (final option in options) {
      longest = math.max(longest, option.length);
    }
    return longest * 7.0 + 26;
  }

  Rect? _cellRectForCoord(FortuneCellCoord coord) {
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    if (coord.row < 0 ||
        coord.column < 0 ||
        coord.row >= metrics.visibleDataRows.length ||
        coord.column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final cell = sheet.cells[coord];
    final rowSpan = math.max(1, cell?.merge?.rowSpan ?? 1);
    final columnSpan = math.max(1, cell?.merge?.columnSpan ?? 1);
    final rowEnd = math.min(
      metrics.visibleDataRows.length - 1,
      coord.row + rowSpan - 1,
    );
    final columnEnd = math.min(
      metrics.visibleDataColumns.length - 1,
      coord.column + columnSpan - 1,
    );
    final startX = metrics.columnStart(coord.column);
    final endX = metrics.columnEnd(columnEnd);
    final startY = metrics.rowStart(coord.row);
    final endY = metrics.rowEnd(rowEnd);
    if (endX <= startX || endY <= startY) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    return Rect.fromLTWH(
      _visualCellLeft(coord.column, settings, metrics),
      sheetTop + _visualCellTop(coord.row, settings, metrics),
      endX - startX,
      endY - startY,
    );
  }

  String _cellKey(FortuneCellCoord coord) => '${coord.row}_${coord.column}';

  List<String> _dataVerificationOptions(
    Object? raw, {
    FortuneSheet? sheet,
    bool resolveReferences = true,
  }) {
    if (raw is! Map) {
      return const [];
    }
    final value = raw['value1'] ?? raw['value'] ?? raw['values'];
    if (value is Iterable) {
      return _dedupeDataVerificationOptions(
        value.map((item) => '$item'.trim()),
      );
    }
    final text = '$value';
    if (resolveReferences) {
      final referenceOptions = _dataVerificationReferenceOptions(
        text,
        sheet ?? _workbook.activeSheet,
      );
      if (referenceOptions != null) {
        return referenceOptions;
      }
    }
    return _dedupeDataVerificationOptions(
      text.split(RegExp(r'[\n,]')).map((item) => item.trim()),
    );
  }

  List<String> _dedupeDataVerificationOptions(Iterable<String> values) {
    final options = <String>[];
    for (final value in values) {
      if (value.isEmpty || options.contains(value)) {
        continue;
      }
      options.add(value);
    }
    return options;
  }

  List<String>? _dataVerificationReferenceOptions(
    String text,
    FortuneSheet defaultSheet,
  ) {
    final reference = text.trim();
    final match = RegExp(
      r"^(?:(?:'((?:[^']|'')*)'|([^'!:]+))!)?\$?([A-Za-z]+)\$?(\d+)(?::(?:(?:'((?:[^']|'')*)'|([^'!:]+))!)?\$?([A-Za-z]+)\$?(\d+))?$",
    ).firstMatch(reference);
    if (match == null) {
      return null;
    }
    final sheetName = _dataVerificationReferenceSheetName(
      match.group(1),
      match.group(2),
    );
    final endSheetName = _dataVerificationReferenceSheetName(
      match.group(5),
      match.group(6),
    );
    if (endSheetName != null && sheetName != endSheetName) {
      return const [];
    }
    var sourceSheet = defaultSheet;
    if (sheetName != null) {
      final matchingSheets = _workbook.sheets.where(
        (candidate) => candidate.name == sheetName || candidate.id == sheetName,
      );
      if (matchingSheets.isEmpty) {
        return const [];
      }
      sourceSheet = matchingSheets.first;
    }
    final startColumn = _columnIndex(match.group(3)!);
    final startRow = int.tryParse(match.group(4)!) == null
        ? null
        : int.parse(match.group(4)!) - 1;
    final endColumn = _columnIndex(match.group(7) ?? match.group(3)!);
    final endRow = int.tryParse(match.group(8) ?? match.group(4)!) == null
        ? null
        : int.parse(match.group(8) ?? match.group(4)!) - 1;
    if (startColumn == null ||
        startRow == null ||
        endColumn == null ||
        endRow == null) {
      return const [];
    }
    final rowStart = math.min(startRow, endRow);
    final rowEnd = math.max(startRow, endRow);
    final columnStart = math.min(startColumn, endColumn);
    final columnEnd = math.max(startColumn, endColumn);
    final options = <String>[];
    for (var rowIndex = rowStart; rowIndex <= rowEnd; rowIndex += 1) {
      for (
        var columnIndex = columnStart;
        columnIndex <= columnEnd;
        columnIndex += 1
      ) {
        final option = sourceSheet
            .cells[FortuneCellCoord(rowIndex, columnIndex)]
            ?.renderedText
            .trim();
        if (option == null || option.isEmpty || options.contains(option)) {
          continue;
        }
        options.add(option);
      }
    }
    return options;
  }

  String? _dataVerificationReferenceSheetName(
    String? quoted,
    String? unquoted,
  ) {
    if (quoted != null) {
      return quoted.replaceAll("''", "'");
    }
    return unquoted;
  }

  int? _columnIndex(String name) {
    var value = 0;
    for (final codeUnit in name.toUpperCase().codeUnits) {
      if (codeUnit < 65 || codeUnit > 90) {
        return null;
      }
      value = value * 26 + codeUnit - 64;
    }
    return value - 1;
  }

  bool get _dataVerificationDialogOpen => _dataVerificationDialogCoord != null;

  static const List<String> _dataVerificationDialogConditionTypes = [
    'dropdown',
    'checkbox',
    'number',
    'number_integer',
    'number_decimal',
    'text_content',
    'text_length',
    'date',
    'validity',
  ];

  String _defaultDataVerificationType2(String type) {
    return switch (type) {
      'dropdown' || 'checkbox' => '',
      'number' ||
      'number_integer' ||
      'number_decimal' ||
      'text_length' ||
      'date' => 'between',
      'text_content' => 'include',
      'validity' => 'identificationNumber',
      _ => '',
    };
  }

  static const Map<String, List<String>> _dataVerificationDialogType2Options = {
    'number': [
      'between',
      'notBetween',
      'equal',
      'notEqualTo',
      'moreThanThe',
      'lessThan',
      'greaterOrEqualTo',
      'lessThanOrEqualTo',
    ],
    'number_integer': [
      'between',
      'notBetween',
      'equal',
      'notEqualTo',
      'moreThanThe',
      'lessThan',
      'greaterOrEqualTo',
      'lessThanOrEqualTo',
    ],
    'number_decimal': [
      'between',
      'notBetween',
      'equal',
      'notEqualTo',
      'moreThanThe',
      'lessThan',
      'greaterOrEqualTo',
      'lessThanOrEqualTo',
    ],
    'text_content': ['include', 'exclude', 'equal'],
    'text_length': [
      'between',
      'notBetween',
      'equal',
      'notEqualTo',
      'moreThanThe',
      'lessThan',
      'greaterOrEqualTo',
      'lessThanOrEqualTo',
    ],
    'date': [
      'between',
      'notBetween',
      'equal',
      'notEqualTo',
      'earlierThan',
      'noEarlierThan',
      'laterThan',
      'noLaterThan',
    ],
    'validity': ['identificationNumber', 'phoneNumber'],
  };

  List<String> _dataVerificationDialogType2OptionsFor(String type) {
    return _dataVerificationDialogType2Options[type] ?? const <String>[];
  }

  bool _dataVerificationDialogUsesType2Selector(String type) {
    return _dataVerificationDialogType2OptionsFor(type).isNotEmpty;
  }

  String _normalizedDataVerificationDialogType2(String type, Object? type2) {
    final options = _dataVerificationDialogType2OptionsFor(type);
    if (options.isEmpty) {
      return _defaultDataVerificationType2(type);
    }
    final text = '${type2 ?? ''}';
    return options.contains(text) ? text : _defaultDataVerificationType2(type);
  }

  bool _dataVerificationDialogUsesValueInputs(String type) {
    return switch (type) {
      'checkbox' ||
      'number' ||
      'number_integer' ||
      'number_decimal' ||
      'text_content' ||
      'text_length' ||
      'date' => true,
      _ => false,
    };
  }

  bool _dataVerificationDialogUsesSecondValueInput(
    String type, [
    String? type2,
  ]) {
    final operator = type2 ?? _dataVerificationDialogType2;
    if (type == 'number' ||
        type == 'number_integer' ||
        type == 'number_decimal' ||
        type == 'text_length' ||
        type == 'date') {
      return operator == 'between' || operator == 'notBetween';
    }
    return switch (type) {
      'checkbox' => true,
      _ => false,
    };
  }

  void _setDataVerificationHintValue(
    Map<String, Object?> rule,
    String hintValue,
    Map<String, Object?>? originalRule,
  ) {
    if (originalRule == null ||
        hintValue.isNotEmpty ||
        originalRule.containsKey('hintValue')) {
      rule['hintValue'] = hintValue;
    } else {
      rule.remove('hintValue');
    }
  }

