  void _showDataVerificationDialog(FortuneCellCoord coord) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    _showDataVerificationDialogForRange(
      FortuneRange(
        rowStart: anchor.row,
        rowEnd: anchor.row,
        columnStart: anchor.column,
        columnEnd: anchor.column,
      ),
    );
