  void _showDataVerificationDialogForRange(FortuneRange range) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(
      FortuneCellCoord(range.rowStart, range.columnStart),
    );
    final raw = sheet.dataVerification[_cellKey(anchor)];
    final originalRule = raw is Map ? Map<String, Object?>.from(raw) : null;
    final rawRule = raw is Map && raw['type'] != 'checkbox' ? raw : null;
    final dialogType = raw is Map && '${raw['type'] ?? ''}'.isNotEmpty
        ? '${raw['type']}'
        : 'dropdown';
    final options = rawRule == null
        ? const <String>[]
        : _dataVerificationOptions(rawRule);
    final optionsText = _dataVerificationDialogUsesValueInputs(dialogType)
        ? '${originalRule?['value1'] ?? ''}'
        : options.join(',');
    final dialogType2 = _normalizedDataVerificationDialogType2(
      dialogType,
      originalRule?['type2'],
    );
    final secondText =
        _dataVerificationDialogUsesSecondValueInput(dialogType, dialogType2)
        ? '${originalRule?['value2'] ?? ''}'
        : '';
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _customSortDialogOpen = false;
      _axisSizeDialogAxis = null;
      _axisSizeDialogIndex = null;
      _conditionRuleDialogOpen = false;
      _dataVerificationDialogCoord = anchor;
      _dataVerificationDialogRange = range;
      _dataVerificationDialogSelectingRange = false;
      _dataVerificationDialogRangeEdited = false;
      _dataVerificationDialogRangeSelectionAnchor = null;
      _dataVerificationDialogRangeSelectionTarget = null;
      _dataVerificationDialogOriginalRule = originalRule;
      _dataVerificationDialogOriginalOptionsText = optionsText;
      _dataVerificationDialogType = dialogType;
      _dataVerificationDialogType2 = dialogType2;
      _dataVerificationDialogAllowMulti =
          fortuneRawBool(rawRule?['type2']) == true;
      _dataVerificationDialogProhibitInput =
          fortuneRawBool(rawRule?['prohibitInput']) == true;
      _dataVerificationDialogHintShow =
          fortuneRawBool(rawRule?['hintShow']) == true;
      _dataVerificationRangeEditorController.text =
          _rangeTextForDataVerification(range);
      _dataVerificationEditorController.text = optionsText;
      _dataVerificationSecondEditorController.text = secondText;
      _dataVerificationHintEditorController.text =
          '${originalRule?['hintValue'] ?? ''}';
      _dataVerificationRangeEditorController.selection = TextSelection(
        baseOffset: 0,
        extentOffset: _dataVerificationRangeEditorController.text.length,
      );
      _dataVerificationEditorController.selection = TextSelection(
        baseOffset: 0,
        extentOffset: _dataVerificationEditorController.text.length,
      );
      _dataVerificationSecondEditorController.selection = TextSelection(
        baseOffset: 0,
        extentOffset: _dataVerificationSecondEditorController.text.length,
      );
      _dataVerificationHintEditorController.selection = TextSelection(
        baseOffset: 0,
        extentOffset: _dataVerificationHintEditorController.text.length,
      );
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _dataVerificationDialogOpen) {
        _dataVerificationEditorFocusNode.requestFocus();
      }
    });
  }

