  Rect? _dataVerificationDialogInputRect([Size? overrideSize]) {
    final rect = _dataVerificationDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    return _dataVerificationDialogValueInputRect(rect);
  }

  Rect _dataVerificationDialogValueInputRect(Rect rect) {
    final input = fortuneDataVerificationInputRect(rect);
    if (!_dataVerificationDialogUsesType2Selector(
      _dataVerificationDialogType,
    )) {
      return input;
    }
    const selectorWidth = fortuneDataVerificationRuleSelectWidth;
    return Rect.fromLTWH(
      input.left + selectorWidth + fortuneDataVerificationRuleSelectGap,
      input.top,
      math.max(
        24.0,
        input.width - selectorWidth - fortuneDataVerificationRuleSelectGap,
      ),
      input.height,
    );
  }

  Rect? _dataVerificationDialogRuleSelectRect([Size? overrideSize]) {
    if (!_dataVerificationDialogUsesType2Selector(
      _dataVerificationDialogType,
    )) {
      return null;
    }
    final rect = _dataVerificationDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    final input = fortuneDataVerificationInputRect(rect);
    return Rect.fromLTWH(
      input.left,
      input.top,
      math.min(fortuneDataVerificationRuleSelectWidth, input.width),
      input.height,
    );
  }

  Rect? _dataVerificationDialogHintInputRect([Size? overrideSize]) {
    final rect = _dataVerificationDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    return fortuneDataVerificationHintInputRect(rect);
  }

  Rect? _dataVerificationDialogSourceRangeIconRect([Size? overrideSize]) {
    if (_dataVerificationDialogType != 'dropdown') {
      return null;
    }
    final rect = _dataVerificationDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    final input = _dataVerificationDialogValueInputRect(rect);
    return Rect.fromLTWH(input.right - 30, input.top, 30, input.height);
  }

  Rect? _dataVerificationDialogTargetRangeIconRect([Size? overrideSize]) {
    final rect = _dataVerificationDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    final input = fortuneDataVerificationRangeInputRect(rect);
    return Rect.fromLTWH(input.right - 30, input.top, 30, input.height);
  }

  String? _dataVerificationDialogCommandAt(Offset local) {
    final rect = _dataVerificationDialogRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    if (fortuneDataVerificationCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (_dataVerificationDialogTargetRangeIconRect()?.contains(local) == true) {
      return 'select-range';
    }
    if (fortuneDataVerificationRangeInputRect(rect).contains(local)) {
      return 'range-input';
    }
    if (_dataVerificationDialogSourceRangeIconRect()?.contains(local) == true) {
      return 'select-dropdown-source';
    }
    if (_dataVerificationDialogValueInputRect(rect).contains(local)) {
      return 'input';
    }
    if (fortuneDataVerificationHintInputRect(rect).contains(local)) {
      return 'hint-input';
    }
    if (fortuneDataVerificationConditionSelectRect(rect).contains(local)) {
      return 'cycle-condition-type';
    }
    if (_dataVerificationDialogRuleSelectRect()?.contains(local) == true) {
      return 'cycle-rule-type';
    }
    if (_dataVerificationDialogUsesSecondValueInput(
          _dataVerificationDialogType,
        ) &&
        fortuneDataVerificationAllowMultiRect(rect).contains(local)) {
      return 'second-input';
    }
    if (fortuneDataVerificationAllowMultiRect(rect).contains(local)) {
      return 'toggle-allow-multi';
    }
    if (fortuneDataVerificationProhibitInputRect(rect).contains(local)) {
      return 'toggle-prohibit-input';
    }
    if (fortuneDataVerificationHintShowRect(rect).contains(local)) {
      return 'toggle-hint-show';
    }
    if (fortuneDataVerificationConfirmButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    if (fortuneDataVerificationDeleteButtonRect(rect).contains(local)) {
      return 'delete';
    }
    if (fortuneDataVerificationCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    return 'modal';
  }

  void _activateDataVerificationDialogCommand(String? command) {
    if (command == null || command == 'modal') {
      return;
    }
    if (command == 'input') {
      _dataVerificationEditorFocusNode.requestFocus();
      return;
    }
    if (command == 'range-input') {
      _dataVerificationRangeEditorFocusNode.requestFocus();
      return;
    }
    if (command == 'hint-input') {
      _dataVerificationHintEditorFocusNode.requestFocus();
      return;
    }
    if (command == 'second-input') {
      _dataVerificationSecondEditorFocusNode.requestFocus();
      return;
    }
    if (command == 'select-range') {
      setState(() {
        _dataVerificationDialogSelectingRange = true;
        _dataVerificationDialogRangeSelectionAnchor = null;
        _dataVerificationDialogRangeSelectionTarget = 'target';
      });
      _focusNode.requestFocus();
      return;
    }
    if (command == 'select-dropdown-source') {
      setState(() {
        _dataVerificationDialogSelectingRange = true;
        _dataVerificationDialogRangeSelectionAnchor = null;
        _dataVerificationDialogRangeSelectionTarget = 'dropdown-source';
      });
      _focusNode.requestFocus();
      return;
    }
    if (command == 'cycle-condition-type') {
      setState(() {
        final index = _dataVerificationDialogConditionTypes.indexOf(
          _dataVerificationDialogType,
        );
        final nextIndex = index < 0
            ? 0
            : (index + 1) % _dataVerificationDialogConditionTypes.length;
        _dataVerificationDialogType =
            _dataVerificationDialogConditionTypes[nextIndex];
        _dataVerificationDialogType2 = _defaultDataVerificationType2(
          _dataVerificationDialogType,
        );
        _dataVerificationDialogAllowMulti = false;
        _dataVerificationEditorController.clear();
        _dataVerificationSecondEditorController.clear();
      });
      return;
    }
    if (command == 'cycle-rule-type') {
      setState(() {
        final options = _dataVerificationDialogType2OptionsFor(
          _dataVerificationDialogType,
        );
        if (options.isEmpty) {
          return;
        }
        final index = options.indexOf(_dataVerificationDialogType2);
        _dataVerificationDialogType2 =
            options[index < 0 ? 0 : (index + 1) % options.length];
        _dataVerificationEditorController.clear();
        _dataVerificationSecondEditorController.clear();
      });
      return;
    }
    if (command == 'toggle-allow-multi') {
      setState(() {
        _dataVerificationDialogAllowMulti = !_dataVerificationDialogAllowMulti;
      });
      return;
    }
    if (command == 'toggle-prohibit-input') {
      setState(() {
        _dataVerificationDialogProhibitInput =
            !_dataVerificationDialogProhibitInput;
      });
      return;
    }
    if (command == 'toggle-hint-show') {
      setState(() {
        _dataVerificationDialogHintShow = !_dataVerificationDialogHintShow;
      });
      return;
    }
    if (command == 'confirm') {
      _commitDataVerificationDialog();
      return;
    }
    if (command == 'delete') {
      _deleteDataVerificationDialogRange();
      return;
    }
    setState(() {
      _dataVerificationDialogCoord = null;
      _dataVerificationDialogRange = null;
      _dataVerificationDialogSelectingRange = false;
      _dataVerificationDialogRangeEdited = false;
      _dataVerificationDialogRangeSelectionAnchor = null;
      _dataVerificationDialogRangeSelectionTarget = null;
      _dataVerificationDialogOriginalRule = null;
      _dataVerificationDialogOriginalOptionsText = '';
      _dataVerificationDialogType = 'dropdown';
      _dataVerificationDialogType2 = '';
      _dataVerificationRangeEditorController.clear();
      _dataVerificationSecondEditorController.clear();
      _dataVerificationHintEditorController.clear();
    });
    _focusNode.requestFocus();
  }

  void _startDataVerificationDialogRangeSelection(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final coord = _cellCoordAtLocal(local, settings, metrics);
    if (coord == null || !_canSelectCell(_workbook.activeSheet, coord)) {
      return;
    }
    _dataVerificationDialogRangeSelectionAnchor = coord;
    _applyDataVerificationDialogRangeSelection(coord, coord);
  }

  bool _updateDataVerificationDialogRangeSelection(PointerMoveEvent event) {
    final anchor = _dataVerificationDialogRangeSelectionAnchor;
    if (anchor == null || !_dataVerificationDialogOpen) {
      return false;
    }
    final settings = _workbook.settings;
    final metrics = _workbook.activeSheet.metrics(settings);
    final nextScrollOffset = _autoScrollOffsetForDrag(
      event.localPosition,
      settings,
      metrics,
    );
    final coord = _cellCoordAtLocal(
      event.localPosition,
      settings,
      metrics,
      scrollOverride: nextScrollOffset,
    );
    if (coord == null) {
      return true;
    }
    if (!_canSelectCell(_workbook.activeSheet, coord)) {
      _cancelDataVerificationDialogRangeSelection();
      return true;
    }
    _applyDataVerificationDialogRangeSelection(
      anchor,
      coord,
      nextScrollOffset: nextScrollOffset,
    );
    return true;
  }

  bool _commitDataVerificationDialogRangeSelection() {
    if (_dataVerificationDialogRangeSelectionAnchor == null) {
      return false;
    }
    setState(() {
      _dataVerificationDialogSelectingRange = false;
      _dataVerificationDialogRangeSelectionAnchor = null;
      _dataVerificationDialogRangeSelectionTarget = null;
    });
    return true;
  }

  void _cancelDataVerificationDialogRangeSelection() {
    _dataVerificationDialogSelectingRange = false;
    _dataVerificationDialogRangeSelectionAnchor = null;
    _dataVerificationDialogRangeSelectionTarget = null;
  }

  void _applyDataVerificationDialogRangeSelection(
    FortuneCellCoord anchor,
    FortuneCellCoord extent, {
    Offset? nextScrollOffset,
  }) {
    final target = _dataVerificationDialogRangeSelectionTarget;
    final range = _expandRangeForMergedCells(
      FortuneRange(
        rowStart: math.min(anchor.row, extent.row),
        rowEnd: math.max(anchor.row, extent.row),
        columnStart: math.min(anchor.column, extent.column),
        columnEnd: math.max(anchor.column, extent.column),
      ),
    );
    final rangeText = getRangetxt(
      _workbook,
      _workbook.activeSheet.id,
      range,
      currentSheetId: _workbook.activeSheet.id,
    );
    setState(() {
      if (nextScrollOffset != null) {
        scrollOffset = nextScrollOffset;
      }
      selection = FortuneSelection(
        row: anchor.row,
        column: anchor.column,
        rowEnd: extent.row,
        columnEnd: extent.column,
      );
      _writeSelectionRange(range, anchor);
      if (target == 'dropdown-source') {
        _dataVerificationEditorController.value = TextEditingValue(
          text: rangeText,
          selection: TextSelection.collapsed(offset: rangeText.length),
        );
      } else {
        _dataVerificationDialogRange = range;
        _dataVerificationDialogRangeEdited = true;
        _dataVerificationRangeEditorController.value = TextEditingValue(
          text: rangeText,
          selection: TextSelection.collapsed(offset: rangeText.length),
        );
      }
    });
  }

  FortuneRange? _dataVerificationDialogRangeFromText() {
    final parsed = getRangeByTxt(
      _workbook.activeSheet,
      _dataVerificationRangeEditorController.text,
    );
    final range = parsed.isEmpty ? null : parsed.last;
    if (range == null) {
      return null;
    }
    final sheet = _workbook.activeSheet;
    return _expandRangeForMergedCells(
      FortuneRange(
        rowStart: math.max(0, range.rowStart),
        rowEnd: math.min(_effectiveRowCount(sheet) - 1, range.rowEnd),
        columnStart: math.max(0, range.columnStart),
        columnEnd: math.min(_effectiveColumnCount(sheet) - 1, range.columnEnd),
      ),
    );
  }

  bool _syncDataVerificationDialogRangeFromInput() {
    final range = _dataVerificationDialogRangeFromText();
    if (range == null ||
        range.rowStart > range.rowEnd ||
        range.columnStart > range.columnEnd) {
      _dataVerificationRangeEditorFocusNode.requestFocus();
      return false;
    }
    final rangeText = _rangeTextForDataVerification(range);
    final previousRange = _dataVerificationDialogRange;
    final rangeChanged =
        previousRange == null ||
        previousRange.rowStart != range.rowStart ||
        previousRange.rowEnd != range.rowEnd ||
        previousRange.columnStart != range.columnStart ||
        previousRange.columnEnd != range.columnEnd;
    setState(() {
      _dataVerificationDialogRange = range;
      _dataVerificationDialogRangeEdited =
          _dataVerificationDialogRangeEdited || rangeChanged;
      if (_dataVerificationRangeEditorController.text != rangeText) {
        _dataVerificationRangeEditorController.value = TextEditingValue(
          text: rangeText,
          selection: TextSelection.collapsed(offset: rangeText.length),
        );
      }
    });
    return true;
  }

  void _commitDataVerificationDialog() {
    final coord = _dataVerificationDialogCoord;
    if (coord == null) {
      return;
    }
    if (!_syncDataVerificationDialogRangeFromInput()) {
      return;
    }
    final range = _dataVerificationDialogRange;
    if (range == null) {
      return;
    }
    final options = _dataVerificationOptions({
      'value1': _dataVerificationEditorController.text,
    });
    final hintValue = _dataVerificationHintEditorController.text;
    final rangeText = _rangeTextForDataVerification(range);
    final dialogOriginalRule = _dataVerificationDialogOriginalRule;
    final preserveOriginalRule =
        dialogOriginalRule != null &&
        '${dialogOriginalRule['type'] ?? ''}' != 'dropdown' &&
        _dataVerificationDialogType == '${dialogOriginalRule['type'] ?? ''}' &&
        _dataVerificationDialogType2 ==
            _normalizedDataVerificationDialogType2(
              _dataVerificationDialogType,
              dialogOriginalRule['type2'],
            ) &&
        _dataVerificationEditorController.text ==
            _dataVerificationDialogOriginalOptionsText &&
        (!_dataVerificationDialogUsesSecondValueInput(
              _dataVerificationDialogType,
            ) ||
            _dataVerificationSecondEditorController.text ==
                '${dialogOriginalRule['value2'] ?? ''}');
    if (options.isEmpty &&
        !preserveOriginalRule &&
        _dataVerificationDialogType == 'dropdown') {
      _dataVerificationEditorFocusNode.requestFocus();
      return;
    }
    final sheet = _workbook.activeSheet;
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final dataVerification = Map<String, Object?>.from(sheet.dataVerification);
    var nextSheet = sheet;
    var cellChanged = false;
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
        final key = _cellKey(anchor);
        final raw = sheet.dataVerification[key];
        final originalRule = raw is Map ? Map<String, Object?>.from(raw) : null;
        final Map<String, Object?> nextRule;
        if (preserveOriginalRule) {
          nextRule = Map<String, Object?>.from(dialogOriginalRule);
          nextRule
            ..['checked'] = false
            ..['prohibitInput'] = _dataVerificationDialogProhibitInput
            ..['hintShow'] = _dataVerificationDialogHintShow;
          _setDataVerificationHintValue(
            nextRule,
            hintValue,
            dialogOriginalRule,
          );
        } else if (_dataVerificationDialogType == 'dropdown') {
          nextRule = raw is Map
              ? Map<String, Object?>.from(raw)
              : _defaultDataVerificationRule(
                  rangeText: _rangeTextForDataVerification(range),
                );
          final String dropdownType2;
          if (_dataVerificationDialogAllowMulti) {
            dropdownType2 = 'true';
          } else if (originalRule == null) {
            dropdownType2 = '';
          } else {
            dropdownType2 = 'false';
          }
          nextRule
            ..['type'] = 'dropdown'
            ..['type2'] = dropdownType2
            ..['value1'] = options.join(',')
            ..['checked'] = false
            ..['remote'] = false
            ..['prohibitInput'] = _dataVerificationDialogProhibitInput
            ..['hintShow'] = _dataVerificationDialogHintShow;
          _setDataVerificationHintValue(nextRule, hintValue, originalRule);
          if (originalRule != null &&
              _dataVerificationDialogAllowMulti == false &&
              originalRule['type2'] == 'dropdown') {
            final originalWithoutType2 = Map<String, Object?>.from(originalRule)
              ..remove('type2');
            final nextWithoutType2 = Map<String, Object?>.from(nextRule)
              ..remove('type2');
            if (_jsonLikeEquals(originalWithoutType2, nextWithoutType2)) {
              nextRule['type2'] = 'dropdown';
            }
          }
        } else {
          nextRule = raw is Map
              ? Map<String, Object?>.from(raw)
              : _defaultDataVerificationRule(
                  rangeText: _rangeTextForDataVerification(range),
                );
          final usesValueInputs = _dataVerificationDialogUsesValueInputs(
            _dataVerificationDialogType,
          );
          final usesSecondValueInput =
              _dataVerificationDialogUsesSecondValueInput(
                _dataVerificationDialogType,
              );
          nextRule
            ..['type'] = _dataVerificationDialogType
            ..['type2'] = _dataVerificationDialogType2
            ..['value1'] = usesValueInputs
                ? _dataVerificationEditorController.text
                : ''
            ..['value2'] = usesSecondValueInput
                ? _dataVerificationSecondEditorController.text
                : ''
            ..['checked'] = false
            ..['remote'] = false
            ..['prohibitInput'] = _dataVerificationDialogProhibitInput
            ..['hintShow'] = _dataVerificationDialogHintShow;
          _setDataVerificationHintValue(nextRule, hintValue, originalRule);
        }
        if (_dataVerificationDialogRangeEdited ||
            originalRule == null ||
            originalRule.containsKey('rangeTxt')) {
          nextRule['rangeTxt'] = rangeText;
        }
        dataVerification[key] = nextRule;
        if (preserveOriginalRule && nextRule['type'] == 'checkbox') {
          final checkboxValue = nextRule['value2'];
          final updatedSheet = setCellValue(
            nextSheet,
            anchor.row,
            anchor.column,
            checkboxValue == null ? null : '$checkboxValue',
          );
          if (_cellWouldChange(nextSheet, anchor, updatedSheet.cells[anchor])) {
            cellChanged = true;
          }
          nextSheet = updatedSheet;
        } else if (!preserveOriginalRule && nextRule['type'] == 'checkbox') {
          final updatedSheet = setCellValue(
            nextSheet,
            anchor.row,
            anchor.column,
            _dataVerificationSecondEditorController.text,
          );
          if (_cellWouldChange(nextSheet, anchor, updatedSheet.cells[anchor])) {
            cellChanged = true;
          }
          nextSheet = updatedSheet;
        }
      }
    }
    final changed =
        cellChanged ||
        !_jsonLikeEquals(sheet.dataVerification, dataVerification);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = nextSheet.copyWith(
          dataVerification: dataVerification,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _dataVerificationDialogCoord = null;
      _dataVerificationDialogRange = null;
      _dataVerificationDialogSelectingRange = false;
      _dataVerificationDialogRangeEdited = false;
      _dataVerificationDialogRangeSelectionAnchor = null;
      _dataVerificationDialogRangeSelectionTarget = null;
      _dataVerificationDialogOriginalRule = null;
      _dataVerificationDialogOriginalOptionsText = '';
      _dataVerificationDialogType = 'dropdown';
      _dataVerificationDialogType2 = '';
      _dataVerificationRangeEditorController.clear();
      _dataVerificationSecondEditorController.clear();
      _dataVerificationHintEditorController.clear();
    });
    _focusNode.requestFocus();
  }

  void _deleteDataVerificationDialogRange() {
    final range = _dataVerificationDialogRange;
    if (range == null) {
      return;
    }
    final sheet = _workbook.activeSheet;
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final dataVerification = Map<String, Object?>.from(sheet.dataVerification);
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
        dataVerification.remove(_cellKey(anchor));
      }
    }
    final changed = !_jsonLikeEquals(sheet.dataVerification, dataVerification);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          dataVerification: dataVerification,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _dataVerificationDialogCoord = null;
      _dataVerificationDialogRange = null;
      _dataVerificationDialogSelectingRange = false;
      _dataVerificationDialogRangeEdited = false;
      _dataVerificationDialogRangeSelectionAnchor = null;
      _dataVerificationDialogRangeSelectionTarget = null;
      _dataVerificationDialogOriginalRule = null;
      _dataVerificationDialogOriginalOptionsText = '';
      _dataVerificationDialogType = 'dropdown';
      _dataVerificationDialogType2 = '';
      _dataVerificationSecondEditorController.clear();
      _dataVerificationHintEditorController.clear();
    });
    _focusNode.requestFocus();
  }

  Rect? _splitTextDialogRect([Size? overrideSize]) {
    if (!_splitTextDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    if (size == null) {
      return null;
    }
    return fortuneSplitTextDialogRect(size);
  }

  Rect? _splitTextOtherInputRect([Size? overrideSize]) {
    final rect = _splitTextDialogRect(overrideSize);
    return rect == null ? null : fortuneSplitTextOtherInputRect(rect);
  }

  void _showSplitTextDialog() {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final rawRanges = _rawSelectionRanges(sheet);
    final selectedRanges = rawRanges.isEmpty
        ? <FortuneRange>[range]
        : rawRanges;
    if (selectedRanges.length > 1) {
      _showLocationMessageDialog(widget.locale.splitTextTipNoMulti);
      return;
    }
    if (selectedRanges.single.columnStart != selectedRanges.single.columnEnd) {
      _showLocationMessageDialog(widget.locale.splitTextTipNoMultiColumn);
      return;
    }
    setState(() {
      _closeTransientMenus();
      _splitTextDialogOpen = true;
      _splitTextTab = false;
      _splitTextSemicolon = false;
      _splitTextComma = false;
      _splitTextSpace = false;
      _splitTextOther = false;
      _splitTextConsecutive = false;
      _splitTextOtherController.clear();
    });
    _focusNode.requestFocus();
  }

  String? _splitTextDialogCommandAt(Offset local) {
    final rect = _splitTextDialogRect();
    if (rect == null) {
      return null;
    }
    if (!rect.contains(local)) {
      return 'modal';
    }
    if (fortuneSplitTextCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    for (final key in fortuneSplitTextDelimiterKeys) {
      if (fortuneSplitTextDelimiterRowRect(rect, key).contains(local)) {
        return 'toggle-$key';
      }
    }
    if (fortuneSplitTextOkButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    if (fortuneSplitTextCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    return null;
  }

  void _activateSplitTextDialogCommand(String? command) {
    switch (command) {
      case 'toggle-tab':
        setState(() => _splitTextTab = !_splitTextTab);
        break;
      case 'toggle-semicolon':
        setState(() => _splitTextSemicolon = !_splitTextSemicolon);
        break;
      case 'toggle-comma':
        setState(() => _splitTextComma = !_splitTextComma);
        break;
      case 'toggle-space':
        setState(() => _splitTextSpace = !_splitTextSpace);
        break;
      case 'toggle-other':
        setState(() => _splitTextOther = !_splitTextOther);
        if (_splitTextOther) {
          _splitTextOtherFocusNode.requestFocus();
        }
        break;
      case 'toggle-consecutive':
        setState(() => _splitTextConsecutive = !_splitTextConsecutive);
        break;
      case 'confirm':
        _commitSplitTextDialog();
        break;
      case 'cancel':
      case 'modal':
        setState(() => _splitTextDialogOpen = false);
        _focusNode.requestFocus();
        break;
    }
  }

  List<List<String>> _splitTextPreviewData() {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    return getSplitColumnData(
      sheet,
      selection: range,
      tab: _splitTextTab,
      semicolon: _splitTextSemicolon,
      comma: _splitTextComma,
      space: _splitTextSpace,
      other: _splitTextOther ? _splitTextOtherController.text : null,
      consecutive: _splitTextConsecutive,
    );
  }

  void _commitSplitTextDialog() {
    final data = _splitTextPreviewData();
    if (data.isEmpty || data.first.length <= 1) {
      setState(() => _splitTextDialogOpen = false);
      _focusNode.requestFocus();
      return;
    }
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    final targetRange = FortuneRange(
      rowStart: range.rowStart,
      rowEnd: range.rowStart + data.length - 1,
      columnStart: range.columnStart,
      columnEnd: range.columnStart + data.first.length - 1,
    );
    if (!_canEditRange(sheet, targetRange)) {
      setState(() => _splitTextDialogOpen = false);
      _focusNode.requestFocus();
      return;
    }
    if (_splitTextWouldOverwrite(sheet, data, range)) {
      setState(() {
        _splitTextDialogOpen = false;
        _pendingSplitTextData = data;
        _pendingSplitTextRange = range;
        _locationMessageDialogText = widget.locale.splitConfirmToExe;
        _locationMessageDialogConfirm = true;
      });
      _focusNode.requestFocus();
      return;
    }
    _applySplitTextData(data, range);
  }

  bool _splitTextWouldOverwrite(
    FortuneSheet sheet,
    List<List<String>> data,
    FortuneRange range,
  ) {
    for (var row = 0; row < data.length; row += 1) {
      for (var column = 1; column < data.first.length; column += 1) {
        final coord = FortuneCellCoord(
          range.rowStart + row,
          range.columnStart + column,
        );
        final cell = sheet.cells[coord];
        if (cell != null && !isRealNull(cell.value)) {
          return true;
        }
      }
    }
    return false;
  }

  void _applySplitTextData(List<List<String>> data, FortuneRange range) {
    final sheet = _workbook.activeSheet;
    _recordUndoSnapshot();
    setState(() {
      for (var row = 0; row < data.length; row += 1) {
        for (var column = 0; column < data.first.length; column += 1) {
          final coord = FortuneCellCoord(
            range.rowStart + row,
            range.columnStart + column,
          );
          _setSplitTextCell(sheet, coord, data[row][column]);
        }
      }
      _splitTextDialogOpen = false;
      _locationMessageDialogText = null;
      _locationMessageDialogConfirm = false;
      _pendingSplitTextData = null;
      _pendingSplitTextRange = null;
      _recalculateWorkbookFormulas();
    });
    _focusNode.requestFocus();
  }

  void _setSplitTextCell(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    String value,
  ) {
    final nextSheet = sheet.setCellValue(coord.row, coord.column, value);
    final nextCell = nextSheet.cells[coord];
    if (nextCell == null) {
      sheet.cells.remove(coord);
      sheet.hyperlinks.remove('${coord.row}_${coord.column}');
      _removeFunctionGroupAt(sheet, coord);
      return;
    }
    final splitCell = nextCell.copyWith(inlineRuns: null);
    _setSheetCell(sheet, coord, splitCell);
    _syncSheetHyperlinkForCell(sheet, coord, splitCell);
  }

