  Future<void> _pickImageForInsertDialog() async {
    if (!_imageInsertDialogOpen || _imageInsertIsEditing) {
      return;
    }
    final picker = widget.imagePicker ?? _pickImageFromFileSystem;
    final picked = await picker();
    if (picked == null || !mounted) {
      _focusNode.requestFocus();
      return;
    }
    final shouldDecode = picked.width == null || picked.height == null;
    final decoded = shouldDecode ? await _decodeImageBytes(picked.bytes) : null;
    if (!mounted) {
      decoded?.dispose();
      _focusNode.requestFocus();
      return;
    }
    final imageWidth = decoded?.width ?? picked.width;
    final imageHeight = decoded?.height ?? picked.height;
    if (imageWidth == null || imageHeight == null) {
      decoded?.dispose();
      _focusNode.requestFocus();
      return;
    }
    final displaySize = _imageInsertInitialDisplaySize(
      imageWidth.toDouble(),
      imageHeight.toDouble(),
    );
    _disposeImageInsertDecodedImage();
    setState(() {
      _imageInsertPickResult = picked;
      _imageInsertDecodedImage = decoded;
      _imageInsertFileName = _imageInsertBaseName(picked.fileName);
      _imageInsertOriginalWidthPx = imageWidth.toDouble();
      _imageInsertOriginalHeightPx = imageHeight.toDouble();
      _setImageInsertControllerText(
        _imageInsertWidthController,
        _formatImageInsertNumber(displaySize.width),
      );
      _setImageInsertControllerText(
        _imageInsertHeightController,
        _formatImageInsertNumber(displaySize.height),
      );
    });
    _imageInsertWidthFocusNode.requestFocus();
  }

  void _commitImageInsertDialog() {
    if (_imageInsertEditingImageId != null) {
      _commitImageEditDialog();
      return;
    }
    final picked = _imageInsertPickResult;
    if (!_imageInsertDialogOpen || picked == null) {
      return;
    }
    final widthValue = double.tryParse(_imageInsertWidthController.text.trim());
    final heightValue = double.tryParse(
      _imageInsertHeightController.text.trim(),
    );
    if (widthValue == null ||
        heightValue == null ||
        widthValue <= 0 ||
        heightValue <= 0) {
      _imageInsertWidthFocusNode.requestFocus();
      return;
    }
    final rotation =
        double.tryParse(_imageInsertRotationController.text.trim()) ?? 0;
    final activeSheet = _workbook.activeSheet;
    final anchor = activeSheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(activeSheet, anchor)) {
      _focusNode.requestFocus();
      return;
    }
    final metrics = activeSheet.metrics(_workbook.settings);
    final left = metrics.columnStart(anchor.column);
    final top = metrics.rowStart(anchor.row);
    final src = _imageDataUri(picked);
    final imageId = _newImageId();
    final usesMillimeters = _imageInsertUsesMillimeters;
    final imageWidth = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(widthValue)
        : widthValue;
    final imageHeight = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(heightValue)
        : heightValue;
    final extraFields = <String, Object?>{
      'originWidth': _imageInsertOriginalWidthPx,
      'originHeight': _imageInsertOriginalHeightPx,
      'rotation': rotation,
    };
    if (usesMillimeters) {
      extraFields['widthMm'] = widthValue;
      extraFields['heightMm'] = heightValue;
    }
    final images = List<FortuneImage>.from(activeSheet.images)
      ..add(
        FortuneImage(
          id: imageId,
          src: src,
          left: left,
          top: top,
          width: imageWidth,
          height: imageHeight,
          extraFields: extraFields,
        ),
      );
    final sheets = [..._workbook.sheets];
    _recordUndoSnapshot();
    final previousDecoded = _decodedImages[src];
    previousDecoded?.dispose();
    final decoded = _imageInsertDecodedImage;
    if (decoded != null) {
      _decodedImages[src] = decoded;
      _imageInsertDecodedImage = null;
    }
    sheets[_workbook.activeSheetIndex] = activeSheet.copyWith(images: images);
    setState(() {
      _workbook = _workbook.copyWith(sheets: sheets);
      _activeImageId = imageId;
      _imageInsertDialogOpen = false;
      _imageInsertEditingImageId = null;
      _imageInsertPickResult = null;
      _imageInsertHoveredControl = null;
      _imageInsertPressedControl = null;
    });
    _clearImageInsertInputSelections();
    _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    _focusNode.requestFocus();
  }

  void _commitImageEditDialog() {
    final imageId = _imageInsertEditingImageId;
    final current = imageId == null ? null : _imageById(imageId);
    if (!_imageInsertDialogOpen || current == null) {
      return;
    }
    final widthValue = double.tryParse(_imageInsertWidthController.text.trim());
    final heightValue = double.tryParse(
      _imageInsertHeightController.text.trim(),
    );
    if (widthValue == null ||
        heightValue == null ||
        widthValue <= 0 ||
        heightValue <= 0) {
      _imageInsertWidthFocusNode.requestFocus();
      return;
    }
    final rotation =
        double.tryParse(_imageInsertRotationController.text.trim()) ?? 0;
    final usesMillimeters = _imageInsertUsesMillimeters;
    final imageWidth = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(widthValue)
        : widthValue;
    final imageHeight = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(heightValue)
        : heightValue;
    final extraFields = <String, Object?>{
      ...current.extraFields,
      'rotation': rotation,
    };
    if (usesMillimeters) {
      extraFields['widthMm'] = widthValue;
      extraFields['heightMm'] = heightValue;
    } else {
      extraFields.remove('widthMm');
      extraFields.remove('heightMm');
    }
    _recordUndoSnapshot();
    _replaceImage(
      current.id,
      current.copyWith(
        width: imageWidth,
        height: imageHeight,
        extraFields: extraFields,
      ),
    );
    setState(() {
      _activeImageId = current.id;
      _imageInsertDialogOpen = false;
      _imageInsertEditingImageId = null;
      _imageInsertPickResult = null;
      _imageInsertHoveredControl = null;
      _imageInsertPressedControl = null;
    });
    _clearImageInsertInputSelections();
    _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    _focusNode.requestFocus();
  }

  void _cancelImageInsertDialog() {
    if (!_imageInsertDialogOpen) {
      return;
    }
    _disposeImageInsertDecodedImage();
    setState(() {
      _imageInsertDialogOpen = false;
      _imageInsertEditingImageId = null;
      _imageInsertPickResult = null;
      _imageInsertHoveredControl = null;
      _imageInsertPressedControl = null;
    });
    _clearImageInsertInputSelections();
    _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    _focusNode.requestFocus();
  }

  List<FortuneBarcodeFormatOption> get _effectiveBarcodeFormats {
    return widget.barcodeFormats.isEmpty
        ? const <FortuneBarcodeFormatOption>[
            FortuneBarcodeFormatOption(id: 'qrCode', label: 'QR Code'),
          ]
        : widget.barcodeFormats;
  }

  List<String> get _effectiveBarcodeObjectIds {
    final result = <String>[];
    final seen = <String>{};
    for (final raw in widget.barcodeObjectIds) {
      final value = raw.trim();
      if (value.isEmpty) {
        continue;
      }
      if (seen.add(value.toLowerCase())) {
        result.add(value);
      }
    }
    if (result.isEmpty) {
      result.add('#BARCODE');
    }
    final current = _barcodeObjectIdController.text.trim();
    if (_barcodeDialogOpen &&
        current.isNotEmpty &&
        seen.add(current.toLowerCase())) {
      result.add(current);
    }
    return result;
  }

  int _barcodeObjectIdIndexForValue(String value) {
    final normalized = value.trim().toLowerCase();
    final options = _effectiveBarcodeObjectIds;
    final index = options.indexWhere(
      (option) => option.toLowerCase() == normalized,
    );
    return index < 0 ? 0 : index;
  }

  String get _selectedBarcodeObjectId {
    final options = _effectiveBarcodeObjectIds;
    final index = _barcodeObjectIdIndex.clamp(0, options.length - 1);
    return options[index];
  }

  void _setBarcodeObjectIdSelection(String value) {
    _setImageInsertControllerText(_barcodeObjectIdController, value);
    _barcodeObjectIdIndex = _barcodeObjectIdIndexForValue(value);
  }

  FortuneBarcodeFormatOption get _selectedBarcodeFormat {
    if (_barcodeIsEditing &&
        !_barcodeFormatChanged &&
        _barcodeEditingFormatId != null) {
      return _barcodeFormatOptionForMetadata(
        _barcodeEditingFormatId,
        _barcodeEditingFormatLabel,
      );
    }
    final formats = _effectiveBarcodeFormats;
    final index = _barcodeFormatIndex.clamp(0, formats.length - 1);
    return formats[index];
  }

  int _barcodeFormatIndexForMetadata(String? id, String? label) {
    final formats = _effectiveBarcodeFormats;
    if (id != null && id.trim().isNotEmpty) {
      final normalizedId = id.trim().toLowerCase();
      final exactIndex = formats.indexWhere((format) => format.id == id);
      if (exactIndex >= 0) {
        return exactIndex;
      }
      final normalizedIndex = formats.indexWhere(
        (format) => format.id.toLowerCase() == normalizedId,
      );
      if (normalizedIndex >= 0) {
        return normalizedIndex;
      }
    }
    if (label != null && label.trim().isNotEmpty) {
      final normalizedLabel = label.trim().toLowerCase();
      return formats.indexWhere(
        (format) => format.label.toLowerCase() == normalizedLabel,
      );
    }
    return -1;
  }

  FortuneBarcodeFormatOption _barcodeFormatOptionForMetadata(
    String? id,
    String? label, [
    int? fallbackIndex,
  ]) {
    final formats = _effectiveBarcodeFormats;
    final index = _barcodeFormatIndexForMetadata(id, label);
    if (index >= 0) {
      return formats[index];
    }
    final fallbackId = id?.trim();
    if (fallbackId != null && fallbackId.isNotEmpty) {
      final fallbackLabel = label?.trim();
      return FortuneBarcodeFormatOption(
        id: fallbackId,
        label: fallbackLabel == null || fallbackLabel.isEmpty
            ? fallbackId
            : fallbackLabel,
      );
    }
    final indexFallback = (fallbackIndex ?? _barcodeFormatIndex).clamp(
      0,
      formats.length - 1,
    );
    return formats[indexFallback];
  }

  int _barcodeFormatIndexForId(String id) {
    final formats = _effectiveBarcodeFormats;
    final index = formats.indexWhere((format) => format.id == id);
    return index < 0 ? 0 : index;
  }

  int _defaultBarcodeFormatIndex() {
    return _barcodeFormatIndexForId('code128');
  }

  double _initialBarcodeFormatMenuScrollOffset() {
    final formats = _effectiveBarcodeFormats;
    final maxScrollOffset = fortuneBarcodeFormatMenuMaxScrollOffset(
      formats.length,
    );
    if (maxScrollOffset <= 0 || formats.isEmpty) {
      return 0;
    }
    final index = _barcodeFormatIndex.clamp(0, formats.length - 1);
    const visibleHeight = 8 * fortuneContextMenuRowHeight;
    final selectedCenter =
        index * fortuneContextMenuRowHeight + fortuneContextMenuRowHeight / 2;
    return (selectedCenter - visibleHeight / 2)
        .clamp(0.0, maxScrollOffset)
        .toDouble();
  }

  double _initialBarcodeObjectIdMenuScrollOffset() {
    final options = _effectiveBarcodeObjectIds;
    final maxScrollOffset = fortuneBarcodeObjectIdMenuMaxScrollOffset(
      options.length,
    );
    if (maxScrollOffset <= 0 || options.isEmpty) {
      return 0;
    }
    final index = _barcodeObjectIdIndex.clamp(0, options.length - 1);
    const visibleHeight = 8 * fortuneContextMenuRowHeight;
    final selectedCenter =
        index * fortuneContextMenuRowHeight + fortuneContextMenuRowHeight / 2;
    return (selectedCenter - visibleHeight / 2)
        .clamp(0.0, maxScrollOffset)
        .toDouble();
  }

  int? _barcodeObjectIdMenuIndexAt(Offset local) {
    final rect = _barcodeDialogRect();
    if (rect == null || !_barcodeObjectIdMenuOpen) {
      return null;
    }
    final options = _effectiveBarcodeObjectIds;
    final menu = fortuneBarcodeObjectIdMenuRect(rect, options.length);
    if (!menu.contains(local)) {
      return null;
    }
    final index =
        ((local.dy - menu.top + _barcodeObjectIdMenuScrollOffset) /
                fortuneContextMenuRowHeight)
            .floor();
    return index >= 0 && index < options.length ? index : null;
  }

  int? _barcodeFormatMenuIndexAt(Offset local) {
    final rect = _barcodeDialogRect();
    if (rect == null || !_barcodeFormatMenuOpen) {
      return null;
    }
    final menu = fortuneBarcodeFormatMenuRect(
      rect,
      _effectiveBarcodeFormats.length,
    );
    if (!menu.contains(local)) {
      return null;
    }
    final index =
        ((local.dy - menu.top + _barcodeFormatMenuScrollOffset) /
                fortuneContextMenuRowHeight)
            .floor();
    return index >= 0 && index < _effectiveBarcodeFormats.length ? index : null;
  }

  int? _barcodeTextFontMenuIndexAt(Offset local) {
    return _barcodeTextMenuIndexAt(
      local,
      open: _barcodeTextFontMenuOpen,
      itemCount: _barcodeTextFontOptions.length,
      scrollOffset: _barcodeTextFontMenuScrollOffset,
      menuRect: (dialogRect, itemCount) => fortuneBarcodeTextFontMenuRect(
        dialogRect,
        itemCount,
        labels: _barcodeTextFontOptions,
      ),
    );
  }

  int? _barcodeTextFontSizeMenuIndexAt(Offset local) {
    return _barcodeTextMenuIndexAt(
      local,
      open: _barcodeTextFontSizeMenuOpen,
      itemCount: _barcodeTextFontSizeOptions.length,
      scrollOffset: _barcodeTextFontSizeMenuScrollOffset,
      menuRect: fortuneBarcodeTextFontSizeMenuRect,
    );
  }

  int? _barcodeTextMenuIndexAt(
    Offset local, {
    required bool open,
    required int itemCount,
    required double scrollOffset,
    required Rect Function(Rect dialogRect, int itemCount) menuRect,
  }) {
    final rect = _barcodeDialogRect();
    if (rect == null || !open) {
      return null;
    }
    final menu = menuRect(rect, itemCount);
    if (!menu.contains(local)) {
      return null;
    }
    final index =
        ((local.dy - menu.top + scrollOffset) / fortuneContextMenuRowHeight)
            .floor();
    return index >= 0 && index < itemCount ? index : null;
  }

