  void _showBarcodeEditDialog(FortuneImage image) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final extra = image.extraFields;
    final formatId = extra['barcodeFormatId']?.toString();
    final formatLabel = extra['barcodeFormatLabel']?.toString();
    final formatIndex = _barcodeFormatIndexForMetadata(formatId, formatLabel);
    final fallbackFormatIndex = formatIndex >= 0
        ? formatIndex
        : _defaultBarcodeFormatIndex();
    final originalFormat = _barcodeFormatOptionForMetadata(
      formatId,
      formatLabel,
      fallbackFormatIndex,
    );
    final widthValue = _barcodeEditDisplayLogicalSize(image.width);
    final heightValue = _barcodeEditDisplayLogicalSize(image.height);
    final barHeightValue = _barcodeEditBarHeightValue(image);
    final rotation = _imageRotationDegrees(extra['rotation']);
    setState(() {
      _closeTransientMenus();
      _barcodeDialogOpen = true;
      _barcodeEditingImageId = image.id;
      _barcodeEditingFormatId = originalFormat.id;
      _barcodeEditingFormatLabel = originalFormat.label;
      _barcodeFormatChanged = false;
      _setBarcodeObjectIdSelection(
        extra[fortuneBarcodeObjectIdExtraKey]?.toString() ?? image.id,
      );
      _barcodeObjectIdMenuOpen = false;
      _barcodeObjectIdMenuHoveredIndex = null;
      _barcodeObjectIdMenuScrollOffset = 0;
      _barcodeFormatIndex = fallbackFormatIndex;
      _barcodeAspectLocked = true;
      _barcodeFormatMenuOpen = false;
      _barcodeFormatMenuHoveredIndex = null;
      _barcodeFormatMenuScrollOffset = 0;
      _barcodeHumanReadableFontFamily =
          extra['barcodeHumanReadableFontFamily']?.toString() ??
          _selectedBarcodeTextFontFamily;
      _barcodeHumanReadableFontSize = _barcodeEditTextFontSizeValue(image);
      _barcodeTextFontMenuOpen = false;
      _barcodeTextFontMenuHoveredIndex = null;
      _barcodeTextFontMenuScrollOffset = 0;
      _barcodeTextFontSizeMenuOpen = false;
      _barcodeTextFontSizeMenuHoveredIndex = null;
      _barcodeTextFontSizeMenuScrollOffset = 0;
      _barcodeShowHumanReadableText = extra['barcodeShowText'] == true;
      _barcodeHoveredControl = null;
      _barcodePressedControl = null;
      _barcodeErrorText = null;
      _toolbarHoveredKey = null;
      _toolbarHoveredComboArrowKey = null;
      _barcodeUpdatingPair = true;
      try {
        _setImageInsertControllerText(
          _barcodeTextController,
          extra['barcodeText']?.toString() ?? '',
        );
        _setImageInsertControllerText(
          _barcodeWidthController,
          _formatImageInsertNumber(widthValue),
        );
        _setImageInsertControllerText(
          _barcodeHeightController,
          _formatImageInsertNumber(heightValue),
        );
        _setImageInsertControllerText(
          _barcodeRotationController,
          _formatImageInsertNumber(rotation),
        );
        _setImageInsertControllerText(
          _barcodeModuleScaleController,
          _formatImageInsertNumber(
            _metadataDouble(extra['barcodeModuleScale'], 3),
          ),
        );
        _setImageInsertControllerText(
          _barcodeBarHeightController,
          _formatImageInsertNumber(barHeightValue),
        );
        _setImageInsertControllerText(
          _barcodeLeadingQuietZoneController,
          extra['barcodeLeadingText']?.toString() ?? '',
        );
        _setImageInsertControllerText(
          _barcodeTrailingQuietZoneController,
          extra['barcodeTrailingText']?.toString() ?? '',
        );
      } finally {
        _barcodeUpdatingPair = false;
      }
    });
    fortuneSheetDebugLog(
      'barcode edit open image=${image.id} metadataFormatId=$formatId '
      'metadataFormatLabel=$formatLabel formatIndex=$formatIndex '
      'fallbackFormatIndex=$fallbackFormatIndex '
      'editingFormat=${originalFormat.id}/${originalFormat.label}',
    );
    _barcodeTextFocusNode.requestFocus();
  }

  Future<void> _commitBarcodeDialog() async {
    if (!_barcodeDialogOpen) {
      return;
    }
    final renderer = widget.barcodeRenderer;
    if (renderer == null) {
      setState(() => _barcodeErrorText = '바코드 생성기를 찾을 수 없습니다.');
      return;
    }
    final text = _barcodeTextController.text.trim();
    final objectId = _barcodeObjectIdController.text.trim();
    final widthValue = double.tryParse(_barcodeWidthController.text.trim());
    final heightValue = double.tryParse(_barcodeHeightController.text.trim());
    final moduleScale =
        double.tryParse(_barcodeModuleScaleController.text.trim()) ?? 3;
    final barHeightValue =
        double.tryParse(_barcodeBarHeightController.text.trim()) ?? 10;
    final leadingText = _barcodeLeadingQuietZoneController.text;
    final trailingText = _barcodeTrailingQuietZoneController.text;
    if (objectId.isEmpty) {
      setState(() => _barcodeErrorText = 'ID를 선택하세요.');
      return;
    }
    if (text.isEmpty) {
      _barcodeTextFocusNode.requestFocus();
      setState(() => _barcodeErrorText = '내용을 입력하세요.');
      return;
    }
    if (widthValue == null ||
        heightValue == null ||
        widthValue < 0 ||
        heightValue < 0 ||
        moduleScale <= 0 ||
        barHeightValue <= 0) {
      _barcodeWidthFocusNode.requestFocus();
      setState(() => _barcodeErrorText = '입력값을 확인하세요.');
      return;
    }
    final rotation =
        double.tryParse(_barcodeRotationController.text.trim()) ?? 0;
    final usesMillimeters = _barcodeUsesMillimeters;
    final requestedWidth = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(widthValue)
        : widthValue;
    final requestedHeight = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(heightValue)
        : heightValue;
    final requestedBarHeight = usesMillimeters
        ? fortuneMillimetersToLogicalPixels(barHeightValue)
        : barHeightValue;
    final format = _selectedBarcodeFormat;
    fortuneSheetDebugLog(
      'barcode commit editingImageId=$_barcodeEditingImageId '
      'format=${format.id}/${format.label} formatChanged=$_barcodeFormatChanged '
      'editingFormat=$_barcodeEditingFormatId/$_barcodeEditingFormatLabel '
      'index=$_barcodeFormatIndex text="$text" width=$requestedWidth '
      'height=$requestedHeight barHeight=$requestedBarHeight '
      'showText=$_barcodeShowHumanReadableText',
    );
    final result = await renderer(
      FortuneBarcodeRequest(
        text: text,
        formatId: format.id,
        width: requestedWidth,
        height: requestedHeight,
        rotation: rotation,
        moduleScale: moduleScale,
        barHeight: requestedBarHeight,
        leadingText: leadingText,
        trailingText: trailingText,
        showHumanReadableText: _barcodeShowHumanReadableText,
        humanReadableFontFamily: _selectedBarcodeTextFontFamily,
        humanReadableFontSize: _barcodeHumanReadableFontSize,
      ),
    );
    if (!mounted) {
      return;
    }
    if (result == null) {
      fortuneSheetDebugLog(
        'barcode commit renderer-null format=${format.id}/${format.label}',
      );
      setState(() => _barcodeErrorText = '바코드를 생성하지 못했습니다.');
      return;
    }
    final imageWidth = requestedWidth > 0
        ? requestedWidth
        : (result.pixelWidth ?? 120).toDouble();
    final imageHeight = requestedHeight > 0
        ? requestedHeight
        : (result.pixelHeight ?? 60).toDouble();
    final renderedBodyTop = (result.bodyTop ?? 0).toDouble();
    final renderedBodyHeight = _barcodeShowHumanReadableText
        ? (result.bodyHeight?.toDouble() ??
        math.min(requestedBarHeight, imageHeight))
        : imageHeight;
    final src = _bytesDataUri(result.bytes, result.mimeType);
    final extraFields = <String, Object?>{
      'fortuneBarcode': true,
      fortuneBarcodeObjectIdExtraKey: objectId,
      'barcodeText': text,
      'barcodeFormatId': format.id,
      'barcodeFormatLabel': format.label,
      'originWidth': result.pixelWidth ?? imageWidth,
      'originHeight': result.pixelHeight ?? imageHeight,
      'rotation': rotation,
      'barcodeModuleScale': moduleScale,
      'barcodeBarHeight': barHeightValue,
      'barcodeLeadingText': leadingText,
      'barcodeTrailingText': trailingText,
      'barcodeShowText': _barcodeShowHumanReadableText,
      'barcodeHumanReadableFontFamily': _selectedBarcodeTextFontFamily,
      'barcodeHumanReadableFontSize': _barcodeHumanReadableFontSize,
      fortuneBarcodeBodyTopExtraKey: renderedBodyTop,
      fortuneBarcodeBodyHeightExtraKey: renderedBodyHeight,
      fortuneBarcodeBodyRatioExtraKey: imageHeight <= 0
          ? 1.0
          : (renderedBodyHeight / imageHeight)
            .clamp(0.0, 1.0),
        // The ID label is an editor-only overlay drawn above the barcode body.
        // Print/export paths must exclude it and use this metadata only to
        // identify barcode objects.
        fortuneBarcodeIdLabelPrintExcludedExtraKey: true,
    };
    if (usesMillimeters) {
      extraFields['widthMm'] = widthValue > 0
          ? widthValue
          : fortuneLogicalPixelsToMillimeters(imageWidth);
      extraFields['heightMm'] = heightValue > 0
          ? heightValue
          : fortuneLogicalPixelsToMillimeters(imageHeight);
    }
    final activeSheet = _workbook.activeSheet;
    final editingImageId = _barcodeEditingImageId;
    _recordUndoSnapshot();
    if (editingImageId != null) {
      final current = _imageById(editingImageId);
      if (current == null) {
        return;
      }
      _replaceImage(
        editingImageId,
        current.copyWith(
          src: src,
          width: imageWidth,
          height: imageHeight,
          extraFields: extraFields,
        ),
      );
      fortuneSheetDebugLog(
        'barcode commit replace image=$editingImageId '
        'savedFormat=${extraFields['barcodeFormatId']}/'
        '${extraFields['barcodeFormatLabel']} '
        'imageSize=$imageWidth x $imageHeight',
      );
      setState(() {
        _activeImageId = editingImageId;
        _barcodeDialogOpen = false;
        _barcodeEditingImageId = null;
        _barcodeEditingFormatId = null;
        _barcodeEditingFormatLabel = null;
        _barcodeFormatChanged = false;
        _barcodeHoveredControl = null;
        _barcodePressedControl = null;
        _barcodeObjectIdMenuOpen = false;
        _barcodeObjectIdMenuHoveredIndex = null;
        _barcodeObjectIdMenuScrollOffset = 0;
        _barcodeFormatMenuOpen = false;
        _barcodeFormatMenuHoveredIndex = null;
        _barcodeFormatMenuScrollOffset = 0;
        _barcodeTextFontMenuOpen = false;
        _barcodeTextFontMenuHoveredIndex = null;
        _barcodeTextFontMenuScrollOffset = 0;
        _barcodeTextFontSizeMenuOpen = false;
        _barcodeTextFontSizeMenuHoveredIndex = null;
        _barcodeTextFontSizeMenuScrollOffset = 0;
        _barcodeErrorText = null;
      });
    } else {
      final anchor = activeSheet.mergeAnchorFor(
        FortuneCellCoord(selection.row, selection.column),
      );
      if (!_canEditCell(activeSheet, anchor)) {
        _focusNode.requestFocus();
        return;
      }
      final metrics = activeSheet.metrics(_workbook.settings);
      final imageId = _newImageId();
      final images = List<FortuneImage>.from(activeSheet.images)
        ..add(
          FortuneImage(
            id: imageId,
            src: src,
            left: metrics.columnStart(anchor.column),
            top: metrics.rowStart(anchor.row),
            width: imageWidth,
            height: imageHeight,
            extraFields: extraFields,
          ),
        );
      final sheets = [..._workbook.sheets];
      sheets[_workbook.activeSheetIndex] = activeSheet.copyWith(images: images);
      setState(() {
        _workbook = _workbook.copyWith(sheets: sheets);
        _activeImageId = imageId;
        _barcodeDialogOpen = false;
        _barcodeEditingImageId = null;
        _barcodeEditingFormatId = null;
        _barcodeEditingFormatLabel = null;
        _barcodeFormatChanged = false;
        _barcodeHoveredControl = null;
        _barcodePressedControl = null;
        _barcodeObjectIdMenuOpen = false;
        _barcodeObjectIdMenuHoveredIndex = null;
        _barcodeObjectIdMenuScrollOffset = 0;
        _barcodeFormatMenuOpen = false;
        _barcodeFormatMenuHoveredIndex = null;
        _barcodeFormatMenuScrollOffset = 0;
        _barcodeTextFontMenuOpen = false;
        _barcodeTextFontMenuHoveredIndex = null;
        _barcodeTextFontMenuScrollOffset = 0;
        _barcodeTextFontSizeMenuOpen = false;
        _barcodeTextFontSizeMenuHoveredIndex = null;
        _barcodeTextFontSizeMenuScrollOffset = 0;
        _barcodeErrorText = null;
      });
    }
    _clearBarcodeInputSelections();
    _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    _decodeImageIfNeeded(src);
    _focusNode.requestFocus();
  }

  void _cancelBarcodeDialog() {
    if (!_barcodeDialogOpen) {
      return;
    }
    setState(() {
      _barcodeDialogOpen = false;
      _barcodeEditingImageId = null;
      _barcodeEditingFormatId = null;
      _barcodeEditingFormatLabel = null;
      _barcodeFormatChanged = false;
      _barcodeHoveredControl = null;
      _barcodePressedControl = null;
      _barcodeObjectIdMenuOpen = false;
      _barcodeObjectIdMenuHoveredIndex = null;
      _barcodeObjectIdMenuScrollOffset = 0;
      _barcodeFormatMenuOpen = false;
      _barcodeFormatMenuHoveredIndex = null;
      _barcodeFormatMenuScrollOffset = 0;
      _barcodeTextFontMenuOpen = false;
      _barcodeTextFontMenuHoveredIndex = null;
      _barcodeTextFontMenuScrollOffset = 0;
      _barcodeTextFontSizeMenuOpen = false;
      _barcodeTextFontSizeMenuHoveredIndex = null;
      _barcodeTextFontSizeMenuScrollOffset = 0;
      _barcodeErrorText = null;
    });
    _clearBarcodeInputSelections();
    _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    _focusNode.requestFocus();
  }

  void _disposeImageInsertDecodedImage() {
    _imageInsertDecodedImage?.dispose();
    _imageInsertDecodedImage = null;
  }

  String _imageInsertBaseName(String fileName) {
    final parts = fileName.split(RegExp(r'[\\/]'));
    return parts.isEmpty || parts.last.isEmpty ? fileName : parts.last;
  }

  double _logicalPixelsToMillimeters(double pixels) => pixels * 25.4 / 96.0;

  bool get _imageInsertUsesMillimeters {
    return fortuneSheetGridClientPhysicalSize(_workbook.activeSheet) != null;
  }

  String get _imageInsertUnitLabel => _imageInsertUsesMillimeters ? 'mm' : 'px';

  Size _imageInsertInitialDisplaySize(double imageWidth, double imageHeight) {
    final logicalSize = _imageInsertVisibleLogicalSize(imageWidth, imageHeight);
    if (_imageInsertUsesMillimeters) {
      return Size(
        _logicalPixelsToMillimeters(logicalSize.width),
        _logicalPixelsToMillimeters(logicalSize.height),
      );
    }
    return logicalSize;
  }

  Size _imageInsertVisibleLogicalSize(double imageWidth, double imageHeight) {
    final initialWidth = _imageInsertUsesMillimeters
        ? imageWidth
        : imageWidth * 0.5;
    final initialHeight = _imageInsertUsesMillimeters
        ? imageHeight
        : imageHeight * 0.5;
    if (initialWidth <= 0 || initialHeight <= 0) {
      return Size(initialWidth, initialHeight);
    }
    final viewport = _sheetDataViewportSize(
      _lastCanvasSize ?? context.size,
      _workbook.settings,
      _workbook.activeSheet,
    );
    if (viewport == null || viewport.width <= 0 || viewport.height <= 0) {
      return Size(initialWidth, initialHeight);
    }
    final maxWidth = viewport.width * 0.8;
    final maxHeight = viewport.height * 0.8;
    final scale = math.min(
      1.0,
      math.min(maxWidth / initialWidth, maxHeight / initialHeight),
    );
    return Size(initialWidth * scale, initialHeight * scale);
  }

  double _imageInsertDisplayLogicalSize(double logicalPixels, Object? rawMm) {
    if (_imageInsertUsesMillimeters) {
      if (rawMm is num) {
        return rawMm.toDouble();
      }
      if (rawMm is String) {
        return double.tryParse(rawMm.trim()) ??
            _logicalPixelsToMillimeters(logicalPixels);
      }
      return _logicalPixelsToMillimeters(logicalPixels);
    }
    return logicalPixels;
  }

  String _formatImageInsertNumber(double value) {
    final fixed = value.toStringAsFixed(2);
    return fixed.replaceFirst(RegExp(r'\.?0+$'), '');
  }

  void _setImageInsertControllerText(
    TextEditingController controller,
    String text,
  ) {
    controller.value = TextEditingValue(
      text: text,
      selection: TextSelection.collapsed(offset: text.length),
    );
  }

  void _collapseDialogInputSelection(TextEditingController controller) {
    final selection = controller.selection;
    if (!selection.isValid || selection.isCollapsed) {
      return;
    }
    final offset = selection.extentOffset.clamp(0, controller.text.length);
    controller.value = controller.value.copyWith(
      selection: TextSelection.collapsed(offset: offset),
      composing: TextRange.empty,
    );
  }

  void _clearImageInsertInputSelections({TextEditingController? except}) {
    for (final input in _imageInsertDialogInputs) {
      if (identical(input.controller, except)) {
        continue;
      }
      _collapseDialogInputSelection(input.controller);
    }
  }

  void _clearBarcodeInputSelections({TextEditingController? except}) {
    for (final input in _barcodeDialogInputs) {
      if (identical(input.controller, except)) {
        continue;
      }
      _collapseDialogInputSelection(input.controller);
    }
  }

  void _handleImageInsertInputFocusChanged() {
    if (!_imageInsertDialogOpen) {
      return;
    }
    for (final input in _imageInsertDialogInputs) {
      if (!input.focusNode.hasFocus) {
        _collapseDialogInputSelection(input.controller);
      }
    }
    if (!_imageInsertDialogInputs.any((input) => input.focusNode.hasFocus)) {
      _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    }
  }

  void _handleBarcodeInputFocusChanged() {
    if (!_barcodeDialogOpen) {
      return;
    }
    for (final input in _barcodeDialogInputs) {
      if (!input.focusNode.hasFocus) {
        _collapseDialogInputSelection(input.controller);
      }
    }
    if (!_barcodeDialogInputs.any((input) => input.focusNode.hasFocus)) {
      _endImageInsertInputSelectionDrag(_imageInsertDragSelectionPointer ?? -1);
    }
  }

  void _handleImageInsertWidthChanged() {
    if (_imageInsertUpdatingPair || !_imageInsertAspectLocked) {
      return;
    }
    final ratio = _imageInsertAspectRatio;
    final width = double.tryParse(_imageInsertWidthController.text.trim());
    if (ratio == null || width == null || width <= 0) {
      return;
    }
    _imageInsertUpdatingPair = true;
    _setImageInsertControllerText(
      _imageInsertHeightController,
      _formatImageInsertNumber(width / ratio),
    );
    _imageInsertUpdatingPair = false;
  }

  void _handleImageInsertHeightChanged() {
    if (_imageInsertUpdatingPair || !_imageInsertAspectLocked) {
      return;
    }
    final ratio = _imageInsertAspectRatio;
    final height = double.tryParse(_imageInsertHeightController.text.trim());
    if (ratio == null || height == null || height <= 0) {
      return;
    }
    _imageInsertUpdatingPair = true;
    _setImageInsertControllerText(
      _imageInsertWidthController,
      _formatImageInsertNumber(height * ratio),
    );
    _imageInsertUpdatingPair = false;
  }

  double get _barcodeAspectRatio => math.max(0.1, _selectedBarcodeFormat.ratio);

  void _handleBarcodeWidthChanged() {
    if (_barcodeUpdatingPair || !_barcodeAspectLocked) {
      return;
    }
    final width = double.tryParse(_barcodeWidthController.text.trim());
    if (!_barcodeDialogOpen || width == null || width <= 0) {
      return;
    }
    _barcodeUpdatingPair = true;
    _setImageInsertControllerText(
      _barcodeHeightController,
      _formatImageInsertNumber(width / _barcodeAspectRatio),
    );
    _barcodeUpdatingPair = false;
  }

  void _handleBarcodeHeightChanged() {
    if (_barcodeUpdatingPair || !_barcodeAspectLocked) {
      return;
    }
    final height = double.tryParse(_barcodeHeightController.text.trim());
    if (!_barcodeDialogOpen || height == null || height <= 0) {
      return;
    }
    _barcodeUpdatingPair = true;
    _setImageInsertControllerText(
      _barcodeWidthController,
      _formatImageInsertNumber(height * _barcodeAspectRatio),
    );
    _barcodeUpdatingPair = false;
  }

  void _toggleBarcodeAspectLock() {
    if (!_barcodeDialogOpen) {
      return;
    }
    setState(() {
      _barcodeAspectLocked = !_barcodeAspectLocked;
    });
    if (_barcodeAspectLocked) {
      _handleBarcodeWidthChanged();
    }
  }

  void _cycleBarcodeRotation() {
    const values = <double>[0, 90, 180, 270];
    final current =
        double.tryParse(_barcodeRotationController.text.trim()) ?? 0;
    var index = values.indexWhere((value) => (value - current).abs() < 0.01);
    index = index < 0 ? 0 : (index + 1) % values.length;
    _setImageInsertControllerText(
      _barcodeRotationController,
      _formatImageInsertNumber(values[index]),
    );
  }

  void _toggleBarcodeFormatMenu() {
    if (!_barcodeDialogOpen) {
      return;
    }
    setState(() {
      final nextOpen = !_barcodeFormatMenuOpen;
      _barcodeFormatMenuOpen = nextOpen;
      _barcodeFormatMenuHoveredIndex = null;
      _barcodeFormatMenuScrollOffset = nextOpen
          ? _initialBarcodeFormatMenuScrollOffset()
          : 0;
      _barcodeObjectIdMenuOpen = false;
      _barcodeTextFontMenuOpen = false;
      _barcodeTextFontSizeMenuOpen = false;
      _barcodeErrorText = null;
    });
