    setState(() {
      _barcodeFormatIndex = index.clamp(0, _effectiveBarcodeFormats.length - 1);
      _barcodeFormatChanged = true;
      _barcodeFormatMenuOpen = false;
      _barcodeFormatMenuHoveredIndex = null;
      _barcodeFormatMenuScrollOffset = 0;
      _barcodeTextFontMenuOpen = false;
      _barcodeTextFontSizeMenuOpen = false;
      _barcodeErrorText = null;
    });
    final selected = _effectiveBarcodeFormats[_barcodeFormatIndex];
    fortuneSheetDebugLog(
      'barcode format select requestedIndex=$index '
      'selected=$_barcodeFormatIndex ${selected.id}/${selected.label}',
    );
    if (_barcodeAspectLocked) {
      _handleBarcodeWidthChanged();
    }
