  double? get _imageInsertAspectRatio {
    final width = _imageInsertOriginalWidthPx;
    final height = _imageInsertOriginalHeightPx;
    if (width == null || height == null || width <= 0 || height <= 0) {
      return null;
    }
    return width / height;
  }

