  void _cycleImageInsertRotation() {
    const values = <double>[0, 90, 180, 270];
    final current =
        double.tryParse(_imageInsertRotationController.text.trim()) ?? 0;
    double next = values.first;
    for (final value in values) {
      if (value > current % 360) {
        next = value;
        break;
      }
    }
    _setImageInsertControllerText(
      _imageInsertRotationController,
      _formatImageInsertNumber(next),
    );
    setState(() {});
  }

  String _newImageId() {
    final random = math.Random().nextInt(0x7fffffff).toRadixString(36);
    final time = DateTime.now().millisecondsSinceEpoch.toRadixString(36);
    return 'img_${random}_$time';
  }

  Future<ui.Image?> _decodeImageBytes(Uint8List bytes) async {
    try {
      final codec = await ui.instantiateImageCodec(bytes);
      final frame = await codec.getNextFrame();
      codec.dispose();
      return frame.image;
    } on Object {
      return null;
    }
  }

  Rect _imageRect(FortuneImage image, FortuneSettings settings) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final zoomRatio = _workbook.activeSheet.zoomRatio <= 0
        ? 1.0
        : _workbook.activeSheet.zoomRatio;
    return Rect.fromLTWH(
      _sheetDataLeft(settings) + image.left * zoomRatio - scrollOffset.dx,
      sheetTop +
          _sheetDataTop(settings) +
          image.top * zoomRatio -
          scrollOffset.dy,
      image.width * zoomRatio,
      image.height * zoomRatio,
    );
  }

  FortuneCellCoord _imageAnchorCoord(
    FortuneImage image,
    FortuneSheetMetrics metrics,
  ) {
    return FortuneCellCoord(
      metrics.rowAt(image.top).index,
      metrics.columnAt(image.left).index,
    );
  }

  List<FortuneImage> _imagesForInternalPaste(
    FortuneSheet sheet,
    FortuneRange targetRange,
    List<FortuneImage> images, {
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    if (images.isEmpty) {
      return const [];
    }
    final metrics = sheet.metrics(_workbook.settings);
    final targetVisibleRows = [
      for (var row = targetRange.rowStart; row <= targetRange.rowEnd; row += 1)
        if (!sheet.hiddenRows.contains(row)) row,
    ];
    final targetVisibleColumns = [
      for (
        var column = targetRange.columnStart;
        column <= targetRange.columnEnd;
        column += 1
      )
        if (!sheet.hiddenColumns.contains(column)) column,
    ];
    return [
      for (final image in images)
        ?_imageForInternalPaste(
          image,
          metrics,
          copiedVisibleRows,
          copiedVisibleColumns,
          targetVisibleRows,
          targetVisibleColumns,
        ),
    ];
  }

  FortuneImage? _imageForInternalPaste(
    FortuneImage image,
    FortuneSheetMetrics metrics,
    List<int> copiedVisibleRows,
    List<int> copiedVisibleColumns,
    List<int> targetVisibleRows,
    List<int> targetVisibleColumns,
  ) {
    final sourceAnchor = _imageAnchorCoord(image, metrics);
    final sourceRowIndex = copiedVisibleRows.indexOf(sourceAnchor.row);
    final sourceColumnIndex = copiedVisibleColumns.indexOf(sourceAnchor.column);
    if (sourceRowIndex < 0 ||
        sourceColumnIndex < 0 ||
        sourceRowIndex >= targetVisibleRows.length ||
        sourceColumnIndex >= targetVisibleColumns.length) {
      return null;
    }
    final targetRow = targetVisibleRows[sourceRowIndex];
    final targetColumn = targetVisibleColumns[sourceColumnIndex];
    final dx =
        metrics.columnStart(targetColumn) -
        metrics.columnStart(sourceAnchor.column);
    final dy = metrics.rowStart(targetRow) - metrics.rowStart(sourceAnchor.row);
    return image.copyWith(
      id: _newImageId(),
      left: image.left + dx,
      top: image.top + dy,
    );
  }

  FortuneImage? _imageById(String id) {
    for (final image in _workbook.activeSheet.images) {
      if (image.id == id) {
        return image;
      }
    }
    return null;
  }

  String? _imageIdAt(Offset local, FortuneSettings settings) {
    final images = _workbook.activeSheet.images;
    for (var index = images.length - 1; index >= 0; index -= 1) {
      final image = images[index];
      if (_imageRect(image, settings).contains(local)) {
        return image.id;
      }
    }
    return null;
  }

  String? _imageResizeSideAt(Offset local, FortuneSettings settings) {
    final active = _activeImageId == null ? null : _imageById(_activeImageId!);
    if (active == null) {
      return null;
    }
    final rect = _imageRect(active, settings);
    if (Rect.fromCenter(
      center: _imageRotationHandleCenter(rect),
      width: 14,
      height: 14,
    ).contains(local)) {
      return 'rotate';
    }
    for (final entry in _imageResizeHandleCenters(rect).entries) {
      if (Rect.fromCenter(
        center: entry.value,
        width: 12,
        height: 12,
      ).contains(local)) {
        return entry.key;
      }
    }
    return null;
  }

  void _updateImageResizeCursor(Offset local) {
    if (_imageResizeSide != null) {
      _setMouseCursor(_cursorForImageResizeSide(_imageResizeSide!));
      return;
    }
    if (_sheetListIndexAt(local) != null) {
      _setMouseCursor(SystemMouseCursors.click);
      return;
    }
    final side = _imageResizeSideAt(local, _workbook.settings);
    if (side == null && _imageIdAt(local, _workbook.settings) != null) {
      _setMouseCursor(SystemMouseCursors.move);
      return;
    }
    _setMouseCursor(
      side == null ? SystemMouseCursors.basic : _cursorForImageResizeSide(side),
    );
  }

  void _setMouseCursor(MouseCursor cursor) {
    if (_mouseCursor == cursor) {
      return;
    }
    setState(() {
      _mouseCursor = cursor;
    });
  }

  MouseCursor _cursorForImageResizeSide(String side) {
    return switch (side) {
      'rotate' => SystemMouseCursors.grab,
      'lt' || 'rb' => SystemMouseCursors.resizeUpLeftDownRight,
      'rt' || 'lb' => SystemMouseCursors.resizeUpRightDownLeft,
      'mt' || 'mb' => SystemMouseCursors.resizeUpDown,
      'lm' || 'rm' => SystemMouseCursors.resizeLeftRight,
      _ => SystemMouseCursors.basic,
    };
  }

  Offset _imageRotationHandleCenter(Rect rect) {
    return Offset(rect.center.dx, rect.top - 32.0);
  }

  Map<String, Offset> _imageResizeHandleCenters(Rect rect) {
    const handleCenterOutset = 1.0;
    final outsideLeft = rect.left - handleCenterOutset;
    final outsideTop = rect.top - handleCenterOutset;
    final outsideRight = rect.right + handleCenterOutset;
    final outsideBottom = rect.bottom + handleCenterOutset;
    final middleX = rect.center.dx;
    final middleY = rect.center.dy;

    return <String, Offset>{
      'lt': Offset(outsideLeft, outsideTop),
      'mt': Offset(middleX, outsideTop),
      'rt': Offset(outsideRight, outsideTop),
      'lm': Offset(outsideLeft, middleY),
      'rm': Offset(outsideRight, middleY),
      'lb': Offset(outsideLeft, outsideBottom),
      'mb': Offset(middleX, outsideBottom),
      'rb': Offset(outsideRight, outsideBottom),
    };
  }

  void _startImageResize(String side, Offset local) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final active = _activeImageId == null ? null : _imageById(_activeImageId!);
    if (active == null) {
      return;
    }
    setState(() {
      _imageResizeSide = side;
      _imageResizeStart = local;
      _imageResizeInitial = active;
      _imageResizeSnapshotRecorded = false;
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  bool _updateImageResize(Offset local) {
    final side = _imageResizeSide;
    final start = _imageResizeStart;
    final initial = _imageResizeInitial;
    if (side == null || start == null || initial == null) {
      return false;
    }
    if (side == 'rotate') {
      return _updateImageRotation(local, start, initial);
    }
    final dx = local.dx - start.dx;
    final dy = local.dy - start.dy;
    final zoomRatio = _workbook.activeSheet.zoomRatio <= 0
        ? 1.0
        : _workbook.activeSheet.zoomRatio;
    const minWidth = 90.0;
    const minHeight = 60.0;
    var left = initial.left;
    var top = initial.top;
    var width = initial.width;
    var height = initial.height;
    if (side.contains('l')) {
      final right = initial.left + initial.width;
      final modelDx = dx / zoomRatio;
      if (width - modelDx < minWidth) {
        left += width - minWidth;
      } else {
        left += modelDx;
      }
      if (left < 0) {
        left = 0;
      }
      width = math.max(minWidth, right - left);
    }
    if (side.contains('r')) {
      width = math.max(minWidth, width + dx / zoomRatio);
    }
    if (side.contains('t')) {
      final bottom = initial.top + initial.height;
      final modelDy = dy / zoomRatio;
      if (height - modelDy < minHeight) {
        top += height - minHeight;
      } else {
        top += modelDy;
      }
      if (top < 0) {
        top = 0;
      }
      height = math.max(minHeight, bottom - top);
    }
    if (side.contains('b')) {
      height = math.max(minHeight, height + dy / zoomRatio);
    }

    final changed =
        left != initial.left ||
        top != initial.top ||
        width != initial.width ||
        height != initial.height;
    if (!changed) {
      return true;
    }
    if (!_imageResizeSnapshotRecorded) {
      _recordUndoSnapshot();
      _imageResizeSnapshotRecorded = true;
    }
    _replaceImage(
      initial.id,
      initial.copyWith(
        left: left,
        top: top,
        width: width,
        height: height,
        extraFields: fortuneImageResizeExtraFieldsForMetadata(
          initial,
          width: width,
          height: height,
          usesMillimeters: _imageInsertUsesMillimeters,
        ),
      ),
    );
    return true;
  }

  bool _updateImageRotation(Offset local, Offset start, FortuneImage initial) {
    final rect = _imageRect(initial, _workbook.settings);
    final center = rect.center;
    if ((start - center).distance < 1 || (local - center).distance < 1) {
      return true;
    }
    final initialRotation = _imageRotationDegrees(
      initial.extraFields['rotation'],
    );
    final delta = _normalizeImageRotationDelta(
      _imageAngleDegrees(center, local) - _imageAngleDegrees(center, start),
    );
    final rotation = _normalizeImageRotation(initialRotation + delta);
    final currentRotation = _normalizeImageRotation(
      _imageRotationDegrees(_imageById(initial.id)?.extraFields['rotation']),
    );
    if ((rotation - currentRotation).abs() < 0.01) {
      return true;
    }
    if (!_imageResizeSnapshotRecorded) {
      _recordUndoSnapshot();
      _imageResizeSnapshotRecorded = true;
    }
    _replaceImage(
      initial.id,
      initial.copyWith(
        extraFields: <String, Object?>{
          ...initial.extraFields,
          'rotation': double.parse(rotation.toStringAsFixed(2)),
        },
      ),
    );
    return true;
  }

  double _imageAngleDegrees(Offset center, Offset point) {
    return math.atan2(point.dy - center.dy, point.dx - center.dx) *
        180 /
        math.pi;
  }

  double _normalizeImageRotationDelta(double degrees) {
    var normalized = degrees % 360;
    if (normalized > 180) {
      normalized -= 360;
    }
    if (normalized <= -180) {
      normalized += 360;
    }
    return normalized;
  }

  double _normalizeImageRotation(double degrees) {
    var normalized = degrees % 360;
    if (normalized < 0) {
      normalized += 360;
    }
    return normalized;
  }

  double _imageRotationDegrees(Object? value) {
    if (value is num) {
      return value.toDouble();
    }
    if (value is String) {
      return double.tryParse(value.trim()) ?? 0;
    }
    return 0;
  }

  void _startImageMove(String imageId, Offset local) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final active = _imageById(imageId);
    if (active == null) {
      return;
    }
    setState(() {
      _activeImageId = imageId;
      _imageMoveStart = local;
      _imageMoveInitial = active;
      _imageMoveSnapshotRecorded = false;
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  bool _updateImageMove(Offset local) {
    final start = _imageMoveStart;
    final initial = _imageMoveInitial;
    if (start == null || initial == null) {
      return false;
    }
    final dx = local.dx - start.dx;
    final dy = local.dy - start.dy;
    final zoomRatio = _workbook.activeSheet.zoomRatio <= 0
        ? 1.0
        : _workbook.activeSheet.zoomRatio;
    final left = initial.left + dx / zoomRatio;
    final top = math.max(0.0, initial.top + dy / zoomRatio);
    if (left == initial.left && top == initial.top) {
      return true;
    }
    if (!_imageMoveSnapshotRecorded) {
      _recordUndoSnapshot();
      _imageMoveSnapshotRecorded = true;
    }
    _replaceImage(initial.id, initial.copyWith(left: left, top: top));
    return true;
  }

  void _replaceImage(String id, FortuneImage image) {
    final sheet = _workbook.activeSheet;
    final images = [
      for (final existing in sheet.images)
        if (existing.id == id) image else existing,
    ];
    final sheets = [..._workbook.sheets];
    sheets[_workbook.activeSheetIndex] = sheet.copyWith(images: images);
    setState(() {
      _workbook = _workbook.copyWith(sheets: sheets);
    });
  }

  bool _deleteActiveImage() {
    final activeImageId = _activeImageId;
    if (activeImageId == null) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    if (!_canEditRange(sheet, _currentSelectionRange(sheet))) {
      setState(_closeTransientMenus);
      return true;
    }
    final images = [
      for (final image in sheet.images)
        if (image.id != activeImageId) image,
    ];
    if (images.length == sheet.images.length) {
      setState(() {
        _activeImageId = null;
        _cancelImageResize();
        _cancelImageMove();
      });
      return true;
    }
    _recordUndoSnapshot();
    final sheets = [..._workbook.sheets];
    sheets[_workbook.activeSheetIndex] = sheet.copyWith(images: images);
    setState(() {
      _workbook = _workbook.copyWith(sheets: sheets);
      _activeImageId = null;
      _cancelImageResize();
      _cancelImageMove();
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
    return true;
  }

  bool _commitImageResize() {
    if (_imageResizeSide == null) {
      return false;
    }
    setState(_cancelImageResize);
    return true;
  }

  bool _commitImageMove() {
    if (_imageMoveStart == null) {
      return false;
    }
    setState(_cancelImageMove);
    return true;
  }

  void _cancelImageResize() {
    _imageResizeSide = null;
    _imageResizeStart = null;
    _imageResizeInitial = null;
    _imageResizeSnapshotRecorded = false;
  }

  void _cancelImageMove() {
    _imageMoveStart = null;
    _imageMoveInitial = null;
    _imageMoveSnapshotRecorded = false;
  }

  void _toggleSelectedCellStyle(String key) {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final activeCoord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final previous = sheet.cells[activeCoord] ?? const FortuneCell();
    final previousBold = previous.hasRawBold
        ? fortuneRawBool(previous.rawBold) == true
        : previous.bold;
    final previousItalic = previous.hasRawItalic
        ? fortuneRawBool(previous.rawItalic) == true
        : previous.italic;
    final previousUnderline = previous.hasRawUnderline
        ? fortuneRawBool(previous.rawUnderline) == true
        : previous.underline;
    final previousStrikeThrough = previous.hasRawStrikeThrough
        ? fortuneRawBool(previous.rawStrikeThrough) == true
        : previous.strikeThrough;
    final nextValue = switch (key) {
      fortuneToolbarBoldCommand => !previousBold,
      fortuneToolbarItalicCommand => !previousItalic,
      fortuneToolbarUnderlineCommand => !previousUnderline,
      fortuneToolbarStrikeThroughCommand => !previousStrikeThrough,
      _ => null,
    };
    if (nextValue == null) {
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final updates = <MapEntry<FortuneCellCoord, FortuneCell>>[];
    for (final coord in targets) {
      final cell = sheet.cells[coord] ?? const FortuneCell();
      final rawValue = nextValue ? 1 : 0;
      final next = switch (key) {
        fortuneToolbarBoldCommand => cell.copyWith(
          bold: nextValue,
          rawBold: rawValue,
          hasRawBold: true,
        ),
        fortuneToolbarItalicCommand => cell.copyWith(
          italic: nextValue,
          rawItalic: rawValue,
          hasRawItalic: true,
        ),
        fortuneToolbarUnderlineCommand => cell.copyWith(
          underline: nextValue,
          rawUnderline: rawValue,
          hasRawUnderline: true,
        ),
        fortuneToolbarStrikeThroughCommand => cell.copyWith(
          strikeThrough: nextValue,
          rawStrikeThrough: rawValue,
          hasRawStrikeThrough: true,
        ),
        _ => cell,
      };
      if (_cellWouldChange(sheet, coord, next)) {
        updates.add(MapEntry(coord, next));
      }
    }
    if (updates.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    _recordUndoSnapshot();
    setState(() {
      for (final update in updates) {
        _setSheetCell(sheet, update.key, update.value);
      }
      _closeTransientMenus();
    });
  }

  Rect? _formulaBarInputRect() {
    final size = context.size;
    if (size == null) {
      return null;
    }
    final settings = _workbook.settings;
    return fortuneFormulaBarInputRect(size, settings);
  }

  List<MapEntry<String, Rect>> _visibleToolbarItemRects([Size? buildSize]) {
    if (!_workbook.settings.showToolbar) {
      return const [];
    }
    final width = buildSize?.width ?? context.size?.width ?? double.infinity;
    return fortuneVisibleToolbarItemRects(
      width,
      items: _toolbarItemsWithCustom(),
    );
  }

  List<String> _toolbarItemsWithCustom() {
    return fortuneToolbarItemsWithCustom(
      _workbook.settings.toolbarItems,
      _workbook.settings.customToolbarItems,
    );
  }

  List<String> _toolbarPopupOptionsFor(String key, double width) {
    if (key == fortuneToolbarFontPopupKey) {
      return [
        for (final family in _workbook.settings.fontFamilies)
          fortuneToolbarFontFamilyCommand(family),
      ];
    }
    return key == fortuneToolbarMorePopupKey
        ? fortuneToolbarOverflowItems(width, items: _toolbarItemsWithCustom())
        : key == fortuneToolbarFreezePopupKey
        ? fortuneFreezeMenuItems
        : key == fortuneToolbarCommentCommand
        ? _toolbarCommentPopupCommands()
        : fortuneToolbarPopupItems[key] ??
              const ['Default', 'Arial', '10', '12', '14', '18'];
  }

  List<String> _toolbarCommentPopupCommands() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    return sheet.cells[coord]?.comment == null
        ? fortuneToolbarCommentEmptyPopupCommands
        : fortuneToolbarCommentExistingPopupCommands;
  }

  double _toolbarPopupMaxScrollOffset() {
    final key = toolbarPopupKey;
    final size = context.size;
    if (key == null || size == null) {
      return 0;
    }
    final options = _toolbarPopupOptionsFor(key, size.width);
    final naturalHeight = fortuneToolbarPopupHeightFor(key, options);
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    return math.max(0.0, naturalHeight - visibleHeight);
  }

  double _initialToolbarPopupScrollOffsetFor(String key) {
    final size = context.size;
    if (size == null) {
      return 0;
    }
    final options = _toolbarPopupOptionsFor(key, size.width);
    final selectedIndex = _currentToolbarPopupSelectedIndexFor(key, options);
    if (selectedIndex == null) {
      return 0;
    }
    final naturalHeight = fortuneToolbarPopupHeightFor(key, options);
    final visibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final maxScrollOffset = math.max(0.0, naturalHeight - visibleHeight);
    if (maxScrollOffset <= 0) {
      return 0;
    }
    final selectedTop = _toolbarPopupOptionRelativeTop(
      key,
      options,
      selectedIndex,
    );
    final selectedHeight = options[selectedIndex] == '|'
        ? fortuneToolbarMenuDividerHeight
        : fortuneToolbarPopupRowHeightFor(key);
    return (selectedTop + selectedHeight / 2 - visibleHeight / 2)
        .clamp(0.0, maxScrollOffset)
        .toDouble();
  }

  int? _currentToolbarPopupSelectedIndex(double width) {
    final key = toolbarPopupKey;
    if (key == null) {
      return null;
    }
    return _currentToolbarPopupSelectedIndexFor(
      key,
      _toolbarPopupOptionsFor(key, width),
    );
  }

  int? _currentToolbarPopupSelectedIndexFor(String key, List<String> options) {
    if (key == fortuneToolbarFormatCommand) {
      final index = options.indexOf(_currentToolbarFormatCommand());
      return index < 0 ? null : index;
    }
    if (key == fortuneToolbarFontPopupKey) {
      final fontFamily = _currentToolbarFontFamily();
      if (fontFamily == null || fontFamily.isEmpty) {
        return null;
      }
      for (var index = 0; index < options.length; index += 1) {
        if (fortuneToolbarFontFamilyFromCommand(options[index]) == fontFamily) {
          return index;
        }
      }
      return null;
    }
    if (key == fortuneToolbarFontSizePopupKey) {
      final fontSize = _currentToolbarFontSize();
      if (fontSize == null) {
        return null;
      }
      for (var index = 0; index < options.length; index += 1) {
        final commandSize = _toolbarFontSizeForCommand(options[index]);
        if (commandSize != null &&
            (fontSize - commandSize.toDouble()).abs() < 0.001) {
          return index;
        }
      }
    }
    return null;
  }

  String? _toolbarPopupScrollButtonDirectionAt(Offset local) {
    final rect = _toolbarPopupRect();
    if (rect == null || _toolbarPopupMaxScrollOffset() <= 0) {
      return null;
    }
    final scrollOffset = _toolbarPopupScrollOffset
        .clamp(0.0, _toolbarPopupMaxScrollOffset())
        .toDouble();
    if (scrollOffset > 0.5 &&
        fortuneToolbarPopupScrollButtonRect(
          rect,
          fortuneToolbarPopupScrollButtonUp,
        ).contains(local)) {
      return fortuneToolbarPopupScrollButtonUp;
    }
    if (scrollOffset < _toolbarPopupMaxScrollOffset() - 0.5 &&
        fortuneToolbarPopupScrollButtonRect(
          rect,
          fortuneToolbarPopupScrollButtonDown,
        ).contains(local)) {
      return fortuneToolbarPopupScrollButtonDown;
    }
    return null;
  }

  void _activateToolbarPopupScrollButton(String direction) {
    final maxScrollOffset = _toolbarPopupMaxScrollOffset();
    final currentOffset = _toolbarPopupScrollOffset
        .clamp(0.0, maxScrollOffset)
        .toDouble();
    final key = toolbarPopupKey;
    final rowHeight = key == null
        ? fortuneToolbarPopupRowHeight
        : fortuneToolbarPopupRowHeightFor(key);
    final delta = direction == fortuneToolbarPopupScrollButtonUp
        ? -rowHeight
        : rowHeight;
    final nextOffset = (currentOffset + delta).clamp(0.0, maxScrollOffset);
    setState(() {
      _toolbarPopupScrollOffset = nextOffset;
      _toolbarPopupPressedScrollButtonDirection = direction;
      _toolbarPopupHoveredScrollButtonDirection = switch (direction) {
        fortuneToolbarPopupScrollButtonUp when nextOffset > 0.5 => direction,
        fortuneToolbarPopupScrollButtonDown
            when nextOffset < maxScrollOffset - 0.5 =>
          direction,
        _ => null,
      };
      _toolbarPopupHoveredIndex = null;
      _toolbarBorderHoveredTopLevelIndex = null;
      _toolbarBorderHoveredSubmenuIndex = null;
      _conditionFormatHoveredTopLevelIndex = null;
      _conditionFormatHoveredSubmenuIndex = null;
    });
  }

  Rect? _toolbarPopupRect([Size? buildSize]) {
    final key = toolbarPopupKey;
    final size = buildSize ?? context.size;
    if (key == null || size == null) {
      return null;
    }
    Rect? itemRect;
    for (final entry in _visibleToolbarItemRects(size)) {
      if (entry.key == key) {
        itemRect = entry.value;
        break;
      }
    }
    final options = _toolbarPopupOptionsFor(key, size.width);
    final width = fortuneToolbarPopupWidthFor(
      key,
      options: options,
      viewportWidth: size.width,
    );
    final naturalHeight = fortuneToolbarPopupHeightFor(key, options);
    final height = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: size.height,
      naturalHeight: naturalHeight,
    );
    final left = fortuneToolbarPopupLeftFor(
      key: key,
      itemRect: itemRect,
      viewportWidth: size.width,
      popupWidth: width,
    );
    return Rect.fromLTWH(left, fortuneToolbarPopupTop, width, height);
  }

  bool _toolbarPopupEventContains(Offset local) {
    final key = toolbarPopupKey;
    if (key == null) {
      return false;
    }
    if (_toolbarPopupRect()?.contains(local) == true) {
      return true;
    }
    if (key == fortuneToolbarFormatCommand) {
      final popupRect = _toolbarPopupRect();
      final size = context.size;
      return popupRect != null &&
          size != null &&
          fortuneToolbarFormatMoreSubmenuRect(
            popupRect,
            viewportWidth: size.width,
          ).contains(local);
    }
    if (key == fortuneToolbarConditionFormatPopupKey) {
      final submenuKey = _conditionFormatSubmenuKey;
      return submenuKey != null &&
          _conditionFormatSubmenuRect(submenuKey)?.contains(local) == true;
    }
    if (key == fortuneToolbarBorderPopupKey) {
      final submenuKey = _toolbarBorderSubmenuKey;
      return submenuKey != null &&
          _toolbarBorderSubmenuRect(submenuKey)?.contains(local) == true;
    }
    return false;
  }

  bool _handleToolbarPopupPointerDown(PointerDownEvent event) {
    final local = event.localPosition;
    if (!_toolbarPopupEventContains(local)) {
      return false;
    }
    if ((event.buttons & kSecondaryMouseButton) != 0) {
      return true;
    }
    final toolbarPopupScrollDirection = _toolbarPopupScrollButtonDirectionAt(
      local,
    );
    if (toolbarPopupScrollDirection != null) {
      final keepEditing =
          toolbarPopupKey != null &&
          _shouldKeepEditingForToolbarCombo(toolbarPopupKey!);
      if (keepEditing) {
        _rememberInlineToolbarSelectionRange();
      } else {
        _commitEditing();
      }
      _commitSheetRename();
      _activateToolbarPopupScrollButton(toolbarPopupScrollDirection);
      return true;
    }
    final toolbarBorderStyleWidthInput = _toolbarBorderStyleWidthInputAt(local);
    if (toolbarBorderStyleWidthInput != null) {
      _commitEditing();
      _commitSheetRename();
      _toolbarBorderStyleWidthFocusNodes[toolbarBorderStyleWidthInput]
          ?.requestFocus();
      return true;
    }
    final toolbarPopupCommand = _toolbarPopupCommandAt(local);
    if (toolbarPopupCommand != null) {
      if (_isInlineToolbarFormatCommand(toolbarPopupCommand)) {
        fortuneSheetDebugLog(
          'editor inlineToolbar popupCommand command=$toolbarPopupCommand '
          'selection=${_debugSelection(_editorController.selection)} '
          'stored=${_debugRange(_inlineToolbarSelectionRange)} '
          'runs=${_debugEditorRuns()}',
        );
        _rememberInlineToolbarSelectionRange();
      } else {
        _commitEditing();
      }
      _commitSheetRename();
      _activateToolbarPopupCommand(toolbarPopupCommand);
      return true;
    }
    return true;
  }

  Rect _toolbarPopupContentViewportRect(Rect rect) {
    final maxScrollOffset = _toolbarPopupMaxScrollOffset();
    final scrollOffset = _toolbarPopupScrollOffset
        .clamp(0.0, maxScrollOffset)
        .toDouble();
    return fortuneToolbarPopupContentViewportRect(
      rect,
      scrollOffset,
      maxScrollOffset,
    );
  }

  Rect? _conditionFormatTopLevelPopupRect() {
    if (toolbarPopupKey != fortuneToolbarConditionFormatPopupKey) {
      return null;
    }
    final size = context.size;
    if (size == null) {
      return null;
    }
    Rect? itemRect;
    for (final entry in _visibleToolbarItemRects()) {
      if (entry.key == fortuneToolbarConditionFormatPopupKey) {
        itemRect = entry.value;
        break;
      }
    }
    const width = fortuneConditionFormatTopLevelPopupWidth;
    final left = math.min(
      math.max(
        fortuneToolbarPopupViewportMargin,
        (itemRect?.left ?? fortuneToolbarPopupFallbackLeft) -
            fortuneToolbarPopupViewportMargin,
      ),
      math.max(
        fortuneToolbarPopupViewportMargin,
        size.width - width - fortuneToolbarPopupViewportMargin,
      ),
    );
    return Rect.fromLTWH(
      left,
      fortuneToolbarPopupTop,
      width,
      fortuneToolbarPopupVisibleHeightFor(
        viewportHeight: size.height,
        naturalHeight: fortuneToolbarPopupHeightFor(
          fortuneToolbarConditionFormatPopupKey,
          fortuneConditionFormatTopLevelItems,
        ),
      ),
    );
  }

  Rect? _conditionFormatSubmenuRect(String submenuKey) {
    final topLevel = _conditionFormatTopLevelPopupRect();
    final size = context.size;
    if (topLevel == null || size == null) {
      return null;
    }
    final items = _conditionFormatSubmenuItems(submenuKey);
    if (items.isEmpty) {
      return null;
    }
    final width = switch (submenuKey) {
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionSubmenuWidth,
      _ => fortuneConditionFormatSubmenuWidth,
    };
    final topLevelIndex = switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightTopLevelIndex,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionTopLevelIndex,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteTopLevelIndex,
      _ => 0,
    };
    final desiredLeft = topLevel.right;
    final left = desiredLeft + width > size.width
        ? math.max(
            fortuneToolbarPopupViewportMargin,
            topLevel.left +
                fortuneConditionFormatSubmenuOverflowLeftInset -
                width,
          )
        : desiredLeft;
    return Rect.fromLTWH(
      left,
      _toolbarPopupOptionTop(
            topLevel,
            fortuneToolbarConditionFormatPopupKey,
            fortuneConditionFormatTopLevelItems,
            topLevelIndex,
          ) -
          _toolbarPopupScrollOffset +
          fortuneConditionFormatSubmenuTopOffset,
      width,
      items.length * fortuneConditionFormatSubmenuRowHeight,
    );
  }

  Rect? _toolbarBorderSubmenuRect(String submenuKey, [Size? buildSize]) {
    final topLevel = _toolbarPopupRect(buildSize);
    final size = buildSize ?? context.size;
    if (toolbarPopupKey != fortuneToolbarBorderPopupKey ||
        topLevel == null ||
        size == null) {
      return null;
    }
    final width = submenuKey == fortuneToolbarBorderColorSubmenuKey
        ? fortuneToolbarFontColorPopupWidth
        : fortuneToolbarBorderStyleSubmenuWidth;
    final height = submenuKey == fortuneToolbarBorderColorSubmenuKey
        ? fortuneToolbarFontColorPopupHeight
        : fortuneToolbarPopupVerticalPadding +
              fortuneToolbarBorderStyleSubmenuResetHeight +
              fortuneToolbarBorderStyleSubmenuRowHeight *
                  fortuneToolbarBorderStyleValues.length;
    final desiredLeft = topLevel.right;
    final left = desiredLeft + width > size.width
        ? math.max(fortuneToolbarPopupViewportMargin, topLevel.left - width)
        : desiredLeft;
    return Rect.fromLTWH(left, topLevel.bottom - height, width, height);
  }

  Rect? _toolbarBorderStyleWidthInputRect(int style, [Size? buildSize]) {
    if (!fortuneToolbarBorderWidthEditableStyles.contains(style)) {
      return null;
    }
    final submenuRect = _toolbarBorderSubmenuRect(
      fortuneToolbarBorderStyleSubmenuKey,
      buildSize,
    );
    if (submenuRect == null) {
      return null;
    }
    final index = fortuneToolbarBorderStyleValues.indexOf(style);
    if (index < 0) {
      return null;
    }
    final rowTop =
        submenuRect.top +
        fortuneToolbarPopupContentTopPadding +
        fortuneToolbarBorderStyleSubmenuResetHeight +
        fortuneToolbarBorderStyleSubmenuRowHeight * index;
    return fortuneToolbarBorderStyleWidthInputRect(
      Rect.fromLTWH(
        submenuRect.left,
        rowTop,
        submenuRect.width,
        fortuneToolbarBorderStyleSubmenuRowHeight,
      ),
    );
  }

  int? _toolbarBorderStyleWidthInputAt(Offset local) {
    if (toolbarPopupKey != fortuneToolbarBorderPopupKey ||
        _toolbarBorderSubmenuKey != fortuneToolbarBorderStyleSubmenuKey) {
      return null;
    }
    for (final style in fortuneToolbarBorderWidthEditableStyles) {
      final rect = _toolbarBorderStyleWidthInputRect(style);
      if (rect != null && rect.contains(local)) {
        return style;
      }
    }
    return null;
  }

  int? _toolbarPopupOptionIndexAt(
    Rect rect,
    String key,
    List<String> options,
    double y,
  ) {
    var top = rect.top + fortuneToolbarPopupContentTopPaddingFor(key);
    for (var index = 0; index < options.length; index += 1) {
      final height = options[index] == '|'
          ? fortuneToolbarMenuDividerHeight
          : fortuneToolbarPopupRowHeightFor(key);
      if (y >= top && y < top + height) {
        return options[index] == '|' ? null : index;
      }
      top += height;
    }
    return null;
  }

  double _toolbarPopupOptionTop(
    Rect rect,
    String key,
    List<String> options,
    int optionIndex,
  ) {
    return rect.top + _toolbarPopupOptionRelativeTop(key, options, optionIndex);
  }

  double _toolbarPopupOptionRelativeTop(
    String key,
    List<String> options,
    int optionIndex,
  ) {
    var top = fortuneToolbarPopupContentTopPaddingFor(key);
    for (
      var index = 0;
      index < optionIndex && index < options.length;
      index += 1
    ) {
      top += options[index] == '|'
          ? fortuneToolbarMenuDividerHeight
          : fortuneToolbarPopupRowHeightFor(key);
    }
    return top;
  }

  List<String> _conditionFormatSubmenuItems(String submenuKey) {
    return switch (submenuKey) {
      fortuneConditionFormatHighlightSubmenuKey =>
        fortuneConditionFormatHighlightItems,
      fortuneConditionFormatSelectionSubmenuKey =>
        fortuneConditionFormatSelectionItems,
      fortuneConditionFormatDeleteSubmenuKey =>
        fortuneConditionFormatDeleteItems,
      _ => const <String>[],
    };
  }

  String? _toolbarPopupCommandAt(Offset local) {
    final key = toolbarPopupKey;
    if (key == null) {
      return null;
    }
    if (key == fortuneToolbarFormatCommand) {
      final popupRect = _toolbarPopupRect();
      final size = context.size;
      if (popupRect != null && size != null) {
        final submenuRect = fortuneToolbarFormatMoreSubmenuRect(
          popupRect,
          viewportWidth: size.width,
        );
        if (submenuRect.contains(local)) {
          final index =
              ((local.dy - submenuRect.top) /
                      fortuneToolbarFormatMoreSubmenuRowHeight)
                  .floor();
          return index >= 0 &&
                  index < fortuneToolbarFormatMoreSubmenuCommands.length
              ? fortuneToolbarFormatMoreSubmenuCommands[index]
              : null;
        }
      }
    }
    if (key == fortuneToolbarConditionFormatPopupKey) {
      final submenuKey = _conditionFormatSubmenuKey;
      if (submenuKey != null) {
        final submenuRect = _conditionFormatSubmenuRect(submenuKey);
        final submenuItems = _conditionFormatSubmenuItems(submenuKey);
        if (submenuRect != null && submenuRect.contains(local)) {
          final submenuIndex =
              ((local.dy - submenuRect.top) /
                      fortuneConditionFormatSubmenuRowHeight)
                  .floor();
          if (submenuIndex >= 0 && submenuIndex < submenuItems.length) {
            return submenuItems[submenuIndex];
          }
          return null;
        }
      }
    }
    if (key == fortuneToolbarBorderPopupKey) {
      final submenuKey = _toolbarBorderSubmenuKey;
      if (submenuKey != null) {
        final submenuRect = _toolbarBorderSubmenuRect(submenuKey);
        if (submenuRect != null && submenuRect.contains(local)) {
          return _toolbarBorderSubmenuCommandAt(submenuRect, local, submenuKey);
        }
      }
    }
    final rect = _toolbarPopupRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    if (!_toolbarPopupContentViewportRect(rect).contains(local)) {
      return null;
    }
    if (key == fortuneToolbarFontColorPopupKey ||
        key == fortuneToolbarBackgroundPopupKey) {
      final contentRect = Rect.fromLTWH(
        rect.left,
        rect.top,
        rect.width,
        fortuneToolbarPopupHeightFor(
          key,
          _toolbarPopupOptionsFor(key, rect.width),
        ),
      );
      return _toolbarColorPickerPopupCommandAt(
        contentRect,
        Offset(local.dx, local.dy + _toolbarPopupScrollOffset),
        key,
      );
    }
    if (key == fortuneToolbarFormatCommand) {
      final options = fortuneToolbarPopupItems[key];
      if (options == null) {
        return null;
      }
      final index = _toolbarPopupOptionIndexAt(
        rect,
        key,
        options,
        local.dy + _toolbarPopupScrollOffset,
      );
      if (index == null) {
        return null;
      }
      return options[index] == fortuneToolbarFormatMoreCommand
          ? 'modal'
          : options[index];
    }
    if (key == fortuneToolbarConditionFormatPopupKey) {
      final topLevelRect = _conditionFormatTopLevelPopupRect();
      if (topLevelRect != null && topLevelRect.contains(local)) {
        final topLevelIndex = _toolbarPopupOptionIndexAt(
          topLevelRect,
          key,
          fortuneConditionFormatTopLevelItems,
          local.dy + _toolbarPopupScrollOffset,
        );
        if (topLevelIndex == fortuneConditionFormatHighlightTopLevelIndex) {
          return fortuneConditionFormatHighlightSubmenuCommand;
        }
        if (topLevelIndex == fortuneConditionFormatSelectionTopLevelIndex) {
          return fortuneConditionFormatSelectionSubmenuCommand;
        }
        if (topLevelIndex == fortuneConditionFormatDeleteTopLevelIndex) {
          return fortuneConditionFormatDeleteSubmenuCommand;
        }
      }
      return null;
    }
    if (key == fortuneToolbarBorderPopupKey) {
      final topLevelIndex = _toolbarPopupOptionIndexAt(
        rect,
        key,
        fortuneToolbarBorderPopupCommands,
        local.dy + _toolbarPopupScrollOffset,
      );
      if (topLevelIndex == null) {
        return null;
      }
      final option = fortuneToolbarBorderPopupCommands[topLevelIndex];
      if (option == fortuneToolbarBorderColorSubmenuKey ||
          option == fortuneToolbarBorderStyleSubmenuKey) {
        return option;
      }
      return option;
    }
    final options = _toolbarPopupOptionsFor(key, context.size?.width ?? 0);
    final index = _toolbarPopupOptionIndexAt(
      rect,
      key,
      options,
      local.dy + _toolbarPopupScrollOffset,
    );
    if (index == null || index < 0 || index >= options.length) {
      return null;
    }
    final command = options[index];
    if (command == fortuneConditionFormatHighlightRulesCommand ||
        command == fortuneConditionFormatItemSelectionRulesCommand) {
      return 'modal';
    }
    return command;
  }

  String? _toolbarBorderSubmenuCommandAt(
    Rect rect,
    Offset local,
    String submenuKey,
  ) {
    if (submenuKey == fortuneToolbarBorderColorSubmenuKey) {
      final command = _toolbarColorPickerPopupCommandAt(
        rect,
        local,
        fortuneToolbarFontColorPopupKey,
      );
      if (command == fortuneToolbarFontColorResetCommand) {
        return fortuneToolbarBorderColorResetCommand;
      }
      if (command == fortuneToolbarFontColorCustomBlackCommand) {
        return fortuneToolbarBorderColorCustomBlackCommand;
      }
      if (command != null &&
          command.startsWith(fortuneToolbarFontColorPaletteCommandPrefix)) {
        return fortuneToolbarBorderColorPaletteCommand(
          command.substring(fortuneToolbarFontColorPaletteCommandPrefix.length),
        );
      }
      return null;
    }
    final index = _toolbarBorderSubmenuIndexAt(rect, submenuKey, local);
    if (index == null) {
      return null;
    }
    if (index == 0) {
      return fortuneToolbarBorderStyleDefaultCommand;
    }
    return fortuneToolbarBorderStyleCommand(
      fortuneToolbarBorderStyleValues[index - 1],
    );
  }

  String? _toolbarColorPickerPopupCommandAt(
    Rect rect,
    Offset local,
    String key,
  ) {
    final isBackground = key == fortuneToolbarBackgroundPopupKey;
    final resetRect = Rect.fromLTWH(
      rect.left,
      rect.top,
      rect.width,
      fortuneToolbarFontColorResetHeight,
    );
    if (resetRect.contains(local)) {
      return isBackground
          ? fortuneToolbarBackgroundResetCommand
          : fortuneToolbarFontColorResetCommand;
    }
    final customRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarFontColorCustomTop,
      rect.width,
      fortuneToolbarFontColorCustomHeight,
    );
    final okRect = Rect.fromLTWH(
      customRect.right -
          fortuneToolbarFontColorCustomOkRightInset -
          fortuneToolbarFontColorCustomOkWidth,
      customRect.top + fortuneToolbarFontColorCustomOkTop,
      fortuneToolbarFontColorCustomOkWidth,
      fortuneToolbarFontColorCustomOkHeight,
    );
    if (okRect.contains(local)) {
      return isBackground
          ? fortuneToolbarBackgroundCustomBlackCommand
          : fortuneToolbarFontColorCustomBlackCommand;
    }
    final pickerRect = Rect.fromLTWH(
      rect.left,
      rect.top + fortuneToolbarFontColorPickerTop,
      rect.width,
      rect.height - fortuneToolbarFontColorPickerTop,
    );
    if (!pickerRect.contains(local)) {
      return null;
    }
    final step =
        fortuneToolbarColorPickerItemSize +
        fortuneToolbarColorPickerItemMargin * 2;
    for (var row = 0; row < fortuneToolbarColorPickerPalette.length; row += 1) {
      final colors = fortuneToolbarColorPickerPalette[row];
      for (var column = 0; column < colors.length; column += 1) {
        final itemRect = Rect.fromLTWH(
          pickerRect.left +
              fortuneToolbarColorPickerPadding +
              column * step +
              fortuneToolbarColorPickerItemMargin,
          pickerRect.top +
              fortuneToolbarColorPickerPadding +
              row * step +
              fortuneToolbarColorPickerItemMargin,
          fortuneToolbarColorPickerItemSize,
          fortuneToolbarColorPickerItemSize,
        );
        if (itemRect.contains(local)) {
          return isBackground
              ? fortuneToolbarBackgroundPaletteCommand(colors[column])
              : fortuneToolbarFontColorPaletteCommand(colors[column]);
        }
      }
    }
    return null;
  }

  void _activateToolbarPopupCommand(String command) {
    if (command == 'modal') {
      return;
    }
    if (_applyInlineToolbarFormatCommand(command)) {
      return;
    }
    if (_activateCustomToolbarItem(command)) {
      return;
    }
    if (fortuneToolbarItems.contains(command)) {
      if (_isToolbarEditCommand(command)) {
        _activateToolbarEditCommand(command);
        return;
      }
      if (_isToolbarStyleCommand(command)) {
        _toggleSelectedCellStyle(command);
        return;
      }
      if (_isToolbarComboCommand(command)) {
        setState(() {
          toolbarPopupKey = command;
          _toolbarPopupHoveredIndex = null;
          _toolbarPopupScrollOffset = _initialToolbarPopupScrollOffsetFor(
            command,
          );
          _conditionFormatSubmenuKey = null;
          _conditionFormatHoveredTopLevelIndex = null;
          _conditionFormatHoveredSubmenuIndex = null;
        });
        return;
      }
      if (_isToolbarImmediateCommand(command)) {
        _activateToolbarImmediateCommand(command);
        return;
      }
    }
    if (command == fortuneConditionFormatHighlightSubmenuCommand ||
        command == fortuneConditionFormatSelectionSubmenuCommand ||
        command == fortuneConditionFormatDeleteSubmenuCommand) {
      setState(() {
        _conditionFormatSubmenuKey = switch (command) {
          fortuneConditionFormatHighlightSubmenuCommand =>
            fortuneConditionFormatHighlightSubmenuKey,
          fortuneConditionFormatSelectionSubmenuCommand =>
            fortuneConditionFormatSelectionSubmenuKey,
          _ => fortuneConditionFormatDeleteSubmenuKey,
        };
        _conditionFormatHoveredTopLevelIndex = null;
        _conditionFormatHoveredSubmenuIndex = null;
      });
      return;
    }
    if (fortuneFreezeMenuItems.contains(command)) {
      if (!_workbook.settings.allowEdit) {
        setState(_closeTransientMenus);
        return;
      }
      final sheet = _workbook.activeSheet;
      final nextFrozen = _frozenPaneForCommand(command, sheet);
      final frozenChanged = !_frozenPaneEquals(sheet.frozen, nextFrozen);
      if (frozenChanged) {
        _recordUndoSnapshot();
      }
      setState(() {
        if (frozenChanged) {
          _setActiveSheetFrozen(nextFrozen);
        }
        _closeTransientMenus();
      });
      return;
    }
    if (_isToolbarSortFilterCommand(command)) {
      _applyToolbarSortFilterCommand(command);
      return;
    }
    if (_isToolbarBorderSubmenuCommand(command)) {
      _activateToolbarBorderSubmenuCommand(command);
      return;
    }
    if (_isToolbarBorderCommand(command)) {
      _applyToolbarBorderCommand(command);
      return;
    }
    if (_isToolbarMergeCommand(command)) {
      _applyToolbarMergeCommand(command);
      return;
    }
    if (_isToolbarFormulaCommand(command)) {
      _applyToolbarFormulaCommand(command);
      return;
    }
    if (command == fortuneToolbarFormulaLearnMoreCommand) {
      _showFormulaSearchDialog();
      return;
    }
    if (_isToolbarLocationCommand(command)) {
      _applyToolbarLocationCommand(command);
      return;
    }
    if (_isToolbarConditionFormatCommand(command)) {
      _applyToolbarConditionFormatCommand(command);
      return;
    }
    if (_isToolbarCommentPopupCommand(command)) {
      _applyToolbarCommentPopupCommand(command);
      return;
    }
    if (fortuneToolbarFormatMoreSubmenuCommands.contains(command)) {
      _showFormatSearchDialog(command);
      return;
    }
    if (_isToolbarCellFormatPopupCommand(command)) {
      _applyToolbarCellFormatPopupCommand(command);
      return;
    }
    setState(() {
      _closeTransientMenus();
    });
  }

  bool _isToolbarFormulaCommand(String command) {
    return fortuneToolbarFormulaCommands.contains(command);
  }

  bool _isToolbarLocationCommand(String command) {
    return fortuneToolbarLocationPopupCommands.contains(command);
  }

  void _applyToolbarLocationCommand(String command) {
    if (command == fortuneToolbarLocationCommand) {
      _showLocationDialog();
      return;
    }
    final sheet = _workbook.activeSheet;
    if (command == fortuneToolbarLocationRowSpanCommand &&
        !_locationHasAtLeastTwoRows(sheet)) {
      _showLocationMessageDialog(widget.locale.locationTiplessTwoRow);
      return;
    }
    if (command == fortuneToolbarLocationColumnSpanCommand &&
        !_locationHasAtLeastTwoColumns(sheet)) {
      _showLocationMessageDialog(widget.locale.locationTiplessTwoColumn);
      return;
    }
    final ranges = switch (command) {
      fortuneToolbarLocationFormulaCommand => _locationMatchingRanges(
        sheet,
        (cell) => cell.formula != null && cell.formula!.isNotEmpty,
      ),
      fortuneToolbarLocationDateCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasTruthyValue(cell) &&
            !_locationCellHasFormula(cell) &&
            _locationCellType(cell) == 'd',
      ),
      fortuneToolbarLocationNumberCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasTruthyValue(cell) &&
            !_locationCellHasFormula(cell) &&
            (_locationCellType(cell) == 'n' ||
                (_locationCellType(cell) == null &&
                    double.tryParse(cell.renderedText) != null)),
      ),
      fortuneToolbarLocationStringCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasTruthyValue(cell) &&
            !_locationCellHasFormula(cell) &&
            (_locationCellType(cell) == 's' ||
                _locationCellType(cell) == 'g' ||
                (_locationCellType(cell) == null &&
                    cell.renderedText.isNotEmpty &&
                    double.tryParse(cell.renderedText) == null &&
                    !cell.renderedText.startsWith('#'))),
      ),
      fortuneToolbarLocationBoolCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasTruthyValue(cell) &&
            !_locationCellHasFormula(cell) &&
            (_locationCellType(cell) == 'b' ||
                _isLocationLogicalText(cell.renderedText)),
      ),
      fortuneToolbarLocationErrorCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasTruthyValue(cell) &&
            !_locationCellHasFormula(cell) &&
            (_locationCellType(cell) == 'e' ||
                cell.renderedText.startsWith('#')),
      ),
      fortuneToolbarLocationNullCommand => _locationNullRanges(sheet),
      fortuneToolbarLocationRowSpanCommand => _locationSpanRanges(
        sheet,
        axis: Axis.vertical,
      ),
      fortuneToolbarLocationColumnSpanCommand => _locationSpanRanges(
        sheet,
        axis: Axis.horizontal,
      ),
      _ => const <FortuneRange>[],
    };
    if (ranges.isEmpty) {
      _showLocationMessageDialog(widget.locale.locationTipNotFindCell);
      return;
    }
    setState(() {
      _writeLocationSelectionRanges(ranges);
      _closeTransientMenus();
    });
  }

  void _showLocationMessageDialog(String text) {
    setState(() {
      _closeTransientMenus();
      _locationDialogOpen = false;
      _locationMessageDialogText = text;
      _locationMessageDialogConfirm = false;
    });
    _focusNode.requestFocus();
  }

  Rect? _locationMessageDialogRect([Size? overrideSize]) {
    if (_locationMessageDialogText == null) {
      return null;
    }
    final size = overrideSize ?? context.size;
    if (size == null) {
      return null;
    }
    return fortuneLocationMessageDialogRect(
      size,
      message: _locationMessageDialogText,
    );
  }

  String? _locationMessageDialogCommandAt(Offset local) {
    final rect = _locationMessageDialogRect();
    if (rect == null) {
      return null;
    }
    if (fortuneLocationMessageCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (_locationMessageDialogConfirm &&
        fortuneLocationMessageConfirmCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    final okRect = _locationMessageDialogConfirm
        ? fortuneLocationMessageConfirmOkButtonRect(rect)
        : fortuneLocationMessageOkButtonRect(rect);
    if (okRect.contains(local)) {
      if (_locationMessageDialogConfirm) {
        return 'confirm';
      }
      return 'close';
    }
    return null;
  }

  void _activateLocationMessageDialogCommand(String? command) {
    if (command == 'confirm' && _locationMessageDialogConfirm) {
      final data = _pendingSplitTextData;
      final range = _pendingSplitTextRange;
      if (data != null && range != null) {
        _applySplitTextData(data, range);
        return;
      }
    }
    if (command == 'close' || command == 'cancel' || command == 'confirm') {
      setState(() {
        _locationMessageDialogText = null;
        _locationMessageDialogConfirm = false;
        _pendingSplitTextData = null;
        _pendingSplitTextRange = null;
      });
      _focusNode.requestFocus();
    }
  }

  bool _activateCustomToolbarItem(String? command) {
    if (command == null) {
      return false;
    }
    for (final item in _workbook.settings.customToolbarItems) {
      if (item.key != command) {
        continue;
      }
      if (item.disabled) {
        return true;
      }
      item.onClick?.call(item);
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        dataVerificationDropdownCoord = null;
        filterDropdownColumn = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        _toolbarPopupHoveredIndex = null;
        _toolbarPopupScrollOffset = 0;
        _conditionFormatSubmenuKey = null;
        _conditionFormatHoveredTopLevelIndex = null;
        _conditionFormatHoveredSubmenuIndex = null;
      });
      return true;
    }
    return false;
  }

  void _writeLocationSelectionRanges(List<FortuneRange> ranges) {
    final first = ranges.first;
    final focus = FortuneCellCoord(first.rowStart, first.columnStart);
    selection = FortuneSelection(
      row: first.rowStart,
      column: first.columnStart,
      rowEnd: first.rowEnd,
      columnEnd: first.columnEnd,
    );
    _writeSelectionRanges(ranges, focus);
  }

  void _showLocationDialog() {
    setState(() {
      _closeTransientMenus();
      _locationDialogOpen = true;
      _locationDialogType = fortuneToolbarLocationCommand;
      _locationConstantDate = true;
      _locationConstantNumber = true;
      _locationConstantString = true;
      _locationConstantLogical = true;
      _locationConstantError = true;
      _locationFormulaDate = true;
      _locationFormulaNumber = true;
      _locationFormulaString = true;
      _locationFormulaLogical = true;
      _locationFormulaError = true;
    });
    _focusNode.requestFocus();
  }

  Rect? _locationDialogRect([Size? overrideSize]) {
    if (!_locationDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    if (size == null) {
      return null;
    }
    return fortuneLocationDialogRect(size);
  }

  String? _locationDialogCommandAt(Offset local) {
    final rect = _locationDialogRect();
    if (rect == null) {
      return null;
    }
    if (!rect.contains(local)) {
      return 'cancel';
    }
    if (fortuneLocationCloseButtonRect(rect).contains(local) ||
        fortuneLocationCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (fortuneLocationOkButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    for (final type in fortuneLocationDialogTypes) {
      if (fortuneLocationTypeRowRect(rect, type).contains(local)) {
        return 'type-$type';
      }
    }
    if (_locationDialogType == fortuneToolbarLocationCommand ||
        _locationDialogType == fortuneToolbarLocationFormulaCommand) {
      for (final key in fortuneLocationDialogValueKeys) {
        if (fortuneLocationValueRect(
          rect,
          _locationDialogType,
          key,
        ).contains(local)) {
          return 'toggle-$_locationDialogType-$key';
        }
      }
    }
    return null;
  }

  void _activateLocationDialogCommand(String? command) {
    if (command == null) {
      return;
    }
    if (command == 'confirm') {
      _commitLocationDialog();
      return;
    }
    if (command == 'cancel') {
      setState(() => _locationDialogOpen = false);
      _focusNode.requestFocus();
      return;
    }
    if (command.startsWith('type-')) {
      setState(() {
        _locationDialogType = command.substring('type-'.length);
      });
      return;
    }
    if (command.startsWith('toggle-$fortuneToolbarLocationCommand-')) {
      final key = command.substring(
        'toggle-$fortuneToolbarLocationCommand-'.length,
      );
      setState(() => _toggleLocationConstantValue(key));
      return;
    }
    if (command.startsWith('toggle-$fortuneToolbarLocationFormulaCommand-')) {
      final key = command.substring(
        'toggle-$fortuneToolbarLocationFormulaCommand-'.length,
      );
      setState(() => _toggleLocationFormulaValue(key));
    }
  }

  void _toggleLocationConstantValue(String key) {
    switch (key) {
      case fortuneToolbarLocationDateCommand:
        _locationConstantDate = !_locationConstantDate;
        break;
      case fortuneToolbarLocationNumberCommand:
        _locationConstantNumber = !_locationConstantNumber;
        break;
      case fortuneToolbarLocationStringCommand:
        _locationConstantString = !_locationConstantString;
        break;
      case 'locationBool':
        _locationConstantLogical = !_locationConstantLogical;
        break;
      case fortuneToolbarLocationErrorCommand:
        _locationConstantError = !_locationConstantError;
        break;
    }
  }

  void _toggleLocationFormulaValue(String key) {
    switch (key) {
      case fortuneToolbarLocationDateCommand:
        _locationFormulaDate = !_locationFormulaDate;
        break;
      case fortuneToolbarLocationNumberCommand:
        _locationFormulaNumber = !_locationFormulaNumber;
        break;
      case fortuneToolbarLocationStringCommand:
        _locationFormulaString = !_locationFormulaString;
        break;
      case 'locationBool':
        _locationFormulaLogical = !_locationFormulaLogical;
        break;
      case fortuneToolbarLocationErrorCommand:
        _locationFormulaError = !_locationFormulaError;
        break;
    }
  }

  void _commitLocationDialog() {
    final sheet = _workbook.activeSheet;
    if (_locationDialogType == fortuneToolbarLocationRowSpanCommand &&
        !_locationHasAtLeastTwoRows(sheet)) {
      _showLocationMessageDialog(widget.locale.locationTiplessTwoRow);
      return;
    }
    if (_locationDialogType == fortuneToolbarLocationColumnSpanCommand &&
        !_locationHasAtLeastTwoColumns(sheet)) {
      _showLocationMessageDialog(widget.locale.locationTiplessTwoColumn);
      return;
    }
    final ranges = switch (_locationDialogType) {
      fortuneToolbarLocationCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasTruthyValue(cell) &&
            !_locationCellHasFormula(cell) &&
            _locationCellMatchesSelectedKinds(
              cell,
              date: _locationConstantDate,
              number: _locationConstantNumber,
              string: _locationConstantString,
              logical: _locationConstantLogical,
              error: _locationConstantError,
            ),
      ),
      fortuneToolbarLocationFormulaCommand => _locationMatchingRanges(
        sheet,
        (cell) =>
            _locationCellHasFormula(cell) &&
            _locationCellMatchesSelectedKinds(
              cell,
              date: _locationFormulaDate,
              number: _locationFormulaNumber,
              string: _locationFormulaString,
              logical: _locationFormulaLogical,
              error: _locationFormulaError,
            ),
      ),
      'locationNull' => _locationNullRanges(sheet),
      fortuneToolbarLocationRowSpanCommand => _locationSpanRanges(
        sheet,
        axis: Axis.vertical,
      ),
      fortuneToolbarLocationColumnSpanCommand => _locationSpanRanges(
        sheet,
        axis: Axis.horizontal,
      ),
      _ => const <FortuneRange>[],
    };
    setState(() {
      _closeTransientMenus();
      if (ranges.isNotEmpty) {
        _writeLocationSelectionRanges(ranges);
      } else {
        _locationMessageDialogText = widget.locale.locationTipNotFindCell;
      }
      _locationDialogOpen = false;
    });
    _focusNode.requestFocus();
  }

  List<FortuneRange> _locationBaseRanges(FortuneSheet sheet) {
    final ranges = _rawSelectionRanges(sheet);
    if (ranges.isEmpty) {
      ranges.add(_currentSelectionRange(sheet));
    }
    if (ranges.length == 1 &&
        ranges.single.rowStart == ranges.single.rowEnd &&
        ranges.single.columnStart == ranges.single.columnEnd) {
      return [
        FortuneRange(
          rowStart: 0,
          rowEnd: _effectiveRowCount(sheet) - 1,
          columnStart: 0,
          columnEnd: _effectiveColumnCount(sheet) - 1,
        ),
      ];
    }
    return ranges;
  }

  List<FortuneRange> _locationCurrentSelectionRanges(FortuneSheet sheet) {
    final ranges = _rawSelectionRanges(sheet);
    if (ranges.isEmpty) {
      ranges.add(_currentSelectionRange(sheet));
    }
    return ranges;
  }

  bool _locationHasAtLeastTwoRows(FortuneSheet sheet) {
    final ranges = _locationCurrentSelectionRanges(sheet);
    return ranges.length > 1 ||
        ranges.any((range) => range.rowStart != range.rowEnd);
  }

  bool _locationHasAtLeastTwoColumns(FortuneSheet sheet) {
    final ranges = _locationCurrentSelectionRanges(sheet);
    return ranges.length > 1 ||
        ranges.any((range) => range.columnStart != range.columnEnd);
  }

  List<FortuneRange> _locationMatchingRanges(
    FortuneSheet sheet,
    bool Function(FortuneCell cell) matches,
  ) {
    final hits = <FortuneCellCoord>[];
    for (final range in _locationBaseRanges(sheet)) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
          final cell = sheet.cells[anchor];
          if (cell != null && matches(cell)) {
            hits.add(FortuneCellCoord(row, column));
          }
        }
      }
    }
    return _coalesceLocationHits(hits);
  }

  List<FortuneRange> _locationNullRanges(FortuneSheet sheet) {
    final hits = <FortuneCellCoord>[];
    for (final range in _locationBaseRanges(sheet)) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
          final cell = sheet.cells[anchor];
          if (cell == null || !_locationCellHasContent(cell)) {
            hits.add(FortuneCellCoord(row, column));
          }
        }
      }
    }
    return _coalesceLocationHits(hits);
  }

  List<FortuneRange> _locationSpanRanges(
    FortuneSheet sheet, {
    required Axis axis,
  }) {
    final ranges = _rawSelectionRanges(sheet);
    if (ranges.isEmpty) {
      ranges.add(_currentSelectionRange(sheet));
    }
    final result = <FortuneRange>[];
    for (final range in ranges) {
      if (axis == Axis.vertical) {
        if (range.rowStart == range.rowEnd) {
          continue;
        }
        for (var row = range.rowStart; row <= range.rowEnd; row += 2) {
          result.add(
            FortuneRange(
              rowStart: row,
              rowEnd: row,
              columnStart: range.columnStart,
              columnEnd: range.columnEnd,
            ),
          );
        }
      } else {
        if (range.columnStart == range.columnEnd) {
          continue;
        }
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 2
        ) {
          result.add(
            FortuneRange(
              rowStart: range.rowStart,
              rowEnd: range.rowEnd,
              columnStart: column,
              columnEnd: column,
            ),
          );
        }
      }
    }
    return result;
  }

  List<FortuneRange> _coalesceLocationHits(List<FortuneCellCoord> hits) {
    if (hits.isEmpty) {
      return const <FortuneRange>[];
    }
    hits.sort((a, b) {
      final rowCompare = a.row.compareTo(b.row);
      return rowCompare == 0 ? a.column.compareTo(b.column) : rowCompare;
    });
    final ranges = <FortuneRange>[];
    var start = hits.first;
    var end = hits.first;
    for (final hit in hits.skip(1)) {
      if (hit.row == end.row && hit.column == end.column + 1) {
        end = hit;
        continue;
      }
      ranges.add(
        FortuneRange(
          rowStart: start.row,
          rowEnd: end.row,
          columnStart: start.column,
          columnEnd: end.column,
        ),
      );
      start = hit;
      end = hit;
    }
    ranges.add(
      FortuneRange(
        rowStart: start.row,
        rowEnd: end.row,
        columnStart: start.column,
        columnEnd: end.column,
      ),
    );
    return ranges;
  }

  bool _locationCellHasContent(FortuneCell cell) {
    return cell.formula != null && cell.formula!.isNotEmpty ||
        cell.value.isNotEmpty ||
        (cell.displayValue != null && cell.displayValue!.isNotEmpty);
  }

  bool _locationCellHasFormula(FortuneCell cell) {
    return cell.formula != null && cell.formula!.isNotEmpty;
  }

  bool _locationCellHasTruthyValue(FortuneCell cell) {
    final value = cell.hasRawValue ? cell.rawValue : cell.value;
    return switch (value) {
      null => false,
      bool value => value,
      num value => value != 0,
      String value => value.isNotEmpty,
      _ => true,
    };
  }

  bool _locationCellMatchesSelectedKinds(
    FortuneCell cell, {
    required bool date,
    required bool number,
    required bool string,
    required bool logical,
    required bool error,
  }) {
    if (!date && !number && !string && !logical && !error) {
      return false;
    }
    final type = _locationCellType(cell);
    final text = cell.renderedText;
    if (date && type == 'd') {
      return true;
    }
    if (number &&
        (type == 'n' || (type == null && double.tryParse(text) != null))) {
      return true;
    }
    if (string &&
        (type == 's' ||
            type == 'g' ||
            (type == null &&
                text.isNotEmpty &&
                double.tryParse(text) == null &&
                !text.startsWith('#') &&
                !_isLocationLogicalText(text)))) {
      return true;
    }
    if (logical && (type == 'b' || _isLocationLogicalText(text))) {
      return true;
    }
    if (error && (type == 'e' || text.startsWith('#'))) {
      return true;
    }
    return false;
  }

  bool _isLocationLogicalText(String text) {
    final normalized = text.trim().toUpperCase();
    return normalized == 'TRUE' || normalized == 'FALSE';
  }

  String? _locationCellType(FortuneCell cell) {
    return cell.cellType?.type;
  }

  void _showFormulaSearchDialog() {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, anchor)) {
      setState(_closeTransientMenus);
      return;
    }
    setState(() {
      _closeTransientMenus();
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      _formulaSearchDialogOpen = true;
      _formulaSearchCategoryMenuOpen = false;
      _formulaSearchCategoryType = 0;
      _formulaSearchSelectedIndex = 0;
      _formulaSearchScrollOffset = 0;
      _formulaSearchEditorController.clear();
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _formulaSearchDialogOpen) {
        _formulaSearchEditorFocusNode.requestFocus();
      }
    });
  }

  void _showFormatSearchDialog(String type) {
    setState(() {
      _closeTransientMenus();
      _formatSearchDialogOpen = true;
      _formatSearchType = type;
      _formatSearchSelectedIndex = 0;
      _formatSearchScrollOffset = 0;
      _formatSearchDecimalController.text = '2';
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted &&
          _formatSearchDialogOpen &&
          _formatSearchType != fortuneToolbarFormatMoreDateTimeCommand) {
        _formatSearchDecimalFocusNode.requestFocus();
      }
    });
  }

  Rect? _formatSearchDialogRect([Size? overrideSize]) {
    if (!_formatSearchDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    return size == null ? null : fortuneFormatSearchDialogRect(size);
  }

  Rect? _formatSearchDecimalInputRect([Size? overrideSize]) {
    final rect = _formatSearchDialogRect(overrideSize);
    return rect == null ? null : fortuneFormatSearchDecimalInputRect(rect);
  }

  String? _formatSearchDialogCommandAt(Offset local) {
    final rect = _formatSearchDialogRect();
    if (rect == null) {
      return null;
    }
    if (!rect.contains(local)) {
      return 'modal';
    }
    if (fortuneFormatSearchCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (_formatSearchType != fortuneToolbarFormatMoreDateTimeCommand &&
        fortuneFormatSearchDecimalInputRect(rect).contains(local)) {
      return 'decimal-input';
    }
    final options = fortuneFormatSearchOptionsFor(_formatSearchType);
    final firstVisibleIndex = fortuneFormatSearchFirstVisibleIndex(
      _formatSearchScrollOffset,
      options.length,
    );
    final visibleRows = math.min(
      options.length - firstVisibleIndex,
      fortuneFormatSearchVisibleRowCount(),
    );
    for (var visibleIndex = 0; visibleIndex < visibleRows; visibleIndex += 1) {
      if (fortuneFormatSearchListRowRect(rect, visibleIndex).contains(local)) {
        return 'option-${firstVisibleIndex + visibleIndex}';
      }
    }
    if (fortuneFormatSearchConfirmButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    if (fortuneFormatSearchCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    return 'modal';
  }

  void _activateFormatSearchDialogCommand(String? command) {
    if (command == null || command == 'decimal-input') {
      return;
    }
    if (command == 'confirm') {
      _confirmFormatSearchDialog();
      return;
    }
    setState(() {
      if (command == 'cancel') {
        _formatSearchDialogOpen = false;
        _focusNode.requestFocus();
        return;
      }
      if (command.startsWith('option-')) {
        final index = int.tryParse(command.substring('option-'.length));
        if (index != null) {
          _formatSearchSelectedIndex = index.clamp(
            0,
            fortuneFormatSearchOptionsFor(_formatSearchType).length - 1,
          );
        }
      }
    });
  }

  void _confirmFormatSearchDialog() {
    final options = fortuneFormatSearchOptionsFor(_formatSearchType);
    if (options.isEmpty) {
      setState(() {
        _formatSearchDialogOpen = false;
      });
      return;
    }
    final option =
        options[_formatSearchSelectedIndex.clamp(0, options.length - 1)];
    if (_formatSearchType == fortuneToolbarFormatMoreDateTimeCommand) {
      _applyFormatSearchFormat(option.value);
      return;
    }
    final decimalPlaces = int.tryParse(_formatSearchDecimalController.text);
    if (decimalPlaces == null || decimalPlaces < 0 || decimalPlaces > 9) {
      _showLocationMessageDialog(widget.locale.tipDecimalPlaces);
      return;
    }
    final zero = 0.toStringAsFixed(decimalPlaces);
    final format = option.position == 'after'
        ? '$zero${option.value}'
        : '${option.value}$zero';
    _applyFormatSearchFormat(format);
  }

  void _applyFormatSearchFormat(String format) {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(() {
        _formatSearchDialogOpen = false;
        _focusNode.requestFocus();
      });
      return;
    }
    final updates = <FortuneCellCoord, FortuneCell>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final coord = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
        final previous = sheet.cells[coord];
        if (previous == null || previous.cellType?.type != 'n') {
          continue;
        }
        final previousType = previous.cellType ?? const FortuneCellType();
        final rawValue = previous.hasRawValue
            ? previous.rawValue
            : previous.value;
        final displayValue = update(format, rawValue);
        updates[coord] = previous.copyWith(
          cellType: previousType.copyWith(type: 'n', format: format),
          displayValue: displayValue,
          rawDisplayValue: cloneFortuneMetadata(displayValue),
          hasRawDisplayValue: true,
        );
      }
    }
    final hasChanges = updates.entries.any(
      (entry) => _cellWouldChange(sheet, entry.key, entry.value),
    );
    if (hasChanges) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChanges) {
        for (final entry in updates.entries) {
          if (_cellWouldChange(sheet, entry.key, entry.value)) {
            _setSheetCell(sheet, entry.key, entry.value);
          }
        }
      }
      _formatSearchDialogOpen = false;
      _focusNode.requestFocus();
    });
  }

  List<FortuneFormulaSearchFunction> _filteredFormulaSearchFunctions() {
    return fortuneFormulaSearchFilteredFunctions(
      _formulaSearchEditorController.text,
      _formulaSearchCategoryType,
    );
  }

  Rect? _formulaSearchDialogRect([Size? overrideSize]) {
    if (!_formulaSearchDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    if (size == null) {
      return null;
    }
    return fortuneFormulaSearchDialogRect(size);
  }

  Rect? _formulaSearchInputRect([Size? overrideSize]) {
    final rect = _formulaSearchDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    return fortuneFormulaSearchInputRect(rect);
  }

  String? _formulaSearchDialogCommandAt(Offset local) {
    final rect = _formulaSearchDialogRect();
    if (rect == null) {
      return null;
    }
    if (_formulaSearchCategoryMenuOpen) {
      final menuRect = fortuneFormulaSearchCategoryMenuRect(rect);
      if (menuRect.contains(local)) {
        final index =
            ((local.dy - menuRect.top) /
                    fortuneFormulaSearchCategoryOptionHeight)
                .floor();
        if (index >= 0 && index < fortuneFormulaSearchCategories.length) {
          return 'category-${fortuneFormulaSearchCategories[index].type}';
        }
      }
    }
    if (!rect.contains(local)) {
      return 'modal';
    }
    if (fortuneFormulaSearchCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (fortuneFormulaSearchInputRect(rect).contains(local)) {
      return 'input';
    }
    if (fortuneFormulaSearchCategorySelectRect(rect).contains(local)) {
      return 'toggle-category';
    }
    final filteredFunctions = _filteredFormulaSearchFunctions();
    final firstVisibleIndex = fortuneFormulaSearchFirstVisibleIndex(
      _formulaSearchScrollOffset,
      filteredFunctions.length,
    );
    final visibleRows = math.min(
      filteredFunctions.length - firstVisibleIndex,
      fortuneFormulaSearchVisibleRowCount(),
    );
    for (var visibleIndex = 0; visibleIndex < visibleRows; visibleIndex += 1) {
      if (fortuneFormulaSearchListRowRect(rect, visibleIndex).contains(local)) {
        return 'function-${firstVisibleIndex + visibleIndex}';
      }
    }
    if (fortuneFormulaSearchOkButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    if (fortuneFormulaSearchCancelButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    return 'modal';
  }

  void _activateFormulaSearchDialogCommand(String? command) {
    if (command == null || command == 'input') {
      return;
    }
    if (command == 'confirm') {
      _confirmFormulaSearchDialog();
      return;
    }
    setState(() {
      if (command == 'cancel') {
        _formulaSearchDialogOpen = false;
        _formulaSearchCategoryMenuOpen = false;
        return;
      }
      if (command == 'modal') {
        _formulaSearchCategoryMenuOpen = false;
        return;
      }
      if (command == 'toggle-category') {
        _formulaSearchCategoryMenuOpen = !_formulaSearchCategoryMenuOpen;
        return;
      }
      if (command.startsWith('category-')) {
        final categoryType = int.tryParse(
          command.substring('category-'.length),
        );
        if (categoryType != null) {
          _formulaSearchCategoryType = categoryType;
          _formulaSearchSelectedIndex = 0;
          _formulaSearchScrollOffset = 0;
          _formulaSearchCategoryMenuOpen = false;
          _formulaSearchEditorController.clear();
        }
        return;
      }
      if (command.startsWith('function-')) {
        final index = int.tryParse(command.substring('function-'.length));
        if (index != null) {
          _formulaSearchSelectedIndex = index;
          _formulaSearchCategoryMenuOpen = false;
        }
      }
    });
  }

  void _confirmFormulaSearchDialog() {
    final filteredFunctions = _filteredFormulaSearchFunctions();
    if (filteredFunctions.isEmpty) {
      return;
    }
    final selectedIndex = _formulaSearchSelectedIndex.clamp(
      0,
      filteredFunctions.length - 1,
    );
    final functionName = filteredFunctions[selectedIndex].name.toUpperCase();
    final coord = _workbook.activeSheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    _startEditingWithText(coord, '=$functionName(');
  }

  bool _isToolbarCommentPopupCommand(String command) {
    return fortuneToolbarCommentEmptyPopupCommands.contains(command) ||
        fortuneToolbarCommentExistingPopupCommands.contains(command);
  }

  void _applyToolbarCommentPopupCommand(String command) {
    switch (command) {
      case fortuneToolbarCommentInsertCommand:
        _insertSelectedCellComment();
        break;
      case fortuneToolbarCommentEditCommand:
        _editSelectedCellComment();
        break;
      case fortuneToolbarCommentDeleteCommand:
        _deleteSelectedCellComment();
        break;
      case fortuneToolbarCommentShowHideCommand:
        _toggleSelectedCellCommentVisibility();
        break;
      case fortuneToolbarCommentShowHideAllCommand:
        _toggleAllCommentVisibility();
        break;
      default:
        setState(_closeTransientMenus);
    }
  }

  bool _isToolbarBorderSubmenuCommand(String command) {
    return command == fortuneToolbarBorderColorSubmenuKey ||
        command == fortuneToolbarBorderStyleSubmenuKey ||
        command == fortuneToolbarBorderColorResetCommand ||
        command == fortuneToolbarBorderColorCustomBlackCommand ||
        command.startsWith(fortuneToolbarBorderColorPaletteCommandPrefix) ||
        command == fortuneToolbarBorderStyleDefaultCommand ||
        command.startsWith(fortuneToolbarBorderStyleCommandPrefix);
  }

  void _activateToolbarBorderSubmenuCommand(String command) {
    if (command == fortuneToolbarBorderColorSubmenuKey ||
        command == fortuneToolbarBorderStyleSubmenuKey) {
      setState(() {
        _toolbarBorderSubmenuKey = command;
        _toolbarBorderHoveredTopLevelIndex = fortuneToolbarBorderPopupCommands
            .indexOf(command);
        _toolbarBorderHoveredSubmenuIndex = null;
      });
      return;
    }
    final preserveExistingStrokeWidth =
        command == fortuneToolbarBorderColorResetCommand ||
        command == fortuneToolbarBorderColorCustomBlackCommand ||
        command.startsWith(fortuneToolbarBorderColorPaletteCommandPrefix);
    var nextBorderColor = _toolbarRecentBorderColor;
    String? nextBorderRawColor = _toolbarRecentBorderRawColor;
    var nextBorderStyle = _toolbarRecentBorderStyle;
    double? nextBorderStyleWidth;
    var closeAfterApply = false;
    if (command == fortuneToolbarBorderColorResetCommand) {
      nextBorderColor = const Color(0xff000000);
      nextBorderRawColor = null;
    } else if (command == fortuneToolbarBorderColorCustomBlackCommand) {
      nextBorderColor = const Color(0xff000000);
      nextBorderRawColor = '#000000';
    } else if (command.startsWith(
      fortuneToolbarBorderColorPaletteCommandPrefix,
    )) {
      final hex = command.substring(
        fortuneToolbarBorderColorPaletteCommandPrefix.length,
      );
      nextBorderColor = fortuneToolbarHexColor(hex);
      nextBorderRawColor = hex;
    } else if (command == fortuneToolbarBorderStyleDefaultCommand) {
      nextBorderStyle = 1;
    } else if (command.startsWith(fortuneToolbarBorderStyleCommandPrefix)) {
      final style = int.tryParse(
        command.substring(fortuneToolbarBorderStyleCommandPrefix.length),
      );
      if (style != null && fortuneToolbarBorderStyleValues.contains(style)) {
        nextBorderStyle = style;
        if (fortuneToolbarBorderWidthEditableStyles.contains(style)) {
          nextBorderStyleWidth = _toolbarBorderStyleWidthInputValue(style);
          closeAfterApply = true;
        }
      }
    }
    final effectiveBorderStyleWidth =
        nextBorderStyleWidth ??
        (fortuneToolbarBorderWidthEditableStyles.contains(nextBorderStyle)
            ? _toolbarBorderStyleStrokeWidths[nextBorderStyle]
            : null);

    final sheet = _workbook.activeSheet;
    final range = _borderCommandRange(sheet);
    final borderUpdates = _canEditRange(sheet, range)
        ? _existingBorderStyleColorUpdates(
            sheet,
            range,
            color: nextBorderColor,
            rawColor: nextBorderRawColor,
            style: nextBorderStyle,
            strokeWidth: effectiveBorderStyleWidth,
            preserveExistingStrokeWidth: preserveExistingStrokeWidth,
          )
        : const <FortuneBorderInfo>[];
    if (borderUpdates.isNotEmpty) {
      _recordUndoSnapshot();
    }
    setState(() {
      _toolbarRecentBorderColor = nextBorderColor;
      _toolbarRecentBorderRawColor = nextBorderRawColor;
      _toolbarRecentBorderStyle = nextBorderStyle;
      if (nextBorderStyleWidth != null) {
        _toolbarBorderStyleStrokeWidths = {
          ..._toolbarBorderStyleStrokeWidths,
          nextBorderStyle: nextBorderStyleWidth,
        };
        _syncToolbarBorderStyleWidthController(
          nextBorderStyle,
          nextBorderStyleWidth,
        );
      }
      if (borderUpdates.isNotEmpty) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          borderInfo: [...sheet.borderInfo, ...borderUpdates],
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      if (closeAfterApply) {
        _closeTransientMenus();
        _focusNode.requestFocus();
      }
    });
  }

  List<FortuneBorderInfo> _existingBorderStyleColorUpdates(
    FortuneSheet sheet,
    FortuneRange range, {
    required Color color,
    required String? rawColor,
    required int style,
    double? strokeWidth,
    bool preserveExistingStrokeWidth = false,
  }) {
    final computedBorders = FortuneBorderCompute.compute(sheet);
    final updates = <FortuneBorderInfo>[];
    void add(
      FortuneCellCoord coord,
      String borderType,
      FortuneBorderSide? side,
    ) {
      final nextStrokeWidth = preserveExistingStrokeWidth
          ? side?.strokeWidth
          : strokeWidth;
      if (side == null ||
          (side.color == color &&
              side.style == style &&
              side.strokeWidth == nextStrokeWidth)) {
        return;
      }
      updates.add(
        FortuneBorderInfo(
          rangeType: 'range',
          borderType: borderType,
          color: color,
          rawColor: rawColor,
          hasRawColor: rawColor != null,
          style: style,
          strokeWidth: nextStrokeWidth,
          ranges: [
            FortuneRange(
              rowStart: coord.row,
              rowEnd: coord.row,
              columnStart: coord.column,
              columnEnd: coord.column,
              rowFocus: coord.row,
              columnFocus: coord.column,
            ),
          ],
        ),
      );
    }

    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final coord = FortuneCellCoord(row, column);
        final borders = computedBorders[coord];
        if (borders == null) {
          continue;
        }
        add(coord, fortuneToolbarBorderTopCommand, borders.top);
        add(coord, fortuneToolbarBorderRightCommand, borders.right);
        add(coord, fortuneToolbarBorderBottomCommand, borders.bottom);
        add(coord, fortuneToolbarBorderLeftCommand, borders.left);
        add(coord, fortuneToolbarBorderSlashCommand, borders.slash);
      }
    }
    return updates;
  }

  bool _isToolbarConditionFormatCommand(String command) {
    return command == fortuneConditionFormatDeleteSheetRuleCommand ||
        _conditionRuleTypeForCommand(command) != null ||
        _conditionImmediateRuleTypeForCommand(command) != null;
  }

  void _applyToolbarConditionFormatCommand(String command) {
    final sheet = _workbook.activeSheet;
    if (!checkProtectionFormatCells(sheet)) {
      final message = _protectionFormatCellsMessage(sheet);
      setState(() {
        _closeTransientMenus();
        if (message != null) {
          _locationMessageDialogText = message;
        }
      });
      return;
    }
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    if (!_canEditCell(sheet, coord)) {
      setState(_closeTransientMenus);
      return;
    }
    if (command == fortuneConditionFormatDeleteSheetRuleCommand) {
      final hadRules =
          sheet.conditionFormats is List &&
          (sheet.conditionFormats! as List).isNotEmpty;
      if (hadRules &&
          !_canEditConditionFormatRules(sheet, sheet.conditionFormats)) {
        setState(_closeTransientMenus);
        return;
      }
      if (hadRules) {
        _recordUndoSnapshot();
      }
      setState(() {
        if (hadRules) {
          _replaceActiveSheet(
            sheet.copyWith(
              conditionFormats: const [],
              hasRawConditionFormats: true,
            ),
          );
        }
        _closeTransientMenus();
      });
      return;
    }
    final ruleType = _conditionRuleTypeForCommand(command);
    final immediateRuleType = _conditionImmediateRuleTypeForCommand(command);
    if ((ruleType != null || immediateRuleType != null) &&
        !_canEditRange(sheet, _conditionRuleSelectionRange(sheet))) {
      setState(_closeTransientMenus);
      return;
    }
    if (ruleType != null) {
      _showConditionRuleDialog(
        ruleType,
        duplicateValue: command == fortuneConditionFormatUniqueValuesCommand
            ? fortuneConditionRuleUniqueValue
            : null,
      );
      return;
    }
    if (immediateRuleType != null) {
      _appendConditionRule(
        sheet,
        _conditionNameForImmediateRule(immediateRuleType),
        _conditionValuesForImmediateRule(immediateRuleType),
      );
    }
  }

  String? _protectionFormatCellsMessage(FortuneSheet sheet) {
    final authority = sheet.authority;
    if (authority is! Map) {
      return null;
    }
    String? nonEmptyText(Object? value) {
      if (value == null) {
        return null;
      }
      final text = '$value';
      return text.isEmpty ? null : text;
    }

    return nonEmptyText(authority['hintText']) ??
        nonEmptyText(authority['defaultSheetHintText']);
  }

  String? _conditionRuleTypeForCommand(String command) {
    return switch (command) {
      fortuneConditionFormatGreaterThanCommand =>
        fortuneConditionRuleDefaultType,
      fortuneConditionFormatLessThanCommand => fortuneConditionRuleLessThanType,
      fortuneConditionFormatEqualCommand => fortuneConditionRuleEqualType,
      fortuneConditionFormatTextContainsCommand =>
        fortuneConditionRuleTextContainsType,
      fortuneConditionFormatBetweenCommand => fortuneConditionRuleBetweenType,
      fortuneConditionFormatDateOccurrenceCommand =>
        fortuneConditionRuleOccurrenceDateType,
      fortuneConditionFormatDuplicateValuesCommand =>
        fortuneConditionRuleDuplicateType,
      fortuneConditionFormatUniqueValuesCommand =>
        fortuneConditionRuleDuplicateType,
      fortuneConditionFormatTop10Command => fortuneConditionRuleTop10Type,
      fortuneConditionFormatTop10PercentCommand =>
        fortuneConditionRuleTop10PercentType,
      fortuneConditionFormatBottom10Command => fortuneConditionRuleLast10Type,
      fortuneConditionFormatBottom10PercentCommand =>
        fortuneConditionRuleLast10PercentType,
      fortuneConditionFormatAboveAverageCommand =>
        fortuneConditionRuleAboveAverageType,
      fortuneConditionFormatBelowAverageCommand =>
        fortuneConditionRuleBelowAverageType,
      _ => null,
    };
  }

  String? _conditionImmediateRuleTypeForCommand(String command) {
    return switch (command) {
      fortuneConditionFormatDateYesterdayCommand =>
        fortuneConditionRuleOccurrenceDateYesterdayType,
      fortuneConditionFormatDateTodayCommand =>
        fortuneConditionRuleOccurrenceDateTodayType,
      fortuneConditionFormatDateTomorrowCommand =>
        fortuneConditionRuleOccurrenceDateTomorrowType,
      fortuneConditionFormatDateLast7DaysCommand =>
        fortuneConditionRuleOccurrenceDateLast7DaysType,
      fortuneConditionFormatDateLastWeekCommand =>
        fortuneConditionRuleOccurrenceDateLastWeekType,
      fortuneConditionFormatDateThisWeekCommand =>
        fortuneConditionRuleOccurrenceDateThisWeekType,
      fortuneConditionFormatDateLastMonthCommand =>
        fortuneConditionRuleOccurrenceDateLastMonthType,
      fortuneConditionFormatDateThisMonthCommand =>
        fortuneConditionRuleOccurrenceDateThisMonthType,
      _ => null,
    };
  }

  String _conditionNameForImmediateRule(String type) {
    return switch (type) {
      String occurrenceDatePreset
          when fortuneConditionRuleOccurrenceDatePresetTypes.contains(
            occurrenceDatePreset,
          ) =>
        fortuneConditionRuleOccurrenceDateType,
      _ => type,
    };
  }

  List<String> _conditionValuesForImmediateRule(String type) {
    return switch (type) {
      fortuneConditionRuleOccurrenceDateYesterdayType => [
        _conditionDateString(_today().subtract(const Duration(days: 1))),
      ],
      fortuneConditionRuleOccurrenceDateTodayType => [
        _conditionDateString(_today()),
      ],
      fortuneConditionRuleOccurrenceDateTomorrowType => [
        _conditionDateString(_today().add(const Duration(days: 1))),
      ],
      fortuneConditionRuleOccurrenceDateLast7DaysType => [
        '${_conditionDateString(_today().subtract(const Duration(days: 6)))} - ${_conditionDateString(_today())}',
      ],
      fortuneConditionRuleOccurrenceDateLastWeekType => [
        _conditionDateRangeString(_lastWeekRange()),
      ],
      fortuneConditionRuleOccurrenceDateThisWeekType => [
        _conditionDateRangeString(_thisWeekRange()),
      ],
      fortuneConditionRuleOccurrenceDateLastMonthType => [
        _conditionDateRangeString(_lastMonthRange()),
      ],
      fortuneConditionRuleOccurrenceDateThisMonthType => [
        _conditionDateRangeString(_thisMonthRange()),
      ],
      _ => const [],
    };
  }

  DateTime _today() {
    final now = DateTime.now();
    return DateTime(now.year, now.month, now.day);
  }

  String _conditionDateString(DateTime date) {
    final month = date.month.toString().padLeft(2, '0');
    final day = date.day.toString().padLeft(2, '0');
    return '${date.year}-$month-$day';
  }

  String _conditionDateRangeString((DateTime, DateTime) range) {
    return '${_conditionDateString(range.$1)} - ${_conditionDateString(range.$2)}';
  }

  (DateTime, DateTime) _thisWeekRange() {
    final today = _today();
    final start = today.subtract(Duration(days: today.weekday - 1));
    return (start, start.add(const Duration(days: 6)));
  }

  (DateTime, DateTime) _lastWeekRange() {
    final thisWeek = _thisWeekRange();
    final start = thisWeek.$1.subtract(const Duration(days: 7));
    return (start, start.add(const Duration(days: 6)));
  }

  (DateTime, DateTime) _thisMonthRange() {
    final today = _today();
    final start = DateTime(today.year, today.month);
    final end = DateTime(today.year, today.month + 1, 0);
    return (start, end);
  }

  (DateTime, DateTime) _lastMonthRange() {
    final today = _today();
    final start = DateTime(today.year, today.month - 1);
    final end = DateTime(today.year, today.month, 0);
    return (start, end);
  }

  void _applyToolbarFormulaCommand(String command) {
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final targetsAndRanges = _quickFormulaTargetsAndRanges(sheet, anchor);
    if (targetsAndRanges.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    final functionName =
        fortuneToolbarFormulaFunctionNames[command] ??
        fortuneToolbarFormulaFunctionNames[fortuneToolbarFormulaSumCommand]!;
    final updates = <(FortuneCellCoord, FortuneCell)>[];
    for (final (coord, range) in targetsAndRanges) {
      final target = sheet.mergeAnchorFor(coord);
      if (!_canEditCell(sheet, target)) {
        continue;
      }
      final formula =
          '=$functionName(${_cellRef(range.rowStart, range.columnStart)}:${_cellRef(range.rowEnd, range.columnEnd)})';
      final previous = sheet.cells[target] ?? const FortuneCell();
      final nextCell = previous.withFormulaBarInput(
        formula,
        formulaDisplayValue: previous.formula == formula
            ? previous.displayValue
            : null,
      );
      if (_cellWouldChange(sheet, target, nextCell)) {
        updates.add((target, nextCell));
      }
    }
    if (updates.isEmpty) {
      setState(_closeTransientMenus);
      return;
    }
    _recordUndoSnapshot();
    setState(() {
      for (final (target, nextCell) in updates) {
        _setSheetCell(sheet, target, nextCell);
      }
      _recalculateWorkbookFormulas();
      _closeTransientMenus();
    });
  }

  List<(FortuneCellCoord, FortuneRange)> _quickFormulaTargetsAndRanges(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    final selectedRange = _currentSelectionRange(sheet);
    final selectedFormulaRange = _explicitQuickFormulaRange(
      sheet,
      selectedRange,
    );
    if (selectedFormulaRange != null) {
      return [
        (
          sheet.mergeAnchorFor(
            _quickFormulaTargetForRange(selectedFormulaRange),
          ),
          selectedFormulaRange,
        ),
      ];
    }
    if (!_isSingleCellRange(selectedRange)) {
      return _quickFormulaTargetsForGridSelection(sheet, selectedRange);
    }
    final range = _quickFormulaRange(sheet, coord);
    if (range == null) {
      return const [];
    }
    return [(coord, range)];
  }

  bool _isSingleCellRange(FortuneRange range) {
    return range.rowStart == range.rowEnd &&
        range.columnStart == range.columnEnd;
  }

  FortuneRange? _explicitQuickFormulaRange(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    final isSingleCell = _isSingleCellRange(range);
    final isOneDimensional =
        range.rowStart == range.rowEnd || range.columnStart == range.columnEnd;
    if (isSingleCell || !isOneDimensional) {
      return null;
    }
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (_isNumericCell(sheet.cells[FortuneCellCoord(row, column)])) {
          return range;
        }
      }
    }
    return null;
  }

  FortuneCellCoord _quickFormulaTargetForRange(FortuneRange range) {
    if (range.columnStart == range.columnEnd) {
      return FortuneCellCoord(range.rowEnd + 1, range.columnStart);
    }
    return FortuneCellCoord(range.rowStart, range.columnEnd + 1);
  }

  List<(FortuneCellCoord, FortuneRange)> _quickFormulaTargetsForGridSelection(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    if (range.rowStart == range.rowEnd ||
        range.columnStart == range.columnEnd) {
      return const [];
    }
    final targets = <(FortuneCellCoord, FortuneRange)>[];
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      final rowRange = FortuneRange(
        rowStart: row,
        rowEnd: row,
        columnStart: range.columnStart,
        columnEnd: range.columnEnd,
      );
      if (_rangeHasNumericCell(sheet, rowRange)) {
        targets.add((FortuneCellCoord(row, range.columnEnd + 1), rowRange));
      }
    }
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      final columnRange = FortuneRange(
        rowStart: range.rowStart,
        rowEnd: range.rowEnd,
        columnStart: column,
        columnEnd: column,
      );
      if (_rangeHasNumericCell(sheet, columnRange)) {
        targets.add((FortuneCellCoord(range.rowEnd + 1, column), columnRange));
      }
    }
    return targets;
  }

  bool _rangeHasNumericCell(FortuneSheet sheet, FortuneRange range) {
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (_isNumericCell(sheet.cells[FortuneCellCoord(row, column)])) {
          return true;
        }
      }
    }
    return false;
  }

  FortuneRange? _quickFormulaRange(FortuneSheet sheet, FortuneCellCoord coord) {
    final above = _contiguousNumericRangeAbove(sheet, coord);
    if (above != null) {
      return above;
    }
    return _contiguousNumericRangeLeft(sheet, coord);
  }

  FortuneRange? _contiguousNumericRangeAbove(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    var row = coord.row - 1;
    while (row >= 0 &&
        _isNumericCell(sheet.cells[FortuneCellCoord(row, coord.column)])) {
      row -= 1;
    }
    final start = row + 1;
    final end = coord.row - 1;
    if (start > end) {
      return null;
    }
    return FortuneRange(
      rowStart: start,
      rowEnd: end,
      columnStart: coord.column,
      columnEnd: coord.column,
    );
  }

  FortuneRange? _contiguousNumericRangeLeft(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    var column = coord.column - 1;
    while (column >= 0 &&
        _isNumericCell(sheet.cells[FortuneCellCoord(coord.row, column)])) {
      column -= 1;
    }
    final start = column + 1;
    final end = coord.column - 1;
    if (start > end) {
      return null;
    }
    return FortuneRange(
      rowStart: coord.row,
      rowEnd: coord.row,
      columnStart: start,
      columnEnd: end,
    );
  }

  bool _isNumericCell(FortuneCell? cell) {
    if (cell == null) {
      return false;
    }
    final text = cell.displayValue ?? cell.value;
    return double.tryParse(text.replaceAll(',', '').trim()) != null;
  }

  String _cellRef(int row, int column) {
    return '${_columnName(column)}${row + 1}';
  }

  String _columnName(int index) {
    var value = index + 1;
    final chars = <String>[];
    while (value > 0) {
      final remainder = (value - 1) % 26;
      chars.insert(0, String.fromCharCode(65 + remainder));
      value = (value - 1) ~/ 26;
    }
    return chars.join();
  }

  bool _isToolbarMergeCommand(String command) {
    return fortuneToolbarMergeCommands.contains(command);
  }

  void _applyToolbarMergeCommand(String command) {
    final sheet = _workbook.activeSheet;
    final range = command == fortuneToolbarMergeCancelCommand
        ? _currentSelectionRange(sheet)
        : _mergeCommandRange(sheet, command);
    final anchor = sheet.mergeAnchorFor(
      FortuneCellCoord(range.rowStart, range.columnStart),
    );
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final cells = Map<FortuneCellCoord, FortuneCell>.from(sheet.cells);
    if (command == fortuneToolbarMergeCancelCommand) {
      _clearMergesInRange(cells, range);
    } else {
      _clearMergesInRange(cells, range);
      switch (command) {
        case fortuneToolbarMergeAllCommand:
          _combineMergeRangeTextIntoAnchor(
            cells,
            FortuneRange(
              rowStart: range.rowStart,
              rowEnd: range.rowEnd,
              columnStart: range.columnStart,
              columnEnd: range.columnEnd,
            ),
          );
          _mergeCellsAt(
            cells,
            FortuneCellCoord(range.rowStart, range.columnStart),
            rowSpan: range.rowEnd - range.rowStart + 1,
            columnSpan: range.columnEnd - range.columnStart + 1,
          );
        case fortuneToolbarMergeHorizontalCommand:
          for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
            _combineMergeRangeTextIntoAnchor(
              cells,
              FortuneRange(
                rowStart: row,
                rowEnd: row,
                columnStart: range.columnStart,
                columnEnd: range.columnEnd,
              ),
            );
            _mergeCellsAt(
              cells,
              FortuneCellCoord(row, range.columnStart),
              rowSpan: 1,
              columnSpan: range.columnEnd - range.columnStart + 1,
            );
          }
        case fortuneToolbarMergeVerticalCommand:
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          ) {
            _combineMergeRangeTextIntoAnchor(
              cells,
              FortuneRange(
                rowStart: range.rowStart,
                rowEnd: range.rowEnd,
                columnStart: column,
                columnEnd: column,
              ),
            );
            _mergeCellsAt(
              cells,
              FortuneCellCoord(range.rowStart, column),
              rowSpan: range.rowEnd - range.rowStart + 1,
              columnSpan: 1,
            );
          }
        default:
          break;
      }
    }
    final cellsChanged = !_cellMapsEqual(sheet.cells, cells);
    if (cellsChanged) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (cellsChanged) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(cells: cells);
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      selection = FortuneSelection(
        row: anchor.row,
        column: anchor.column,
        rowEnd: range.rowEnd,
        columnEnd: range.columnEnd,
      );
      _closeTransientMenus();
    });
  }

  FortuneRange _currentSelectionRange(FortuneSheet sheet) {
    final rowStart = selection.rowStart.clamp(0, _effectiveRowCount(sheet) - 1);
    final rowEnd = selection.normalizedRowEnd.clamp(
      rowStart,
      _effectiveRowCount(sheet) - 1,
    );
    final columnStart = selection.columnStart.clamp(
      0,
      _effectiveColumnCount(sheet) - 1,
    );
    final columnEnd = selection.normalizedColumnEnd.clamp(
      columnStart,
      _effectiveColumnCount(sheet) - 1,
    );
    return FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
    );
  }

  ({FortuneCellCoord anchor, int rowSpan, int columnSpan})?
  _selectedCellColumnSplitTarget(FortuneSheet sheet) {
    final range = _currentSelectionRange(sheet);
    final coord = FortuneCellCoord(range.rowStart, range.columnStart);
    final anchor = sheet.mergeAnchorFor(coord);
    final merge = sheet.cells[anchor]?.merge;
    if (merge == null) {
      return (anchor: anchor, rowSpan: 1, columnSpan: 1);
    }
    final rowSpan = math.max(1, merge.rowSpan);
    final columnSpan = math.max(1, merge.columnSpan);
    return (anchor: anchor, rowSpan: rowSpan, columnSpan: columnSpan);
  }

  FortuneRange _cellColumnSplitTargetRange(
    ({FortuneCellCoord anchor, int rowSpan, int columnSpan}) target,
  ) {
    return FortuneRange(
      rowStart: target.anchor.row,
      rowEnd: target.anchor.row + target.rowSpan - 1,
      columnStart: target.anchor.column,
      columnEnd: target.anchor.column + target.columnSpan - 1,
    );
  }

  bool _canSplitSelectedCellColumn() {
    if (_contextMenuIsEditor || _contextMenuIsHeader) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final target = _selectedCellColumnSplitTarget(sheet);
    if (target == null || target.columnSpan < 2) {
      return false;
    }
    final targetRange = _cellColumnSplitTargetRange(target);
    if (!_canEditRange(sheet, targetRange)) {
      return false;
    }
    for (
      var column = targetRange.columnStart;
      column <= targetRange.columnEnd;
      column += 1
    ) {
      if (_isIndexReadOnly(sheet.colReadOnly, column)) {
        return false;
      }
    }
    final splitOffset = math.max(1, target.columnSpan ~/ 2);
    final insertAt = target.anchor.column + splitOffset;
    return _canEditColumnStructureFrom(sheet, insertAt);
  }

  bool _selectionContainsCoord(FortuneSheet sheet, FortuneCellCoord coord) {
    final ranges = _rawSelectionRanges(sheet);
    if (ranges.isEmpty) {
      ranges.add(_currentSelectionRange(sheet));
    }
    return ranges.any(
      (range) =>
          coord.row >= range.rowStart &&
          coord.row <= range.rowEnd &&
          coord.column >= range.columnStart &&
          coord.column <= range.columnEnd,
    );
  }

  FortuneRange _headerContextRangeForRightClick(
    ({String axis, int index, FortuneRange range}) headerSelection,
  ) {
    final ranges = _rawSelectionRanges(_workbook.activeSheet);
    for (final range in ranges) {
      final rowSelected = range.extraFields['row_select'] == true;
      final columnSelected = range.extraFields['column_select'] == true;
      if (headerSelection.axis == 'row' &&
          rowSelected &&
          headerSelection.index >= range.rowStart &&
          headerSelection.index <= range.rowEnd) {
        return range;
      }
      if (headerSelection.axis == 'column' &&
          columnSelected &&
          headerSelection.index >= range.columnStart &&
          headerSelection.index <= range.columnEnd) {
        return range;
      }
      if (headerSelection.axis == 'all' && rowSelected && columnSelected) {
        return range;
      }
    }
    return headerSelection.range;
  }

  FortuneRange _mergeCommandRange(FortuneSheet sheet, String command) {
    final range = _currentSelectionRange(sheet);
    if (!selection.isSingleCell) {
      return range;
    }
    final maxRow = _effectiveRowCount(sheet) - 1;
    final maxColumn = _effectiveColumnCount(sheet) - 1;
    final rowEnd = command == fortuneToolbarMergeHorizontalCommand
        ? range.rowStart
        : math.min(maxRow, range.rowStart + 1);
    final columnEnd = command == fortuneToolbarMergeVerticalCommand
        ? range.columnStart
        : math.min(maxColumn, range.columnStart + 1);
    return FortuneRange(
      rowStart: range.rowStart,
      rowEnd: rowEnd,
      columnStart: range.columnStart,
      columnEnd: columnEnd,
    );
  }

  void _combineMergeRangeTextIntoAnchor(
    Map<FortuneCellCoord, FortuneCell> cells,
    FortuneRange range,
  ) {
    final parts = <String>[];
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final text = cells[FortuneCellCoord(row, column)]?.renderedText ?? '';
        if (text.isNotEmpty) {
          parts.add(text);
        }
      }
    }
    if (parts.isEmpty) {
      return;
    }
    final anchor = FortuneCellCoord(range.rowStart, range.columnStart);
    final text = parts.join('\n');
    cells[anchor] = (cells[anchor] ?? const FortuneCell()).withEditedValue(
      text,
    );
  }

  bool _canEditRange(FortuneSheet sheet, FortuneRange range) {
    if (!_workbook.settings.allowEdit) {
      return false;
    }
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (!_canEditCell(
          sheet,
          sheet.mergeAnchorFor(FortuneCellCoord(row, column)),
        )) {
          return false;
        }
      }
    }
    return true;
  }

  bool _canEditControllerRangeObject(FortuneSheet sheet, Object range) {
    if (range is FortuneRange) {
      return _canEditRange(sheet, range);
    }
    if (range is Iterable<FortuneRange>) {
      final ranges = range.toList();
      if (ranges.isEmpty) {
        return _workbook.settings.allowEdit;
      }
      return ranges.every((item) => _canEditRange(sheet, item));
    }
    return _workbook.settings.allowEdit;
  }

  bool _canEditRowStructureFrom(FortuneSheet sheet, int rowFrom) {
    if (!_canEditSheetDefaultCell(sheet)) {
      return false;
    }
    final targets = <FortuneCellCoord>{};
    for (final coord in sheet.cells.keys) {
      if (coord.row >= rowFrom) {
        targets.add(sheet.mergeAnchorFor(coord));
      }
    }
    for (final coord in targets) {
      if (!_canEditCellIgnoringAxisReadOnly(sheet, coord)) {
        return false;
      }
    }
    return true;
  }

  bool _canEditColumnStructureFrom(FortuneSheet sheet, int columnFrom) {
    if (!_canEditSheetDefaultCell(sheet)) {
      return false;
    }
    final targets = <FortuneCellCoord>{};
    for (final coord in sheet.cells.keys) {
      if (coord.column >= columnFrom) {
        targets.add(sheet.mergeAnchorFor(coord));
      }
    }
    for (final coord in targets) {
      if (!_canEditCellIgnoringAxisReadOnly(sheet, coord)) {
        return false;
      }
    }
    return true;
  }

  bool _canEditSheetDefaultCell(FortuneSheet sheet) {
    if (!_workbook.settings.allowEdit) {
      return false;
    }
    final authority = sheet.authority;
    if (authority is! Map) {
      return true;
    }
    final sheetProtection = authority['sheet'];
    if (sheetProtection == null) {
      return true;
    }
    return sheetProtection is num && sheetProtection == 0;
  }

  bool _canEditFilterCommand(FortuneSheet sheet) {
    return _canEditSheetDefaultCell(sheet) &&
        isAllowEdit(sheet, settings: _workbook.settings);
  }

  void _clearMergesInRange(
    Map<FortuneCellCoord, FortuneCell> cells,
    FortuneRange range,
  ) {
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(FortuneCellCoord(row, column));
      }
    }
    for (final coord in targets) {
      _clearMergeAt(cells, coord);
    }
  }

  void _mergeCellsAt(
    Map<FortuneCellCoord, FortuneCell> cells,
    FortuneCellCoord anchor, {
    required int rowSpan,
    required int columnSpan,
  }) {
    if (rowSpan <= 1 && columnSpan <= 1) {
      return;
    }
    final merge = FortuneCellMerge(
      row: anchor.row,
      column: anchor.column,
      rowSpan: rowSpan,
      columnSpan: columnSpan,
    );
    cells[anchor] = (cells[anchor] ?? const FortuneCell()).copyWith(
      merge: merge,
    );
    for (var r = anchor.row; r < anchor.row + rowSpan; r += 1) {
      for (var c = anchor.column; c < anchor.column + columnSpan; c += 1) {
        final coord = FortuneCellCoord(r, c);
        if (coord == anchor) {
          continue;
        }
        cells[coord] = (cells[coord] ?? const FortuneCell()).copyWith(
          merge: FortuneCellMerge(row: anchor.row, column: anchor.column),
        );
      }
    }
  }

  void _clearMergeAt(
    Map<FortuneCellCoord, FortuneCell> cells,
    FortuneCellCoord coord,
  ) {
    final anchor = _mergeAnchorInCells(cells, coord);
    final merge = cells[anchor]?.merge;
    if (merge == null) {
      return;
    }
    final rowSpan = math.max(1, merge.rowSpan);
    final columnSpan = math.max(1, merge.columnSpan);
    for (var r = merge.row; r < merge.row + rowSpan; r += 1) {
      for (var c = merge.column; c < merge.column + columnSpan; c += 1) {
        final cellCoord = FortuneCellCoord(r, c);
        final cell = cells[cellCoord];
        if (cell == null) {
          continue;
        }
        final withoutMerge = _cellWithoutMerge(cell);
        if (withoutMerge.isVisuallyEmpty) {
          cells.remove(cellCoord);
        } else {
          cells[cellCoord] = withoutMerge;
        }
      }
    }
  }

  FortuneCellCoord _mergeAnchorInCells(
    Map<FortuneCellCoord, FortuneCell> cells,
    FortuneCellCoord coord,
  ) {
    final merge = cells[coord]?.merge;
    if (merge == null) {
      return coord;
    }
    return FortuneCellCoord(merge.row, merge.column);
  }

  FortuneCell _cellWithoutMerge(FortuneCell cell) {
    return cell.copyWith(merge: null);
  }

  bool _isToolbarBorderCommand(String command) {
    return fortuneToolbarBorderCommands.contains(command);
  }

  void _applyToolbarBorderCommand(String command) {
    final sheet = _workbook.activeSheet;
    final range = _borderCommandRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    if (command == fortuneToolbarBorderNoneCommand &&
        !_rangeHasComputedBorders(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final nextBorderInfo = FortuneBorderInfo(
      rangeType: 'range',
      borderType: command,
      color: _toolbarRecentBorderColor,
      rawColor: _toolbarRecentBorderRawColor,
      hasRawColor: _toolbarRecentBorderRawColor != null,
      style: _toolbarRecentBorderStyle,
      strokeWidth: _toolbarBorderStyleStrokeWidths[_toolbarRecentBorderStyle],
      ranges: [range],
    );
    if (_lastBorderInfoSemanticallyEquals(sheet.borderInfo, nextBorderInfo) ||
        !_borderCommandWouldChangeComputedBorders(sheet, nextBorderInfo)) {
      setState(_closeTransientMenus);
      return;
    }
    final borderInfo = [...sheet.borderInfo, nextBorderInfo];
    final sheets = [..._workbook.sheets];
    sheets[_workbook.activeSheetIndex] = sheet.copyWith(borderInfo: borderInfo);
    _recordUndoSnapshot();
    setState(() {
      _workbook = _workbook.copyWith(sheets: sheets);
      _closeTransientMenus();
    });
  }

  bool _rangeHasComputedBorders(FortuneSheet sheet, FortuneRange range) {
    final borders = FortuneBorderCompute.compute(sheet);
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (borders.containsKey(FortuneCellCoord(row, column))) {
          return true;
        }
      }
    }
    return false;
  }

  bool _lastBorderInfoSemanticallyEquals(
    List<FortuneBorderInfo> borderInfo,
    FortuneBorderInfo next,
  ) {
    if (borderInfo.isEmpty) {
      return false;
    }
    return _borderInfoSemanticallyEquals(borderInfo.last, next);
  }

  bool _borderInfoListSemanticallyEquals(
    List<FortuneBorderInfo> left,
    List<FortuneBorderInfo> right,
  ) {
    if (left.length != right.length) {
      return false;
    }
    for (var i = 0; i < left.length; i += 1) {
      if (!_borderInfoSemanticallyEquals(left[i], right[i])) {
        return false;
      }
    }
    return true;
  }

  bool _borderCommandWouldChangeComputedBorders(
    FortuneSheet sheet,
    FortuneBorderInfo next,
  ) {
    final before = FortuneBorderCompute.compute(sheet);
    final after = FortuneBorderCompute.compute(
      sheet.copyWith(borderInfo: [...sheet.borderInfo, next]),
    );
    return !_computedBorderMapsSemanticallyEqual(before, after);
  }

  bool _computedBorderMapsSemanticallyEqual(
    Map<FortuneCellCoord, FortuneCellBorders> left,
    Map<FortuneCellCoord, FortuneCellBorders> right,
  ) {
    if (left.length != right.length) {
      return false;
    }
    for (final entry in left.entries) {
      final other = right[entry.key];
      if (other == null || !_cellBordersSemanticallyEqual(entry.value, other)) {
        return false;
      }
    }
    return true;
  }

  bool _cellBordersSemanticallyEqual(
    FortuneCellBorders left,
    FortuneCellBorders right,
  ) {
    return _borderSideSemanticallyEqual(left.top, right.top) &&
        _borderSideSemanticallyEqual(left.right, right.right) &&
        _borderSideSemanticallyEqual(left.bottom, right.bottom) &&
        _borderSideSemanticallyEqual(left.left, right.left) &&
        _borderSideSemanticallyEqual(left.slash, right.slash);
  }

  bool _borderSideSemanticallyEqual(
    FortuneBorderSide? left,
    FortuneBorderSide? right,
  ) {
    if (left == null || right == null) {
      return left == right;
    }
    return left.color == right.color &&
        left.style == right.style &&
        left.strokeWidth == right.strokeWidth;
  }

  bool _borderInfoSemanticallyEquals(
    FortuneBorderInfo left,
    FortuneBorderInfo right,
  ) {
    if (left.rangeType != right.rangeType ||
        left.borderType != right.borderType ||
        left.color != right.color ||
        left.style != right.style ||
        left.strokeWidth != right.strokeWidth ||
        left.ranges.length != right.ranges.length) {
      return false;
    }
    for (var i = 0; i < left.ranges.length; i += 1) {
      if (!_rangeSemanticallyEquals(left.ranges[i], right.ranges[i])) {
        return false;
      }
    }
    return true;
  }

  bool _rangeSemanticallyEquals(FortuneRange left, FortuneRange right) {
    return left.rowStart == right.rowStart &&
        left.rowEnd == right.rowEnd &&
        left.columnStart == right.columnStart &&
        left.columnEnd == right.columnEnd &&
        left.rowFocus == right.rowFocus &&
        left.columnFocus == right.columnFocus;
  }

  FortuneRange _borderCommandRange(FortuneSheet sheet) {
    final range = _currentSelectionRange(sheet);
    if (!selection.isSingleCell) {
      return range;
    }
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final merge = sheet.cells[coord]?.merge;
    final rowSpan = math.max(1, merge?.rowSpan ?? 1);
    final columnSpan = math.max(1, merge?.columnSpan ?? 1);
    return FortuneRange(
      rowStart: coord.row,
      rowEnd: math.min(_effectiveRowCount(sheet) - 1, coord.row + rowSpan - 1),
      columnStart: coord.column,
      columnEnd: math.min(
        _effectiveColumnCount(sheet) - 1,
        coord.column + columnSpan - 1,
      ),
      rowFocus: coord.row,
      columnFocus: coord.column,
    );
  }

  bool _isToolbarCellFormatPopupCommand(String command) {
    return command == fortuneToolbarFontColorResetCommand ||
        command.startsWith(fortuneToolbarFontFamilyCommandPrefix) ||
        command == fortuneToolbarFontColorCustomBlackCommand ||
        command.startsWith(fortuneToolbarFontColorPaletteCommandPrefix) ||
        command == fortuneToolbarBackgroundResetCommand ||
        command == fortuneToolbarBackgroundCustomBlackCommand ||
        command.startsWith(fortuneToolbarBackgroundPaletteCommandPrefix) ||
        fortuneToolbarPopupItems.values.any((items) => items.contains(command));
  }

  bool _isInlineToolbarComboKey(String key) {
    return key == fortuneToolbarFontPopupKey ||
        key == fortuneToolbarFontSizePopupKey ||
        key == fortuneToolbarFontColorPopupKey ||
        key == fortuneToolbarBackgroundPopupKey;
  }

  bool _shouldKeepEditingForToolbarCombo(String key) {
    return _editingCoord != null && _isInlineToolbarComboKey(key);
  }

  bool _shouldKeepEditingForEditorTapOutside(PointerDownEvent event) {
    if (_editingCoord == null) {
      return false;
    }
    final local = _canvasLocalPositionForGlobal(event.position);
    final popupKey = toolbarPopupKey;
    if (popupKey != null && _toolbarPopupEventContains(local)) {
      final popupCommand = _toolbarPopupCommandAt(local);
      if (_shouldKeepEditingForToolbarCombo(popupKey) ||
          (popupCommand != null &&
              _isInlineToolbarFormatCommand(popupCommand))) {
        _rememberInlineToolbarSelectionRange();
        return true;
      }
    }
    final comboArrowKey = _toolbarComboArrowKeyAt(local);
    if (comboArrowKey != null &&
        _shouldKeepEditingForToolbarCombo(comboArrowKey)) {
      _rememberInlineToolbarSelectionRange();
      return true;
    }
    final toolbarKey = _toolbarKeyAt(local);
    if (_isToolbarComboCommand(toolbarKey) &&
        _shouldKeepEditingForToolbarCombo(toolbarKey!)) {
      _rememberInlineToolbarSelectionRange();
      return true;
    }
    if (_isToolbarStyleCommand(toolbarKey)) {
      return _inlineToolbarFormatRange() != null;
    }
    return false;
  }

  TextRange? _currentInlineToolbarSelectionRange() {
    if (_editingCoord == null || _editorController.text.isEmpty) {
      return null;
    }
    final selection = _editorController.selection;
    if (!selection.isValid || selection.isCollapsed) {
      return null;
    }
    final start = math.max(0, math.min(selection.start, selection.end));
    final end = math.min(
      _editorController.text.length,
      math.max(selection.start, selection.end),
    );
    if (start >= end) {
      return null;
    }
    return TextRange(start: start, end: end);
  }

  void _rememberInlineToolbarSelectionRange() {
    final range = _currentInlineToolbarSelectionRange();
    if (range != null) {
      _inlineToolbarSelectionRange = range;
      fortuneSheetDebugLog(
        'editor inlineToolbar remember range=${_debugRange(range)} '
        'selection=${_debugSelection(_editorController.selection)} '
        'runs=${_debugEditorRuns(range: range)}',
      );
    } else {
      fortuneSheetDebugLog(
        'editor inlineToolbar remember noRange '
        'selection=${_debugSelection(_editorController.selection)} '
        'stored=${_debugRange(_inlineToolbarSelectionRange)}',
      );
    }
  }

  void _rememberEditorSelection(TextSelection selection) {
    if (_editingCoord == null || !selection.isValid || selection.isCollapsed) {
      return;
    }
    final start = math.max(0, math.min(selection.start, selection.end));
    final end = math.min(
      _editorController.text.length,
      math.max(selection.start, selection.end),
    );
    if (start >= end) {
      return;
    }
    _inlineToolbarSelectionRange = TextRange(start: start, end: end);
  }

  TextRange? _inlineToolbarFormatRange() {
    final current = _currentInlineToolbarSelectionRange();
    if (current != null) {
      _inlineToolbarSelectionRange = current;
      fortuneSheetDebugLog(
        'editor inlineToolbar range source=current '
        'range=${_debugRange(current)} '
        'selection=${_debugSelection(_editorController.selection)} '
        'runs=${_debugEditorRuns(range: current)}',
      );
      return current;
    }
    final remembered = _inlineToolbarSelectionRange;
    if (remembered == null || _editingCoord == null) {
      fortuneSheetDebugLog(
        'editor inlineToolbar range source=none '
        'selection=${_debugSelection(_editorController.selection)} '
        'stored=${_debugRange(remembered)} editing=$_editingCoord',
      );
      return null;
    }
    final textLength = _editorController.text.length;
    final start = math.max(0, math.min(remembered.start, textLength));
    final end = math.max(start, math.min(remembered.end, textLength));
    if (start >= end) {
      fortuneSheetDebugLog(
        'editor inlineToolbar range source=rememberedEmpty '
        'stored=${_debugRange(remembered)} textLength=$textLength',
      );
      return null;
    }
    final range = TextRange(start: start, end: end);
    fortuneSheetDebugLog(
      'editor inlineToolbar range source=remembered '
      'range=${_debugRange(range)} '
      'selection=${_debugSelection(_editorController.selection)} '
      'stored=${_debugRange(remembered)} runs=${_debugEditorRuns(range: range)}',
    );
    return range;
  }

  ({TextRange range, TextSelection selection, bool fromCollapsedLine})?
  _editorContextInlineFormatTargetRange(String command) {
    final current = _currentInlineToolbarSelectionRange();
    if (current != null) {
      fortuneSheetDebugLog(
        'editor inlineInput range command=$command source=currentSelection '
        'range=${_debugRange(current)} selection=${_debugSelection(_editorController.selection)}',
      );
      return (
        range: current,
        selection: _editorController.selection,
        fromCollapsedLine: false,
      );
    }
    final menuRange = _editorContextMenuSelectionRange;
    if (menuRange != null) {
      fortuneSheetDebugLog(
        'editor inlineInput range command=$command source=contextSelection '
        'range=${_debugRange(menuRange)} selection=${_debugSelection(_editorController.selection)}',
      );
      return (
        range: menuRange,
        selection: _editorController.selection,
        fromCollapsedLine: false,
      );
    }
    final selection = _editorController.selection;
    if (selection.isValid && selection.isCollapsed) {
      final lineRange = _editorLineRangeForOffset(selection.extentOffset);
      fortuneSheetDebugLog(
        'editor inlineInput range command=$command source=collapsedLine '
        'range=${_debugRange(lineRange)} selection=${_debugSelection(selection)} '
        'value=${_debugValue(_editorController.value)}',
      );
      if (lineRange != null) {
        return (
          range: lineRange,
          selection: selection,
          fromCollapsedLine: true,
        );
      }
    }
    final remembered = _inlineToolbarFormatRange();
    fortuneSheetDebugLog(
      'editor inlineInput range command=$command source=remembered '
      'range=${_debugRange(remembered)} selection=${_debugSelection(selection)} '
      'inlineRange=${_debugRange(_inlineToolbarSelectionRange)}',
    );
    if (remembered == null) {
      return null;
    }
    return (
      range: remembered,
      selection: _editorController.selection,
      fromCollapsedLine: false,
    );
  }

  TextRange? _editorContextSelectedFormatRange(String command) {
    final current = _currentInlineToolbarSelectionRange();
    if (current != null) {
      fortuneSheetDebugLog(
        'editor contextFormat range command=$command source=currentSelection '
        'range=${_debugRange(current)} selection=${_debugSelection(_editorController.selection)}',
      );
      return current;
    }
    final menuRange = _editorContextMenuSelectionRange;
    if (menuRange != null) {
      fortuneSheetDebugLog(
        'editor contextFormat range command=$command source=contextSelection '
        'range=${_debugRange(menuRange)} selection=${_debugSelection(_editorController.selection)}',
      );
      return menuRange;
    }
    final remembered = _inlineToolbarFormatRange();
    fortuneSheetDebugLog(
      'editor contextFormat range command=$command source=remembered '
      'range=${_debugRange(remembered)} selection=${_debugSelection(_editorController.selection)} '
      'inlineRange=${_debugRange(_inlineToolbarSelectionRange)}',
    );
    return remembered;
  }

  TextRange? _editorLineRangeForOffset(int offset) {
    final text = _editorController.text;
    if (text.isEmpty) {
      return null;
    }
    var cursor = offset.clamp(0, text.length).toInt();
    if (cursor > 0 &&
        (cursor == text.length || text.codeUnitAt(cursor) == 10)) {
      cursor -= 1;
    }
    final before = text.substring(0, cursor);
    final lineStart = before.lastIndexOf('\n') + 1;
    final lineEndIndex = text.indexOf('\n', cursor);
    final lineEnd = lineEndIndex == -1 ? text.length : lineEndIndex;
    if (lineStart >= lineEnd) {
      return null;
    }
    return TextRange(start: lineStart, end: lineEnd);
  }

  void _restoreInlineToolbarSelectionRange(TextRange range) {
    if (_editingCoord == null || _editorController.text.isEmpty) {
      return;
    }
    final textLength = _editorController.text.length;
    final start = math.max(0, math.min(range.start, textLength));
    final end = math.max(start, math.min(range.end, textLength));
    if (start >= end) {
      return;
    }
    _editorController.selection = TextSelection(
      baseOffset: start,
      extentOffset: end,
    );
    _syncEditorPlatformEditingState(_editorController.value);
    fortuneSheetDebugLog(
      'editor inlineToolbar restore range=${_debugRange(range)} '
      'selection=${_debugSelection(_editorController.selection)}',
    );
  }

  void _refocusEditorAndRestoreInlineToolbarSelectionRange(TextRange range) {
    _editorFocusNode.requestFocus();
    _restoreInlineToolbarSelectionRange(range);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || _editingCoord == null) {
        return;
      }
      _editorFocusNode.requestFocus();
      _restoreInlineToolbarSelectionRange(range);
    });
  }

  void _restoreEditorSelectionRange(
    TextRange range, {
    TextSelection? preferredSelection,
  }) {
    if (_editingCoord == null || _editorController.text.isEmpty) {
      return;
    }
    final textLength = _editorController.text.length;
    final rawStart = math.min(range.start, range.end);
    final rawEnd = math.max(range.start, range.end);
    final normalizedRange = TextRange(
      start: math.max(0, math.min(rawStart, textLength)),
      end: math.max(0, math.min(rawEnd, textLength)),
    );
    if (normalizedRange.start >= normalizedRange.end) {
      return;
    }
    _inlineToolbarSelectionRange = normalizedRange;
    final selection = _editorSelectionForRange(
      normalizedRange,
      preferredSelection: preferredSelection,
    );
    _editorController.selection = selection;
    _syncEditorPlatformEditingState(
      _editorController.value.copyWith(selection: selection),
    );
  }

  void _refocusEditorAndRestoreSelectionRange(
    TextRange range, {
    TextSelection? preferredSelection,
  }) {
    _editorFocusNode.requestFocus();
    _restoreEditorSelectionRange(range, preferredSelection: preferredSelection);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || _editingCoord == null) {
        return;
      }
      _editorFocusNode.requestFocus();
      _restoreEditorSelectionRange(
        range,
        preferredSelection: preferredSelection,
      );
    });
  }

  bool _isInlineToolbarFormatCommand(String command) {
    return _inlineToolbarFormat(command) != null;
  }

  bool _applyInlineToolbarFormatCommand(String command) {
    if (_editingCoord == null) {
      fortuneSheetDebugLog(
        'editor inlineToolbar apply noEditing command=$command',
      );
      return false;
    }
    final format = _inlineToolbarFormat(command);
    if (format == null) {
      fortuneSheetDebugLog(
        'editor inlineToolbar apply noFormat command=$command '
        'selection=${_debugSelection(_editorController.selection)}',
      );
      return false;
    }
    final range = _inlineToolbarFormatRange();
    if (range == null) {
      fortuneSheetDebugLog(
        'editor inlineToolbar apply noRange command=$command '
        'key=${format.key} value=${format.value} '
        'selection=${_debugSelection(_editorController.selection)} '
        'stored=${_debugRange(_inlineToolbarSelectionRange)} '
        'runs=${_debugEditorRuns()}',
      );
      setState(_closeTransientMenus);
      _editorFocusNode.requestFocus();
      return true;
    }
    fortuneSheetDebugLog(
      'editor inlineToolbar apply begin command=$command '
      'key=${format.key} value=${format.value} range=${_debugRange(range)} '
      'selection=${_debugSelection(_editorController.selection)} '
      'runsBefore=${_debugEditorRuns()}',
    );
    _recordEditorInlineUndoSnapshot();
    _editorController.applyInlineFormat(format.key, format.value, range: range);
    _inlineToolbarSelectionRange = range;
    setState(() {
      _rememberToolbarColorCommand(command);
      _closeTransientMenus();
    });
    _refocusEditorAndRestoreInlineToolbarSelectionRange(range);
    fortuneSheetDebugLog(
      'editor inlineToolbar apply complete command=$command '
      'key=${format.key} value=${format.value} range=${_debugRange(range)} '
      'selection=${_debugSelection(_editorController.selection)} '
      'runsAfter=${_debugEditorRuns()}',
    );
    return true;
  }

  ({String key, Object? value})? _inlineToolbarFormat(String command) {
    final font = _toolbarFontFamilyForCommand(command);
    if (font != null) {
      return (key: 'ff', value: font);
    }
    final fontSize = _toolbarFontSizeForCommand(command);
    if (fontSize != null) {
      return (key: 'fs', value: fontSize);
    }
    if (command == fortuneToolbarFontColorResetCommand) {
      return (key: 'fc', value: '#000000');
    }
    if (command == fortuneToolbarFontColorCustomBlackCommand) {
      return (key: 'fc', value: '#000000');
    }
    if (command.startsWith(fortuneToolbarFontColorPaletteCommandPrefix)) {
      return (
        key: 'fc',
        value: command.substring(
          fortuneToolbarFontColorPaletteCommandPrefix.length,
        ),
      );
    }
    if (fortuneToolbarColorCommands.containsKey(command) &&
        (command == fortuneToolbarFontColorBlackCommand ||
            command == fortuneToolbarFontColorRedCommand ||
            command == fortuneToolbarFontColorGreenCommand ||
            command == fortuneToolbarFontColorBlueCommand ||
            command == fortuneToolbarFontColorOrangeCommand ||
            command == fortuneToolbarFontColorPurpleCommand)) {
      return (key: 'fc', value: fortuneToolbarColorCommands[command]);
    }
    if (command == fortuneToolbarBackgroundResetCommand ||
        command == fortuneToolbarBackgroundNoneCommand) {
      return (key: 'bg', value: null);
    }
    if (command == fortuneToolbarBackgroundCustomBlackCommand) {
      return (key: 'bg', value: '#000000');
    }
    if (command.startsWith(fortuneToolbarBackgroundPaletteCommandPrefix)) {
      return (
        key: 'bg',
        value: command.substring(
          fortuneToolbarBackgroundPaletteCommandPrefix.length,
        ),
      );
    }
    if (fortuneToolbarColorCommands.containsKey(command) &&
        fortuneToolbarBackgroundCommands.contains(command)) {
      return (key: 'bg', value: fortuneToolbarColorCommands[command]);
    }
    final run = _currentEditingRun();
    return switch (command) {
      fortuneToolbarBoldCommand => (key: 'bl', value: !(run?.bold ?? false)),
      fortuneToolbarItalicCommand => (
        key: 'it',
        value: !(run?.italic ?? false),
      ),
      fortuneToolbarUnderlineCommand => (
        key: 'un',
        value: !(run?.underline ?? false),
      ),
      fortuneToolbarStrikeThroughCommand => (
        key: 'cl',
        value: !(run?.strikeThrough ?? false),
      ),
      _ => null,
    };
  }

  String? _toolbarFontFamilyForCommand(String command) {
    final dynamicFontFamily = fortuneToolbarFontFamilyFromCommand(command);
    if (dynamicFontFamily != null) {
      return dynamicFontFamily;
    }
    return switch (command) {
      fortuneToolbarFontTimesCommand => 'Times New Roman',
      fortuneToolbarFontArialCommand => 'Arial',
      fortuneToolbarFontTahomaCommand => 'Tahoma',
      fortuneToolbarFontVerdanaCommand => 'Verdana',
      _ => null,
    };
  }

  int? _toolbarFontSizeForCommand(String command) {
    return switch (command) {
      fortuneToolbarFontSize4Command => 4,
      fortuneToolbarFontSize5Command => 5,
      fortuneToolbarFontSize6Command => 6,
      fortuneToolbarFontSize7Command => 7,
      fortuneToolbarFontSize8Command => 8,
      fortuneToolbarFontSize9Command => 9,
      fortuneToolbarFontSize10Command => 10,
      fortuneToolbarFontSize11Command => 11,
      fortuneToolbarFontSize12Command => 12,
      fortuneToolbarFontSize14Command => 14,
      fortuneToolbarFontSize16Command => 16,
      fortuneToolbarFontSize18Command => 18,
      fortuneToolbarFontSize20Command => 20,
      fortuneToolbarFontSize22Command => 22,
      fortuneToolbarFontSize24Command => 24,
      fortuneToolbarFontSize26Command => 26,
      fortuneToolbarFontSize28Command => 28,
      fortuneToolbarFontSize36Command => 36,
      fortuneToolbarFontSize48Command => 48,
      fortuneToolbarFontSize72Command => 72,
      _ => null,
    };
  }

  Map<String, String> _currentToolbarComboLabels() {
    final labels = <String, String>{};
    final formatCommand = _currentToolbarFormatCommand();
    final fontFamily = _currentToolbarFontFamily();
    final fontSize = _currentToolbarFontSize();
    labels[fortuneToolbarFormatCommand] = _toolbarPopupLabel(formatCommand);
    if (fontFamily != null && fontFamily.isNotEmpty) {
      labels[fortuneToolbarFontPopupKey] = fontFamily;
    }
    if (fontSize != null) {
      labels[fortuneToolbarFontSizePopupKey] = _toolbarFontSizeLabel(fontSize);
    }
    return labels;
  }

  String _currentToolbarFormatCommand() {
    final cell = _currentSelectionCell();
    final cellType = cell?.cellType;
    final format = cellType?.format;
    if (format == null || format.trim().isEmpty) {
      return cellType?.type == 's'
          ? fortuneToolbarFormatPlainTextCommand
          : fortuneToolbarFormatAutomaticCommand;
    }
    for (final entry in fortuneToolbarFormatValues.entries) {
      if (entry.value == format) {
        return entry.key;
      }
    }
    for (final command in fortuneToolbarFormatCommands) {
      if (command != '|' &&
          _toolbarFormatValueForPopupCommand(command) == format) {
        return command;
      }
    }
    return fortuneToolbarFormatAutomaticCommand;
  }

  String _toolbarPopupLabel(String command) {
    return widget.locale.toolbarPopupLabels[command] ??
        fortuneToolbarPopupLabels[command] ??
        command;
  }

  String? _currentToolbarFontFamily() {
    final editingRun = _currentEditingRun();
    if (editingRun != null) {
      return _toolbarFontFamilyLabel(editingRun.fontFamily) ??
          _defaultToolbarFontFamilyLabel();
    }
    final cell = _currentSelectionCell();
    if (cell == null) {
      return _defaultToolbarFontFamilyLabel();
    }
    final firstRun = _firstNonEmptyInlineRun(cell);
    return _toolbarFontFamilyLabel(firstRun?.fontFamily ?? cell.fontFamily) ??
        _defaultToolbarFontFamilyLabel();
  }

  double? _currentToolbarFontSize() {
    final editingRun = _currentEditingRun();
    if (editingRun != null) {
      return editingRun.fontSize ?? _workbook.settings.defaultFontSize;
    }
    final cell = _currentSelectionCell();
    if (cell == null) {
      return _workbook.settings.defaultFontSize;
    }
    final firstRun = _firstNonEmptyInlineRun(cell);
    return firstRun?.fontSize ??
        cell.fontSize ??
        _workbook.settings.defaultFontSize;
  }

  String _defaultToolbarFontFamilyLabel() {
    return _toolbarFontFamilyLabel(
          fortuneToolbarDefaultComboLabels[fortuneToolbarFontPopupKey],
        ) ??
        fortuneToolbarDefaultComboLabels[fortuneToolbarFontPopupKey]!;
  }

  FortuneInlineTextRun? _currentEditingRun() {
    if (_editingCoord == null || _editorController.text.isEmpty) {
      return null;
    }
    final selection = _editorController.selection;
    final offset = selection.isValid
        ? math.min(
            _editorController.text.length,
            math.max(0, selection.extentOffset),
          )
        : _editorController.text.length;
    return _editorController.runAtOffset(offset);
  }

  FortuneCell? _currentSelectionCell() {
    final sheet = _workbook.activeSheet;
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    return sheet.cells[coord];
  }

  FortuneInlineTextRun? _firstNonEmptyInlineRun(FortuneCell cell) {
    final runs = cell.inlineRuns;
    if (runs == null) {
      return null;
    }
    for (final run in runs) {
      if (run.text.isNotEmpty) {
        return run;
      }
    }
    return null;
  }

  String? _toolbarFontFamilyLabel(String? value) {
    if (value == null || value.trim().isEmpty) {
      return null;
    }
    return fortuneResolveFontFamily(value, _workbook.settings.fontFamilies);
  }

  String _toolbarFontSizeLabel(double value) {
    if (value == value.roundToDouble()) {
      return value.round().toString();
    }
    return value.toString();
  }

  void _applyToolbarCellFormatPopupCommand(String command) {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final updates = <FortuneCellCoord, FortuneCell>{};
    for (final coord in targets) {
      final previous = sheet.cells[coord] ?? const FortuneCell();
      final nextCell = _cellWithPopupFormat(previous, command);
      updates[coord] = nextCell;
    }
    final hasChanges = updates.entries.any(
      (entry) => _cellWouldChange(sheet, entry.key, entry.value),
    );
    if (hasChanges) {
      _recordUndoSnapshot();
    }
    setState(() {
      _rememberToolbarColorCommand(command);
      if (hasChanges) {
        for (final entry in updates.entries) {
          if (_cellWouldChange(sheet, entry.key, entry.value)) {
            _setSheetCell(sheet, entry.key, entry.value);
          }
        }
      }
      _closeTransientMenus();
    });
  }

  FortuneCell _cellWithPopupFormat(FortuneCell previous, String command) {
    final toolbarFormat = _toolbarFormatValueForPopupCommand(command);
    if (toolbarFormat != null) {
      return previous.copyWith(
        cellType: FortuneCellType(
          type: command == fortuneToolbarFormatPlainTextCommand ? 's' : 'n',
          format: toolbarFormat,
        ),
      );
    }
    final fontFamily = fortuneToolbarFontFamilyFromCommand(command);
    if (fontFamily != null) {
      return previous.copyWith(fontFamily: fontFamily);
    }
    final fontSize = _toolbarFontSizeForCommand(command);
    if (fontSize != null) {
      return previous.copyWith(fontSize: fontSize);
    }
    return switch (command) {
      fortuneToolbarFontTimesCommand => previous.copyWith(
        fontFamily: 'Times New Roman',
      ),
      fortuneToolbarFontArialCommand => previous.copyWith(fontFamily: 'Arial'),
      fortuneToolbarFontTahomaCommand => previous.copyWith(
        fontFamily: 'Tahoma',
      ),
      fortuneToolbarFontVerdanaCommand => previous.copyWith(
        fontFamily: 'Verdana',
      ),
      fortuneToolbarFontColorBlackCommand ||
      fortuneToolbarFontColorRedCommand ||
      fortuneToolbarFontColorGreenCommand ||
      fortuneToolbarFontColorBlueCommand ||
      fortuneToolbarFontColorOrangeCommand ||
      fortuneToolbarFontColorPurpleCommand => previous.copyWith(
        foreground: fortuneToolbarColorCommands[command],
      ),
      fortuneToolbarFontColorResetCommand => previous.copyWith(
        foreground: const Color(0xff000000),
        rawForeground: null,
        hasRawForeground: true,
      ),
      fortuneToolbarFontColorCustomBlackCommand => previous.copyWith(
        foreground: const Color(0xff000000),
        rawForeground: '#000000',
        hasRawForeground: true,
      ),
      String paletteCommand
          when paletteCommand.startsWith(
            fortuneToolbarFontColorPaletteCommandPrefix,
          ) =>
        previous.copyWith(
          foreground: fortuneToolbarHexColor(
            paletteCommand.substring(
              fortuneToolbarFontColorPaletteCommandPrefix.length,
            ),
          ),
          rawForeground: paletteCommand.substring(
            fortuneToolbarFontColorPaletteCommandPrefix.length,
          ),
          hasRawForeground: true,
        ),
      fortuneToolbarBackgroundYellowCommand ||
      fortuneToolbarBackgroundGreenCommand ||
      fortuneToolbarBackgroundBlueCommand ||
      fortuneToolbarBackgroundRedCommand ||
      fortuneToolbarBackgroundGrayCommand => previous.copyWith(
        background: fortuneToolbarColorCommands[command],
      ),
      fortuneToolbarBackgroundNoneCommand => previous.copyWith(
        background: null,
      ),
      fortuneToolbarBackgroundResetCommand => previous.copyWith(
        background: null,
        rawBackground: null,
        hasRawBackground: false,
      ),
      fortuneToolbarBackgroundCustomBlackCommand => previous.copyWith(
        background: const Color(0xff000000),
        rawBackground: '#000000',
        hasRawBackground: true,
      ),
      String backgroundPaletteCommand
          when backgroundPaletteCommand.startsWith(
            fortuneToolbarBackgroundPaletteCommandPrefix,
          ) =>
        previous.copyWith(
          background: fortuneToolbarHexColor(
            backgroundPaletteCommand.substring(
              fortuneToolbarBackgroundPaletteCommandPrefix.length,
            ),
          ),
          rawBackground: backgroundPaletteCommand.substring(
            fortuneToolbarBackgroundPaletteCommandPrefix.length,
          ),
          hasRawBackground: true,
        ),
      fortuneToolbarAlignLeftCommand => previous.copyWith(horizontalAlign: '1'),
      fortuneToolbarAlignCenterCommand => previous.copyWith(
        horizontalAlign: '0',
      ),
      fortuneToolbarAlignRightCommand => previous.copyWith(
        horizontalAlign: '2',
      ),
      fortuneToolbarVerticalAlignMiddleCommand => previous.copyWith(
        verticalAlign: '0',
      ),
      fortuneToolbarVerticalAlignTopCommand => previous.copyWith(
        verticalAlign: '1',
      ),
      fortuneToolbarVerticalAlignBottomCommand => previous.copyWith(
        verticalAlign: '2',
      ),
      fortuneToolbarWrapOverflowCommand => previous.copyWith(textWrap: '1'),
      fortuneToolbarWrapClipCommand => previous.copyWith(textWrap: '0'),
      fortuneToolbarWrapWrapCommand => previous.copyWith(textWrap: '2'),
      fortuneToolbarRotateNoneCommand => previous.copyWith(
        textRotationMode: '0',
      ),
      fortuneToolbarRotateUpCommand => previous.copyWith(textRotationMode: '1'),
      fortuneToolbarRotateDownCommand => previous.copyWith(
        textRotationMode: '2',
      ),
      fortuneToolbarRotateVerticalCommand => previous.copyWith(
        textRotationMode: '3',
      ),
      fortuneToolbarRotateUp90Command => previous.copyWith(
        textRotationMode: '4',
      ),
      fortuneToolbarRotateDown90Command => previous.copyWith(
        textRotationMode: '5',
      ),
      _ => previous,
    };
  }

  String? _toolbarFormatValueForPopupCommand(String command) {
    if (command == fortuneToolbarFormatAccountingCommand) {
      return '${_workbook.settings.currency}(0.00)';
    }
    if (command == fortuneToolbarFormatCurrencyCommand) {
      return '${_workbook.settings.currency}0.00';
    }
    return fortuneToolbarFormatValues[command];
  }

  FortuneFrozenPane? _frozenPaneForCommand(String command, FortuneSheet sheet) {
    if (command == fortuneFreezeCancelCommand) {
      return null;
    }
    var rowFocus = selection.row;
    var columnFocus = selection.column;
    final merge = sheet.cells[FortuneCellCoord(rowFocus, columnFocus)]?.merge;
    if (merge != null) {
      rowFocus = merge.row + math.max(1, merge.rowSpan).toInt() - 1;
      columnFocus = merge.column + math.max(1, merge.columnSpan).toInt() - 1;
    }
    final type = switch (command) {
      fortuneFreezeRowCommand => 'rangeRow',
      fortuneFreezeColumnCommand => 'rangeColumn',
      _ => 'both',
    };
    return (sheet.frozen ?? FortuneFrozenPane(type: type)).copyWith(
      type: type,
      rowFocus: rowFocus,
      columnFocus: columnFocus,
    );
  }

  int _freezeColumnIndexAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final x = local.dx - _sheetDataLeft(settings) + scrollOffset.dx;
    final column = metrics.columnAt(x);
    return x > (column.start + column.end) / 2
        ? column.index
        : column.index - 1;
  }

  int _freezeRowIndexAt(
    Offset local,
    FortuneSettings settings,
    FortuneSheetMetrics metrics,
  ) {
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final y = local.dy - sheetTop - _sheetDataTop(settings) + scrollOffset.dy;
    final row = metrics.rowAt(y);
    return y > (row.start + row.end) / 2 ? row.index : row.index - 1;
  }

  void _setActiveSheetFrozen(FortuneFrozenPane? frozen) {
    final sheets = [..._workbook.sheets];
    final sheet = _workbook.activeSheet;
    sheets[_workbook.activeSheetIndex] = sheet.copyWith(frozen: frozen);
    _workbook = _workbook.copyWith(sheets: sheets);
  }

  bool _frozenPaneEquals(FortuneFrozenPane? left, FortuneFrozenPane? right) {
    if (identical(left, right)) {
      return true;
    }
    if (left == null || right == null) {
      return left == right;
    }
    return left.type == right.type &&
        left.rowFocus == right.rowFocus &&
        left.rawRowFocus == right.rawRowFocus &&
        left.hasRawRowFocus == right.hasRawRowFocus &&
        left.columnFocus == right.columnFocus &&
        left.rawColumnFocus == right.rawColumnFocus &&
        left.hasRawColumnFocus == right.hasRawColumnFocus &&
        _objectMapEquals(left.extraFields, right.extraFields) &&
        _objectMapEquals(left.rangeExtraFields, right.rangeExtraFields);
  }

  bool _objectMapEquals(Map<String, Object?> left, Map<String, Object?> right) {
    if (left.length != right.length) {
      return false;
    }
    for (final entry in left.entries) {
      if (!right.containsKey(entry.key) || right[entry.key] != entry.value) {
        return false;
      }
    }
    return true;
  }

  FortuneFrozenPane? _columnFreezeForIndex(
    FortuneFrozenPane? frozen,
    int columnIndex,
  ) {
    if (columnIndex < 0) {
      if (frozen == null) {
        return null;
      }
      if (frozen.freezesRows && frozen.freezesColumns) {
        return FortuneFrozenPane(
          type: 'rangeRow',
          rowFocus: frozen.rowFocus ?? 0,
          rawRowFocus: frozen.rawRowFocus,
          hasRawRowFocus: frozen.hasRawRowFocus,
          columnFocus: 0,
          extraFields: frozen.extraFields,
          rangeExtraFields: frozen.rangeExtraFields,
        );
      }
      return frozen.freezesColumns ? null : frozen;
    }
    if (frozen == null || !frozen.freezesRows) {
      return FortuneFrozenPane(
        type: 'rangeColumn',
        rowFocus: 0,
        columnFocus: columnIndex,
      );
    }
    return FortuneFrozenPane(
      type: 'rangeBoth',
      rowFocus: frozen.rowFocus ?? 0,
      rawRowFocus: frozen.rawRowFocus,
      hasRawRowFocus: frozen.hasRawRowFocus,
      columnFocus: columnIndex,
      extraFields: frozen.extraFields,
      rangeExtraFields: frozen.rangeExtraFields,
    );
  }

  FortuneFrozenPane? _rowFreezeForIndex(
    FortuneFrozenPane? frozen,
    int rowIndex,
  ) {
    if (rowIndex < 0) {
      if (frozen == null) {
        return null;
      }
      if (frozen.freezesRows && frozen.freezesColumns) {
        return FortuneFrozenPane(
          type: 'rangeColumn',
          rowFocus: 0,
          columnFocus: frozen.columnFocus ?? 0,
          rawColumnFocus: frozen.rawColumnFocus,
          hasRawColumnFocus: frozen.hasRawColumnFocus,
          extraFields: frozen.extraFields,
          rangeExtraFields: frozen.rangeExtraFields,
        );
      }
      return frozen.freezesRows ? null : frozen;
    }
    if (frozen == null || !frozen.freezesColumns) {
      return FortuneFrozenPane(
        type: 'rangeRow',
        rowFocus: rowIndex,
        columnFocus: 0,
      );
    }
    return FortuneFrozenPane(
      type: 'rangeBoth',
      rowFocus: rowIndex,
      columnFocus: frozen.columnFocus ?? 0,
      rawColumnFocus: frozen.rawColumnFocus,
      hasRawColumnFocus: frozen.hasRawColumnFocus,
      extraFields: frozen.extraFields,
      rangeExtraFields: frozen.rangeExtraFields,
    );
  }

  _SheetTabsAction? _sheetTabsActionAt(Offset local) {
    final settings = _workbook.settings;
    if (!settings.showSheetTabs) {
      return null;
    }
    final size = context.size;
    if (size == null) {
      return null;
    }
    final statTop = size.height - settings.statisticBarHeight;
    final tabTop = statTop - settings.effectiveSheetBarHeight;
    if (settings.allowEdit &&
        local.dy >= statTop &&
        local.dy <= size.height &&
        fortuneBottomBackTopButtonRect(size, settings).contains(local)) {
      return const _SheetTabsAction.backTop();
    }
    if (settings.allowEdit &&
        local.dy >= statTop &&
        local.dy <= size.height &&
        fortuneBottomAddRowsButtonRect(size, settings).contains(local) &&
        _bottomAddRowsCount(_workbook.activeSheet) > 0) {
      return const _SheetTabsAction.addRows();
    }
    if (local.dy < tabTop || local.dy > statTop) {
      return null;
    }
    if (settings.allowEdit && local.dx >= 0 && local.dx < 29) {
      return const _SheetTabsAction.add();
    }
    if (settings.allowEdit &&
        !_sheetTabsOverflow(size.width) &&
        local.dx >= 30 &&
        local.dx < 58) {
      return const _SheetTabsAction.sheetList();
    }
    if (local.dx >= 30 && local.dx < 44) {
      return const _SheetTabsAction.scroll(-1);
    }
    if (local.dx >= 44 && local.dx < 58) {
      return const _SheetTabsAction.scroll(1);
    }

    final tabViewport = _sheetTabViewport(size.width);
    if (!tabViewport.contains(local)) {
      return null;
    }
    var x = tabViewport.left - _sheetTabScrollOffset;
    for (var i = 0; i < _workbook.sheets.length; i += 1) {
      final sheet = _workbook.sheets[i];
      if (sheet.hide == 1) {
        continue;
      }
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      if (local.dx >= x && local.dx < x + width) {
        return _SheetTabsAction.select(i, openMenu: local.dx >= x + width - 22);
      }
      x += width - 1;
    }
    return null;
  }

  double? _sheetTabInsertionXAt(Offset local) {
    final size = context.size;
    if (size == null) {
      return null;
    }
    final viewport = _sheetTabViewport(size.width);
    if (!viewport.contains(local)) {
      return null;
    }
    final contentX = local.dx - viewport.left + _sheetTabScrollOffset;
    var x = viewport.left;
    var contentLeft = 0.0;
    for (final sheet in _workbook.sheets) {
      if (sheet.hide == 1) {
        continue;
      }
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      if (contentX < contentLeft + width / 2) {
        return x - _sheetTabScrollOffset;
      }
      contentLeft += width - 1;
      x += width - 1;
    }
    return x - _sheetTabScrollOffset;
  }

  int _sheetTabInsertBeforeIndexAt(Offset local) {
    final size = context.size;
    if (size == null) {
      return _workbook.sheets.length;
    }
    final viewport = _sheetTabViewport(size.width);
    final contentX = local.dx - viewport.left + _sheetTabScrollOffset;
    var contentLeft = 0.0;
    var lastVisible = -1;
    for (var i = 0; i < _workbook.sheets.length; i += 1) {
      final sheet = _workbook.sheets[i];
      if (sheet.hide == 1) {
        continue;
      }
      lastVisible = i;
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      if (contentX < contentLeft + width / 2) {
        return i;
      }
      contentLeft += width - 1;
    }
    return lastVisible < 0 ? _workbook.sheets.length : lastVisible + 1;
  }

  void _activateSheetTabsAction(
    _SheetTabsAction action,
    Duration timeStamp,
    Offset local,
  ) {
    if (action.appendRows) {
      _appendRowsAtBottom();
      return;
    }
    if (action.backTop) {
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        sheetListAt = null;
        hiddenSheetListAt = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        scrollOffset = Offset(scrollOffset.dx, 0);
      });
      return;
    }
    if (action.scrollDirection != 0) {
      setState(() {
        _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
          _sheetTabScrollOffset + action.scrollDirection * 96,
        );
        contextMenuAt = null;
        sheetTabMenuAt = null;
        sheetListAt = null;
        hiddenSheetListAt = null;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
      });
      return;
    }

    if (action.openSheetList) {
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        final nextSheetListAt = sheetListAt == null ? _sheetListOrigin() : null;
        sheetListAt = nextSheetListAt;
        _sheetListScrollOffset = 0;
        hiddenSheetListAt = null;
        _sheetTabMenuSheetIndex = null;
        _sheetTabColorMenuOpen = false;
        toolbarPopupKey = null;
      });
      return;
    }

    if (action.openMenu && action.sheetIndex != null) {
      final targetSheet = _workbook.sheets[action.sheetIndex!];
      final didChangeSheet = targetSheet.id != _workbook.activeSheet.id;
      if (didChangeSheet &&
          _workbook.settings.beforeActivateSheet?.call(targetSheet.id) ==
              false) {
        return;
      }
      setState(() {
        if (didChangeSheet) {
          _rememberActiveSheetScrollOffset();
          _activateSheetAtIndex(action.sheetIndex!);
        }
        contextMenuAt = null;
        final sheetTabItems = _sheetTabMenuItems;
        sheetTabMenuAt = sheetTabItems.isEmpty
            ? null
            : _sheetTabMenuOrigin(local);
        sheetListAt = null;
        hiddenSheetListAt = null;
        _sheetTabMenuSheetIndex = action.sheetIndex;
        toolbarPopupKey = null;
      });
      if (didChangeSheet) {
        _workbook.settings.afterActivateSheet?.call(targetSheet.id);
      }
      return;
    }

    FortuneSheet? addedSheet;
    String? activatedSheetId;
    if (action.addSheet) {
      if (!_workbook.settings.allowEdit) {
        setState(_closeTransientMenus);
        return;
      }
      final nextId = _nextSheetId(padDefaultId: true);
      if (nextId == null) {
        return;
      }
      addedSheet = FortuneSheet(
        id: nextId,
        name: generateRandomSheetName(_workbook.sheets),
      );
      if (_workbook.settings.beforeAddSheet?.call(addedSheet) == false) {
        return;
      }
      _recordUndoSnapshot();
    } else if (action.sheetIndex != null) {
      final targetSheet = _workbook.sheets[action.sheetIndex!];
      if (targetSheet.id != _workbook.activeSheet.id) {
        if (_workbook.settings.beforeActivateSheet?.call(targetSheet.id) ==
            false) {
          return;
        }
        activatedSheetId = targetSheet.id;
      }
    }

    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      if (action.addSheet) {
        _rememberActiveSheetScrollOffset();
        final sheets = [..._workbook.sheets];
        sheets.add(addedSheet!);
        _workbook = _workbook.copyWith(
          sheets: sheets,
          activeSheetIndex: sheets.length - 1,
        );
        selection = _selectionFromSheet(addedSheet);
        scrollOffset = _scrollOffsetFromSheet(addedSheet);
        _sheetTabScrollOffset = _sheetTabOffsetToReveal(sheets.length - 1);
        return;
      }
      if (action.sheetIndex != null) {
        final targetSheet = _workbook.sheets[action.sheetIndex!];
        final didChangeSheet = targetSheet.id != _workbook.activeSheet.id;
        if (didChangeSheet) {
          _rememberActiveSheetScrollOffset();
          _activateSheetAtIndex(action.sheetIndex!);
        }
        _sheetTabScrollOffset = _sheetTabOffsetToReveal(action.sheetIndex!);
      }
    });
    if (action.addSheet) {
      _workbook.settings.afterAddSheet?.call(addedSheet!);
    } else if (activatedSheetId != null) {
      _workbook.settings.afterActivateSheet?.call(activatedSheetId);
    }
    if (!action.addSheet) {
      final last = _lastSheetTabDownTime;
      final isDoubleClick =
          _lastSheetTabDownIndex == action.sheetIndex &&
          last != null &&
          timeStamp - last < const Duration(milliseconds: 450);
      _lastSheetTabDownTime = timeStamp;
      _lastSheetTabDownIndex = action.sheetIndex;
      if (isDoubleClick && action.sheetIndex != null) {
        _startRenamingSheet(action.sheetIndex!);
      }
    }
  }

  int _bottomAddRowsCount(FortuneSheet sheet) {
    return math.max(0, sheet.addRows ?? _workbook.settings.addRows);
  }

  void _appendRowsAtBottom() {
    final sheet = _workbook.activeSheet;
    final count = _bottomAddRowsCount(sheet);
    if (count <= 0 || !_canEditSheetDefaultCell(sheet)) {
      setState(_closeTransientMenus);
      return;
    }
    final rowCount = _effectiveRowCount(sheet);
    _queueRowColOnOp('insertRowCol', {
      'type': 'row',
      'index': math.max(0, rowCount - 1),
      'count': count,
      'direction': 'rightbottom',
      'id': sheet.id,
    });
    _recordUndoSnapshot();
    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _replaceActiveSheet(sheet.copyWith(rowCount: rowCount + count));
    });
  }

  String? _sheetTabMenuCommandAt(Offset local) {
    final at = sheetTabMenuAt;
    if (at == null || _sheetTabMenuSheetIndex == null) {
      return null;
    }
    final items = _sheetTabMenuItems;
    final rect = fortuneSheetTabMenuRect(at, items);
    if (!rect.contains(local)) {
      return null;
    }
    var y = rect.top + fortuneSheetTabMenuContentTopPadding;
    for (final item in items) {
      if (item == '|') {
        y += fortuneSheetTabMenuDividerHeight;
        continue;
      }
      if (local.dy >= y && local.dy < y + fortuneSheetTabMenuRowHeight) {
        return item;
      }
      y += fortuneSheetTabMenuRowHeight;
    }
    return null;
  }

  String? _sheetTabColorMenuCommandAt(Offset local) {
    final at = sheetTabMenuAt;
    if (!_sheetTabColorMenuOpen ||
        at == null ||
        _sheetTabMenuSheetIndex == null) {
      return null;
    }
    final rect = fortuneSheetTabColorMenuRect(at, _sheetTabMenuItems);
    if (!rect.contains(local)) {
      return null;
    }
    final command = _toolbarColorPickerPopupCommandAt(
      rect,
      local,
      fortuneToolbarFontColorPopupKey,
    );
    if (command == fortuneToolbarFontColorResetCommand) {
      return fortuneSheetTabColorResetCommand;
    }
    if (command == fortuneToolbarFontColorCustomBlackCommand) {
      return fortuneSheetTabColorCustomBlackCommand;
    }
    if (command != null &&
        command.startsWith(fortuneToolbarFontColorPaletteCommandPrefix)) {
      return fortuneSheetTabColorPaletteCommand(
        command.substring(fortuneToolbarFontColorPaletteCommandPrefix.length),
      );
    }
    if (!_workbook.settings.allowEdit) {
      return fortuneSheetTabColorResetCommand;
    }
    return null;
  }

  String? _contextMenuCommandAt(Offset local) {
    final index = _contextMenuItemIndexAt(local);
    if (index == null) {
      return null;
    }
    final command = _activeContextMenuItems[index];
    return _activeContextMenuDisabledItems.contains(command) ? null : command;
  }

  List<String> get _editorContextMenuItems {
    final range = _editorContextMenuSelectionRange;
    final containsScript =
        range != null && _editorController.rangeContainsScript(range);
    return <String>[
      fortuneContextCopyCommand,
      fortuneContextPasteCommand,
      '|',
      if (containsScript) ...[
        fortuneEditorContextClearScriptCommand,
      ] else ...[
        fortuneEditorContextSuperscriptCommand,
        fortuneEditorContextSubscriptCommand,
      ],
      '|',
      fortuneEditorContextLetterSpacingCommand,
      fortuneEditorContextFontScaleCommand,
      fortuneEditorContextLineHeightCommand,
    ];
  }

  Set<String> get _activeContextMenuDisabledItems {
    if (!_contextMenuIsEditor) {
      return <String>{
        if (!_canSplitSelectedCellColumn())
          fortuneContextSplitCellColumnCommand,
        ...?_workbook.settings.contextMenuDisabledItemsBuilder?.call(),
      };
    }
    return <String>{
      if (_editorContextMenuSelectionRange == null) fortuneContextCopyCommand,
      if (_editorContextMenuSelectionRange == null)
        fortuneEditorContextSuperscriptCommand,
      if (_editorContextMenuSelectionRange == null)
        fortuneEditorContextSubscriptCommand,
      if (!_editorClipboardHasPasteText) fortuneContextPasteCommand,
    };
  }

  String? _contextMenuInlineInputCommandAt(Offset local) {
    final at = contextMenuAt;
    if (at == null) {
      return null;
    }
    final items = _activeContextMenuItems;
    for (final command in fortuneContextMenuInlineInputCommands) {
      if (!items.contains(command)) {
        continue;
      }
      final rect = fortuneContextMenuInlineInputRect(at, command, items);
      if (rect != null && rect.contains(local)) {
        return command;
      }
    }
    return null;
  }

  void _focusContextMenuInlineInput(String command) {
    final controller = _contextMenuInlineInputControllers[command];
    final focusNode = _contextMenuInlineInputFocusNodes[command];
    if (controller == null || focusNode == null) {
      return;
    }
    controller.selection = TextSelection(
      baseOffset: 0,
      extentOffset: controller.text.length,
    );
    focusNode.requestFocus();
  }

  void _focusOrCloseContextMenuAxisSizeInput(String command) {
    final sheet = _workbook.activeSheet;
    if (!_canEditSheetDefaultCell(sheet)) {
      setState(_closeTransientMenus);
      _focusNode.requestFocus();
      return;
    }
    final range = _currentSelectionRange(sheet);
    if (command == fortuneContextSetLabelWidthCommand ||
        command == fortuneContextSetLabelHeightCommand) {
      _focusContextMenuInlineInput(command);
      return;
    }
    if (command == fortuneContextSetRowHeightCommand) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        if (_isIndexReadOnly(sheet.rowReadOnly, row)) {
          setState(_closeTransientMenus);
          _focusNode.requestFocus();
          return;
        }
      }
    } else {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (_isIndexReadOnly(sheet.colReadOnly, column)) {
          setState(_closeTransientMenus);
          _focusNode.requestFocus();
          return;
        }
      }
    }
    _focusContextMenuInlineInput(command);
  }

  int? _contextMenuItemIndexAt(Offset local) {
    final at = contextMenuAt;
    if (at == null) {
      return null;
    }
    final items = _activeContextMenuItems;
    final rect = fortuneContextMenuRect(at, items);
    if (!rect.contains(local)) {
      return null;
    }
    var y = rect.top + fortuneContextMenuContentTopPadding;
    for (var index = 0; index < items.length; index += 1) {
      final item = items[index];
      if (item == '|') {
        y += fortuneContextMenuDividerHeight;
        continue;
      }
      if (local.dy >= y && local.dy < y + fortuneContextMenuRowHeight) {
        return index;
      }
      y += fortuneContextMenuRowHeight;
    }
    return null;
  }

  List<String> get _activeContextMenuItems => _contextMenuItemsForSelection(
    _contextMenuIsEditor
        ? _editorContextMenuItems
        : _contextMenuIsHeader
        ? _workbook.settings.headerContextMenu
        : _workbook.settings.cellContextMenu,
  );

  List<String> get _sheetTabMenuItems => fortuneSheetTabRenderableMenuItems(
    _workbook.settings.sheetTabContextMenu,
  );

  void _syncContextMenuInlineInputControllers(List<String> items) {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    _contextMenuInlineInputInitialTexts.clear();
    for (final command in fortuneContextMenuInlineInputCommands) {
      if (!items.contains(command)) {
        continue;
      }
      final controller = _contextMenuInlineInputControllers[command];
      if (controller == null) {
        continue;
      }
      final value = switch (command) {
        fortuneContextInsertRowCommand || fortuneContextInsertRowBelowCommand =>
          (range.rowEnd - range.rowStart + 1).clamp(1, 999).toString(),
        fortuneContextInsertColumnCommand ||
        fortuneContextInsertColumnRightCommand =>
          (range.columnEnd - range.columnStart + 1).clamp(1, 999).toString(),
        fortuneContextSetRowHeightCommand => _formatAxisMenuSizeValue(
          sheet,
          sheet.rowHeights[range.rowStart] ??
              sheet.defaultRowHeight ??
              _workbook.settings.defaultRowHeight,
        ),
        fortuneContextSetColumnWidthCommand => _formatAxisMenuSizeValue(
          sheet,
          sheet.columnWidths[range.columnStart] ??
              sheet.defaultColWidth ??
              _workbook.settings.defaultColWidth,
        ),
        fortuneContextSetLabelWidthCommand =>
          fortuneSheetGridClientWidthMm(sheet)?.toString() ?? '',
        fortuneContextSetLabelHeightCommand =>
          fortuneSheetGridClientHeightMm(sheet)?.toString() ?? '',
        fortuneEditorContextLetterSpacingCommand ||
        fortuneEditorContextFontScaleCommand ||
        fortuneEditorContextLineHeightCommand =>
          _editorContextInlineInputValueForCommand(command),
        _ => '1',
      };
      controller.text = value;
      _contextMenuInlineInputInitialTexts[command] = value;
    }
  }

  String _editorContextInlineInputValueForCommand(String command) {
    final target = _editorContextInlineFormatTargetRange(command);
    if (target == null) {
      fortuneSheetDebugLog(
        'editor inlineInput prefill command=$command range=null text=""',
      );
      return '';
    }
    final key = switch (command) {
      fortuneEditorContextLetterSpacingCommand => 'letterSpacing',
      fortuneEditorContextFontScaleCommand => 'fontScale',
      fortuneEditorContextLineHeightCommand => 'lineHeight',
      _ => null,
    };
    if (key == null) {
      return '';
    }
    final caretRunText = _editorContextCollapsedRunInputValue(command, key);
    if (caretRunText != null) {
      return caretRunText;
    }
    final runs = _editorController.runsForRange(target.range);
    double? first;
    for (final run in runs) {
      if (!run.extraFields.containsKey(key)) {
        fortuneSheetDebugLog(
          'editor inlineInput prefill command=$command key=$key '
          'range=${_debugRange(target.range)} missingRun textLength=${run.text.length}',
        );
        return '';
      }
      final value = _doubleFromObject(run.extraFields[key]);
      if (value == null || !value.isFinite) {
        fortuneSheetDebugLog(
          'editor inlineInput prefill command=$command key=$key '
          'range=${_debugRange(target.range)} invalidValue=${run.extraFields[key]}',
        );
        return '';
      }
      first ??= value;
      if ((first - value).abs() > 0.0001) {
        fortuneSheetDebugLog(
          'editor inlineInput prefill command=$command key=$key '
          'range=${_debugRange(target.range)} mixed first=$first next=$value',
        );
        return '';
      }
    }
    final text = first == null ? '' : _formatEditorInlineInputValue(first);
    fortuneSheetDebugLog(
      'editor inlineInput prefill command=$command key=$key '
      'range=${_debugRange(target.range)} text="$text"',
    );
    return text;
  }

  String? _editorContextCollapsedRunInputValue(String command, String key) {
    if (command != fortuneEditorContextLetterSpacingCommand &&
        command != fortuneEditorContextFontScaleCommand &&
        command != fortuneEditorContextLineHeightCommand) {
      return null;
    }
    final selection = _editorController.selection;
    if (!selection.isValid || !selection.isCollapsed) {
      return null;
    }
    final run = _editorController.runAtOffset(selection.extentOffset);
    if (run == null) {
      fortuneSheetDebugLog(
        'editor inlineInput prefill command=$command key=$key '
        'source=collapsedRun offset=${selection.extentOffset} text=""',
      );
      return '';
    }
    if (!run.extraFields.containsKey(key)) {
      fortuneSheetDebugLog(
        'editor inlineInput prefill command=$command key=$key '
        'source=collapsedRun offset=${selection.extentOffset} missingRun '
        'textLength=${run.text.length}',
      );
      return '';
    }
    final value = _doubleFromObject(run.extraFields[key]);
    if (value == null || !value.isFinite) {
      fortuneSheetDebugLog(
        'editor inlineInput prefill command=$command key=$key '
        'source=collapsedRun offset=${selection.extentOffset} '
        'invalidValue=${run.extraFields[key]}',
      );
      return '';
    }
    final text = _formatEditorInlineInputValue(value);
    fortuneSheetDebugLog(
      'editor inlineInput prefill command=$command key=$key '
      'source=collapsedRun offset=${selection.extentOffset} text="$text"',
    );
    return text;
  }

  String _formatEditorInlineInputValue(double value) {
    if (value == value.roundToDouble()) {
      return value.toInt().toString();
    }
    return value
        .toStringAsFixed(2)
        .replaceFirst(RegExp(r'0+$'), '')
        .replaceFirst(RegExp(r'\.$'), '');
  }

  double? _doubleFromObject(Object? value) {
    if (value is num) {
      return value.toDouble();
    }
    return double.tryParse('$value');
  }

  List<String> _contextMenuItemsForSelection(
    List<String> items, {
    FortuneRange? range,
  }) {
    final rendered = fortuneContextRenderableMenuItems(items);
    final ranges = range == null
        ? _rawSelectionRanges(_workbook.activeSheet)
        : null;
    final extraFields =
        range?.extraFields ??
        (ranges == null || ranges.isEmpty
            ? const <String, Object?>{}
            : ranges.first.extraFields);
    final rowSelected = extraFields['row_select'] == true;
    final columnSelected = extraFields['column_select'] == true;
    final adjustedSheet =
        fortuneSheetGridClientPhysicalSize(_workbook.activeSheet) != null;
    final filtered = rendered
        .where(
          (item) => switch (item) {
            fortuneContextShowGridLinesCommand =>
              adjustedSheet && rowSelected && columnSelected,
            fortuneContextShowRulerCommand =>
              adjustedSheet && rowSelected && columnSelected,
            fortuneContextInsertRowCommand => !columnSelected,
            fortuneContextInsertRowBelowCommand => !columnSelected,
            fortuneContextInsertColumnCommand => !rowSelected,
            fortuneContextInsertColumnRightCommand => !rowSelected,
            fortuneContextSplitCellColumnCommand =>
              !rowSelected && !columnSelected,
            fortuneContextDeleteCellCommand => false,
            fortuneContextDeleteRowCommand ||
            fortuneContextHideRowCommand ||
            fortuneContextShowHiddenRowCommand ||
            fortuneContextSetRowHeightCommand => rowSelected,
            fortuneContextDeleteColumnCommand ||
            fortuneContextHideColumnCommand ||
            fortuneContextShowHiddenColumnCommand ||
            fortuneContextSetColumnWidthCommand => columnSelected,
            fortuneContextSetLabelWidthCommand ||
            fortuneContextSetLabelHeightCommand =>
              adjustedSheet && rowSelected && columnSelected,
            _ => true,
          },
        )
        .toList();
    if (adjustedSheet && rowSelected && columnSelected) {
      filtered.add(fortuneContextImportLabelFileCommand);
      filtered.add(fortuneContextExportLabelFileCommand);
    }
    return List<String>.unmodifiable(filtered);
  }

  Offset _contextMenuOrigin(Offset local, List<String> items) {
    final size = context.size;
    if (size == null) {
      return local;
    }
    final rect = fortuneContextMenuRect(local, items);
    var left = local.dx;
    var top = local.dy;
    if (rect.right > size.width) {
      left -= rect.width;
    }
    if (rect.bottom > size.height) {
      top -= rect.height;
    }
    if (top < 0) {
      top = 0;
    }
    return Offset(left, top);
  }

  void _activateContextMenuCommand(String command) {
    if (_contextMenuIsEditor) {
      fortuneSheetDebugLog(
        'editor contextMenu command=$command '
        'storedRange=${_debugRange(_editorContextMenuSelectionRange)} '
        'inlineRange=${_debugRange(_inlineToolbarSelectionRange)} '
        'value=${_debugValue(_editorController.value)}',
      );
      switch (command) {
        case fortuneContextCopyCommand:
          unawaited(
            _copyEditorRangeToClipboard(
              _editorContextMenuSelectionRange ?? _inlineToolbarFormatRange(),
            ),
          );
        case fortuneContextPasteCommand:
          final range = _editorContextMenuSelectionRange;
          _queueEditorTextMutation(
            () => _pasteClipboardIntoEditor(replaceRange: range),
          );
        case fortuneEditorContextSuperscriptCommand:
          _applyEditorContextScript('superscript');
        case fortuneEditorContextSubscriptCommand:
          _applyEditorContextScript('subscript');
        case fortuneEditorContextClearScriptCommand:
          _clearEditorContextScript();
        case fortuneEditorContextLetterSpacingCommand ||
            fortuneEditorContextFontScaleCommand ||
            fortuneEditorContextLineHeightCommand:
          if (_contextMenuInlineInputFocusNodes[command]?.hasFocus == true) {
            _commitEditorContextInlineInput(command);
          } else {
            _focusContextMenuInlineInput(command);
          }
      }
      return;
    }
    switch (command) {
      case fortuneContextCopyCommand:
        _copySelectionToClipboard();
      case fortuneContextPasteCommand:
        if (_rawSelectionRanges(_workbook.activeSheet).length > 1) {
          setState(_closeTransientMenus);
          break;
        }
        unawaited(_pasteClipboardToSelection());
      case fortuneContextClearCommand:
        _clearSelection();
      case fortuneContextClearSheetCommand:
        _clearControllerSheet(id: _workbook.activeSheet.id);
      case fortuneContextSortCommand:
        _showCustomSortDialog();
      case fortuneContextOrderAzCommand:
        _sortSelectedRange(isAscending: true);
      case fortuneContextOrderZaCommand:
        _sortSelectedRange(isAscending: false);
      case fortuneContextInsertRowCommand:
        _insertRowAtSelection(count: _contextMenuInsertCount(command));
      case fortuneContextInsertRowBelowCommand:
        _insertRowAtSelection(
          direction: 'rightbottom',
          count: _contextMenuInsertCount(command),
        );
      case fortuneContextInsertColumnCommand:
        _insertColumnAtSelection(count: _contextMenuInsertCount(command));
      case fortuneContextInsertColumnRightCommand:
        _insertColumnAtSelection(
          direction: 'rightbottom',
          count: _contextMenuInsertCount(command),
        );
      case fortuneContextSplitCellColumnCommand:
        _splitSelectedCellColumn();
      case fortuneContextDeleteRowCommand:
        _deleteRowAtSelection();
      case fortuneContextDeleteColumnCommand:
        _deleteColumnAtSelection();
      case fortuneContextDeleteCellCommand:
        _clearSelection();
      case fortuneContextHideRowCommand:
        _hideRowAtSelection();
      case fortuneContextShowHiddenRowCommand:
        _showHiddenRowsAtSelection();
      case fortuneContextHideColumnCommand:
        _hideColumnAtSelection();
      case fortuneContextShowHiddenColumnCommand:
        _showHiddenColumnsAtSelection();
      case fortuneContextSetRowHeightCommand:
        _focusOrCloseContextMenuAxisSizeInput(command);
      case fortuneContextSetColumnWidthCommand:
        _focusOrCloseContextMenuAxisSizeInput(command);
      case fortuneContextSetLabelWidthCommand:
        _focusOrCloseContextMenuAxisSizeInput(command);
      case fortuneContextSetLabelHeightCommand:
        _focusOrCloseContextMenuAxisSizeInput(command);
      case fortuneContextShowGridLinesCommand:
        _toggleSheetGridLinesVisible();
      case fortuneContextShowRulerCommand:
        _toggleSheetRulerVisible();
      case fortuneToolbarFilterCommand:
        _toggleSelectedColumnFilter();
      case fortuneToolbarImageCommand:
        _showImageInsertDialog();
      case fortuneToolbarBarcodeCommand:
        _showBarcodeInsertDialog();
      case fortuneToolbarLinkCommand:
        _toggleSelectedCellHyperlinkMetadata();
      case fortuneContextDataCommand:
        _toggleSelectedCellDataVerification();
      case fortuneContextCellFormatCommand:
        _showFormatSearchDialog(fortuneToolbarFormatMoreNumberCommand);
      default:
        final handler = _workbook.settings.onContextMenuCommand;
        if (handler != null) {
          setState(_closeTransientMenus);
          unawaited(Future<void>.sync(() => handler(command)));
          break;
        }
        setState(() {
          _closeTransientMenus();
        });
    }
  }

  void _toggleSheetRulerVisible() {
    final nextVisible = !_activeSheetRulerVisible();
    _recordUndoSnapshot();
    setState(() {
      _writeSheetRulerState(visible: nextVisible);
      if (!nextVisible) {
        _sheetRulerHoveredGuideIndex = null;
        _sheetRulerSelectedGuideIndex = null;
        _sheetRulerTooltipText = null;
        _sheetRulerTooltipPosition = null;
        _sheetRulerDraggingGuide = null;
        _sheetRulerDragAxis = null;
        _sheetRulerHoveringRuler = false;
      }
      _closeTransientMenus();
    });
  }

  void _toggleSheetGridLinesVisible() {
    final sheet = _workbook.activeSheet;
    _recordUndoSnapshot();
    setState(() {
      _replaceActiveSheet(sheet.copyWith(showGridLines: !sheet.showGridLines));
      _closeTransientMenus();
    });
  }

  int _contextMenuInsertCount(String command) {
    final text = _contextMenuInlineInputControllers[command]?.text.trim();
    return (int.tryParse(text ?? '') ?? 1).clamp(1, 999).toInt();
  }

  bool _isEditorContextInlineInputCommand(String command) {
    return command == fortuneEditorContextLetterSpacingCommand ||
        command == fortuneEditorContextFontScaleCommand ||
        command == fortuneEditorContextLineHeightCommand;
  }

  bool _commitEditorContextInlineInput(String command) {
    final controller = _contextMenuInlineInputControllers[command];
    final rawText = controller?.text.trim() ?? '';
    final value = double.tryParse(rawText);
    fortuneSheetDebugLog(
      'editor inlineInput commit begin command=$command raw="$rawText" '
      'parsed=$value selection=${_debugSelection(_editorController.selection)} '
      'storedRange=${_debugRange(_editorContextMenuSelectionRange)} '
      'inlineRange=${_debugRange(_inlineToolbarSelectionRange)}',
    );
    final isValid = switch (command) {
      fortuneEditorContextLetterSpacingCommand => value != null,
      fortuneEditorContextFontScaleCommand ||
      fortuneEditorContextLineHeightCommand => value != null && value > 0,
      _ => false,
    };
    if (!isValid) {
      fortuneSheetDebugLog(
        'editor inlineInput commit invalid command=$command raw="$rawText" parsed=$value',
      );
      _focusContextMenuInlineInput(command);
      return false;
    }
    final format = switch (command) {
      fortuneEditorContextLetterSpacingCommand => (
        key: 'letterSpacing',
        value: value,
      ),
      fortuneEditorContextFontScaleCommand => (key: 'fontScale', value: value),
      fortuneEditorContextLineHeightCommand => (
        key: 'lineHeight',
        value: value,
      ),
      _ => null,
    };
    if (format == null) {
      fortuneSheetDebugLog(
        'editor inlineInput commit noFormat command=$command',
      );
      return false;
    }
    return _applyEditorContextInlineFormat(command, format.key, format.value);
  }

  bool _applyEditorContextInlineFormat(
    String command,
    String key,
    Object? value,
  ) {
    if (_editingCoord == null) {
      fortuneSheetDebugLog(
        'editor inlineInput apply noEditing command=$command key=$key value=$value',
      );
      setState(_closeTransientMenus);
      _focusNode.requestFocus();
      return true;
    }
    final target = _editorContextInlineFormatTargetRange(command);
    if (target == null) {
      fortuneSheetDebugLog(
        'editor inlineInput apply noRange command=$command key=$key value=$value '
        'selection=${_debugSelection(_editorController.selection)} '
        'valueState=${_debugValue(_editorController.value)}',
      );
      setState(_closeTransientMenus);
      _editorFocusNode.requestFocus();
      return true;
    }
    fortuneSheetDebugLog(
      'editor inlineInput apply begin command=$command key=$key value=$value '
      'range=${_debugRange(target.range)} collapsedLine=${target.fromCollapsedLine} '
      'selection=${_debugSelection(target.selection)} runs=${_editorController.runsForRange(target.range).length}',
    );
    _recordEditorInlineUndoSnapshot();
    _editorController.applyInlineFormat(key, value, range: target.range);
    if (!target.fromCollapsedLine) {
      _inlineToolbarSelectionRange = target.range;
    }
    setState(_closeTransientMenus);
    if (target.fromCollapsedLine) {
      _editorFocusNode.requestFocus();
      _editorController.selection = target.selection;
      _syncEditorPlatformEditingState(
        _editorController.value.copyWith(selection: target.selection),
      );
    } else {
      _refocusEditorAndRestoreInlineToolbarSelectionRange(target.range);
    }
    fortuneSheetDebugLog(
      'editor inlineInput apply complete command=$command key=$key value=$value '
      'range=${_debugRange(target.range)} collapsedLine=${target.fromCollapsedLine} '
      'selection=${_debugSelection(_editorController.selection)} '
      'valueState=${_debugValue(_editorController.value)}',
    );
    return true;
  }

  bool _applyEditorContextScript(String script) {
    return _updateEditorContextScript(script: script);
  }

  bool _clearEditorContextScript() {
    return _updateEditorContextScript(script: null);
  }

  bool _updateEditorContextScript({required String? script}) {
    if (_editingCoord == null) {
      fortuneSheetDebugLog('editor contextScript noEditing script=$script');
      setState(_closeTransientMenus);
      _focusNode.requestFocus();
      return true;
    }
    final command = script == null
        ? fortuneEditorContextClearScriptCommand
        : script == 'superscript'
        ? fortuneEditorContextSuperscriptCommand
        : fortuneEditorContextSubscriptCommand;
    final range = _editorContextSelectedFormatRange(command);
    if (range == null) {
      fortuneSheetDebugLog(
        'editor contextScript noRange command=$command script=$script '
        'selection=${_debugSelection(_editorController.selection)} '
        'storedRange=${_debugRange(_editorContextMenuSelectionRange)} '
        'inlineRange=${_debugRange(_inlineToolbarSelectionRange)}',
      );
      setState(_closeTransientMenus);
      _editorFocusNode.requestFocus();
      return true;
    }
    final preferredSelection = _editorController.selection;
    final baseFontSize = _editorScriptBaseFontSize(range);
    fortuneSheetDebugLog(
      'editor contextScript apply begin command=$command script=$script '
      'range=${_debugRange(range)} baseFontSize=$baseFontSize '
      'selection=${_debugSelection(preferredSelection)} '
      'runs=${_editorController.runsForRange(range).length}',
    );
    _recordEditorInlineUndoSnapshot();
    if (script == null) {
      _editorController.clearScriptAndSetFontSize(range, baseFontSize);
    } else {
      final scriptFontSize = baseFontSize * fortuneInlineScriptFontSizeScale;
      _editorController.applyInlineFormat('fs', scriptFontSize, range: range);
      _editorController.applyInlineFormat('script', script, range: range);
    }
    _inlineToolbarSelectionRange = range;
    setState(_closeTransientMenus);
    _refocusEditorAndRestoreSelectionRange(
      range,
      preferredSelection: preferredSelection,
    );
    fortuneSheetDebugLog(
      'editor contextScript apply complete command=$command script=$script '
      'range=${_debugRange(range)} selection=${_debugSelection(_editorController.selection)} '
      'valueState=${_debugValue(_editorController.value)}',
    );
    return true;
  }

  double _editorScriptBaseFontSize(TextRange range) {
    final editingCoord = _editingCoord;
    final sheet = _workbook.activeSheet;
    final cell = editingCoord == null ? null : sheet.cells[editingCoord];
    if (range.start <= 0) {
      return cell?.fontSize ?? _workbook.settings.defaultFontSize;
    }
    return _editorController.runAtOffset(range.start)?.fontSize ??
        cell?.fontSize ??
        _workbook.settings.defaultFontSize;
  }

  bool _commitContextMenuAxisSize(String command) {
    final controller = _contextMenuInlineInputControllers[command];
    if (controller == null) {
      return false;
    }
    final inputExtent = double.tryParse(controller.text.trim());
    if (inputExtent == null || inputExtent <= 0) {
      _focusContextMenuInlineInput(command);
      return false;
    }
    final sheet = _workbook.activeSheet;
    if (!_canEditSheetDefaultCell(sheet)) {
      setState(_closeTransientMenus);
      _focusNode.requestFocus();
      return true;
    }
    if (command == fortuneContextSetLabelWidthCommand ||
        command == fortuneContextSetLabelHeightCommand) {
      return _commitContextMenuLabelSize(command, inputExtent);
    }
    final range = _currentSelectionRange(sheet);
    final isRow = command == fortuneContextSetRowHeightCommand;
    final extent = _axisMenuSizeInputToLogicalPixels(sheet, inputExtent);
    final hasChange = isRow
        ? Iterable<int>.generate(
            range.rowEnd - range.rowStart + 1,
            (offset) => range.rowStart + offset,
          ).any(
            (row) =>
                !_isIndexReadOnly(sheet.rowReadOnly, row) &&
                (sheet.rowHeights[row] != extent ||
                    sheet.customHeight[row] != 1),
          )
        : Iterable<int>.generate(
            range.columnEnd - range.columnStart + 1,
            (offset) => range.columnStart + offset,
          ).any(
            (column) =>
                !_isIndexReadOnly(sheet.colReadOnly, column) &&
                (sheet.columnWidths[column] != extent ||
                    sheet.customWidth[column] != 1),
          );
    if (hasChange) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChange) {
        if (isRow) {
          final rowHeights = Map<int, double>.from(sheet.rowHeights);
          final customHeight = Map<int, double>.from(sheet.customHeight);
          for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
            if (!_isIndexReadOnly(sheet.rowReadOnly, row)) {
              rowHeights[row] = extent;
              customHeight[row] = 1;
            }
          }
          _replaceActiveSheet(
            sheet.copyWith(rowHeights: rowHeights, customHeight: customHeight),
          );
        } else {
          final columnWidths = Map<int, double>.from(sheet.columnWidths);
          final customWidth = Map<int, double>.from(sheet.customWidth);
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          ) {
            if (!_isIndexReadOnly(sheet.colReadOnly, column)) {
              columnWidths[column] = extent;
              customWidth[column] = 1;
            }
          }
          _replaceActiveSheet(
            sheet.copyWith(
              columnWidths: columnWidths,
              customWidth: customWidth,
            ),
          );
        }
      }
      _closeTransientMenus();
    });
    _focusNode.requestFocus();
    return true;
  }

  bool _commitContextMenuLabelSize(String command, double inputExtent) {
    final sheet = _workbook.activeSheet;
    final physicalSize = fortuneSheetGridClientPhysicalSize(sheet);
    if (physicalSize == null) {
      setState(_closeTransientMenus);
      _focusNode.requestFocus();
      return true;
    }
    final extent = inputExtent.round();
    if (extent <= 0) {
      _focusContextMenuInlineInput(command);
      return false;
    }
    final nextWidth = command == fortuneContextSetLabelWidthCommand
        ? extent
        : physicalSize.widthMm;
    final nextHeight = command == fortuneContextSetLabelHeightCommand
        ? extent
        : physicalSize.heightMm;
    if (nextWidth == physicalSize.widthMm &&
        nextHeight == physicalSize.heightMm) {
      setState(_closeTransientMenus);
      _focusNode.requestFocus();
      return true;
    }
    _resizeControllerSheetGridClientArea(nextWidth, nextHeight, id: sheet.id);
    _focusNode.requestFocus();
    return true;
  }

  Offset _sheetTabMenuOrigin(Offset local) {
    final size = context.size;
    if (size == null) {
      return local;
    }
    final height = fortuneSheetTabMenuHeight(_sheetTabMenuItems);
    return Offset(
      local.dx,
      math.max(4, math.min(local.dy - height, size.height - height - 4)),
    );
  }

  int? _sheetListIndexAt(Offset local) {
    final at = sheetListAt;
    final size = context.size;
    if (at == null || size == null || _workbook.sheets.isEmpty) {
      return null;
    }
    final rect = fortuneSheetListRect(
      at,
      _workbook.sheets.length,
      viewportHeight: size.height,
    );
    if (!rect.contains(local)) {
      return null;
    }
    final index =
        ((local.dy -
                    rect.top -
                    fortuneSheetTabMenuContentTopPadding +
                    _sheetListScrollOffset) /
                fortuneSheetListRowHeight)
            .floor();
    return index < 0 || index >= _workbook.sheets.length ? null : index;
  }

  int? _sheetListHiddenButtonIndexAt(Offset local) {
    final at = sheetListAt;
    final size = context.size;
    if (at == null || size == null || _workbook.sheets.isEmpty) {
      return null;
    }
    final rect = fortuneSheetListRect(
      at,
      _workbook.sheets.length,
      viewportHeight: size.height,
    );
    if (!rect.contains(local)) {
      return null;
    }
    final scrolledAt = at.translate(0, -_sheetListScrollOffset);
    for (var index = 0; index < _workbook.sheets.length; index += 1) {
      if (_workbook.sheets[index].hide == 1 &&
          fortuneSheetListHiddenButtonRect(
            scrolledAt,
            index,
            _workbook.sheets.length,
          ).contains(local)) {
        return index;
      }
    }
    return null;
  }

  Offset _sheetListOrigin() {
    final size = context.size;
    if (size == null) {
      return Offset.zero;
    }
    final height = fortuneSheetListViewportHeight(
      _workbook.sheets.length,
      size.height,
    );
    return Offset(
      fortuneSheetListLeft,
      math.max(4, size.height - fortuneSheetListBottomOffset - height),
    );
  }

  double _sheetListMaxScrollOffset() {
    final size = context.size;
    if (size == null) {
      return 0;
    }
    return math.max(
      0.0,
      fortuneSheetListHeight(_workbook.sheets.length) -
          fortuneSheetListViewportHeight(_workbook.sheets.length, size.height),
    );
  }

  void _activateSheetListItem(int index) {
    if (index < 0 || index >= _workbook.sheets.length) {
      return;
    }
    final targetSheet = _workbook.sheets[index];
    final didChangeSheet = targetSheet.id != _workbook.activeSheet.id;
    if (didChangeSheet &&
        _workbook.settings.beforeActivateSheet?.call(targetSheet.id) == false) {
      return;
    }
    setState(() {
      if (didChangeSheet) {
        _rememberActiveSheetScrollOffset();
        _activateSheetAtIndex(index);
        _sheetTabScrollOffset = _sheetTabOffsetToReveal(index);
      }
      contextMenuAt = null;
      sheetTabMenuAt = null;
      sheetListAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      _sheetTabColorMenuOpen = false;
      toolbarPopupKey = null;
    });
    if (didChangeSheet) {
      _workbook.settings.afterActivateSheet?.call(targetSheet.id);
    }
  }

  int? _hiddenSheetListIndexAt(Offset local) {
    final at = hiddenSheetListAt;
    if (at == null) {
      return null;
    }
    final hidden = _hiddenSheetIndexes();
    if (hidden.isEmpty) {
      return null;
    }
    final rect = fortuneHiddenSheetListRect(at, hidden.length);
    if (!rect.contains(local)) {
      return null;
    }
    final index =
        ((local.dy - rect.top - fortuneSheetTabMenuContentTopPadding) /
                fortuneSheetListRowHeight)
            .floor();
    if (index < 0 || index >= hidden.length) {
      return null;
    }
    return hidden[index];
  }

  Offset _hiddenSheetListOrigin() {
    final at = sheetTabMenuAt ?? Offset.zero;
    final index = _sheetTabMenuItems.indexOf(fortuneSheetTabShowHiddenCommand);
    final proposed = Offset(
      at.dx + fortuneSheetTabMenuWidth,
      at.dy +
          fortuneSheetTabMenuContentTopPadding +
          math.max(0, index) * fortuneSheetTabMenuRowHeight,
    );
    final size = context.size;
    if (size == null) {
      return proposed;
    }
    final hiddenCount = _hiddenSheetIndexes().length;
    final height = fortuneHiddenSheetListHeight(hiddenCount);
    return Offset(
      math.min(proposed.dx, size.width - 180 - 4),
      math.min(proposed.dy, size.height - height - 4),
    );
  }

  void _activateSheetTabMenuCommand(String command) {
    final index = _sheetTabMenuSheetIndex;
    if (index == null || index < 0 || index >= _workbook.sheets.length) {
      return;
    }
    final mutatesSheet =
        command != fortuneSheetTabColorCommand &&
        command != fortuneSheetTabShowHiddenCommand;
    if (mutatesSheet && !_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    if (command == fortuneSheetTabColorCommand) {
      if (!_workbook.settings.allowEdit) {
        setState(_closeTransientMenus);
        return;
      }
      setState(() {
        contextMenuAt = null;
        hiddenSheetListAt = null;
        toolbarPopupKey = null;
        _sheetTabColorMenuOpen = true;
      });
      return;
    }
    if (command == fortuneSheetTabColorResetCommand) {
      _setSheetTabColor(index, null);
      return;
    }
    if (command == fortuneSheetTabColorCustomBlackCommand) {
      _setSheetTabColor(index, '#000000');
      return;
    }
    if (command.startsWith(fortuneSheetTabColorPaletteCommandPrefix)) {
      _setSheetTabColor(
        index,
        command.substring(fortuneSheetTabColorPaletteCommandPrefix.length),
      );
      return;
    }
    if (command == fortuneSheetTabRenameCommand) {
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        _sheetTabColorMenuOpen = false;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
      });
      _startRenamingSheet(index);
      return;
    }
    if (command == fortuneSheetTabShowHiddenCommand) {
      final hidden = _hiddenSheetIndexes();
      final origin = _hiddenSheetListOrigin();
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        _sheetTabColorMenuOpen = false;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        hiddenSheetListAt = hidden.isEmpty ? null : origin;
      });
      return;
    }
    if (command == fortuneSheetTabFocusCommand) {
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        _sheetTabColorMenuOpen = false;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
        _activateSheetAtIndex(index);
        _sheetTabScrollOffset = _sheetTabOffsetToReveal(index);
      });
      return;
    }
    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabColorMenuOpen = false;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      selection = const FortuneSelection(row: 0, column: 0);
      scrollOffset = Offset.zero;
      switch (command) {
        case fortuneSheetTabCopyCommand:
          _copySheet(index);
        case fortuneSheetTabMoveLeftCommand:
          _moveSheet(index, -1);
        case fortuneSheetTabMoveRightCommand:
          _moveSheet(index, 1);
        case fortuneSheetTabMoveCommand:
          _moveSheet(index, 1);
        case fortuneSheetTabDeleteCommand:
          _deleteSheet(index);
        case fortuneSheetTabHideCommand:
          _hideSheet(index);
      }
    });
  }

  void _setSheetTabColor(int index, String? color) {
    if (!_workbook.settings.allowEdit) {
      setState(() {
        contextMenuAt = null;
        sheetTabMenuAt = null;
        hiddenSheetListAt = null;
        _sheetTabColorMenuOpen = false;
        _sheetTabMenuSheetIndex = null;
        toolbarPopupKey = null;
      });
      return;
    }
    setState(() {
      _recordUndoSnapshot();
      final sheets = [..._workbook.sheets];
      sheets[index] = sheets[index].copyWith(
        color: color,
        rawColor: color,
        hasRawColor: color != null,
      );
      _workbook = _workbook.copyWith(sheets: sheets);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabColorMenuOpen = false;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  void _copySheet(int index) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final nextId = _nextSheetId();
    if (nextId == null) {
      return;
    }
    _recordUndoSnapshot();
    final source = _workbook.sheets[index];
    final sheets = [..._workbook.sheets];
    final copy = source.copyWith(
      id: nextId,
      name: _copySheetName(source.name),
      cells: Map<FortuneCellCoord, FortuneCell>.from(source.cells),
      hide: null,
      status: 0,
    );
    sheets.insert(index + 1, copy);
    _workbook = _workbook.copyWith(sheets: sheets, activeSheetIndex: index + 1);
    _sheetTabScrollOffset = _sheetTabOffsetToReveal(index + 1);
  }

  void _deleteSheet(int index) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    final visible = _visibleSheetIndexes();
    if (visible.length <= 1) {
      return;
    }
    final deletedSheet = _workbook.sheets[index];
    if (_workbook.settings.beforeDeleteSheet?.call(deletedSheet.id) == false) {
      return;
    }
    _recordUndoSnapshot();
    final sheets = [..._workbook.sheets]..removeAt(index);
    final activeIndex = math.min(index, sheets.length - 1);
    _workbook = _workbook.copyWith(
      sheets: sheets,
      activeSheetIndex: _nearestVisibleSheetIndex(sheets, activeIndex),
    );
    _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
      _sheetTabScrollOffset,
      sheets: sheets,
    );
    _workbook.settings.afterDeleteSheet?.call(deletedSheet.id);
  }

  void _moveSheet(int index, int direction) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    if (index < 0 || index >= _workbook.sheets.length) {
      return;
    }
    if ((direction < 0 && index == 0) ||
        (direction > 0 && index == _workbook.sheets.length - 1)) {
      return;
    }
    _recordUndoSnapshot();
    final delta = direction < 0 ? -1.5 : 1.5;
    final orderedIndexes = List<int>.generate(
      _workbook.sheets.length,
      (i) => i,
    );
    double orderFor(int sheetIndex) =>
        sheetIndex == index ? sheetIndex + delta : sheetIndex.toDouble();
    orderedIndexes.sort((a, b) {
      final byOrder = orderFor(a).compareTo(orderFor(b));
      return byOrder != 0 ? byOrder : a.compareTo(b);
    });
    final sheets = [
      for (final sheetIndex in orderedIndexes) _workbook.sheets[sheetIndex],
    ];
    final activeIndex = orderedIndexes.indexOf(index);
    _workbook = _workbook.copyWith(
      sheets: sheets,
      activeSheetIndex: activeIndex,
    );
    _sheetTabScrollOffset = _sheetTabOffsetToReveal(
      activeIndex,
      sheets: sheets,
    );
  }

  void _reorderSheetByDrag(int from, int insertBefore) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    if (from < 0 || from >= _workbook.sheets.length) {
      return;
    }
    var target = insertBefore.clamp(0, _workbook.sheets.length).toInt();
    if (target == from || target == from + 1) {
      return;
    }
    _recordUndoSnapshot();
    final sheets = [..._workbook.sheets];
    final sheet = sheets.removeAt(from);
    if (target > from) {
      target -= 1;
    }
    target = target.clamp(0, sheets.length).toInt();
    sheets.insert(target, sheet);
    _workbook = _workbook.copyWith(sheets: sheets, activeSheetIndex: target);
    _sheetTabScrollOffset = _sheetTabOffsetToReveal(target, sheets: sheets);
    selection = const FortuneSelection(row: 0, column: 0);
    scrollOffset = Offset.zero;
    contextMenuAt = null;
    sheetTabMenuAt = null;
    hiddenSheetListAt = null;
    _sheetTabMenuSheetIndex = null;
    _sheetTabColorMenuOpen = false;
    toolbarPopupKey = null;
    _hoveredCommentCoord = null;
  }

  void _hideSheet(int index) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    if (index < 0 || index >= _workbook.sheets.length) {
      return;
    }
    if (_workbook.sheets[index].hide == 1) {
      return;
    }
    final visible = _visibleSheetIndexes();
    if (visible.length <= 1) {
      return;
    }
    _recordUndoSnapshot();
    final sheets = [..._workbook.sheets];
    sheets[index] = sheets[index].copyWith(hide: 1, status: 0);
    _workbook = _workbook.copyWith(
      sheets: sheets,
      activeSheetIndex: _nearestVisibleSheetIndex(sheets, 0),
    );
    _sheetTabScrollOffset = _clampedSheetTabScrollOffset(
      _sheetTabScrollOffset,
      sheets: sheets,
    );
  }

  void _showHiddenSheet(int hiddenIndex) {
    if (!_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    if (hiddenIndex < 0 ||
        hiddenIndex >= _workbook.sheets.length ||
        _workbook.sheets[hiddenIndex].hide != 1) {
      return;
    }
    _recordUndoSnapshot();
    setState(() {
      final sheets = [..._workbook.sheets];
      sheets[hiddenIndex] = sheets[hiddenIndex].copyWith(hide: null, status: 0);
      _rememberActiveSheetScrollOffset();
      sheets[hiddenIndex] = sheets[hiddenIndex].copyWith(
        selectionRange: const [],
        hasRawSelectionRange: true,
      );
      _workbook = _workbook.copyWith(
        sheets: sheets,
        activeSheetIndex: hiddenIndex,
      );
      _sheetTabScrollOffset = _sheetTabOffsetToReveal(
        hiddenIndex,
        sheets: sheets,
      );
      selection = _selectionFromSheet(sheets[hiddenIndex]);
      scrollOffset = _scrollOffsetFromSheet(sheets[hiddenIndex]);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      sheetListAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
    });
  }

  void _showSheetFromSheetListHiddenButton(int index) {
    if (!_workbook.settings.allowEdit) {
      return;
    }
    if (index < 0 ||
        index >= _workbook.sheets.length ||
        _workbook.sheets[index].hide != 1) {
      return;
    }
    final nextWorkbook = showSheet(_workbook, _workbook.sheets[index].id);
    if (nextWorkbook.sheets[index].hide == 1) {
      return;
    }
    _recordUndoSnapshot();
    setState(() {
      _workbook = nextWorkbook;
    });
  }

  List<int> _visibleSheetIndexes() {
    final indexes = <int>[];
    for (var i = 0; i < _workbook.sheets.length; i += 1) {
      if (_workbook.sheets[i].hide != 1) {
        indexes.add(i);
      }
    }
    return indexes;
  }

  List<int> _hiddenSheetIndexes() {
    final indexes = <int>[];
    for (var i = 0; i < _workbook.sheets.length; i += 1) {
      if (_workbook.sheets[i].hide == 1) {
        indexes.add(i);
      }
    }
    return indexes;
  }

  int _nearestVisibleSheetIndex(List<FortuneSheet> sheets, int from) {
    for (var i = from; i < sheets.length; i += 1) {
      if (sheets[i].hide != 1) {
        return i;
      }
    }
    for (var i = math.min(from, sheets.length - 1); i >= 0; i -= 1) {
      if (sheets[i].hide != 1) {
        return i;
      }
    }
    return 0;
  }

  String? _nextSheetId({bool padDefaultId = false}) {
    final generateSheetId = _workbook.settings.generateSheetId;
    if (generateSheetId != null) {
      final nextId = generateSheetId();
      return nextId.isNotEmpty &&
              !_workbook.sheets.any((sheet) => sheet.id == nextId)
          ? nextId
          : null;
    }
    var index = _workbook.sheets.length + 1;
    String candidate() {
      final suffix = padDefaultId ? index.toString().padLeft(2, '0') : '$index';
      return 'sheet_$suffix';
    }

    while (_workbook.sheets.any((sheet) => sheet.id == candidate())) {
      index += 1;
    }
    return candidate();
  }

  String _copySheetName(String name) {
    final base = name.replaceFirst(RegExp(r'\(copy\d*\)$'), '');
    int? index;
    late String candidate;
    final names = _workbook.sheets.map((sheet) => sheet.name).toSet();
    do {
      final suffix = index == null ? '(copy)' : '(copy$index)';
      final lengthLimit = 31 - suffix.length;
      final truncatedBase = base.length > lengthLimit
          ? '${base.substring(0, math.max(0, lengthLimit - 1))}…'
          : base;
      candidate = '$truncatedBase$suffix';
      index = (index ?? 1) + 1;
    } while (names.contains(candidate));
    return candidate;
  }

  void _startRenamingSheet(int index) {
    if (!_workbook.settings.allowEdit) {
      setState(_closeTransientMenus);
      return;
    }
    if (index < 0 || index >= _workbook.sheets.length) {
      return;
    }
    setState(() {
      _renamingSheetIndex = index;
      _workbook = _workbook.copyWith(activeSheetIndex: index);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _sheetTabEditorController.value = TextEditingValue(
        text: _workbook.sheets[index].name,
        selection: TextSelection(
          baseOffset: 0,
          extentOffset: _workbook.sheets[index].name.length,
        ),
      );
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _renamingSheetIndex != null) {
        _sheetTabEditorFocusNode.requestFocus();
      }
    });
  }

  void _commitSheetRename() {
    final index = _renamingSheetIndex;
    if (index == null || index < 0 || index >= _workbook.sheets.length) {
      return;
    }
    final rename = _prepareSheetRename(index, _sheetTabEditorController.text);
    setState(() {
      if (rename != null) {
        _applyPreparedSheetRename(index, rename, activateSheet: true);
        final sheets = _workbook.sheets;
        _sheetTabScrollOffset = _sheetTabOffsetToReveal(index, sheets: sheets);
      }
      _renamingSheetIndex = null;
    });
    if (rename != null) {
      _notifyPreparedSheetRename(rename);
    }
    _focusNode.requestFocus();
  }

  ({String sheetId, String oldName, String nextName})? _prepareSheetRename(
    int index,
    String requestedName,
  ) {
    if (!_workbook.settings.allowEdit) {
      return null;
    }
    final nextName = requestedName.trim();
    if (!_isValidSheetName(nextName) ||
        _sheetNameExists(nextName, excludingIndex: index)) {
      return null;
    }
    final oldName = _workbook.sheets[index].name;
    if (nextName == oldName) {
      return null;
    }
    final sheetId = _workbook.sheets[index].id;
    if (_workbook.settings.beforeUpdateSheetName?.call(
          sheetId,
          oldName,
          nextName,
        ) ==
        false) {
      return null;
    }
    return (sheetId: sheetId, oldName: oldName, nextName: nextName);
  }

  void _applyPreparedSheetRename(
    int index,
    ({String sheetId, String oldName, String nextName}) rename, {
    bool activateSheet = false,
  }) {
    _recordUndoSnapshot();
    final sheets = [..._workbook.sheets];
    sheets[index] = sheets[index].copyWith(name: rename.nextName);
    _workbook = _workbook.copyWith(
      sheets: sheets,
      activeSheetIndex: activateSheet ? index : _workbook.activeSheetIndex,
    );
  }

  void _notifyPreparedSheetRename(
    ({String sheetId, String oldName, String nextName}) rename,
  ) {
    _workbook.settings.afterUpdateSheetName?.call(
      rename.sheetId,
      rename.oldName,
      rename.nextName,
    );
  }

  bool _isValidSheetName(String name) {
    if (name.isEmpty || name.length > 31) {
      return false;
    }
    if (name.startsWith("'") || name.endsWith("'")) {
      return false;
    }
    return !RegExp(r'[：:/？?*\[\]\\]').hasMatch(name);
  }

  bool _sheetNameExists(String name, {required int excludingIndex}) {
    for (var i = 0; i < _workbook.sheets.length; i += 1) {
      if (i != excludingIndex && _workbook.sheets[i].name == name) {
        return true;
      }
    }
    return false;
  }

  void _cancelSheetRename() {
    if (_renamingSheetIndex == null) {
      return;
    }
    setState(() {
      _renamingSheetIndex = null;
    });
    _focusNode.requestFocus();
  }

  bool _handleToolbarPopupKeyEvent(KeyEvent event) {
    if (toolbarPopupKey == null ||
        (event is! KeyDownEvent && event is! KeyRepeatEvent)) {
      return false;
    }
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.escape) {
      setState(_closeTransientMenus);
    }
    return true;
  }

  KeyEventResult _handleSheetKeyEvent(FocusNode node, KeyEvent event) {
    final shouldConsume = _shouldConsumeSheetKeyEvent(event);
    _handleKeyEvent(event);
    return shouldConsume ? KeyEventResult.handled : KeyEventResult.ignored;
  }

  bool _shouldConsumeSheetKeyEvent(KeyEvent event) {
    final isNavigationRepeat =
        event is KeyRepeatEvent && _isSelectionNavigationKey(event.logicalKey);
    if (event is! KeyDownEvent && !isNavigationRepeat) {
      return false;
    }
    if (_inlineMenuNumberEditorFocused ||
        _editingCoord != null ||
        _editingFormulaBar ||
        _filterDropdownSearchFocusNode.hasFocus ||
        _renamingSheetIndex != null ||
        !_sheetFocused) {
      return false;
    }
    final isShortcutPressed =
        HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed;
    return event.logicalKey == LogicalKeyboardKey.tab ||
        _isSelectionNavigationKey(event.logicalKey) ||
        (isShortcutPressed && _isSelectionNavigationKey(event.logicalKey));
  }

  void _handleKeyEvent(KeyEvent event) {
    final isNavigationRepeat =
        event is KeyRepeatEvent && _isSelectionNavigationKey(event.logicalKey);
    if (event is! KeyDownEvent && !isNavigationRepeat) {
      return;
    }
    if (_inlineMenuNumberEditorFocused) {
      return;
    }
    if (_imageInsertDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        _cancelImageInsertDialog();
      } else if (event.logicalKey == LogicalKeyboardKey.enter) {
        _commitImageInsertDialog();
      }
      return;
    }
    if (_barcodeDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        _cancelBarcodeDialog();
      } else if (event.logicalKey == LogicalKeyboardKey.enter) {
        unawaited(_commitBarcodeDialog());
      }
      return;
    }
    if (_handleToolbarPopupKeyEvent(event)) {
      return;
    }
    if (_editingCoord != null || _editingFormulaBar) {
      return;
    }
    if (_filterDropdownSearchFocusNode.hasFocus) {
      return;
    }
    if (_renamingSheetIndex != null) {
      return;
    }
    if (_axisSizeDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() {
          _axisSizeDialogAxis = null;
          _axisSizeDialogIndex = null;
        });
      }
      return;
    }
    if (_hyperlinkDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        if (_hyperlinkDialogSelectingCellRange) {
          _closeHyperlinkDialogRangeSelection();
        } else {
          setState(() {
            _hyperlinkDialogCoord = null;
            _hyperlinkDialogSelectingCellRange = false;
            _hyperlinkDialogRangeSelectionOriginAddress = null;
            _hyperlinkDialogRangeSelectionAnchor = null;
          });
        }
      } else if (event.logicalKey == LogicalKeyboardKey.enter) {
        if (_hyperlinkDialogSelectingCellRange) {
          _confirmHyperlinkDialogRangeSelection();
        } else {
          _commitHyperlinkDialog();
        }
      }
      return;
    }
    if (_dataVerificationDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() {
          _dataVerificationDialogCoord = null;
          _dataVerificationDialogRange = null;
          _dataVerificationDialogOriginalRule = null;
          _dataVerificationDialogOriginalOptionsText = '';
          _dataVerificationDialogType = 'dropdown';
          _dataVerificationDialogType2 = '';
          _dataVerificationRangeEditorController.clear();
        });
      }
      return;
    }
    if (_customSortDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() => _customSortDialogOpen = false);
      }
      return;
    }
    if (_conditionRuleDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() => _conditionRuleDialogOpen = false);
      } else if (event.logicalKey == LogicalKeyboardKey.enter) {
        _commitConditionRuleDialog();
      }
      return;
    }
    if (_formatSearchDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() => _formatSearchDialogOpen = false);
        _focusNode.requestFocus();
      } else if (event.logicalKey == LogicalKeyboardKey.enter) {
        _confirmFormatSearchDialog();
      }
      return;
    }
    if (_formulaSearchDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() {
          _formulaSearchDialogOpen = false;
          _formulaSearchCategoryMenuOpen = false;
        });
      }
      return;
    }
    if (_splitTextDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() => _splitTextDialogOpen = false);
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.enter) {
        _commitSplitTextDialog();
        return;
      }
      return;
    }
    if (_locationDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() => _locationDialogOpen = false);
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.enter) {
        _commitLocationDialog();
        return;
      }
      return;
    }
    if (_locationMessageDialogText != null) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        _activateLocationMessageDialogCommand('cancel');
      } else if (event.logicalKey == LogicalKeyboardKey.enter) {
        _activateLocationMessageDialogCommand(
          _locationMessageDialogConfirm ? 'confirm' : 'close',
        );
      }
      return;
    }
    if (_screenshotDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape ||
          event.logicalKey == LogicalKeyboardKey.enter) {
        setState(() {
          _screenshotDialogOpen = false;
          _screenshotRange = null;
        });
      }
      return;
    }
    if (_searchDialogOpen) {
      if (_handleDialogFocusTraversalKeyEvent(event)) {
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.escape) {
        setState(() => _searchDialogOpen = false);
        return;
      }
      if (event.logicalKey == LogicalKeyboardKey.enter) {
        _searchNextFromDialog();
        return;
      }
      return;
    }
    if (_activeDialogOpen) {
      return;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape &&
        _copiedCellRange != null) {
      setState(_clearCopiedSelectionState);
      return;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape &&
        contextMenuAt != null) {
      setState(_closeTransientMenus);
      return;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape &&
        _workbook.activeSheet.selectionRange is List &&
        (_workbook.activeSheet.selectionRange as List).isNotEmpty) {
      setState(_clearSelectionRangeMetadata);
      return;
    }
    final isShortcutPressed =
        HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed;
    if (isShortcutPressed &&
        HardwareKeyboard.instance.isShiftPressed &&
        event.logicalKey == LogicalKeyboardKey.keyF) {
      setState(() {
        _sheetFocused = !_sheetFocused;
      });
      return;
    }
    if (!_sheetFocused) {
      return;
    }
    if (isShortcutPressed && _insertCurrentDateTimeShortcut(event.logicalKey)) {
      return;
    }
    if (isShortcutPressed && _applyZoomShortcut(event.logicalKey)) {
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyB) {
      _toggleSelectedCellStyle(fortuneToolbarBoldCommand);
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyA) {
      _selectAllActiveSheet();
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyF) {
      _showSearchDialog();
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyH) {
      _showSearchDialog(replace: true);
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyD) {
      _fillSelectionFromEdge(down: true);
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyR) {
      _fillSelectionFromEdge(down: false);
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyC) {
      _copySelectionToClipboard();
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyX) {
      _copySelectionToClipboard(cut: true);
      return;
    }
    if (isShortcutPressed &&
        HardwareKeyboard.instance.isShiftPressed &&
        event.logicalKey == LogicalKeyboardKey.keyZ) {
      _redoWorkbookChange();
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyZ) {
      _undoWorkbookChange();
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyY) {
      _redoWorkbookChange();
      return;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyV) {
      if (_rawSelectionRanges(_workbook.activeSheet).length > 1) {
        setState(_closeTransientMenus);
        return;
      }
      unawaited(_pasteClipboardToSelection());
      return;
    }
    if (isShortcutPressed &&
        _moveSelectionWithArrow(event.logicalKey, jumpToEdge: true)) {
      return;
    }
    if (event.logicalKey == LogicalKeyboardKey.tab) {
      _moveSelectionWithTab();
      return;
    }
    final editingCharacter = _printableEditingCharacter(event);
    if (editingCharacter != null) {
      _startEditingWithText(
        FortuneCellCoord(selection.row, selection.column),
        editingCharacter,
      );
      return;
    }
    if ((event.logicalKey == LogicalKeyboardKey.delete ||
            event.logicalKey == LogicalKeyboardKey.backspace) &&
        _deleteActiveImage()) {
      return;
    }
    if ((event.logicalKey == LogicalKeyboardKey.delete ||
            event.logicalKey == LogicalKeyboardKey.backspace) &&
        _deleteSelectedSheetRulerGuide()) {
      return;
    }
    if (event.logicalKey == LogicalKeyboardKey.delete ||
        event.logicalKey == LogicalKeyboardKey.backspace) {
      _clearSelection();
      return;
    }
    if (_moveSelectionWithArrow(event.logicalKey)) {
      return;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter ||
        event.logicalKey == LogicalKeyboardKey.f2) {
      _startEditing(FortuneCellCoord(selection.row, selection.column));
    }
  }

  bool get _inlineMenuNumberEditorFocused {
    return _toolbarBorderStyleWidthFocusNodes.values.any(
          (node) => node.hasFocus,
        ) ||
        _contextMenuInlineInputFocusNodes.values.any((node) => node.hasFocus);
  }

  bool get _activeDialogOpen {
    return _locationMessageDialogText != null ||
        _screenshotDialogOpen ||
        _customSortDialogOpen ||
        _axisSizeDialogOpen ||
        _hyperlinkDialogOpen ||
        _dataVerificationDialogOpen ||
        _splitTextDialogOpen ||
        _locationDialogOpen ||
        _formatSearchDialogOpen ||
        _formulaSearchDialogOpen ||
        _conditionRuleDialogOpen ||
        _searchDialogOpen;
  }

  bool get _anySheetDialogOpen =>
      _activeDialogOpen || _imageInsertDialogOpen || _barcodeDialogOpen;

  void _notifyDialogVisibilityIfChanged() {
    final open = _anySheetDialogOpen;
    if (_lastDialogVisibilityNotified == null && !open) {
      _lastDialogVisibilityNotified = false;
      return;
    }
    if (_lastDialogVisibilityNotified == open) {
      return;
    }
    _lastDialogVisibilityNotified = open;
    final callback = _workbook.settings.onDialogVisibilityChanged;
    if (callback == null) {
      return;
    }
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted && open) {
        return;
      }
      unawaited(Future<void>.sync(() => callback(open)));
    });
  }

  void _notifyDialogVisibilityClosedOnDispose() {
    if (_lastDialogVisibilityNotified != true) {
      return;
    }
    final callback = _workbook.settings.onDialogVisibilityChanged;
    if (callback == null) {
      return;
    }
    unawaited(Future<void>.sync(() => callback(false)));
  }

  bool _isSelectionNavigationKey(LogicalKeyboardKey key) {
    return key == LogicalKeyboardKey.arrowUp ||
        key == LogicalKeyboardKey.arrowDown ||
        key == LogicalKeyboardKey.arrowLeft ||
        key == LogicalKeyboardKey.arrowRight ||
        key == LogicalKeyboardKey.tab;
  }

  String? _printableEditingCharacter(KeyEvent event) {
    if (HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed ||
        HardwareKeyboard.instance.isAltPressed) {
      return null;
    }
    final character = event.character;
    if (character == null || character.isEmpty) {
      return null;
    }
    if (character.length != 1) {
      return null;
    }
    final codeUnit = character.codeUnitAt(0);
    if (codeUnit < 0x20 && character != ' ') {
      return null;
    }
    return character;
  }

  bool _insertCurrentDateTimeShortcut(LogicalKeyboardKey key) {
    if (!HardwareKeyboard.instance.isShiftPressed) {
      return false;
    }
    if (key != LogicalKeyboardKey.semicolon &&
        key != LogicalKeyboardKey.quote) {
      return false;
    }
    _startEditingWithText(
      FortuneCellCoord(selection.row, selection.column),
      getNowDateTime(2),
    );
    return true;
  }

  void _selectAllActiveSheet() {
    final sheet = _workbook.activeSheet;
    final rowEnd = math.max(0, _effectiveRowCount(sheet) - 1);
    final columnEnd = math.max(0, _effectiveColumnCount(sheet) - 1);
    final selectedSheet = selectAll(sheet);
    final rawSelection = selectedSheet.selectionSave is List
        ? selectedSheet.selectionSave! as List
        : null;
    setState(() {
      selection = FortuneSelection(
        row: 0,
        column: 0,
        rowEnd: rowEnd,
        columnEnd: columnEnd,
      );
      final sheets = [..._workbook.sheets];
      sheets[_workbook.activeSheetIndex] = selectedSheet.copyWith(
        selectionRange: rawSelection == null
            ? null
            : [for (final item in rawSelection) cloneFortuneMetadata(item)],
        hasRawSelectionRange: rawSelection != null,
      );
      _workbook = _workbook.copyWith(sheets: sheets);
      _closeTransientMenus();
    });
  }

  void _fillSelectionFromEdge({required bool down}) {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (down && range.rowEnd <= range.rowStart) {
      setState(_closeTransientMenus);
      return;
    }
    if (!down && range.columnEnd <= range.columnStart) {
      setState(_closeTransientMenus);
      return;
    }
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final cells = <FortuneCellCoord, FortuneCell>{
      for (final entry in sheet.cells.entries) entry.key: entry.value,
    };
    var changed = false;
    if (down) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column++
      ) {
        final sourceCoord = FortuneCellCoord(range.rowStart, column);
        final sourceCell = sheet.cells[sourceCoord];
        if (sourceCell == null) {
          continue;
        }
        for (var row = range.rowStart + 1; row <= range.rowEnd; row++) {
          final target = FortuneCellCoord(row, column);
          if (!_canEditCell(sheet, target)) {
            continue;
          }
          final nextCell = _shortcutFilledCell(
            cells[target] ?? const FortuneCell(),
            sourceCell,
            mode: 'down',
            step: row - range.rowStart,
          );
          if (_cellWouldChange(sheet, target, nextCell)) {
            cells[target] = nextCell;
            changed = true;
          }
        }
      }
    } else {
      for (var row = range.rowStart; row <= range.rowEnd; row++) {
        final sourceCoord = FortuneCellCoord(row, range.columnStart);
        final sourceCell = sheet.cells[sourceCoord];
        if (sourceCell == null) {
          continue;
        }
        for (
          var column = range.columnStart + 1;
          column <= range.columnEnd;
          column++
        ) {
          final target = FortuneCellCoord(row, column);
          if (!_canEditCell(sheet, target)) {
            continue;
          }
          final nextCell = _shortcutFilledCell(
            cells[target] ?? const FortuneCell(),
            sourceCell,
            mode: 'right',
            step: column - range.columnStart,
          );
          if (_cellWouldChange(sheet, target, nextCell)) {
            cells[target] = nextCell;
            changed = true;
          }
        }
      }
    }
    if (!changed) {
      setState(_closeTransientMenus);
      return;
    }
    _recordUndoSnapshot();
    setState(() {
      final sheets = [..._workbook.sheets];
      final nextSheet = sheet.copyWith(cells: cells);
      sheets[_workbook.activeSheetIndex] = nextSheet;
      _workbook = _workbook.copyWith(sheets: sheets);
      _recalculateWorkbookFormulas();
      _closeTransientMenus();
    });
  }

  FortuneCell _shortcutFilledCell(
    FortuneCell target,
    FortuneCell source, {
    required String mode,
    required int step,
  }) {
    final formula = source.formula;
    if (formula != null && formula.isNotEmpty) {
      final adjusted = functionCopy(formula, mode, step);
      return target.withFormulaBarInput(
        adjusted.startsWith('=') ? adjusted : '=$adjusted',
      );
    }
    final rawValue = source.hasRawValue ? source.rawValue : source.value;
    final value = rawValue?.toString();
    return target.copyWith(
      value: value,
      rawValue: value,
      hasRawValue: source.hasRawValue || value != null,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      displayValue: null,
      rawDisplayValue: null,
      hasRawDisplayValue: false,
    );
  }

  bool _applyZoomShortcut(LogicalKeyboardKey key) {
    final isZoomOut =
        key == LogicalKeyboardKey.minus ||
        key == LogicalKeyboardKey.numpadSubtract;
    final isZoomIn =
        key == LogicalKeyboardKey.equal ||
        key == LogicalKeyboardKey.add ||
        key == LogicalKeyboardKey.numpadAdd;
    final isZoomReset =
        key == LogicalKeyboardKey.digit0 || key == LogicalKeyboardKey.numpad0;
    if (!isZoomOut && !isZoomIn && !isZoomReset) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final nextZoom = isZoomReset
        ? 1.0
        : (sheet.zoomRatio + (isZoomIn ? 0.1 : -0.1)).clamp(0.1, 4.0);
    final roundedZoom = (nextZoom * 10).roundToDouble() / 10;
    if (roundedZoom == sheet.zoomRatio) {
      return true;
    }
    setState(() {
      final sheets = [..._workbook.sheets];
      sheets[_workbook.activeSheetIndex] = sheet.copyWith(
        zoomRatio: roundedZoom,
      );
      _workbook = _workbook.copyWith(sheets: sheets);
    });
    return true;
  }

  String? _zoomCommandAt(Offset local) {
    final settings = _workbook.settings;
    if (!settings.showSheetTabs) {
      return null;
    }
    final size = context.size;
    if (size == null) {
      return null;
    }
    if (_zoomMenuOpen) {
      final menu = fortuneZoomPresetMenuRect(size, settings);
      if (menu.contains(local)) {
        final index = ((local.dy - menu.top) / fortuneZoomPresetRowHeight)
            .floor();
        if (index >= 0 && index < fortuneZoomPresetValues.length) {
          return 'preset:$index';
        }
      }
    }
    if (fortuneZoomOutButtonRect(size, settings).contains(local)) {
      return 'out';
    }
    if (fortuneZoomRatioButtonRect(size, settings).contains(local)) {
      return 'menu';
    }
    if (fortuneZoomInButtonRect(size, settings).contains(local)) {
      return 'in';
    }
    return null;
  }

  void _activateZoomCommand(String command) {
    final sheet = _workbook.activeSheet;
    final currentZoom = sheet.zoomRatio <= 0 ? 1.0 : sheet.zoomRatio;
    double? nextZoom;
    if (command == 'menu') {
      setState(() {
        _closeTransientMenus();
        _zoomMenuOpen = true;
      });
      return;
    }
    if (command == 'out') {
      nextZoom = currentZoom - 0.1;
    } else if (command == 'in') {
      nextZoom = currentZoom + 0.1;
    } else if (command.startsWith('preset:')) {
      final index = int.tryParse(command.substring('preset:'.length));
      if (index != null &&
          index >= 0 &&
          index < fortuneZoomPresetValues.length) {
        nextZoom = fortuneZoomPresetValues[index];
      }
    }
    if (nextZoom == null) {
      return;
    }
    final roundedZoom =
        (nextZoom.clamp(0.1, 4.0).toDouble() * 10).roundToDouble() / 10;
    setState(() {
      if (roundedZoom != currentZoom) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          zoomRatio: roundedZoom,
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _closeTransientMenus();
    });
  }

  void _clearCopiedSelectionState() {
    _copiedCellCoord = null;
    _copiedCellRange = null;
    _copiedCells = null;
    _copiedBorders = null;
    _copiedDataVerification = null;
    _copiedRawDataVerification = null;
    _copiedRawHyperlinks = null;
    _copiedFilter = null;
    _copiedRawFilter = null;
    _copiedHasRawFilter = false;
    _copiedFilterSelect = null;
    _copiedImages = null;
    _copiedClipboardText = null;
    _copiedCellsAreCut = false;
    _closeTransientMenus();
  }

  bool _moveSelectionWithArrow(
    LogicalKeyboardKey key, {
    bool jumpToEdge = false,
  }) {
    final (rowDelta, columnDelta) = switch (key) {
      LogicalKeyboardKey.arrowUp => (-1, 0),
      LogicalKeyboardKey.arrowDown => (1, 0),
      LogicalKeyboardKey.arrowLeft => (0, -1),
      LogicalKeyboardKey.arrowRight => (0, 1),
      _ => (0, 0),
    };
    if (rowDelta == 0 && columnDelta == 0) {
      return false;
    }
    final sheet = _workbook.activeSheet;
    final maxRow = _effectiveRowCount(sheet) - 1;
    final maxColumn = _effectiveColumnCount(sheet) - 1;
    final isShiftPressed = HardwareKeyboard.instance.isShiftPressed;
    final currentRange = _currentSelectionRange(sheet);
    final focusedRange = _cellSelectionRange(
      FortuneCellCoord(selection.row, selection.column),
    );
    final moveFromMergedRange =
        !isShiftPressed &&
        !jumpToEdge &&
        (focusedRange.rowStart != focusedRange.rowEnd ||
            focusedRange.columnStart != focusedRange.columnEnd) &&
        _sameRange(currentRange, focusedRange);
    final baseRow = moveFromMergedRange
        ? rowDelta > 0
              ? focusedRange.rowEnd
              : focusedRange.rowStart
        : isShiftPressed
        ? selection.rowEnd
        : selection.row;
    final baseColumn = moveFromMergedRange
        ? columnDelta > 0
              ? focusedRange.columnEnd
              : focusedRange.columnStart
        : isShiftPressed
        ? selection.columnEnd
        : selection.column;
    final nextRow = baseRow.clamp(0, maxRow);
    final nextColumn = baseColumn.clamp(0, maxColumn);
    final (movedRow, movedColumn) = jumpToEdge
        ? _selectionEdgeCoord(
            sheet,
            currentRow: nextRow,
            currentColumn: nextColumn,
            rowDelta: rowDelta,
            columnDelta: columnDelta,
            maxRow: maxRow,
            maxColumn: maxColumn,
          )
        : (
            rowDelta == 0
                ? nextRow
                : _moveIndexSkippingHidden(
                    sheet.hiddenRows,
                    current: nextRow,
                    delta: rowDelta,
                    maxIndex: maxRow,
                  ),
            columnDelta == 0
                ? nextColumn
                : _moveIndexSkippingHidden(
                    sheet.hiddenColumns,
                    current: nextColumn,
                    delta: columnDelta,
                    maxIndex: maxColumn,
                  ),
          );
    setState(() {
      if (isShiftPressed) {
        selection = FortuneSelection(
          row: selection.row,
          column: selection.column,
          rowEnd: movedRow,
          columnEnd: movedColumn,
        );
        _writeSelectionRange(
          _currentSelectionRange(sheet),
          FortuneCellCoord(selection.row, selection.column),
        );
      } else {
        final movedFocus = sheet.mergeAnchorFor(
          FortuneCellCoord(movedRow, movedColumn),
        );
        final movedRange = _cellSelectionRange(movedFocus);
        selection = FortuneSelection(
          row: movedRange.rowStart,
          column: movedRange.columnStart,
          rowEnd: movedRange.rowEnd,
          columnEnd: movedRange.columnEnd,
        );
        _writeSelectionRange(movedRange, movedFocus);
      }
      _ensureSelectionTargetVisible(sheet, row: movedRow, column: movedColumn);
      _closeTransientMenus();
    });
    return true;
  }

  void _ensureSelectionTargetVisible(
    FortuneSheet sheet, {
    required int row,
    required int column,
  }) {
    final size = _lastCanvasSize ?? context.size;
    if (size == null) {
      return;
    }
    final settings = _workbook.settings;
    final metrics = sheet.metrics(settings);
    final viewport = _sheetDataViewportSize(size, settings, sheet);
    if (viewport == null || viewport.width <= 0 || viewport.height <= 0) {
      return;
    }
    final nextScroll = scrollToHighlightCell(
      sheet,
      row,
      column,
      scrollLeft: scrollOffset.dx,
      scrollTop: scrollOffset.dy,
      viewportWidth: viewport.width,
      viewportHeight: viewport.height,
      visibleDataRows: metrics.visibleDataRows,
      visibleDataColumns: metrics.visibleDataColumns,
    );
    scrollOffset = _clampScrollOffsetToVisibleSheet(
      Offset(
        nextScroll['scrollLeft']?.toDouble() ?? scrollOffset.dx,
        nextScroll['scrollTop']?.toDouble() ?? scrollOffset.dy,
      ),
      sheet,
      settings: settings,
    );
  }

  int _moveIndexSkippingHidden(
    Set<int> hiddenIndexes, {
    required int current,
    required int delta,
    required int maxIndex,
  }) {
    var candidate = (current + delta).clamp(0, maxIndex);
    while (hiddenIndexes.contains(candidate)) {
      final next = candidate + delta;
      if (next < 0 || next > maxIndex) {
        return current;
      }
      candidate = next;
    }
    return candidate;
  }

  void _moveSelectionWithTab() {
    final sheet = _workbook.activeSheet;
    final maxColumn = _effectiveColumnCount(sheet) - 1;
    final range = _currentSelectionRange(sheet);
    final isShiftPressed = HardwareKeyboard.instance.isShiftPressed;
    final nextColumn =
        ((isShiftPressed ? range.columnStart : range.columnEnd) +
                (isShiftPressed ? -1 : 1))
            .clamp(0, maxColumn);
    final target = sheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, nextColumn),
    );
    final targetRange = _cellSelectionRange(target);
    setState(() {
      selection = FortuneSelection(
        row: targetRange.rowStart,
        column: targetRange.columnStart,
        rowEnd: targetRange.rowEnd,
        columnEnd: targetRange.columnEnd,
      );
      _writeSelectionRange(targetRange, target);
      _ensureSelectionTargetVisible(
        sheet,
        row: targetRange.rowStart,
        column: targetRange.columnStart,
      );
      _closeTransientMenus();
    });
  }

  (int, int) _selectionEdgeCoord(
    FortuneSheet sheet, {
    required int currentRow,
    required int currentColumn,
    required int rowDelta,
    required int columnDelta,
    required int maxRow,
    required int maxColumn,
  }) {
    final startRow = math.min(selection.row, selection.rowEnd);
    final endRow = math.max(selection.row, selection.rowEnd);
    final startColumn = math.min(selection.column, selection.columnEnd);
    final endColumn = math.max(selection.column, selection.columnEnd);
    var row = currentRow;
    var column = currentColumn;
    if (rowDelta < 0) {
      row = startRow - 1;
    } else if (rowDelta > 0) {
      row = endRow + 1;
    } else if (columnDelta < 0) {
      column = startColumn - 1;
    } else if (columnDelta > 0) {
      column = endColumn + 1;
    }
    final axisMax = columnDelta == 0 ? maxRow : maxColumn;
    while (row >= 0 &&
        column >= 0 &&
        (columnDelta == 0 ? row : column) < axisMax) {
      final filled = _cellHasMoveValue(sheet, row, column);
      final previousFilled = _cellHasMoveValue(
        sheet,
        row - rowDelta,
        column - columnDelta,
      );
      final nextFilled = _cellHasMoveValue(
        sheet,
        row + rowDelta,
        column + columnDelta,
      );
      if (filled && (!previousFilled || !nextFilled)) {
        break;
      }
      row += rowDelta;
      column += columnDelta;
    }
    return (row.clamp(0, maxRow), column.clamp(0, maxColumn));
  }

  bool _cellHasMoveValue(FortuneSheet sheet, int row, int column) {
    if (row < 0 || column < 0) {
      return false;
    }
    final cell = sheet.cells[FortuneCellCoord(row, column)];
    return cell != null && !cell.isVisuallyEmpty;
  }

  void _copySelectionToClipboard({bool cut = false}) {
    final sheet = _workbook.activeSheet;
    final selectedRanges = _rawSelectionRanges(sheet);
    final range = _currentSelectionRange(sheet);
    final copyRanges = selectedRanges.isEmpty
        ? <FortuneRange>[range]
        : selectedRanges;
    final hasPartialMerge = copyRanges.any(
      (range) => hasPartMC(
        sheet,
        range.rowStart,
        range.rowEnd,
        range.columnStart,
        range.columnEnd,
      ),
    );
    final copyGuard = handleCopy(
      selections: copyRanges,
      paintModelOn: _formatPainterSourceRange != null,
      hasPartialMerge: hasPartialMerge,
      hasConditionFormatOverlap: _copyRangesHaveConditionFormatOverlap(
        sheet,
        copyRanges,
      ),
      hasOverlap: selectIsOverlap(sheet, copyRanges),
    );
    if (copyGuard == null ||
        copyGuard['type'] == 'copyBlocked' ||
        cut && copyRanges.length > 1) {
      setState(() {
        _cancelFormatPainterDrag(clearPainter: true);
        _closeTransientMenus();
      });
      return;
    }
    if (cut && !_canEditRange(sheet, range)) {
      setState(() {
        _cancelFormatPainterDrag(clearPainter: true);
        _closeTransientMenus();
      });
      return;
    }
    final singleCoord = selection.isSingleCell
        ? sheet.mergeAnchorFor(
            FortuneCellCoord(selection.row, selection.column),
          )
        : null;
    final text = _selectionClipboardTextForRanges(sheet, copyRanges);
    final copiedCells = <FortuneCellCoord, FortuneCell>{};
    final computedBorders = FortuneBorderCompute.compute(sheet);
    final copiedBorders = <FortuneCellCoord, FortuneCellBorders>{};
    final copiedDataVerification = <FortuneCellCoord, Object?>{};
    final copiedRawDataVerification = <FortuneCellCoord, Object?>{};
    final copiedRawHyperlinks = <FortuneCellCoord, Object?>{};
    final rawDataVerification = sheet.rawDataVerification;
    final rawHyperlinks = sheet.rawHyperlinks;
    final filterSelectRange = _filterSelectRange(sheet);
    final copiesFilterMetadata =
        filterSelectRange != null &&
        _rangeContainsRange(range, filterSelectRange);
    final copiedFilter = copiesFilterMetadata
        ? Map<String, Object?>.from(cloneFortuneMetadata(sheet.filter) as Map)
        : null;
    final copiedRawFilter = copiesFilterMetadata && sheet.hasRawFilter
        ? cloneFortuneMetadata(sheet.rawFilter)
        : null;
    final copiedFilterSelect = copiesFilterMetadata
        ? cloneFortuneMetadata(sheet.filterSelect)
        : null;
    final metrics = sheet.metrics(_workbook.settings);
    final copiedImages = <FortuneImage>[
      for (final image in sheet.images)
        if (_rangeContainsCoord(range, _imageAnchorCoord(image, metrics)) &&
            !sheet.hiddenRows.contains(_imageAnchorCoord(image, metrics).row) &&
            !sheet.hiddenColumns.contains(
              _imageAnchorCoord(image, metrics).column,
            ))
          image,
    ];
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      if (sheet.hiddenRows.contains(row)) {
        continue;
      }
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (sheet.hiddenColumns.contains(column)) {
          continue;
        }
        final coord = FortuneCellCoord(row, column);
        final cell = sheet.cells[coord];
        if (cell != null) {
          copiedCells[coord] = cell;
        }
        final borders = computedBorders[coord];
        if (borders != null && _cellBordersHaveAnySide(borders)) {
          copiedBorders[coord] = borders;
        }
        final dataVerification = sheet.dataVerification[_cellKey(coord)];
        if (dataVerification != null) {
          copiedDataVerification[coord] = cloneFortuneMetadata(
            dataVerification,
          );
        }
        final key = _cellKey(coord);
        if (rawDataVerification is Map &&
            rawDataVerification.containsKey(key)) {
          copiedRawDataVerification[coord] = cloneFortuneMetadata(
            rawDataVerification[key],
          );
        }
        if (rawHyperlinks is Map && rawHyperlinks.containsKey(key)) {
          copiedRawHyperlinks[coord] = cloneFortuneMetadata(rawHyperlinks[key]);
        }
      }
    }
    Clipboard.setData(ClipboardData(text: text));
    setState(() {
      _cancelFormatPainterDrag(clearPainter: true);
      _copiedCellCoord = copyRanges.length == 1 ? singleCoord : null;
      _copiedClipboardText = text;
      _copiedCellRange = copyRanges.length == 1 ? range : null;
      _copiedCells = copyRanges.length == 1 ? copiedCells : null;
      _copiedBorders = copyRanges.length == 1 ? copiedBorders : null;
      _copiedDataVerification = copyRanges.length == 1
          ? copiedDataVerification
          : null;
      _copiedRawDataVerification = copyRanges.length == 1
          ? copiedRawDataVerification
          : null;
      _copiedRawHyperlinks = copyRanges.length == 1
          ? copiedRawHyperlinks
          : null;
      _copiedFilter = copyRanges.length == 1 ? copiedFilter : null;
      _copiedRawFilter = copyRanges.length == 1 ? copiedRawFilter : null;
      _copiedHasRawFilter =
          copyRanges.length == 1 && copiesFilterMetadata && sheet.hasRawFilter;
      _copiedFilterSelect = copyRanges.length == 1 ? copiedFilterSelect : null;
      _copiedImages = copyRanges.length == 1 ? copiedImages : null;
      _copiedCellsAreCut = cut;
      _writeCopySelectionRangeMetadata(copyRanges);
      _closeTransientMenus();
    });
  }

  bool _copyRangesHaveConditionFormatOverlap(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
  ) {
    if (ranges.length <= 1 || sheet.conditionFormats == null) {
      return false;
    }
    final computeMap = getComputeMap(sheet);
    if (computeMap == null || computeMap.isEmpty) {
      return false;
    }
    for (final range in ranges) {
      final rowStart = math.min(range.rowStart, range.rowEnd);
      final rowEnd = math.max(range.rowStart, range.rowEnd);
      final columnStart = math.min(range.columnStart, range.columnEnd);
      final columnEnd = math.max(range.columnStart, range.columnEnd);
      for (var row = rowStart; row <= rowEnd; row += 1) {
        for (var column = columnStart; column <= columnEnd; column += 1) {
          if (checkCF(row, column, computeMap) != null) {
            return true;
          }
        }
      }
    }
    return false;
  }

  String _selectionClipboardText(FortuneSheet sheet, FortuneRange range) {
    return _selectionClipboardTextForRowsAndColumns(
      sheet,
      [for (var row = range.rowStart; row <= range.rowEnd; row += 1) row],
      [
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        )
          column,
      ],
    );
  }

  String _selectionClipboardTextForRanges(
    FortuneSheet sheet,
    List<FortuneRange> ranges,
  ) {
    if (ranges.length == 1) {
      return _selectionClipboardText(sheet, ranges.single);
    }
    final rows = <int>[];
    final columns = <int>[];
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        if (!rows.contains(row)) {
          rows.add(row);
        }
      }
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if (!columns.contains(column)) {
          columns.add(column);
        }
      }
    }
    return _selectionClipboardTextForRowsAndColumns(sheet, rows, columns);
  }

  String _selectionClipboardTextForRowsAndColumns(
    FortuneSheet sheet,
    List<int> sourceRows,
    List<int> sourceColumns,
  ) {
    final rows = <String>[];
    for (final row in sourceRows) {
      if (sheet.hiddenRows.contains(row)) {
        continue;
      }
      final columns = <String>[];
      for (final column in sourceColumns) {
        if (sheet.hiddenColumns.contains(column)) {
          continue;
        }
        final coord = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
        final cell = sheet.cells[coord];
        columns.add(cell?.formula ?? cell?.renderedText ?? '');
      }
      rows.add(columns.join('\t'));
    }
    return rows.join('\n');
  }

  Future<void> _pasteClipboardToSelection() async {
    final activeSheet = _workbook.activeSheet;
    final selectedRanges = _rawSelectionRanges(activeSheet);
    if (selectedRanges.isEmpty) {
      selectedRanges.add(_currentSelectionRange(activeSheet));
    }
    if (selectedRanges.length > 1 ||
        !_canEditRange(activeSheet, selectedRanges.single)) {
      setState(() {
        _closeTransientMenus();
      });
      return;
    }
    final data = await Clipboard.getData(Clipboard.kTextPlain);
    if (!mounted) {
      return;
    }
    final text = data?.text;
    if (text == null) {
      setState(() {
        _closeTransientMenus();
      });
      return;
    }
    _pasteTextAtSelection(text);
  }

  String _normalizedClipboardLineEndings(String text) {
    return text.replaceAll('\r\n', '\n').replaceAll('\r', '\n');
  }

  bool _clipboardTextMatchesInternalCopy(String text) {
    final copiedText = _copiedClipboardText;
    return copiedText != null &&
        _normalizedClipboardLineEndings(copiedText) ==
            _normalizedClipboardLineEndings(text);
  }

  void _pasteTextAtSelection(String text) {
    final activeSheet = _workbook.activeSheet;
    final selectedRanges = _rawSelectionRanges(activeSheet);
    if (selectedRanges.isEmpty) {
      selectedRanges.add(_currentSelectionRange(activeSheet));
    }
    if (selectedRanges.length > 1) {
      setState(() {
        _closeTransientMenus();
      });
      return;
    }
    if (!_canEditRange(activeSheet, selectedRanges.single)) {
      setState(() {
        _closeTransientMenus();
      });
      return;
    }
    if (_workbook.settings.beforePaste?.call(selectedRanges, text) == false) {
      setState(() {
        _closeTransientMenus();
      });
      return;
    }
    final copiedRange = _copiedCellRange;
    final copiedCells = _copiedCells;
    final copiedBorders = _copiedBorders;
    final copiedDataVerification = _copiedDataVerification;
    final copiedRawDataVerification = _copiedRawDataVerification;
    final copiedRawHyperlinks = _copiedRawHyperlinks;
    final copiedFilter = _copiedFilter;
    final copiedRawFilter = _copiedRawFilter;
    final copiedHasRawFilter = _copiedHasRawFilter;
    final copiedFilterSelect = _copiedFilterSelect;
    final copiedImages = _copiedImages;
    final textMatchesInternalCopy =
        copiedRange != null &&
        copiedCells != null &&
        _clipboardTextMatchesInternalCopy(text);
    final rows = _normalizedClipboardLineEndings(text).split('\n');
    if (!textMatchesInternalCopy && rows.isNotEmpty && rows.last.isEmpty) {
      rows.removeLast();
    }
    if (!textMatchesInternalCopy && rows.isNotEmpty) {
      final firstColumnCount = rows.first.split('\t').length;
      rows.removeWhere((row) => row.split('\t').length < firstColumnCount);
    }
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    final rangeRowCount = range.rowEnd - range.rowStart + 1;
    final rangeColumnCount = range.columnEnd - range.columnStart + 1;
    final pastedRowCount = rows.length;
    final pastedColumnCount = rows.fold<int>(0, (max, row) {
      final columnCount = row.split('\t').length;
      return columnCount > max ? columnCount : max;
    });
    final copiedVisibleRows = copiedRange == null
        ? const <int>[]
        : [
            for (
              var row = copiedRange.rowStart;
              row <= copiedRange.rowEnd;
              row += 1
            )
              if (!sheet.hiddenRows.contains(row)) row,
          ];
    final copiedVisibleColumns = copiedRange == null
        ? const <int>[]
        : [
            for (
              var column = copiedRange.columnStart;
              column <= copiedRange.columnEnd;
              column += 1
            )
              if (!sheet.hiddenColumns.contains(column)) column,
          ];
    final isExternalPlainFormulaPaste =
        !textMatchesInternalCopy &&
        pastedRowCount == 1 &&
        pastedColumnCount == 1 &&
        rows.first.startsWith('=');
    final usesInternalCopy =
        textMatchesInternalCopy &&
        copiedVisibleRows.isNotEmpty &&
        copiedVisibleColumns.isNotEmpty;
    final sourceRowCount = usesInternalCopy
        ? copiedVisibleRows.length
        : pastedRowCount;
    final sourceColumnCount = usesInternalCopy
        ? copiedVisibleColumns.length
        : pastedColumnCount;
    final selectionIsPastedMultiple =
        sourceRowCount > 0 &&
        sourceColumnCount > 0 &&
        rangeRowCount % sourceRowCount == 0 &&
        rangeColumnCount % sourceColumnCount == 0;
    final repeatsIntoSelection =
        (rangeRowCount > sourceRowCount ||
            rangeColumnCount > sourceColumnCount) &&
        sourceRowCount > 0 &&
        sourceColumnCount > 0 &&
        !isExternalPlainFormulaPaste &&
        !_copiedCellsAreCut &&
        (!usesInternalCopy || selectionIsPastedMultiple);
    final targetRowCount = repeatsIntoSelection
        ? rangeRowCount
        : sourceRowCount;
    final targetGridColumnCount = repeatsIntoSelection
        ? rangeColumnCount
        : sourceColumnCount;
    final updates = <FortuneCellCoord, FortuneCell?>{};
    final borderUpdates = <FortuneBorderInfo>[];
    final rawBorderInfoUpdates = <Object?>[];
    final dataVerificationUpdates = <FortuneCellCoord, Object?>{};
    final rawDataVerificationUpdates = <FortuneCellCoord, Object?>{};
    final rawHyperlinkUpdates = <FortuneCellCoord, Object?>{};
    final targetCoords = <FortuneCellCoord>{};
    final pastedSourceCoords = <FortuneCellCoord>{};
    var imageUpdates = const <FortuneImage>[];
    var pasteBlocked = false;
    String? pasteBlockedMessage;
    for (var r = 0; r < targetRowCount; r += 1) {
      final targetRow = range.rowStart + r;
      if (sheet.hiddenRows.contains(targetRow)) {
        continue;
      }
      final sourceColumns = usesInternalCopy
          ? const <String>[]
          : rows[r % pastedRowCount].split('\t');
      final targetColumnCount = repeatsIntoSelection
          ? rangeColumnCount
          : usesInternalCopy
          ? copiedVisibleColumns.length
          : sourceColumns.length;
      for (var c = 0; c < targetColumnCount; c += 1) {
        final targetColumn = range.columnStart + c;
        if (sheet.hiddenColumns.contains(targetColumn)) {
          continue;
        }
        if (sourceColumns.isEmpty &&
            !repeatsIntoSelection &&
            !usesInternalCopy) {
          continue;
        }
        final sourceText = sourceColumns.isEmpty
            ? ''
            : sourceColumns[c % sourceColumns.length];
        final coord = sheet.mergeAnchorFor(
          FortuneCellCoord(targetRow, targetColumn),
        );
        final sourceCoord = usesInternalCopy
            ? FortuneCellCoord(
                copiedVisibleRows[r % copiedVisibleRows.length],
                copiedVisibleColumns[c % copiedVisibleColumns.length],
              )
            : null;
        final sourceCell = sourceCoord == null
            ? null
            : copiedCells![sourceCoord];
        final sourceBorders = sourceCoord == null
            ? null
            : copiedBorders?[sourceCoord];
        final sourceFormula = _cellFormulaText(sourceCell);
        final translatedFormula = sourceFormula == null
            ? null
            : FortuneFormulaEngine.translateReferences(
                sourceFormula,
                rowDelta: coord.row - sourceCoord!.row,
                columnDelta: coord.column - sourceCoord.column,
              );
        final text = usesInternalCopy
            ? (translatedFormula ?? sourceCell?.renderedText ?? sourceText)
            : (translatedFormula ?? _translatedPasteText(sourceText, coord));
        final dataVerificationFailure = _dataVerificationInputFailureText(
          sheet,
          coord,
          text,
        );
        if (!_canEditCell(sheet, coord) || dataVerificationFailure != null) {
          pasteBlocked = true;
          pasteBlockedMessage ??= dataVerificationFailure;
          continue;
        }
        if (sourceBorders != null && _cellBordersHaveAnySide(sourceBorders)) {
          if (sheet.hasRawBorderInfo && sheet.rawBorderInfo is List) {
            rawBorderInfoUpdates.addAll(
              _rawBorderInfoForTarget(coord, sourceBorders),
            );
          } else {
            borderUpdates.addAll(
              _formatPainterBorderInfosForTarget(coord, sourceBorders),
            );
          }
        }
        if (sourceCoord != null &&
            copiedDataVerification?.containsKey(sourceCoord) == true) {
          dataVerificationUpdates[coord] = cloneFortuneMetadata(
            copiedDataVerification![sourceCoord],
          );
        }
        if (sourceCoord != null &&
            copiedRawDataVerification?.containsKey(sourceCoord) == true) {
          rawDataVerificationUpdates[coord] = cloneFortuneMetadata(
            copiedRawDataVerification![sourceCoord],
          );
        }
        if (sourceCoord != null &&
            copiedRawHyperlinks?.containsKey(sourceCoord) == true) {
          rawHyperlinkUpdates[coord] = cloneFortuneMetadata(
            copiedRawHyperlinks![sourceCoord],
          );
        }
        targetCoords.add(coord);
        if (sourceCoord != null) {
          pastedSourceCoords.add(sourceCoord);
        }
        final previous = updates.containsKey(coord)
            ? updates[coord]
            : sheet.cells[coord];
        final baseCell = previous ?? const FortuneCell();
        updates[coord] = sourceCell == null
            ? isExternalPlainFormulaPaste
                  ? _cellForExternalFormulaPaste(sheet, coord, baseCell, text)
                  : text.isEmpty && baseCell.merge == null
                  ? null
                  : baseCell
                        .withFormulaBarInput(text)
                        .copyWith(comment: null, hyperlink: null)
            : _cellForInternalPaste(
                sourceCell,
                sourceCoord!,
                coord,
                sheet: sheet,
                translatedFormula: translatedFormula,
              );
      }
    }
    final targetPasteRange = FortuneRange(
      rowStart: range.rowStart,
      rowEnd: range.rowStart + targetRowCount - 1,
      columnStart: range.columnStart,
      columnEnd: range.columnStart + targetGridColumnCount - 1,
    );
    if (usesInternalCopy &&
        !pasteBlocked &&
        (copiedImages?.isNotEmpty ?? false)) {
      imageUpdates = _imagesForInternalPaste(
        sheet,
        targetPasteRange,
        copiedImages!,
        copiedVisibleRows: copiedVisibleRows,
        copiedVisibleColumns: copiedVisibleColumns,
      );
    }
    final conditionFormatUpdates = usesInternalCopy && !pasteBlocked
        ? _copiedCellsAreCut
              ? _conditionFormatsForInternalCutPaste(
                  sheet: sheet,
                  copiedRange: copiedRange,
                  targetRange: targetPasteRange,
                  copiedVisibleRows: copiedVisibleRows,
                  copiedVisibleColumns: copiedVisibleColumns,
                )
              : _conditionFormatsForInternalPaste(
                  sheet: sheet,
                  copiedRange: copiedRange,
                  targetRange: targetPasteRange,
                  pastedRowCount: pastedRowCount,
                  pastedColumnCount: pastedColumnCount,
                  copiedVisibleRows: copiedVisibleRows,
                  copiedVisibleColumns: copiedVisibleColumns,
                )
        : null;
    final filterMetadataUpdate =
        usesInternalCopy &&
            _copiedCellsAreCut &&
            !pasteBlocked &&
            _filterSourceVisibleCellsWerePasted(
              copiedFilterSelect: copiedFilterSelect,
              pastedSourceCoords: pastedSourceCoords,
              copiedVisibleRows: copiedVisibleRows,
              copiedVisibleColumns: copiedVisibleColumns,
            ) &&
            copiedFilter != null &&
            copiedFilterSelect != null
        ? _filterMetadataForInternalPaste(
            copiedFilter: copiedFilter,
            copiedFilterSelect: copiedFilterSelect,
            targetRange: targetPasteRange,
            copiedVisibleRows: copiedVisibleRows,
            copiedVisibleColumns: copiedVisibleColumns,
          )
        : null;
    final rawFilterMetadataUpdate =
        filterMetadataUpdate != null && copiedHasRawFilter
        ? _rawFilterMetadataForInternalPaste(
            copiedRawFilter: copiedRawFilter,
            copiedFilterSelect: copiedFilterSelect,
            targetRange: targetPasteRange,
            copiedVisibleRows: copiedVisibleRows,
            copiedVisibleColumns: copiedVisibleColumns,
          )
        : null;
    final hasBorderChanges = borderUpdates.any(
      (borderInfo) => !sheet.borderInfo.any(
        (existing) => _borderInfoSemanticallyEquals(existing, borderInfo),
      ),
    );
    final hasChanges =
        updates.entries.any(
          (entry) => _cellWouldChange(sheet, entry.key, entry.value),
        ) ||
        hasBorderChanges ||
        rawBorderInfoUpdates.isNotEmpty ||
        imageUpdates.isNotEmpty ||
        conditionFormatUpdates != null ||
        (filterMetadataUpdate != null &&
            (!_jsonLikeEquals(sheet.filter, filterMetadataUpdate.filter) ||
                !_jsonLikeEquals(
                  sheet.filterSelect,
                  filterMetadataUpdate.filterSelect,
                ) ||
                (copiedHasRawFilter &&
                    !_jsonLikeEquals(
                      sheet.rawFilter,
                      rawFilterMetadataUpdate,
                    )) ||
                (sheet.hasRawFilter != copiedHasRawFilter))) ||
        dataVerificationUpdates.entries.any(
          (entry) =>
              _dataVerificationWouldChange(sheet, entry.key, entry.value),
        ) ||
        rawDataVerificationUpdates.entries.any(
          (entry) =>
              _rawDataVerificationWouldChange(sheet, entry.key, entry.value),
        ) ||
        rawHyperlinkUpdates.entries.any(
          (entry) => _rawHyperlinkWouldChange(sheet, entry.key, entry.value),
        );
    final completedInternalCutPaste =
        usesInternalCopy && _copiedCellsAreCut && !pasteBlocked;
    if (hasChanges) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChanges) {
        Map<Object?, Object?>? nextRawDataVerification;
        Map<Object?, Object?>? nextRawHyperlinks;
        Object? nextRawBorderInfo;
        final functionGroupClearCoords = <FortuneCellCoord>[];
        final functionGroupEnsureCoords = <FortuneCellCoord>[];
        for (final entry in updates.entries) {
          if (_pasteUpdateClearsFormulaGroup(sheet, entry.key, entry.value)) {
            functionGroupClearCoords.add(entry.key);
          }
          if (_cellHasFormulaMetadata(entry.value)) {
            functionGroupEnsureCoords.add(entry.key);
          }
          if (entry.value == null) {
            sheet.cells.remove(entry.key);
            sheet.hyperlinks.remove('${entry.key.row}_${entry.key.column}');
          } else {
            _setSheetCell(sheet, entry.key, entry.value!);
            _syncSheetHyperlinkForCell(sheet, entry.key, entry.value!);
          }
        }
        for (final borderInfo in borderUpdates) {
          if (!sheet.borderInfo.any(
            (existing) => _borderInfoSemanticallyEquals(existing, borderInfo),
          )) {
            sheet.borderInfo.add(borderInfo);
          }
        }
        if (rawBorderInfoUpdates.isNotEmpty) {
          nextRawBorderInfo = [
            if (sheet.rawBorderInfo is List)
              for (final item in sheet.rawBorderInfo! as List)
                cloneFortuneMetadata(item),
            for (final item in rawBorderInfoUpdates) cloneFortuneMetadata(item),
          ];
        }
        for (final entry in dataVerificationUpdates.entries) {
          final key = _cellKey(entry.key);
          final value = entry.value;
          if (value == null) {
            sheet.dataVerification.remove(key);
          } else {
            sheet.dataVerification[key] = value;
          }
        }
        if (rawDataVerificationUpdates.isNotEmpty) {
          final rawDataVerification = sheet.rawDataVerification;
          nextRawDataVerification = rawDataVerification is Map
              ? Map<Object?, Object?>.from(
                  cloneFortuneMetadata(rawDataVerification) as Map,
                )
              : <Object?, Object?>{};
          for (final entry in rawDataVerificationUpdates.entries) {
            nextRawDataVerification[_cellKey(entry.key)] = cloneFortuneMetadata(
              entry.value,
            );
          }
        }
        if (rawHyperlinkUpdates.isNotEmpty) {
          final rawHyperlinks = sheet.rawHyperlinks;
          nextRawHyperlinks = rawHyperlinks is Map
              ? Map<Object?, Object?>.from(
                  cloneFortuneMetadata(rawHyperlinks) as Map,
                )
              : <Object?, Object?>{};
          for (final entry in rawHyperlinkUpdates.entries) {
            nextRawHyperlinks[_cellKey(entry.key)] = cloneFortuneMetadata(
              entry.value,
            );
          }
        }
        if (completedInternalCutPaste) {
          final metrics = sheet.metrics(_workbook.settings);
          final copiedImageIds = copiedImages
              ?.where(
                (image) => pastedSourceCoords.contains(
                  _imageAnchorCoord(image, metrics),
                ),
              )
              .map((image) => image.id)
              .toSet();
          if (copiedImageIds != null && copiedImageIds.isNotEmpty) {
            sheet.images.removeWhere(
              (image) => copiedImageIds.contains(image.id),
            );
          }
        }
        sheet.images.addAll(imageUpdates);
        if (completedInternalCutPaste) {
          final copiedBorderSourceRanges = [
            for (final sourceCoord
                in copiedBorders?.keys ?? const <FortuneCellCoord>[])
              if (pastedSourceCoords.contains(sourceCoord) &&
                  !targetCoords.contains(sourceCoord))
                FortuneRange(
                  rowStart: sourceCoord.row,
                  rowEnd: sourceCoord.row,
                  columnStart: sourceCoord.column,
                  columnEnd: sourceCoord.column,
                  rowFocus: sourceCoord.row,
                  columnFocus: sourceCoord.column,
                ),
          ];
          if (copiedBorderSourceRanges.isNotEmpty) {
            sheet.borderInfo.add(
              FortuneBorderInfo(
                rangeType: 'range',
                borderType: fortuneToolbarBorderNoneCommand,
                color: const Color(0xff000000),
                style: 1,
                ranges: copiedBorderSourceRanges,
              ),
            );
          }
          if (sheet.hasRawBorderInfo && sheet.rawBorderInfo is List) {
            final rawBorderInfoBase = _rawBorderInfoWithoutRanges(
              sheet.rawBorderInfo,
              copiedBorderSourceRanges,
            );
            final rawBorderInfo = rawBorderInfoBase is List
                ? [
                    for (final item in rawBorderInfoBase)
                      cloneFortuneMetadata(item),
                  ]
                : <Object?>[];
            rawBorderInfo.addAll(
              rawBorderInfoUpdates.map(cloneFortuneMetadata),
            );
            nextRawBorderInfo = rawBorderInfo;
          }
          for (final sourceCoord in copiedCells.keys) {
            if (pastedSourceCoords.contains(sourceCoord) &&
                !targetCoords.contains(sourceCoord)) {
              if (_cellHasFormulaMetadata(sheet.cells[sourceCoord])) {
                functionGroupClearCoords.add(sourceCoord);
              }
              sheet.cells.remove(sourceCoord);
              sheet.hyperlinks.remove(
                '${sourceCoord.row}_${sourceCoord.column}',
              );
            }
          }
          for (final sourceCoord
              in copiedDataVerification?.keys ?? const <FortuneCellCoord>[]) {
            if (pastedSourceCoords.contains(sourceCoord) &&
                !targetCoords.contains(sourceCoord)) {
              sheet.dataVerification.remove(_cellKey(sourceCoord));
            }
          }
          for (final sourceCoord
              in copiedRawDataVerification?.keys ??
                  const <FortuneCellCoord>[]) {
            if (pastedSourceCoords.contains(sourceCoord) &&
                !targetCoords.contains(sourceCoord)) {
              final rawDataVerification = sheet.rawDataVerification;
              nextRawDataVerification ??= rawDataVerification is Map
                  ? Map<Object?, Object?>.from(
                      cloneFortuneMetadata(rawDataVerification) as Map,
                    )
                  : <Object?, Object?>{};
              nextRawDataVerification.remove(_cellKey(sourceCoord));
            }
          }
          for (final sourceCoord
              in copiedRawHyperlinks?.keys ?? const <FortuneCellCoord>[]) {
            if (pastedSourceCoords.contains(sourceCoord) &&
                !targetCoords.contains(sourceCoord)) {
              final rawHyperlinks = sheet.rawHyperlinks;
              nextRawHyperlinks ??= rawHyperlinks is Map
                  ? Map<Object?, Object?>.from(
                      cloneFortuneMetadata(rawHyperlinks) as Map,
                    )
                  : <Object?, Object?>{};
              nextRawHyperlinks.remove(_cellKey(sourceCoord));
            }
          }
        }
        FortuneSheet? nextFunctionGroupSheet;
        for (final coord in functionGroupClearCoords) {
          nextFunctionGroupSheet = _sheetWithoutFunctionGroupAt(
            nextFunctionGroupSheet ?? sheet,
            coord,
          );
        }
        for (final coord in functionGroupEnsureCoords) {
          nextFunctionGroupSheet = _sheetWithCalcChainAt(
            nextFunctionGroupSheet ?? sheet,
            coord,
          );
        }
        if (conditionFormatUpdates != null ||
            filterMetadataUpdate != null ||
            nextRawBorderInfo != null ||
            nextRawDataVerification != null ||
            nextRawHyperlinks != null ||
            nextFunctionGroupSheet != null) {
          var nextSheet = nextFunctionGroupSheet ?? sheet;
          if (conditionFormatUpdates != null) {
            nextSheet = nextSheet.copyWith(
              conditionFormats: conditionFormatUpdates,
              hasRawConditionFormats: true,
            );
          }
          if (filterMetadataUpdate != null) {
            nextSheet = nextSheet.copyWith(
              filter: filterMetadataUpdate.filter,
              rawFilter: copiedHasRawFilter ? rawFilterMetadataUpdate : null,
              hasRawFilter: copiedHasRawFilter,
              filterSelect: filterMetadataUpdate.filterSelect,
              hasRawFilterSelect: filterMetadataUpdate.filterSelect != null,
            );
          }
          if (nextRawBorderInfo != null) {
            nextSheet = nextSheet.copyWith(
              rawBorderInfo: nextRawBorderInfo,
              hasRawBorderInfo: true,
            );
          }
          if (nextRawDataVerification != null) {
            nextSheet = nextSheet.copyWith(
              rawDataVerification: nextRawDataVerification,
              hasRawDataVerification: true,
            );
          }
          if (nextRawHyperlinks != null) {
            nextSheet = nextSheet.copyWith(
              rawHyperlinks: nextRawHyperlinks,
              hasRawHyperlinks: true,
            );
          }
          _replaceActiveSheet(nextSheet);
          _recalculateWorkbookFormulas();
        } else {
          _recalculateWorkbookFormulas();
        }
      }
      if (completedInternalCutPaste) {
        _copiedCellsAreCut = false;
        _copiedCellCoord = null;
        _copiedCellRange = null;
        _copiedCells = null;
        _copiedBorders = null;
        _copiedDataVerification = null;
        _copiedRawDataVerification = null;
        _copiedRawHyperlinks = null;
        _copiedFilter = null;
        _copiedRawFilter = null;
        _copiedHasRawFilter = false;
        _copiedFilterSelect = null;
        _copiedImages = null;
        _clearSelectionRangeMetadata();
      }
      if (!pasteBlocked && targetRowCount > 0 && targetGridColumnCount > 0) {
        final pasteFocus = FortuneCellCoord(
          targetPasteRange.rowStart,
          targetPasteRange.columnStart,
        );
        selection = FortuneSelection(
          row: pasteFocus.row,
          column: pasteFocus.column,
          rowEnd: targetPasteRange.rowEnd,
          columnEnd: targetPasteRange.columnEnd,
        );
        _writeSelectionSaveRange(targetPasteRange, pasteFocus);
      }
      _closeTransientMenus();
      if (pasteBlockedMessage != null) {
        _locationMessageDialogText = pasteBlockedMessage;
        _locationMessageDialogConfirm = false;
      }
    });
  }

  bool _pasteUpdateClearsFormulaGroup(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell? nextCell,
  ) {
    final current = sheet.cells[coord];
    final hadFormula = _cellHasFormulaMetadata(current);
    final hasNextFormula = _cellHasFormulaMetadata(nextCell);
    return hadFormula && !hasNextFormula;
  }

  bool _cellHasFormulaMetadata(FortuneCell? cell) {
    return cell?.formula != null ||
        (cell?.hasRawFormula == true && cell?.rawFormula != null);
  }

  FortuneSheet _sheetWithCalcChainAt(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    return sheet.copyWith(
      calcChain: _formulaGroupWithCoord(sheet.calcChain, coord, sheet.id),
      hasRawCalcChain: true,
    );
  }

  FortuneSheet _sheetWithoutFunctionGroupAt(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    return sheet.copyWith(
      calcChain: _formulaGroupWithoutCoord(sheet.calcChain, coord, sheet.id),
      hasRawCalcChain: sheet.hasRawCalcChain || sheet.calcChain != null,
      dynamicArray: _formulaGroupWithoutCoord(
        sheet.dynamicArray,
        coord,
        sheet.id,
      ),
      hasRawDynamicArray:
          sheet.hasRawDynamicArray || sheet.dynamicArray != null,
      dynamicArrayCompute: _dynamicArrayComputeWithoutCoord(
        sheet.dynamicArrayCompute,
        coord,
        sheet.id,
      ),
      hasRawDynamicArrayCompute:
          sheet.hasRawDynamicArrayCompute || sheet.dynamicArrayCompute != null,
    );
  }

  Object? _formulaGroupWithCoord(
    Object? raw,
    FortuneCellCoord coord,
    String sheetId,
  ) {
    final entry = {'r': coord.row, 'c': coord.column, 'id': sheetId};
    if (raw is! List) {
      return [entry];
    }
    final next = <Object?>[];
    var hasEntry = false;
    for (final item in raw) {
      if (_formulaGroupEntryMatches(item, coord, sheetId)) {
        hasEntry = true;
      }
      next.add(cloneFortuneMetadata(item));
    }
    if (!hasEntry) {
      next.add(entry);
    }
    return next;
  }

  Object? _formulaGroupWithoutCoord(
    Object? raw,
    FortuneCellCoord coord,
    String sheetId,
  ) {
    if (raw is! List) {
      return cloneFortuneMetadata(raw);
    }
    return [
      for (final item in raw)
        if (!_formulaGroupEntryMatches(item, coord, sheetId))
          cloneFortuneMetadata(item),
    ];
  }

  bool _formulaGroupEntryMatches(
    Object? raw,
    FortuneCellCoord coord,
    String sheetId,
  ) {
    if (raw is! Map) {
      return false;
    }
    final row = _intValue(raw['r']);
    final column = _intValue(raw['c']);
    final id = raw['id']?.toString() ?? sheetId;
    return row == coord.row && column == coord.column && id == sheetId;
  }

  Object? _dynamicArrayComputeWithoutCoord(
    Object? raw,
    FortuneCellCoord coord,
    String sheetId,
  ) {
    if (raw is Map) {
      final next = Map<Object?, Object?>.from(raw);
      next.remove('${coord.row}_${coord.column}');
      return next;
    }
    if (raw is List) {
      return [
        for (final item in raw)
          if (!_formulaGroupEntryMatches(item, coord, sheetId))
            cloneFortuneMetadata(item),
      ];
    }
    return cloneFortuneMetadata(raw);
  }

  FortuneCell _cellForExternalFormulaPaste(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell baseCell,
    String formula,
  ) {
    Object? result;
    Object? formulaError;
    try {
      result = _normalizedExternalFormulaPasteResult(
        FortuneFormulaEngine.evaluateFormula(sheet, formula),
      );
    } on StateError catch (error) {
      formulaError = error.message;
    } catch (_) {
      formulaError = ERROR_VALUE;
    }
    final payload = handleFormulaStringPaste(
      _workbook,
      <String, Object?>{
        'currentSheetId': sheet.id,
        'formulaCache': <String, Object?>{},
        'luckysheet_select_save': [
          {
            'row': [coord.row, coord.row],
            'column': [coord.column, coord.column],
          },
        ],
      },
      formula,
      result: result,
      formulaError: formulaError,
    );
    final payloadSheet = payload?['sheet'];
    final cell = payloadSheet is FortuneSheet
        ? payloadSheet.cells[coord]
        : null;
    return (cell ?? baseCell.withFormulaBarInput(formula)).copyWith(
      comment: null,
      hyperlink: null,
    );
  }

  Object? _normalizedExternalFormulaPasteResult(Object? value) {
    if (value is double &&
        value.isFinite &&
        value == value.truncateToDouble()) {
      return value.toInt();
    }
    return value;
  }

  String _translatedPasteText(String text, FortuneCellCoord target) {
    final source = _copiedCellCoord;
    if (source == null ||
        !_clipboardTextMatchesInternalCopy(text) ||
        !text.startsWith('=')) {
      return text;
    }
    return FortuneFormulaEngine.translateReferences(
      text,
      rowDelta: target.row - source.row,
      columnDelta: target.column - source.column,
    );
  }

  FortuneCell _cellForInternalPaste(
    FortuneCell sourceCell,
    FortuneCellCoord sourceCoord,
    FortuneCellCoord targetCoord, {
    required FortuneSheet sheet,
    String? translatedFormula,
  }) {
    var cell = translatedFormula == null
        ? sourceCell
        : sourceCell.withFormulaBarInput(translatedFormula);
    final merge = sourceCell.merge;
    if (merge != null) {
      final rowDelta = targetCoord.row - sourceCoord.row;
      final columnDelta = targetCoord.column - sourceCoord.column;
      cell = cell.copyWith(
        merge: merge.copyWith(
          row: merge.row + rowDelta,
          column: merge.column + columnDelta,
        ),
      );
    }
    final hyperlink = sourceCell.hyperlink;
    if (hyperlink != null) {
      cell = cell.copyWith(
        hyperlink: hyperlink.copyWith(
          row: targetCoord.row,
          column: targetCoord.column,
          id: sheet.id,
        ),
      );
    }
    final comment = sourceCell.comment;
    if (comment != null && (comment.left != null || comment.top != null)) {
      final metrics = sheet.metrics(_workbook.settings);
      final dx =
          metrics.columnStart(targetCoord.column) -
          metrics.columnStart(sourceCoord.column);
      final dy =
          metrics.rowStart(targetCoord.row) - metrics.rowStart(sourceCoord.row);
      cell = cell.copyWith(
        comment: comment.copyWith(
          left: comment.left == null ? null : math.max(0, comment.left! + dx),
          top: comment.top == null ? null : math.max(0, comment.top! + dy),
        ),
      );
    }
    return cell;
  }

  ({Map<String, Object?> filter, Object? filterSelect})
  _filterMetadataForInternalPaste({
    required Map<String, Object?> copiedFilter,
    required Object? copiedFilterSelect,
    required FortuneRange targetRange,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    final filterSelect = _translateFilterRangeMetadata(
      copiedFilterSelect,
      targetRange: targetRange,
      copiedVisibleRows: copiedVisibleRows,
      copiedVisibleColumns: copiedVisibleColumns,
    );
    final filterSelectRange = _rangeFromFilterSelectMetadata(filterSelect);
    final filter = <String, Object?>{};
    for (final entry in copiedFilter.entries) {
      final raw = entry.value;
      if (raw is! Map) {
        filter[_translateFilterKey(
          entry.key,
          targetStart: targetRange.columnStart,
          copiedVisibleIndexes: copiedVisibleColumns,
        )] = cloneFortuneMetadata(
          raw,
        );
        continue;
      }
      final config = Map<String, Object?>.from(
        cloneFortuneMetadata(raw) as Map,
      );
      _translateFilterConfig(
        config,
        targetRange: filterSelectRange,
        fallbackTargetRange: targetRange,
        copiedVisibleRows: copiedVisibleRows,
        copiedVisibleColumns: copiedVisibleColumns,
      );
      final cindex = _intValue(config['cindex']);
      final key = cindex != null && filterSelectRange != null
          ? '${cindex - filterSelectRange.columnStart}'
          : _translateFilterKey(
              entry.key,
              targetStart: targetRange.columnStart,
              copiedVisibleIndexes: copiedVisibleColumns,
            );
      filter[key] = config;
    }
    return (filter: filter, filterSelect: filterSelect);
  }

  Object? _rawFilterMetadataForInternalPaste({
    required Object? copiedRawFilter,
    required Object? copiedFilterSelect,
    required FortuneRange targetRange,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    if (copiedRawFilter is! Map) {
      return cloneFortuneMetadata(copiedRawFilter);
    }
    return _filterMetadataForInternalPaste(
      copiedFilter: {
        for (final entry in copiedRawFilter.entries)
          '${entry.key}': cloneFortuneMetadata(entry.value),
      },
      copiedFilterSelect: copiedFilterSelect,
      targetRange: targetRange,
      copiedVisibleRows: copiedVisibleRows,
      copiedVisibleColumns: copiedVisibleColumns,
    ).filter;
  }

  bool _filterSourceVisibleCellsWerePasted({
    required Object? copiedFilterSelect,
    required Set<FortuneCellCoord> pastedSourceCoords,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    final filterRange = _rangeFromFilterSelectMetadata(copiedFilterSelect);
    if (filterRange == null) {
      return true;
    }
    for (final row in copiedVisibleRows) {
      if (row < filterRange.rowStart || row > filterRange.rowEnd) {
        continue;
      }
      for (final column in copiedVisibleColumns) {
        if (column < filterRange.columnStart ||
            column > filterRange.columnEnd) {
          continue;
        }
        if (!pastedSourceCoords.contains(FortuneCellCoord(row, column))) {
          return false;
        }
      }
    }
    return true;
  }

  String _translateFilterKey(
    String key, {
    required int targetStart,
    required List<int> copiedVisibleIndexes,
  }) {
    final column = int.tryParse(key);
    if (column == null) {
      return key;
    }
    final mapped = _mapVisibleIndex(
      column,
      copiedVisibleIndexes: copiedVisibleIndexes,
      targetStart: targetStart,
    );
    return '${mapped ?? column}';
  }

  void _translateFilterConfig(
    Map<String, Object?> config, {
    required FortuneRange? targetRange,
    required FortuneRange fallbackTargetRange,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    final rowTargetStart =
        targetRange?.rowStart ?? fallbackTargetRange.rowStart;
    final columnTargetStart =
        targetRange?.columnStart ?? fallbackTargetRange.columnStart;
    final rowRange = _mapVisibleRange(
      _intValue(config['str']),
      _intValue(config['edr']),
      copiedVisibleIndexes: copiedVisibleRows,
      targetStart: rowTargetStart,
    );
    if (rowRange != null) {
      config['str'] = rowRange.$1;
      config['edr'] = rowRange.$2;
    }
    final columnRange = _mapVisibleRange(
      _intValue(config['stc']),
      _intValue(config['edc']),
      copiedVisibleIndexes: copiedVisibleColumns,
      targetStart: columnTargetStart,
    );
    if (columnRange != null) {
      config['stc'] = columnRange.$1;
      config['edc'] = columnRange.$2;
    }
    final cindex = _intValue(config['cindex']);
    if (cindex != null) {
      final mapped = _mapVisibleIndex(
        cindex,
        copiedVisibleIndexes: copiedVisibleColumns,
        targetStart: columnTargetStart,
      );
      if (mapped != null) {
        config['cindex'] = mapped;
      }
    }
    final rowhidden = config['rowhidden'];
    if (rowhidden is Map) {
      final translated = <String, Object?>{};
      for (final entry in rowhidden.entries) {
        final row = _intValue(entry.key);
        final mapped = row == null
            ? null
            : _mapVisibleIndex(
                row,
                copiedVisibleIndexes: copiedVisibleRows,
                targetStart: rowTargetStart,
              );
        if (mapped != null) {
          translated['$mapped'] = entry.value;
        }
      }
      if (translated.isEmpty) {
        config.remove('rowhidden');
      } else {
        config['rowhidden'] = translated;
      }
    }
    final row = config['row'];
    if (row is List) {
      config['row'] = _translateNumericList(
        row,
        targetStart: rowTargetStart,
        copiedVisibleIndexes: copiedVisibleRows,
      );
    }
    final column = config['column'];
    if (column is List) {
      config['column'] = _translateNumericList(
        column,
        targetStart: columnTargetStart,
        copiedVisibleIndexes: copiedVisibleColumns,
      );
    }
    final rowFocus = _intValue(config['row_focus']);
    if (rowFocus != null) {
      final mapped = _mapVisibleIndex(
        rowFocus,
        copiedVisibleIndexes: copiedVisibleRows,
        targetStart: rowTargetStart,
      );
      if (mapped != null) {
        config['row_focus'] = mapped;
      }
    }
    final columnFocus = _intValue(config['column_focus']);
    if (columnFocus != null) {
      final mapped = _mapVisibleIndex(
        columnFocus,
        copiedVisibleIndexes: copiedVisibleColumns,
        targetStart: columnTargetStart,
      );
      if (mapped != null) {
        config['column_focus'] = mapped;
      }
    }
  }

  Object? _translateFilterRangeMetadata(
    Object? raw, {
    required FortuneRange targetRange,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
    String? key,
  }) {
    if (raw is Map) {
      return {
        for (final entry in raw.entries)
          entry.key: _translateFilterRangeMetadata(
            entry.value,
            targetRange: targetRange,
            copiedVisibleRows: copiedVisibleRows,
            copiedVisibleColumns: copiedVisibleColumns,
            key: '${entry.key}',
          ),
      };
    }
    if (raw is List) {
      if (key == 'row') {
        return _translateNumericList(
          raw,
          targetStart: targetRange.rowStart,
          copiedVisibleIndexes: copiedVisibleRows,
        );
      }
      if (key == 'column') {
        return _translateNumericList(
          raw,
          targetStart: targetRange.columnStart,
          copiedVisibleIndexes: copiedVisibleColumns,
        );
      }
      return [
        for (final item in raw)
          _translateFilterRangeMetadata(
            item,
            targetRange: targetRange,
            copiedVisibleRows: copiedVisibleRows,
            copiedVisibleColumns: copiedVisibleColumns,
          ),
      ];
    }
    final value = _intValue(raw);
    if (value != null) {
      if (key == 'row_focus' || key == 'r') {
        return _mapVisibleIndex(
              value,
              copiedVisibleIndexes: copiedVisibleRows,
              targetStart: targetRange.rowStart,
            ) ??
            value;
      }
      if (key == 'column_focus' || key == 'c') {
        return _mapVisibleIndex(
              value,
              copiedVisibleIndexes: copiedVisibleColumns,
              targetStart: targetRange.columnStart,
            ) ??
            value;
      }
    }
    return cloneFortuneMetadata(raw);
  }

  List<Object?> _translateNumericList(
    List raw, {
    required int targetStart,
    required List<int> copiedVisibleIndexes,
  }) {
    if (raw.length >= 2) {
      final range = _mapVisibleRange(
        _intValue(raw[0]),
        _intValue(raw[1]),
        copiedVisibleIndexes: copiedVisibleIndexes,
        targetStart: targetStart,
      );
      if (range != null) {
        return [range.$1, range.$2, ...raw.skip(2)];
      }
    }
    return [
      for (final item in raw)
        if (_intValue(item) case final value?)
          _mapVisibleIndex(
                value,
                copiedVisibleIndexes: copiedVisibleIndexes,
                targetStart: targetStart,
              ) ??
              item
        else
          item,
    ];
  }

  int? _mapVisibleIndex(
    int value, {
    required List<int> copiedVisibleIndexes,
    required int targetStart,
  }) {
    final index = copiedVisibleIndexes.indexOf(value);
    return index < 0 ? null : targetStart + index;
  }

  (int, int)? _mapVisibleRange(
    int? start,
    int? end, {
    required List<int> copiedVisibleIndexes,
    required int targetStart,
  }) {
    if (start == null || end == null) {
      return null;
    }
    final lower = math.min(start, end);
    final upper = math.max(start, end);
    final mapped = <int>[
      for (var i = 0; i < copiedVisibleIndexes.length; i += 1)
        if (copiedVisibleIndexes[i] >= lower &&
            copiedVisibleIndexes[i] <= upper)
          targetStart + i,
    ];
    if (mapped.isEmpty) {
      return null;
    }
    return (mapped.first, mapped.last);
  }

  FortuneRange? _rangeFromFilterSelectMetadata(Object? raw) {
    if (raw is! Map) {
      return null;
    }
    final row = raw['row'];
    final column = raw['column'];
    if (row is! List ||
        column is! List ||
        row.length < 2 ||
        column.length < 2) {
      return null;
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return null;
    }
    return FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
    );
  }

  Object? _conditionFormatsForInternalPaste({
    required FortuneSheet sheet,
    required FortuneRange copiedRange,
    required FortuneRange targetRange,
    required int pastedRowCount,
    required int pastedColumnCount,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    final rawRules = sheet.conditionFormats;
    if (rawRules is! List || rawRules.isEmpty) {
      return null;
    }
    List<List<int>> visibleIndexRuns(
      List<int> visibleValues,
      int start,
      int end,
    ) {
      final runs = <List<int>>[];
      var current = <int>[];
      for (var index = 0; index < visibleValues.length; index += 1) {
        final value = visibleValues[index];
        if (value < start || value > end) {
          continue;
        }
        if (current.isNotEmpty && index != current.last + 1) {
          runs.add(current);
          current = <int>[];
        }
        current.add(index);
      }
      if (current.isNotEmpty) {
        runs.add(current);
      }
      return runs;
    }

    final rowRepeats = math.max(
      1,
      (targetRange.rowEnd - targetRange.rowStart + 1) ~/ pastedRowCount,
    );
    final columnRepeats = math.max(
      1,
      (targetRange.columnEnd - targetRange.columnStart + 1) ~/
          pastedColumnCount,
    );
    final additions = <Object?>[];
    for (final rawRule in rawRules) {
      if (rawRule is! Map) {
        continue;
      }
      final shiftedRanges = <Map<String, Object?>>[];
      for (final ruleRange in _conditionFormatRuleRanges(rawRule)) {
        final copiedIntersection = _rangeIntersection(ruleRange, copiedRange);
        if (copiedIntersection == null) {
          continue;
        }
        final rowRuns = visibleIndexRuns(
          copiedVisibleRows,
          copiedIntersection.rowStart,
          copiedIntersection.rowEnd,
        );
        final columnRuns = visibleIndexRuns(
          copiedVisibleColumns,
          copiedIntersection.columnStart,
          copiedIntersection.columnEnd,
        );
        if (rowRuns.isEmpty || columnRuns.isEmpty) {
          continue;
        }
        for (var rowRepeat = 0; rowRepeat < rowRepeats; rowRepeat += 1) {
          for (
            var columnRepeat = 0;
            columnRepeat < columnRepeats;
            columnRepeat += 1
          ) {
            final rowBase = targetRange.rowStart + rowRepeat * pastedRowCount;
            final columnBase =
                targetRange.columnStart + columnRepeat * pastedColumnCount;
            for (final rowRun in rowRuns) {
              for (final columnRun in columnRuns) {
                shiftedRanges.add({
                  'row': [rowBase + rowRun.first, rowBase + rowRun.last],
                  'column': [
                    columnBase + columnRun.first,
                    columnBase + columnRun.last,
                  ],
                });
              }
            }
          }
        }
      }
      if (shiftedRanges.isEmpty) {
        continue;
      }
      final clonedRule = <String, Object?>{};
      for (final entry in rawRule.entries) {
        clonedRule['${entry.key}'] = cloneFortuneMetadata(entry.value);
      }
      clonedRule['cellrange'] = shiftedRanges;
      additions.add(clonedRule);
    }
    if (additions.isEmpty) {
      return null;
    }
    return [...rawRules, ...additions];
  }

  Object? _conditionFormatsForInternalCutPaste({
    required FortuneSheet sheet,
    required FortuneRange copiedRange,
    required FortuneRange targetRange,
    required List<int> copiedVisibleRows,
    required List<int> copiedVisibleColumns,
  }) {
    final rawRules = sheet.conditionFormats;
    if (rawRules is! List || rawRules.isEmpty) {
      return null;
    }
    List<List<int>> visibleIndexRuns(
      List<int> visibleValues,
      int start,
      int end,
    ) {
      final runs = <List<int>>[];
      var current = <int>[];
      for (var index = 0; index < visibleValues.length; index += 1) {
        final value = visibleValues[index];
        if (value < start || value > end) {
          continue;
        }
        if (current.isNotEmpty && index != current.last + 1) {
          runs.add(current);
          current = <int>[];
        }
        current.add(index);
      }
      if (current.isNotEmpty) {
        runs.add(current);
      }
      return runs;
    }

    FortuneRange originalVisibleRange(List<int> rowRun, List<int> columnRun) {
      return FortuneRange(
        rowStart: copiedVisibleRows[rowRun.first],
        rowEnd: copiedVisibleRows[rowRun.last],
        columnStart: copiedVisibleColumns[columnRun.first],
        columnEnd: copiedVisibleColumns[columnRun.last],
      );
    }

    var changed = false;
    final nextRules = <Object?>[];
    for (final rawRule in rawRules) {
      if (rawRule is! Map) {
        nextRules.add(cloneFortuneMetadata(rawRule));
        continue;
      }
      final nextRanges = <Map<String, Object?>>[];
      for (final ruleRange in _conditionFormatRuleRanges(rawRule)) {
        final copiedIntersection = _rangeIntersection(ruleRange, copiedRange);
        if (copiedIntersection == null) {
          nextRanges.add(_conditionRangeMap(ruleRange));
          continue;
        }
        final rowRuns = visibleIndexRuns(
          copiedVisibleRows,
          copiedIntersection.rowStart,
          copiedIntersection.rowEnd,
        );
        final columnRuns = visibleIndexRuns(
          copiedVisibleColumns,
          copiedIntersection.columnStart,
          copiedIntersection.columnEnd,
        );
        if (rowRuns.isEmpty || columnRuns.isEmpty) {
          nextRanges.add(_conditionRangeMap(ruleRange));
          continue;
        }
        changed = true;
        var remaining = [_conditionRangeMap(ruleRange)];
        for (final rowRun in rowRuns) {
          for (final columnRun in columnRuns) {
            final cutRange = originalVisibleRange(rowRun, columnRun);
            remaining = [
              for (final range in remaining)
                ..._conditionRangeRestAfterCut(
                  FortuneRange(
                    rowStart: (range['row'] as List)[0] as int,
                    rowEnd: (range['row'] as List)[1] as int,
                    columnStart: (range['column'] as List)[0] as int,
                    columnEnd: (range['column'] as List)[1] as int,
                  ),
                  cutRange,
                ),
            ];
            nextRanges.add(
              _conditionRangeMap(
                FortuneRange(
                  rowStart: targetRange.rowStart + rowRun.first,
                  rowEnd: targetRange.rowStart + rowRun.last,
                  columnStart: targetRange.columnStart + columnRun.first,
                  columnEnd: targetRange.columnStart + columnRun.last,
                ),
              ),
            );
          }
        }
        nextRanges.addAll(remaining);
      }
      final clonedRule = <String, Object?>{};
      for (final entry in rawRule.entries) {
        clonedRule['${entry.key}'] = cloneFortuneMetadata(entry.value);
      }
      clonedRule['cellrange'] = nextRanges;
      nextRules.add(clonedRule);
    }
    return changed ? nextRules : null;
  }

  List<Map<String, Object?>> _conditionRangeRestAfterCut(
    FortuneRange range,
    FortuneRange cut,
  ) {
    final intersection = _rangeIntersection(range, cut);
    if (intersection == null) {
      return [_conditionRangeMap(range)];
    }
    final pieces = <FortuneRange>[];
    if (range.rowStart < intersection.rowStart) {
      pieces.add(
        FortuneRange(
          rowStart: range.rowStart,
          rowEnd: intersection.rowStart - 1,
          columnStart: range.columnStart,
          columnEnd: range.columnEnd,
        ),
      );
    }
    if (intersection.rowEnd < range.rowEnd) {
      pieces.add(
        FortuneRange(
          rowStart: intersection.rowEnd + 1,
          rowEnd: range.rowEnd,
          columnStart: range.columnStart,
          columnEnd: range.columnEnd,
        ),
      );
    }
    if (range.columnStart < intersection.columnStart) {
      pieces.add(
        FortuneRange(
          rowStart: intersection.rowStart,
          rowEnd: intersection.rowEnd,
          columnStart: range.columnStart,
          columnEnd: intersection.columnStart - 1,
        ),
      );
    }
    if (intersection.columnEnd < range.columnEnd) {
      pieces.add(
        FortuneRange(
          rowStart: intersection.rowStart,
          rowEnd: intersection.rowEnd,
          columnStart: intersection.columnEnd + 1,
          columnEnd: range.columnEnd,
        ),
      );
    }
    return [for (final piece in pieces) _conditionRangeMap(piece)];
  }

  Map<String, Object?> _conditionRangeMap(FortuneRange range) {
    return {
      'row': [range.rowStart, range.rowEnd],
      'column': [range.columnStart, range.columnEnd],
    };
  }

  void _clearSelection() {
    final sheet = _workbook.activeSheet;
    final range = _currentSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final targets = <FortuneCellCoord>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        targets.add(sheet.mergeAnchorFor(FortuneCellCoord(row, column)));
      }
    }
    final updates = <FortuneCellCoord, FortuneCell>{};
    for (final coord in targets) {
      final previous = sheet.cells[coord];
      if (previous != null) {
        updates[coord] = previous.withClearedContent();
      }
    }
    final hasChanges = updates.entries.any(
      (entry) => _cellWouldChange(sheet, entry.key, entry.value),
    );
    if (hasChanges) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChanges) {
        for (final entry in updates.entries) {
          if (_cellWouldChange(sheet, entry.key, entry.value)) {
            _setSheetCell(sheet, entry.key, entry.value);
          }
        }
        _recalculateWorkbookFormulas();
      }
      _closeTransientMenus();
    });
  }

  String? _dataVerificationInputFailureText(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    String text,
  ) {
    final raw = sheet.dataVerification[_cellKey(coord)];
    if (raw is! Map || fortuneRawBool(raw['prohibitInput']) != true) {
      return null;
    }
    if (_isDataVerificationInputAllowed(sheet, coord, text)) {
      return null;
    }
    return getFailureText(Map<String, Object?>.from(raw));
  }

  bool _isDataVerificationInputAllowed(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    String text,
  ) {
    final raw = sheet.dataVerification[_cellKey(coord)];
    if (raw is! Map || fortuneRawBool(raw['prohibitInput']) != true) {
      return true;
    }
    final type = '${raw['type'] ?? ''}';
    final type2 = '${raw['type2'] ?? ''}';
    if (type == 'dropdown') {
      final options = _dataVerificationOptions(raw, sheet: sheet);
      if (options.isEmpty) {
        return false;
      }
      final normalizedValues = fortuneRawBool(raw['type2']) == true
          ? _dataVerificationDropdownInputValues(text)
          : [text.trim()];
      return normalizedValues.isNotEmpty &&
          normalizedValues.every((value) {
            return options.any((option) => option.trim() == value);
          });
    }
    if (type == 'number' ||
        type == 'number_integer' ||
        type == 'number_decimal') {
      final parsed = double.tryParse(text.trim());
      if (parsed == null) {
        return false;
      }
      if (type == 'number_integer' && parsed % 1 != 0) {
        return false;
      }
      if (type == 'number_decimal' && parsed % 1 == 0) {
        return false;
      }
      final value1 = double.tryParse('${raw['value1'] ?? ''}');
      final value2 = double.tryParse('${raw['value2'] ?? ''}');
      return _dataVerificationNumericConditionAllowed(
        parsed,
        type2,
        value1,
        value2,
      );
    }
    if (type == 'text_content') {
      final expected = '${raw['value1'] ?? ''}';
      return switch (type2) {
        'include' => text.contains(expected),
        'exclude' => !text.contains(expected),
        'equal' => text == expected,
        _ => true,
      };
    }
    if (type == 'text_length') {
      final value1 = double.tryParse('${raw['value1'] ?? ''}');
      final value2 = double.tryParse('${raw['value2'] ?? ''}');
      return _dataVerificationNumericConditionAllowed(
        text.length.toDouble(),
        type2,
        value1,
        value2,
      );
    }
    if (type == 'date') {
      final value = _dataVerificationDateValue(text);
      if (value == null) {
        return false;
      }
      final value1 = _dataVerificationDateValue(raw['value1']);
      final value2 = _dataVerificationDateValue(raw['value2']);
      return _dataVerificationDateConditionAllowed(
        value,
        type2,
        value1,
        value2,
      );
    }
    if (type == 'validity') {
      return switch (type2) {
        'identificationNumber' => _dataVerificationIdCardAllowed(text),
        'phoneNumber' => RegExp(r'^1[3456789]\d{9}$').hasMatch(text.trim()),
        _ => true,
      };
    }
    return true;
  }

  List<String> _dataVerificationDropdownInputValues(String text) {
    return text.split(',').map((value) => value.trim()).toList(growable: false);
  }

  bool _dataVerificationNumericConditionAllowed(
    double value,
    String type2,
    double? value1,
    double? value2,
  ) {
    return switch (type2) {
      'between' =>
        value1 == null || value2 == null
            ? true
            : value >= value1 && value <= value2,
      'notBetween' =>
        value1 == null || value2 == null
            ? true
            : value < value1 || value > value2,
      'equal' => value1 == null ? true : value == value1,
      'notEqualTo' => value1 == null ? true : value != value1,
      'moreThanThe' => value1 == null ? true : value > value1,
      'lessThan' => value1 == null ? true : value < value1,
      'greaterOrEqualTo' => value1 == null ? true : value >= value1,
      'lessThanOrEqualTo' => value1 == null ? true : value <= value1,
      _ => true,
    };
  }

  DateTime? _dataVerificationDateValue(Object? raw) {
    if (raw == null) {
      return null;
    }
    if (raw is num && raw.isFinite) {
      return DateTime.utc(1899, 12, 30).add(Duration(days: raw.floor()));
    }
    final text = '$raw'.trim();
    if (text.isEmpty) {
      return null;
    }
    final serial = double.tryParse(text);
    if (serial != null && serial.isFinite) {
      return DateTime.utc(1899, 12, 30).add(Duration(days: serial.floor()));
    }
    final match = RegExp(
      r'^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:\s\d{1,2}:\d{1,2}(?::\d{1,2})?)?$',
    ).firstMatch(text);
    if (match == null) {
      return null;
    }
    final year = int.parse(match.group(1)!);
    final month = int.parse(match.group(2)!);
    final day = int.parse(match.group(3)!);
    if (year < 1900) {
      return null;
    }
    if (month > 12 || day > 31) {
      return null;
    }
    if (month == 2) {
      final leapDay = DateTime.utc(year, 2, 29).day == 29;
      if (day > (leapDay ? 29 : 28)) {
        return null;
      }
    }
    return DateTime.utc(year, month, day);
  }

  bool _dataVerificationDateConditionAllowed(
    DateTime value,
    String type2,
    DateTime? value1,
    DateTime? value2,
  ) {
    final day = DateTime.utc(value.year, value.month, value.day);
    int compare(DateTime other) =>
        day.compareTo(DateTime.utc(other.year, other.month, other.day));
    return switch (type2) {
      'between' =>
        value1 == null || value2 == null
            ? true
            : compare(value1) >= 0 && compare(value2) <= 0,
      'notBetween' =>
        value1 == null || value2 == null
            ? true
            : compare(value1) < 0 || compare(value2) > 0,
      'equal' => value1 == null ? true : compare(value1) == 0,
      'notEqualTo' => value1 == null ? true : compare(value1) != 0,
      'earlierThan' => value1 == null ? true : compare(value1) < 0,
      'noEarlierThan' => value1 == null ? true : compare(value1) >= 0,
      'laterThan' => value1 == null ? true : compare(value1) > 0,
      'noLaterThan' => value1 == null ? true : compare(value1) <= 0,
      _ => true,
    };
  }

  bool _dataVerificationIdCardAllowed(String text) {
    final value = text.trim();
    final match = RegExp(
      r'^(?:[1-9]\d{7}(?:(?:0\d)|(?:1[0-2]))(?:(?:[0|1|2]\d)|(?:3[0-1]))\d{3}|[1-9]\d{5}[1-9]\d{3}(?:(?:0\d)|(?:1[0-2]))(?:(?:[0|1|2]\d)|(?:3[0-1]))(?:\d{4}|\d{3}[Xx]))$',
    ).firstMatch(value);
    if (match == null) {
      return false;
    }
    if (value.length != 18) {
      return true;
    }
    const weights = [7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2];
    const checks = ['1', '0', '10', '9', '8', '7', '6', '5', '4', '3', '2'];
    var sum = 0;
    for (var index = 0; index < weights.length; index += 1) {
      sum += int.parse(value.substring(index, index + 1)) * weights[index];
    }
    final expected = checks[sum % 11];
    final actual = value.substring(17);
    return expected == '10'
        ? actual == 'X' || actual == 'x'
        : actual == expected;
  }

  void _insertRowAtSelection({String direction = 'lefttop', int? count}) {
    final sheet = _workbook.activeSheet;
    final rowCount = _effectiveRowCount(sheet);
    final range = _currentSelectionRange(sheet);
    final sourceRow = direction == 'rightbottom'
        ? range.rowEnd
        : range.rowStart;
    final row = direction == 'rightbottom' ? range.rowEnd + 1 : range.rowStart;
    final insertCount = (count ?? range.rowEnd - range.rowStart + 1)
        .clamp(1, 999)
        .toInt();
    for (
      var currentRow = range.rowStart;
      currentRow <= range.rowEnd;
      currentRow += 1
    ) {
      if (_isIndexReadOnly(sheet.rowReadOnly, currentRow)) {
        setState(_closeTransientMenus);
        return;
      }
    }
    if (!_canEditRowStructureFrom(sheet, sourceRow)) {
