          sheet.filter,
          row: row,
          count: insertCount,
          filterSelect: nextFilterSelect,
        ),
      );
      _replaceActiveSheet(
        sheet.copyWith(
          rowCount: rowCount + insertCount,
          cells: sheet.cells,
          nullCells: sheet.nullCells,
          rowHeights: sheet.rowHeights,
          customHeight: sheet.customHeight,
          hiddenRows: sheet.hiddenRows,
          hiddenRowValues: sheet.hiddenRowValues,
          dataVerification: sheet.dataVerification,
          hyperlinks: sheet.hyperlinks,
          borderInfo: sheet.borderInfo,
          images: sheet.images,
          rowReadOnly: _shiftIndexKeyMetadata(
            sheet.rowReadOnly,
            from: row,
            delta: insertCount,
          ),
          frozen: _shiftFrozenPane(
            sheet.frozen,
            rowFrom: row,
            rowDelta: insertCount,
          ),
          selectionSave: _shiftSheetRangeMetadata(
            _contextMenuPreviousSelectionSave ?? sheet.selectionSave,
            rowFrom: row,
            rowDelta: insertCount,
          ),
          selectionRange: _shiftSheetRangeMetadata(
            _contextMenuPreviousSelectionRange ?? sheet.selectionRange,
            rowFrom: row,
            rowDelta: insertCount,
          ),
          filter: sheet.filter,
