  void _splitSelectedCellColumn() {
    final sheet = _workbook.activeSheet;
    final target = _selectedCellColumnSplitTarget(sheet);
    if (target == null || !_canSplitSelectedCellColumn()) {
      setState(_closeTransientMenus);
      return;
    }
    final splitOffset = math.max(1, target.columnSpan ~/ 2);
    final insertAt = target.anchor.column + splitOffset;
    const insertCount = 1;
    _queueRowColOnOp('insertRowCol', {
      'type': 'column',
      'index': insertAt,
      'count': insertCount,
      'direction': 'lefttop',
      'id': sheet.id,
    });
    _recordUndoSnapshot();
    setState(() {
      final metrics = sheet.metrics(_workbook.settings);
      final imageDelta = _defaultColumnExtent(sheet) * insertCount;
      final imageFrom = metrics.columnStart(insertAt);
      var nextSheet = sheet.insertRowOrColumn(
        'column',
        insertAt,
        insertCount,
        direction: 'lefttop',
      );
      final sourceCell = sheet.cells[target.anchor] ?? const FortuneCell();
      final cells = Map<FortuneCellCoord, FortuneCell>.from(nextSheet.cells);
      final expandedTargetRange = FortuneRange(
        rowStart: target.anchor.row,
        rowEnd: target.anchor.row + target.rowSpan - 1,
        columnStart: target.anchor.column,
        columnEnd: target.anchor.column + target.columnSpan,
      );
      _clearMergesInRange(cells, expandedTargetRange);
      final leftAnchor = target.anchor;
      final leftColumnSpan = splitOffset;
      final rightAnchor = FortuneCellCoord(
        target.anchor.row,
        target.anchor.column + leftColumnSpan,
      );
      final rightColumnSpan = target.columnSpan + insertCount - leftColumnSpan;
      cells[leftAnchor] = sourceCell.copyWith(merge: null);
      cells[rightAnchor] = _emptySplitCellFrom(sourceCell);
      _mergeCellsAt(
        cells,
        leftAnchor,
        rowSpan: target.rowSpan,
        columnSpan: leftColumnSpan,
      );
      _mergeCellsAt(
        cells,
        rightAnchor,
        rowSpan: target.rowSpan,
        columnSpan: rightColumnSpan,
      );
      nextSheet = nextSheet.copyWith(
        cells: cells,
        images: _shiftImages(
          nextSheet.images,
          leftFrom: imageFrom,
          leftDelta: imageDelta,
        ),
      );
      _replaceActiveSheet(nextSheet);
      selection = FortuneSelection(
        row: leftAnchor.row,
        column: leftAnchor.column,
        rowEnd: leftAnchor.row + target.rowSpan - 1,
        columnEnd: leftAnchor.column + leftColumnSpan - 1,
      );
      _closeTransientMenus();
    });
  }

  FortuneCell _emptySplitCellFrom(FortuneCell source) {
    return source.copyWith(
      value: '',
      rawValue: null,
      hasRawValue: false,
      displayValue: null,
      rawDisplayValue: null,
      hasRawDisplayValue: false,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      merge: null,
      comment: null,
      hyperlink: null,
      inlineRuns: null,
    );
  }

  void _deleteRowAtSelection() {
