      final imageDelta = List<double>.generate(deleteCount, (offset) {
        final currentRow = row + offset;
        return metrics.rowEnd(currentRow) - metrics.rowStart(currentRow);
      }).fold<double>(0, (total, extent) => total + extent);
      final imageFrom = metrics.rowEnd(row + deleteCount - 1);
      var cells = sheet.cells;
