        borderInfo = _deleteBorderInfo(borderInfo, row: row);
        nextRowReadOnly = _deleteIndexKeyMetadata(nextRowReadOnly, index: row);
        nextSelectionSave = _deleteSheetRangeMetadata(
          nextSelectionSave,
          row: row,
        );
        nextSelectionRange = _deleteSheetRangeMetadata(
          nextSelectionRange,
          row: row,
        );
        nextFilterSelect = _deleteSheetRangeMetadata(
          nextFilterSelect,
          row: row,
        );
        nextCalcChain = _deleteSheetRangeMetadata(nextCalcChain, row: row);
        nextConditionFormats = _deleteSheetRangeMetadata(
          nextConditionFormats,
          row: row,
        );
        nextAlternateFormats = _deleteSheetRangeMetadata(
          nextAlternateFormats,
          row: row,
        );
        nextPivotTable = _deleteSheetRangeMetadata(nextPivotTable, row: row);
        nextDynamicArray = _deleteSheetRangeMetadata(
          nextDynamicArray,
          row: row,
        );
        nextDynamicArrayCompute = _deleteDynamicArrayCompute(
          nextDynamicArrayCompute,
          row: row,
        );
        nextFrozen = _deleteFrozenPane(nextFrozen, row: row);
      }
      filter = _deleteFilterRows(
