          dynamicArray: nextDynamicArray,
          hasRawDynamicArray: nextDynamicArray != null,
          dynamicArrayCompute: nextDynamicArrayCompute,
          hasRawDynamicArrayCompute: nextDynamicArrayCompute != null,
        ),
      );
      selection = FortuneSelection(
        row: math.min(row, math.max(1, rowCount - deleteCount) - 1),
