    }
    final range = _currentSelectionRange(sheet);
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      if (_isIndexReadOnly(sheet.rowReadOnly, row)) {
        setState(_closeTransientMenus);
        return;
      }
    }
    if (range.rowStart > range.rowEnd) {
      setState(_closeTransientMenus);
      return;
    }
    final rows = List<int>.generate(
      range.rowEnd - range.rowStart + 1,
      (offset) => range.rowStart + offset,
    );
    final changed = rows.any(
      (row) =>
          !sheet.hiddenRows.contains(row) || sheet.hiddenRowValues[row] != 0,
    );
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        for (final row in rows) {
          sheet.hiddenRows.add(row);
          sheet.hiddenRowValues[row] = 0;
        }
        _replaceActiveSheet(
          sheet.copyWith(
            hiddenRows: sheet.hiddenRows,
            hiddenRowValues: sheet.hiddenRowValues,
          ),
        );
      }
      _closeTransientMenus();
    });
  }

  void _showHiddenRowsAtSelection() {
    final sheet = _workbook.activeSheet;
    if (!_canEditSheetDefaultCell(sheet)) {
      setState(_closeTransientMenus);
      return;
    }
    final range = _currentSelectionRange(sheet);
    if (range.rowStart > range.rowEnd) {
      setState(_closeTransientMenus);
      return;
    }
    final rows = List<int>.generate(
      range.rowEnd - range.rowStart + 1,
      (offset) => range.rowStart + offset,
    );
    final selectedHiddenRows = rows.where(sheet.hiddenRows.contains).toList();
    final rowsToShow = selectedHiddenRows.isNotEmpty
        ? selectedHiddenRows
        : _contextMenuIsHeader
        ? _adjacentHiddenRowsForSelection(sheet, range)
        : const <int>[];
    final changed = rowsToShow.any(sheet.hiddenRows.contains);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        for (final row in rowsToShow) {
          sheet.hiddenRows.remove(row);
          sheet.hiddenRowValues.remove(row);
        }
        _replaceActiveSheet(
          sheet.copyWith(
            hiddenRows: sheet.hiddenRows,
            hiddenRowValues: sheet.hiddenRowValues,
          ),
        );
      }
      _closeTransientMenus();
    });
  }

  List<int> _adjacentHiddenRowsForSelection(
    FortuneSheet sheet,
    FortuneRange range,
  ) {
    final before = <int>[];
    for (var row = range.rowStart - 1; row >= 0; row -= 1) {
      if (!sheet.hiddenRows.contains(row)) {
        break;
      }
      before.add(row);
    }
    if (before.isNotEmpty) {
      return before;
    }
    final rowEnd = math.max(0, _effectiveRowCount(sheet) - 1);
    final after = <int>[];
    for (var row = range.rowEnd + 1; row <= rowEnd; row += 1) {
      if (!sheet.hiddenRows.contains(row)) {
        break;
      }
      after.add(row);
    }
    return after;
  }

  void _hideColumnAtSelection() {
    final sheet = _workbook.activeSheet;
    if (!_canEditSheetDefaultCell(sheet)) {
      setState(_closeTransientMenus);
      return;
    }
    final range = _currentSelectionRange(sheet);
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      if (_isIndexReadOnly(sheet.colReadOnly, column)) {
        setState(_closeTransientMenus);
        return;
      }
    }
    if (range.columnStart > range.columnEnd) {
      setState(_closeTransientMenus);
      return;
    }
    final columns = List<int>.generate(
      range.columnEnd - range.columnStart + 1,
      (offset) => range.columnStart + offset,
    );
    final changed = columns.any(
      (column) =>
          !sheet.hiddenColumns.contains(column) ||
          sheet.hiddenColumnValues[column] != 0,
    );
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        for (final column in columns) {
          sheet.hiddenColumns.add(column);
          sheet.hiddenColumnValues[column] = 0;
        }
        _replaceActiveSheet(
          sheet.copyWith(
            hiddenColumns: sheet.hiddenColumns,
            hiddenColumnValues: sheet.hiddenColumnValues,
          ),
        );
      }
      _closeTransientMenus();
    });
  }

