  bool get _axisSizeDialogOpen => _axisSizeDialogAxis != null;

  bool _usesMillimeterAxisMenuSizes(FortuneSheet sheet) {
    return fortuneSheetGridClientPhysicalSize(sheet) != null;
  }

  double _axisMenuSizeInputToLogicalPixels(FortuneSheet sheet, double value) {
    if (!_usesMillimeterAxisMenuSizes(sheet)) {
      return value;
    }
    return fortuneMillimetersToLogicalPixels(value);
  }

  String _formatAxisMenuSizeValue(FortuneSheet sheet, double logicalPixels) {
    final value = _usesMillimeterAxisMenuSizes(sheet)
        ? fortuneLogicalPixelsToMillimeters(logicalPixels)
        : logicalPixels;
    return _formatAxisSizeValue(value);
  }

  String _formatAxisSizeValue(double value) {
    if (value == value.roundToDouble()) {
      return value.round().toString();
    }
    return value
        .toStringAsFixed(2)
        .replaceFirst(RegExp(r'0+$'), '')
        .replaceFirst(RegExp(r'\.$'), '');
  }

