  String? _imageInsertDialogCommandAt(Offset local) {
    final rect = _imageInsertDialogRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    if (!_imageInsertIsEditing &&
        fortuneImageInsertFileButtonRect(rect).contains(local)) {
      return 'file';
    }
    if (fortuneImageInsertWidthInputRect(rect).contains(local)) {
      return 'width';
    }
    if (fortuneImageInsertHeightInputRect(rect).contains(local)) {
      return 'height';
    }
    if (fortuneImageInsertLinkButtonRect(rect).contains(local)) {
      return 'link';
    }
    if (fortuneImageInsertRotationInputRect(rect).contains(local)) {
      return 'rotation';
    }
    if (fortuneImageInsertRotateButtonRect(rect).contains(local)) {
      return 'rotate';
    }
    if ((_imageInsertIsEditing || _imageInsertPickResult != null) &&
        fortuneImageInsertConfirmButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    if (fortuneImageInsertCancelButtonRect(rect).contains(local) ||
        fortuneImageInsertCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    return 'modal';
  }

  String? _barcodeDialogCommandAt(Offset local) {
    final rect = _barcodeDialogRect();
    if (rect == null || !rect.contains(local)) {
      if (_barcodeFormatMenuOpen && rect != null) {
        final index = _barcodeFormatMenuIndexAt(local);
        if (index != null) {
          return 'format-$index';
        }
      }
      if (_barcodeTextFontMenuOpen && rect != null) {
        final index = _barcodeTextFontMenuIndexAt(local);
        if (index != null) {
          return 'text-font-$index';
        }
      }
      if (_barcodeTextFontSizeMenuOpen && rect != null) {
        final index = _barcodeTextFontSizeMenuIndexAt(local);
        if (index != null) {
          return 'text-font-size-$index';
        }
      }
      return null;
    }
    if (_barcodeFormatMenuOpen) {
      final index = _barcodeFormatMenuIndexAt(local);
      if (index != null) {
        return 'format-$index';
      }
    }
    if (_barcodeObjectIdMenuOpen) {
      final index = _barcodeObjectIdMenuIndexAt(local);
      if (index != null) {
        return 'object-id-$index';
      }
    }
    if (_barcodeTextFontMenuOpen) {
      final index = _barcodeTextFontMenuIndexAt(local);
      if (index != null) {
        return 'text-font-$index';
      }
    }
    if (_barcodeTextFontSizeMenuOpen) {
      final index = _barcodeTextFontSizeMenuIndexAt(local);
      if (index != null) {
        return 'text-font-size-$index';
      }
    }
    if (fortuneBarcodeObjectIdInputRect(rect).contains(local)) {
      return 'object-id';
    }
    if (fortuneBarcodeTextInputRect(rect).contains(local)) {
      return 'text';
    }
    if (fortuneBarcodeFormatComboRect(rect).contains(local)) {
      return 'format';
    }
    if (fortuneBarcodeWidthInputRect(rect).contains(local)) {
      return 'width';
    }
    if (fortuneBarcodeModuleScaleInputRect(rect).contains(local)) {
      return 'module-scale';
    }
    if (fortuneBarcodeBarHeightInputRect(rect).contains(local)) {
      return 'bar-height';
    }
    if (fortuneBarcodeHeightInputRect(rect).contains(local)) {
      return 'height';
    }
    if (fortuneBarcodeLeadingQuietZoneInputRect(rect).contains(local)) {
      return 'leading-quiet-zone';
    }
    if (fortuneBarcodeTrailingQuietZoneInputRect(rect).contains(local)) {
      return 'trailing-quiet-zone';
    }
    if (fortuneBarcodeShowTextCheckboxRect(rect).contains(local)) {
      return 'show-text';
    }
    if (fortuneBarcodeTextFontComboRect(rect).contains(local)) {
      return 'text-font';
    }
    if (fortuneBarcodeTextFontSizeComboRect(rect).contains(local)) {
      return 'text-font-size';
    }
    if (fortuneBarcodeLinkButtonRect(rect).contains(local)) {
      return 'link';
    }
    if (fortuneBarcodeRotationInputRect(rect).contains(local)) {
      return 'rotation';
    }
    if (fortuneBarcodeRotateButtonRect(rect).contains(local)) {
      return 'rotate';
    }
    if (fortuneBarcodeConfirmButtonRect(rect).contains(local)) {
      return 'confirm';
    }
    if (fortuneBarcodeCancelButtonRect(rect).contains(local) ||
        fortuneBarcodeCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    return 'modal';
  }

  String? _dialogCloseButtonKeyAt(Offset local) {
    final locationMessageRect = _locationMessageDialogRect();
    if (locationMessageRect != null &&
        fortuneLocationMessageCloseButtonRect(
          locationMessageRect,
        ).contains(local)) {
      return 'location-message';
    }
    final screenshotRect = _screenshotDialogRect();
    if (screenshotRect != null &&
        fortuneScreenshotCloseButtonRect(screenshotRect).contains(local)) {
      return 'screenshot';
    }
    final searchRect = _searchDialogRect();
    if (searchRect != null &&
        fortuneSearchCloseButtonRect(searchRect).contains(local)) {
      return 'search';
    }
    final customSortRect = _customSortDialogRect();
    if (customSortRect != null &&
        fortuneCustomSortCloseButtonRect(customSortRect).contains(local)) {
      return 'custom-sort';
    }
    final imageInsertRect = _imageInsertDialogRect();
    if (imageInsertRect != null &&
        fortuneImageInsertCloseButtonRect(imageInsertRect).contains(local)) {
      return 'image-insert';
    }
    final barcodeRect = _barcodeDialogRect();
    if (barcodeRect != null &&
        fortuneBarcodeCloseButtonRect(barcodeRect).contains(local)) {
      return 'barcode';
    }
    final hyperlinkDialogRect = _hyperlinkDialogRect();
    if (_hyperlinkDialogSelectingCellRange &&
        hyperlinkDialogRect != null &&
        fortuneHyperlinkRangeSelectionCloseButtonRect(
          hyperlinkDialogRect,
        ).contains(local)) {
      return 'hyperlink-range';
    }
    final dataVerificationRect = _dataVerificationDialogRect();
    if (dataVerificationRect != null &&
        fortuneDataVerificationCloseButtonRect(
          dataVerificationRect,
        ).contains(local)) {
      return 'data-verification';
    }
    final splitTextRect = _splitTextDialogRect();
    if (splitTextRect != null &&
        fortuneSplitTextCloseButtonRect(splitTextRect).contains(local)) {
      return 'split-text';
    }
    final locationRect = _locationDialogRect();
    if (locationRect != null &&
        fortuneLocationCloseButtonRect(locationRect).contains(local)) {
      return 'location';
    }
    final formatSearchRect = _formatSearchDialogRect();
    if (formatSearchRect != null &&
        fortuneFormatSearchCloseButtonRect(formatSearchRect).contains(local)) {
      return 'format-search';
    }
    final formulaSearchRect = _formulaSearchDialogRect();
    if (formulaSearchRect != null &&
        fortuneFormulaSearchCloseButtonRect(formulaSearchRect).contains(local)) {
      return 'formula-search';
    }
    final conditionRuleRect = _conditionRuleDialogRect();
    if (conditionRuleRect != null &&
        fortuneConditionRuleCloseButtonRect(conditionRuleRect).contains(local)) {
      return 'condition-rule';
    }
    return null;
  }

  bool _updateDialogCloseHover(Offset local) {
    final closeKey = _dialogCloseButtonKeyAt(local);
    if (closeKey != null) {
      if (_dialogCloseHoveredKey != closeKey ||
          _imageInsertHoveredControl != null ||
          _barcodeHoveredControl != null) {
        setState(() {
          _dialogCloseHoveredKey = closeKey;
          _imageInsertHoveredControl = null;
          _barcodeHoveredControl = null;
        });
      }
      _setMouseCursor(SystemMouseCursors.click);
      return true;
    }
    if (_dialogCloseHoveredKey != null) {
      setState(() {
        _dialogCloseHoveredKey = null;
      });
    }
    return false;
  }

  void _activateDialogCloseButton(String key) {
    switch (key) {
      case 'location-message':
        _activateLocationMessageDialogCommand('cancel');
      case 'screenshot':
        _activateScreenshotDialogCommand('close');
      case 'search':
        _activateSearchDialogCommand('close');
      case 'custom-sort':
        _activateCustomSortDialogCommand('cancel');
      case 'image-insert':
        _activateImageInsertDialogCommand('cancel');
      case 'barcode':
        _activateBarcodeDialogCommand('cancel');
      case 'hyperlink-range':
        _activateHyperlinkDialogCommand('cancel-range');
      case 'data-verification':
        _activateDataVerificationDialogCommand('cancel');
      case 'split-text':
        _activateSplitTextDialogCommand('cancel');
      case 'location':
        _activateLocationDialogCommand('cancel');
      case 'format-search':
        _activateFormatSearchDialogCommand('cancel');
      case 'formula-search':
        _activateFormulaSearchDialogCommand('cancel');
      case 'condition-rule':
        _activateConditionRuleDialogCommand('cancel');
    }
  }

  void _activateImageInsertDialogCommand(String? command) {
    if (command == null || command == 'modal') {
      return;
    }
    if (command == 'width') {
      _imageInsertWidthFocusNode.requestFocus();
      return;
    }
    if (command == 'height') {
      _imageInsertHeightFocusNode.requestFocus();
      return;
    }
    if (command == 'rotation') {
      _imageInsertRotationFocusNode.requestFocus();
      return;
    }
    if (command == 'file') {
      unawaited(_pickImageForInsertDialog());
      return;
    }
    if (command == 'link') {
      _toggleImageInsertAspectLock();
      return;
    }
    if (command == 'rotate') {
      _cycleImageInsertRotation();
      return;
    }
    if (command == 'confirm') {
      _commitImageInsertDialog();
      return;
    }
    _cancelImageInsertDialog();
  }

  void _activateBarcodeDialogCommand(String? command) {
    if (command == null || command == 'modal') {
      return;
    }
    if (command == 'text') {
      _barcodeTextFocusNode.requestFocus();
      return;
    }
    if (command == 'object-id') {
      _toggleBarcodeObjectIdMenu();
      return;
    }
    if (command == 'width') {
      _barcodeWidthFocusNode.requestFocus();
      return;
    }
    if (command == 'module-scale') {
      _barcodeModuleScaleFocusNode.requestFocus();
      return;
    }
    if (command == 'bar-height') {
      _barcodeBarHeightFocusNode.requestFocus();
      return;
    }
    if (command == 'height') {
      _barcodeHeightFocusNode.requestFocus();
      return;
    }
    if (command == 'leading-quiet-zone') {
      _barcodeLeadingQuietZoneFocusNode.requestFocus();
      return;
    }
    if (command == 'trailing-quiet-zone') {
      _barcodeTrailingQuietZoneFocusNode.requestFocus();
      return;
    }
    if (command == 'show-text') {
      setState(() {
        _barcodeShowHumanReadableText = !_barcodeShowHumanReadableText;
      });
      return;
    }
    if (command == 'rotation') {
      _barcodeRotationFocusNode.requestFocus();
      return;
    }
    if (command == 'format') {
      _toggleBarcodeFormatMenu();
      return;
    }
    if (command == 'text-font') {
      _toggleBarcodeTextFontMenu();
      return;
    }
    if (command == 'text-font-size') {
      _toggleBarcodeTextFontSizeMenu();
      return;
    }
    if (command.startsWith('format-')) {
      final index = int.tryParse(command.substring('format-'.length));
      if (index != null) {
        _selectBarcodeFormat(index);
      }
      return;
    }
    if (command.startsWith('object-id-')) {
      final index = int.tryParse(command.substring('object-id-'.length));
      if (index != null) {
        _selectBarcodeObjectId(index);
      }
      return;
    }
    if (command.startsWith('text-font-size-')) {
      final index = int.tryParse(command.substring('text-font-size-'.length));
      if (index != null) {
        _selectBarcodeTextFontSize(index);
      }
      return;
    }
    if (command.startsWith('text-font-')) {
      final index = int.tryParse(command.substring('text-font-'.length));
      if (index != null) {
        _selectBarcodeTextFont(index);
      }
      return;
    }
    if (command == 'link') {
      _toggleBarcodeAspectLock();
      return;
    }
    if (command == 'rotate') {
      _cycleBarcodeRotation();
      return;
    }
    if (command == 'confirm') {
      if (!_barcodeCanConfirm) {
        return;
      }
      unawaited(_commitBarcodeDialog());
      return;
    }
    _cancelBarcodeDialog();
  }

