  void _commitAxisSizeDialog() {
    final axis = _axisSizeDialogAxis;
    final index = _axisSizeDialogIndex;
    final inputExtent = double.tryParse(_axisSizeEditorController.text.trim());
    if (axis == null ||
        index == null ||
        inputExtent == null ||
        inputExtent <= 0) {
      _axisSizeEditorFocusNode.requestFocus();
      return;
    }
    final sheet = _workbook.activeSheet;
    if (!_canEditSheetDefaultCell(sheet)) {
      setState(() {
        _axisSizeDialogAxis = null;
        _axisSizeDialogIndex = null;
      });
      _focusNode.requestFocus();
      return;
    }
    final extent = _axisMenuSizeInputToLogicalPixels(sheet, inputExtent);
    final range = _currentSelectionRange(sheet);
    final hasChange = axis == 'row'
        ? Iterable<int>.generate(
            range.rowEnd - range.rowStart + 1,
            (offset) => range.rowStart + offset,
          ).any(
            (row) =>
                !_isIndexReadOnly(sheet.rowReadOnly, row) &&
                (sheet.rowHeights[row] != extent ||
                    sheet.customHeight[row] != 1),
          )
        : Iterable<int>.generate(
            range.columnEnd - range.columnStart + 1,
            (offset) => range.columnStart + offset,
          ).any(
            (column) =>
                !_isIndexReadOnly(sheet.colReadOnly, column) &&
                (sheet.columnWidths[column] != extent ||
                    sheet.customWidth[column] != 1),
          );
    if (hasChange) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (hasChange) {
        if (axis == 'row') {
          final rowHeights = Map<int, double>.from(sheet.rowHeights);
          final customHeight = Map<int, double>.from(sheet.customHeight);
          for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
            if (!_isIndexReadOnly(sheet.rowReadOnly, row)) {
              rowHeights[row] = extent;
              customHeight[row] = 1;
            }
          }
          _replaceActiveSheet(
            sheet.copyWith(rowHeights: rowHeights, customHeight: customHeight),
          );
        } else {
          final columnWidths = Map<int, double>.from(sheet.columnWidths);
          final customWidth = Map<int, double>.from(sheet.customWidth);
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          ) {
            if (!_isIndexReadOnly(sheet.colReadOnly, column)) {
              columnWidths[column] = extent;
              customWidth[column] = 1;
            }
          }
          _replaceActiveSheet(
            sheet.copyWith(
              columnWidths: columnWidths,
              customWidth: customWidth,
            ),
          );
        }
      }
      _axisSizeDialogAxis = null;
      _axisSizeDialogIndex = null;
    });
  }

  void _sortSelectedRange({
    required bool isAscending,
    int sortColumnOffset = 0,
    bool? hasHeader,
  }) {
    final sheet = _workbook.activeSheet;
    final range = _rawSelectionRange(sheet.selectionSave);
    if (range == null || range.rowStart == range.rowEnd) {
      setState(_closeTransientMenus);
      return;
    }
    final rowStart = range.rowStart.clamp(0, _effectiveRowCount(sheet) - 1);
    final rowEnd = range.rowEnd.clamp(rowStart, _effectiveRowCount(sheet) - 1);
    final columnStart = range.columnStart.clamp(
      0,
      _effectiveColumnCount(sheet) - 1,
    );
    final columnEnd = range.columnEnd.clamp(
      columnStart,
      _effectiveColumnCount(sheet) - 1,
    );
    final sortColumn = (columnStart + sortColumnOffset).clamp(
      columnStart,
      columnEnd,
    );
    final sortRows = hasHeader == null
        ? _sortDataRowRange(sheet, rowStart, rowEnd, columnStart)
        : FortuneRange(
            rowStart: hasHeader ? math.min(rowStart + 1, rowEnd) : rowStart,
            rowEnd: rowEnd,
            columnStart: columnStart,
            columnEnd: columnStart,
          );
    if (sortRows == null || sortRows.rowStart == sortRows.rowEnd) {
      setState(_closeTransientMenus);
      return;
    }
    _sortRowsInRange(
      sheet,
      rowStart: rowStart,
      rowEnd: rowEnd,
      sortRowStart: sortRows.rowStart,
      sortRowEnd: sortRows.rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
      sortColumn: sortColumn,
      isAscending: isAscending,
    );
  }

  void _sortFilterRange(int column, {required bool isAscending}) {
    final sheet = _workbook.activeSheet;
    final key = _filterKeyForColumn(sheet, column);
    final raw = sheet.filter[key];
    final filterSelectRange = _filterSelectRange(sheet);
    final rawConfig = raw is Map
        ? Map<String, Object?>.from(raw)
        : <String, Object?>{};
    final headerRange = raw is Map
        ? _filterConfigHeaderRange(sheet, rawConfig, filterSelectRange)
        : (
            filterSelectRange?.rowStart ?? 0,
            filterSelectRange?.rowEnd ?? _effectiveRowCount(sheet) - 1,
          );
    final columnRange = raw is Map
        ? _filterConfigColumnRange(rawConfig, filterSelectRange, column)
        : (
            filterSelectRange?.columnStart ?? column,
            filterSelectRange?.columnEnd ?? column,
          );
    final rowCount = _effectiveRowCount(sheet);
    final columnCount = _effectiveColumnCount(sheet);
    final rowStart = math
        .min(headerRange.$1, headerRange.$2)
        .clamp(0, rowCount - 1);
    final rowEnd = math
        .max(headerRange.$1, headerRange.$2)
        .clamp(0, rowCount - 1);
    final sortRowStart = math.min(rowStart + 1, rowEnd);
    final columnStart = math
        .min(columnRange.$1, columnRange.$2)
        .clamp(0, columnCount - 1);
    final columnEnd = math
        .max(columnRange.$1, columnRange.$2)
        .clamp(0, columnCount - 1);
    if (sortRowStart >= rowEnd) {
      setState(_closeTransientMenus);
      return;
    }
    _sortRowsInRange(
      sheet,
      rowStart: rowStart,
      rowEnd: rowEnd,
      sortRowStart: sortRowStart,
      sortRowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
      sortColumn: column.clamp(columnStart, columnEnd),
      isAscending: isAscending,
    );
  }

  void _sortRowsInRange(
    FortuneSheet sheet, {
    required int rowStart,
    required int rowEnd,
    required int sortRowStart,
    required int sortRowEnd,
    required int columnStart,
    required int columnEnd,
    required int sortColumn,
    required bool isAscending,
  }) {
    final editRange = FortuneRange(
      rowStart: sortRowStart,
      rowEnd: sortRowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
    );
    if (!_canEditRange(sheet, editRange)) {
      setState(_closeTransientMenus);
      return;
    }
    if (_rangeContainsMergedCell(
      sheet,
      sortRowStart,
      sortRowEnd,
      columnStart,
      columnEnd,
    )) {
      setState(_closeTransientMenus);
      return;
    }

    final rows = [
      for (var row = sortRowStart; row <= sortRowEnd; row += 1) row,
    ];
    final originalIndex = {for (var i = 0; i < rows.length; i += 1) rows[i]: i};
    rows.sort((leftRow, rightRow) {
      final compare = _compareSortCells(
        sheet.cells[FortuneCellCoord(leftRow, sortColumn)],
        sheet.cells[FortuneCellCoord(rightRow, sortColumn)],
        isAscending: isAscending,
      );
      if (compare != 0) {
        return compare;
      }
      return originalIndex[leftRow]!.compareTo(originalIndex[rightRow]!);
    });
    if (rows.indexed.every((entry) => entry.$2 == sortRowStart + entry.$1)) {
      setState(_closeTransientMenus);
      return;
    }

    _recordUndoSnapshot();

    final oldToNewRow = <int, int>{};
    for (var offset = 0; offset < rows.length; offset += 1) {
      final newRow = sortRowStart + offset;
      final oldRow = rows[offset];
      oldToNewRow[oldRow] = newRow;
    }

    setState(() {
      _replaceCells(
        sheet,
        _sortRangeCells(
          sheet.cells,
          rowStart: rowStart,
          rowEnd: rowEnd,
          columnStart: columnStart,
          columnEnd: columnEnd,
          oldToNewRow: oldToNewRow,
        ),
      );
      _replaceCoordSet(
        sheet.nullCells,
        _sortRangeCoords(
          sheet.nullCells,
          columnStart: columnStart,
          columnEnd: columnEnd,
          oldToNewRow: oldToNewRow,
        ),
      );
      _replaceObjectMap(
        sheet.dataVerification,
        _sortCellKeyMetadata(
          sheet.dataVerification,
          columnStart: columnStart,
          columnEnd: columnEnd,
          oldToNewRow: oldToNewRow,
        ),
      );
      _replaceObjectMap(
        sheet.hyperlinks,
        _sortCellKeyMetadata(
          sheet.hyperlinks,
          columnStart: columnStart,
          columnEnd: columnEnd,
          oldToNewRow: oldToNewRow,
        ),
      );
      _recalculateWorkbookFormulas();
      _closeTransientMenus();
    });
  }

  void _showCustomSortDialog() {
    final sheet = _workbook.activeSheet;
    final range = _rawSelectionRange(sheet.selectionSave);
    if (range == null || range.rowStart == range.rowEnd) {
      setState(_closeTransientMenus);
      return;
    }
    if (!_canEditRange(sheet, range)) {
      setState(_closeTransientMenus);
      return;
    }
    final columnCount = math.max(1, range.columnEnd - range.columnStart + 1);
    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _customSortDialogOpen = true;
      _customSortHasHeader = false;
      _customSortAscending = true;
      _customSortColumnOffset = _customSortColumnOffset.clamp(
        0,
        columnCount - 1,
      );
    });
  }

  void _showConditionRuleDialog(String type, {String? duplicateValue}) {
    final sheet = _workbook.activeSheet;
    if (!_canEditRange(sheet, _conditionRuleSelectionRange(sheet))) {
      setState(_closeTransientMenus);
      return;
    }
    setState(() {
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _conditionRuleDialogOpen = true;
      _conditionRuleType = type;
      _conditionRuleDuplicateValue =
          duplicateValue ?? fortuneConditionRuleDuplicateValue;
      _conditionRuleDuplicateMenuOpen = false;
      _conditionRuleTextColorEnabled = true;
      _conditionRuleCellColorEnabled = true;
      _conditionRuleTextColor = fortuneConditionRuleDefaultTextColor;
      _conditionRuleCellColor = fortuneConditionRuleDefaultCellColor;
      _conditionRuleEditorController.text = _conditionRuleIsProjectType(type)
          ? fortuneConditionRuleDefaultProjectValue
          : '';
      _conditionRuleSecondEditorController.text = '';
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted &&
          _conditionRuleDialogOpen &&
          _conditionRuleHasTextInput(_conditionRuleType)) {
        _conditionRuleEditorFocusNode.requestFocus();
      }
    });
  }

  Rect? _conditionRuleDialogRect([Size? overrideSize]) {
    if (!_conditionRuleDialogOpen) {
      return null;
    }
    final size = overrideSize ?? context.size;
    if (size == null) {
      return null;
    }
    final height = _conditionRuleDialogHeight(_conditionRuleType);
    return fortuneConditionRuleDialogRect(size, height);
  }

  double _conditionRuleDialogHeight(String type) {
    if (type == fortuneConditionRuleBetweenType) {
      return fortuneConditionRuleExpandedDialogHeight;
    }
    if (_conditionRuleIsAverageType(type)) {
      return fortuneConditionRuleAverageDialogHeight;
    }
    return fortuneConditionRuleDefaultDialogHeight;
  }

  Rect? _conditionRuleInputRect([Size? overrideSize]) {
    if (!_conditionRuleHasTextInput(_conditionRuleType)) {
      return null;
    }
    final rect = _conditionRuleDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    final width = _conditionRuleType == fortuneConditionRuleBetweenType
        ? fortuneConditionRuleBetweenInputBoxWidth
        : fortuneConditionRuleInputBoxWidth;
    final contentLeft =
        rect.left + fortuneConditionRuleContentPaddingHorizontal;
    final left = _conditionRuleIsProjectType(_conditionRuleType)
        ? contentLeft +
              _conditionRuleProjectPrefixWidth(_conditionRuleType) +
              fortuneConditionRuleProjectInputMargin
        : contentLeft;
    return Rect.fromLTWH(
      left,
      rect.top + fortuneConditionRuleControlTop,
      width,
      fortuneConditionRuleInputBoxHeight,
    );
  }

  Rect? _conditionRuleSecondInputRect([Size? overrideSize]) {
    if (_conditionRuleType != fortuneConditionRuleBetweenType) {
      return null;
    }
    final rect = _conditionRuleDialogRect(overrideSize);
    if (rect == null) {
      return null;
    }
    final firstInputRight =
        rect.left +
        fortuneConditionRuleContentPaddingHorizontal +
        fortuneConditionRuleBetweenInputBoxWidth;
    return Rect.fromLTWH(
      firstInputRight +
          fortuneConditionRuleBetweenSeparatorMargin * 2 +
          fortuneConditionRuleBetweenSeparatorWidth,
      rect.top + fortuneConditionRuleControlTop,
      fortuneConditionRuleBetweenInputBoxWidth,
      fortuneConditionRuleInputBoxHeight,
    );
  }

  String? _conditionRuleDialogCommandAt(Offset local) {
    final rect = _conditionRuleDialogRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    if (fortuneConditionRuleCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    if (_conditionRuleType == fortuneConditionRuleDuplicateType) {
      final selectRect = _conditionRuleDuplicateSelectRect(rect);
      if (_conditionRuleDuplicateMenuOpen) {
        for (
          var index = 0;
          index < fortuneConditionRuleDuplicateValues.length;
          index += 1
        ) {
          final optionRect = Rect.fromLTWH(
            selectRect.left,
            selectRect.bottom + index * fortuneConditionRuleSelectOptionHeight,
            selectRect.width,
            fortuneConditionRuleSelectOptionHeight,
          );
          if (optionRect.contains(local)) {
            return 'duplicate-$index';
          }
        }
      }
      if (selectRect.contains(local)) {
        return 'duplicate-toggle';
      }
    }
    final setTop = _conditionRuleSetAsTop(rect, _conditionRuleType);
    final contentLeft =
        rect.left + fortuneConditionRuleContentPaddingHorizontal;
    final contentWidth =
        rect.width - fortuneConditionRuleContentPaddingHorizontal * 2;
    final textColorRow = Rect.fromLTWH(
      contentLeft,
      setTop + fortuneConditionRuleSetBoxTopOffset,
      contentWidth,
      fortuneConditionRuleSetRowHeight,
    );
    for (
      var index = 0;
      index < fortuneConditionRuleTextColorChoices.length;
      index += 1
    ) {
      if (_conditionRulePaletteRect(
        textColorRow,
        index,
        fortuneConditionRuleTextColorChoices.length,
      ).contains(local)) {
        return 'text-color-$index';
      }
    }
    if (_conditionRuleToggleRect(textColorRow).contains(local)) {
      return 'toggle-text-color';
    }
    final cellColorRow = Rect.fromLTWH(
      contentLeft,
      setTop +
          fortuneConditionRuleSetBoxTopOffset +
          fortuneConditionRuleSetRowHeight,
      contentWidth,
      fortuneConditionRuleSetRowHeight,
    );
    for (
      var index = 0;
      index < fortuneConditionRuleCellColorChoices.length;
      index += 1
    ) {
      if (_conditionRulePaletteRect(
        cellColorRow,
        index,
        fortuneConditionRuleCellColorChoices.length,
      ).contains(local)) {
        return 'cell-color-$index';
      }
    }
    if (_conditionRuleToggleRect(cellColorRow).contains(local)) {
      return 'toggle-cell-color';
    }
    final confirmRect = fortuneConditionRuleConfirmButtonRect(rect);
    if (confirmRect.contains(local)) {
      return 'confirm';
    }
    final cancelRect = fortuneConditionRuleCancelButtonRect(rect);
    if (cancelRect.contains(local)) {
      return 'cancel';
    }
    return 'modal';
  }

  void _activateConditionRuleDialogCommand(String? command) {
    if (command == null || command == 'modal') {
      return;
    }
    if (command == 'cancel') {
      setState(() {
        _resetConditionRuleDialogState();
      });
      return;
    }
    if (command == 'confirm') {
      _conditionRuleDuplicateMenuOpen = false;
      _commitConditionRuleDialog();
      return;
    }
    if (command == 'duplicate-toggle') {
      setState(() {
        _conditionRuleDuplicateMenuOpen = !_conditionRuleDuplicateMenuOpen;
      });
      return;
    }
    if (command.startsWith('duplicate-')) {
      final optionIndex = int.tryParse(command.substring('duplicate-'.length));
      if (optionIndex == null ||
          optionIndex < 0 ||
          optionIndex >= fortuneConditionRuleDuplicateValues.length) {
        return;
      }
      setState(() {
        _conditionRuleDuplicateValue =
            fortuneConditionRuleDuplicateValues[optionIndex];
        _conditionRuleDuplicateMenuOpen = false;
      });
      return;
    }
    if (command == 'toggle-text-color') {
      setState(() {
        _conditionRuleTextColorEnabled = !_conditionRuleTextColorEnabled;
      });
      return;
    }
    if (command == 'toggle-cell-color') {
      setState(() {
        _conditionRuleCellColorEnabled = !_conditionRuleCellColorEnabled;
      });
      return;
    }
    if (command.startsWith('text-color-')) {
      final index = int.tryParse(command.substring('text-color-'.length));
      if (index != null &&
          index >= 0 &&
          index < fortuneConditionRuleTextColorChoices.length) {
        setState(() {
          _conditionRuleTextColor = fortuneConditionRuleTextColorChoices[index];
          _conditionRuleTextColorEnabled = true;
        });
      }
      return;
    }
    if (command.startsWith('cell-color-')) {
      final index = int.tryParse(command.substring('cell-color-'.length));
      if (index != null &&
          index >= 0 &&
          index < fortuneConditionRuleCellColorChoices.length) {
        setState(() {
          _conditionRuleCellColor = fortuneConditionRuleCellColorChoices[index];
          _conditionRuleCellColorEnabled = true;
        });
      }
    }
  }

  void _commitConditionRuleDialog() {
    if (_conditionRuleType == fortuneConditionRuleDuplicateType) {
      _appendConditionRule(
        _workbook.activeSheet,
        fortuneConditionRuleDuplicateType,
        [_conditionRuleDuplicateValue],
      );
      return;
    }
    if (_conditionRuleIsAverageType(_conditionRuleType)) {
      _appendConditionRule(_workbook.activeSheet, _conditionRuleType, [
        _conditionRuleType,
      ]);
      return;
    }
    final value = _conditionRuleEditorController.text.trim();
    final secondValue = _conditionRuleSecondEditorController.text.trim();
    if (!_isValidConditionRuleValue(_conditionRuleType, value, secondValue)) {
      setState(() {
        _resetConditionRuleDialogState();
      });
      return;
    }
    final sheet = _workbook.activeSheet;
    final values = _conditionRuleType == fortuneConditionRuleBetweenType
        ? [value, secondValue]
        : [value];
    _appendConditionRule(sheet, _conditionRuleType, values);
  }

  bool _conditionRuleIsProjectType(String type) {
    return fortuneConditionRuleProjectTypes.contains(type);
  }

  double _conditionRuleProjectPrefixWidth(String type) {
    if (fortuneConditionRuleProjectTopTypes.contains(type)) {
      return fortuneConditionRuleProjectTopLabelWidth;
    }
    if (fortuneConditionRuleProjectBottomTypes.contains(type)) {
      return fortuneConditionRuleProjectBottomLabelWidth;
    }
    return 0;
  }

  bool _conditionRuleIsAverageType(String type) {
    return fortuneConditionRuleAverageTypes.contains(type);
  }

  bool _conditionRuleHasTextInput(String type) {
    return type != fortuneConditionRuleDuplicateType &&
        !_conditionRuleIsAverageType(type);
  }

  void _appendConditionRule(
    FortuneSheet sheet,
    String ruleType,
    List<String> values,
  ) {
    final range = _conditionRuleSelectionRange(sheet);
    if (!_canEditRange(sheet, range)) {
      setState(() {
        _resetConditionRuleDialogState();
        _closeTransientMenus();
      });
      return;
    }
    final rule = _conditionRuleForSelection(sheet, ruleType, values);
    final existing = sheet.conditionFormats is List
        ? [...sheet.conditionFormats! as List]
        : <Object?>[];
    existing.add(rule);
    _recordUndoSnapshot();
    setState(() {
      _replaceActiveSheet(
        sheet.copyWith(
          conditionFormats: existing,
          hasRawConditionFormats: true,
        ),
      );
      _resetConditionRuleDialogState();
      _closeTransientMenus();
    });
  }

  Map<String, Object?> _conditionRuleForSelection(
    FortuneSheet sheet,
    String type,
    List<String> values,
  ) {
    final range = _conditionRuleSelectionRange(sheet);
    return {
      'type': 'default',
      'cellrange': [
        {
          'row': [range.rowStart, range.rowEnd],
          'column': [range.columnStart, range.columnEnd],
        },
      ],
      'conditionName': type,
      'conditionValue': values,
      'format': _conditionRuleFormat(),
    };
  }

  FortuneRange _conditionRuleSelectionRange(FortuneSheet sheet) {
    return _rawSelectionRange(sheet.selectionSave) ??
        FortuneRange(
          rowStart: selection.row,
          rowEnd: selection.row,
          columnStart: selection.column,
          columnEnd: selection.column,
        );
  }

  bool _canEditConditionFormatRules(FortuneSheet sheet, Object? rules) {
    if (rules is! List) {
      return true;
    }
    for (final rule in rules) {
      if (rule is! Map) {
        continue;
      }
      for (final range in _conditionFormatRuleRanges(rule)) {
        if (!_canEditRange(sheet, range)) {
          return false;
        }
      }
    }
    return true;
  }

  List<FortuneRange> _conditionFormatRuleRanges(Map rule) {
    final rawRanges = rule['cellrange'];
    if (rawRanges is! List) {
      return const <FortuneRange>[];
    }
    final ranges = <FortuneRange>[];
    for (final rawRange in rawRanges) {
      if (rawRange is! Map) {
        continue;
      }
      final row = rawRange['row'];
      final column = rawRange['column'];
      if (row is! List ||
          row.length < 2 ||
          column is! List ||
          column.length < 2) {
        continue;
      }
      final rowStart = _intValue(row[0]);
      final rowEnd = _intValue(row[1]);
      final columnStart = _intValue(column[0]);
      final columnEnd = _intValue(column[1]);
      if (rowStart == null ||
          rowEnd == null ||
          columnStart == null ||
          columnEnd == null) {
        continue;
      }
      ranges.add(
        FortuneRange(
          rowStart: math.min(rowStart, rowEnd),
          rowEnd: math.max(rowStart, rowEnd),
          columnStart: math.min(columnStart, columnEnd),
          columnEnd: math.max(columnStart, columnEnd),
        ),
      );
    }
    return ranges;
  }

  Map<String, Object?> _conditionRuleFormat() {
    return {
      'textColor': _conditionRuleTextColorEnabled
          ? _conditionRuleTextColor
          : null,
      'cellColor': _conditionRuleCellColorEnabled
          ? _conditionRuleCellColor
          : null,
    };
  }

  Rect _conditionRuleToggleRect(Rect row) {
    return Rect.fromLTWH(
      row.left + fortuneConditionRuleSetRowPaddingHorizontal,
      row.top,
      fortuneConditionRuleSetToggleWidth,
      row.height,
    );
  }

  Rect _conditionRulePaletteRect(Rect row, int index, int count) {
    final paletteWidth =
        count * fortuneConditionRuleColorSwatchSize +
        (count - 1) * fortuneConditionRuleColorSwatchGap;
    final left =
        row.right -
        fortuneConditionRuleSetRowPaddingHorizontal -
        paletteWidth +
        index *
            (fortuneConditionRuleColorSwatchSize +
                fortuneConditionRuleColorSwatchGap);
    final top =
        row.top +
        fortuneConditionRuleSetRowPaddingVertical +
        (fortuneConditionRuleSetColorLineHeight -
                fortuneConditionRuleColorSwatchSize) /
            2;
    return Rect.fromLTWH(
      left,
      top,
      fortuneConditionRuleColorSwatchSize,
      fortuneConditionRuleColorSwatchSize,
    );
  }

  Rect _conditionRuleDuplicateSelectRect(Rect dialogRect) {
    return Rect.fromLTWH(
      dialogRect.left + fortuneConditionRuleContentPaddingHorizontal,
      dialogRect.top + fortuneConditionRuleControlTop,
      fortuneConditionRuleSelectBoxWidth,
      fortuneConditionRuleSelectBoxHeight,
    );
  }

  double _conditionRuleSetAsTop(Rect rect, String type) {
    if (type == fortuneConditionRuleBetweenType) {
      return rect.top + fortuneConditionRuleDefaultSetTop;
    }
    if (_conditionRuleIsAverageType(type)) {
      return rect.top + fortuneConditionRuleAverageSetTop;
    }
    return rect.top + fortuneConditionRuleDefaultSetTop;
  }

  bool _isValidConditionRuleValue(
    String type,
    String value,
    String secondValue,
  ) {
    if (value.isEmpty) {
      return false;
    }
    return switch (type) {
      String numericType
          when fortuneConditionRuleNumericComparisonTypes.contains(
            numericType,
          ) =>
        double.tryParse(value) != null,
      fortuneConditionRuleBetweenType =>
        secondValue.isNotEmpty &&
            double.tryParse(value) != null &&
            double.tryParse(secondValue) != null,
      String projectType
          when fortuneConditionRuleProjectTypes.contains(projectType) =>
        _isValidConditionProjectValue(value),
      _ => true,
    };
  }

  bool _isValidConditionProjectValue(String value) {
    final parsed = int.tryParse(value);
    return parsed != null &&
        parsed.toString() == value &&
        parsed >= fortuneConditionRuleMinProjectValue &&
        parsed <= fortuneConditionRuleMaxProjectValue;
  }

  Rect? _customSortDialogRect() {
    if (!_customSortDialogOpen) {
      return null;
    }
    final size = context.size;
    if (size == null) {
      return null;
    }
    final optionCount = _customSortColumnLabels().length
        .clamp(1, fortuneCustomSortDialogMaxVisibleColumns)
        .toInt();
    return fortuneCustomSortDialogRect(size, optionCount);
  }

  String? _customSortDialogCommandAt(Offset local) {
    final rect = _customSortDialogRect();
    if (rect == null || !rect.contains(local)) {
      return null;
    }
    if (fortuneCustomSortCloseButtonRect(rect).contains(local)) {
      return 'cancel';
    }
    final headerRect = Rect.fromLTWH(rect.left + 18, rect.top + 51, 150, 24);
    if (headerRect.contains(local)) {
      return 'toggle-header';
    }
    final labels = _customSortColumnLabels();
    final visibleCount = labels.length
        .clamp(1, fortuneCustomSortDialogMaxVisibleColumns)
        .toInt();
    for (var index = 0; index < visibleCount; index += 1) {
      final row = fortuneCustomSortColumnRowRect(rect, index);
      if (row.contains(local)) {
        return 'column-$index';
      }
    }
    final ascRect = Rect.fromLTWH(rect.right - 118, rect.top + 88, 90, 24);
    if (ascRect.contains(local)) {
      return 'ascending';
    }
    final descRect = fortuneCustomSortDescendingHitRect(rect);
    if (descRect.contains(local)) {
      return 'descending';
    }
    final confirmRect = fortuneCustomSortConfirmButtonRect(rect);
    if (confirmRect.contains(local)) {
      return 'confirm';
    }
    return 'modal';
  }

  void _activateCustomSortDialogCommand(String? command) {
    if (command == null || command == 'modal') {
      return;
    }
    if (command == 'confirm') {
      _sortSelectedRange(
        isAscending: _customSortAscending,
        sortColumnOffset: _customSortColumnOffset,
        hasHeader: _customSortHasHeader,
      );
      return;
    }
    setState(() {
      if (command == 'cancel') {
        _customSortDialogOpen = false;
        return;
      }
      if (command == 'toggle-header') {
        _customSortHasHeader = !_customSortHasHeader;
        return;
      }
      if (command == 'ascending') {
        _customSortAscending = true;
        return;
      }
      if (command == 'descending') {
        _customSortAscending = false;
        return;
      }
      if (command.startsWith('column-')) {
        final index = int.tryParse(command.substring('column-'.length));
        if (index != null) {
          _customSortColumnOffset = index;
        }
      }
    });
  }

  List<String> _customSortColumnLabels() {
    final sheet = _workbook.activeSheet;
    final range = _rawSelectionRange(sheet.selectionSave);
    if (range == null) {
      return const ['A'];
    }
    final labels = <String>[];
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      if (_customSortHasHeader) {
        final cell = sheet.cells[FortuneCellCoord(range.rowStart, column)];
        final label = (cell?.displayValue ?? cell?.value ?? '').trim();
        labels.add(label.isEmpty ? 'Column ${_columnName(column)}' : label);
      } else {
        labels.add(_columnName(column));
      }
    }
    return labels;
  }

  FortuneRange? _rawSelectionRange(Object? raw) {
    if (raw is! List || raw.isEmpty) {
      return null;
    }
    final first = raw.first;
    if (first is! Map) {
      return null;
    }
    final row = first['row'];
    final column = first['column'];
    if (row is! List ||
        row.length < 2 ||
        column is! List ||
        column.length < 2) {
      return null;
    }
    final rowStart = _intValue(row[0]);
    final rowEnd = _intValue(row[1]);
    final columnStart = _intValue(column[0]);
    final columnEnd = _intValue(column[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null) {
      return null;
    }
    return FortuneRange(
      rowStart: math.min(rowStart, rowEnd),
      rowEnd: math.max(rowStart, rowEnd),
      columnStart: math.min(columnStart, columnEnd),
      columnEnd: math.max(columnStart, columnEnd),
    );
  }

  FortuneRange? _sortDataRowRange(
    FortuneSheet sheet,
    int rowStart,
    int rowEnd,
    int columnStart,
  ) {
    int? sortStart;
    int? sortEnd;
    for (var row = rowStart; row <= rowEnd; row += 1) {
      final cell = sheet.cells[FortuneCellCoord(row, columnStart)];
      if (cell == null || cell.merge != null) {
        continue;
      }
      final value = _sortValue(cell);
      if (value == null) {
        continue;
      }
      if (sortStart == null && _containsHan(value)) {
        sortStart = row + 1;
        sortEnd = row + 1;
        continue;
      }
      sortStart ??= row;
      sortEnd = row;
    }
    if (sortStart == null || sortEnd == null || sortStart > rowEnd) {
      return null;
    }
    return FortuneRange(
      rowStart: sortStart,
      rowEnd: sortEnd,
      columnStart: columnStart,
      columnEnd: columnStart,
    );
  }

  bool _containsHan(String value) {
    return RegExp(r'[\u4e00-\u9fa5]').hasMatch(value);
  }

  bool _rangeContainsMergedCell(
    FortuneSheet sheet,
    int rowStart,
    int rowEnd,
    int columnStart,
    int columnEnd,
  ) {
    for (var row = rowStart; row <= rowEnd; row += 1) {
      for (var column = columnStart; column <= columnEnd; column += 1) {
        if (sheet.cells[FortuneCellCoord(row, column)]?.merge != null) {
          return true;
        }
      }
    }
    return false;
  }

  int _compareSortCells(
    FortuneCell? left,
    FortuneCell? right, {
    required bool isAscending,
  }) {
    final leftValue = _sortValue(left);
    final rightValue = _sortValue(right);
    if (leftValue == null && rightValue == null) {
      return 0;
    }
    if (leftValue == null) {
      return 1;
    }
    if (rightValue == null) {
      return -1;
    }
    final leftNumber = num.tryParse(leftValue);
    final rightNumber = num.tryParse(rightValue);
    if (leftNumber != null && rightNumber != null) {
      final compare = leftNumber.compareTo(rightNumber);
      return isAscending ? compare : -compare;
    }
    if (leftNumber != null) {
      return isAscending ? -1 : 1;
    }
    if (rightNumber != null) {
      return isAscending ? 1 : -1;
    }
    final compare = leftValue.compareTo(rightValue);
    return isAscending ? compare : -compare;
  }

  String? _sortValue(FortuneCell? cell) {
    if (cell == null) {
      return null;
    }
    final value = cell.value.trim();
    return value.isEmpty ? null : value;
  }

  Map<FortuneCellCoord, FortuneCell> _sortRangeCells(
    Map<FortuneCellCoord, FortuneCell> cells, {
    required int rowStart,
    required int rowEnd,
    required int columnStart,
    required int columnEnd,
    required Map<int, int> oldToNewRow,
  }) {
    final sorted = <FortuneCellCoord, FortuneCell>{};
    for (final entry in cells.entries) {
      final coord = entry.key;
      final newRow = oldToNewRow[coord.row];
      if (newRow == null ||
          coord.column < columnStart ||
          coord.column > columnEnd) {
        sorted[coord] = entry.value;
        continue;
      }
      final rowDelta = newRow - coord.row;
      final nextCoord = FortuneCellCoord(newRow, coord.column);
      sorted[nextCoord] = _cellWithSortedRow(entry.value, rowDelta: rowDelta);
    }
    return sorted;
  }

  Set<FortuneCellCoord> _sortRangeCoords(
    Set<FortuneCellCoord> coords, {
    required int columnStart,
    required int columnEnd,
    required Map<int, int> oldToNewRow,
  }) {
    return {
      for (final coord in coords)
        if (oldToNewRow[coord.row] case final newRow?
            when coord.column >= columnStart && coord.column <= columnEnd)
          FortuneCellCoord(newRow, coord.column)
        else
          coord,
    };
  }

  Map<String, Object?> _sortCellKeyMetadata(
    Map<String, Object?> values, {
    required int columnStart,
    required int columnEnd,
    required Map<int, int> oldToNewRow,
  }) {
    return {
      for (final entry in values.entries)
        _sortedCellKey(
          entry.key,
          columnStart: columnStart,
          columnEnd: columnEnd,
          oldToNewRow: oldToNewRow,
        ): _sortCellKeyMetadataValue(
          entry.value,
          oldToNewRow,
        ),
    };
  }

  Object? _sortCellKeyMetadataValue(Object? value, Map<int, int> oldToNewRow) {
    if (value is! Map) {
      return value;
    }
    final next = <String, Object?>{};
    value.forEach((key, entryValue) {
      if (key == 'r') {
        final row = _intValue(entryValue);
        if (row != null && oldToNewRow.containsKey(row)) {
          next['$key'] = oldToNewRow[row];
          return;
        }
      }
      next['$key'] = entryValue;
    });
    return next;
  }

  String _sortedCellKey(
    String key, {
    required int columnStart,
    required int columnEnd,
    required Map<int, int> oldToNewRow,
  }) {
    final coord = _coordFromKey(key);
    if (coord == null ||
        coord.column < columnStart ||
        coord.column > columnEnd) {
      return key;
    }
    final newRow = oldToNewRow[coord.row];
    return newRow == null ? key : '${newRow}_${coord.column}';
  }

  FortuneCell _cellWithSortedRow(FortuneCell cell, {required int rowDelta}) {
    if (rowDelta == 0) {
      return cell;
    }
    var next = _cellWithShiftedMetadata(
      cell,
      rowFrom: 0,
      rowDelta: rowDelta,
      shiftCommentTop: true,
      commentTopDelta: _defaultRowExtent(_workbook.activeSheet) * rowDelta,
    );
    final formula = next.formula;
    if (formula != null) {
      next = next.copyWith(
        formula: FortuneFormulaEngine.translateReferences(
          formula,
          rowDelta: rowDelta,
          columnDelta: 0,
        ),
        displayValue: null,
        rawDisplayValue: null,
        hasRawDisplayValue: false,
      );
    }
    return next;
  }

