  Object? _shiftIndexKeyMetadata(
    Object? raw, {
    required int from,
    required int delta,
  }) {
    if (raw is! Map) {
      return raw;
    }
    final next = <String, Object?>{};
    raw.forEach((key, value) {
      final index = int.tryParse('$key');
      if (index == null) {
        next['$key'] = value;
        return;
      }
      final nextIndex = index >= from ? index + delta : index;
      next['$nextIndex'] = value;
    });
    return next;
  }

  Object? _deleteIndexKeyMetadata(Object? raw, {required int index}) {
    if (raw is! Map) {
      return raw;
    }
    final next = <String, Object?>{};
    raw.forEach((key, value) {
      final current = int.tryParse('$key');
      if (current == null) {
        next['$key'] = value;
        return;
      }
      if (current == index) {
        return;
      }
      next['${current > index ? current - 1 : current}'] = value;
    });
    return next;
  }

  bool _isIndexReadOnly(Object? raw, int index) {
    if (raw is! Map) {
      return false;
    }
    final value = raw[index] ?? raw['$index'];
    if (value == null) {
      return false;
    }
    if (value is bool) {
      return value;
    }
    if (value is num) {
      return value != 0;
    }
    final normalized = '$value'.toLowerCase();
    return normalized != '0' && normalized != 'false';
  }

  bool _canEditCell(FortuneSheet sheet, FortuneCellCoord coord) {
    if (!_workbook.settings.allowEdit) {
      return false;
    }
    if (_isIndexReadOnly(sheet.rowReadOnly, coord.row) ||
        _isIndexReadOnly(sheet.colReadOnly, coord.column)) {
      return false;
    }
    return _canEditCellIgnoringAxisReadOnly(sheet, coord);
  }

  bool _canEditCellIgnoringAxisReadOnly(
    FortuneSheet sheet,
    FortuneCellCoord coord,
  ) {
    if (!_workbook.settings.allowEdit) {
      return false;
    }
    final cell = sheet.cells[coord];
    final locked = cell?.locked;
    if (locked != null) {
      return !locked;
    }
    return _canEditSheetDefaultCell(sheet);
  }

  void _replaceCells(
    FortuneSheet sheet,
    Map<FortuneCellCoord, FortuneCell> cells,
  ) {
    sheet.cells
      ..clear()
      ..addAll(cells);
    sheet.nullCells.removeAll(cells.keys);
  }

  void _setSheetCell(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell cell,
  ) {
    final previous = sheet.cells[coord];
    sheet.cells[coord] = cell;
    sheet.nullCells.remove(coord);
    final hadFormula =
        previous?.formula != null ||
        (previous?.hasRawFormula == true && previous?.rawFormula != null);
    final hasNextFormula =
        cell.formula != null || (cell.hasRawFormula && cell.rawFormula != null);
    if (hadFormula && !hasNextFormula) {
      _removeFunctionGroupAt(sheet, coord);
    }
  }

  void _removeFunctionGroupAt(FortuneSheet sheet, FortuneCellCoord coord) {
    _removeFormulaGroupEntries(sheet.calcChain, coord, sheet.id);
    _removeFormulaGroupEntries(sheet.dynamicArray, coord, sheet.id);
    final dynamicArrayCompute = sheet.dynamicArrayCompute;
    if (dynamicArrayCompute is Map) {
      dynamicArrayCompute.remove('${coord.row}_${coord.column}');
    } else {
      _removeFormulaGroupEntries(dynamicArrayCompute, coord, sheet.id);
    }
  }

  void _removeFormulaGroupEntries(
    Object? raw,
    FortuneCellCoord coord,
    String sheetId,
  ) {
    if (raw is List) {
      raw.removeWhere(
        (item) => _formulaGroupEntryMatches(item, coord, sheetId),
      );
    }
  }

  void _syncSheetHyperlinkForCell(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell cell,
  ) {
    final key = '${coord.row}_${coord.column}';
    final hyperlink = cell.hyperlink;
    if (hyperlink == null) {
      sheet.hyperlinks.remove(key);
      return;
    }
    sheet.hyperlinks[key] = {
      'linkType': hyperlink.linkType ?? 'webpage',
      'linkAddress': hyperlink.linkAddress ?? '',
    };
  }

