  Map<FortuneCellCoord, FortuneCell> _shiftRows(
    Map<FortuneCellCoord, FortuneCell> cells,
    int from,
    int delta, {
    double commentTopDelta = 0,
  }) {
    return {
      for (final entry in cells.entries)
        FortuneCellCoord(
          entry.key.row >= from ? entry.key.row + delta : entry.key.row,
          entry.key.column,
        ): _cellWithShiftedMetadata(
          entry.value,
          shiftCommentTop: entry.key.row >= from,
          commentTopDelta: commentTopDelta,
          rowFrom: from,
          rowDelta: delta,
        ),
    };
  }

  Map<FortuneCellCoord, FortuneCell> _shiftColumns(
    Map<FortuneCellCoord, FortuneCell> cells,
    int from,
    int delta, {
    double commentLeftDelta = 0,
  }) {
    return {
      for (final entry in cells.entries)
        FortuneCellCoord(
          entry.key.row,
          entry.key.column >= from
              ? entry.key.column + delta
              : entry.key.column,
        ): _cellWithShiftedMetadata(
          entry.value,
          shiftCommentLeft: entry.key.column >= from,
          commentLeftDelta: commentLeftDelta,
          columnFrom: from,
          columnDelta: delta,
        ),
    };
  }

  Set<FortuneCellCoord> _shiftCoordRows(
    Set<FortuneCellCoord> coords,
    int from,
    int delta,
  ) {
    return {
      for (final coord in coords)
        FortuneCellCoord(
          coord.row >= from ? coord.row + delta : coord.row,
          coord.column,
        ),
    };
  }

  Set<FortuneCellCoord> _shiftCoordColumns(
    Set<FortuneCellCoord> coords,
    int from,
    int delta,
  ) {
