      for (final coord in coords)
        FortuneCellCoord(
          coord.row,
          coord.column >= from ? coord.column + delta : coord.column,
        ),
    };
  }

  Map<FortuneCellCoord, FortuneCell> _deleteRow(
    Map<FortuneCellCoord, FortuneCell> cells,
    int row, {
    double commentTopDelta = 0,
  }) {
    return {
      for (final entry in cells.entries)
        if (entry.key.row != row)
          FortuneCellCoord(
            entry.key.row > row ? entry.key.row - 1 : entry.key.row,
            entry.key.column,
          ): _cellWithShiftedMetadata(
            entry.value,
            shiftCommentTop: entry.key.row > row,
            commentTopDelta: commentTopDelta,
            rowFrom: row + 1,
            rowDelta: -1,
          ),
    };
  }

  Map<FortuneCellCoord, FortuneCell> _deleteColumn(
    Map<FortuneCellCoord, FortuneCell> cells,
    int column, {
    double commentLeftDelta = 0,
  }) {
    return {
      for (final entry in cells.entries)
        if (entry.key.column != column)
          FortuneCellCoord(
            entry.key.row,
            entry.key.column > column ? entry.key.column - 1 : entry.key.column,
          ): _cellWithShiftedMetadata(
            entry.value,
            shiftCommentLeft: entry.key.column > column,
            commentLeftDelta: commentLeftDelta,
            columnFrom: column + 1,
            columnDelta: -1,
          ),
    };
  }

  Set<FortuneCellCoord> _deleteCoordRow(Set<FortuneCellCoord> coords, int row) {
    return {
      for (final coord in coords)
        if (coord.row != row)
