          FortuneCellCoord(
            coord.row,
            coord.column > column ? coord.column - 1 : coord.column,
          ),
    };
  }

  FortuneCell _cellWithShiftedMetadata(
    FortuneCell cell, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
    bool shiftCommentTop = false,
    double commentTopDelta = 0,
    bool shiftCommentLeft = false,
    double commentLeftDelta = 0,
  }) {
    final merge = cell.merge;
    final shiftedMerge = merge == null
        ? null
        : () {
            final nextRow = rowFrom != null && merge.row >= rowFrom
                ? merge.row + rowDelta
                : merge.row;
            final nextColumn = columnFrom != null && merge.column >= columnFrom
                ? merge.column + columnDelta
                : merge.column;
            return FortuneCellMerge(
              row: nextRow,
              rawRow: nextRow == merge.row ? merge.rawRow : null,
              hasRawRow: nextRow == merge.row ? merge.hasRawRow : false,
              column: nextColumn,
              rawColumn: nextColumn == merge.column ? merge.rawColumn : null,
              hasRawColumn: nextColumn == merge.column
                  ? merge.hasRawColumn
                  : false,
              rowSpan: merge.rowSpan,
              rawRowSpan: merge.rawRowSpan,
              hasRawRowSpan: merge.hasRawRowSpan,
              columnSpan: merge.columnSpan,
              rawColumnSpan: merge.rawColumnSpan,
              hasRawColumnSpan: merge.hasRawColumnSpan,
              extraFields: merge.extraFields,
            );
          }();
    final comment = cell.comment;
    final shiftedComment = comment?.copyWith(
      top: shiftCommentTop && comment.top != null
          ? math.max(0, comment.top! + commentTopDelta)
          : comment.top,
      left: shiftCommentLeft && comment.left != null
          ? math.max(0, comment.left! + commentLeftDelta)
          : comment.left,
    );
    final hyperlink = cell.hyperlink;
    final shiftedHyperlink = hyperlink?.copyWith(
      row: rowFrom != null && hyperlink.row != null && hyperlink.row! >= rowFrom
          ? math.max(0, hyperlink.row! + rowDelta)
          : hyperlink.row,
      column:
          columnFrom != null &&
              hyperlink.column != null &&
              hyperlink.column! >= columnFrom
          ? math.max(0, hyperlink.column! + columnDelta)
          : hyperlink.column,
    );
    if (shiftedMerge == merge &&
        shiftedComment == comment &&
        shiftedHyperlink == hyperlink) {
      return cell;
    }
    return cell.copyWith(
      merge: shiftedMerge,
      comment: shiftedComment,
      hyperlink: shiftedHyperlink,
    );
  }

