  Map<String, Object?> _shiftCellKeyMap(
    Map<String, Object?> values, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    return {
      for (final entry in values.entries)
        _shiftCellKey(
          entry.key,
          rowFrom: rowFrom,
          rowDelta: rowDelta,
          columnFrom: columnFrom,
          columnDelta: columnDelta,
        ): entry.value,
    };
  }

  Map<String, Object?> _insertCellKeyMap(
    Map<String, Object?> values, {
    int? row,
    int? column,
    required int count,
  }) {
    final next = <String, Object?>{};
    for (final entry in values.entries) {
      final coord = _coordFromKey(entry.key);
      if (coord == null) {
        next[entry.key] = entry.value;
        continue;
      }
      if (row != null) {
        if (coord.row < row) {
          next[entry.key] = entry.value;
        } else if (coord.row == row) {
          for (var offset = 0; offset < count; offset += 1) {
            next['${coord.row + offset}_${coord.column}'] =
                cloneFortuneMetadata(entry.value);
          }
          next['${coord.row + count}_${coord.column}'] = cloneFortuneMetadata(
            entry.value,
          );
        } else {
          next['${coord.row + count}_${coord.column}'] = entry.value;
        }
        continue;
      }
      if (column != null) {
        if (coord.column < column) {
          next[entry.key] = entry.value;
        } else if (coord.column == column) {
          for (var offset = 0; offset < count; offset += 1) {
            next['${coord.row}_${coord.column + offset}'] =
                cloneFortuneMetadata(entry.value);
          }
          next['${coord.row}_${coord.column + count}'] = cloneFortuneMetadata(
            entry.value,
          );
        } else {
          next['${coord.row}_${coord.column + count}'] = entry.value;
        }
        continue;
      }
      next[entry.key] = entry.value;
    }
    return next;
  }

  Map<String, Object?> _deleteCellKeyMap(
    Map<String, Object?> values, {
    int? row,
    int? column,
  }) {
    return {
      for (final entry in values.entries)
        if (_deletedCellKey(entry.key, row: row, column: column) == null)
          _shiftCellKey(
            entry.key,
            rowFrom: row == null ? null : row + 1,
            rowDelta: row == null ? 0 : -1,
            columnFrom: column == null ? null : column + 1,
            columnDelta: column == null ? 0 : -1,
          ): entry.value,
    };
  }

  String _shiftCellKey(
    String key, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    final coord = _coordFromKey(key);
    if (coord == null) {
      return key;
    }
    final row = rowFrom != null && coord.row >= rowFrom
        ? coord.row + rowDelta
        : coord.row;
    final column = columnFrom != null && coord.column >= columnFrom
        ? coord.column + columnDelta
        : coord.column;
    return '${math.max(0, row)}_${math.max(0, column)}';
  }

  String? _deletedCellKey(String key, {int? row, int? column}) {
    final coord = _coordFromKey(key);
    if (coord == null) {
      return null;
    }
    if (row != null && coord.row == row) {
      return key;
    }
    if (column != null && coord.column == column) {
      return key;
    }
    return null;
  }

  FortuneCellCoord? _coordFromKey(String key) {
    final parts = key.split('_');
    if (parts.length != 2) {
      return null;
    }
    final row = int.tryParse(parts[0]);
    final column = int.tryParse(parts[1]);
    if (row == null || column == null) {
      return null;
    }
    return FortuneCellCoord(row, column);
  }

  String _shiftColumnKey(String key, int from, int delta) {
    final column = int.tryParse(key);
    if (column == null || column < from) {
      return key;
    }
    return '${math.max(0, column + delta)}';
  }

  Map<String, Object?> _insertFilterRows(
    Map<String, Object?> values, {
    required int row,
    required int count,
    required Object? filterSelect,
  }) {
    final shiftedRows = _metadataRange(filterSelect, 'row');
    return {
      for (final entry in values.entries)
        entry.key: entry.value is Map
            ? _insertFilterRowsConfig(
                entry.value! as Map,
                row: row,
                count: count,
                shiftedRows: shiftedRows,
              )
            : entry.value,
    };
  }

  Map<String, Object?> _insertFilterRowsConfig(
    Map raw, {
    required int row,
    required int count,
    required (int, int)? shiftedRows,
  }) {
    final next = Map<String, Object?>.from(cloneFortuneMetadata(raw) as Map);
    final rowhidden = next['rowhidden'];
    if (rowhidden is Map) {
      next['rowhidden'] = {
        for (final entry in rowhidden.entries)
          if (_intValue(entry.key) case final hiddenRow?)
            '${hiddenRow < row ? hiddenRow : hiddenRow + count}': 0,
      };
    }
    if (shiftedRows != null) {
      next['str'] = shiftedRows.$1;
      next['edr'] = shiftedRows.$2;
    } else {
      final str = _shiftIndex(next['str'], row, count);
      if (str != null) {
        next['str'] = str;
      }
      final edr = _shiftIndex(next['edr'], row, count);
      if (edr != null) {
        next['edr'] = edr;
      }
    }
    return next;
  }

  Map<String, Object?> _insertFilterColumns(
    Map<String, Object?> values, {
    required int column,
    required int count,
    required Object? filterSelect,
  }) {
    final shiftedColumns = _metadataRange(filterSelect, 'column');
    final next = <String, Object?>{};
    for (final entry in values.entries) {
      final raw = entry.value;
      if (raw is! Map) {
        next[_shiftColumnKey(entry.key, column, count)] = raw;
        continue;
      }
      final config = Map<String, Object?>.from(
        cloneFortuneMetadata(raw) as Map,
      );
      var cindex = _intValue(config['cindex']);
      if (cindex != null && cindex >= column) {
        cindex += count;
        config['cindex'] = cindex;
      }
      if (shiftedColumns != null) {
        config['stc'] = shiftedColumns.$1;
        config['edc'] = shiftedColumns.$2;
      }
      final key = cindex != null && shiftedColumns != null
          ? '${cindex - shiftedColumns.$1}'
          : _shiftColumnKey(entry.key, column, count);
      next[key] = config;
    }
    return next;
  }

  Map<String, Object?> _deleteFilterRows(
    Map<String, Object?> values, {
    required int row,
    required int count,
    required Object? filterSelect,
  }) {
    if (filterSelect == null) {
      return const {};
    }
    final shiftedRows = _metadataRange(filterSelect, 'row');
    final next = <String, Object?>{};
    final end = row + count - 1;
    for (final entry in values.entries) {
      final raw = entry.value;
      if (raw is! Map) {
        next[entry.key] = raw;
        continue;
      }
      final config = Map<String, Object?>.from(
        cloneFortuneMetadata(raw) as Map,
      );
      final rowhidden = config['rowhidden'];
      if (rowhidden is Map) {
        final shiftedRowhidden = <String, Object?>{};
        for (final hiddenEntry in rowhidden.entries) {
          final hiddenRow = _intValue(hiddenEntry.key);
          if (hiddenRow == null || (hiddenRow >= row && hiddenRow <= end)) {
            continue;
          }
          shiftedRowhidden['${hiddenRow > end ? hiddenRow - count : hiddenRow}'] =
              0;
        }
        if (shiftedRowhidden.isEmpty) {
          continue;
        }
        config['rowhidden'] = shiftedRowhidden;
      }
      if (shiftedRows != null) {
        config['str'] = shiftedRows.$1;
        config['edr'] = shiftedRows.$2;
      }
      next[entry.key] = config;
    }
    return next;
  }

  Map<String, Object?> _deleteFilterColumns(
    Map<String, Object?> values, {
    required int column,
    required int count,
    required Object? filterSelect,
  }) {
    if (filterSelect == null) {
      return const {};
    }
    final shiftedColumns = _metadataRange(filterSelect, 'column');
    final next = <String, Object?>{};
    final end = column + count - 1;
    for (final entry in values.entries) {
      final raw = entry.value;
      final keyIndex = int.tryParse(entry.key);
      final rawCindex = raw is Map ? _intValue(raw['cindex']) : null;
      final cindex = rawCindex ?? keyIndex;
      if (cindex != null && cindex >= column && cindex <= end) {
        continue;
      }
      if (raw is! Map) {
        next[keyIndex != null && keyIndex > end
                ? '${keyIndex - count}'
                : entry.key] =
            raw;
        continue;
      }
      final config = Map<String, Object?>.from(
        cloneFortuneMetadata(raw) as Map,
      );
      final shiftedCindex = cindex != null && cindex > end
          ? cindex - count
          : cindex;
      if (rawCindex != null && shiftedCindex != null) {
        config['cindex'] = shiftedCindex;
      }
      if (shiftedColumns != null) {
        config['stc'] = shiftedColumns.$1;
        config['edc'] = shiftedColumns.$2;
      }
      final key =
          rawCindex != null && shiftedCindex != null && shiftedColumns != null
          ? '${shiftedCindex - shiftedColumns.$1}'
          : keyIndex != null && keyIndex > end
          ? '${keyIndex - count}'
          : entry.key;
      next[key] = config;
    }
    return next;
  }

  (int, int)? _metadataRange(Object? raw, String key) {
    if (raw is! Map) {
      return null;
    }
    final value = raw[key];
    if (value is! List || value.length < 2) {
      return null;
    }
    final start = _intValue(value[0]);
    final end = _intValue(value[1]);
    if (start == null || end == null) {
      return null;
    }
    return (math.min(start, end), math.max(start, end));
  }

  List<FortuneBorderInfo> _shiftBorderInfo(
    List<FortuneBorderInfo> items, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    return [
      for (final item in items)
        FortuneBorderInfo(
          rangeType: item.rangeType,
          borderType: item.borderType,
          color: item.color,
          style: item.style,
          ranges: [
            for (final range in item.ranges)
              _shiftRange(
                range,
                rowFrom: rowFrom,
                rowDelta: rowDelta,
                columnFrom: columnFrom,
                columnDelta: columnDelta,
              ),
          ],
          extraFields: item.extraFields,
        ),
    ];
  }

  FortuneRange _shiftRange(
    FortuneRange range, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    var rowStart = range.rowStart;
    var rowEnd = range.rowEnd;
    var columnStart = range.columnStart;
    var columnEnd = range.columnEnd;
    var rowFocus = range.rowFocus;
    var columnFocus = range.columnFocus;
    if (rowFrom != null) {
      if (rowStart >= rowFrom) {
        rowStart += rowDelta;
        rowEnd += rowDelta;
      } else if (rowEnd >= rowFrom && rowDelta > 0) {
        rowEnd += rowDelta;
      }
      if (rowFocus != null && rowFocus >= rowFrom) {
        rowFocus += rowDelta;
      }
    }
    if (columnFrom != null) {
      if (columnStart >= columnFrom) {
        columnStart += columnDelta;
        columnEnd += columnDelta;
      } else if (columnEnd >= columnFrom && columnDelta > 0) {
        columnEnd += columnDelta;
      }
      if (columnFocus != null && columnFocus >= columnFrom) {
        columnFocus += columnDelta;
      }
    }
    return FortuneRange(
      rowStart: math.max(0, rowStart),
      rowEnd: math.max(0, rowEnd),
      columnStart: math.max(0, columnStart),
      columnEnd: math.max(0, columnEnd),
      rowFocus: rowFocus == null ? null : math.max(0, rowFocus),
      columnFocus: columnFocus == null ? null : math.max(0, columnFocus),
      extraFields: range.extraFields,
    );
  }

  List<FortuneBorderInfo> _deleteBorderInfo(
    List<FortuneBorderInfo> items, {
    int? row,
    int? column,
  }) {
    final next = <FortuneBorderInfo>[];
    for (final item in items) {
      final ranges = <FortuneRange>[];
      for (final range in item.ranges) {
        final deleted = _deleteRange(range, row: row, column: column);
        if (deleted != null) {
          ranges.add(deleted);
        }
      }
      if (ranges.isNotEmpty) {
        next.add(
          FortuneBorderInfo(
            rangeType: item.rangeType,
            borderType: item.borderType,
            color: item.color,
            style: item.style,
            ranges: ranges,
            extraFields: item.extraFields,
          ),
        );
      }
    }
    return next;
  }

  FortuneRange? _deleteRange(FortuneRange range, {int? row, int? column}) {
    var rowStart = range.rowStart;
    var rowEnd = range.rowEnd;
    var columnStart = range.columnStart;
    var columnEnd = range.columnEnd;
    var rowFocus = range.rowFocus;
    var columnFocus = range.columnFocus;
    if (row != null) {
      if (rowStart == rowEnd && rowStart == row) {
        return null;
      }
      if (rowStart > row) {
        rowStart -= 1;
        rowEnd -= 1;
      } else if (rowEnd >= row) {
        rowEnd -= 1;
      }
      if (rowFocus != null) {
        if (rowFocus == row) {
          rowFocus = math.min(rowStart, rowEnd);
        } else if (rowFocus > row) {
          rowFocus -= 1;
        }
      }
    }
    if (column != null) {
      if (columnStart == columnEnd && columnStart == column) {
        return null;
      }
      if (columnStart > column) {
        columnStart -= 1;
        columnEnd -= 1;
      } else if (columnEnd >= column) {
        columnEnd -= 1;
      }
      if (columnFocus != null) {
        if (columnFocus == column) {
          columnFocus = math.min(columnStart, columnEnd);
        } else if (columnFocus > column) {
          columnFocus -= 1;
        }
      }
    }
    if (rowEnd < rowStart || columnEnd < columnStart) {
      return null;
    }
    return FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
      rowFocus: rowFocus,
      columnFocus: columnFocus,
      extraFields: range.extraFields,
    );
  }

  List<FortuneImage> _shiftImages(
    List<FortuneImage> images, {
    double? topFrom,
    double topDelta = 0,
    double? leftFrom,
    double leftDelta = 0,
  }) {
    return [
      for (final image in images)
        image.copyWith(
          top: topFrom != null && image.top >= topFrom
              ? math.max(0, image.top + topDelta)
              : image.top,
          left: leftFrom != null && image.left >= leftFrom
              ? math.max(0, image.left + leftDelta)
              : image.left,
        ),
    ];
  }

  FortuneFrozenPane? _shiftFrozenPane(
    FortuneFrozenPane? frozen, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    if (frozen == null) {
      return null;
    }
    final rowFocus = frozen.rowFocus;
    final columnFocus = frozen.columnFocus;
    final rowChanged =
        rowFocus != null && rowFrom != null && rowFocus >= rowFrom;
    final columnChanged =
        columnFocus != null && columnFrom != null && columnFocus >= columnFrom;
    return FortuneFrozenPane(
      type: frozen.type,
      rowFocus: rowChanged ? rowFocus + rowDelta : rowFocus,
      rawRowFocus: rowChanged ? null : frozen.rawRowFocus,
      hasRawRowFocus: rowChanged ? false : frozen.hasRawRowFocus,
      columnFocus: columnChanged ? columnFocus + columnDelta : columnFocus,
      rawColumnFocus: columnChanged ? null : frozen.rawColumnFocus,
      hasRawColumnFocus: columnChanged ? false : frozen.hasRawColumnFocus,
      extraFields: frozen.extraFields,
      rangeExtraFields: frozen.rangeExtraFields,
    );
  }

  FortuneFrozenPane? _deleteFrozenPane(
    FortuneFrozenPane? frozen, {
    int? row,
    int? column,
  }) {
    if (frozen == null) {
      return null;
    }
    var rowFocus = frozen.rowFocus;
    var columnFocus = frozen.columnFocus;
    var rowChanged = false;
    var columnChanged = false;
    if (rowFocus != null && row != null) {
      rowFocus = rowFocus > row ? rowFocus - 1 : math.max(0, rowFocus - 1);
      rowChanged = true;
    }
    if (columnFocus != null && column != null) {
      columnFocus = columnFocus > column
          ? columnFocus - 1
          : math.max(0, columnFocus - 1);
      columnChanged = true;
    }
    return FortuneFrozenPane(
      type: frozen.type,
      rowFocus: rowFocus,
      rawRowFocus: rowChanged ? null : frozen.rawRowFocus,
      hasRawRowFocus: rowChanged ? false : frozen.hasRawRowFocus,
      columnFocus: columnFocus,
      rawColumnFocus: columnChanged ? null : frozen.rawColumnFocus,
      hasRawColumnFocus: columnChanged ? false : frozen.hasRawColumnFocus,
      extraFields: frozen.extraFields,
      rangeExtraFields: frozen.rangeExtraFields,
    );
  }

  Object? _shiftSheetRangeMetadata(
    Object? raw, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    if (raw is List) {
      return [
        for (final item in raw)
          _shiftSheetRangeMetadata(
            item,
            rowFrom: rowFrom,
            rowDelta: rowDelta,
            columnFrom: columnFrom,
            columnDelta: columnDelta,
          ),
      ];
    }
    if (raw is Map) {
      final next = Map<Object?, Object?>.from(raw);
      final rowRange = _shiftRangeArray(next['row'], rowFrom, rowDelta);
      if (rowRange != null) {
        next['row'] = rowRange;
      }
      final columnRange = _shiftRangeArray(
        next['column'],
        columnFrom,
        columnDelta,
      );
      if (columnRange != null) {
        next['column'] = columnRange;
      }
      final rowFocus = _shiftIndex(next['row_focus'], rowFrom, rowDelta);
      if (rowFocus != null) {
        next['row_focus'] = rowFocus;
      }
      final columnFocus = _shiftIndex(
        next['column_focus'],
        columnFrom,
        columnDelta,
      );
      if (columnFocus != null) {
        next['column_focus'] = columnFocus;
      }
      final r = _shiftIndex(next['r'], rowFrom, rowDelta);
      if (r != null) {
        next['r'] = r;
      }
      final c = _shiftIndex(next['c'], columnFrom, columnDelta);
      if (c != null) {
        next['c'] = c;
      }
      for (final entry in next.entries.toList()) {
        if (_isRangeCoordinateKey(entry.key)) {
          continue;
        }
        final value = entry.value;
        if (value is List || value is Map) {
          next[entry.key] = _shiftSheetRangeMetadata(
            value,
            rowFrom: rowFrom,
            rowDelta: rowDelta,
            columnFrom: columnFrom,
            columnDelta: columnDelta,
          );
        }
      }
      return next;
    }
    return raw;
  }

  Object? _deleteSheetRangeMetadata(Object? raw, {int? row, int? column}) {
    if (raw is List) {
      final next = [
        for (final item in raw)
          ?_deleteSheetRangeMetadata(item, row: row, column: column),
      ];
      return next.isEmpty ? null : next;
    }
    if (raw is Map) {
      final next = Map<Object?, Object?>.from(raw);
      final rowRange = _deleteRangeArray(next['row'], row);
      if (next.containsKey('row')) {
        if (rowRange == null) {
          return null;
        }
        next['row'] = rowRange;
      }
      final columnRange = _deleteRangeArray(next['column'], column);
      if (next.containsKey('column')) {
        if (columnRange == null) {
          return null;
        }
        next['column'] = columnRange;
      }
      final r = _deleteCoordinateIndex(next['r'], row);
      if (next.containsKey('r')) {
        if (r == null) {
          return null;
        }
        next['r'] = r;
      }
      final c = _deleteCoordinateIndex(next['c'], column);
      if (next.containsKey('c')) {
        if (c == null) {
          return null;
        }
        next['c'] = c;
      }
      final rowFocus = _deleteIndex(next['row_focus'], row);
      if (rowFocus != null) {
        next['row_focus'] = rowFocus;
      }
      final columnFocus = _deleteIndex(next['column_focus'], column);
      if (columnFocus != null) {
        next['column_focus'] = columnFocus;
      }
      for (final entry in next.entries.toList()) {
        if (_isRangeCoordinateKey(entry.key)) {
          continue;
        }
        final value = entry.value;
        if (value is List || value is Map) {
          final deleted = _deleteSheetRangeMetadata(
            value,
            row: row,
            column: column,
          );
          if (deleted == null) {
            if (entry.key == 'cellrange') {
              return null;
            }
            next.remove(entry.key);
          } else {
            next[entry.key] = deleted;
          }
        }
      }
      return next;
    }
    return raw;
  }

  Object? _shiftDynamicArrayCompute(
    Object? raw, {
    int? rowFrom,
    int rowDelta = 0,
    int? columnFrom,
    int columnDelta = 0,
  }) {
    if (raw is! Map) {
      return raw;
    }
    return _shiftCellKeyMap(
      Map<String, Object?>.from(raw),
      rowFrom: rowFrom,
      rowDelta: rowDelta,
      columnFrom: columnFrom,
      columnDelta: columnDelta,
    );
  }

  Object? _deleteDynamicArrayCompute(Object? raw, {int? row, int? column}) {
    if (raw is! Map) {
      return raw;
    }
    return _deleteCellKeyMap(
      Map<String, Object?>.from(raw),
      row: row,
      column: column,
    );
  }

  List<int>? _shiftRangeArray(Object? raw, int? from, int delta) {
    if (raw is! List || raw.length < 2 || from == null) {
      return raw is List && raw.length >= 2
          ? [_intValue(raw[0]) ?? 0, _intValue(raw[1]) ?? 0]
          : null;
    }
    var start = _intValue(raw[0]) ?? 0;
    var end = _intValue(raw[1]) ?? start;
    if (start >= from) {
      start += delta;
      end += delta;
    } else if (end >= from && delta > 0) {
      end += delta;
    }
    return [math.max(0, start), math.max(0, end)];
  }

  List<int>? _deleteRangeArray(Object? raw, int? index) {
    if (raw is! List || raw.length < 2) {
      return null;
    }
    var start = _intValue(raw[0]) ?? 0;
    var end = _intValue(raw[1]) ?? start;
    if (index == null) {
      return [start, end];
    }
    if (start == end && start == index) {
      return null;
    }
    if (start > index) {
      start -= 1;
      end -= 1;
    } else if (end >= index) {
      end -= 1;
    }
    if (end < start) {
      return null;
    }
    return [math.max(0, start), math.max(0, end)];
  }

  int? _shiftIndex(Object? raw, int? from, int delta) {
    final index = _intValue(raw);
    if (index == null) {
      return null;
    }
    return from != null && index >= from ? math.max(0, index + delta) : index;
  }

  int? _deleteIndex(Object? raw, int? deleted) {
    final index = _intValue(raw);
    if (index == null) {
      return null;
    }
    if (deleted == null) {
      return index;
    }
    if (index == deleted) {
      return math.max(0, index - 1);
    }
    return index > deleted ? index - 1 : index;
  }

  int? _deleteCoordinateIndex(Object? raw, int? deleted) {
    final index = _intValue(raw);
    if (index == null) {
      return null;
    }
    if (deleted == null) {
      return index;
    }
    if (index == deleted) {
      return null;
    }
    return index > deleted ? index - 1 : index;
  }

  int? _intValue(Object? raw) {
    if (raw is int) {
      return raw;
    }
    if (raw is num) {
      return raw.toInt();
    }
    return int.tryParse('$raw');
  }

  bool _isRangeCoordinateKey(Object? key) {
    return key == 'row' ||
        key == 'column' ||
        key == 'row_focus' ||
        key == 'column_focus' ||
        key == 'r' ||
        key == 'c';
  }

  double _defaultRowExtent(FortuneSheet sheet) {
    return (sheet.defaultRowHeight ?? _workbook.settings.defaultRowHeight) + 1;
  }

  double _defaultColumnExtent(FortuneSheet sheet) {
    return (sheet.defaultColWidth ?? _workbook.settings.defaultColWidth) + 1;
  }

  void _startEditing(FortuneCellCoord coord) {
    final anchor = _workbook.activeSheet.mergeAnchorFor(coord);
    final cell = _workbook.activeSheet.cells[anchor];
    if (!_canEditCell(_workbook.activeSheet, anchor)) {
      return;
    }
    final initialValue = TextEditingValue(
      text: cell?.renderedText ?? '',
      selection: TextSelection.collapsed(
        offset: (cell?.renderedText ?? '').length,
      ),
    );
    _traceCellEditor(
      'startEditing request',
      coord: anchor,
      value: initialValue,
      details: 'hasCell=${cell != null}',
    );
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _editingCoord = anchor;
      _inlineToolbarSelectionRange = null;
      _editorTextMutationSession += 1;
      if (_editorScrollController.hasClients) {
        _editorScrollController.jumpTo(0);
      }
      _editingFormulaBar = false;
      _editorController.setCellValue(cell, initialValue);
      _editorTraceLastValue = initialValue;
      _resetEditorInlineHistory();
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _editingCoord != null) {
        _editorFocusNode.requestFocus();
      }
    });
  }

  void _startEditingWithText(FortuneCellCoord coord, String text) {
    final anchor = _workbook.activeSheet.mergeAnchorFor(coord);
    if (!_canEditCell(_workbook.activeSheet, anchor)) {
      setState(() {
        _formulaSearchDialogOpen = false;
        _formulaSearchCategoryMenuOpen = false;
      });
      return;
    }
    final initialValue = TextEditingValue(
      text: text,
      selection: TextSelection.collapsed(offset: text.length),
    );
    _traceCellEditor(
      'startEditingWithText request',
      coord: anchor,
      value: initialValue,
    );
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _formulaSearchDialogOpen = false;
      _formulaSearchCategoryMenuOpen = false;
      _editingCoord = anchor;
      _inlineToolbarSelectionRange = null;
      _editorTextMutationSession += 1;
      if (_editorScrollController.hasClients) {
        _editorScrollController.jumpTo(0);
      }
      _editingCommentCoord = null;
      _editingFormulaBar = false;
      _editorController.setCellValue(null, initialValue);
      _editorTraceLastValue = initialValue;
      _resetEditorInlineHistory();
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _editingCoord != null) {
        _editorFocusNode.requestFocus();
      }
    });
  }

  void _startFormulaBarEditing() {
    final coord = FortuneCellCoord(selection.row, selection.column);
    final anchor = _workbook.activeSheet.mergeAnchorFor(coord);
    final cell = _workbook.activeSheet.cells[anchor];
    if (!_canEditCell(_workbook.activeSheet, anchor) ||
        _workbook.activeSheet.hiddenRows.contains(anchor.row) ||
        _workbook.activeSheet.hiddenColumns.contains(anchor.column)) {
      return;
    }
    final text = cell?.formula ?? cell?.renderedText ?? '';
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _editingCoord = null;
      _inlineToolbarSelectionRange = null;
      _editingFormulaBar = true;
      _formulaBarEditorController.value = TextEditingValue(
        text: text,
        selection: TextSelection.collapsed(offset: text.length),
      );
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _editingFormulaBar) {
        _formulaBarEditorFocusNode.requestFocus();
      }
    });
  }

  void _startCommentEditing(
    FortuneCellCoord coord, {
    _WorkbookHistorySnapshot? draftUndoSnapshot,
  }) {
    final anchor = _workbook.activeSheet.mergeAnchorFor(coord);
    final cell = _workbook.activeSheet.cells[anchor];
    final comment = cell?.comment;
    if (comment == null || !_canEditCell(_workbook.activeSheet, anchor)) {
      return;
    }
    setState(() {
      selection = FortuneSelection(row: anchor.row, column: anchor.column);
      contextMenuAt = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _hoveredCommentCoord = null;
      _editingCoord = null;
      _inlineToolbarSelectionRange = null;
      _editingFormulaBar = false;
      _editingCommentCoord = anchor;
      _commentEditorDraftUndoSnapshot = draftUndoSnapshot;
      _commentEditorController.value = TextEditingValue(
        text: comment.value,
        selection: TextSelection.collapsed(offset: comment.value.length),
      );
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted && _editingCommentCoord != null) {
        _commentEditorFocusNode.requestFocus();
      }
    });
  }

  void _commitEditing() {
    _traceCellEditor('commitEditing requested');
    _logEditorDebug('commitEditing requested');
    if (_editingCommentCoord != null) {
      _commitCommentEditing();
      return;
    }
    if (_editingFormulaBar) {
      _commitFormulaBarEditing();
      return;
    }
    if (_editingCoord == null) {
      _logEditorDebug('commitEditing ignored noActiveEditor');
      return;
    }
    if (_editorTextMutationPendingCount > 0) {
      _logEditorDebug('commitEditing queuedForPendingMutation');
      _queueEditorTextMutation(_commitActiveCellEditing);
      return;
    }
    _commitActiveCellEditing();
  }

  void _commitActiveCellEditing() {
    final coord = _editingCoord;
    if (coord == null) {
      return;
    }
    _traceCellEditor('commitActiveCellEditing start');
    _logEditorDebug('commitActiveCellEditing start');
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    final previousCell = sheet.cells[anchor];
    final previous = previousCell ?? const FortuneCell();
    final text = _editorController.text;
    if (!_canEditCell(sheet, anchor)) {
      setState(() {
        _editingCoord = null;
        _inlineToolbarSelectionRange = null;
        _editorTextMutationSession += 1;
      });
      _focusNode.requestFocus();
      return;
    }
    final dataVerificationFailure = _dataVerificationInputFailureText(
      sheet,
      anchor,
      text,
    );
    if (dataVerificationFailure != null) {
      setState(() {
        _editingCoord = null;
        _inlineToolbarSelectionRange = null;
        _editorTextMutationSession += 1;
      });
      _showLocationMessageDialog(dataVerificationFailure);
      _focusNode.requestFocus();
      return;
    }
    if (_workbook.settings.beforeUpdateCell?.call(
          anchor.row,
          anchor.column,
          text,
        ) ==
        false) {
      setState(() {
        _editingCoord = null;
        _inlineToolbarSelectionRange = null;
        _editorTextMutationSession += 1;
      });
      _focusNode.requestFocus();
      return;
    }
    final nextCell = text.isEmpty && previous.merge == null
        ? null
        : text.startsWith('=')
        ? previous.withFormulaBarInput(text)
        : _editorController.hasInlineRuns
        ? previous
              .withEditedValue(text)
              .copyWith(inlineRuns: _editorController.inlineRuns)
        : previous.withEditedValue(text);
    final changed = _cellWouldChange(sheet, anchor, nextCell);
    _traceCellEditor(
      'commitActiveCellEditing result',
      coord: anchor,
      details: 'changed=$changed nextCell=${nextCell != null}',
    );
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        if (nextCell == null) {
          sheet.cells.remove(anchor);
        } else {
          _setSheetCell(sheet, anchor, nextCell);
          _syncWrappedEditRowHeight(sheet, anchor, nextCell);
        }
        _recalculateWorkbookFormulas();
      }
      _editingCoord = null;
      _inlineToolbarSelectionRange = null;
      _clearEditorInlineHistory();
      _editorTextMutationSession += 1;
    });
    if (changed) {
      _workbook.settings.afterUpdateCell?.call(
        anchor.row,
        anchor.column,
        previousCell,
        nextCell,
      );
    }
    _focusNode.requestFocus();
  }

  void _commitCommentEditing() {
    final coord = _editingCommentCoord;
    if (coord == null) {
      return;
    }
    final sheet = _workbook.activeSheet;
    final anchor = sheet.mergeAnchorFor(coord);
    final previous = sheet.cells[anchor] ?? const FortuneCell();
    final currentComment = previous.comment;
    final draftUndoSnapshot = _commentEditorDraftUndoSnapshot;
    if (currentComment == null || !_canEditCell(sheet, anchor)) {
      setState(() {
        _editingCommentCoord = null;
        _commentEditorDraftUndoSnapshot = null;
      });
      _focusNode.requestFocus();
      return;
    }
    final nextComment = FortuneCellComment(
      value: _commentEditorController.text,
      left: currentComment.left,
      top: currentComment.top,
      width: currentComment.width,
      height: currentComment.height,
      isShow: currentComment.isShow,
    );
    if (_workbook.settings.beforeUpdateComment?.call(
          anchor.row,
          anchor.column,
          nextComment.value,
        ) ==
        false) {
      setState(() {
        _editingCommentCoord = null;
        _commentEditorDraftUndoSnapshot = null;
      });
      _focusNode.requestFocus();
      return;
    }
    if (nextComment.value == currentComment.value) {
      if (draftUndoSnapshot != null) {
        _pushUndoSnapshot(draftUndoSnapshot);
      }
      setState(() {
        _editingCommentCoord = null;
        _commentEditorDraftUndoSnapshot = null;
      });
      _focusNode.requestFocus();
      return;
    }
    final nextCell = _cellWithComment(previous, nextComment);
    if (_cellWouldChange(sheet, anchor, nextCell)) {
      if (draftUndoSnapshot != null) {
        _pushUndoSnapshot(draftUndoSnapshot);
      } else {
        _recordUndoSnapshot();
      }
    }
    setState(() {
      _setSheetCell(sheet, anchor, nextCell);
      _editingCommentCoord = null;
      _commentEditorDraftUndoSnapshot = null;
    });
    _workbook.settings.afterUpdateComment?.call(
      anchor.row,
      anchor.column,
      currentComment.value,
      nextComment.value,
    );
    _focusNode.requestFocus();
  }

  void _commitFormulaBarEditing() {
    if (!_editingFormulaBar) {
      return;
    }
    final coord = _workbook.activeSheet.mergeAnchorFor(
      FortuneCellCoord(selection.row, selection.column),
    );
    final sheet = _workbook.activeSheet;
    final previousCell = sheet.cells[coord];
    final previous = previousCell ?? const FortuneCell();
    final text = _formulaBarEditorController.text;
    if (!_canEditCell(sheet, coord)) {
      setState(() {
        _editingFormulaBar = false;
      });
      _focusNode.requestFocus();
      return;
    }
    final dataVerificationFailure = _dataVerificationInputFailureText(
      sheet,
      coord,
      text,
    );
    if (dataVerificationFailure != null) {
      setState(() {
        _editingFormulaBar = false;
      });
      _showLocationMessageDialog(dataVerificationFailure);
      _focusNode.requestFocus();
      return;
    }
    if (_workbook.settings.beforeUpdateCell?.call(
          coord.row,
          coord.column,
          text,
        ) ==
        false) {
      setState(() {
        _editingFormulaBar = false;
      });
      _focusNode.requestFocus();
      return;
    }
    final nextCell = text.isEmpty && previous.merge == null
        ? null
        : previous.withFormulaBarInput(
            text,
            formulaDisplayValue: previous.formula == text
                ? previous.displayValue
                : null,
          );
    final changed = _cellWouldChange(sheet, coord, nextCell);
    if (changed) {
      _recordUndoSnapshot();
    }
    setState(() {
      if (changed) {
        if (nextCell == null) {
          sheet.cells.remove(coord);
        } else {
          _setSheetCell(sheet, coord, nextCell);
          _syncWrappedEditRowHeight(sheet, coord, nextCell);
        }
        _recalculateWorkbookFormulas();
      }
      _editingFormulaBar = false;
    });
    if (changed) {
      _workbook.settings.afterUpdateCell?.call(
        coord.row,
        coord.column,
        previousCell,
        nextCell,
      );
    }
    _moveSelectionWithArrow(LogicalKeyboardKey.arrowDown);
    _focusNode.requestFocus();
  }

  bool _cellWouldChange(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneCell? nextCell,
  ) {
    final previous = sheet.cells[coord];
    if (previous == null || nextCell == null) {
      return previous != nextCell;
    }
    return !_jsonLikeEquals(
      FortuneSheetCodec.cellToJson(previous),
      FortuneSheetCodec.cellToJson(nextCell),
    );
  }

  bool _dataVerificationWouldChange(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    Object? nextRule,
  ) {
    final key = _cellKey(coord);
    final previous = sheet.dataVerification[key];
    if (previous == null || nextRule == null) {
      return previous != nextRule;
    }
    return !_jsonLikeEquals(previous, nextRule);
  }

  bool _rawDataVerificationWouldChange(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    Object? nextRule,
  ) {
    final rawDataVerification = sheet.rawDataVerification;
    if (rawDataVerification is! Map) {
      return true;
    }
    final key = _cellKey(coord);
    if (!rawDataVerification.containsKey(key)) {
      return true;
    }
    return !_jsonLikeEquals(rawDataVerification[key], nextRule);
  }

  bool _rawHyperlinkWouldChange(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    Object? nextLink,
  ) {
    final rawHyperlinks = sheet.rawHyperlinks;
    if (rawHyperlinks is! Map) {
      return true;
    }
    final key = _cellKey(coord);
    if (!rawHyperlinks.containsKey(key)) {
      return true;
    }
    return !_jsonLikeEquals(rawHyperlinks[key], nextLink);
  }

  bool _cellMapsEqual(
    Map<FortuneCellCoord, FortuneCell> left,
    Map<FortuneCellCoord, FortuneCell> right,
  ) {
    if (left.length != right.length) {
      return false;
    }
    for (final entry in left.entries) {
      final rightCell = right[entry.key];
      if (rightCell == null ||
          !_jsonLikeEquals(
            FortuneSheetCodec.cellToJson(entry.value),
            FortuneSheetCodec.cellToJson(rightCell),
          )) {
        return false;
      }
    }
    return true;
  }

  bool _sheetHyperlinkWouldChange(
    FortuneSheet sheet,
    FortuneCellCoord coord,
    FortuneHyperlink? nextHyperlink,
  ) {
    final key = '${coord.row}_${coord.column}';
    if (nextHyperlink == null) {
      return sheet.hyperlinks.containsKey(key);
    }
    return !_jsonLikeEquals(sheet.hyperlinks[key], {
      'linkType': nextHyperlink.linkType ?? 'webpage',
      'linkAddress': nextHyperlink.linkAddress ?? '',
    });
  }

  bool _jsonLikeEquals(Object? left, Object? right) {
    if (left is Map && right is Map) {
      if (left.length != right.length) {
        return false;
      }
      for (final entry in left.entries) {
        if (!right.containsKey(entry.key) ||
            !_jsonLikeEquals(entry.value, right[entry.key])) {
          return false;
        }
      }
      return true;
    }
    if (left is List && right is List) {
      if (left.length != right.length) {
        return false;
      }
      for (var index = 0; index < left.length; index += 1) {
        if (!_jsonLikeEquals(left[index], right[index])) {
          return false;
        }
      }
      return true;
    }
    return left == right;
  }

  bool _intSetEquals(Set<int> left, Set<int> right) {
    if (left.length != right.length) {
      return false;
    }
    return left.every(right.contains);
  }

  void _cancelEditing() {
    if (_editingCommentCoord != null) {
      final draftUndoSnapshot = _commentEditorDraftUndoSnapshot;
      setState(() {
        if (draftUndoSnapshot != null) {
          _restoreHistorySnapshot(draftUndoSnapshot);
        } else {
          _editingCommentCoord = null;
          _commentEditorDraftUndoSnapshot = null;
        }
      });
      _focusNode.requestFocus();
      return;
    }
    if (_editingFormulaBar) {
      setState(() {
        _editingFormulaBar = false;
      });
      _focusNode.requestFocus();
      return;
    }
    if (_editingCoord == null) {
      return;
    }
    setState(() {
      _editingCoord = null;
      _clearEditorInlineHistory();
      _editorTextMutationSession += 1;
    });
    _focusNode.requestFocus();
  }

  TextRange? _editorSelectedRange() {
    final selection = _editorController.selection;
    if (!selection.isValid || selection.isCollapsed) {
      return null;
    }
    return TextRange(
      start: math.min(selection.start, selection.end),
      end: math.max(selection.start, selection.end),
    );
  }

  bool _editorSelectionMatchesRange(TextRange range) {
    final selection = _editorController.selection;
    return selection.isValid &&
        math.min(selection.start, selection.end) == range.start &&
        math.max(selection.start, selection.end) == range.end;
  }

  TextSelection _editorSelectionForRange(
    TextRange range, {
    TextSelection? preferredSelection,
  }) {
    if (preferredSelection != null && preferredSelection.isValid) {
      final start = math.min(
        preferredSelection.baseOffset,
        preferredSelection.extentOffset,
      );
      final end = math.max(
        preferredSelection.baseOffset,
        preferredSelection.extentOffset,
      );
      if (start == range.start && end == range.end) {
        return preferredSelection;
      }
    }
    return TextSelection(baseOffset: range.start, extentOffset: range.end);
  }

  void _restoreEditorCopySelection(
    TextRange range, {
    TextSelection? preferredSelection,
  }) {
    if (_editingCoord == null) {
      fortuneSheetDebugLog(
        'editor contextCopy restore skipped noActiveEditor '
        'range=${_debugRange(range)} preferred=${_debugSelection(preferredSelection)}',
      );
      return;
    }
    _inlineToolbarSelectionRange = range;
    final selection = _editorSelectionForRange(
      range,
      preferredSelection: preferredSelection,
    );
    _editorController.selection = selection;
    _syncEditorPlatformEditingState(
      _editorController.value.copyWith(selection: selection),
    );
    fortuneSheetDebugLog(
      'editor contextCopy restore range=${_debugRange(range)} '
      'preferred=${_debugSelection(preferredSelection)} '
      'applied=${_debugSelection(selection)} value=${_debugValue(_editorController.value)}',
    );
  }

  Future<void> _copyEditorSelectionToClipboard({bool cut = false}) async {
    return _copyEditorRangeToClipboard(_editorSelectedRange(), cut: cut);
  }

  Future<void> _copyEditorRangeToClipboard(
    TextRange? range, {
    bool cut = false,
  }) async {
    fortuneSheetDebugLog(
      'editor contextCopy start cut=$cut contextMenu=$_contextMenuIsEditor '
      'inputRange=${_debugRange(range)} value=${_debugValue(_editorController.value)}',
    );
    if (range == null) {
      fortuneSheetDebugLog(
        'editor contextCopy abort nullRange contextMenu=$_contextMenuIsEditor '
        'value=${_debugValue(_editorController.value)}',
      );
      if (_contextMenuIsEditor) {
        setState(_closeTransientMenus);
      }
      return;
    }
    final text = _editorController.text;
    final copyRange = TextRange(
      start: math.max(0, math.min(range.start, range.end)),
      end: math.min(text.length, math.max(range.start, range.end)),
    );
    if (copyRange.start >= copyRange.end) {
      fortuneSheetDebugLog(
        'editor contextCopy abort emptyRange copyRange=${_debugRange(copyRange)} '
        'textLength=${text.length} value=${_debugValue(_editorController.value)}',
      );
      if (_contextMenuIsEditor) {
        setState(_closeTransientMenus);
      }
      return;
    }
    final selectedText = text.substring(copyRange.start, copyRange.end);
    final selectedRuns = _editorController.runsForRange(copyRange);
    final selectionBeforeCopy = _editorController.selection;
    fortuneSheetDebugLog(
      'editor contextCopy clipboardSet begin copyRange=${_debugRange(copyRange)} '
      'selectionBefore=${_debugSelection(selectionBeforeCopy)} '
      'selectedText=${_debugText(selectedText)}',
    );
    await Clipboard.setData(ClipboardData(text: selectedText));
    if (!mounted) {
      return;
    }
    fortuneSheetDebugLog(
      'editor contextCopy clipboardSet complete copyRange=${_debugRange(copyRange)} '
      'current=${_debugSelection(_editorController.selection)} '
      'contextMenu=$_contextMenuIsEditor editing=$_editingCoord',
    );
    _editorClipboardHasPasteText = selectedText.isNotEmpty;
    _copiedEditorClipboardText = selectedText;
    _copiedEditorInlineRuns = selectedRuns.isEmpty
        ? null
        : [for (final run in selectedRuns) run.copyWith()];
    final forceRestoreSelectionAfterCopy = _contextMenuIsEditor;
    final restoreSelectionAfterCopy =
        forceRestoreSelectionAfterCopy ||
        _editorSelectionMatchesRange(copyRange);
    fortuneSheetDebugLog(
      'editor contextCopy decision cut=$cut forceRestore=$forceRestoreSelectionAfterCopy '
      'restore=$restoreSelectionAfterCopy matches=${_editorSelectionMatchesRange(copyRange)} '
      'current=${_debugSelection(_editorController.selection)}',
    );
    if (cut) {
      _replaceEditorRange(copyRange, '');
    } else if (restoreSelectionAfterCopy) {
      _restoreEditorCopySelection(
        copyRange,
        preferredSelection: selectionBeforeCopy,
      );
    }
    if (_contextMenuIsEditor) {
      fortuneSheetDebugLog('editor contextCopy closeMenu');
      setState(_closeTransientMenus);
    }
    if (!cut && restoreSelectionAfterCopy) {
      _editorFocusNode.requestFocus();
      _restoreEditorCopySelection(
        copyRange,
        preferredSelection: selectionBeforeCopy,
      );
      WidgetsBinding.instance.addPostFrameCallback((_) {
        fortuneSheetDebugLog(
          'editor contextCopy postFrame before mounted=$mounted editing=$_editingCoord '
          'selection=${_debugSelection(_editorController.selection)}',
        );
        if (!mounted ||
            _editingCoord == null ||
            (!forceRestoreSelectionAfterCopy &&
                !_editorSelectionMatchesRange(copyRange))) {
          return;
        }
        _editorFocusNode.requestFocus();
        _restoreEditorCopySelection(
          copyRange,
          preferredSelection: selectionBeforeCopy,
        );
        fortuneSheetDebugLog(
          'editor contextCopy postFrame after selection=${_debugSelection(_editorController.selection)}',
        );
      });
    }
  }

  Future<void> _pasteClipboardIntoEditor({TextRange? replaceRange}) async {
    final data = await Clipboard.getData(Clipboard.kTextPlain);
    if (!mounted) {
      return;
    }
    final pasteText = data?.text;
    if (pasteText == null) {
      if (_contextMenuIsEditor) {
        setState(_closeTransientMenus);
      }
      return;
    }
    final text = _editorController.text;
    final selection = _editorController.selection;
    final rawRange =
        replaceRange ??
        (selection.isValid
            ? TextRange(
                start: math.min(selection.start, selection.end),
                end: math.max(selection.start, selection.end),
              )
            : TextRange(start: text.length, end: text.length));
    final range = TextRange(
      start: math.max(0, math.min(rawRange.start, rawRange.end)),
      end: math.min(text.length, math.max(rawRange.start, rawRange.end)),
    );
    final copiedRuns = _copiedEditorInlineRuns;
    if (copiedRuns != null && _copiedEditorClipboardText == pasteText) {
      _editorController.replaceRangeWithRuns(range, pasteText, copiedRuns);
      _setEditorValueFromUserEdit(
        _editorController.value.copyWith(
          selection: TextSelection.collapsed(
            offset: range.start + pasteText.length,
          ),
        ),
      );
    } else {
      _replaceEditorRange(range, pasteText);
    }
    if (_contextMenuIsEditor) {
      setState(_closeTransientMenus);
    }
  }

  void _queueEditorTextMutation(FutureOr<void> Function() mutate) {
    final session = _editorTextMutationSession;
    _editorTextMutationPendingCount += 1;
    _logEditorDebug('queueMutation pending=$_editorTextMutationPendingCount');
    final nextMutation = _editorTextMutationQueue.then((_) async {
      if (!mounted ||
          _editingCoord == null ||
          session != _editorTextMutationSession) {
        fortuneSheetDebugLog(
          'editor mutation skipped mounted=$mounted editing=$_editingCoord '
          'session=$session currentSession=$_editorTextMutationSession',
        );
        return;
      }
      _logEditorDebug('runQueuedMutation before');
      await mutate();
      _logEditorDebug('runQueuedMutation after');
    });
    _editorTextMutationQueue = nextMutation
        .catchError((Object error, StackTrace stackTrace) {
          FlutterError.reportError(
            FlutterErrorDetails(
              exception: error,
              stack: stackTrace,
              library: 'fortune_sheet',
              context: ErrorDescription(
                'while mutating the active cell editor',
              ),
            ),
          );
        })
        .whenComplete(() {
          _editorTextMutationPendingCount = math.max(
            0,
            _editorTextMutationPendingCount - 1,
          );
          _logEditorDebug(
            'queueMutation complete pending=$_editorTextMutationPendingCount',
          );
        });
    unawaited(_editorTextMutationQueue);
  }

  void _runOrQueueEditorTextMutation(VoidCallback mutate) {
    if (_editorTextMutationPendingCount == 0) {
      _logEditorDebug('runImmediateMutation before');
      mutate();
      _logEditorDebug('runImmediateMutation after');
      return;
    }
    _logEditorDebug(
      'runOrQueue deferred pending=$_editorTextMutationPendingCount',
    );
    _queueEditorTextMutation(mutate);
  }

  void _replaceEditorRange(TextRange range, String replacement) {
    final text = _editorController.text;
    final start = math.min(math.max(range.start, 0), text.length);
    final end = math.min(math.max(range.end, start), text.length);
    final nextText = text.replaceRange(start, end, replacement);
    fortuneSheetDebugLog(
      'editor replaceRange start=$start end=$end replacement=${_debugText(replacement)} '
      'before=${_debugText(text)} after=${_debugText(nextText)}',
    );
    _setEditorValueFromUserEdit(
      TextEditingValue(
        text: nextText,
        selection: TextSelection.collapsed(offset: start + replacement.length),
      ),
    );
  }

  void _setEditorValueFromUserEdit(TextEditingValue value) {
    _traceCellEditor(
      'setValueFromUserEdit',
      previousValue: _editorController.value,
      value: value,
    );
    final editableState = _editorEditableKey.currentState;
    if (editableState == null ||
        Overlay.maybeOf(editableState.context) == null) {
      fortuneSheetDebugLog(
        'editor setValue controllerFallback value=${_debugValue(value)} '
        'hasState=${editableState != null}',
      );
      _editorController.value = value;
      _syncEditorPlatformEditingState(value);
      return;
    }
    fortuneSheetDebugLog(
      'editor setValue userUpdate value=${_debugValue(value)}',
    );
    editableState.userUpdateTextEditingValue(
      value,
      SelectionChangedCause.keyboard,
    );
  }

  void _syncEditorPlatformEditingState(TextEditingValue value) {
    if (!_editorFocusNode.hasFocus) {
      return;
    }
    _traceCellEditor('syncPlatformEditingState', value: value);
    fortuneSheetDebugLog(
      'editor syncPlatformEditingState value=${_debugValue(value)}',
    );
    unawaited(
      SystemChannels.textInput.invokeMethod<void>(
        'TextInput.setEditingState',
        value.toJSON(),
      ),
    );
  }

  void _insertEditorText(String text) {
    final value = _editorController.value;
    final currentText = value.text;
    final selection = value.selection;
    final range = selection.isValid
        ? TextRange(
            start: math.min(selection.start, selection.end),
            end: math.max(selection.start, selection.end),
          )
        : TextRange(start: currentText.length, end: currentText.length);
    fortuneSheetDebugLog(
      'editor insertText text=${_debugText(text)} range=${range.start}-${range.end} '
      'value=${_debugValue(value)}',
    );
    _replaceEditorRange(range, text);
  }

  void _logEditorDebug(String event) {
    if (!fortuneSheetDebugLogEnabled) {
      return;
    }
    fortuneSheetDebugLog(
      'editor $event coord=$_editingCoord pending=$_editorTextMutationPendingCount '
      'session=$_editorTextMutationSession value=${_debugValue(_editorController.value)}',
    );
  }

  void _traceCellEditor(
    String event, {
    FortuneCellCoord? coord,
    TextEditingValue? previousValue,
    TextEditingValue? value,
    TextSelection? selection,
    SelectionChangedCause? selectionCause,
    KeyEvent? keyEvent,
    String? details,
  }) {
    final traceSeq = ++_editorTraceSeq;
    final traceCoord = coord ?? _editingCoord;
    final traceValue = value ?? _editorController.value;
    final previous = previousValue;
    final keyDetails = keyEvent == null
        ? ''
        : ' key=${keyEvent.logicalKey.debugName ?? keyEvent.logicalKey.keyLabel}'
              ' char=${_debugText(keyEvent.character ?? '')}'
              ' type=${keyEvent.runtimeType}'
              ' ctrl=${HardwareKeyboard.instance.isControlPressed}'
              ' shift=${HardwareKeyboard.instance.isShiftPressed}'
              ' alt=${HardwareKeyboard.instance.isAltPressed}'
              ' meta=${HardwareKeyboard.instance.isMetaPressed}';
    final selectionDetails = selection == null
        ? ''
        : ' changedSelection=${_debugSelection(selection)}'
              ' cause=${selectionCause?.name ?? 'null'}';
    final previousDetails = previous == null
        ? ''
        : ' previous=${_debugValue(previous)}'
              ' deltaText=${traceValue.text.length - previous.text.length}';
    final extraDetails = details == null ? '' : ' $details';
          final message = 'cellEditorTrace#$traceSeq event=$event coord=$traceCoord '
        'pending=$_editorTextMutationPendingCount '
        'session=$_editorTextMutationSession '
        'focus=${_editorFocusNode.hasFocus} '
        'value=${_debugValue(traceValue)}'
        '$previousDetails$keyDetails$selectionDetails$extraDetails';
    scheduleMicrotask(() => debugPrint(message));
  }

  String _debugRange(TextRange? range) {
    if (range == null) {
      return 'null';
    }
    return '${range.start}-${range.end} valid=${range.isValid}';
  }

  String _debugSelection(TextSelection? selection) {
    if (selection == null) {
      return 'null';
    }
    return '${selection.baseOffset}-${selection.extentOffset} '
        'start=${selection.start} end=${selection.end} '
        'collapsed=${selection.isCollapsed} valid=${selection.isValid}';
  }

  String _debugRect(Rect? rect) {
    if (rect == null) {
      return 'null';
    }
    return '${rect.left.toStringAsFixed(1)},${rect.top.toStringAsFixed(1)},'
        '${rect.right.toStringAsFixed(1)},${rect.bottom.toStringAsFixed(1)}';
  }

  String _debugValue(TextEditingValue value) {
    return 'text=${_debugText(value.text)} '
        'selection=${value.selection.baseOffset}-${value.selection.extentOffset} '
        'composing=${value.composing.start}-${value.composing.end}';
  }

  String _debugEditorRuns({TextRange? range}) {
    final runs = range == null
        ? _editorController.inlineRuns
        : _editorController.runsForRange(range);
    if (runs.isEmpty) {
      return '[]';
    }
    final parts = <String>[];
    for (var index = 0; index < runs.length && index < 8; index += 1) {
      final run = runs[index];
      final extras = run.extraFields.entries
          .map((entry) => '${entry.key}:${entry.value}')
          .join(',');
      parts.add(
        '$index("${_debugText(run.text)}" fs=${run.fontSize} ff=${run.fontFamily} '
        'fg=${run.foreground} bl=${run.bold} it=${run.italic} extras={$extras})',
      );
    }
    if (runs.length > 8) {
      parts.add('...${runs.length - 8} more');
    }
    return '[${parts.join(' | ')}]';
  }

  String _debugText(String text) {
    const maxDebugTextLength = 300;
    final escaped = text.replaceAll('\n', r'\n').replaceAll('\r', r'\r');
    if (escaped.length <= maxDebugTextLength) {
      return escaped;
    }
    return '${escaped.substring(0, maxDebugTextLength)}...'
      '(${escaped.length} chars)';
  }

  KeyEventResult _handleEditorKeyEvent(FocusNode node, KeyEvent event) {
    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
      return KeyEventResult.ignored;
    }
    _traceCellEditor('keyEvent', keyEvent: event);
    if (_handleToolbarPopupKeyEvent(event)) {
      _traceCellEditor('keyEvent handled toolbarPopup', keyEvent: event);
      return KeyEventResult.handled;
    }
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.escape) {
      _cancelEditing();
      _traceCellEditor('keyEvent handled escape', keyEvent: event);
      return KeyEventResult.handled;
    }
    final isShortcutPressed =
        HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed;
    final isShiftPressed = HardwareKeyboard.instance.isShiftPressed;
    if (event is KeyDownEvent && isShortcutPressed) {
      if (event.logicalKey == LogicalKeyboardKey.keyA) {
        _setEditorValueFromUserEdit(
          _editorController.value.copyWith(
            selection: TextSelection(
              baseOffset: 0,
              extentOffset: _editorController.text.length,
            ),
          ),
        );
        _traceCellEditor('keyEvent handled selectAll', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.keyC) {
        unawaited(_copyEditorSelectionToClipboard());
        _traceCellEditor('keyEvent handled copy', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.keyX) {
        _queueEditorTextMutation(
          () => _copyEditorSelectionToClipboard(cut: true),
        );
        _traceCellEditor('keyEvent handled cut', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.keyV) {
        _queueEditorTextMutation(_pasteClipboardIntoEditor);
        _traceCellEditor('keyEvent handled paste', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.keyZ) {
        if (isShiftPressed) {
          if (!_redoEditorInlineFormat()) {
            _editorUndoController.redo();
          }
        } else {
          if (!_undoEditorInlineFormat()) {
            _editorUndoController.undo();
          }
        }
        _traceCellEditor('keyEvent handled undo', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.keyY) {
        if (!_redoEditorInlineFormat()) {
          _editorUndoController.redo();
        }
        _traceCellEditor('keyEvent handled redo', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.insert) {
        unawaited(_copyEditorSelectionToClipboard());
        _traceCellEditor('keyEvent handled ctrlInsert', keyEvent: event);
        return KeyEventResult.handled;
      }
    }
    if (event is KeyDownEvent && isShiftPressed) {
      if (event.logicalKey == LogicalKeyboardKey.insert) {
        _queueEditorTextMutation(_pasteClipboardIntoEditor);
        _traceCellEditor('keyEvent handled shiftInsert', keyEvent: event);
        return KeyEventResult.handled;
      }
      if (event.logicalKey == LogicalKeyboardKey.delete) {
        _queueEditorTextMutation(
          () => _copyEditorSelectionToClipboard(cut: true),
        );
        _traceCellEditor('keyEvent handled shiftDelete', keyEvent: event);
        return KeyEventResult.handled;
      }
    }
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.enter &&
        (HardwareKeyboard.instance.isShiftPressed ||
            HardwareKeyboard.instance.isAltPressed ||
            HardwareKeyboard.instance.isMetaPressed)) {
      fortuneSheetDebugLog(
        'editor multilineEnter key=${event.logicalKey.keyLabel} '
        'shift=${HardwareKeyboard.instance.isShiftPressed} '
        'alt=${HardwareKeyboard.instance.isAltPressed} '
        'meta=${HardwareKeyboard.instance.isMetaPressed}',
      );
      _runOrQueueEditorTextMutation(() => _insertEditorText('\n'));
      _traceCellEditor('keyEvent handled multilineEnter', keyEvent: event);
      return KeyEventResult.handled;
    }
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.enter &&
        !HardwareKeyboard.instance.isShiftPressed &&
        !HardwareKeyboard.instance.isAltPressed &&
        !HardwareKeyboard.instance.isMetaPressed) {
      if (_editorController.value.composing.isValid &&
          !_editorController.value.composing.isCollapsed) {
        _traceCellEditor('keyEvent ignored composingEnter', keyEvent: event);
        return KeyEventResult.ignored;
      }
      _commitEditing();
      _traceCellEditor('keyEvent handled enterCommit', keyEvent: event);
      return KeyEventResult.handled;
    }
    if (_shouldSkipDeletionKeyAfterImeUpdate(event)) {
      _editorSkipDeletionKeyUntil = null;
      if (_deleteImeResidualAfterCaret(event)) {
        _editorImeResidualDeletionValue = null;
        _traceCellEditor(
          'keyEvent handled imeResidualDeletion',
          keyEvent: event,
        );
        return KeyEventResult.handled;
      }
      _editorImeResidualDeletionValue = null;
      _traceCellEditor('keyEvent handled imeDeletion', keyEvent: event);
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.backspace ||
        event.logicalKey == LogicalKeyboardKey.delete) {
      _traceCellEditor(
        'keyEvent ignored editableTextDeletion',
        keyEvent: event,
      );
      return KeyEventResult.ignored;
    }
    if (_applyTextEditorNavigationKey(
      _editorController,
      event,
      multiline: true,
    )) {
      _traceCellEditor('keyEvent handled navigation', keyEvent: event);
      return KeyEventResult.handled;
    }
    _traceCellEditor('keyEvent ignored', keyEvent: event);
    return KeyEventResult.ignored;
  }

  bool _shouldSkipDeletionKeyAfterImeUpdate(KeyEvent event) {
    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
      return false;
    }
    if (event.logicalKey != LogicalKeyboardKey.backspace &&
        event.logicalKey != LogicalKeyboardKey.delete) {
      return false;
    }
    final until = _editorSkipDeletionKeyUntil;
    if (until == null) {
      return false;
    }
    if (DateTime.now().isAfter(until)) {
      _editorSkipDeletionKeyUntil = null;
      _editorImeResidualDeletionValue = null;
      return false;
    }
    return true;
  }

  bool _valueHasImeResidualAfterCaret(
    TextEditingValue previousValue,
    TextEditingValue currentValue,
    TextEditingValue? compositionBaseValue,
  ) {
    final selection = currentValue.selection;
    final composing = currentValue.composing;
    if (!selection.isValid || !selection.isCollapsed) {
      return false;
    }
    if (!composing.isValid || !composing.isCollapsed) {
      return false;
    }
    final offset = selection.start;
    if (offset != composing.start ||
        offset < 0 ||
        offset >= currentValue.text.length) {
      return false;
    }
    if (!previousValue.composing.isValid ||
        previousValue.composing.isCollapsed ||
        previousValue.composing.start != offset) {
      return false;
    }
    if (previousValue.text.length - currentValue.text.length != 1) {
      return false;
    }
    if (previousValue.text.substring(0, offset) !=
        currentValue.text.substring(0, offset)) {
      return false;
    }
    final currentSuffix = currentValue.text.substring(offset);
    if (!previousValue.text.endsWith(currentSuffix)) {
      return false;
    }
    if (compositionBaseValue == null ||
        compositionBaseValue.selection.start != offset ||
        !compositionBaseValue.composing.isValid ||
        !compositionBaseValue.composing.isCollapsed ||
        compositionBaseValue.composing.start != offset) {
      return false;
    }
    return compositionBaseValue.text.substring(offset) != currentSuffix;
  }

  bool _deleteImeResidualAfterCaret(KeyEvent event) {
    if (event.logicalKey != LogicalKeyboardKey.backspace) {
      return false;
    }
    final value = _editorController.value;
    if (_editorImeResidualDeletionValue != value) {
      return false;
    }
    final selection = value.selection;
    if (!selection.isValid || !selection.isCollapsed) {
      return false;
    }
    final offset = selection.start;
    if (offset < 0 || offset >= value.text.length) {
      return false;
    }
    final nextText = value.text.replaceRange(offset, offset + 1, '');
    _setEditorValueFromUserEdit(
      TextEditingValue(
        text: nextText,
        selection: TextSelection.collapsed(offset: offset),
      ),
    );
    return true;
  }

  KeyEventResult _handleFormulaBarEditorKeyEvent(
    FocusNode node,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      _cancelEditing();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter &&
        !HardwareKeyboard.instance.isShiftPressed) {
      _commitFormulaBarEditing();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  KeyEventResult _handleSheetTabEditorKeyEvent(FocusNode node, KeyEvent event) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      _cancelSheetRename();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter) {
      _commitSheetRename();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  KeyEventResult _handleFilterDropdownSearchKeyEvent(
    FocusNode node,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      setState(() {
        _filterDropdownSearchController.clear();
        _filterDropdownScrollOffset = 0;
      });
      _focusNode.requestFocus();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter) {
      _focusNode.requestFocus();
      return KeyEventResult.handled;
    }
    final isShortcutPressed =
        HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed;
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyA) {
      _filterDropdownSearchController.selection = TextSelection(
        baseOffset: 0,
        extentOffset: _filterDropdownSearchController.text.length,
      );
      return KeyEventResult.handled;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyC) {
      unawaited(_copyFilterDropdownSearchSelection());
      return KeyEventResult.handled;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyX) {
      unawaited(_cutFilterDropdownSearchSelection());
      return KeyEventResult.handled;
    }
    if (isShortcutPressed && event.logicalKey == LogicalKeyboardKey.keyV) {
      unawaited(_pasteIntoFilterDropdownSearchSelection());
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  TextRange? _filterDropdownSearchSelectedRange() {
    final selection = _filterDropdownSearchController.selection;
    if (!selection.isValid || selection.isCollapsed) {
      return null;
    }
    return TextRange(
      start: math.min(selection.start, selection.end),
      end: math.max(selection.start, selection.end),
    );
  }

  Future<void> _copyFilterDropdownSearchSelection() async {
    final range = _filterDropdownSearchSelectedRange();
    if (range == null) {
      return;
    }
    await Clipboard.setData(
      ClipboardData(
        text: _filterDropdownSearchController.text.substring(
          range.start,
          range.end,
        ),
      ),
    );
  }

  Future<void> _cutFilterDropdownSearchSelection() async {
    final range = _filterDropdownSearchSelectedRange();
    if (range == null) {
      return;
    }
    final text = _filterDropdownSearchController.text;
    await Clipboard.setData(
      ClipboardData(text: text.substring(range.start, range.end)),
    );
    if (!mounted) {
      return;
    }
    setState(() {
      _filterDropdownSearchController.value = TextEditingValue(
        text: text.replaceRange(range.start, range.end, ''),
        selection: TextSelection.collapsed(offset: range.start),
      );
      _filterDropdownScrollOffset = 0;
    });
  }

  Future<void> _pasteIntoFilterDropdownSearchSelection() async {
    final data = await Clipboard.getData(Clipboard.kTextPlain);
    final pasteText = data?.text;
    if (pasteText == null || !mounted) {
      return;
    }
    final text = _filterDropdownSearchController.text;
    final selection = _filterDropdownSearchController.selection;
    final start = selection.isValid
        ? math.min(selection.start, selection.end)
        : text.length;
    final end = selection.isValid
        ? math.max(selection.start, selection.end)
        : text.length;
    final nextText = text.replaceRange(start, end, pasteText);
    setState(() {
      _filterDropdownSearchController.value = TextEditingValue(
        text: nextText,
        selection: TextSelection.collapsed(offset: start + pasteText.length),
      );
      _filterDropdownScrollOffset = 0;
    });
  }

  TextEditingController? _controllerForTextInputFocusNode(FocusNode node) {
    if (identical(node, _commentEditorFocusNode)) {
      return _commentEditorController;
    }
    if (identical(node, _conditionRuleEditorFocusNode)) {
      return _conditionRuleEditorController;
    }
    if (identical(node, _conditionRuleSecondEditorFocusNode)) {
      return _conditionRuleSecondEditorController;
    }
    if (identical(node, _hyperlinkDisplayEditorFocusNode)) {
      return _hyperlinkDisplayEditorController;
    }
    if (identical(node, _hyperlinkAddressEditorFocusNode)) {
      return _hyperlinkAddressEditorController;
    }
    if (identical(node, _axisSizeEditorFocusNode)) {
      return _axisSizeEditorController;
    }
    if (identical(node, _dataVerificationEditorFocusNode)) {
      return _dataVerificationEditorController;
    }
    if (identical(node, _dataVerificationRangeEditorFocusNode)) {
      return _dataVerificationRangeEditorController;
    }
    if (identical(node, _dataVerificationSecondEditorFocusNode)) {
      return _dataVerificationSecondEditorController;
    }
    if (identical(node, _dataVerificationHintEditorFocusNode)) {
      return _dataVerificationHintEditorController;
    }
    if (identical(node, _formulaSearchEditorFocusNode)) {
      return _formulaSearchEditorController;
    }
    if (identical(node, _formatSearchDecimalFocusNode)) {
      return _formatSearchDecimalController;
    }
    if (identical(node, _searchEditorFocusNode)) {
      return _searchEditorController;
    }
    if (identical(node, _replaceEditorFocusNode)) {
      return _replaceEditorController;
    }
    if (identical(node, _splitTextOtherFocusNode)) {
      return _splitTextOtherController;
    }
    for (final input in _imageInsertDialogInputs) {
      if (identical(node, input.focusNode)) {
        return input.controller;
      }
    }
    for (final input in _barcodeDialogInputs) {
      if (identical(node, input.focusNode)) {
        return input.controller;
      }
    }
    return null;
  }

  bool _handleDialogFocusTraversalKeyEvent(KeyEvent event) {
    if (event is! KeyDownEvent ||
        event.logicalKey != LogicalKeyboardKey.tab ||
        HardwareKeyboard.instance.isAltPressed ||
        HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed) {
      return false;
    }
    return _focusAdjacentDialogControl(
      previous: HardwareKeyboard.instance.isShiftPressed,
    );
  }

  bool _focusAdjacentDialogControl({required bool previous}) {
    final nodes = _activeDialogFocusNodes();
    if (nodes.isEmpty) {
      return false;
    }
    final currentIndex = nodes.indexWhere((node) => node.hasFocus);
    final nextIndex = currentIndex < 0
        ? (previous ? nodes.length - 1 : 0)
        : previous
        ? (currentIndex - 1 + nodes.length) % nodes.length
        : (currentIndex + 1) % nodes.length;
    _focusDialogControl(nodes[nextIndex]);
    return true;
  }

  List<FocusNode> _activeDialogFocusNodes() {
    if (_imageInsertDialogOpen) {
      return _sortDialogFocusNodesByVisibleOrder(
        _imageInsertDialogInputs
            .map((input) => input.focusNode)
            .toList(growable: false),
      );
    }
    if (_barcodeDialogOpen) {
      return _sortDialogFocusNodesByVisibleOrder(
        _barcodeDialogInputs
            .map((input) => input.focusNode)
            .toList(growable: false),
      );
    }
    if (_axisSizeDialogOpen) {
      return [_axisSizeEditorFocusNode];
    }
    if (_hyperlinkDialogOpen && !_hyperlinkDialogSelectingCellRange) {
      return _sortDialogFocusNodesByVisibleOrder([
        if (_hyperlinkDialogDisplayInputRect() != null)
          _hyperlinkDisplayEditorFocusNode,
        _hyperlinkAddressEditorFocusNode,
      ]);
    }
    if (_dataVerificationDialogOpen && !_dataVerificationDialogSelectingRange) {
      return _sortDialogFocusNodesByVisibleOrder([
        _dataVerificationRangeEditorFocusNode,
        _dataVerificationEditorFocusNode,
        if (_dataVerificationDialogUsesSecondValueInput(
          _dataVerificationDialogType,
          _dataVerificationDialogType2,
        ))
          _dataVerificationSecondEditorFocusNode,
        _dataVerificationHintEditorFocusNode,
      ]);
    }
    if (_splitTextDialogOpen) {
      return [_splitTextOtherFocusNode];
    }
    if (_formatSearchDialogOpen &&
        _formatSearchType != fortuneToolbarFormatMoreDateTimeCommand) {
      return [_formatSearchDecimalFocusNode];
    }
    if (_formulaSearchDialogOpen) {
      return [_formulaSearchEditorFocusNode];
    }
    if (_conditionRuleDialogOpen) {
      return _sortDialogFocusNodesByVisibleOrder([
        _conditionRuleEditorFocusNode,
        if (_conditionRuleSecondInputRect() != null)
          _conditionRuleSecondEditorFocusNode,
      ]);
    }
    if (_searchDialogOpen) {
      return _sortDialogFocusNodesByVisibleOrder([
        _searchEditorFocusNode,
        if (_searchReplaceMode) _replaceEditorFocusNode,
      ]);
    }
    return const <FocusNode>[];
  }

  List<FocusNode> _sortDialogFocusNodesByVisibleOrder(List<FocusNode> nodes) {
    final indexed = [
      for (var index = 0; index < nodes.length; index += 1)
        (
          index: index,
          node: nodes[index],
          rect: _dialogFocusNodeRect(nodes[index]),
        ),
    ];
    indexed.sort((left, right) {
      final leftRect = left.rect;
      final rightRect = right.rect;
      if (leftRect == null || rightRect == null) {
        return left.index.compareTo(right.index);
      }
      final top = leftRect.top.compareTo(rightRect.top);
      if (top != 0) {
        return top;
      }
      final horizontal = leftRect.left.compareTo(rightRect.left);
      if (horizontal != 0) {
        return horizontal;
      }
      return left.index.compareTo(right.index);
    });
    return [for (final item in indexed) item.node];
  }

  Rect? _dialogFocusNodeRect(FocusNode node) {
    if (identical(node, _imageInsertWidthFocusNode)) {
      return _imageInsertWidthInputRect();
    }
    if (identical(node, _imageInsertHeightFocusNode)) {
      return _imageInsertHeightInputRect();
    }
    if (identical(node, _imageInsertRotationFocusNode)) {
      return _imageInsertRotationInputRect();
    }
    if (identical(node, _barcodeTextFocusNode)) {
      return _barcodeTextInputRect();
    }
    if (identical(node, _barcodeModuleScaleFocusNode)) {
      return _barcodeModuleScaleInputRect();
    }
    if (identical(node, _barcodeBarHeightFocusNode)) {
      return _barcodeBarHeightInputRect();
    }
    if (identical(node, _barcodeWidthFocusNode)) {
      return _barcodeWidthInputRect();
    }
    if (identical(node, _barcodeHeightFocusNode)) {
      return _barcodeHeightInputRect();
    }
    if (identical(node, _barcodeRotationFocusNode)) {
      return _barcodeRotationInputRect();
    }
    if (identical(node, _barcodeLeadingQuietZoneFocusNode)) {
      return _barcodeLeadingQuietZoneInputRect();
    }
    if (identical(node, _barcodeTrailingQuietZoneFocusNode)) {
      return _barcodeTrailingQuietZoneInputRect();
    }
    if (identical(node, _hyperlinkDisplayEditorFocusNode)) {
      return _hyperlinkDialogDisplayInputRect();
    }
    if (identical(node, _hyperlinkAddressEditorFocusNode)) {
      return _hyperlinkDialogAddressEditorRect();
    }
    if (identical(node, _dataVerificationRangeEditorFocusNode)) {
      final rect = _dataVerificationDialogRect();
      return rect == null ? null : fortuneDataVerificationRangeInputRect(rect);
    }
    if (identical(node, _dataVerificationEditorFocusNode)) {
      return _dataVerificationDialogInputRect();
    }
    if (identical(node, _dataVerificationSecondEditorFocusNode)) {
      final rect = _dataVerificationDialogRect();
      return rect == null ? null : fortuneDataVerificationAllowMultiRect(rect);
    }
    if (identical(node, _dataVerificationHintEditorFocusNode)) {
      return _dataVerificationDialogHintInputRect();
    }
    if (identical(node, _conditionRuleEditorFocusNode)) {
      return _conditionRuleInputRect();
    }
    if (identical(node, _conditionRuleSecondEditorFocusNode)) {
      return _conditionRuleSecondInputRect();
    }
    if (identical(node, _searchEditorFocusNode)) {
      return _searchDialogInputRect();
    }
    if (identical(node, _replaceEditorFocusNode)) {
      return _searchDialogReplaceInputRect();
    }
    return null;
  }

  void _focusDialogControl(FocusNode node) {
    final controller = _controllerForTextInputFocusNode(node);
    if (controller != null) {
      controller.selection = TextSelection(
        baseOffset: 0,
        extentOffset: controller.text.length,
      );
    }
    node.requestFocus();
  }

  KeyEventResult _handleFocusedTextEditingShortcut(
    FocusNode node,
    KeyEvent event,
  ) {
    final controller = _controllerForTextInputFocusNode(node);
    if (controller == null) {
      return KeyEventResult.ignored;
    }
    return _handleTextEditingShortcut(controller, event)
        ? KeyEventResult.handled
        : KeyEventResult.ignored;
  }

  bool _handleTextEditingShortcut(
    TextEditingController controller,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
      return false;
    }
    final keyboard = HardwareKeyboard.instance;
    final primaryModifier = keyboard.isControlPressed || keyboard.isMetaPressed;
    final key = event.logicalKey;
    if (primaryModifier && key == LogicalKeyboardKey.keyA) {
      controller.selection = TextSelection(
        baseOffset: 0,
        extentOffset: controller.text.length,
      );
      return true;
    }
    if ((primaryModifier && key == LogicalKeyboardKey.keyC) ||
        (keyboard.isControlPressed && key == LogicalKeyboardKey.insert)) {
      _copyTextEditingSelection(controller, cut: false);
      return true;
    }
    if ((primaryModifier && key == LogicalKeyboardKey.keyX) ||
        (keyboard.isShiftPressed && key == LogicalKeyboardKey.delete)) {
      _copyTextEditingSelection(controller, cut: true);
      return true;
    }
    if ((primaryModifier && key == LogicalKeyboardKey.keyV) ||
        (keyboard.isShiftPressed && key == LogicalKeyboardKey.insert)) {
      unawaited(_pasteTextEditingSelection(controller));
      return true;
    }
    return false;
  }

  void _copyTextEditingSelection(
    TextEditingController controller, {
    required bool cut,
  }) {
    final selection = controller.selection;
    if (!selection.isValid || selection.isCollapsed) {
      return;
    }
    final text = controller.text;
    final selectedText = selection.textInside(text);
    unawaited(Clipboard.setData(ClipboardData(text: selectedText)));
    if (!cut) {
      return;
    }
    final start = math.min(selection.start, selection.end);
    final end = math.max(selection.start, selection.end);
    controller.value = TextEditingValue(
      text: text.replaceRange(start, end, ''),
      selection: TextSelection.collapsed(offset: start),
    );
  }

  Future<void> _pasteTextEditingSelection(
    TextEditingController controller,
  ) async {
    final data = await Clipboard.getData(Clipboard.kTextPlain);
    final pasteText = data?.text;
    if (pasteText == null || pasteText.isEmpty) {
      return;
    }
    final value = controller.value;
    final text = value.text;
    final selection = value.selection.isValid
        ? value.selection
        : TextSelection.collapsed(offset: text.length);
    final start = math.min(selection.start, selection.end);
    final end = math.max(selection.start, selection.end);
    controller.value = TextEditingValue(
      text: text.replaceRange(start, end, pasteText),
      selection: TextSelection.collapsed(offset: start + pasteText.length),
    );
  }

  Widget _buildTextEditingShortcutActions(
    TextEditingController controller,
    Widget child,
  ) {
    return Shortcuts(
      shortcuts: const <ShortcutActivator, Intent>{
        SingleActivator(LogicalKeyboardKey.keyA, control: true):
            _FortuneSelectAllTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyA, meta: true):
            _FortuneSelectAllTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyC, control: true):
            _FortuneCopyTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyC, meta: true):
            _FortuneCopyTextIntent(),
        SingleActivator(LogicalKeyboardKey.insert, control: true):
            _FortuneCopyTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyX, control: true):
            _FortuneCutTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyX, meta: true):
            _FortuneCutTextIntent(),
        SingleActivator(LogicalKeyboardKey.delete, shift: true):
            _FortuneCutTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyV, control: true):
            _FortunePasteTextIntent(),
        SingleActivator(LogicalKeyboardKey.keyV, meta: true):
            _FortunePasteTextIntent(),
        SingleActivator(LogicalKeyboardKey.insert, shift: true):
            _FortunePasteTextIntent(),
      },
      child: Actions(
        actions: <Type, Action<Intent>>{
          _FortuneSelectAllTextIntent:
              CallbackAction<_FortuneSelectAllTextIntent>(
                onInvoke: (_) {
                  controller.selection = TextSelection(
                    baseOffset: 0,
                    extentOffset: controller.text.length,
                  );
                  return null;
                },
              ),
          _FortuneCopyTextIntent: CallbackAction<_FortuneCopyTextIntent>(
            onInvoke: (_) {
              _copyTextEditingSelection(controller, cut: false);
              return null;
            },
          ),
          _FortuneCutTextIntent: CallbackAction<_FortuneCutTextIntent>(
            onInvoke: (_) {
              _copyTextEditingSelection(controller, cut: true);
              return null;
            },
          ),
          _FortunePasteTextIntent: CallbackAction<_FortunePasteTextIntent>(
            onInvoke: (_) {
              unawaited(_pasteTextEditingSelection(controller));
              return null;
            },
          ),
        },
        child: child,
      ),
    );
  }

  Widget _buildDialogTextEditingShortcutActions(
    TextEditingController controller,
    Widget child,
  ) {
    return Shortcuts(
      shortcuts: const <ShortcutActivator, Intent>{
        SingleActivator(LogicalKeyboardKey.tab):
            _FortuneNextDialogFocusIntent(),
        SingleActivator(LogicalKeyboardKey.tab, shift: true):
            _FortunePreviousDialogFocusIntent(),
      },
      child: Actions(
        actions: <Type, Action<Intent>>{
          _FortuneNextDialogFocusIntent:
              CallbackAction<_FortuneNextDialogFocusIntent>(
                onInvoke: (_) {
                  _focusAdjacentDialogControl(previous: false);
                  return null;
                },
              ),
          _FortunePreviousDialogFocusIntent:
              CallbackAction<_FortunePreviousDialogFocusIntent>(
                onInvoke: (_) {
                  _focusAdjacentDialogControl(previous: true);
                  return null;
                },
              ),
        },
        child: _buildTextEditingShortcutActions(controller, child),
      ),
    );
  }

  KeyEventResult _handleCommentEditorKeyEvent(FocusNode node, KeyEvent event) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    final shortcutResult = _handleFocusedTextEditingShortcut(node, event);
    if (shortcutResult != KeyEventResult.ignored) {
      return shortcutResult;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      _cancelEditing();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter &&
        !HardwareKeyboard.instance.isShiftPressed) {
      _commitCommentEditing();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  KeyEventResult _handleHyperlinkDialogEditorKeyEvent(
    FocusNode node,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    final shortcutResult = _handleFocusedTextEditingShortcut(node, event);
    if (shortcutResult != KeyEventResult.ignored) {
      return shortcutResult;
    }
    if (_handleDialogFocusTraversalKeyEvent(event)) {
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      if (_hyperlinkDialogSelectingCellRange) {
        _closeHyperlinkDialogRangeSelection();
      } else {
        setState(() {
          _hyperlinkDialogCoord = null;
          _hyperlinkDialogSelectingCellRange = false;
          _hyperlinkDialogRangeSelectionOriginAddress = null;
          _hyperlinkDialogRangeSelectionAnchor = null;
        });
      }
      _focusNode.requestFocus();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter) {
      _commitHyperlinkDialog();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

