  KeyEventResult _handleInlineMenuNumberEditorKeyEvent(
    TextEditingController controller,
    KeyEvent event, {
    required VoidCallback onEscape,
    required VoidCallback onEnter,
  }) {
    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
      return KeyEventResult.ignored;
    }
    if (_handleTextEditingShortcut(controller, event)) {
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      onEscape();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter) {
      onEnter();
      return KeyEventResult.handled;
    }
    if (_applyTextEditorNavigationKey(controller, event)) {
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  bool _applyTextEditorNavigationKey(
    TextEditingController controller,
    KeyEvent event, {
    bool multiline = false,
  }) {
    if (HardwareKeyboard.instance.isAltPressed) {
      return false;
    }
    final isShortcutPressed =
        HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed;
    final text = controller.text;
    final selection = controller.selection;
    var start = selection.start;
    var end = selection.end;
    if (!selection.isValid) {
      start = text.length;
      end = text.length;
    }
    start = start.clamp(0, text.length);
    end = end.clamp(0, text.length);
    final rangeStart = math.min(start, end);
    final rangeEnd = math.max(start, end);

    void updateText(String value, int offset) {
      final nextValue = TextEditingValue(
        text: value,
        selection: TextSelection.collapsed(
          offset: offset.clamp(0, value.length),
        ),
      );
      if (identical(controller, _editorController)) {
        _setEditorValueFromUserEdit(nextValue);
      } else {
        controller.value = nextValue;
      }
    }

    void updateSelection(int offset) {
      final nextSelection = TextSelection.collapsed(
        offset: offset.clamp(0, text.length),
      );
      if (identical(controller, _editorController)) {
        _inlineToolbarSelectionRange = null;
        _setEditorValueFromUserEdit(
          controller.value.copyWith(selection: nextSelection),
        );
      } else {
        controller.selection = nextSelection;
      }
    }

    void extendSelection(int offset) {
      final extent = offset.clamp(0, text.length);
      final nextSelection = TextSelection(
        baseOffset: selection.isValid ? selection.baseOffset : rangeStart,
        extentOffset: extent,
      );
      if (identical(controller, _editorController)) {
        _setEditorValueFromUserEdit(
          controller.value.copyWith(selection: nextSelection),
        );
      } else {
        controller.selection = nextSelection;
      }
    }

    void moveSelection(int offset) {
      if (HardwareKeyboard.instance.isShiftPressed) {
        extendSelection(offset);
      } else {
        updateSelection(offset);
      }
    }

    int lineStartFor(int offset) {
      final before = text.lastIndexOf('\n', math.max(0, offset - 1));
      return before < 0 ? 0 : before + 1;
    }

    int lineEndFor(int offset) {
      final after = text.indexOf('\n', offset.clamp(0, text.length));
      return after < 0 ? text.length : after;
    }

    int verticalOffset({required bool down}) {
      if (!multiline) {
        return down ? text.length : 0;
      }
      final caret = HardwareKeyboard.instance.isShiftPressed
          ? (selection.isValid ? selection.extentOffset : rangeStart)
          : down
          ? rangeEnd
          : rangeStart;
      final currentLineStart = lineStartFor(caret);
      final currentLineEnd = lineEndFor(caret);
      final desiredColumn = (caret - currentLineStart).clamp(
        0,
        currentLineEnd - currentLineStart,
      );
      if (down) {
        if (currentLineEnd >= text.length) {
          return text.length;
        }
        final nextLineStart = currentLineEnd + 1;
        final nextLineEnd = lineEndFor(nextLineStart);
        return math.min(nextLineStart + desiredColumn, nextLineEnd);
      }
      if (currentLineStart <= 0) {
        return 0;
      }
      final previousLineEnd = currentLineStart - 1;
      final previousLineStart = lineStartFor(previousLineEnd);
      return math.min(previousLineStart + desiredColumn, previousLineEnd);
    }

    int horizontalOffset({required bool right}) {
      if (!multiline) {
        return right ? text.length : 0;
      }
      final caret = HardwareKeyboard.instance.isShiftPressed
          ? (selection.isValid ? selection.extentOffset : rangeStart)
          : right
          ? rangeEnd
          : rangeStart;
      return right ? lineEndFor(caret) : lineStartFor(caret);
    }

    bool isWordCharacter(String character) {
      return RegExp(r'[A-Za-z0-9_]').hasMatch(character);
    }

    int previousWordOffset(int offset) {
      var index = offset.clamp(0, text.length);
      while (index > 0 && !isWordCharacter(text[index - 1])) {
        index -= 1;
      }
      while (index > 0 && isWordCharacter(text[index - 1])) {
        index -= 1;
      }
      return index;
    }

    int nextWordOffset(int offset) {
      var index = offset.clamp(0, text.length);
      while (index < text.length && !isWordCharacter(text[index])) {
        index += 1;
      }
      while (index < text.length && isWordCharacter(text[index])) {
        index += 1;
      }
      return index;
    }

    int shortcutCaret({required bool right}) {
      if (HardwareKeyboard.instance.isShiftPressed) {
        return selection.isValid ? selection.extentOffset : rangeStart;
      }
      if (!selection.isCollapsed) {
        return right ? rangeEnd : rangeStart;
      }
      return rangeStart;
    }

    if (isShortcutPressed) {
      switch (event.logicalKey) {
        case LogicalKeyboardKey.arrowLeft:
          moveSelection(previousWordOffset(shortcutCaret(right: false)));
          return true;
        case LogicalKeyboardKey.arrowRight:
          moveSelection(nextWordOffset(shortcutCaret(right: true)));
          return true;
        case LogicalKeyboardKey.home:
          moveSelection(0);
          return true;
        case LogicalKeyboardKey.end:
          moveSelection(text.length);
          return true;
      }
      return false;
    }

    switch (event.logicalKey) {
      case LogicalKeyboardKey.arrowLeft:
        moveSelection(
          HardwareKeyboard.instance.isShiftPressed && selection.isValid
              ? selection.extentOffset - 1
              : selection.isCollapsed
              ? rangeStart - 1
              : rangeStart,
        );
        return true;
      case LogicalKeyboardKey.arrowRight:
        moveSelection(
          HardwareKeyboard.instance.isShiftPressed && selection.isValid
              ? selection.extentOffset + 1
              : selection.isCollapsed
              ? rangeEnd + 1
              : rangeEnd,
        );
        return true;
      case LogicalKeyboardKey.arrowUp:
        moveSelection(verticalOffset(down: false));
        return true;
      case LogicalKeyboardKey.arrowDown:
        moveSelection(verticalOffset(down: true));
        return true;
      case LogicalKeyboardKey.home:
        moveSelection(horizontalOffset(right: false));
        return true;
      case LogicalKeyboardKey.end:
        moveSelection(horizontalOffset(right: true));
        return true;
      case LogicalKeyboardKey.backspace:
        if (rangeStart != rangeEnd) {
          updateText(text.replaceRange(rangeStart, rangeEnd, ''), rangeStart);
          return true;
        }
        if (rangeStart <= 0) {
          return true;
        }
        updateText(
          text.replaceRange(rangeStart - 1, rangeStart, ''),
          rangeStart - 1,
        );
        return true;
      case LogicalKeyboardKey.delete:
        if (rangeStart != rangeEnd) {
          updateText(text.replaceRange(rangeStart, rangeEnd, ''), rangeStart);
          return true;
        }
        if (rangeStart >= text.length) {
          return true;
        }
        updateText(
          text.replaceRange(rangeStart, rangeStart + 1, ''),
          rangeStart,
        );
        return true;
    }
    return false;
  }

  KeyEventResult _handleToolbarBorderStyleWidthKeyEvent(
    int style,
    FocusNode node,
    KeyEvent event,
  ) {
    final controller = _toolbarBorderStyleWidthControllers[style];
    if (controller == null) {
      return KeyEventResult.ignored;
    }
    return _handleInlineMenuNumberEditorKeyEvent(
      controller,
      event,
      onEscape: () {
        controller.text = _formatToolbarBorderStyleWidth(
          _toolbarBorderStyleStrokeWidths[style] ?? 2,
        );
        _focusNode.requestFocus();
      },
      onEnter: () => _commitToolbarBorderStyleWidth(style),
    );
  }

  KeyEventResult _handleContextMenuInlineInputKeyEvent(
    String command,
    FocusNode node,
    KeyEvent event,
  ) {
    final controller = _contextMenuInlineInputControllers[command];
    if (controller == null) {
      return KeyEventResult.ignored;
    }
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.tab &&
        !HardwareKeyboard.instance.isAltPressed &&
        !HardwareKeyboard.instance.isControlPressed &&
        !HardwareKeyboard.instance.isMetaPressed) {
      _focusAdjacentContextMenuInlineInput(
        command,
        previous: HardwareKeyboard.instance.isShiftPressed,
      );
      return KeyEventResult.handled;
    }
    return _handleInlineMenuNumberEditorKeyEvent(
      controller,
      event,
      onEscape: () {
        final wasEditorContextMenu = _contextMenuIsEditor;
        final range = _inlineToolbarSelectionRange;
        setState(_closeTransientMenus);
        if (wasEditorContextMenu && range != null) {
          _refocusEditorAndRestoreInlineToolbarSelectionRange(range);
        } else {
          _focusNode.requestFocus();
        }
      },
      onEnter: () => _commitContextMenuInlineInput(command),
    );
  }

  void _focusAdjacentContextMenuInlineInput(
    String command, {
    required bool previous,
  }) {
    final commands = _activeContextMenuItems
        .where(fortuneContextMenuItemHasInlineInput)
        .where(_contextMenuInlineInputFocusNodes.containsKey)
        .toList(growable: false);
    if (commands.length < 2) {
      return;
    }
    final index = commands.indexOf(command);
    if (index < 0) {
      return;
    }
    final nextIndex = previous
        ? (index - 1 + commands.length) % commands.length
        : (index + 1) % commands.length;
    _focusContextMenuInlineInput(commands[nextIndex]);
  }

  void _commitToolbarBorderStyleWidth(int style) {
    final controller = _toolbarBorderStyleWidthControllers[style];
    if (controller == null) {
      return;
    }
    final nextWidth = _toolbarBorderStyleWidthInputValue(style);
    final sheet = _workbook.activeSheet;
    final range = _borderCommandRange(sheet);
    final borderUpdates = _canEditRange(sheet, range)
        ? _existingBorderStyleColorUpdates(
            sheet,
            range,
            color: _toolbarRecentBorderColor,
            rawColor: _toolbarRecentBorderRawColor,
            style: style,
            strokeWidth: nextWidth,
          )
        : const <FortuneBorderInfo>[];
    if (borderUpdates.isNotEmpty) {
      _recordUndoSnapshot();
    }
    setState(() {
      _toolbarRecentBorderStyle = style;
      _toolbarBorderStyleStrokeWidths = {
        ..._toolbarBorderStyleStrokeWidths,
        style: nextWidth,
      };
      _syncToolbarBorderStyleWidthController(style, nextWidth);
      if (borderUpdates.isNotEmpty) {
        final sheets = [..._workbook.sheets];
        sheets[_workbook.activeSheetIndex] = sheet.copyWith(
          borderInfo: [...sheet.borderInfo, ...borderUpdates],
        );
        _workbook = _workbook.copyWith(sheets: sheets);
      }
      _closeTransientMenus();
    });
    _focusNode.requestFocus();
  }

  double _toolbarBorderStyleWidthInputValue(int style) {
    final controller = _toolbarBorderStyleWidthControllers[style];
    final parsed = double.tryParse(controller?.text.trim() ?? '');
    return (parsed ?? 2).clamp(2.0, 4.0).toDouble();
  }

  void _syncToolbarBorderStyleWidthController(int style, double width) {
    final controller = _toolbarBorderStyleWidthControllers[style];
    if (controller == null) {
      return;
    }
    final text = _formatToolbarBorderStyleWidth(width);
    controller.value = TextEditingValue(
      text: text,
      selection: TextSelection.collapsed(offset: text.length),
    );
  }

  void _commitContextMenuInlineInput(String command) {
    final commands = _changedContextMenuInlineInputCommands(command);
    for (final changedCommand in commands) {
      if (!_commitSingleContextMenuInlineInput(changedCommand)) {
        return;
      }
    }
  }

  List<String> _changedContextMenuInlineInputCommands(String fallbackCommand) {
    final commands = <String>[];
    for (final command in _activeContextMenuItems) {
      if (!fortuneContextMenuItemHasInlineInput(command)) {
        continue;
      }
      final controller = _contextMenuInlineInputControllers[command];
      final initialText = _contextMenuInlineInputInitialTexts[command];
      if (controller == null || initialText == null) {
        continue;
      }
      if (controller.text.trim() != initialText.trim()) {
        commands.add(command);
      }
    }
    return commands.isEmpty ? <String>[fallbackCommand] : commands;
  }

  bool _commitSingleContextMenuInlineInput(String command) {
    if (_contextMenuIsEditor && _isEditorContextInlineInputCommand(command)) {
      return _commitEditorContextInlineInput(command);
    }
    if (command == fortuneContextSetRowHeightCommand ||
        command == fortuneContextSetColumnWidthCommand ||
        command == fortuneContextSetLabelWidthCommand ||
        command == fortuneContextSetLabelHeightCommand) {
      return _commitContextMenuAxisSize(command);
    }
    _activateContextMenuCommand(command);
    return true;
  }

  KeyEventResult _handleDataVerificationEditorKeyEvent(
    FocusNode node,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    final shortcutResult = _handleFocusedTextEditingShortcut(node, event);
    if (shortcutResult != KeyEventResult.ignored) {
      return shortcutResult;
    }
    if (_handleDialogFocusTraversalKeyEvent(event)) {
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      setState(() {
        _dataVerificationDialogCoord = null;
        _dataVerificationDialogRange = null;
        _dataVerificationRangeEditorController.clear();
      });
      _focusNode.requestFocus();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter) {
      _commitDataVerificationDialog();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  KeyEventResult _handleFormulaSearchEditorKeyEvent(
    FocusNode node,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent) {
      return KeyEventResult.ignored;
    }
    final shortcutResult = _handleFocusedTextEditingShortcut(node, event);
    if (shortcutResult != KeyEventResult.ignored) {
      return shortcutResult;
    }
    if (_handleDialogFocusTraversalKeyEvent(event)) {
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      setState(() {
        _formulaSearchDialogOpen = false;
        _formulaSearchCategoryMenuOpen = false;
      });
      _focusNode.requestFocus();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.enter) {
      _confirmFormulaSearchDialog();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  KeyEventResult _handleDialogTextEditorKeyEvent(
    FocusNode node,
    KeyEvent event,
  ) {
    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
      return KeyEventResult.ignored;
    }
    final shortcutResult = _handleFocusedTextEditingShortcut(node, event);
    if (shortcutResult != KeyEventResult.ignored) {
      return shortcutResult;
    }
    if (_handleDialogFocusTraversalKeyEvent(event)) {
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  Rect? _editingRect() {
    final coord = _editingCoord;
    if (coord == null) {
      return null;
    }
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    if (coord.row < 0 ||
        coord.column < 0 ||
        coord.row >= metrics.visibleDataRows.length ||
        coord.column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final cell = sheet.cells[coord];
    final merge = cell?.merge;
    final rowSpan = math.max(1, merge?.rowSpan ?? 1);
    final columnSpan = math.max(1, merge?.columnSpan ?? 1);
    final rowEnd = math.min(
      metrics.visibleDataRows.length - 1,
      coord.row + rowSpan - 1,
    );
    final columnEnd = math.min(
      metrics.visibleDataColumns.length - 1,
      coord.column + columnSpan - 1,
    );
    final startX = metrics.columnStart(coord.column);
    final endX = metrics.columnEnd(columnEnd);
    final startY = metrics.rowStart(coord.row);
    final endY = metrics.rowEnd(rowEnd);
    if (endX <= startX || endY <= startY) {
      return null;
    }
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    return Rect.fromLTWH(
      _visualCellLeft(coord.column, settings, metrics),
      sheetTop + _visualCellTop(coord.row, settings, metrics),
      endX - startX,
      endY - startY,
    ).inflate(1);
  }

  RenderEditable? _editorRenderEditable() {
    final context = _editorEditableKey.currentContext;
    if (context == null) {
      return null;
    }
    final renderObject = context.findRenderObject();
    if (renderObject is RenderEditable) {
      return renderObject;
    }
    RenderEditable? result;
    void visit(Element element) {
      if (result != null) {
        return;
      }
      final childRenderObject = element.findRenderObject();
      if (childRenderObject is RenderEditable) {
        result = childRenderObject;
        return;
      }
      element.visitChildren(visit);
    }

    (context as Element).visitChildren(visit);
    return result;
  }

  int? _editorTextOffsetForGlobalPosition(Offset globalPosition) {
    final renderEditable = _editorRenderEditable();
    if (renderEditable == null) {
      return null;
    }
    final position = renderEditable.getPositionForPoint(globalPosition);
    return math.min(
      math.max(position.offset, 0),
      _editorController.text.length,
    );
  }

  Offset _canvasLocalPositionForGlobal(Offset globalPosition) {
    final renderObject = context.findRenderObject();
    if (renderObject is RenderBox) {
      return renderObject.globalToLocal(globalPosition);
    }
    return globalPosition;
  }

  void _startEditorSelectionDrag(PointerDownEvent event) {
    if (_editingCoord == null) {
      return;
    }
    final menuAt = contextMenuAt;
    final canvasLocal = _canvasLocalPositionForGlobal(event.position);
    if (_contextMenuIsEditor &&
        menuAt != null &&
        fortuneContextMenuRect(
          menuAt,
          _editorContextMenuItems,
        ).contains(canvasLocal)) {
      fortuneSheetDebugLog(
        'editor selectionDrag ignored contextMenuHit '
        'pointer=${event.pointer} buttons=${event.buttons} '
        'canvasLocal=${canvasLocal.dx.toStringAsFixed(1)},${canvasLocal.dy.toStringAsFixed(1)} '
        'menuAt=$menuAt selection=${_debugSelection(_editorController.selection)}',
      );
      return;
    }
    if (_toolbarPopupEventContains(canvasLocal)) {
      fortuneSheetDebugLog(
        'editor selectionDrag ignored toolbarPopupHit '
        'pointer=${event.pointer} buttons=${event.buttons} '
        'canvasLocal=${canvasLocal.dx.toStringAsFixed(1)},${canvasLocal.dy.toStringAsFixed(1)} '
        'toolbarPopupKey=$toolbarPopupKey '
        'selection=${_debugSelection(_editorController.selection)} '
        'stored=${_debugRange(_inlineToolbarSelectionRange)}',
      );
      return;
    }
    final offset = _editorTextOffsetForGlobalPosition(event.position);
    if (offset == null) {
      return;
    }
    _editorFocusNode.requestFocus();
    if (event.kind == PointerDeviceKind.mouse &&
        (event.buttons & kSecondaryMouseButton) != 0) {
      _showEditorContextMenu(event, offset, openingPointer: event.pointer);
      return;
    }
    if (contextMenuAt != null) {
      setState(_closeTransientMenus);
    }
    _inlineToolbarSelectionRange = null;
    _editorDragSelectionPointer = event.pointer;
    _editorDragSelectionBaseOffset = offset;
    _editorController.selection = TextSelection.collapsed(offset: offset);
  }

  void _showEditorContextMenu(
    PointerDownEvent event,
    int offset, {
    int? openingPointer,
  }) {
    final selection = _editorController.selection;
    final selectedRange = selection.isValid && !selection.isCollapsed
        ? TextRange(
            start: math.min(selection.start, selection.end),
            end: math.max(selection.start, selection.end),
          )
        : _inlineToolbarFormatRange();
    final keepSelection = selectedRange != null;
    final keepCollapsedCaret = !keepSelection && selection.isValid;
    fortuneSheetDebugLog(
      'editor contextMenu open offset=$offset keepSelection=$keepSelection '
      'keepCollapsedCaret=$keepCollapsedCaret '
      'openingPointer=$openingPointer '
      'selectedRange=${_debugRange(selectedRange)} '
      'selection=${_debugSelection(selection)} value=${_debugValue(_editorController.value)}',
    );
    setState(() {
      _editorContextMenuOpeningPointer = openingPointer;
      if (!keepSelection && !keepCollapsedCaret) {
        _editorController.selection = TextSelection.collapsed(offset: offset);
      }
      _editorContextMenuSelectionRange = keepSelection ? selectedRange : null;
      final menuItems = _editorContextMenuItems;
      _syncContextMenuInlineInputControllers(menuItems);
      contextMenuAt = _contextMenuOrigin(
        _canvasLocalPositionForGlobal(event.position),
        menuItems,
      );
      _contextMenuHoveredIndex = null;
      _contextMenuIsHeader = false;
      _contextMenuIsEditor = true;
      _editorClipboardHasPasteText =
          _copiedEditorClipboardText?.isNotEmpty == true;
      _contextMenuPreviousSelectionSave = null;
      _contextMenuPreviousSelectionRange = null;
      sheetTabMenuAt = null;
      hiddenSheetListAt = null;
      dataVerificationDropdownCoord = null;
      filterDropdownColumn = null;
      _sheetTabMenuSheetIndex = null;
      toolbarPopupKey = null;
      _activeImageId = null;
    });
    unawaited(_refreshEditorClipboardAvailability());
  }

  Future<void> _refreshEditorClipboardAvailability() async {
    final menuAt = contextMenuAt;
    ClipboardData? data;
    try {
      data = await Clipboard.getData(Clipboard.kTextPlain);
    } catch (_) {
      data = null;
    }
    if (!mounted || !_contextMenuIsEditor || contextMenuAt != menuAt) {
      return;
    }
    final hasText = data?.text?.isNotEmpty == true;
    if (_editorClipboardHasPasteText == hasText) {
      return;
    }
    setState(() {
      _editorClipboardHasPasteText = hasText;
    });
  }

  void _updateEditorSelectionDrag(PointerMoveEvent event) {
    if (_editorDragSelectionPointer != event.pointer) {
      return;
    }
    final baseOffset = _editorDragSelectionBaseOffset;
    if (_editingCoord == null || baseOffset == null) {
      return;
    }
    final extentOffset = _editorTextOffsetForGlobalPosition(event.position);
    if (extentOffset == null) {
      return;
    }
    _editorController.selection = TextSelection(
      baseOffset: baseOffset,
      extentOffset: extentOffset,
    );
  }

  void _endEditorSelectionDrag(int pointer) {
    if (_editorDragSelectionPointer != pointer) {
      return;
    }
    _editorDragSelectionPointer = null;
    _editorDragSelectionBaseOffset = null;
  }

  RenderEditable? _renderEditableForKey(GlobalKey<EditableTextState> key) {
    final context = key.currentContext;
    if (context == null) {
      return null;
    }
    final renderObject = context.findRenderObject();
    if (renderObject is RenderEditable) {
      return renderObject;
    }
    RenderEditable? result;
    void visit(Element element) {
      if (result != null) {
        return;
      }
      final childRenderObject = element.findRenderObject();
      if (childRenderObject is RenderEditable) {
        result = childRenderObject;
        return;
      }
      element.visitChildren(visit);
    }

    (context as Element).visitChildren(visit);
    return result;
  }

  int? _textOffsetForGlobalPosition(
    GlobalKey<EditableTextState> key,
    TextEditingController controller,
    Offset globalPosition,
  ) {
    final renderEditable = _renderEditableForKey(key);
    if (renderEditable == null) {
      return null;
    }
    final position = renderEditable.getPositionForPoint(globalPosition);
    return math.min(math.max(position.offset, 0), controller.text.length);
  }

  void _startImageInsertInputSelectionDrag(
    PointerDownEvent event,
    TextEditingController controller,
    FocusNode focusNode,
    GlobalKey<EditableTextState> editableKey,
  ) {
    if (!_imageInsertDialogOpen && !_barcodeDialogOpen) {
      return;
    }
    ContextMenuController.removeAny();
    final offset = _textOffsetForGlobalPosition(
      editableKey,
      controller,
      event.position,
    );
    if (offset == null) {
      return;
    }
    focusNode.requestFocus();
    if (_imageInsertDialogOpen) {
      _clearImageInsertInputSelections(except: controller);
    }
    if (_barcodeDialogOpen) {
      _clearBarcodeInputSelections(except: controller);
    }
    _imageInsertDragSelectionPointer = event.pointer;
    _imageInsertDragSelectionBaseOffset = offset;
    _imageInsertDragSelectionController = controller;
    _imageInsertDragSelectionEditableKey = editableKey;
    controller.selection = TextSelection.collapsed(offset: offset);
  }

  Future<void> _showDialogEditableTextContextMenu(
    PointerDownEvent event,
    TextEditingController controller,
    FocusNode focusNode,
    GlobalKey<EditableTextState> editableKey,
  ) async {
    ContextMenuController.removeAny();
    focusNode.requestFocus();
    if (_imageInsertDialogOpen) {
      _clearImageInsertInputSelections(except: controller);
    }
    if (_barcodeDialogOpen) {
      _clearBarcodeInputSelections(except: controller);
    }
    final selection = controller.selection;
    if (!selection.isValid || selection.isCollapsed) {
      final offset = _textOffsetForGlobalPosition(
        editableKey,
        controller,
        event.position,
      );
      if (offset != null) {
        controller.selection = TextSelection.collapsed(offset: offset);
      }
    }
    final buttonItems = await _dialogEditableTextContextMenuButtonItems(
      controller,
    );
    if (buttonItems.isEmpty) {
      return;
    }
    if (!mounted) {
      return;
    }
    final editableState = editableKey.currentState;
    final editableContext = editableKey.currentContext;
    if (editableState == null || editableContext == null) {
      return;
    }
    if (!editableContext.mounted) {
      return;
    }
    ContextMenuController().show(
      context: editableContext,
      contextMenuBuilder: (context) => _dialogEditableTextSelectionToolbar(
        context,
        event.position,
        buttonItems,
      ),
      debugRequiredFor: editableState.widget,
    );
  }

  Widget _dialogEditableTextSelectionToolbar(
    BuildContext context,
    Offset primaryAnchor,
    List<ContextMenuButtonItem> buttonItems,
  ) {
    final theme = Theme.of(context);
    final enabledColor = theme.colorScheme.onSurface;
    final disabledColor = enabledColor.withValues(alpha: 0.38);
    return AdaptiveTextSelectionToolbar(
      anchors: TextSelectionToolbarAnchors(primaryAnchor: primaryAnchor),
      children: [
        for (final buttonItem in buttonItems)
          if (buttonItem.onPressed == null)
            DesktopTextSelectionToolbarButton(
              onPressed: null,
              child: Text(
                AdaptiveTextSelectionToolbar.getButtonLabel(
                  context,
                  buttonItem,
                ),
                overflow: TextOverflow.ellipsis,
                style: TextStyle(color: disabledColor),
              ),
            )
          else
            DesktopTextSelectionToolbarButton.text(
              context: context,
              onPressed: buttonItem.onPressed,
              text: AdaptiveTextSelectionToolbar.getButtonLabel(
                context,
                buttonItem,
              ),
            ),
      ],
    );
  }

  Future<List<ContextMenuButtonItem>> _dialogEditableTextContextMenuButtonItems(
    TextEditingController controller,
  ) async {
    final selection = controller.selection;
    final hasSelection = selection.isValid && !selection.isCollapsed;
    final clipboardData = await Clipboard.getData(Clipboard.kTextPlain);
    final hasClipboardText = clipboardData?.text?.isNotEmpty == true;
    final textLength = controller.text.length;
    final hasText = textLength > 0;
    final hasFullSelection =
        selection.isValid &&
        math.min(selection.start, selection.end) == 0 &&
        math.max(selection.start, selection.end) == textLength;

    void closeMenu() {
      ContextMenuController.removeAny();
    }

    return [
      ContextMenuButtonItem(
        type: ContextMenuButtonType.cut,
        label: widget.locale.dialogInputCut,
        onPressed: hasSelection
            ? () {
                closeMenu();
                _copyTextEditingSelection(controller, cut: true);
              }
            : null,
      ),
      ContextMenuButtonItem(
        type: ContextMenuButtonType.copy,
        label: widget.locale.dialogInputCopy,
        onPressed: hasSelection
            ? () {
                closeMenu();
                _copyTextEditingSelection(controller, cut: false);
              }
            : null,
      ),
      ContextMenuButtonItem(
        type: ContextMenuButtonType.paste,
        label: widget.locale.dialogInputPaste,
        onPressed: hasClipboardText
            ? () {
                closeMenu();
                unawaited(_pasteTextEditingSelection(controller));
              }
            : null,
      ),
      ContextMenuButtonItem(
        type: ContextMenuButtonType.selectAll,
        label: widget.locale.dialogInputSelectAll,
        onPressed: hasText && !hasFullSelection
            ? () {
                closeMenu();
                controller.selection = TextSelection(
                  baseOffset: 0,
                  extentOffset: controller.text.length,
                );
              }
            : null,
      ),
    ];
  }

  void _updateImageInsertInputSelectionDrag(PointerMoveEvent event) {
    if (_imageInsertDragSelectionPointer != event.pointer) {
      return;
    }
    final baseOffset = _imageInsertDragSelectionBaseOffset;
    final controller = _imageInsertDragSelectionController;
    final editableKey = _imageInsertDragSelectionEditableKey;
    if (baseOffset == null || controller == null || editableKey == null) {
      return;
    }
    final extentOffset = _textOffsetForGlobalPosition(
      editableKey,
      controller,
      event.position,
    );
    if (extentOffset == null) {
      return;
    }
    controller.selection = TextSelection(
      baseOffset: baseOffset,
      extentOffset: extentOffset,
    );
  }

  void _endImageInsertInputSelectionDrag(int pointer) {
    if (_imageInsertDragSelectionPointer != pointer) {
      return;
    }
    _imageInsertDragSelectionPointer = null;
    _imageInsertDragSelectionBaseOffset = null;
    _imageInsertDragSelectionController = null;
    _imageInsertDragSelectionEditableKey = null;
  }

  int _inlineMenuTextOffsetForLocalPosition(
    TextEditingController controller,
    double editorWidth,
    double fontSize,
    Offset localPosition,
  ) {
    final text = controller.text;
    if (text.isEmpty) {
      return 0;
    }
    final textPainter = TextPainter(
      text: TextSpan(
        text: text,
        style: TextStyle(
          color: const Color(0xff222222),
          fontSize: fontSize,
          fontFamily: 'Arial',
          height: 1,
        ),
      ),
      maxLines: 1,
      textDirection: TextDirection.ltr,
    )..layout();
    final textLeft = math.max(0.0, (editorWidth - textPainter.width) / 2);
    final textX = (localPosition.dx - textLeft).clamp(
      0.0,
      math.max(0.0, textPainter.width),
    );
    final position = textPainter.getPositionForOffset(
      Offset(textX.toDouble(), fontSize / 2),
    );
    return position.offset.clamp(0, text.length).toInt();
  }

  void _startInlineMenuInputSelectionDrag(
    PointerDownEvent event,
    TextEditingController controller,
    FocusNode focusNode,
    double editorWidth,
    double fontSize,
  ) {
    if ((event.buttons & kPrimaryMouseButton) == 0) {
      return;
    }
    ContextMenuController.removeAny();
    focusNode.requestFocus();
    final offset = _inlineMenuTextOffsetForLocalPosition(
      controller,
      editorWidth,
      fontSize,
      event.localPosition,
    );
    _inlineMenuDragSelectionPointer = event.pointer;
    _inlineMenuDragSelectionBaseOffset = offset;
    _inlineMenuDragSelectionEditorWidth = editorWidth;
    _inlineMenuDragSelectionFontSize = fontSize;
    _inlineMenuDragSelectionController = controller;
    controller.selection = TextSelection.collapsed(offset: offset);
  }

  void _updateInlineMenuInputSelectionDrag(PointerMoveEvent event) {
    if (_inlineMenuDragSelectionPointer != event.pointer) {
      return;
    }
    final baseOffset = _inlineMenuDragSelectionBaseOffset;
    final editorWidth = _inlineMenuDragSelectionEditorWidth;
    final fontSize = _inlineMenuDragSelectionFontSize;
    final controller = _inlineMenuDragSelectionController;
    if (baseOffset == null ||
        editorWidth == null ||
        fontSize == null ||
        controller == null) {
      return;
    }
    final extentOffset = _inlineMenuTextOffsetForLocalPosition(
      controller,
      editorWidth,
      fontSize,
      event.localPosition,
    );
    controller.selection = TextSelection(
      baseOffset: baseOffset,
      extentOffset: extentOffset,
    );
  }

  void _endInlineMenuInputSelectionDrag(int pointer) {
    if (_inlineMenuDragSelectionPointer != pointer) {
      return;
    }
    _inlineMenuDragSelectionPointer = null;
    _inlineMenuDragSelectionBaseOffset = null;
    _inlineMenuDragSelectionEditorWidth = null;
    _inlineMenuDragSelectionFontSize = null;
    _inlineMenuDragSelectionController = null;
  }

  Widget _buildEditor() {
    final rect = _editingRect();
    final coord = _editingCoord;
    if (rect == null || coord == null) {
      return const SizedBox.shrink();
    }
    final settings = _workbook.settings;
    final cell = _workbook.activeSheet.cells[coord];
    final fontSize = cell?.fontSize ?? settings.defaultFontSize;
    _editorController.fontFamilyResolver = (raw, baseStyle) {
      return fortuneResolveFontFamily(
        raw,
        _workbook.settings.fontFamilies,
        fallback: baseStyle.fontFamily ?? 'Arial',
      );
    };
    return Positioned(
      left: rect.left,
      top: rect.top,
      width: math.max(rect.width, 40),
      height: math.max(rect.height, 22),
      child: Focus(
        onKeyEvent: _handleEditorKeyEvent,
        child: DecoratedBox(
          decoration: BoxDecoration(
            color: cell?.background ?? const Color(0xffffffff),
            border: Border.all(color: const Color(0xff0188fb), width: 2),
          ),
          child: Padding(
            padding: const EdgeInsets.symmetric(horizontal: 2),
            child: Listener(
              behavior: HitTestBehavior.translucent,
              onPointerDown: _startEditorSelectionDrag,
              onPointerMove: _updateEditorSelectionDrag,
              onPointerUp: (event) => _endEditorSelectionDrag(event.pointer),
              onPointerCancel: (event) =>
                  _endEditorSelectionDrag(event.pointer),
              child: EditableText(
                key: _editorEditableKey,
                controller: _editorController,
                focusNode: _editorFocusNode,
                undoController: _editorUndoController,
                style: TextStyle(
                  color: cell?.foreground ?? const Color(0xff000000),
                  fontSize: fontSize,
                  fontFamily: cell == null
                      ? 'Arial'
                      : _resolvedCellFontFamily(cell),
                  fontWeight: cell?.bold ?? false
                      ? FontWeight.w700
                      : FontWeight.w400,
                  fontStyle: cell?.italic ?? false
                      ? FontStyle.italic
                      : FontStyle.normal,
                ),
                cursorColor: const Color(0xff000000),
                backgroundCursorColor: const Color(0x330188fb),
                selectionColor: const Color(0x550188fb),
                selectionWidthStyle: ui.BoxWidthStyle.tight,
                selectionHeightStyle: ui.BoxHeightStyle.tight,
                selectionControls: desktopTextSelectionControls,
                contextMenuBuilder: _fortuneEditableTextContextMenuBuilder,
                onSelectionChanged: _handleEditorSelectionChanged,
                mouseCursor: SystemMouseCursors.text,
                enableInteractiveSelection: true,
                rendererIgnoresPointer: true,
                maxLines: null,
                scrollController: _editorScrollController,
                strutStyle: StrutStyle(fontSize: fontSize, height: 1.2),
                keyboardType: TextInputType.multiline,
                textInputAction: TextInputAction.newline,
                onSubmitted: (_) {
                  _traceCellEditor('editableText onSubmitted');
                  _commitEditing();
                },
                onEditingComplete: () {
                  _traceCellEditor('editableText onEditingComplete');
                  _commitEditing();
                },
                onTapOutside: (event) {
                  if (_shouldKeepEditingForEditorTapOutside(event)) {
                    _logEditorDebug('tapOutside keepEditing toolbarInline');
                    _traceCellEditor('tapOutside keepEditing toolbarInline');
                    return;
                  }
                  _logEditorDebug('tapOutside commitEditing');
                  _traceCellEditor('tapOutside commitEditing');
                  _commitEditing();
                },
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildFormulaBarEditor() {
    if (!_editingFormulaBar || !_workbook.settings.showFormulaBar) {
      return const SizedBox.shrink();
    }
    final settings = _workbook.settings;
    const nameBoxWidth = 99.0;
    return Positioned(
      left: nameBoxWidth + 49,
      right: 0,
