  Rect? _commentBoxRectForCoord(FortuneCellCoord coord) {
    final settings = _workbook.settings;
    final sheet = _workbook.activeSheet;
    final metrics = sheet.metrics(settings);
    if (coord.row < 0 ||
        coord.column < 0 ||
        coord.row >= metrics.visibleDataRows.length ||
        coord.column >= metrics.visibleDataColumns.length) {
      return null;
    }
    final cell = sheet.cells[coord];
    final comment = cell?.comment;
    if (comment == null) {
      return null;
    }
    final columnSpan = math.max(1, cell?.merge?.columnSpan ?? 1);
    final columnEnd = math.min(
      metrics.visibleDataColumns.length - 1,
      coord.column + columnSpan - 1,
    );
    final cellRight =
        _visualCellLeft(coord.column, settings, metrics) +
        metrics.columnEnd(columnEnd) -
        metrics.columnStart(coord.column);
    final cellTop = _visualCellTop(coord.row, settings, metrics);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final left = comment.left == null
        ? cellRight + 18 * sheet.zoomRatio
        : _sheetDataLeft(settings) +
              comment.left! * sheet.zoomRatio -
              scrollOffset.dx;
    final top = comment.top == null
        ? math.max(2.0, cellTop - 18 * sheet.zoomRatio)
        : _sheetDataTop(settings) +
              comment.top! * sheet.zoomRatio -
              scrollOffset.dy;
    return Rect.fromLTWH(
      left,
      sheetTop + top,
      (comment.width ?? 144) * sheet.zoomRatio,
      (comment.height ?? 84) * sheet.zoomRatio,
    );
  }

  Rect? _commentEditorRect() {
    final coord = _editingCommentCoord;
    if (coord == null) {
      return null;
    }
    return _commentBoxRectForCoord(coord);
  }

  List<Widget> _buildCommentResizeHandles() {
    const size = 7.0;
    Widget handle(Alignment alignment) {
      return Align(
        alignment: alignment,
        child: SizedBox(
          width: size,
          height: size,
          child: DecoratedBox(
            decoration: BoxDecoration(
              color: const Color(0xffffffff),
              border: Border.all(color: const Color(0xff000000)),
            ),
          ),
        ),
      );
    }

    return const [
      Alignment.topLeft,
      Alignment.topCenter,
      Alignment.topRight,
      Alignment.centerLeft,
      Alignment.centerRight,
      Alignment.bottomLeft,
      Alignment.bottomCenter,
      Alignment.bottomRight,
    ].map(handle).toList();
  }

