    final heightRect = _barcodeHeightInputRect(size);
    final leadingQuietZoneRect = _barcodeLeadingQuietZoneInputRect(size);
    final trailingQuietZoneRect = _barcodeTrailingQuietZoneInputRect(size);
    final rotationRect = _barcodeRotationInputRect(size);
    if (objectIdRect == null ||
        textRect == null ||
        moduleScaleRect == null ||
        barHeightRect == null ||
        widthRect == null ||
        heightRect == null ||
        leadingQuietZoneRect == null ||
        trailingQuietZoneRect == null ||
        rotationRect == null) {
      return const SizedBox.shrink();
    }
    return Positioned.fill(
      child: Stack(
        children: [
          if (!_barcodeFormatMenuIntersects(size, textRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-text-input'),
              editableKey: _barcodeTextEditableKey,
              rect: textRect,
              controller: _barcodeTextController,
              focusNode: _barcodeTextFocusNode,
              keyboardType: TextInputType.text,
            ),
          if (!_barcodeFormatMenuIntersects(size, widthRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-width-input'),
              editableKey: _barcodeWidthEditableKey,
              rect: widthRect,
              controller: _barcodeWidthController,
              focusNode: _barcodeWidthFocusNode,
            ),
          if (!_barcodeFormatMenuIntersects(size, moduleScaleRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-module-scale-input'),
              editableKey: _barcodeModuleScaleEditableKey,
              rect: moduleScaleRect,
              controller: _barcodeModuleScaleController,
              focusNode: _barcodeModuleScaleFocusNode,
            ),
          if (!_barcodeFormatMenuIntersects(size, barHeightRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-bar-height-input'),
              editableKey: _barcodeBarHeightEditableKey,
              rect: barHeightRect,
              controller: _barcodeBarHeightController,
              focusNode: _barcodeBarHeightFocusNode,
            ),
          if (!_barcodeFormatMenuIntersects(size, heightRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-height-input'),
              editableKey: _barcodeHeightEditableKey,
              rect: heightRect,
              controller: _barcodeHeightController,
              focusNode: _barcodeHeightFocusNode,
            ),
          if (!_barcodeFormatMenuIntersects(size, rotationRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-rotation-input'),
              editableKey: _barcodeRotationEditableKey,
              rect: rotationRect,
              controller: _barcodeRotationController,
              focusNode: _barcodeRotationFocusNode,
              signed: true,
            ),
          if (!_barcodeFormatMenuIntersects(size, leadingQuietZoneRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-leading-quiet-zone-input'),
              editableKey: _barcodeLeadingQuietZoneEditableKey,
              rect: leadingQuietZoneRect,
              controller: _barcodeLeadingQuietZoneController,
              focusNode: _barcodeLeadingQuietZoneFocusNode,
              keyboardType: TextInputType.text,
            ),
          if (!_barcodeFormatMenuIntersects(size, trailingQuietZoneRect))
            _buildBarcodeDialogInput(
              key: const ValueKey('fortune-barcode-trailing-quiet-zone-input'),
              editableKey: _barcodeTrailingQuietZoneEditableKey,
              rect: trailingQuietZoneRect,
              controller: _barcodeTrailingQuietZoneController,
              focusNode: _barcodeTrailingQuietZoneFocusNode,
              keyboardType: TextInputType.text,
            ),
        ],
      ),
    );
  }

  bool _barcodeFormatMenuIntersects(Size size, Rect rect) {
    final dialogRect = _barcodeDialogRect(size);
    if (dialogRect == null) {
      return false;
    }
    if (_barcodeFormatMenuOpen &&
        fortuneBarcodeFormatMenuRect(
          dialogRect,
          _effectiveBarcodeFormats.length,
        ).overlaps(rect)) {
      return true;
    }
    if (_barcodeObjectIdMenuOpen &&
        fortuneBarcodeObjectIdMenuRect(
          dialogRect,
          _effectiveBarcodeObjectIds.length,
        ).overlaps(rect)) {
      return true;
    }
    if (_barcodeTextFontMenuOpen &&
        fortuneBarcodeTextFontMenuRect(
          dialogRect,
          _barcodeTextFontOptions.length,
          labels: _barcodeTextFontOptions,
        ).overlaps(rect)) {
      return true;
    }
    return _barcodeTextFontSizeMenuOpen &&
        fortuneBarcodeTextFontSizeMenuRect(
          dialogRect,
          _barcodeTextFontSizeOptions.length,
        ).overlaps(rect);
  }

