  Widget _buildInlineMenuNumberEditor({
    required Key key,
    required Rect rect,
    required TextEditingController controller,
    required FocusNode focusNode,
    required FocusOnKeyEventCallback onKeyEvent,
    required ValueChanged<String> onSubmitted,
    double fontSize = 11,
    double verticalOffset = 2,
    String? hintText,
    bool allowNegative = false,
  }) {
    final editorHeight = math.min(rect.height - 2, fontSize + 4);
    final editorWidth = math.max(12.0, rect.width - 6);
    return Positioned(
      left: rect.left + 3,
      top: rect.top + (rect.height - editorHeight) / 2 + verticalOffset,
      width: editorWidth,
      height: editorHeight,
      child: Listener(
        behavior: HitTestBehavior.opaque,
        onPointerDown: (event) => _startInlineMenuInputSelectionDrag(
          event,
          controller,
          focusNode,
          editorWidth,
          fontSize,
        ),
        onPointerMove: _updateInlineMenuInputSelectionDrag,
        onPointerUp: (event) => _endInlineMenuInputSelectionDrag(event.pointer),
        onPointerCancel: (event) =>
            _endInlineMenuInputSelectionDrag(event.pointer),
        child: Focus(
          onKeyEvent: onKeyEvent,
          child: Stack(
            fit: StackFit.expand,
            children: [
              if (hintText != null)
                ValueListenableBuilder<TextEditingValue>(
                  valueListenable: controller,
                  builder: (context, value, child) {
                    if (value.text.isNotEmpty) {
                      return const SizedBox.shrink();
                    }
                    return Center(child: child);
                  },
                  child: Text(
                    hintText,
                    textAlign: TextAlign.center,
                    overflow: TextOverflow.clip,
                    maxLines: 1,
                    style: TextStyle(
                      color: const Color(0xff777777),
                      fontSize: fontSize,
                      fontFamily: 'Arial',
                      height: 1,
                    ),
                  ),
                ),
              EditableText(
                key: key,
                controller: controller,
                focusNode: focusNode,
                style: TextStyle(
                  color: const Color(0xff222222),
                  fontSize: fontSize,
                  fontFamily: 'Arial',
                  height: 1,
                ),
                cursorColor: const Color(0xff0188fb),
                cursorHeight: fontSize + 2,
                backgroundCursorColor: const Color(0x330188fb),
                selectionColor: const Color(0x550188fb),
                selectionWidthStyle: ui.BoxWidthStyle.tight,
                selectionHeightStyle: ui.BoxHeightStyle.tight,
                mouseCursor: SystemMouseCursors.text,
                enableInteractiveSelection: true,
                rendererIgnoresPointer: true,
                maxLines: 1,
                textAlign: TextAlign.center,
                strutStyle: StrutStyle(
                  fontSize: fontSize,
                  height: 1,
                  forceStrutHeight: true,
                ),
                keyboardType: const TextInputType.numberWithOptions(
                  decimal: true,
                ),
                textInputAction: TextInputAction.done,
                inputFormatters: [
                  FilteringTextInputFormatter.allow(
                    allowNegative ? RegExp(r'[0-9.-]') : RegExp(r'[0-9.]'),
                  ),
                ],
                onSubmitted: onSubmitted,
                onEditingComplete: () => onSubmitted(controller.text),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildToolbarBorderStyleWidthEditors(Size size) {
    if (toolbarPopupKey != fortuneToolbarBorderPopupKey ||
        _toolbarBorderSubmenuKey != fortuneToolbarBorderStyleSubmenuKey) {
      return const SizedBox.shrink();
    }
    final children = <Widget>[];
    for (final style in fortuneToolbarBorderWidthEditableStyles) {
      final rect = _toolbarBorderStyleWidthInputRect(style, size);
      final controller = _toolbarBorderStyleWidthControllers[style];
      final focusNode = _toolbarBorderStyleWidthFocusNodes[style];
      if (rect == null || controller == null || focusNode == null) {
        continue;
      }
      children.add(
        _buildInlineMenuNumberEditor(
          key: ValueKey('fortune-border-style-width-$style'),
          rect: rect,
          controller: controller,
          focusNode: focusNode,
          onKeyEvent: (node, event) =>
              _handleToolbarBorderStyleWidthKeyEvent(style, node, event),
          onSubmitted: (_) => _commitToolbarBorderStyleWidth(style),
          verticalOffset: 1,
        ),
      );
    }
    if (children.isEmpty) {
      return const SizedBox.shrink();
    }
    return Stack(children: children);
  }

  Widget _buildContextMenuInlineInputEditors() {
    final at = contextMenuAt;
    if (at == null) {
      return const SizedBox.shrink();
    }
    final items = _activeContextMenuItems;
    final children = <Widget>[];
    for (final command in fortuneContextMenuInlineInputCommands) {
      if (!items.contains(command)) {
        continue;
      }
      final rect = fortuneContextMenuInlineInputRect(at, command, items);
      final controller = _contextMenuInlineInputControllers[command];
      final focusNode = _contextMenuInlineInputFocusNodes[command];
      if (rect == null || controller == null || focusNode == null) {
        continue;
      }
      children.add(
        _buildInlineMenuNumberEditor(
          key: ValueKey('fortune-context-menu-input-$command'),
          rect: rect,
          controller: controller,
          focusNode: focusNode,
          onKeyEvent: (node, event) =>
              _handleContextMenuInlineInputKeyEvent(command, node, event),
          onSubmitted: (_) => _commitContextMenuInlineInput(command),
          allowNegative: command == fortuneEditorContextLetterSpacingCommand,
          fontSize: 12,
          verticalOffset: _isEditorContextInlineInputCommand(command) ? 1 : 3,
          hintText: widget.locale.contextMenuLabels['$command-hint'],
        ),
      );
    }
    if (children.isEmpty) {
      return const SizedBox.shrink();
    }
    return Stack(children: children);
  }

