  bool _conditionRuleUsesNumericInput() {
    return fortuneConditionRuleNumericComparisonTypes.contains(
          _conditionRuleType,
        ) ||
        _conditionRuleType == fortuneConditionRuleBetweenType ||
        _conditionRuleIsProjectType(_conditionRuleType);
  }

  TextInputType _conditionRuleKeyboardType() {
    if (_conditionRuleType == fortuneConditionRuleOccurrenceDateType) {
      return TextInputType.datetime;
    }
    return _conditionRuleUsesNumericInput()
        ? TextInputType.number
        : TextInputType.text;
  }

  Rect? _sheetTabRectFor(Size size, int index) {
    if (index < 0 || index >= _workbook.sheets.length) {
      return null;
    }
    final settings = _workbook.settings;
    final statTop = size.height - settings.statisticBarHeight;
    final tabTop = statTop - settings.effectiveSheetBarHeight;
    final tabViewport = _sheetTabViewport(size.width);
    var x = tabViewport.left - _sheetTabScrollOffset;
    for (var i = 0; i < _workbook.sheets.length; i += 1) {
      final sheet = _workbook.sheets[i];
      if (sheet.hide == 1) {
        continue;
      }
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      if (i == index) {
        return Rect.fromLTWH(x, tabTop + 1, width, 29).intersect(
          Rect.fromLTWH(tabViewport.left, tabTop + 1, tabViewport.width, 29),
        );
      }
      x += width - 1;
    }
    return null;
  }

  Rect _sheetTabViewport(double width) {
    return Rect.fromLTWH(58, 0, math.max(0, width - 58), double.infinity);
  }

  bool _sheetTabsOverflow(double width) {
    return _sheetTabsTotalWidth() > _sheetTabViewport(width).width;
  }

  double _sheetTabsTotalWidth({List<FortuneSheet>? sheets}) {
    var total = 0.0;
    for (final sheet in sheets ?? _workbook.sheets) {
      if (sheet.hide == 1) {
        continue;
      }
      total += math.max(72.0, (sheet.name.length * 8 + 32).toDouble()) - 1;
    }
    return math.max(0, total);
  }

  double _clampedSheetTabScrollOffset(
    double offset, {
    List<FortuneSheet>? sheets,
  }) {
    final size = context.size;
    if (size == null) {
      return math.max(0, offset);
    }
    final maxOffset = math.max(
      0.0,
      _sheetTabsTotalWidth(sheets: sheets) -
          _sheetTabViewport(size.width).width,
    );
    return offset.clamp(0, maxOffset).toDouble();
  }

  double _sheetTabOffsetToReveal(int index, {List<FortuneSheet>? sheets}) {
    final size = context.size;
    if (size == null) {
      return _clampedSheetTabScrollOffset(
        _sheetTabScrollOffset,
        sheets: sheets,
      );
    }
    final tabSheets = sheets ?? _workbook.sheets;
    var tabLeft = 0.0;
    for (var i = 0; i < tabSheets.length; i += 1) {
      final sheet = tabSheets[i];
      if (sheet.hide == 1) {
        continue;
      }
      final width = math.max(72.0, (sheet.name.length * 8 + 32).toDouble());
      final tabRight = tabLeft + width;
      if (i == index) {
        final viewportWidth = _sheetTabViewport(size.width).width;
        var next = _sheetTabScrollOffset;
        if (tabLeft < next) {
          next = tabLeft;
        } else if (tabRight > next + viewportWidth) {
          next = tabRight - viewportWidth;
        }
        return _clampedSheetTabScrollOffset(next, sheets: tabSheets);
      }
      tabLeft += width - 1;
    }
    return _clampedSheetTabScrollOffset(
      _sheetTabScrollOffset,
      sheets: tabSheets,
    );
  }

  Widget _buildSheetTabEditor(Size size) {
    final index = _renamingSheetIndex;
    if (index == null) {
      return const SizedBox.shrink();
