                    _dataVerificationDialogRangeText,
                dataVerificationDialogType: _dataVerificationDialogType,
                dataVerificationDialogType2: _dataVerificationDialogType2,
                dataVerificationDialogOptionsText:
                    _dataVerificationEditorController.text,
                dataVerificationDialogSecondText:
                    _dataVerificationSecondEditorController.text,
                dataVerificationDialogHintText:
                    _dataVerificationHintEditorController.text,
                dataVerificationDialogAllowMulti:
                    _dataVerificationDialogAllowMulti,
                dataVerificationDialogProhibitInput:
                    _dataVerificationDialogProhibitInput,
                dataVerificationDialogHintShow: _dataVerificationDialogHintShow,
                splitTextDialogOpen: _splitTextDialogOpen,
                splitTextTab: _splitTextTab,
                splitTextSemicolon: _splitTextSemicolon,
                splitTextComma: _splitTextComma,
                splitTextSpace: _splitTextSpace,
                splitTextOther: _splitTextOther,
                splitTextConsecutive: _splitTextConsecutive,
                splitTextOtherText: _splitTextOtherController.text,
                splitTextPreview: _splitTextPreviewData(),
                locationDialogOpen: _locationDialogOpen,
                locationDialogType: _locationDialogType,
                locationConstantDate: _locationConstantDate,
                locationConstantNumber: _locationConstantNumber,
                locationConstantString: _locationConstantString,
                locationConstantLogical: _locationConstantLogical,
                locationConstantError: _locationConstantError,
                locationFormulaDate: _locationFormulaDate,
                locationFormulaNumber: _locationFormulaNumber,
                locationFormulaString: _locationFormulaString,
                locationFormulaLogical: _locationFormulaLogical,
                locationFormulaError: _locationFormulaError,
                locationMessageDialogText: _locationMessageDialogText,
                locationMessageDialogConfirm: _locationMessageDialogConfirm,
                screenshotDialogOpen: _screenshotDialogOpen,
                screenshotRange: _screenshotRange,
                screenshotImageDataUrl: _screenshotImageDataUrl,
                screenshotImage: _screenshotImage,
                searchDialogOpen: _searchDialogOpen,
                searchReplaceMode: _searchReplaceMode,
                searchRegex: _searchRegex,
                searchWholeWord: _searchWholeWord,
                searchCaseSensitive: _searchCaseSensitive,
                searchText: _searchEditorController.text,
                replaceText: _replaceEditorController.text,
                searchResults: _searchResults,
                searchSelectedResultIndex: _searchSelectedResultIndex,
                searchDialogOffset: _searchDialogOffset,
                formulaSearchDialogOpen: _formulaSearchDialogOpen,
                formulaSearchCategoryType: _formulaSearchCategoryType,
                formulaSearchSelectedIndex: _formulaSearchSelectedIndex,
                formulaSearchText: _formulaSearchEditorController.text,
                formulaSearchCategoryMenuOpen: _formulaSearchCategoryMenuOpen,
                formulaSearchScrollOffset: _formulaSearchScrollOffset,
                conditionRuleDialogOpen: _conditionRuleDialogOpen,
                conditionRuleType: _conditionRuleType,
                conditionRuleDuplicateValue: _conditionRuleDuplicateValue,
                conditionRuleDuplicateMenuOpen: _conditionRuleDuplicateMenuOpen,
                conditionRuleTextColorEnabled: _conditionRuleTextColorEnabled,
                conditionRuleCellColorEnabled: _conditionRuleCellColorEnabled,
                conditionRuleTextColor: _conditionRuleTextColor,
                conditionRuleCellColor: _conditionRuleCellColor,
                conditionFormatSubmenuKey: _conditionFormatSubmenuKey,
                conditionFormatHoveredTopLevelIndex:
                    _conditionFormatHoveredTopLevelIndex,
                conditionFormatHoveredSubmenuIndex:
                    _conditionFormatHoveredSubmenuIndex,
                hoveredColumnHeaderIndex: _hoveredColumnHeaderIndex,
                hoveredRowHeaderIndex: _hoveredRowHeaderIndex,
                activeImageId: _activeImageId,
                decodedImages: Map<String, ui.Image>.unmodifiable(
                  _decodedImages,
                ),
                textDirection: Directionality.of(context),
                zoomMenuOpen: _zoomMenuOpen,
                sheetFocused: _sheetFocused,
                deferToolbarPopup: toolbarPopupKey != null,
                deferContextMenu: contextMenuAt != null,
                sheetRulerVisible: _activeSheetRulerVisible(),
                sheetRulerGuides: _activeSheetRulerGuides(),
                sheetRulerDraggingGuide: _sheetRulerDraggingGuide,
                sheetRulerHoveredGuideIndex: _sheetRulerHoveredGuideIndex,
                sheetRulerSelectedGuideIndex: _sheetRulerSelectedGuideIndex,
                sheetRulerTooltipText: _sheetRulerTooltipText,
                sheetRulerTooltipPosition: _sheetRulerTooltipPosition == null
                    ? null
                    : Offset(
                        _sheetRulerTooltipPosition!.dx,
                        _sheetRulerTooltipPosition!.dy -
                            _workbook.settings.effectiveToolbarHeight -
                            _workbook.settings.effectiveFormulaBarHeight,
                      ),
                contextMenuCheckedItems: {
                  if (_workbook.activeSheet.showGridLines)
                    fortuneContextShowGridLinesCommand,
                  if (_activeSheetRulerVisible())
                    fortuneContextShowRulerCommand,
                },
              );
              return CustomPaint(
                painter: sheetPainter,
                child: Stack(
                  fit: StackFit.expand,
                  children: [
                    _buildEditor(),
                    _buildFormulaBarEditor(),
                    _buildHyperlinkDialogEditors(size),
                    _buildCommentEditor(),
                    _buildAxisSizeEditor(size),
                    _buildImageInsertDialogEditors(size),
                    _buildBarcodeDialogEditors(size),
                    if (toolbarPopupKey != null)
                      Positioned.fill(
                        child: IgnorePointer(
                          child: CustomPaint(
                            painter: sheetPainter
                                .toolbarPopupForegroundPainter(),
                          ),
                        ),
                      ),
                    _buildToolbarBorderStyleWidthEditors(size),
                    _buildDataVerificationEditor(size),
                    _buildSplitTextOtherEditor(size),
                    _buildSearchEditors(size),
                    _buildFormulaSearchEditor(size),
                    _buildFormatSearchDecimalEditor(size),
                    _buildConditionRuleEditor(size),
                    _buildFilterDropdownSearchEditor(size),
                    _buildSheetTabEditor(size),
                    if (contextMenuAt != null)
                      Positioned.fill(
                        child: IgnorePointer(
                          child: CustomPaint(
                            painter: sheetPainter
                                .contextMenuForegroundPainter(),
                          ),
                        ),
                      ),
                    _buildContextMenuInlineInputEditors(),
                  ],
                ),
              );
            },
          ),
        ),
      ),
    );
  }
}

class _HeaderResizeTarget {
  const _HeaderResizeTarget.row(this.index, {this.hidden = false})
    : axis = 'row';

  const _HeaderResizeTarget.column(this.index, {this.hidden = false})
    : axis = 'column';

  final String axis;
  final int index;
  final bool hidden;
}

class _SheetTabsAction {
  const _SheetTabsAction.add()
    : addSheet = true,
      appendRows = false,
      backTop = false,
      openSheetList = false,
      sheetIndex = null,
      scrollDirection = 0,
      openMenu = false;

  const _SheetTabsAction.addRows()
    : addSheet = false,
      appendRows = true,
      backTop = false,
      openSheetList = false,
      sheetIndex = null,
      scrollDirection = 0,
      openMenu = false;

  const _SheetTabsAction.backTop()
    : addSheet = false,
      appendRows = false,
      backTop = true,
      openSheetList = false,
      sheetIndex = null,
      scrollDirection = 0,
      openMenu = false;

  const _SheetTabsAction.select(this.sheetIndex, {this.openMenu = false})
    : addSheet = false,
      appendRows = false,
      backTop = false,
      openSheetList = false,
      scrollDirection = 0;

  const _SheetTabsAction.scroll(this.scrollDirection)
    : addSheet = false,
      appendRows = false,
      backTop = false,
      openSheetList = false,
      sheetIndex = null,
      openMenu = false;

  const _SheetTabsAction.sheetList()
    : addSheet = false,
      appendRows = false,
      backTop = false,
      openSheetList = true,
      sheetIndex = null,
      scrollDirection = 0,
      openMenu = false;

  final bool addSheet;
  final bool appendRows;
  final bool backTop;
  final bool openSheetList;
  final int? sheetIndex;
  final int scrollDirection;
  final bool openMenu;
}
